insert into room_unit_comments values (1, 100101, 1, 1, 1, 0, 1, 'ここに困ってる人は\\nいないよね…？\\nよかった♪', 0);
insert into room_unit_comments values (2, 100101, 1, 2, 1, 0, 1, '冒険の準備準備…\\nうん、忘れ物はなし！\\n…あっ！', 0);
insert into room_unit_comments values (3, 100101, 1, 3, 1, 0, 1, 'リズムを意識して…\\nわんつーわんつー！\\nうん、調子はバッチリ', 0);
insert into room_unit_comments values (4, 100101, 1, 4, 1, 0, 1, 'ここで特訓していい？\\n物は壊さないように\\n気をつけるね！', 0);
insert into room_unit_comments values (5, 100101, 1, 5, 1, 0, 1, 'なんか落ち着かないや\\nもしかして、\\n困ってる人が\\n近くにいるのかな…？', 0);
insert into room_unit_comments values (6, 100101, 1, 101, 4, 0, 1, 'えへへ…いつも\\n一緒にいてくれて\\nありがとねっ！', 0);
insert into room_unit_comments values (7, 100101, 1, 102, 8, 0, 1, 'ちゃんと覚えてるよ\\n騎士くんの声…\\nあの時はありがとね！', 0);
insert into room_unit_comments values (8, 100101, 2, 1, 1, 0, 1, 'あははっ！\\nやったなー！\\nお返しだー！\\nこちょこちょこちょ…', 0);
insert into room_unit_comments values (9, 100101, 2, 2, 1, 0, 1, 'どうしたの？\\nもしかして困ってる？\\nあたしにまかせて！', 0);
insert into room_unit_comments values (10, 100101, 2, 3, 1, 0, 1, 'えっとね…しっぽは\\n触っちゃダメだよ？', 0);
insert into room_unit_comments values (11, 100101, 2, 4, 1, 0, 1, '反応しない特訓…\\nだったけど無理～！\\n悔しいよぉ～！', 0);
insert into room_unit_comments values (12, 100101, 2, 101, 4, 0, 1, 'ふぁふぃ？\\nやられた～！\u3000ほっぺ\\nぷにぷにしないでぇ～', 0);
insert into room_unit_comments values (13, 100101, 2, 102, 8, 0, 1, 'えへへ…\\n騎士くんの手だ…\\nあったかいな…♪', 0);
insert into room_unit_comments values (14, 100101, 2, 1, 1, 1, 1, 'おはよー！\\n今日も元気に\\nいっちゃうよー！', 0);
insert into room_unit_comments values (15, 100101, 2, 2, 1, 2, 1, 'ユイちゃんに\\nおやつ作って\\nもらおうかな～♪', 0);
insert into room_unit_comments values (16, 100101, 2, 3, 1, 3, 1, '寝るのも修行だって\\nこないだレイさんが\\n言ってたんだ…', 0);
insert into room_unit_comments values (17, 100101, 3, 1, 1, 0, 1, 'ちゃんとケアして\\n傷が残らないように\\nしないと…', 0);
insert into room_unit_comments values (18, 100101, 3, 2, 1, 0, 1, '一回休むと\\nこのままずるずる\\nいきそう…', 0);
insert into room_unit_comments values (19, 100101, 3, 3, 1, 0, 1, '新しい練習相手に…\\nって冗談だよ冗談！\\n本気じゃないから！', 0);
insert into room_unit_comments values (20, 100101, 3, 4, 1, 0, 1, '落ち着くなぁ～\\n心だけじゃなくて\\n体もほぐれそう♪', 0);
insert into room_unit_comments values (21, 100101, 3, 5, 1, 0, 1, 'あったかい所に\\nいると体が丸く\\nなっちゃう…', 0);
insert into room_unit_comments values (22, 100101, 3, 6, 1, 0, 1, 'いつ何が起きるか\\n分からないし、\\nもっと力をつけないと', 0);
insert into room_unit_comments values (23, 100101, 3, 7, 1, 0, 1, '美味しいけど、\\n食べ過ぎないように\\nしないと…！！', 0);
insert into room_unit_comments values (24, 100101, 3, 8, 1, 0, 1, '文字が多いと\\n眠くなっちゃう…\\n危ない危ない！', 0);
insert into room_unit_comments values (26, 100102, 1, 1, 1, 0, 1, 'リズムを意識して…\\nわんつーわんつー！\\nうん、調子はバッチリ', 0);
insert into room_unit_comments values (27, 100102, 1, 2, 1, 0, 1, 'のんびりするのって\\n退屈かも…\\n何かして遊ばない？', 0);
insert into room_unit_comments values (28, 100102, 1, 3, 1, 0, 1, '留守番はちょっと\\n苦手かも…\\nなんか寂しいんだもん', 0);
insert into room_unit_comments values (29, 100102, 1, 4, 1, 0, 1, 'あたしのお友達も\\n呼んできていい？\\nきっと楽しいよ！', 0);
insert into room_unit_comments values (30, 100102, 1, 5, 1, 0, 1, '誰も困ってないよね？\\n…何をすれば\\nいいのか分かんないや', 0);
insert into room_unit_comments values (31, 100102, 1, 101, 8, 0, 1, 'ちゃんと覚えてるよ\\n騎士くんの声…\\nあの時はありがとね！', 0);
insert into room_unit_comments values (32, 100102, 1, 102, 8, 0, 1, '…なんであたし\\n騎士くんばっかり\\n見てるんだろ…', 0);
insert into room_unit_comments values (33, 100102, 2, 1, 1, 0, 1, '反応しない特訓…\\nだったけど無理～！\\n悔しいよぉ～！', 0);
insert into room_unit_comments values (34, 100102, 2, 2, 1, 0, 1, '触るのって楽しい？\\n…そっか\\n少しだけだよ…？', 0);
insert into room_unit_comments values (35, 100102, 2, 3, 1, 0, 1, 'あたしの元気を\\nわけてあげるね！\\nフレー！\u3000フレー！', 0);
insert into room_unit_comments values (36, 100102, 2, 4, 1, 0, 1, '何かムズムズする！？\\nって騎士くんかぁー\\nどしたの？', 0);
insert into room_unit_comments values (37, 100102, 2, 101, 8, 0, 1, 'ひゃうっ！\u3000もう…\\nしっぽはだめだってば\\n次やったらデコピン！', 0);
insert into room_unit_comments values (38, 100102, 2, 102, 8, 0, 1, 'えへへ…\\n騎士くんの手だ…\\nあったかいな…♪', 0);
insert into room_unit_comments values (39, 100102, 2, 1, 1, 1, 1, '朝ごはんと運動！\\nこれがあたしの\\n元気の素だよ！', 0);
insert into room_unit_comments values (40, 100102, 2, 2, 1, 2, 1, 'ユイちゃんに\\nおやつ作って\\nもらおうかな～♪', 0);
insert into room_unit_comments values (41, 100102, 2, 3, 1, 3, 1, '寝るのも修行だって\\nこないだレイさんが\\n言ってたんだ…', 0);
insert into room_unit_comments values (42, 100102, 3, 1, 1, 0, 1, 'これでよし♪\\n騎士くん\\n気づくかな…？', 0);
insert into room_unit_comments values (43, 100102, 3, 2, 1, 0, 1, '一回休むと\\nこのままずるずる\\nいきそう…', 0);
insert into room_unit_comments values (44, 100102, 3, 3, 1, 0, 1, '新しい練習相手に…\\nって冗談だよ冗談！\\n本気じゃないから！', 0);
insert into room_unit_comments values (45, 100102, 3, 4, 1, 0, 1, 'こういうの\\nなんか気になって\\nじーって見ちゃうんだ', 0);
insert into room_unit_comments values (46, 100102, 3, 5, 1, 0, 1, 'あったかい所に\\nいると体が丸く\\nなっちゃう…', 0);
insert into room_unit_comments values (47, 100102, 3, 6, 1, 0, 1, 'いつ何が起きるか\\n分からないし\\nもっと力をつけないと', 0);
insert into room_unit_comments values (48, 100102, 3, 7, 1, 0, 1, 'お腹が減ると\\nなんか力が\\n出ないんだよね…', 0);
insert into room_unit_comments values (49, 100102, 3, 8, 1, 0, 1, '色んなことを\\n知っておくのは\\n大事だよね！', 0);
insert into room_unit_comments values (51, 100201, 1, 1, 1, 0, 1, 'お片付けも済んだし\\n今度は洗濯ものを\\nたたもうかな', 0);
insert into room_unit_comments values (52, 100201, 1, 2, 1, 0, 1, 'この気持ち\\nもっとちゃんと\\n伝えなくっちゃ…', 0);
insert into room_unit_comments values (53, 100201, 1, 3, 1, 0, 1, 'お茶をいれようと\\n思うんだけど\\n他に飲みたい人は\\nいるかな？', 0);
insert into room_unit_comments values (54, 100201, 1, 4, 1, 0, 1, '戦いは\\n得意じゃないけど\\nお料理なら…！', 0);
insert into room_unit_comments values (55, 100201, 1, 5, 1, 0, 1, 'こういう平和な\\n時間が、もっと\\n続くといいな', 0);
insert into room_unit_comments values (56, 100201, 1, 101, 4, 0, 1, 'わたし…\\nもうちょっとだけ勇気\\n出してみようかな', 0);
insert into room_unit_comments values (57, 100201, 1, 102, 8, 0, 1, 'みんなのことが大好き\\nも、もちろん、\\n騎士クンのことも…\\nな、仲間として！', 0);
insert into room_unit_comments values (58, 100201, 2, 1, 1, 0, 1, 'ひゃうっ！\\nな、なに？\\nびっくりしたぁ…', 0);
insert into room_unit_comments values (59, 100201, 2, 2, 1, 0, 1, '男の子って、\\nやっぱりおっきいね。\\nその…手とか\\n他にもいろいろ…', 0);
insert into room_unit_comments values (60, 100201, 2, 3, 1, 0, 1, '困ったことが\\nあったら\\nいつでも話してね', 0);
insert into room_unit_comments values (61, 100201, 2, 4, 1, 0, 1, 'え！\u3000む、虫っ！？\\n取って取って！\\nはやく～！', 0);
insert into room_unit_comments values (62, 100201, 2, 101, 4, 0, 1, 'あのね…\\n一緒におでかけ\\nしたいんだけど…\\nダメかな？', 0);
insert into room_unit_comments values (63, 100201, 2, 102, 8, 0, 1, '騎士クンに\\n伝えたいことがあるの\\nとっても大切な…\\nこ、今度、話すね！', 0);
insert into room_unit_comments values (64, 100201, 2, 1, 1, 1, 1, 'お、おはよう！\\nあの…朝ごはんは\\nもう食べちゃった？', 0);
insert into room_unit_comments values (65, 100201, 2, 2, 1, 2, 1, 'お昼休みだね\\nあの…良かったら\\nお弁当…食べない？', 0);
insert into room_unit_comments values (66, 100201, 2, 3, 1, 3, 1, '遅くまでお疲れ様\\n明日も頑張ろうね\\nふわぁ…', 0);
insert into room_unit_comments values (67, 100201, 3, 1, 1, 0, 1, 'よし…\\nこれなら\\n褒めてもらえるかな？', 0);
insert into room_unit_comments values (68, 100201, 3, 2, 1, 0, 1, 'がんばることも\\n必要だけど、\\nお休みも大切だよね', 0);
insert into room_unit_comments values (69, 100201, 3, 3, 1, 0, 1, 'かわいいなぁ…\\nわたしも今度\\n作ってみよう。\\nえっと、材料は…', 0);
insert into room_unit_comments values (70, 100201, 3, 4, 1, 0, 1, '戦う前にもこうやって\\n落ち着けたら\\nいいのに', 0);
insert into room_unit_comments values (71, 100201, 3, 5, 1, 0, 1, '…はへっ？\\nも、もしかして今\\n寝ちゃってた…？', 0);
insert into room_unit_comments values (72, 100201, 3, 6, 1, 0, 1, '騎士クンと一緒に\\n冒険するなら\\n体力がないと…！', 0);
insert into room_unit_comments values (73, 100201, 3, 7, 1, 0, 1, 'おいしいものって\\n食べ過ぎちゃうけど…\\nしょうがない…よね？', 0);
insert into room_unit_comments values (74, 100201, 3, 8, 1, 0, 1, '…そっか\\nこうすれば魔法が\\nもっと強くなるんだ', 0);
insert into room_unit_comments values (76, 100202, 1, 1, 1, 0, 1, '洗濯と掃除\\nどっちから\\nはじめよう？', 0);
insert into room_unit_comments values (77, 100202, 1, 2, 1, 0, 1, '新しい魔道書を\\n買いに行かなくちゃ\\nもっとたくさん\\n魔法を覚えたいな', 0);
insert into room_unit_comments values (78, 100202, 1, 3, 1, 0, 1, 'お茶をいれようと\\n思うんだけど\\n他に飲みたい人は\\nいるかな？', 0);
insert into room_unit_comments values (79, 100202, 1, 4, 1, 0, 1, '今日はどんな料理に\\n挑戦しよう…♪', 0);
insert into room_unit_comments values (80, 100202, 1, 5, 1, 0, 1, 'この気持ち\\nもっとちゃんと\\n伝えなくっちゃ…', 0);
insert into room_unit_comments values (81, 100202, 1, 101, 8, 0, 1, 'みんなのことが大好き\\nも、もちろん\\n騎士クンのことも…\\nな、仲間として！', 0);
insert into room_unit_comments values (82, 100202, 1, 102, 8, 0, 1, '騎士クンのそばに\\nいられるだけで\\n幸せだよ', 0);
insert into room_unit_comments values (83, 100202, 2, 1, 1, 0, 1, 'えっと、その…\\nこんな所で\\nこういうことされると\\n恥ずかしいよ…', 0);
insert into room_unit_comments values (84, 100202, 2, 2, 1, 0, 1, 'え！\u3000む、虫っ！？\\n取って取って！\\nはやく～！', 0);
insert into room_unit_comments values (85, 100202, 2, 3, 1, 0, 1, 'あ、あの…実は\\n騎士クンのこと…\\nううん、やっぱり\\nなんでもない', 0);
insert into room_unit_comments values (86, 100202, 2, 4, 1, 0, 1, '男の子って\\nやっぱりおっきいね\\nその…手とか\\n他にもいろいろ…', 0);
insert into room_unit_comments values (87, 100202, 2, 101, 8, 0, 1, '騎士クンに\\n伝えたいことがあるの\\nとっても大切な…\\nこ、今度、話すね！', 0);
insert into room_unit_comments values (88, 100202, 2, 102, 8, 0, 1, 'ふふふっ…そんなとこ\\nツンツンしないで\\nくすぐったいよ～', 0);
insert into room_unit_comments values (89, 100202, 2, 1, 1, 1, 1, 'おはよう\\nよく眠れた？\u3000今日も\\n一日、頑張ろうね♪', 0);
insert into room_unit_comments values (90, 100202, 2, 2, 1, 2, 1, 'お腹空いちゃった…\\nそうだ。騎士クンも\\n一緒にお昼食べない？', 0);
insert into room_unit_comments values (91, 100202, 2, 3, 1, 3, 1, 'もうこんな時間…\\nそろそろ寝なくちゃ\\nおやすみなさい', 0);
insert into room_unit_comments values (92, 100202, 3, 1, 1, 0, 1, 'よし…\\nこれなら\\n褒めてもらえるかな？', 0);
insert into room_unit_comments values (93, 100202, 3, 2, 1, 0, 1, 'がんばることも\\n必要だけど\\nお休みも大切だよね', 0);
insert into room_unit_comments values (94, 100202, 3, 3, 1, 0, 1, 'かわいい～♪\\n騎士クンは\\nこういうのって好き？', 0);
insert into room_unit_comments values (95, 100202, 3, 4, 1, 0, 1, '戦う前にもこうやって\\n落ち着けたら\\nいいのに', 0);
insert into room_unit_comments values (96, 100202, 3, 5, 1, 0, 1, 'あの…！\\nよ、良かったら\\n一緒に…！', 0);
insert into room_unit_comments values (97, 100202, 3, 6, 1, 0, 1, '騎士クンと一緒に\\n冒険するなら\\n体力がないと…！', 0);
insert into room_unit_comments values (98, 100202, 3, 7, 1, 0, 1, '最近服のサイズが\\n合わないんだけど…\\n食べ過ぎなのかな？', 0);
insert into room_unit_comments values (99, 100202, 3, 8, 1, 0, 1, '…やっぱり\\n月刊恋愛指南は\\nためになる…', 0);
insert into room_unit_comments values (101, 100301, 1, 1, 1, 0, 1, '装備の手入れでも\\nしようかな…', 0);
insert into room_unit_comments values (102, 100301, 1, 2, 1, 0, 1, '次に鍛えるべきは\\n肉体面か精神面か\\nどちらにしよう…？', 0);
insert into room_unit_comments values (103, 100301, 1, 3, 1, 0, 1, 'ツムギが作ってくれた\\nこの服…一体\\nいつサイズを…？', 0);
insert into room_unit_comments values (104, 100301, 1, 4, 1, 0, 1, '仲間なんていらない\\nそう思ってた頃も\\nあったな…', 0);
insert into room_unit_comments values (105, 100301, 1, 5, 1, 0, 1, '考えごとをしていると\\nつい部屋中を\\n歩いてしまうな', 0);
insert into room_unit_comments values (106, 100301, 1, 101, 4, 0, 1, '彼は\\nどこまで強くなるのか\\n私も負けられないな', 0);
insert into room_unit_comments values (107, 100301, 1, 102, 8, 0, 1, '私が一本を取られる\\nなんてね…願い事は\\nもう決まったのかな？', 0);
insert into room_unit_comments values (108, 100301, 2, 1, 1, 0, 1, 'ああ、キミだったのか\\n人の気配がしたから\\n誰かと思ったよ', 0);
insert into room_unit_comments values (109, 100301, 2, 2, 1, 0, 1, '斬りかかるつもりなら\\nちゃんとかかってきて\\n…呼んだだけ？', 0);
insert into room_unit_comments values (110, 100301, 2, 3, 1, 0, 1, 'なに？\u3000私に相談？\\n戦いについてなら\\n喜んで', 0);
insert into room_unit_comments values (111, 100301, 2, 4, 1, 0, 1, '今のが突き？\\n軽い！\u3000もっと鋭く！\\nさあ、もう一回！', 0);
insert into room_unit_comments values (112, 100301, 2, 101, 4, 0, 1, 'ひゃっ！\u3000ど、どこを\\n触ってるの！？\\n…油断した', 0);
insert into room_unit_comments values (113, 100301, 2, 102, 8, 0, 1, 'キミにはこれからも\\n私のそばに…\\nいや、なんでもない', 0);
insert into room_unit_comments values (114, 100301, 2, 1, 1, 1, 1, 'おはよう\\n今日も充実した\\n一日にしていこう', 0);
insert into room_unit_comments values (115, 100301, 2, 2, 1, 2, 1, 'そろそろ\\nお茶の時間か\\nキミも一緒にどう？', 0);
insert into room_unit_comments values (116, 100301, 2, 3, 1, 3, 1, '遅くまで大変だね\\nまだ仕事があるなら\\n手伝おうか？', 0);
insert into room_unit_comments values (117, 100301, 3, 1, 1, 0, 1, '戦いを経てもなお\\n美しくあるように…\\nこれでよし♪', 0);
insert into room_unit_comments values (118, 100301, 3, 2, 1, 0, 1, '戦ってばかりで\\n休まないと、また\\nユイに怒られるな', 0);
insert into room_unit_comments values (119, 100301, 3, 3, 1, 0, 1, 'ヒヨリみたいに\\n練習相手に…\\nいや、やめておこう', 0);
insert into room_unit_comments values (120, 100301, 3, 4, 1, 0, 1, 'これはいい…\\n戦いの前の精神統一に\\nもってこいじゃないか', 0);
insert into room_unit_comments values (121, 100301, 3, 5, 1, 0, 1, '時々は落ち着いた\\n時間を過ごすのも\\n悪くない…', 0);
insert into room_unit_comments values (122, 100301, 3, 6, 1, 0, 1, '彼に負けないよう\\n私も更に強くなろう\\n共に戦うために！', 0);
insert into room_unit_comments values (123, 100301, 3, 7, 1, 0, 1, '食事は大切だけど\\n食べ過ぎには\\n注意しておこう…', 0);
insert into room_unit_comments values (124, 100301, 3, 8, 1, 0, 1, 'ユイ…！\\nこ、こんな本を\\n読んでいたのか…！', 0);
insert into room_unit_comments values (126, 100302, 1, 1, 1, 0, 1, '海だけじゃなくて\\n川でも釣りがしたいな\\n道具も新調しよう', 0);
insert into room_unit_comments values (127, 100302, 1, 2, 1, 0, 1, 'ツムギが作ってくれた\\nこの服…一体\\nいつサイズを…？', 0);
insert into room_unit_comments values (128, 100302, 1, 3, 1, 0, 1, '彼は\\nどこまで強くなるのか\\n私も負けられないな', 0);
insert into room_unit_comments values (129, 100302, 1, 4, 1, 0, 1, 'そろそろ修行の\\n内容を新しくしよう\\nより厳しいものにね', 0);
insert into room_unit_comments values (130, 100302, 1, 5, 1, 0, 1, '強くなって…誰にも\\n妨げられない自由な\\n生き方がしたい', 0);
insert into room_unit_comments values (131, 100302, 1, 101, 8, 0, 1, 'まさか風邪を引くとは\\n彼の看病のおかげで\\nすっかり良く\\nなったけど', 0);
insert into room_unit_comments values (132, 100302, 1, 102, 8, 0, 1, '私が一本を取られる\\nなんてね…願い事は\\nもう決まったのかな？', 0);
insert into room_unit_comments values (133, 100302, 2, 1, 1, 0, 1, 'どうしたの？\\nなんでもない？\\nそれなら良かった', 0);
insert into room_unit_comments values (134, 100302, 2, 2, 1, 0, 1, 'あんまり突っつくと\\nお返しするよ？\\n覚悟は出来てる？', 0);
insert into room_unit_comments values (135, 100302, 2, 3, 1, 0, 1, 'ねぇ、今度また\\n釣りに行かない？\\n大きいのを狙おう', 0);
insert into room_unit_comments values (136, 100302, 2, 4, 1, 0, 1, '修行がしたいの？\\nそれを早く言ってよ\\nすぐに出発しよう！', 0);
insert into room_unit_comments values (137, 100302, 2, 101, 8, 0, 1, 'ひょっとして\\n今のも一本だなんて\\n言わないよね？', 0);
insert into room_unit_comments values (138, 100302, 2, 102, 8, 0, 1, 'キミにはこれからも\\n私のそばに…\\nいや、なんでもない', 0);
insert into room_unit_comments values (139, 100302, 2, 1, 1, 1, 1, '今日は仕事？\\nそれとも修行？\\n良ければ付き合うよ', 0);
insert into room_unit_comments values (140, 100302, 2, 2, 1, 2, 1, '休息も時には\\n必要だと、仲間から\\n教わったよ', 0);
insert into room_unit_comments values (141, 100302, 2, 3, 1, 3, 1, '遅くまで大変だね\\nまだ仕事があるなら\\n手伝おうか？', 0);
insert into room_unit_comments values (142, 100302, 3, 1, 1, 0, 1, '髪の長さを少し\\n変えてみようかな…\\nわ、私は何を…！', 0);
insert into room_unit_comments values (143, 100302, 3, 2, 1, 0, 1, '休息があってこそ\\n万全な状態で\\n戦えるんだ', 0);
insert into room_unit_comments values (144, 100302, 3, 3, 1, 0, 1, 'ヒヨリみたいに\\n練習相手に…\\nいや、やめておこう', 0);
insert into room_unit_comments values (145, 100302, 3, 4, 1, 0, 1, '体と同様に\\n心もほぐれるね…\\nはぁ…', 0);
insert into room_unit_comments values (146, 100302, 3, 5, 1, 0, 1, '休む時は休む\\nヒヨリもそろそろ\\n覚えて欲しいな…', 0);
insert into room_unit_comments values (147, 100302, 3, 6, 1, 0, 1, '彼に負けないよう\\n私も更に強くなろう\\n共に戦うために！', 0);
insert into room_unit_comments values (148, 100302, 3, 7, 1, 0, 1, '修行のせいか\\n最近食べる量が\\n増えてきたような…', 0);
insert into room_unit_comments values (149, 100302, 3, 8, 1, 0, 1, 'ユイ…！\\nこ、こんな本を\\n読んでいたのか…！', 0);
insert into room_unit_comments values (151, 100401, 1, 1, 1, 0, 1, 'お宝の予感！\\n部屋中を\\n探検しちゃうぞ～', 0);
insert into room_unit_comments values (152, 100401, 1, 2, 1, 0, 1, '落とし穴…どこに\\n作ったんだっけ？', 0);
insert into room_unit_comments values (153, 100401, 1, 3, 1, 0, 1, 'うえ～ん！\\n…嘘泣きしたら\\n相手は油断するかな', 0);
insert into room_unit_comments values (154, 100401, 1, 4, 1, 0, 1, 'ハニートラップって\\nすごく甘いお菓子で\\nイタズラするのかな？', 0);
insert into room_unit_comments values (155, 100401, 1, 5, 1, 0, 1, 'かくれんぼする人\\nこの指、と～まれ！', 0);
insert into room_unit_comments values (156, 100401, 1, 101, 4, 0, 1, 'ミソギ以外の人に\\nイタズラされちゃ\\nダメだよ！', 0);
insert into room_unit_comments values (157, 100401, 1, 102, 8, 0, 1, 'ミソギと遊ぶ？\\nミソギに遊ばれる？', 0);
insert into room_unit_comments values (158, 100401, 2, 1, 1, 0, 1, 'いいこと思いついた！\\nい、イタズラとかじゃ\\nないよ～', 0);
insert into room_unit_comments values (159, 100401, 2, 2, 1, 0, 1, 'うわっ！？\\n\u3000にいちゃんが、\\nミソギにイタズラ？', 0);
insert into room_unit_comments values (160, 100401, 2, 3, 1, 0, 1, 'にいちゃんの\\n通りそうなところに\\nバナナの皮を…', 0);
insert into room_unit_comments values (161, 100401, 2, 4, 1, 0, 1, 'にいちゃんのオデコと\\nホッペと鼻と目と耳に\\n落書きを…', 0);
insert into room_unit_comments values (162, 100401, 2, 101, 4, 0, 1, 'ここ、ミソギ探検隊の\\n基地にしようよ！', 0);
insert into room_unit_comments values (163, 100401, 2, 102, 8, 0, 1, 'だ～れだ…って？\\nにいちゃんの声くらい\\nわかるよ！\\n大好きだもん♪', 0);
insert into room_unit_comments values (164, 100401, 2, 1, 1, 1, 1, 'にいちゃん、おはよ！\\n目覚まし時計を\\n止めておいたのに、\\nよく起きられたね～♪', 0);
insert into room_unit_comments values (165, 100401, 2, 2, 1, 2, 1, 'にいちゃんが\\n昼寝したら、\\nイタズラし放題♪', 0);
insert into room_unit_comments values (166, 100401, 2, 3, 1, 3, 1, '夜の探検も\\nおもしろそう！\\nねぇ出かけちゃダメ？', 0);
insert into room_unit_comments values (167, 100401, 3, 1, 1, 0, 1, 'イタズラには\\nお色気も必要…\\nうん、完璧！', 0);
insert into room_unit_comments values (168, 100401, 3, 2, 1, 0, 1, '座ったら、ブーッって\\nいう音が出たら、\\nおもしろいな～♪', 0);
insert into room_unit_comments values (169, 100401, 3, 3, 1, 0, 1, 'かわいい！\\nミソギ探検隊の\\nマスコットにしよう♪', 0);
insert into room_unit_comments values (170, 100401, 3, 4, 1, 0, 1, '吸うとくしゃみが\\n止まらなくなるお香を\\nここに…くしゅっ！', 0);
insert into room_unit_comments values (171, 100401, 3, 5, 1, 0, 1, 'にひひ…イタズラの\\n証拠、ここで\\n燃やしちゃおう～！', 0);
insert into room_unit_comments values (172, 100401, 3, 6, 1, 0, 1, '探検家は\\n体力勝負だよー！', 0);
insert into room_unit_comments values (173, 100401, 3, 7, 1, 0, 1, 'みんなに分けて\\nあげようかな～\\n激辛ソースも\\n入れちゃうけどね！', 0);
insert into room_unit_comments values (174, 100401, 3, 8, 1, 0, 1, 'こういう所に\\n宝の地図が\\n隠れてるんだよね～', 0);
insert into room_unit_comments values (176, 100402, 1, 1, 1, 0, 1, 'お宝の予感！\\n部屋中を\\n探検しちゃうぞ～', 0);
insert into room_unit_comments values (177, 100402, 1, 2, 1, 0, 1, 'うぅ、探検に出たい！\\nじっとしてなんか\\nいられないよ～！', 0);
insert into room_unit_comments values (178, 100402, 1, 3, 1, 0, 1, 'うえ～ん！\\n…嘘泣きしたら\\n相手は油断するかな', 0);
insert into room_unit_comments values (179, 100402, 1, 4, 1, 0, 1, 'ハニートラップって\\nすごく甘いお菓子で\\nイタズラするのかな？', 0);
insert into room_unit_comments values (180, 100402, 1, 5, 1, 0, 1, 'かくれんぼする人\\nこの指、と～まれ！', 0);
insert into room_unit_comments values (181, 100402, 1, 101, 8, 0, 1, 'にいちゃんのオデコと\\nホッペと鼻と目と耳に\\n落書きを…', 0);
insert into room_unit_comments values (182, 100402, 1, 102, 8, 0, 1, 'にいちゃんが喜ぶ\\nイタズラ、何かない\\nかな～？', 0);
insert into room_unit_comments values (183, 100402, 2, 1, 1, 0, 1, 'ミソギがしかけた\\nイタズラ\\n見つけられるかな？', 0);
insert into room_unit_comments values (184, 100402, 2, 2, 1, 0, 1, '探検する？\\n冒険する？\\nそれとも…\\nイタズラされる？', 0);
insert into room_unit_comments values (185, 100402, 2, 3, 1, 0, 1, '将来の夢は探検家！\\n探したい物はないけど', 0);
insert into room_unit_comments values (186, 100402, 2, 4, 1, 0, 1, 'にいちゃんに宿題！\\n落とし穴を10個\\n掘ること！', 0);
insert into room_unit_comments values (187, 100402, 2, 101, 8, 0, 1, 'だ～れだ…って？\\nにいちゃんの声くらい\\nわかるよ！\\n大好きだもん♪', 0);
insert into room_unit_comments values (188, 100402, 2, 102, 8, 0, 1, 'ここ、ミソギ探検隊の\\n基地にしようよ！', 0);
insert into room_unit_comments values (189, 100402, 2, 1, 1, 1, 1, 'にいちゃん\\n探検に行こうよ！\\n今からなら遭難しても\\n夜には帰れるよ！', 0);
insert into room_unit_comments values (190, 100402, 2, 2, 1, 2, 1, 'にいちゃんが昼寝したら\\nイタズラし放題♪', 0);
insert into room_unit_comments values (191, 100402, 2, 3, 1, 3, 1, '夜の探検も\\nおもしろそう！\\nねぇ出かけちゃダメ？', 0);
insert into room_unit_comments values (192, 100402, 3, 1, 1, 0, 1, 'イタズラには\\nお色気も必要…\\nうん、完璧！', 0);
insert into room_unit_comments values (193, 100402, 3, 2, 1, 0, 1, 'ゆっくりまったりして\\n次のイタズラを\\n考えよ～！', 0);
insert into room_unit_comments values (194, 100402, 3, 3, 1, 0, 1, 'かわいい！\\nミソギ探検隊の\\nマスコットにしよう♪', 0);
insert into room_unit_comments values (195, 100402, 3, 4, 1, 0, 1, '吸うとくしゃみが\\n止まらなくなるお香を\\nここに…くしゅっ！', 0);
insert into room_unit_comments values (196, 100402, 3, 5, 1, 0, 1, 'にひひ…イタズラの\\n証拠、ここで\\n燃やしちゃおう～！', 0);
insert into room_unit_comments values (197, 100402, 3, 6, 1, 0, 1, '探検家は\\n体力勝負だよー！', 0);
insert into room_unit_comments values (198, 100402, 3, 7, 1, 0, 1, '探検のおやつに\\nぴったりかも～！', 0);
insert into room_unit_comments values (199, 100402, 3, 8, 1, 0, 1, 'こういう所に\\n宝の地図が\\n隠れてるんだよね～', 0);
insert into room_unit_comments values (201, 100601, 1, 1, 1, 0, 1, '音楽は全部好きだけど\\n一番好きなのは\\nやっぱりジャズかな', 0);
insert into room_unit_comments values (202, 100601, 1, 2, 1, 0, 1, 'はぁ、はぁ…\\n一人でもいっぱい\\nしないと…\\n特訓…', 0);
insert into room_unit_comments values (203, 100601, 1, 3, 1, 0, 1, 'お姉ちゃんには\\nもっと自信を\\n持ってほしいなぁ', 0);
insert into room_unit_comments values (204, 100601, 1, 4, 1, 0, 1, 'お姉ちゃんのマネ\\nしちゃおうかな？', 0);
insert into room_unit_comments values (205, 100601, 1, 5, 1, 0, 1, '双子って、\\n好みのタイプも\\n似ちゃうのかな？', 0);
insert into room_unit_comments values (206, 100601, 1, 101, 4, 0, 1, 'お兄ちゃんと私は\\n相性抜群です♪', 0);
insert into room_unit_comments values (207, 100601, 1, 102, 8, 0, 1, 'もう待ちきれない…\\nお兄ちゃん、\\n早く帰って来て！', 0);
insert into room_unit_comments values (208, 100601, 2, 1, 1, 0, 1, 'あんっ…着替えよう\\nと思ったのに\\nお兄ちゃんのエッチ！', 0);
insert into room_unit_comments values (209, 100601, 2, 2, 1, 0, 1, 'うふふ、お兄ちゃん！\\n今日は何を\\nするんですか？', 0);
insert into room_unit_comments values (210, 100601, 2, 3, 1, 0, 1, 'そんなところ\\n触っちゃダメ♪', 0);
insert into room_unit_comments values (211, 100601, 2, 4, 1, 0, 1, 'お兄ちゃん、イジワル\\nしないでください…', 0);
insert into room_unit_comments values (212, 100601, 2, 101, 4, 0, 1, 'お兄ちゃん、もっと\\n上級編のテクニック、\\n教えてくださいね！', 0);
insert into room_unit_comments values (213, 100601, 2, 102, 8, 0, 1, 'コーチ、\\n今日も特訓\\nお願いします！', 0);
insert into room_unit_comments values (214, 100601, 2, 1, 1, 1, 1, 'おはようございます\\n昨夜は楽しかった\\nですね、うふふ♪', 0);
insert into room_unit_comments values (215, 100601, 2, 2, 1, 2, 1, 'こんな明るい時間から\\nす、するんですか…\\n二人っきりの特訓…', 0);
insert into room_unit_comments values (216, 100601, 2, 3, 1, 3, 1, '夜はこれからですよ\\nお兄ちゃん♪', 0);
insert into room_unit_comments values (217, 100601, 3, 1, 1, 0, 1, '世界一、かわいく\\nなるんだから♪', 0);
insert into room_unit_comments values (218, 100601, 3, 2, 1, 0, 1, '気持ちいい♪\\nもう立てないよ～', 0);
insert into room_unit_comments values (219, 100601, 3, 3, 1, 0, 1, 'かわいい♪\\nアカリのライバル\\nだね', 0);
insert into room_unit_comments values (220, 100601, 3, 4, 1, 0, 1, 'はぁ…気持ちいい、\\n私、このままダメに\\nなっちゃいそう…', 0);
insert into room_unit_comments values (221, 100601, 3, 5, 1, 0, 1, 'はぁ…アカリ、\\nとろけちゃう…', 0);
insert into room_unit_comments values (222, 100601, 3, 6, 1, 0, 1, 'はぁ…はぁはぁ、\\n私…もう…ダメ\\n限界です…！', 0);
insert into room_unit_comments values (223, 100601, 3, 7, 1, 0, 1, 'わぁ、おいしい～\\nけど食べ過ぎは美容に\\nよくないですよね', 0);
insert into room_unit_comments values (224, 100601, 3, 8, 1, 0, 1, 'この楽譜、\\nサックスで吹いて\\nみたいなぁ♪', 0);
insert into room_unit_comments values (226, 100602, 1, 1, 1, 0, 1, 'このごろ一人でいると\\nお兄ちゃんのこと\\nばかり考えちゃう…', 0);
insert into room_unit_comments values (227, 100602, 1, 2, 1, 0, 1, 'はぁ、はぁ…もっと\\nいっぱいしなくちゃ\\n…練習', 0);
insert into room_unit_comments values (228, 100602, 1, 3, 1, 0, 1, 'このお部屋、なんだか\\n落ち着きます…\\nお兄ちゃんが\\nいるから？', 0);
insert into room_unit_comments values (229, 100602, 1, 4, 1, 0, 1, 'みんなかわいいな～\\n世界一かわいくなる\\nのは、難しいな…', 0);
insert into room_unit_comments values (230, 100602, 1, 5, 1, 0, 1, '双子って、\\n好みのタイプも\\n似ちゃうのかな？', 0);
insert into room_unit_comments values (231, 100602, 1, 101, 8, 0, 1, 'いつか世界でいちばん\\nかわいくなって\\nお兄ちゃんと…', 0);
insert into room_unit_comments values (232, 100602, 1, 102, 8, 0, 1, 'もう待ちきれない…\\nお兄ちゃん、\\n早く帰って来て！', 0);
insert into room_unit_comments values (233, 100602, 2, 1, 1, 0, 1, 'あんっ…着替えよう\\nと思ったのに\\nお兄ちゃんのエッチ！', 0);
insert into room_unit_comments values (234, 100602, 2, 2, 1, 0, 1, '二人きりの秘密の特訓\\n今度はいつですか？\\n待ち遠しいです…', 0);
insert into room_unit_comments values (235, 100602, 2, 3, 1, 0, 1, 'え？\u3000ここでするの？\\nみんなの前で恥ずか\\nしいな…筋トレ', 0);
insert into room_unit_comments values (236, 100602, 2, 4, 1, 0, 1, 'お兄ちゃん、イジワル\\nしないでください…', 0);
insert into room_unit_comments values (237, 100602, 2, 101, 8, 0, 1, 'お兄ちゃんといると\\nわ、私…ドキドキ\\nしてきちゃう…', 0);
insert into room_unit_comments values (238, 100602, 2, 102, 8, 0, 1, 'コーチ、\\n今日も特訓\\nお願いします！', 0);
insert into room_unit_comments values (239, 100602, 2, 1, 1, 1, 1, 'おはようございます\\n昨夜は楽しかった\\nですね、うふふ♪', 0);
insert into room_unit_comments values (240, 100602, 2, 2, 1, 2, 1, 'お兄ちゃんに\\n食べてもらいたいなぁ\\n手作りのお昼ごはん', 0);
insert into room_unit_comments values (241, 100602, 2, 3, 1, 3, 1, 'お風呂入ってきますね\\nそのあとは…\\n二人でい～っぱい\\n遊びましょうね', 0);
insert into room_unit_comments values (242, 100602, 3, 1, 1, 0, 1, 'お姉ちゃんのマネ\\nしちゃおうかな？', 0);
insert into room_unit_comments values (243, 100602, 3, 2, 1, 0, 1, '気持ちいい♪\\nもう立てないよ～', 0);
insert into room_unit_comments values (244, 100602, 3, 3, 1, 0, 1, 'かわいい♪\\nアカリのライバル\\nだね', 0);
insert into room_unit_comments values (245, 100602, 3, 4, 1, 0, 1, 'はぁ…気持ちいい、\\n私、このままダメに\\nなっちゃいそう…', 0);
insert into room_unit_comments values (246, 100602, 3, 5, 1, 0, 1, 'あったか～い…\\nまるでお兄ちゃんが\\n隣にいる時みたい', 0);
insert into room_unit_comments values (247, 100602, 3, 6, 1, 0, 1, '汗をかくと\\n気持ちいいですよね', 0);
insert into room_unit_comments values (248, 100602, 3, 7, 1, 0, 1, 'お兄ちゃんの特訓に\\n付き合うために\\nたっぷり\\n食べておかないと♪', 0);
insert into room_unit_comments values (249, 100602, 3, 8, 1, 0, 1, 'この楽譜\\nサックスで吹いて\\nみたいなぁ♪', 0);
insert into room_unit_comments values (251, 100701, 1, 1, 1, 0, 1, 'プリン、プリン、\\nプリン、プリン、\\nプリン、プリン～♪', 0);
insert into room_unit_comments values (252, 100701, 1, 2, 1, 0, 1, 'う～ら～め～し～や～\\nなの～♪', 0);
insert into room_unit_comments values (253, 100701, 1, 3, 1, 0, 1, 'プリンがないなら\\n死んだほうがマシなの\\nあ、もう死んでたの～', 0);
insert into room_unit_comments values (254, 100701, 1, 4, 1, 0, 1, '幽霊の正体見たり、\\nミヤコなの～', 0);
insert into room_unit_comments values (255, 100701, 1, 5, 1, 0, 1, 'ミヤコがいきなり\\n消えたら、みんな\\n驚くかもなの～♪', 0);
insert into room_unit_comments values (256, 100701, 1, 101, 4, 0, 1, 'アイツがいて、\\nプリンもある。\\nきっとここが天国なの', 0);
insert into room_unit_comments values (257, 100701, 1, 102, 8, 0, 1, 'アイツはプリンセス\\nナイトじゃなくて\\nプリンナイトなの～', 0);
insert into room_unit_comments values (258, 100701, 2, 1, 1, 0, 1, '姿を消して、オマエを\\n見張ってやるの～\\nむふふ～♪', 0);
insert into room_unit_comments values (259, 100701, 2, 2, 1, 0, 1, 'もし成仏した先に\\nプリンがなかったら\\n地獄なの～…', 0);
insert into room_unit_comments values (260, 100701, 2, 3, 1, 0, 1, '右にプリン左にプリン\\n後ろにもプリン♪\\n前にはオマエなの～！', 0);
insert into room_unit_comments values (261, 100701, 2, 4, 1, 0, 1, '死んだ人には\\nお供え物をするの～\\nミヤコにも、プリンを\\n毎日お供えするの～', 0);
insert into room_unit_comments values (262, 100701, 2, 101, 4, 0, 1, 'たくさんオマエと\\n遊べて、\\n成仏しそうなくらい\\nうれしいの～！', 0);
insert into room_unit_comments values (263, 100701, 2, 102, 8, 0, 1, 'オマエのこと\\n気に入ったからずっと\\nとり憑いてやるの～', 0);
insert into room_unit_comments values (264, 100701, 2, 1, 1, 1, 1, 'う～\u3000眠いの…\\n二度目の二度寝を\\nするの…', 0);
insert into room_unit_comments values (265, 100701, 2, 2, 1, 2, 1, 'お昼ご飯はプリンなの\\n３時のおやつも、\\nプリンなの～', 0);
insert into room_unit_comments values (266, 100701, 2, 3, 1, 3, 1, 'ディナーは豪華に、\\nプリンのフルコース\\nなの～♪', 0);
insert into room_unit_comments values (267, 100701, 3, 1, 1, 0, 1, '体が透けちゃうから\\nうまく使えないの～', 0);
insert into room_unit_comments values (268, 100701, 3, 2, 1, 0, 1, 'まったりなの～\\nあとはプリンがあれば\\n完璧なの～', 0);
insert into room_unit_comments values (269, 100701, 3, 3, 1, 0, 1, 'む～…かわいいけど\\nプリンは分けて\\nあげないの～', 0);
insert into room_unit_comments values (270, 100701, 3, 4, 1, 0, 1, 'は～\u3000いい気分なの…\\n成仏しそうなの…', 0);
insert into room_unit_comments values (271, 100701, 3, 5, 1, 0, 1, 'も、もしかして\\nミヤコ、ここで\\n火葬されちゃうの？', 0);
insert into room_unit_comments values (272, 100701, 3, 6, 1, 0, 1, '幽霊には、体力も\\n筋力も関係ないの～！', 0);
insert into room_unit_comments values (273, 100701, 3, 7, 1, 0, 1, 'ぱくぱくモグモグ…\\nミヤコ、幽霊だけど、\\nお腹はすくの～', 0);
insert into room_unit_comments values (274, 100701, 3, 8, 1, 0, 1, 'プリンの写真集が\\nあればいいのに\\nなの～', 0);
insert into room_unit_comments values (276, 100702, 1, 1, 1, 0, 1, 'うらめしや～…\\n裏の飯より\\nプリンがいいの～', 0);
insert into room_unit_comments values (277, 100702, 1, 2, 1, 0, 1, 'プリン♪\u3000プリン♪\\nプリン♪\u3000なの～♪\u3000', 0);
insert into room_unit_comments values (278, 100702, 1, 3, 1, 0, 1, '世界中のケーキ屋が\\nプリンのおいしさを\\n競い合えばいいの～！\\n審査員はミヤコなの～', 0);
insert into room_unit_comments values (279, 100702, 1, 4, 1, 0, 1, '買ってきたプリンには\\n全部ミヤコの名前を\\n書いておくの～', 0);
insert into room_unit_comments values (280, 100702, 1, 5, 1, 0, 1, 'プリンがないなら\\n死んだほうがマシなの\\nあ、もう死んでたの～ ', 0);
insert into room_unit_comments values (281, 100702, 1, 101, 8, 0, 1, 'アイツがいて\\nプリンもある\\nきっとここが天国なの', 0);
insert into room_unit_comments values (282, 100702, 1, 102, 8, 0, 1, 'アイツはプリンセス\\nナイトじゃなくて\\nプリンナイトなの～', 0);
insert into room_unit_comments values (283, 100702, 2, 1, 1, 0, 1, '右にプリン左にプリン\\n後ろにもプリン♪\\n前にはオマエなの～！', 0);
insert into room_unit_comments values (284, 100702, 2, 2, 1, 0, 1, 'もし成仏した先に\\nプリンがなかったら\\n地獄なの～…', 0);
insert into room_unit_comments values (285, 100702, 2, 3, 1, 0, 1, '今日はオマエと\\nプリンを買いに行くの\\n強制なの～\u3000', 0);
insert into room_unit_comments values (286, 100702, 2, 4, 1, 0, 1, '死んだ人には\\nお供え物をするの～\\nミヤコにも、プリンを\\n毎日お供えするの～', 0);
insert into room_unit_comments values (287, 100702, 2, 101, 8, 0, 1, 'たくさんオマエと\\n遊べて\\n成仏しそうなくらい\\nうれしいの～！ ', 0);
insert into room_unit_comments values (288, 100702, 2, 102, 8, 0, 1, 'ミヤコのプリン\\nオマエにだったら\\n分けてあげるの～ ', 0);
insert into room_unit_comments values (289, 100702, 2, 1, 1, 1, 1, 'う～\u3000眠いの…\\n二度目の二度寝を\\nするの… ', 0);
insert into room_unit_comments values (290, 100702, 2, 2, 1, 2, 1, 'う～ら～め～し～や～\\n…明るい時間だと\\n驚かせないの～ ', 0);
insert into room_unit_comments values (291, 100702, 2, 3, 1, 3, 1, 'ひゅ～どろどろ～ん☆\\n真っ暗なうちに\\nいたずらしまくるの～♪', 0);
insert into room_unit_comments values (292, 100702, 3, 1, 1, 0, 1, '体が透けちゃうから\\nうまく使えないの～ ', 0);
insert into room_unit_comments values (293, 100702, 3, 2, 1, 0, 1, '落ち着くの～\\nいまプリン食べたら\\nきっといつもより\\nおいしいの～♪ ', 0);
insert into room_unit_comments values (294, 100702, 3, 3, 1, 0, 1, 'む～…かわいいけど\\nプリンは分けて\\nあげないの～\u3000', 0);
insert into room_unit_comments values (295, 100702, 3, 4, 1, 0, 1, 'は～\u3000いい気分なの…\\n成仏しそうなの…', 0);
insert into room_unit_comments values (296, 100702, 3, 5, 1, 0, 1, 'も、もしかして\\nミヤコ、ここで\\n火葬されちゃうの？ ', 0);
insert into room_unit_comments values (297, 100702, 3, 6, 1, 0, 1, '幽霊には、体力も\\n筋力も関係ないの～！\u3000', 0);
insert into room_unit_comments values (298, 100702, 3, 7, 1, 0, 1, 'おいしいの～\\nプリン味だったら\\nもっとおいしいの～ ', 0);
insert into room_unit_comments values (299, 100702, 3, 8, 1, 0, 1, 'プリンの写真集が\\nあればいいのに\\nなの～ ', 0);
insert into room_unit_comments values (301, 100801, 1, 1, 1, 0, 1, 'もし太陽が滅んでも\\nボクの美しさで大地を\\n照らしてあげる！', 0);
insert into room_unit_comments values (302, 100801, 1, 2, 1, 0, 1, 'う～ん、この部屋には\\nボクの肖像画や\\n彫像が必要だね', 0);
insert into room_unit_comments values (303, 100801, 1, 3, 1, 0, 1, '美の女神と愛の女神が\\nボクを作る時、本気\\n出しちゃったんだね♪', 0);
insert into room_unit_comments values (304, 100801, 1, 4, 1, 0, 1, 'ボクの誕生とともに\\n全ての美しさは過去の\\n遺物になったんだよ！', 0);
insert into room_unit_comments values (305, 100801, 1, 5, 1, 0, 1, 'うわっ昨日より可愛く\\nなってる。明日は\\nどうなっちゃう\\nのかな？', 0);
insert into room_unit_comments values (306, 100801, 1, 101, 4, 0, 1, 'このボクがいるだけで\\nあの人への\\nおもてなしだよね', 0);
insert into room_unit_comments values (307, 100801, 1, 102, 8, 0, 1, 'ボクの可愛さは、\\nふふ…あの人の\\nためのものさ', 0);
insert into room_unit_comments values (308, 100801, 2, 1, 1, 0, 1, 'ねぇ～、ボクって\\n可愛い？\\nふふ、知ってる☆', 0);
insert into room_unit_comments values (309, 100801, 2, 2, 1, 0, 1, '呼んだ？\\n可愛いボクと話したい\\n気持ちはわかるよ', 0);
insert into room_unit_comments values (310, 100801, 2, 3, 1, 0, 1, 'ふふ、ボクに触ると\\nキミも美しく\\nなっちゃうかもよ？', 0);
insert into room_unit_comments values (311, 100801, 2, 4, 1, 0, 1, 'どうかな、\\n今日のボク。\\n美しい？\u3000可愛い？\\nねえ、どっち？', 0);
insert into room_unit_comments values (312, 100801, 2, 101, 4, 0, 1, 'あの人も今、\\n可愛いボクのこと\\n考えてるかな…', 0);
insert into room_unit_comments values (313, 100801, 2, 102, 8, 0, 1, '美しい…\\nキミの瞳に写るボクは\\nより一層きれいだ', 0);
insert into room_unit_comments values (314, 100801, 2, 1, 1, 1, 1, '美しいボクの\\n美しい一日が\\n始まるよ！', 0);
insert into room_unit_comments values (315, 100801, 2, 2, 1, 2, 1, 'さーて、午後からも\\n可愛く美しく\\n華麗に優雅に♪', 0);
insert into room_unit_comments values (316, 100801, 2, 3, 1, 3, 1, 'バラの花びら\\nいっぱい浮かべた\\nお風呂に入ってから\\n寝ようっと♪', 0);
insert into room_unit_comments values (317, 100801, 3, 1, 1, 0, 1, '鏡よ、鏡。この世で\\n一番可愛いボクに\\nお似合いの人はだれ？', 0);
insert into room_unit_comments values (318, 100801, 3, 2, 1, 0, 1, 'ボクが座ったソファは\\n「美しいソファ」に\\nランクアップした！', 0);
insert into room_unit_comments values (319, 100801, 3, 3, 1, 0, 1, 'わあ、可愛い！\\n…まあ、ボクほど\\nじゃないけどさ！', 0);
insert into room_unit_comments values (320, 100801, 3, 4, 1, 0, 1, '服を羽織るように\\n香りをまとうボク…\\n美しい、美しすぎる！', 0);
insert into room_unit_comments values (321, 100801, 3, 5, 1, 0, 1, '気安く触ったら\\n火傷する…\\n炎はボクに似ているね', 0);
insert into room_unit_comments values (322, 100801, 3, 6, 1, 0, 1, '運動は苦手なのに\\n運動するボクの姿は\\n可愛いなんて…罪♪', 0);
insert into room_unit_comments values (323, 100801, 3, 7, 1, 0, 1, 'ボクが食べると、\\n食べ物まで\\n可愛いなあ…', 0);
insert into room_unit_comments values (324, 100801, 3, 8, 1, 0, 1, 'ボクが触った瞬間に、\\nこの本は美を\\n携えてしまうんだ', 0);
insert into room_unit_comments values (326, 100802, 1, 1, 1, 0, 1, 'ボクの美しさは\\nみんなのために\\nあるんだよ！', 0);
insert into room_unit_comments values (327, 100802, 1, 2, 1, 0, 1, 'う～ん、この部屋には\\nボクの肖像画や\\n彫像が必要だね', 0);
insert into room_unit_comments values (328, 100802, 1, 3, 1, 0, 1, 'これ以上美しくなると\\nボクをめぐって\\n大陸中で戦争が\\n始まっちゃう！', 0);
insert into room_unit_comments values (329, 100802, 1, 4, 1, 0, 1, 'ボクの誕生とともに\\n全ての美しさは過去の\\n遺物になったんだよ！', 0);
insert into room_unit_comments values (330, 100802, 1, 5, 1, 0, 1, 'ボクの可愛さについて\\nみんな話し合わない\\nのかな…？', 0);
insert into room_unit_comments values (331, 100802, 1, 101, 8, 0, 1, 'このボクがいるだけで\\nあの人への\\nおもてなしだよね', 0);
insert into room_unit_comments values (332, 100802, 1, 102, 8, 0, 1, 'あの人も今\\n可愛いボクのこと\\n考えてるかな…', 0);
insert into room_unit_comments values (333, 100802, 2, 1, 1, 0, 1, '美の女神と愛の女神が\\nボクを作る時、本気\\n出しちゃったんだね♪', 0);
insert into room_unit_comments values (334, 100802, 2, 2, 1, 0, 1, 'ボクの美しさに嫉妬\\nしたって意味ないよね\\n次元が違うんだから', 0);
insert into room_unit_comments values (335, 100802, 2, 3, 1, 0, 1, 'ボクの化粧品使う？\\n一緒に可愛くなろうよ', 0);
insert into room_unit_comments values (336, 100802, 2, 4, 1, 0, 1, 'ボクがいるだけで\\nこの部屋は美の神殿♪\\nランドソルの新たな\\n観光名所になるね！', 0);
insert into room_unit_comments values (337, 100802, 2, 101, 8, 0, 1, '呼んだ？\\n可愛いボクと話したい\\n気持ちはわかるよ', 0);
insert into room_unit_comments values (338, 100802, 2, 102, 8, 0, 1, '美しい…\\nキミの瞳に写るボクは\\nより一層綺麗だ', 0);
insert into room_unit_comments values (339, 100802, 2, 1, 1, 1, 1, '朝日と共に\\nボクの美しさも\\n周りを照らすよ', 0);
insert into room_unit_comments values (340, 100802, 2, 2, 1, 2, 1, 'ボクの美しさを\\n維持するために\\nお昼ご飯食べなくちゃ', 0);
insert into room_unit_comments values (341, 100802, 2, 3, 1, 3, 1, 'バラの花びらいっぱい\\n浮かべたお風呂に\\n入ってから\\n寝ようっと♪', 0);
insert into room_unit_comments values (342, 100802, 3, 1, 1, 0, 1, '鏡よ、鏡。この世で\\n一番可愛いボクに\\nお似合いの人はだれ？', 0);
insert into room_unit_comments values (343, 100802, 3, 2, 1, 0, 1, 'ボクが座ったソファは\\n「美しいソファ」に\\nランクアップした！', 0);
insert into room_unit_comments values (344, 100802, 3, 3, 1, 0, 1, '可愛いものを\\n可愛いって言える\\nボクって可愛いよね！', 0);
insert into room_unit_comments values (345, 100802, 3, 4, 1, 0, 1, '服を羽織るように\\n香りをまとうボク…\\n美しい、美しすぎる！', 0);
insert into room_unit_comments values (346, 100802, 3, 5, 1, 0, 1, '冷えは美容の大敵\\nなんだから！\\nここ、ボクの場所ね！', 0);
insert into room_unit_comments values (347, 100802, 3, 6, 1, 0, 1, '運動は苦手なのに\\n運動するボクの姿は\\n可愛いなんて…罪♪', 0);
insert into room_unit_comments values (348, 100802, 3, 7, 1, 0, 1, 'ボクが食べると\\n食べ物まで\\n可愛いなあ…', 0);
insert into room_unit_comments values (349, 100802, 3, 8, 1, 0, 1, 'ボクが触った瞬間に\\nこの本は美を\\n携えてしまうんだ', 0);
insert into room_unit_comments values (351, 100901, 1, 1, 1, 0, 1, '「第１０部２０章\\n終焉戦争、開幕」\\n…これでよし！', 0);
insert into room_unit_comments values (352, 100901, 1, 2, 1, 0, 1, '今度シグルドに\\n私の魔法を一つ\\n伝授してやるか', 0);
insert into room_unit_comments values (353, 100901, 1, 3, 1, 0, 1, 'ここでは風が\\n吹いてこないな…\\n換気したい！', 0);
insert into room_unit_comments values (354, 100901, 1, 4, 1, 0, 1, 'そうだ、ナナカに\\nこの間借りた本を\\n返さないと…', 0);
insert into room_unit_comments values (355, 100901, 1, 5, 1, 0, 1, 'まずは包帯をとって\\n手から龍の形の\\n炎を出して…', 0);
insert into room_unit_comments values (356, 100901, 1, 101, 4, 0, 1, 'シグルド…\\n今頃何処で何を\\nしているのだろう…', 0);
insert into room_unit_comments values (357, 100901, 1, 102, 8, 0, 1, '最近、彼の姿が\\nまぶしく見える…\\nどうして…？', 0);
insert into room_unit_comments values (358, 100901, 2, 1, 1, 0, 1, '辞書を知らないか？\\n…探している\\n理由は聞くな', 0);
insert into room_unit_comments values (359, 100901, 2, 2, 1, 0, 1, 'そうだ！\\n貴様の技にも\\n名前をつけてやろう！', 0);
insert into room_unit_comments values (360, 100901, 2, 3, 1, 0, 1, '私に触れても力を\\n奪われないのは\\n貴様くらいだぞ？', 0);
insert into room_unit_comments values (361, 100901, 2, 4, 1, 0, 1, '何事だ？\\nまさか我が瞳に\\n魅入られたのか？', 0);
insert into room_unit_comments values (362, 100901, 2, 101, 4, 0, 1, '貴様がそばにいると\\nとても安心できる…\\n…不思議だ', 0);
insert into room_unit_comments values (363, 100901, 2, 102, 8, 0, 1, 'い、いきなり目の前に\\n現れるな！\u3000ドキドキ\\nするだろうがぁ！', 0);
insert into room_unit_comments values (364, 100901, 2, 1, 1, 1, 1, '「覚醒」めたか…\\n行くぞ、悪を討つ\\n戦いに出発だ！', 0);
insert into room_unit_comments values (365, 100901, 2, 2, 1, 2, 1, '昼間は「ヤツら」も\\n襲ってはこない…\\n束の間の休息だ', 0);
insert into room_unit_comments values (366, 100901, 2, 3, 1, 3, 1, 'どうした？\u3000夜はまだ\\nこれから…ふぁ…\\nね、眠くなどないぞ！', 0);
insert into room_unit_comments values (367, 100901, 3, 1, 1, 0, 1, '何か足りないな…\\n暗黒騎士の紋章を\\n作ろうかな', 0);
insert into room_unit_comments values (368, 100901, 3, 2, 1, 0, 1, 'くっ…！\\n私を眠りの国へ\\n誘うつもりか！', 0);
insert into room_unit_comments values (369, 100901, 3, 3, 1, 0, 1, 'このようなものに\\n懐柔されるものか！\\n…されるものか！', 0);
insert into room_unit_comments values (370, 100901, 3, 4, 1, 0, 1, 'これを使えば\\nもっとそれっぽい\\n雰囲気が出そうだ', 0);
insert into room_unit_comments values (371, 100901, 3, 5, 1, 0, 1, 'これが我らの求めた\\n安寧か…\\n悪くない…', 0);
insert into room_unit_comments values (372, 100901, 3, 6, 1, 0, 1, 'この程度\\n前世での激闘に\\n比べれば…！', 0);
insert into room_unit_comments values (373, 100901, 3, 7, 1, 0, 1, '最近金欠でな…\\nいやぁありがたい…', 0);
insert into room_unit_comments values (374, 100901, 3, 8, 1, 0, 1, 'ここにも\\n前世の記憶が\\n眠っていたとは…', 0);
insert into room_unit_comments values (376, 100902, 1, 1, 1, 0, 1, '「第１３部１章\\n閃光のシグルド」\\n…ついに登場だな', 0);
insert into room_unit_comments values (377, 100902, 1, 2, 1, 0, 1, '何故だ…何故\\nこうもあっさり金欠に\\n逆戻りするのだ！？', 0);
insert into room_unit_comments values (378, 100902, 1, 3, 1, 0, 1, 'やはり転生者という\\n設定はカッコイイ…\\n天才だな、私！', 0);
insert into room_unit_comments values (379, 100902, 1, 4, 1, 0, 1, 'そうだ、ナナカに\\nこの間借りた本を\\n返さないと…', 0);
insert into room_unit_comments values (380, 100902, 1, 5, 1, 0, 1, 'そろそろ今日の分の\\n魔力を溜めないと\\nまた魔力切れが…', 0);
insert into room_unit_comments values (381, 100902, 1, 101, 1, 0, 1, '最近奴がそばに\\nいるだけで、鼓動が\\n早くなるのは何故だ？', 0);
insert into room_unit_comments values (382, 100902, 1, 102, 8, 0, 1, 'シ、シグルド…！\\nだめだ…妄想でも\\n上手く言えない…', 0);
insert into room_unit_comments values (383, 100902, 2, 1, 8, 0, 1, 'なんだ？\u3000新たな\\n賞金の情報を\\n持ってきたのか？', 0);
insert into room_unit_comments values (384, 100902, 2, 2, 1, 0, 1, '名乗りやポーズは\\nその強度で相手を\\n圧倒する技術だ', 0);
insert into room_unit_comments values (385, 100902, 2, 3, 1, 0, 1, 'いいか、魔法の\\n詠唱中は絶対に\\n声をかけるなよ？', 0);
insert into room_unit_comments values (386, 100902, 2, 4, 1, 0, 1, 'おお、ちょうど今\\n貴様専用の設定集を\\n作成中だぞ！', 0);
insert into room_unit_comments values (387, 100902, 2, 101, 1, 0, 1, '貴様がそばにいると\\nとても安心できる…\\n…不思議だ', 0);
insert into room_unit_comments values (388, 100902, 2, 102, 8, 0, 1, 'い、いきなり目の前に\\n現れるな！\u3000ドキドキ\\nするだろうがぁ！', 0);
insert into room_unit_comments values (389, 100902, 2, 1, 8, 1, 1, '夜更かしのせいか\\nまだ眠気が…いや！\\nこれは組織の罠だ！', 0);
insert into room_unit_comments values (390, 100902, 2, 2, 1, 2, 1, '平穏な時に\\n出来るだけ魔力を\\n溜めておかねば…', 0);
insert into room_unit_comments values (391, 100902, 2, 3, 1, 3, 1, '夜になると、力が\\n増した気分になるな\\n…なりませんか？', 0);
insert into room_unit_comments values (392, 100902, 3, 1, 1, 0, 1, '何か足りないな…\\n暗黒騎士の紋章を\\n作ろうかな', 0);
insert into room_unit_comments values (393, 100902, 3, 2, 1, 0, 1, 'お、おのれ\\nヒュプノス…\\n私は負けないぞ…', 0);
insert into room_unit_comments values (394, 100902, 3, 3, 1, 0, 1, 'くっくっくっ…\\n貴様は特別団員に\\nしてやろう', 0);
insert into room_unit_comments values (395, 100902, 3, 4, 1, 0, 1, 'これを使えば\\nもっとそれっぽい\\n雰囲気が出そうだ', 0);
insert into room_unit_comments values (396, 100902, 3, 5, 1, 0, 1, 'これが我らの求めた\\n安寧か…\\n悪くない…', 0);
insert into room_unit_comments values (397, 100902, 3, 6, 1, 0, 1, '新たな戦いに備えて\\n魔力だけでなく\\n体力も鍛えねば！', 0);
insert into room_unit_comments values (398, 100902, 3, 7, 1, 0, 1, '食事は魔力に\\n変換する体力の\\n元になるのだ！', 0);
insert into room_unit_comments values (399, 100902, 3, 8, 1, 0, 1, 'フフフ…\\nこれを覚えれば\\nもっと強く…！', 0);
insert into room_unit_comments values (401, 101001, 1, 1, 1, 0, 1, '王子はんほんまに\\nはんなりしてて、\\n王子はんって感じやわ', 0);
insert into room_unit_comments values (402, 101001, 1, 2, 1, 0, 1, 'この絵本の王子はん、\\n王子はんみたいで\\nええなぁ♪', 0);
insert into room_unit_comments values (403, 101001, 1, 3, 1, 0, 1, 'うちがガラスの靴を\\n落としたら、王子はん\\n見つけてくれるやろか', 0);
insert into room_unit_comments values (404, 101001, 1, 4, 1, 0, 1, 'マホマホ王国\\n次期国王の王子はん\\n…見てみたいわ～', 0);
insert into room_unit_comments values (405, 101001, 1, 5, 1, 0, 1, '王子はんのために\\n糸を紡いで、\\n編み物でもしまひょか', 0);
insert into room_unit_comments values (406, 101001, 1, 101, 4, 0, 1, 'マホ姫と王子はん、\\n絵本の世界より\\nベストカップルや', 0);
insert into room_unit_comments values (407, 101001, 1, 102, 8, 0, 1, '王子はんと\\n一緒にいると\\n胸がせわしのー\\nうごいてかなん', 0);
insert into room_unit_comments values (408, 101001, 2, 1, 1, 0, 1, 'うちら並んでたら\\nお雛様みたいに\\n見えると思いまへん？', 0);
insert into room_unit_comments values (409, 101001, 2, 2, 1, 0, 1, '王子はんを\\n国に連れて帰ったら\\nみんな大歓迎して\\nくれるやろなぁ', 0);
insert into room_unit_comments values (410, 101001, 2, 3, 1, 0, 1, '王子はんは、\\n絵本から出てきた人\\nみたいやね～', 0);
insert into room_unit_comments values (411, 101001, 2, 4, 1, 0, 1, 'うちの話し方\\nのんびりしてます\\nやろか？', 0);
insert into room_unit_comments values (412, 101001, 2, 101, 4, 0, 1, 'マホ姫の手は\\nつべたいから、\\n王子はんが温めて？', 0);
insert into room_unit_comments values (413, 101001, 2, 102, 8, 0, 1, 'うちがもし悪い魔法に\\nかかったら、王子はん\\n口づけしてくれはる？', 0);
insert into room_unit_comments values (414, 101001, 2, 1, 1, 1, 1, '朝は小鳥はんも\\nおなかがすいてるから\\nよう飛び回りはるねえ', 0);
insert into room_unit_comments values (415, 101001, 2, 2, 1, 2, 1, 'お茶請けはお大福が\\nよろしおすけど\\nクッキーもええなあ', 0);
insert into room_unit_comments values (416, 101001, 2, 3, 1, 3, 1, 'うち、普段から\\n夢見がちやけど…\\nほんに眠い時間やわぁ', 0);
insert into room_unit_comments values (417, 101001, 3, 1, 1, 0, 1, '王子はんに\\n会いに行くなら、\\nおめかしせな\\nあかんなぁ', 0);
insert into room_unit_comments values (418, 101001, 3, 2, 1, 0, 1, 'はんなりした\\nええお椅子やわぁ\\nほっこりしますなあ', 0);
insert into room_unit_comments values (419, 101001, 3, 3, 1, 0, 1, 'かいらしもんが\\nいっぱいで、\\nマホマホ王国みたい\\nやわぁ', 0);
insert into room_unit_comments values (420, 101001, 3, 4, 1, 0, 1, '心地ええどす。まるで\\nお花畑にいるようやね', 0);
insert into room_unit_comments values (421, 101001, 3, 5, 1, 0, 1, 'ぽかぽかどす。\\n心まであったかく\\nなりますわぁ', 0);
insert into room_unit_comments values (422, 101001, 3, 6, 1, 0, 1, 'はぁはぁ、お姫はんは\\n激しい運動は\\nしぃひんもんどす～', 0);
insert into room_unit_comments values (423, 101001, 3, 7, 1, 0, 1, 'もぐもぐ…あんまり\\n速う食べられへんけど\\n美味しいわぁ', 0);
insert into room_unit_comments values (424, 101001, 3, 8, 1, 0, 1, '絵本、絵本～\\n幸せやわぁ♪', 0);
insert into room_unit_comments values (426, 101002, 1, 1, 1, 0, 1, '王子はんにとって\\n自慢の姫になるえ～', 0);
insert into room_unit_comments values (427, 101002, 1, 2, 1, 0, 1, 'カボチャの馬車に\\nガラスの靴…\\n欲しいなぁ', 0);
insert into room_unit_comments values (428, 101002, 1, 3, 1, 0, 1, 'うちがガラスの靴を\\n落としたら、王子はん\\n見つけてくれるやろか', 0);
insert into room_unit_comments values (429, 101002, 1, 4, 1, 0, 1, 'マホマホ王国\\n次期国王の王子はん\\n…見てみたいわ～', 0);
insert into room_unit_comments values (430, 101002, 1, 5, 1, 0, 1, 'ほんまなぁ\\nこの絵本が面白いんよ\\n王子はんに\\n読んであげよ', 0);
insert into room_unit_comments values (431, 101002, 1, 101, 8, 0, 1, 'マホ姫と王子はん\\n絵本の世界より\\nベストカップルや', 0);
insert into room_unit_comments values (432, 101002, 1, 102, 8, 0, 1, '王子はんと\\n一緒にいると\\n胸がせわしのー\\nうごいてかなん', 0);
insert into room_unit_comments values (433, 101002, 2, 1, 1, 0, 1, 'たまには、王子はんの\\n好きな絵本も\\n知りたいな～', 0);
insert into room_unit_comments values (434, 101002, 2, 2, 1, 0, 1, '王子はんを\\n国に連れて帰ったら\\nみんな大歓迎して\\nくれるやろなぁ', 0);
insert into room_unit_comments values (435, 101002, 2, 3, 1, 0, 1, 'そのうち、王子はんの\\nお国にも連れてって\\nもらえますやろか？', 0);
insert into room_unit_comments values (436, 101002, 2, 4, 1, 0, 1, '絵本読むんも\\nええなぁ…', 0);
insert into room_unit_comments values (437, 101002, 2, 101, 8, 0, 1, 'うちがもし悪い魔法に\\nかかったら、王子はん\\n口づけしてくれはる？', 0);
insert into room_unit_comments values (438, 101002, 2, 102, 8, 0, 1, 'うちら並んでたら\\nお雛様みたいに\\n見えると思いまへん？', 0);
insert into room_unit_comments values (439, 101002, 2, 1, 1, 1, 1, '朝は小鳥はんも\\nおなかがすいてるから\\nよう飛び回りはるねえ', 0);
insert into room_unit_comments values (440, 101002, 2, 2, 1, 2, 1, 'マホマホ王国では\\nこの時分は\\nみんなお昼寝\\nしてたんよ', 0);
insert into room_unit_comments values (441, 101002, 2, 3, 1, 3, 1, '夜に飛んだり鳴いたり\\nする鳥はんもおるんよ\\n昼は寝てはるんかねぇ', 0);
insert into room_unit_comments values (442, 101002, 3, 1, 1, 0, 1, '王子はんに\\n会いに行くなら\\nおめかしせな\\nあかんなぁ', 0);
insert into room_unit_comments values (443, 101002, 3, 2, 1, 0, 1, '王子はんも一緒に\\nゆっくりしていっても\\nええんよ？', 0);
insert into room_unit_comments values (444, 101002, 3, 3, 1, 0, 1, 'かいらしい子やねぇ\\nうちとお友だちに\\nなってくれるん？', 0);
insert into room_unit_comments values (445, 101002, 3, 4, 1, 0, 1, '癒しアイテムって\\nほんま、好っきゃわぁ', 0);
insert into room_unit_comments values (446, 101002, 3, 5, 1, 0, 1, 'うちのお城にも\\nほしいわぁ。帰ったら\\nさっそく準備せな\\nあかんなぁ', 0);
insert into room_unit_comments values (447, 101002, 3, 6, 1, 0, 1, '部屋の中で運動\\nできるのも、なかなか\\n面白いもんやわぁ', 0);
insert into room_unit_comments values (448, 101002, 3, 7, 1, 0, 1, 'おいひいわ～\\nマホマホ王国には\\nない味やわぁ', 0);
insert into room_unit_comments values (449, 101002, 3, 8, 1, 0, 1, 'しっかり知識を\\n身につけんと\\n魔法も使えへん\\nからなぁ', 0);
insert into room_unit_comments values (451, 101101, 1, 1, 1, 0, 1, '１、２、３、４…\\nあれ？\u3000いま、\\n何段目まで\\n編んだっけ？', 0);
insert into room_unit_comments values (452, 101101, 1, 2, 1, 0, 1, 'おやつのケーキは\\n苺かチョコ…\\nどっちも食べよう！', 0);
insert into room_unit_comments values (453, 101101, 1, 3, 1, 0, 1, 'い、いけない！\\n縫い針落としちゃった', 0);
insert into room_unit_comments values (454, 101101, 1, 4, 1, 0, 1, 'ケーキをクレープで\\n巻いたら…\\n大ヒット商品の予感！', 0);
insert into room_unit_comments values (455, 101101, 1, 5, 1, 0, 1, '「どうだ！妹暮らし」\\nってことわざ\\nなかったっけ？', 0);
insert into room_unit_comments values (456, 101101, 1, 101, 4, 0, 1, 'お兄ちゃんに、\\nお洋服でも\\n作ろうかな？', 0);
insert into room_unit_comments values (457, 101101, 1, 102, 8, 0, 1, 'ここがお兄ちゃんの\\n部屋…\\nドキドキしちゃう～', 0);
insert into room_unit_comments values (458, 101101, 2, 1, 1, 0, 1, 'ねぇ、おにいちゃん\\n一緒に、スイーツでも\\n食べにいかない？', 0);
insert into room_unit_comments values (459, 101101, 2, 2, 1, 0, 1, 'クリームついてた！？\\nさっき食べた、\\nケーキかも…！', 0);
insert into room_unit_comments values (460, 101101, 2, 3, 1, 0, 1, '勉強、見てくれるん\\nですか？\u3000やった～♪', 0);
insert into room_unit_comments values (461, 101101, 2, 4, 1, 0, 1, '服がほつれてますよ？\\n直してあげます！', 0);
insert into room_unit_comments values (462, 101101, 2, 101, 4, 0, 1, '私をお嫁さんに\\nしたいなら、予約は\\nお早目に、ですよ♪', 0);
insert into room_unit_comments values (463, 101101, 2, 102, 8, 0, 1, 'ねぇねぇお兄ちゃん！\\n…えへへ、\\n呼んでみただけ♪', 0);
insert into room_unit_comments values (464, 101101, 2, 1, 1, 1, 1, '今日も１日\\n勉強がんばります！\\n…少しは遊ぼうかな', 0);
insert into room_unit_comments values (465, 101101, 2, 2, 1, 2, 1, 'お昼休憩に\\n甘いものが\\n食べたいです～', 0);
insert into room_unit_comments values (466, 101101, 2, 3, 1, 3, 1, 'ねむいです～\\nでももうちょっと\\n勉強しないと～…', 0);
insert into room_unit_comments values (467, 101101, 3, 1, 1, 0, 1, 'この服、かわいい♪\\n今度作って\\nみよっと～！', 0);
insert into room_unit_comments values (468, 101101, 3, 2, 1, 0, 1, '勉強で疲れたから\\n休憩しよ～っと', 0);
insert into room_unit_comments values (469, 101101, 3, 3, 1, 0, 1, 'かわいい♪\\n私が服を作って\\nあげよっか？', 0);
insert into room_unit_comments values (470, 101101, 3, 4, 1, 0, 1, 'リラックスできます～\\nお兄ちゃんが隣に\\nいるみたい！', 0);
insert into room_unit_comments values (471, 101101, 3, 5, 1, 0, 1, 'のんびりしたら、\\nまた勉強しよっと！', 0);
insert into room_unit_comments values (472, 101101, 3, 6, 1, 0, 1, '運動すると勉強も\\nはかどるよね！', 0);
insert into room_unit_comments values (473, 101101, 3, 7, 1, 0, 1, 'おいし～！\\nお兄ちゃんにも\\nおすそ上げしますね！', 0);
insert into room_unit_comments values (474, 101101, 3, 8, 1, 0, 1, 'お兄ちゃんの記憶を\\n戻す方法、どこかに\\n書いてないかな？', 0);
insert into room_unit_comments values (476, 101102, 1, 1, 1, 0, 1, 'ケーキの食べ過ぎで\\nお腹が…うぅ、\\n因果横暴だよー…', 0);
insert into room_unit_comments values (477, 101102, 1, 2, 1, 0, 1, '１、２、３、４…\\nあれ？\u3000いま、\\n何段目まで\\n編んだっけ？', 0);
insert into room_unit_comments values (478, 101102, 1, 3, 1, 0, 1, 'い、いけない！\\n縫い針落としちゃった', 0);
insert into room_unit_comments values (479, 101102, 1, 4, 1, 0, 1, '笑う時には服着ます！', 0);
insert into room_unit_comments values (480, 101102, 1, 5, 1, 0, 1, '「どうだ！妹暮らし」\\nってことわざ\\nなかったっけ？', 0);
insert into room_unit_comments values (481, 101102, 1, 101, 8, 0, 1, 'お兄ちゃんに、\\nお洋服でも\\n作ろうかな？', 0);
insert into room_unit_comments values (482, 101102, 1, 102, 8, 0, 1, 'お兄ちゃんが帰って\\nきたら、何して遊ぼう\\nかな～？', 0);
insert into room_unit_comments values (483, 101102, 2, 1, 1, 0, 1, '勉強、見てくれるん\\nですか？\u3000やった～♪', 0);
insert into room_unit_comments values (484, 101102, 2, 2, 1, 0, 1, 'クリームついてた！？\\nさっき食べた、\\nケーキかも…！', 0);
insert into room_unit_comments values (485, 101102, 2, 3, 1, 0, 1, 'おにいちゃん！\\nそろそろ、おやつに\\nしませんか？', 0);
insert into room_unit_comments values (486, 101102, 2, 4, 1, 0, 1, '勉強は…\\n明日にしようっと', 0);
insert into room_unit_comments values (487, 101102, 2, 101, 8, 0, 1, '妹だけど、大人な\\nレディですからね！', 0);
insert into room_unit_comments values (488, 101102, 2, 102, 8, 0, 1, 'な、ナデナデとか\\n恥ずかしいな～', 0);
insert into room_unit_comments values (489, 101102, 2, 1, 1, 1, 1, '今日も１日\\n勉強がんばります！\\n…少しは遊ぼうかな', 0);
insert into room_unit_comments values (490, 101102, 2, 2, 1, 2, 1, 'お昼休憩に\\n甘いものが\\n食べたいです～', 0);
insert into room_unit_comments values (491, 101102, 2, 3, 1, 3, 1, 'お兄ちゃんは\\n夜強いんですね\\n私は眠くて…', 0);
insert into room_unit_comments values (492, 101102, 3, 1, 1, 0, 1, '服装や髪形が変わると\\n気分も変わるよね', 0);
insert into room_unit_comments values (493, 101102, 3, 2, 1, 0, 1, 'ここで寝ちゃったら\\n受験勉強が～…\\nぐーー', 0);
insert into room_unit_comments values (494, 101102, 3, 3, 1, 0, 1, 'かわいい♪\\n私が服を作って\\nあげよっか？', 0);
insert into room_unit_comments values (495, 101102, 3, 4, 1, 0, 1, 'いまならどんな試験も\\n合格できそうです！', 0);
insert into room_unit_comments values (496, 101102, 3, 5, 1, 0, 1, 'のんびりしたら\\nまた勉強しよっと！', 0);
insert into room_unit_comments values (497, 101102, 3, 6, 1, 0, 1, 'お兄ちゃんを\\n守るためには\\n毎日、鍛えなくちゃ！', 0);
insert into room_unit_comments values (498, 101102, 3, 7, 1, 0, 1, 'おいし～！\\nお兄ちゃんにも\\nおすそ上げしますね！', 0);
insert into room_unit_comments values (499, 101102, 3, 8, 1, 0, 1, 'この本の服\\nかわいいなぁ♪\\n私に作れるかな？', 0);
insert into room_unit_comments values (501, 101201, 1, 1, 1, 0, 1, 'う～ん、今なら\\nどこでだって\\n眠れちゃいそう…', 0);
insert into room_unit_comments values (502, 101201, 1, 2, 1, 0, 1, 'たくさん寝すぎて、\\n夢の中か現実か\\nわかんなく\\nなっちゃうんだよね～', 0);
insert into room_unit_comments values (503, 101201, 1, 3, 1, 0, 1, '…はっ！？\\nね、寝てないよ？\\nホントだよっ', 0);
insert into room_unit_comments values (504, 101201, 1, 4, 1, 0, 1, 'ぐっすり眠って\\nパワーを\\nフルチャージっ☆', 0);
insert into room_unit_comments values (505, 101201, 1, 5, 1, 0, 1, 'もし、超能力のことが\\nバレたら…ブルブル', 0);
insert into room_unit_comments values (506, 101201, 1, 101, 4, 0, 1, 'テレパシーで\\nキミの心を覗けたら\\n…なんてね！', 0);
insert into room_unit_comments values (507, 101201, 1, 102, 8, 0, 1, 'キミを抱き枕に…\\nじょ、冗談冗談！', 0);
insert into room_unit_comments values (508, 101201, 2, 1, 1, 0, 1, 'ん～、なになに？\\n一緒にお昼寝する？', 0);
insert into room_unit_comments values (509, 101201, 2, 2, 1, 0, 1, '忘れ物しちゃった。\\nま、いっか！\\nえ、ダメ？', 0);
insert into room_unit_comments values (510, 101201, 2, 3, 1, 0, 1, 'おおっ、相談ごと？\\nなにかな\\nなにかな～？', 0);
insert into room_unit_comments values (511, 101201, 2, 4, 1, 0, 1, 'う～ん、もしかして\\nキミにも仲良しになる\\n超能力があるのかも！', 0);
insert into room_unit_comments values (512, 101201, 2, 101, 4, 0, 1, 'むむ～…どう？\\nテレパシーで、私の\\n気持ちを送ったよ！', 0);
insert into room_unit_comments values (513, 101201, 2, 102, 8, 0, 1, 'えっ？\u3000私とキミとの\\n相性？\u3000むむ～…\\nうん、バッチリだよ☆', 0);
insert into room_unit_comments values (514, 101201, 2, 1, 1, 1, 1, 'まだこんな時間？\\nベッドに行って、\\n二度寝しなくちゃ～', 0);
insert into room_unit_comments values (515, 101201, 2, 2, 1, 2, 1, '適度なお昼寝は\\n健康にいいんだって！\\n８時間くらいかな？', 0);
insert into room_unit_comments values (516, 101201, 2, 3, 1, 3, 1, 'どんなにお昼寝しても\\n夜は眠いんだ～', 0);
insert into room_unit_comments values (517, 101201, 3, 1, 1, 0, 1, 'ん～、また寝癖…\\nいっつも\\n寝てるからかなぁ？', 0);
insert into room_unit_comments values (518, 101201, 3, 2, 1, 0, 1, '一休み、一休み…\\nどうせなら百休み\\nくらいしようかな…', 0);
insert into room_unit_comments values (519, 101201, 3, 3, 1, 0, 1, 'これ…可愛い！\\nシオリンに\\n届けてあげたい！', 0);
insert into room_unit_comments values (520, 101201, 3, 4, 1, 0, 1, 'ん～…気分爽快！\\nそれじゃ、おやすみ～\\n…すやぁ…', 0);
insert into room_unit_comments values (521, 101201, 3, 5, 1, 0, 1, '気持ちいい…\\nはっ！\u3000ダメダメ！\\nまた寝るとこだった！', 0);
insert into room_unit_comments values (522, 101201, 3, 6, 1, 0, 1, '眠くならないように、\\n運動しよっと！', 0);
insert into room_unit_comments values (523, 101201, 3, 7, 1, 0, 1, 'お腹いっぱいになると\\n眠くなるよね～', 0);
insert into room_unit_comments values (524, 101201, 3, 8, 1, 0, 1, '睡眠学習って\\n本を読みながら\\n寝るんだっけ？', 0);
insert into room_unit_comments values (526, 101202, 1, 1, 1, 0, 1, 'う～ん、今なら\\nどこでだって\\n眠れちゃいそう…', 0);
insert into room_unit_comments values (527, 101202, 1, 2, 1, 0, 1, 'もっといっぱい\\n超能力使えたら\\nいいのにな～', 0);
insert into room_unit_comments values (528, 101202, 1, 3, 1, 0, 1, 'ねえねえ、\\n今から人助け、\\n付き合ってほしいなー', 0);
insert into room_unit_comments values (529, 101202, 1, 4, 1, 0, 1, 'ぐっすり眠って\\nパワーを\\nフルチャージっ☆', 0);
insert into room_unit_comments values (530, 101202, 1, 5, 1, 0, 1, '人助け、頑張ったら\\nなんだか、眠く…\\n…はっ、ダメダメ！', 0);
insert into room_unit_comments values (531, 101202, 1, 101, 8, 0, 1, 'キミと一緒なら、\\nなんだって出来る！\\n間違いない！', 0);
insert into room_unit_comments values (532, 101202, 1, 102, 8, 0, 1, 'キミを抱き枕に…\\nじょ、冗談冗談！', 0);
insert into room_unit_comments values (533, 101202, 2, 1, 1, 0, 1, '忘れ物しちゃった\\nま、いっか！\\nえ、ダメ？', 0);
insert into room_unit_comments values (534, 101202, 2, 2, 1, 0, 1, 'なに？\u3000困ってる？\\nちょうど良かった！\\n今は体力満タンだよ☆', 0);
insert into room_unit_comments values (535, 101202, 2, 3, 1, 0, 1, '一緒に\\nお出かけしたいなー\\nデートしよっ！', 0);
insert into room_unit_comments values (536, 101202, 2, 4, 1, 0, 1, 'うんうん、そうだねっ\\n困ってる人がいたら\\n見過ごせないよねっ！', 0);
insert into room_unit_comments values (537, 101202, 2, 101, 8, 0, 1, 'むむ～…どう？\\nテレパシーで、私の\\n気持ちを送ったよ！', 0);
insert into room_unit_comments values (538, 101202, 2, 102, 8, 0, 1, 'う～だんだん眠く…\\nねぇ一緒に寝よ？', 0);
insert into room_unit_comments values (539, 101202, 2, 1, 1, 1, 1, 'キミって早起きだね！\\n私は寝ようかな～', 0);
insert into room_unit_comments values (540, 101202, 2, 2, 1, 2, 1, '適度なお昼寝は\\n健康にいいんだって！\\n８時間くらいかな？', 0);
insert into room_unit_comments values (541, 101202, 2, 3, 1, 3, 1, 'どんなにお昼寝しても\\n夜は眠いんだ～', 0);
insert into room_unit_comments values (542, 101202, 3, 1, 1, 0, 1, 'ん～、また寝癖…\\nいっつも\\n寝てるからかなぁ？', 0);
insert into room_unit_comments values (543, 101202, 3, 2, 1, 0, 1, '一休み、一休み…\\nどうせなら百休み\\nくらいしようかな…', 0);
insert into room_unit_comments values (544, 101202, 3, 3, 1, 0, 1, 'これ…可愛い！\\nシオリンに\\n届けてあげたい！', 0);
insert into room_unit_comments values (545, 101202, 3, 4, 1, 0, 1, 'ん～…気分爽快！\\nそれじゃ、おやすみ～\\n…すやぁ…', 0);
insert into room_unit_comments values (546, 101202, 3, 5, 1, 0, 1, 'うう～ん、なんだか\\nいつもより眠ーく\\nなってきたよ…', 0);
insert into room_unit_comments values (547, 101202, 3, 6, 1, 0, 1, 'よーし\\n困ってる人のために\\nパワーアップ☆', 0);
insert into room_unit_comments values (548, 101202, 3, 7, 1, 0, 1, '食べてすぐ寝ると\\n牛になるんだっけ？\\nまぁ、いいかぁ～', 0);
insert into room_unit_comments values (549, 101202, 3, 8, 1, 0, 1, '睡眠学習って\\n本を読みながら\\n寝るんだっけ？', 0);
insert into room_unit_comments values (551, 101601, 1, 1, 1, 0, 1, 'モデルは楽しいよ！\\nファンの子みんな\\n応援してくれるしー！', 0);
insert into room_unit_comments values (552, 101601, 1, 2, 1, 0, 1, '今日のおやつは\\n駄菓子に決定～！\\nいただきまーす！', 0);
insert into room_unit_comments values (553, 101601, 1, 3, 1, 0, 1, 'んー、今日のおやつは\\n何にしよう？\\nやっぱアメ玉かな！', 0);
insert into room_unit_comments values (554, 101601, 1, 4, 1, 0, 1, 'ここで撮影会、\\nしようかな～♪', 0);
insert into room_unit_comments values (555, 101601, 1, 5, 1, 0, 1, '７かける８はぁ\\n７＋７＋７＋７＋…\\nん、何個数えたっけ？', 0);
insert into room_unit_comments values (556, 101601, 1, 101, 4, 0, 1, 'やば…\\nこのままじゃ、うち\\nキュン死にかも…', 0);
insert into room_unit_comments values (557, 101601, 1, 102, 8, 0, 1, '好きなことして\\nヒデサイもいて\\nうちって超～\\nリア充だよね♪', 0);
insert into room_unit_comments values (558, 101601, 2, 1, 1, 0, 1, 'うちの写真撮るの？\\nどんなポーズ？', 0);
insert into room_unit_comments values (559, 101601, 2, 2, 1, 0, 1, 'ネイルの勉強中～♪\\nうまくなったら、\\nヒデサイにしてあげる', 0);
insert into room_unit_comments values (560, 101601, 2, 3, 1, 0, 1, '宿題見てくんない？\\nひとりじゃムリ～', 0);
insert into room_unit_comments values (561, 101601, 2, 4, 1, 0, 1, 'みてこのネイル♪\\n超エモくな～い？\\nヒデサイもする～？', 0);
insert into room_unit_comments values (562, 101601, 2, 101, 4, 0, 1, '新しい美容液で\\n肌まじスベスベ～\\nヒデサイも\\n触ってみる？', 0);
insert into room_unit_comments values (563, 101601, 2, 102, 8, 0, 1, 'ヒデサイと会ってると\\n顔熱くなるんだよね\\n熱なんかないのに…', 0);
insert into room_unit_comments values (564, 101601, 2, 1, 1, 1, 1, '早起きとか\\nつらたんだよねー\\n昼すぎまで寝てたい', 0);
insert into room_unit_comments values (565, 101601, 2, 2, 1, 2, 1, '撮影にむけて\\nダイエットちうだから\\nお昼ぬいてるんだー', 0);
insert into room_unit_comments values (566, 101601, 2, 3, 1, 3, 1, 'お腹すいたー\\nでもこの時間に\\n食べたら絶対に\\n太るやつだよねー', 0);
insert into room_unit_comments values (567, 101601, 3, 1, 1, 0, 1, 'どんなシーンにも合う\\nきれいめわがまま\\nちゃんとコーデだよ♪', 0);
insert into room_unit_comments values (568, 101601, 3, 2, 1, 0, 1, 'ちょっち疲れたかも？\\nガン寝しちゃおっかな', 0);
insert into room_unit_comments values (569, 101601, 3, 3, 1, 0, 1, 'きゃわたーん☆\\n君もおしゃれしよっか', 0);
insert into room_unit_comments values (570, 101601, 3, 4, 1, 0, 1, 'いいにおいじゃん！\\nこれと同じにおいの\\n香水ないかな？', 0);
insert into room_unit_comments values (571, 101601, 3, 5, 1, 0, 1, 'あったまるー\\nこれ、サイツヨに\\n癒しじゃない？', 0);
insert into room_unit_comments values (572, 101601, 3, 6, 1, 0, 1, 'あはは、なんか\\nウォーキングの練習\\nしてるみたーい！', 0);
insert into room_unit_comments values (573, 101601, 3, 7, 1, 0, 1, '体形維持しないと\\nいけないけど\\nついつい食べちゃう！', 0);
insert into room_unit_comments values (574, 101601, 3, 8, 1, 0, 1, '全然読めない～\\nそだ、ヒデサイに\\n読んでもらおっと！', 0);
insert into room_unit_comments values (576, 101602, 1, 1, 1, 0, 1, 'そろそろ\\n仕事の時間だ～\\n出かける準備\\nしよっと！', 0);
insert into room_unit_comments values (577, 101602, 1, 2, 1, 0, 1, '今日のおやつは\\n駄菓子に決定～！\\nいただきまーす！', 0);
insert into room_unit_comments values (578, 101602, 1, 3, 1, 0, 1, 'ヒデサイを見習って\\nうちも少し勉強して\\nみよっかな…\u3000', 0);
insert into room_unit_comments values (579, 101602, 1, 4, 1, 0, 1, '体形維持とか\\n気にしてるんだよ～', 0);
insert into room_unit_comments values (580, 101602, 1, 5, 1, 0, 1, '７かける８はぁ\\n７＋７＋７＋７＋…\\nん、何個数えたっけ？', 0);
insert into room_unit_comments values (581, 101602, 1, 101, 8, 0, 1, 'やば…\\nこのままじゃ、うち\\nキュン死にかも…\u3000', 0);
insert into room_unit_comments values (582, 101602, 1, 102, 8, 0, 1, 'ヒデサイと会ってると\\n顔熱くなるんだよね\\n熱なんかないのに…', 0);
insert into room_unit_comments values (583, 101602, 2, 1, 1, 0, 1, 'うちの写真撮るの？\\nどんなポーズ？', 0);
insert into room_unit_comments values (584, 101602, 2, 2, 1, 0, 1, 'ネイルの勉強中～♪\\nうまくなったら、\\nヒデサイに\\nしてあげる♪', 0);
insert into room_unit_comments values (585, 101602, 2, 3, 1, 0, 1, 'この雑誌の服\\nガチめにほしぃ～', 0);
insert into room_unit_comments values (586, 101602, 2, 4, 1, 0, 1, 'うちのコーデで\\nヒデサイをオシャンに\\nしてあげるね♪', 0);
insert into room_unit_comments values (587, 101602, 2, 101, 8, 0, 1, '新しい美容液で\\n肌まじスベスベ～\\nヒデサイも\\n触ってみる？', 0);
insert into room_unit_comments values (588, 101602, 2, 102, 8, 0, 1, '好きなことして\\nヒデサイもいて\\nうちって超～\\nリア充だよね♪', 0);
insert into room_unit_comments values (589, 101602, 2, 1, 1, 1, 1, '今日は早起き\\nできたんだー\\nメイクもばっち\\nきまってるっしょ？', 0);
insert into room_unit_comments values (590, 101602, 2, 2, 1, 2, 1, '撮影にむけて\\nダイエットちうだから\\nお昼ぬいてるんだー', 0);
insert into room_unit_comments values (591, 101602, 2, 3, 1, 3, 1, 'お腹すいたー\\nでもこの時間に\\n食べたら絶対に\\n太るやつだよねー', 0);
insert into room_unit_comments values (592, 101602, 3, 1, 1, 0, 1, 'この服ね～\\n今年のトレンドなんだ♪\\nかわたんでしょ！', 0);
insert into room_unit_comments values (593, 101602, 3, 2, 1, 0, 1, 'ちょっち疲れたかも？\\nガン寝しちゃおっかな', 0);
insert into room_unit_comments values (594, 101602, 3, 3, 1, 0, 1, 'うわー\\nこのぬいぐるみ\\nもきゅすぎでしょ～！', 0);
insert into room_unit_comments values (595, 101602, 3, 4, 1, 0, 1, 'いいにおーい♪\\nファンのみんなにも\\n教えてあげよー♪', 0);
insert into room_unit_comments values (596, 101602, 3, 5, 1, 0, 1, 'あったまるー\\nこれ、サイツヨに\\n癒しじゃない？', 0);
insert into room_unit_comments values (597, 101602, 3, 6, 1, 0, 1, '食べた分は\\n消費しないとね～', 0);
insert into room_unit_comments values (598, 101602, 3, 7, 1, 0, 1, '体形維持しないと\\nいけないけど\\nついつい食べちゃう！', 0);
insert into room_unit_comments values (599, 101602, 3, 8, 1, 0, 1, '全然読めない～\\nそだ、ヒデサイに\\n読んでもらおっと！', 0);
insert into room_unit_comments values (601, 101701, 1, 1, 1, 0, 1, 'やっさー\\n踊ってると、どんどん\\n楽しくなるさー！', 0);
insert into room_unit_comments values (602, 101701, 1, 2, 1, 0, 1, 'このお菓子、でーじ\\nおいしいねー！\\nキミも食べる？', 0);
insert into room_unit_comments values (603, 101701, 1, 3, 1, 0, 1, 'ハイターイ！\u3000元気な\\nあいさつが一番さ～！', 0);
insert into room_unit_comments values (604, 101701, 1, 4, 1, 0, 1, 'あまった食材があれば\\nチャンプルーにして\\n食べたいさー！ ', 0);
insert into room_unit_comments values (605, 101701, 1, 5, 1, 0, 1, 'さぁ、みんなで歌って\\n踊るさ～♪', 0);
insert into room_unit_comments values (606, 101701, 1, 101, 4, 0, 1, '毎日、最高に幸せさ～\\nキミのおかげだねー', 0);
insert into room_unit_comments values (607, 101701, 1, 102, 8, 0, 1, 'キミへの気持ちを\\n踊りで表現\\nしてみるさ～', 0);
insert into room_unit_comments values (608, 101701, 2, 1, 1, 0, 1, '海でひと泳ぎ\\nしたいさ～\\nキミもどう？', 0);
insert into room_unit_comments values (609, 101701, 2, 2, 1, 0, 1, 'あぎひゃっ！\\n急に声かけたら、\\nビックリするさ～', 0);
insert into room_unit_comments values (610, 101701, 2, 3, 1, 0, 1, '踊りなら、\\n私が手とり足とり\\n教えてあげるさ～！', 0);
insert into room_unit_comments values (611, 101701, 2, 4, 1, 0, 1, '空手の型の\\n練習するさー\\nキミもどう？', 0);
insert into room_unit_comments values (612, 101701, 2, 101, 4, 0, 1, 'よ～し、手をつないで\\n踊るさ～！\\n恥ずかしがること\\nないさ～', 0);
insert into room_unit_comments values (613, 101701, 2, 102, 8, 0, 1, 'キミと一緒だから、\\n毎日楽しいこと\\nばっかりさー', 0);
insert into room_unit_comments values (614, 101701, 2, 1, 1, 1, 1, 'ハイターイ！\\n今日も一日、\\nがんばるさー！', 0);
insert into room_unit_comments values (615, 101701, 2, 2, 1, 2, 1, '午後も頑張るために\\nお昼ご飯は\\nてびちにするさー！', 0);
insert into room_unit_comments values (616, 101701, 2, 3, 1, 3, 1, '故郷では見えない星が\\n見られるんだねえ。\\nなんか不思議さぁ', 0);
insert into room_unit_comments values (617, 101701, 3, 1, 1, 0, 1, '夢中で踊ってたら、\\n髪の毛ぼさぼさに\\nなってるさ～！？', 0);
insert into room_unit_comments values (618, 101701, 3, 2, 1, 0, 1, 'よく食べてよく踊って\\nよく休む。\\nそれが元気の秘訣さ～', 0);
insert into room_unit_comments values (619, 101701, 3, 3, 1, 0, 1, 'ちゅらかーぎーねー！\\nキミはどこから\\n来たのー？', 0);
insert into room_unit_comments values (620, 101701, 3, 4, 1, 0, 1, 'いい香り～、って\\n私もカオリだったさ！\\nなんだか照れるね☆', 0);
insert into room_unit_comments values (621, 101701, 3, 5, 1, 0, 1, '故郷はあんまり暖房を\\n使わなかったから、\\n新鮮さー！', 0);
insert into room_unit_comments values (622, 101701, 3, 6, 1, 0, 1, '汗をかくのは\\n気持ちいいさー！\\nどんどん行くよー！', 0);
insert into room_unit_comments values (623, 101701, 3, 7, 1, 0, 1, 'うーん、おいしいさ～\\nゴーヤっぽいものを\\n混ぜたいさ～', 0);
insert into room_unit_comments values (624, 101701, 3, 8, 1, 0, 1, 'おおー、故郷の民話！\\nこんなとこで見るとは\\n懐かしいさぁ～！', 0);
insert into room_unit_comments values (626, 101702, 1, 1, 1, 0, 1, '焦らなくても\\nなんくるないさ～\\nなるようになるさ～', 0);
insert into room_unit_comments values (627, 101702, 1, 2, 1, 0, 1, 'さぁ、みんなで歌って\\n踊るさ～♪', 0);
insert into room_unit_comments values (628, 101702, 1, 3, 1, 0, 1, '元気がないときは\\n私のところに来るさー', 0);
insert into room_unit_comments values (629, 101702, 1, 4, 1, 0, 1, 'あまった食材があれば\\nチャンプルーにして\\n食べたいさー！ ', 0);
insert into room_unit_comments values (630, 101702, 1, 5, 1, 0, 1, 'ノリノリな音楽と\\n踊りで、疲れを\\n吹き飛ばすさ～！', 0);
insert into room_unit_comments values (631, 101702, 1, 101, 8, 0, 1, '毎日、最高に幸せさ～\\nキミのおかげだねー', 0);
insert into room_unit_comments values (632, 101702, 1, 102, 8, 0, 1, '幸せすぎて踊らずには\\nいられないさ～', 0);
insert into room_unit_comments values (633, 101702, 2, 1, 1, 0, 1, '海でひと泳ぎ\\nしたいさ～\\nキミもどう？', 0);
insert into room_unit_comments values (634, 101702, 2, 2, 1, 0, 1, 'ん？\u3000どうしたの～？\\nヒマなら一緒に\\n踊ろうさ～', 0);
insert into room_unit_comments values (635, 101702, 2, 3, 1, 0, 1, 'キミと一緒だから\\n毎日楽しいこと\\nばっかりさー', 0);
insert into room_unit_comments values (636, 101702, 2, 4, 1, 0, 1, 'ハイターイ！\u3000元気な\\nあいさつが一番さ～！', 0);
insert into room_unit_comments values (637, 101702, 2, 101, 8, 0, 1, 'キミと踊ってる時が\\n一番幸せさ～\\nキミもそう思ってたら\\nうれしいさ～', 0);
insert into room_unit_comments values (638, 101702, 2, 102, 8, 0, 1, '海に沈む夕日は\\nとっても綺麗さ～！\\n今度一緒に見ようね～ ', 0);
insert into room_unit_comments values (639, 101702, 2, 1, 1, 1, 1, '気持ちのいい朝さー！\\nひとっ走り\\nしてくるさー！', 0);
insert into room_unit_comments values (640, 101702, 2, 2, 1, 2, 1, '午後も頑張るために\\nお昼ご飯は\\nてびちにするさー！ ', 0);
insert into room_unit_comments values (641, 101702, 2, 3, 1, 3, 1, '故郷では見えない星が\\n見られるんだねえ\\nなんか不思議さぁ ', 0);
insert into room_unit_comments values (642, 101702, 3, 1, 1, 0, 1, '夢中で踊ってたら\\n髪の毛ぼさぼさに\\nなってるさ～！？', 0);
insert into room_unit_comments values (643, 101702, 3, 2, 1, 0, 1, 'よく食べてよく踊って\\nよく休む\\nそれが元気の秘訣さ～', 0);
insert into room_unit_comments values (644, 101702, 3, 3, 1, 0, 1, 'ちゅらかーぎーねー！\\nキミはどこから\\n来たのー？ ', 0);
insert into room_unit_comments values (645, 101702, 3, 4, 1, 0, 1, 'いい香り～、って\\n私もカオリだったさ！\\nなんだか照れるね☆ ', 0);
insert into room_unit_comments values (646, 101702, 3, 5, 1, 0, 1, '故郷はあんまり暖房を\\n使わなかったから\\n新鮮さー！', 0);
insert into room_unit_comments values (647, 101702, 3, 6, 1, 0, 1, '徹夜で踊り続ける\\nためにも、まずは\\n体を鍛えるさ～', 0);
insert into room_unit_comments values (648, 101702, 3, 7, 1, 0, 1, 'もぐもぐ…もっと\\nおかわりがほしいさー', 0);
insert into room_unit_comments values (649, 101702, 3, 8, 1, 0, 1, 'おおー、故郷の民話！\\nこんなとこで見るとは\\n懐かしいさぁ～！ ', 0);
insert into room_unit_comments values (651, 101801, 1, 1, 1, 0, 1, 'はあ…\\nすてきな小説だった～\\nキュンキュンしちゃう', 0);
insert into room_unit_comments values (652, 101801, 1, 2, 1, 0, 1, 'このお部屋\\n女の子ばかりね。\\n魔族の女子校を\\n思い出しちゃう♪', 0);
insert into room_unit_comments values (653, 101801, 1, 3, 1, 0, 1, '次のテスト\\n恋愛小説から\\n出題したら\\nダメかしら…？', 0);
insert into room_unit_comments values (654, 101801, 1, 4, 1, 0, 1, 'キンコンカンコ～ン♪\\n授業をはじめま～す', 0);
insert into room_unit_comments values (655, 101801, 1, 5, 1, 0, 1, 'はー…\\nちょっと肩が\\nこっちゃった…', 0);
insert into room_unit_comments values (656, 101801, 1, 101, 4, 0, 1, '私、あの子のこと\\n無意識に特別扱い\\nしちゃってるかな…', 0);
insert into room_unit_comments values (657, 101801, 1, 102, 8, 0, 1, '物語だと生徒が先生を\\n好きになるのにな…\\n逆の場合は…', 0);
insert into room_unit_comments values (658, 101801, 2, 1, 1, 0, 1, 'あん！\u3000見ちゃダメよ\\n明日のテストの問題を\\n作ってるとこなの！', 0);
insert into room_unit_comments values (659, 101801, 2, 2, 1, 0, 1, '勉強勉強で\\n疲れたよね？\\n膝枕してあげる！', 0);
insert into room_unit_comments values (660, 101801, 2, 3, 1, 0, 1, 'テストがんばったね～\\nご褒美に先生が\\n特別な授業\\nしてあげるね？', 0);
insert into room_unit_comments values (661, 101801, 2, 4, 1, 0, 1, '学院の外でも\\n私は君の先生よ\\nなんでも聞いてね♪', 0);
insert into room_unit_comments values (662, 101801, 2, 101, 4, 0, 1, '今読んでるのは\\nヒロインが年下の子と\\n恋に落ちる話…あ、\\n深い意味はないのよ～', 0);
insert into room_unit_comments values (663, 101801, 2, 102, 8, 0, 1, '生徒は全員可愛いけど\\n君は少し特別…\\nみんなには内緒よ？', 0);
insert into room_unit_comments values (664, 101801, 2, 1, 1, 1, 1, '学校に\\n遅刻しないように\\n早く準備しないとね', 0);
insert into room_unit_comments values (665, 101801, 2, 2, 1, 2, 1, '男の子といっしょに\\nお弁当を食べるの、\\n夢なんだ～', 0);
insert into room_unit_comments values (666, 101801, 2, 3, 1, 3, 1, '明日の予習はやった？\\n先生も手伝うから\\n寝る前にやりましょ♪', 0);
insert into room_unit_comments values (667, 101801, 3, 1, 1, 0, 1, 'もしかして…\\n少し露出多いかしら？', 0);
insert into room_unit_comments values (668, 101801, 3, 2, 1, 0, 1, 'リラックスすると\\nα波が出て、勉強が\\nはかどるんですって', 0);
insert into room_unit_comments values (669, 101801, 3, 3, 1, 0, 1, 'かわいい♪\u3000あなたも\\n私の生徒になる？', 0);
insert into room_unit_comments values (670, 101801, 3, 4, 1, 0, 1, '学院にもこういう\\n安らぐ設備が\\n必要かしらね？', 0);
insert into room_unit_comments values (671, 101801, 3, 5, 1, 0, 1, 'まだ寒いわぁ\\n誰か隣に\\n来てくれたら…', 0);
insert into room_unit_comments values (672, 101801, 3, 6, 1, 0, 1, '運動部の顧問も\\nできるかしら？', 0);
insert into room_unit_comments values (673, 101801, 3, 7, 1, 0, 1, '学校の給食でも\\n食べたいわぁ～', 0);
insert into room_unit_comments values (674, 101801, 3, 8, 1, 0, 1, 'いい参考書を\\n見つけちゃった♪', 0);
insert into room_unit_comments values (676, 101802, 1, 1, 1, 0, 1, '私の生徒に\\n不良なんていないわ\\nみーんないい子♪', 0);
insert into room_unit_comments values (677, 101802, 1, 2, 1, 0, 1, 'このお部屋\\n女の子ばかりね\\n魔族の女子校を\\n思い出しちゃう♪', 0);
insert into room_unit_comments values (678, 101802, 1, 3, 1, 0, 1, 'あの子、まだかな…\\n宿題も見てあげたいし\\n早く来ないかしら？', 0);
insert into room_unit_comments values (679, 101802, 1, 4, 1, 0, 1, 'はあ…\\nすてきな小説だった～\\nキュンキュンしちゃう', 0);
insert into room_unit_comments values (680, 101802, 1, 5, 1, 0, 1, '学校の図書室に\\n恋愛小説を\\n置いて欲しいなあ', 0);
insert into room_unit_comments values (681, 101802, 1, 101, 8, 0, 1, '私、あの子のこと\\n無意識に特別扱い\\nしちゃってるかな…', 0);
insert into room_unit_comments values (682, 101802, 1, 102, 8, 0, 1, '物語だと生徒が先生を\\n好きになるのにな…\\n逆の場合は…\u3000', 0);
insert into room_unit_comments values (683, 101802, 2, 1, 1, 0, 1, 'あん！\u3000見ちゃダメよ\\n明日のテストの問題を\\n作ってるとこなの！', 0);
insert into room_unit_comments values (684, 101802, 2, 2, 1, 0, 1, '勉強勉強で\\n疲れたよね？\\n膝枕してあげる！', 0);
insert into room_unit_comments values (685, 101802, 2, 3, 1, 0, 1, '宿題はもうやった？\\n苦手なところは\\n先生が見てあげる♪', 0);
insert into room_unit_comments values (686, 101802, 2, 4, 1, 0, 1, 'んん？\u3000なんだか\\n元気がないみたい\\n先生がぎゅぅ～って\\nしてあげる…\u3000', 0);
insert into room_unit_comments values (687, 101802, 2, 101, 8, 0, 1, '君のお勉強も\\nだいぶ進んできたね～\\n補習卒業も近いかな？\\n少し寂しいけど…', 0);
insert into room_unit_comments values (688, 101802, 2, 102, 8, 0, 1, 'テストがんばったね～\\nご褒美に先生が\\n特別な授業\\nしてあげるね？', 0);
insert into room_unit_comments values (689, 101802, 2, 1, 1, 1, 1, '朝の特別授業\\nしてあげましょうか？', 0);
insert into room_unit_comments values (690, 101802, 2, 2, 1, 2, 1, '午後の授業って\\n眠いでしょう？\\n気持ちは分かるけど\\nがんばってね♪', 0);
insert into room_unit_comments values (691, 101802, 2, 3, 1, 3, 1, '明日の予習はやった？\\n先生も手伝うから\\n寝る前にやりましょ♪', 0);
insert into room_unit_comments values (692, 101802, 3, 1, 1, 0, 1, 'もしかして…\\n少し露出多いかしら？', 0);
insert into room_unit_comments values (693, 101802, 3, 2, 1, 0, 1, '私の膝枕と、どっちが\\nフカフカかしら？', 0);
insert into room_unit_comments values (694, 101802, 3, 3, 1, 0, 1, '可愛いわね～\\n教室に置いたら\\n生徒が喜ぶかしら？\u3000', 0);
insert into room_unit_comments values (695, 101802, 3, 4, 1, 0, 1, 'は～落ち着くなぁ～\\n教師には\\nこういうゆとりも\\n必要よね♪\u3000', 0);
insert into room_unit_comments values (696, 101802, 3, 5, 1, 0, 1, 'まだ寒いわぁ\\n誰か隣に\\n来てくれたら…\u3000', 0);
insert into room_unit_comments values (697, 101802, 3, 6, 1, 0, 1, '運動部の顧問も\\nできるかしら？\u3000', 0);
insert into room_unit_comments values (698, 101802, 3, 7, 1, 0, 1, 'あん！\\nお胸にこぼしちゃった', 0);
insert into room_unit_comments values (699, 101802, 3, 8, 1, 0, 1, 'あぁーん♪\\nこういう物語みたいな\\n恋愛あこがれる～\u3000', 0);
insert into room_unit_comments values (701, 102001, 1, 1, 1, 0, 1, 'おにいちゃんは、\\nにんじん食べられる？', 0);
insert into room_unit_comments values (702, 102001, 1, 2, 1, 0, 1, 'えへへ、\\nお絵かきしよ～♪', 0);
insert into room_unit_comments values (703, 102001, 1, 3, 1, 0, 1, 'あのね、ミミと\\nあそんでほしいな～', 0);
insert into room_unit_comments values (704, 102001, 1, 4, 1, 0, 1, 'さっきね、きれいな\\nお花見つけたよ。\\nおにいちゃんにも\\n見せてあげたいな～', 0);
insert into room_unit_comments values (705, 102001, 1, 5, 1, 0, 1, 'うさぎさん、\\nぴょんぴょん\\nぴょーん♪', 0);
insert into room_unit_comments values (706, 102001, 1, 101, 4, 0, 1, 'おにいちゃんの絵、\\nかいてあげるね♪', 0);
insert into room_unit_comments values (707, 102001, 1, 102, 8, 0, 1, 'おっきくなったら\\nおにいちゃんの\\nお嫁さんになるんだ♪', 0);
insert into room_unit_comments values (708, 102001, 2, 1, 1, 0, 1, 'ふわぁ！\\nおにいちゃんの手、\\nおっきいね～', 0);
insert into room_unit_comments values (709, 102001, 2, 2, 1, 0, 1, 'やった～！\\nおにいちゃんが\\nほめてくれた～', 0);
insert into room_unit_comments values (710, 102001, 2, 3, 1, 0, 1, 'ねえねえ\\nおにいちゃん、\\n一緒にあそぼっ♪', 0);
insert into room_unit_comments values (711, 102001, 2, 4, 1, 0, 1, 'おにいちゃん、\\n遊んでくれるの？\\n\u3000わぁい♪', 0);
insert into room_unit_comments values (712, 102001, 2, 101, 4, 0, 1, 'わぁい！\\nおにいちゃんだ～♪\\nぎゅ～っ！', 0);
insert into room_unit_comments values (713, 102001, 2, 102, 8, 0, 1, 'あのねあのね、\\nミミの頭ポンポンって\\nしてほしいな', 0);
insert into room_unit_comments values (714, 102001, 2, 1, 1, 1, 1, 'おひさまさん、\\nおはよ～！\\n毎朝、早おきだね～', 0);
insert into room_unit_comments values (715, 102001, 2, 2, 1, 2, 1, 'うわぁ！\\nお日さまがすごーく\\n高いところにある～', 0);
insert into room_unit_comments values (716, 102001, 2, 3, 1, 3, 1, 'おにいちゃん\\nおやすみのご本\\nよんで～', 0);
insert into room_unit_comments values (717, 102001, 3, 1, 1, 0, 1, 'ミミも、\\nうさぎさんみたいに、\\nかわいくなりたいな♪', 0);
insert into room_unit_comments values (718, 102001, 3, 2, 1, 0, 1, 'のんびり～♪\\nゆったり～♪\\nまったり～♪', 0);
insert into room_unit_comments values (719, 102001, 3, 3, 1, 0, 1, 'わぁ～かわいい～♪\\nミミ、幸せ～♪\\n抱きついていいかな？', 0);
insert into room_unit_comments values (720, 102001, 3, 4, 1, 0, 1, 'いいにおい～♪\\nお鼻ピクピク♪\\nうさぎさんも喜ぶよ♪', 0);
insert into room_unit_comments values (721, 102001, 3, 5, 1, 0, 1, 'あったか～♪\\nぬくぬく～♪\\nポカポカ～♪', 0);
insert into room_unit_comments values (722, 102001, 3, 6, 1, 0, 1, 'ふ、ふぇ～\u3000ミミ、\\n運動苦手だよ～', 0);
insert into room_unit_comments values (723, 102001, 3, 7, 1, 0, 1, 'はむ♪\u3000いっぱい\\n食べて、はやく\\nおっきくなりたいな～', 0);
insert into room_unit_comments values (724, 102001, 3, 8, 1, 0, 1, 'ミミね！\\nこのお話だーい好き！', 0);
insert into room_unit_comments values (726, 102002, 1, 1, 1, 0, 1, 'ぴょんぴょん\\n跳ねるよ\\nうっさぎっさ～ん♪', 0);
insert into room_unit_comments values (727, 102002, 1, 2, 1, 0, 1, 'うさぎさんの\\nマネだよ～\\n似てるかな～？', 0);
insert into room_unit_comments values (728, 102002, 1, 3, 1, 0, 1, 'モフモフすると\\nきもちい～よ', 0);
insert into room_unit_comments values (729, 102002, 1, 4, 1, 0, 1, 'ミソギちゃん\\nキョウカちゃん\\nあ～そ～ぼっ！', 0);
insert into room_unit_comments values (730, 102002, 1, 5, 1, 0, 1, 'おにいちゃん\\nおやすみのご本\\nよんで～', 0);
insert into room_unit_comments values (731, 102002, 1, 101, 8, 0, 1, 'ねえ、おにいちゃん\\nミミのこと、すき？', 0);
insert into room_unit_comments values (732, 102002, 1, 102, 8, 0, 1, 'おっきくなったら\\nおにいちゃんの\\nお嫁さんになるんだ♪', 0);
insert into room_unit_comments values (733, 102002, 2, 1, 1, 0, 1, 'やった～！\\nおにいちゃんが\\nほめてくれた～', 0);
insert into room_unit_comments values (734, 102002, 2, 2, 1, 0, 1, 'おにいちゃん\\n遊んでくれるの？\\nわぁい♪', 0);
insert into room_unit_comments values (735, 102002, 2, 3, 1, 0, 1, 'おにいちゃん\\nあのね…\\nいいこいいこして～', 0);
insert into room_unit_comments values (736, 102002, 2, 4, 1, 0, 1, 'あはは～\\nくすぐったいよ～', 0);
insert into room_unit_comments values (737, 102002, 2, 101, 8, 0, 1, 'おにいちゃんの\\nおひざの上、とっても\\n安心するんだ～！', 0);
insert into room_unit_comments values (738, 102002, 2, 102, 8, 0, 1, 'わぁい♪\\nおにいちゃんの\\nなでなで\\nうれし～な♪', 0);
insert into room_unit_comments values (739, 102002, 2, 1, 1, 1, 1, 'おひさまさん\\nおはよ～！\\n毎朝、早おきだね～', 0);
insert into room_unit_comments values (740, 102002, 2, 2, 1, 2, 1, 'お昼寝お昼寝～♪\\nおにいちゃんと一緒に\\nお昼寝～♪', 0);
insert into room_unit_comments values (741, 102002, 2, 3, 1, 3, 1, '眠くなっちゃった～\\nおにいちゃん！\\n今日は一緒に寝よ～', 0);
insert into room_unit_comments values (742, 102002, 3, 1, 1, 0, 1, 'ミミも\\nうさぎさんみたいに\\nかわいくなりたいな', 0);
insert into room_unit_comments values (743, 102002, 3, 2, 1, 0, 1, 'ふわふわ～モコモコ～\\n気持ちいい～♪\\nミミもゴロゴロ～ン♪', 0);
insert into room_unit_comments values (744, 102002, 3, 3, 1, 0, 1, 'わぁ～かわいい～♪\\nミミ、幸せ～♪\\n抱きついていいかな？', 0);
insert into room_unit_comments values (745, 102002, 3, 4, 1, 0, 1, 'いいにおい～♪\\nお鼻ピクピク♪\\nうさぎさんも喜ぶよ～♪', 0);
insert into room_unit_comments values (746, 102002, 3, 5, 1, 0, 1, 'あったか～♪\\nぬくぬく～♪\\nポカポカ～♪', 0);
insert into room_unit_comments values (747, 102002, 3, 6, 1, 0, 1, 'はぁはぁ…\\nふえ～ミミ\\n疲れちゃうよ～！', 0);
insert into room_unit_comments values (748, 102002, 3, 7, 1, 0, 1, 'はむ♪\u3000いっぱい\\n食べて、はやく\\nおっきくなりたいな～', 0);
insert into room_unit_comments values (749, 102002, 3, 8, 1, 0, 1, 'ミミね！\\nこのお話だーい好き！', 0);
insert into room_unit_comments values (751, 102101, 1, 1, 1, 0, 1, 'はぅぅ…\\n部屋のどこにいたら\\nいいんだろう…', 0);
insert into room_unit_comments values (752, 102101, 1, 2, 1, 0, 1, 'お外より\\nお部屋の中の方が\\n落ち着くな…', 0);
insert into room_unit_comments values (753, 102101, 1, 3, 1, 0, 1, 'クッキー焼いたら\\nみんな食べてくれる\\nかなぁ…', 0);
insert into room_unit_comments values (754, 102101, 1, 4, 1, 0, 1, 'あ、あめんぼあかいな\\nあいうえお！', 0);
insert into room_unit_comments values (755, 102101, 1, 5, 1, 0, 1, 'お芝居には\\n人間観察が大事…\\nじーーーーーー…', 0);
insert into room_unit_comments values (756, 102101, 1, 101, 4, 0, 1, 'お兄ちゃんを見ると、\\n顔が赤くなっちゃうの\\n…な、なんでかな？', 0);
insert into room_unit_comments values (757, 102101, 1, 102, 8, 0, 1, 'れ、恋愛劇…\\nお、お兄ちゃんと\\n練習…', 0);
insert into room_unit_comments values (758, 102101, 2, 1, 1, 0, 1, 'こ、この本、とっても\\nおもしろいんですよ♪', 0);
insert into room_unit_comments values (759, 102101, 2, 2, 1, 0, 1, 'い、一緒に遊んで\\nくれるんですか？\\nや、やったぁ～♪', 0);
insert into room_unit_comments values (760, 102101, 2, 3, 1, 0, 1, 'ランドソルには\\n慣れましたか？\\nわ、私はまだ…', 0);
insert into room_unit_comments values (761, 102101, 2, 4, 1, 0, 1, 'お、お兄ちゃん、\\nお、お話の練習に\\n付き合って欲しいです', 0);
insert into room_unit_comments values (762, 102101, 2, 101, 4, 0, 1, 'リボンがかわいい？\\nほ、ほぇぇぇ～～\\nは、恥ずかしいですぅ', 0);
insert into room_unit_comments values (763, 102101, 2, 102, 8, 0, 1, 'お兄ちゃん…♪\\nえへへ、呼んでみた\\nだけです…♪', 0);
insert into room_unit_comments values (764, 102101, 2, 1, 1, 1, 1, '今日は一日、\\n恥ずかしがらずに\\n過ごせるかなあ…？', 0);
insert into room_unit_comments values (765, 102101, 2, 2, 1, 2, 1, 'お昼ご飯、どうぞ♪\\nわ、私、お料理、\\nうまくなったかな？', 0);
insert into room_unit_comments values (766, 102101, 2, 3, 1, 3, 1, 'おにいちゃんが\\n帰ってくるまで、\\nがんばって\\n起きてました', 0);
insert into room_unit_comments values (767, 102101, 3, 1, 1, 0, 1, '可愛い女の子に変身！\\n出来ますように…♪', 0);
insert into room_unit_comments values (768, 102101, 3, 2, 1, 0, 1, 'ふかふかで\\nあったかくて…\\nお兄ちゃんみたい♪', 0);
insert into room_unit_comments values (769, 102101, 3, 3, 1, 0, 1, 'この子を相手に、\\n演技の練習～', 0);
insert into room_unit_comments values (770, 102101, 3, 4, 1, 0, 1, 'リボンや服に\\n染み込ませておこう。\\nいつでもいい匂い♪', 0);
insert into room_unit_comments values (771, 102101, 3, 5, 1, 0, 1, 'えへへ。\\nぽっかぽかです…', 0);
insert into room_unit_comments values (772, 102101, 3, 6, 1, 0, 1, 'はぁはぁ…\\nふひぃ…\\nはうぅぅぅ～～', 0);
insert into room_unit_comments values (773, 102101, 3, 7, 1, 0, 1, 'もぐもぐ…えへへ、\\n美味しいものを\\n食べてると幸せです', 0);
insert into room_unit_comments values (774, 102101, 3, 8, 1, 0, 1, '戯曲を読んで\\n自分が演じるところを\\n想像するの…', 0);
insert into room_unit_comments values (776, 102102, 1, 1, 1, 0, 1, 'かわいいものを\\nこうして並べて…\\nはぁ…落ちつくぅ♪', 0);
insert into room_unit_comments values (777, 102102, 1, 2, 1, 0, 1, 'ふぁ～、この部屋は\\n時間がゆったりと\\n流れてるみたい', 0);
insert into room_unit_comments values (778, 102102, 1, 3, 1, 0, 1, 'この台本、感動…\\n涙が止まらないよぉ\\nいつか演じてみたいな', 0);
insert into room_unit_comments values (779, 102102, 1, 4, 1, 0, 1, 'お芝居には\\n人間観察が大事…\\nじーーーーーー…', 0);
insert into room_unit_comments values (780, 102102, 1, 5, 1, 0, 1, 'あえいうえおあお\\nかけきくけ、かっ…\\nむ、難しいですぅぅ', 0);
insert into room_unit_comments values (781, 102102, 1, 101, 8, 0, 1, 'お、お腹が空いた時は\\n言ってくださいね\\nが、頑張って\\n作ります！', 0);
insert into room_unit_comments values (782, 102102, 1, 102, 8, 0, 1, 'れ、恋愛劇…\\nお、お兄ちゃんと\\n練習…', 0);
insert into room_unit_comments values (783, 102102, 2, 1, 1, 0, 1, 'こ、この本、とっても\\nおもしろいんですよ♪', 0);
insert into room_unit_comments values (784, 102102, 2, 2, 1, 0, 1, 'お兄ちゃんと\\nいっぱい話せた日は、\\n嬉しくなっちゃいます', 0);
insert into room_unit_comments values (785, 102102, 2, 3, 1, 0, 1, '何か私にできる事\\n…そうだ！\\nお掃除しますね！', 0);
insert into room_unit_comments values (786, 102102, 2, 4, 1, 0, 1, '私、ちょっとずつ、\\n自分に自信が\\nついてきたかもです…', 0);
insert into room_unit_comments values (787, 102102, 2, 101, 8, 0, 1, 'リボンがかわいい？\\nほ、ほぇぇぇ～～\\nは、恥ずかしいですぅ', 0);
insert into room_unit_comments values (788, 102102, 2, 102, 8, 0, 1, 'お兄ちゃん…♪\\nえへへ、呼んでみた\\nだけです…♪', 0);
insert into room_unit_comments values (789, 102102, 2, 1, 1, 1, 1, 'おはようございます♪\\n声出しして、お芝居の\\n練習しなくちゃ', 0);
insert into room_unit_comments values (790, 102102, 2, 2, 1, 2, 1, 'お茶にしますか？\\nクッキー焼いたので、\\nよかったら…', 0);
insert into room_unit_comments values (791, 102102, 2, 3, 1, 3, 1, '寝る前に\\n台本を読むと、\\n覚えやすいんです', 0);
insert into room_unit_comments values (792, 102102, 3, 1, 1, 0, 1, '可愛い女の子に変身！\\n出来ますように…♪', 0);
insert into room_unit_comments values (793, 102102, 3, 2, 1, 0, 1, 'はぅ…\\nフッカフカァ…\\n癒されちゃいます…', 0);
insert into room_unit_comments values (794, 102102, 3, 3, 1, 0, 1, 'この子を相手に\\n演技の練習～', 0);
insert into room_unit_comments values (795, 102102, 3, 4, 1, 0, 1, 'リボンや服に\\n染み込ませておこう\\nいつでもいい匂い♪', 0);
insert into room_unit_comments values (796, 102102, 3, 5, 1, 0, 1, 'えへへ\\nぽっかぽかです…', 0);
insert into room_unit_comments values (797, 102102, 3, 6, 1, 0, 1, 'え、演劇には\\nた、体力も重要\\nだから～', 0);
insert into room_unit_comments values (798, 102102, 3, 7, 1, 0, 1, '残さず\\n食べますね…！', 0);
insert into room_unit_comments values (799, 102102, 3, 8, 1, 0, 1, '戯曲を読んで\\n自分が演じるところを\\n想像するの…', 0);
insert into room_unit_comments values (801, 102201, 1, 1, 1, 0, 1, 'ねえ、人見知りを\\n治すための練習に\\n付き合ってくれない？', 0);
insert into room_unit_comments values (802, 102201, 1, 2, 1, 0, 1, 'アカリみたいに\\nかわいくなるには、\\nどうすればいいのかな', 0);
insert into room_unit_comments values (803, 102201, 1, 3, 1, 0, 1, 'レアカードをゲット！\\nねえねえ、\\nすごいでしょ！？', 0);
insert into room_unit_comments values (804, 102201, 1, 4, 1, 0, 1, 'ア、アイツと同じ\\n部屋にいるのよね…\\nって、だから何よ！？', 0);
insert into room_unit_comments values (805, 102201, 1, 5, 1, 0, 1, '楽しいゲームって\\nやめどきが\\n見つからないわ', 0);
insert into room_unit_comments values (806, 102201, 1, 101, 4, 0, 1, 'もっと女の子らしく\\nなったらアイツも\\n嬉しいかな…って、\\n何考えてるの！？', 0);
insert into room_unit_comments values (807, 102201, 1, 102, 8, 0, 1, 'うぅ…最近、\\nアイツを見るとなんか\\nドキドキするのよね', 0);
insert into room_unit_comments values (808, 102201, 2, 1, 1, 0, 1, 'ゲームに負けた罰\\nだからって、\\nくすぐるのは…\\nあはは…ダメだって！', 0);
insert into room_unit_comments values (809, 102201, 2, 2, 1, 0, 1, 'アンタと話すのは割と\\n緊張しないのよね\\n…なんでかな', 0);
insert into room_unit_comments values (810, 102201, 2, 3, 1, 0, 1, '待ちきれない…\\n新作ゲームの発売日が\\n待ちきれない…', 0);
insert into room_unit_comments values (811, 102201, 2, 4, 1, 0, 1, 'アンタは人見知り\\nしないタチよね？\\nいいなあ～…', 0);
insert into room_unit_comments values (812, 102201, 2, 101, 4, 0, 1, 'ア、アンタってさ\\n好きな人とかい…\\nなな、何でもない！', 0);
insert into room_unit_comments values (813, 102201, 2, 102, 8, 0, 1, 'アンタと…そ、その\\nこうして話してるのも\\nわわ、悪くないわね！', 0);
insert into room_unit_comments values (814, 102201, 2, 1, 1, 1, 1, 'おおおおはよう！\\n…よし！\u3000ちゃんと\\nあいさつできたわ！', 0);
insert into room_unit_comments values (815, 102201, 2, 2, 1, 2, 1, '一緒にごはんとか…\\nううん、やっぱいい！\\nなんでもないからっ！', 0);
insert into room_unit_comments values (816, 102201, 2, 3, 1, 3, 1, '夜はこれからよ！\\n朝まで\\nゲームするからね！', 0);
insert into room_unit_comments values (817, 102201, 3, 1, 1, 0, 1, 'アカリみたいに\\n可愛くなるのは\\n難しいかな', 0);
insert into room_unit_comments values (818, 102201, 3, 2, 1, 0, 1, '寝っ転がりながら\\nゲームができれば\\n気分が良さそう', 0);
insert into room_unit_comments values (819, 102201, 3, 3, 1, 0, 1, '可愛い…けど、\\n私には似合わないかな', 0);
insert into room_unit_comments values (820, 102201, 3, 4, 1, 0, 1, 'はあ、リラックスして\\nゲームができるわ', 0);
insert into room_unit_comments values (821, 102201, 3, 5, 1, 0, 1, 'ん…暖かくて、\\n寝落ちしちゃいそう', 0);
insert into room_unit_comments values (822, 102201, 3, 6, 1, 0, 1, 'ゲーム感覚でやると、\\n体動かすのも\\n楽しいわね', 0);
insert into room_unit_comments values (823, 102201, 3, 7, 1, 0, 1, 'ゲームは頭使うから\\nそのぶん\\n栄養がいるのよ', 0);
insert into room_unit_comments values (824, 102201, 3, 8, 1, 0, 1, 'ふむふむ、なるほど\\n友だちを作るには\\n笑顔が大事っと…', 0);
insert into room_unit_comments values (826, 102202, 1, 1, 1, 0, 1, 'さあ、今日は\\n何のゲームで\\n遊ぼうかな？', 0);
insert into room_unit_comments values (827, 102202, 1, 2, 1, 0, 1, '一緒にゲームができる\\n人がいるっていうのも\\n新鮮だな…', 0);
insert into room_unit_comments values (828, 102202, 1, 3, 1, 0, 1, 'レアカードをゲット！\\nすごいでしょ！？', 0);
insert into room_unit_comments values (829, 102202, 1, 4, 1, 0, 1, 'アカリってどうやって\\n友達作ってるんだろ？\\nコツがあるのかな…', 0);
insert into room_unit_comments values (830, 102202, 1, 5, 1, 0, 1, '楽しいゲームって\\nやめどきが\\n見つからないわ', 0);
insert into room_unit_comments values (831, 102202, 1, 101, 8, 0, 1, 'うぅ…最近\\nアイツを見るとなんか\\nドキドキするのよね', 0);
insert into room_unit_comments values (832, 102202, 1, 102, 8, 0, 1, 'ね、ねえ\\nもう少しその…\\n一緒にゲームしない？', 0);
insert into room_unit_comments values (833, 102202, 2, 1, 1, 0, 1, 'ねえ、人見知りを\\n治すための練習に\\n付き合ってくれない？', 0);
insert into room_unit_comments values (834, 102202, 2, 2, 1, 0, 1, '欲しいゲームが\\n見つからなくて…\\n探すの手伝って！', 0);
insert into room_unit_comments values (835, 102202, 2, 3, 1, 0, 1, 'ねえ、見て！\\n新しいゲームを\\n買って来たの！', 0);
insert into room_unit_comments values (836, 102202, 2, 4, 1, 0, 1, 'ゲームに負けた罰\\nだからって、くすぐる\\nのは…あ、あはは！\\nだ、ダメだって！', 0);
insert into room_unit_comments values (837, 102202, 2, 101, 8, 0, 1, 'ア、アンタってさ\\n好きな人とかい…\\nなな、何でもない！', 0);
insert into room_unit_comments values (838, 102202, 2, 102, 8, 0, 1, 'あ、あのさ…\\nもう少し、そこに\\nいてくれてもいいわよ', 0);
insert into room_unit_comments values (839, 102202, 2, 1, 1, 1, 1, 'おおおおはよう！\\n…よし！\u3000ちゃんと\\nあいさつできたわ！', 0);
insert into room_unit_comments values (840, 102202, 2, 2, 1, 2, 1, '一緒にごはんとか…\\nううん、やっぱいい！\\nなんでもないからっ！', 0);
insert into room_unit_comments values (841, 102202, 2, 3, 1, 3, 1, '夜はこれからよ！\\n朝まで\\nゲームするからね！', 0);
insert into room_unit_comments values (842, 102202, 3, 1, 1, 0, 1, 'もっと女の子らしく\\nなったらアイツも\\n嬉しいかな…って、\\n何考えてるの！？', 0);
insert into room_unit_comments values (843, 102202, 3, 2, 1, 0, 1, 'ふああ…\\n徹夜明けには\\n辛い誘惑だな…', 0);
insert into room_unit_comments values (844, 102202, 3, 3, 1, 0, 1, '可愛い…けど、\\n私には似合わないかな', 0);
insert into room_unit_comments values (845, 102202, 3, 4, 1, 0, 1, 'こういうのに詳しいと\\n女の子っぽく\\n見えたりするのかな', 0);
insert into room_unit_comments values (846, 102202, 3, 5, 1, 0, 1, '寒い日は\\nここでゲームするのが\\n最高のぜいたくよね', 0);
insert into room_unit_comments values (847, 102202, 3, 6, 1, 0, 1, '最近ゲームばかりだし\\nたまにはいいかな？', 0);
insert into room_unit_comments values (848, 102202, 3, 7, 1, 0, 1, 'ゲームは頭使うから\\nそのぶん\\n栄養がいるのよ', 0);
insert into room_unit_comments values (849, 102202, 3, 8, 1, 0, 1, 'ふむふむ、なるほど\\n友だちを作るには\\n笑顔が大事っと…', 0);
insert into room_unit_comments values (851, 102301, 1, 1, 1, 0, 1, 'じゃんけんぽん！\\nあっち向いてほい！\\nあ～ん、負けたぁ\\n\u3000『勝ったぜ！』', 0);
insert into room_unit_comments values (852, 102301, 1, 2, 1, 0, 1, 'ぷうきちがいれば、\\nなんでも出来ちゃうよ', 0);
insert into room_unit_comments values (853, 102301, 1, 3, 1, 0, 1, '発声練習しよっと\\nぷうきち\\nフルスイ～ング！', 0);
insert into room_unit_comments values (854, 102301, 1, 4, 1, 0, 1, 'ここで、ぷうきち\\nフルスイングは、\\nまずいかな～？', 0);
insert into room_unit_comments values (855, 102301, 1, 5, 1, 0, 1, 'この部屋、ぷうきちを\\n置く場所はないのかな', 0);
insert into room_unit_comments values (856, 102301, 1, 101, 4, 0, 1, 'お兄ちゃんって…\\nちょっとぷうきちに\\n似てるかも♪', 0);
insert into room_unit_comments values (857, 102301, 1, 102, 8, 0, 1, 'お兄ちゃんにも、\\nぷうきちのこと\\n好きになって\\nもらいたいな～', 0);
insert into room_unit_comments values (858, 102301, 2, 1, 1, 0, 1, 'おやつは、\\n私とぷうきちの\\n二人分用意してね♪', 0);
insert into room_unit_comments values (859, 102301, 2, 2, 1, 0, 1, 'ぷうきちが、お腹\\nペコペコだって～\\n何かちょうだい！', 0);
insert into room_unit_comments values (860, 102301, 2, 3, 1, 0, 1, '『アヤネに手出したら\\n…坊ちゃんでも、\\n分かってんな？』', 0);
insert into room_unit_comments values (861, 102301, 2, 4, 1, 0, 1, 'ぷうきちとの\\n連携を磨いてるの！\\nもっと仲良くなるよ！', 0);
insert into room_unit_comments values (862, 102301, 2, 101, 4, 0, 1, '特別だからね？\\nもっと触っていいよ\\n…ぷうきちのこと', 0);
insert into room_unit_comments values (863, 102301, 2, 102, 8, 0, 1, 'お兄ちゃんのこと、\\n「ぷう兄」って\\n呼ぼうかな？', 0);
insert into room_unit_comments values (864, 102301, 2, 1, 1, 1, 1, 'お兄ちゃんって\\n朝早いんだね～\\n私はまだ眠いよ～', 0);
insert into room_unit_comments values (865, 102301, 2, 2, 1, 2, 1, 'ふぁ～…ぷうきちと\\nお昼寝してくるね…', 0);
insert into room_unit_comments values (866, 102301, 2, 3, 1, 3, 1, 'ぷうきちと\\nおしゃべりしてたら\\nもうこんな時間…', 0);
insert into room_unit_comments values (868, 102301, 3, 2, 1, 0, 1, '『座り心地がいいな』\\nぷうきちは座れない\\nでしょ？', 0);
insert into room_unit_comments values (869, 102301, 3, 3, 1, 0, 1, 'かわいい～！\\nぷうきちのお友達に\\nしちゃおうかな？', 0);
insert into room_unit_comments values (870, 102301, 3, 4, 1, 0, 1, 'いいニオイ～♪\\nぷうきちも\\n気に入ったみたい！', 0);
insert into room_unit_comments values (871, 102301, 3, 5, 1, 0, 1, 'ぽわぽわする～\\nぷうきちも\\n気持ちいい？', 0);
insert into room_unit_comments values (873, 102301, 3, 7, 1, 0, 1, 'おいしい～\\nぷうきちも\\n食べてみる？', 0);
insert into room_unit_comments values (874, 102301, 3, 8, 1, 0, 1, 'ぷうきち！\\nこの本、読んで～！', 0);
insert into room_unit_comments values (901, 102501, 1, 1, 1, 0, 1, 'どうして失敗ばっかり\\nこうなったら\\n腹を切るしか～！', 0);
insert into room_unit_comments values (902, 102501, 1, 2, 1, 0, 1, 'あれ？\u3000あれ？\\nお部屋の中で迷子に\\nなっちゃいました～', 0);
insert into room_unit_comments values (903, 102501, 1, 3, 1, 0, 1, 'どうしたら転ばなく\\nなるんでしょうか？', 0);
insert into room_unit_comments values (904, 102501, 1, 4, 1, 0, 1, 'わわわわ～～っ\\nふう…\\nきゃ、きゃあっ！', 0);
insert into room_unit_comments values (905, 102501, 1, 5, 1, 0, 1, '私のドジで、\\nこのお部屋を\\n壊しちゃったら\\nどうしましょう～～', 0);
insert into room_unit_comments values (906, 102501, 1, 101, 4, 0, 1, 'おいしい料理で\\nお出迎えしなくちゃ！', 0);
insert into room_unit_comments values (907, 102501, 1, 102, 8, 0, 1, '一生懸命\\nご奉仕しますよ～♪', 0);
insert into room_unit_comments values (908, 102501, 2, 1, 1, 0, 1, '耳かきしましょうか？\\nえ？\u3000こわい？', 0);
insert into room_unit_comments values (909, 102501, 2, 2, 1, 0, 1, 'お疲れでしたら、\\nお昼寝しませんか？\\n膝枕もしますよ？', 0);
insert into room_unit_comments values (910, 102501, 2, 3, 1, 0, 1, 'おかえりなさいませ\\nご主人さま♪', 0);
insert into room_unit_comments values (911, 102501, 2, 4, 1, 0, 1, 'すみません\\nすみません\\nすみません～～', 0);
insert into room_unit_comments values (912, 102501, 2, 101, 4, 0, 1, 'メイドの私が、\\nこんな気持ちを持って\\nいいんでしょうか…', 0);
insert into room_unit_comments values (913, 102501, 2, 102, 8, 0, 1, '私のこと、\\n専属メイドと思って\\n頼ってくださいね', 0);
insert into room_unit_comments values (914, 102501, 2, 1, 1, 1, 1, 'おはようございます♪\\n今日も一日がんば…\\nきゃ、きゃあ！', 0);
insert into room_unit_comments values (915, 102501, 2, 2, 1, 2, 1, 'お昼ごはん…\\n失敗しちゃいましたぁ\\nお、おやつでリベンジします！', 0);
insert into room_unit_comments values (916, 102501, 2, 3, 1, 3, 1, '明日の目標は\\nドジをしないです！\\nき、昨日の目標も\\nドジをしないでした', 0);
insert into room_unit_comments values (917, 102501, 3, 1, 1, 0, 1, 'あ、メイド服が\\nほつれてる\\n後でお裁縫しなくちゃ', 0);
insert into room_unit_comments values (918, 102501, 3, 2, 1, 0, 1, '休憩が終わったら\\nお洗濯にお料理に\\nお掃除もしないと！', 0);
insert into room_unit_comments values (919, 102501, 3, 3, 1, 0, 1, 'かわいい♪\\nあとでお洗濯\\nしてあげますね', 0);
insert into room_unit_comments values (920, 102501, 3, 4, 1, 0, 1, 'いい香り…\\nお嬢様のお部屋にも\\n置いてあげたいです', 0);
insert into room_unit_comments values (921, 102501, 3, 5, 1, 0, 1, 'ここでお洗濯ものを\\n乾かしましょうか', 0);
insert into room_unit_comments values (922, 102501, 3, 6, 1, 0, 1, 'あわわわっ…\\nこ、転びそうです～！', 0);
insert into room_unit_comments values (923, 102501, 3, 7, 1, 0, 1, 'これくらい\\nおいしいものを\\n作ってみたいです～', 0);
insert into room_unit_comments values (924, 102501, 3, 8, 1, 0, 1, '物語のメイドさんって\\n御主人さまを好きに\\nなるんですよね…', 0);
insert into room_unit_comments values (926, 102502, 1, 1, 1, 0, 1, '失敗したら、この\\nお部屋追い出され\\nちゃうかも～？', 0);
insert into room_unit_comments values (927, 102502, 1, 2, 1, 0, 1, 'あれ？\u3000あれ？\\nお部屋の中で迷子に\\nなっちゃいました～', 0);
insert into room_unit_comments values (928, 102502, 1, 3, 1, 0, 1, 'どうやったら、立派な\\nメイドになれるのかな', 0);
insert into room_unit_comments values (929, 102502, 1, 4, 1, 0, 1, '塩にはＳマーク\\n砂糖にはＳマーク\\n…あ、あれ！？', 0);
insert into room_unit_comments values (930, 102502, 1, 5, 1, 0, 1, 'ご用があれば\\nなんでも言って\\nくださいね', 0);
insert into room_unit_comments values (931, 102502, 1, 101, 8, 0, 1, '迷惑をかけすぎて…\\n嫌われちゃったら\\nどうしましょう', 0);
insert into room_unit_comments values (932, 102502, 1, 102, 8, 0, 1, 'メイドの私が\\nこんな気持ちを持って\\nいいんでしょうか…\u3000', 0);
insert into room_unit_comments values (933, 102502, 2, 1, 1, 0, 1, 'おでかけですか？\\nいってらっしゃいませ\\nご主人さま♪', 0);
insert into room_unit_comments values (934, 102502, 2, 2, 1, 0, 1, 'どうして失敗ばっかり\\nこうなったら\\n腹を切るしか～！', 0);
insert into room_unit_comments values (935, 102502, 2, 3, 1, 0, 1, '私、またなにか\\nやっちゃいましたか？', 0);
insert into room_unit_comments values (936, 102502, 2, 4, 1, 0, 1, 'おいしいお茶っ葉が\\n手に入りました～♪\\n一緒に飲みませんか？', 0);
insert into room_unit_comments values (937, 102502, 2, 101, 8, 0, 1, '転んだふりであの人に\\n…って！\\nなんでもないですよ！', 0);
insert into room_unit_comments values (938, 102502, 2, 102, 8, 0, 1, '私、できることなら\\nなんでもやりますよ\\nあなたのためですから', 0);
insert into room_unit_comments values (939, 102502, 2, 1, 1, 1, 1, 'おはようございます♪\\n今日も一日がんば…\\nう、うわあ！', 0);
insert into room_unit_comments values (940, 102502, 2, 2, 1, 2, 1, 'お昼ごはん…\\n失敗しちゃいましたぁ\\nお、おやつでリベンジします！', 0);
insert into room_unit_comments values (941, 102502, 2, 3, 1, 3, 1, '明日の目標は\\nドジをしないです！\\nき、昨日の目標も\\nドジをしないでした', 0);
insert into room_unit_comments values (942, 102502, 3, 1, 1, 0, 1, 'あ、メイド服が\\nほつれてる\\n後でお裁縫しなくちゃ', 0);
insert into room_unit_comments values (943, 102502, 3, 2, 1, 0, 1, 'いい座り心地です～\\nこれならお嬢さまも\\nゆったりできますね♪', 0);
insert into room_unit_comments values (944, 102502, 3, 3, 1, 0, 1, 'かわいい♪\\nあとでお洗濯\\nしてあげますね', 0);
insert into room_unit_comments values (945, 102502, 3, 4, 1, 0, 1, 'いい香り…\\nお嬢様のお部屋にも\\n置いてあげたいです', 0);
insert into room_unit_comments values (946, 102502, 3, 5, 1, 0, 1, '暖かいですけど\\n…私が火に近づいて\\n大丈夫でしょうか！？', 0);
insert into room_unit_comments values (947, 102502, 3, 6, 1, 0, 1, '運動しようとすると\\nいつも怪我するん\\nですよね…', 0);
insert into room_unit_comments values (948, 102502, 3, 7, 1, 0, 1, 'こんなに美味しいもの\\nメイドの私には\\nもったいないです～！', 0);
insert into room_unit_comments values (949, 102502, 3, 8, 1, 0, 1, '物語のメイドさんって\\n御主人さまを好きに\\nなるんですよね…', 0);
insert into room_unit_comments values (951, 102701, 1, 1, 1, 0, 1, 'あの方と私だけの\\n部屋にしたいですわ', 0);
insert into room_unit_comments values (952, 102701, 1, 2, 1, 0, 1, 'あの方は私のもの…\\n眼も耳も鼻も口も髪も\\n首も胸も腰も手も脚も\\nぬくもりも心も…！', 0);
insert into room_unit_comments values (953, 102701, 1, 3, 1, 0, 1, '運命とは決して\\n抗えないもの…\\nクスクス…クスクス', 0);
insert into room_unit_comments values (954, 102701, 1, 4, 1, 0, 1, '部屋からあの方の\\n香りが…\\nああ、至福ですわ', 0);
insert into room_unit_comments values (955, 102701, 1, 5, 1, 0, 1, '毒にも薬にもならない\\n存在なんて嫌ですわ\\nどうせならとびきりの\\n毒でありたい…', 0);
insert into room_unit_comments values (956, 102701, 1, 101, 4, 0, 1, 'クスクス…\\nあの方とデートする\\nイメトレ中ですわ\\nクスクスクスクス…', 0);
insert into room_unit_comments values (957, 102701, 1, 102, 8, 0, 1, '記憶を戻す研究より\\n記憶をねつ造する研究\\nのほうが良いかしら？\\n伴侶という設定で…', 0);
insert into room_unit_comments values (958, 102701, 2, 1, 1, 0, 1, '運命を信じますか？\\nもちろん絶対当然\\n信じますわよね？', 0);
insert into room_unit_comments values (959, 102701, 2, 2, 1, 0, 1, 'この薬は起床時就寝前\\n食前食後食間に、毎日\\n服用してください。\\n惚れ薬ですわ', 0);
insert into room_unit_comments values (960, 102701, 2, 3, 1, 0, 1, 'お願いがあるのです。\\n新しい研究の実験台に\\n…', 0);
insert into room_unit_comments values (961, 102701, 2, 4, 1, 0, 1, 'こっそり栽培している\\n毒きのこが毒々しく\\n育ちましたわ…', 0);
insert into room_unit_comments values (962, 102701, 2, 101, 4, 0, 1, 'あなた様の前では\\n普通の女の子…\\n少し毒薬づくりが\\n得意なだけの…', 0);
insert into room_unit_comments values (963, 102701, 2, 102, 8, 0, 1, '私の身も心も、全てが\\nあなた様のもの。\\nあなた様の全ても…', 0);
insert into room_unit_comments values (964, 102701, 2, 1, 1, 1, 1, 'おはようございます\\n一晩中、あなた様の\\n寝顔を見ていましたわ', 0);
insert into room_unit_comments values (965, 102701, 2, 2, 1, 2, 1, 'お昼を用意しましたの\\n何も入れていませんわ\\nクスクス…', 0);
insert into room_unit_comments values (966, 102701, 2, 3, 1, 3, 1, 'あなた様が眠るまで\\nお傍で見守りますわ。\\n…あの、どうして\\n眠らないのですか？', 0);
insert into room_unit_comments values (967, 102701, 3, 1, 1, 0, 1, 'いっそ鏡の中に\\n閉じ込めてしまえたら\\n私だけのものに…', 0);
insert into room_unit_comments values (968, 102701, 3, 2, 1, 0, 1, 'はっ！\\nリラックスしたら\\n閃きましたわ！', 0);
insert into room_unit_comments values (969, 102701, 3, 3, 1, 0, 1, 'あら、キメラの素体に\\nぴったりですわ', 0);
insert into room_unit_comments values (970, 102701, 3, 4, 1, 0, 1, 'このお部屋は\\n良い香りがしますわ。\\nはっ、あなた様の匂い\\nなのでは…！？', 0);
insert into room_unit_comments values (971, 102701, 3, 5, 1, 0, 1, 'あたたかい…\\n加熱調合にも\\n使えそうですわね', 0);
insert into room_unit_comments values (972, 102701, 3, 6, 1, 0, 1, 'この運動エネルギー\\n何かにうまく\\n利用できないかしら？', 0);
insert into room_unit_comments values (973, 102701, 3, 7, 1, 0, 1, '美味しい。あの方にも\\n差し上げましょう…\\n薬を入れて…', 0);
insert into room_unit_comments values (974, 102701, 3, 8, 1, 0, 1, 'あの方を虜にする\\n方法がどこかに\\n載ってるはずですわ', 0);
insert into room_unit_comments values (976, 102702, 1, 1, 1, 0, 1, 'あの方と私だけの\\n部屋にしたいですわ', 0);
insert into room_unit_comments values (977, 102702, 1, 2, 1, 0, 1, 'こっそり栽培している\\n毒きのこが毒々しく\\n育ちましたわ…', 0);
insert into room_unit_comments values (978, 102702, 1, 3, 1, 0, 1, '新しい薬\\nどうやってあの方に\\n飲ませようかしら', 0);
insert into room_unit_comments values (979, 102702, 1, 4, 1, 0, 1, '部屋からあの方の\\n香りが…\\nああ、至福ですわ', 0);
insert into room_unit_comments values (980, 102702, 1, 5, 1, 0, 1, '記憶を戻す研究より\\n記憶をねつ造する研究\\nのほうが良いかしら？\\n伴侶という設定で…', 0);
insert into room_unit_comments values (981, 102702, 1, 101, 8, 0, 1, 'クスクス…\\nあの方とデートする\\nイメトレ中ですわ\\nクスクスクスクス…', 0);
insert into room_unit_comments values (982, 102702, 1, 102, 8, 0, 1, '魔法も科学も錬金術も\\n全て駆使して\\nあの方のために…', 0);
insert into room_unit_comments values (983, 102702, 2, 1, 1, 0, 1, 'この部屋には雌犬…\\n失礼、女の方がとても\\n沢山いますのね', 0);
insert into room_unit_comments values (984, 102702, 2, 2, 1, 0, 1, 'あなた様には私の伴侶\\nとして高い教養を…\\nあ、逃げられてしまい\\nましたわ…！', 0);
insert into room_unit_comments values (985, 102702, 2, 3, 1, 0, 1, 'お願いがあるのです\\n新しい研究の\\n実験台に…', 0);
insert into room_unit_comments values (986, 102702, 2, 4, 1, 0, 1, 'あなた様が寝ている時\\n私は…クスクス\\nこれ以上は言えません', 0);
insert into room_unit_comments values (987, 102702, 2, 101, 8, 0, 1, '想像の中のあなた様は\\nすっかり私の虜なのに\\n現実は…\\nもどかしいですわね', 0);
insert into room_unit_comments values (988, 102702, 2, 102, 8, 0, 1, 'あなた様の前では\\n普通の女の子…\\n少し毒薬づくりが\\n得意なだけの…', 0);
insert into room_unit_comments values (989, 102702, 2, 1, 1, 1, 1, 'おはようございます\\n一晩中、あなた様の\\n寝顔を見ていましたわ', 0);
insert into room_unit_comments values (990, 102702, 2, 2, 1, 2, 1, 'さあ、お食事ですよ\\n味は保証しますわ\\n特製ソースで少しだけ\\n体が痺れますけど…', 0);
insert into room_unit_comments values (991, 102702, 2, 3, 1, 3, 1, 'あなた様が眠るまで\\nお傍で見守りますわ\\n…あの、どうして\\n眠らないのですか？', 0);
insert into room_unit_comments values (992, 102702, 3, 1, 1, 0, 1, '私ももう少し\\n外見に気を配る\\nべきでしょうか…', 0);
insert into room_unit_comments values (993, 102702, 3, 2, 1, 0, 1, 'はっ！\\nリラックスしたら\\n閃きましたわ！', 0);
insert into room_unit_comments values (994, 102702, 3, 3, 1, 0, 1, 'この私を差し置いて\\nあなた様に媚びるなど\\n言語道断…っ！', 0);
insert into room_unit_comments values (995, 102702, 3, 4, 1, 0, 1, 'このお部屋は\\n良い香りがしますわ\\nはっ、あなた様の匂い\\nなのでは…！？', 0);
insert into room_unit_comments values (996, 102702, 3, 5, 1, 0, 1, '素敵なぬくもり…\\nまるであの方に\\n抱きしめられたような', 0);
insert into room_unit_comments values (997, 102702, 3, 6, 1, 0, 1, 'この運動エネルギー\\n何かにうまく\\n利用できないかしら？', 0);
insert into room_unit_comments values (998, 102702, 3, 7, 1, 0, 1, '美味しい。あの方にも\\n差し上げましょう…\\n薬を入れて…', 0);
insert into room_unit_comments values (999, 102702, 3, 8, 1, 0, 1, 'あの方を虜にする\\n方法がどこかに\\n載ってるはずですわ', 0);
insert into room_unit_comments values (1001, 102801, 1, 1, 1, 0, 1, '子供たちの遊びって\\nあたしが子供の頃と\\nあまり変わらないのね', 0);
insert into room_unit_comments values (1002, 102801, 1, 2, 1, 0, 1, '使えるものは\\n再利用しないと\\n…あ、これとか\\nまだ使えるわね', 0);
insert into room_unit_comments values (1003, 102801, 1, 3, 1, 0, 1, '贅沢は敵！\u3000とはいえ\\n気持ちに余裕のない\\n暮らしはダメよね', 0);
insert into room_unit_comments values (1004, 102801, 1, 4, 1, 0, 1, 'お腹空いたわね、\\n残り物で\\n何か作ろうかしら', 0);
insert into room_unit_comments values (1005, 102801, 1, 5, 1, 0, 1, '商売はノンゼロサムが\\n理想だなぁ。誰も損を\\nしないってことだもの', 0);
insert into room_unit_comments values (1006, 102801, 1, 101, 4, 0, 1, 'あんたが手伝って\\nくれるから、仕事も\\n前より楽しいのよね♪', 0);
insert into room_unit_comments values (1007, 102801, 1, 102, 8, 0, 1, '焼きそばパンが\\n食べたいな～\\nあいつと…', 0);
insert into room_unit_comments values (1008, 102801, 2, 1, 1, 0, 1, 'ねぇあんた、どこか\\n安いお店知らない？', 0);
insert into room_unit_comments values (1009, 102801, 2, 2, 1, 0, 1, 'あたし、エレガントに\\n振る舞えてる？\\n…そう？\u3000嬉しい♪', 0);
insert into room_unit_comments values (1010, 102801, 2, 3, 1, 0, 1, 'いっぱい働いて遊んで\\nよく休んでまた働く。\\nそれが健全な生活よね', 0);
insert into room_unit_comments values (1011, 102801, 2, 4, 1, 0, 1, '一緒に部屋の\\n整頓でもする？\\nハマると楽しいわよ♪', 0);
insert into room_unit_comments values (1012, 102801, 2, 101, 4, 0, 1, 'あんたがいると\\n子供たちも喜ぶわ♪\\nもちろんあたしもね！', 0);
insert into room_unit_comments values (1013, 102801, 2, 102, 8, 0, 1, 'ね、あんた今、幸せ？\\n何びっくりしてるのよ\\n大事なことじゃないの', 0);
insert into room_unit_comments values (1014, 102801, 2, 1, 1, 1, 1, '面倒な用事は午前中に\\n片づけてしまうのが、\\n時間の使い方のコツよ', 0);
insert into room_unit_comments values (1015, 102801, 2, 2, 1, 2, 1, '午後のティータイム\\nとかどう？\\n良いカフェがあるの♪', 0);
insert into room_unit_comments values (1016, 102801, 2, 3, 1, 3, 1, 'さ、エレガントな夜を\\n楽しみましょ。\\nモダンな音楽でも\\nかけましょうか？', 0);
insert into room_unit_comments values (1017, 102801, 3, 1, 1, 0, 1, 'レディたるもの\\n身嗜みはしっかりとね\\n見本にならないと♪', 0);
insert into room_unit_comments values (1018, 102801, 3, 2, 1, 0, 1, 'これで仕事は一段落ね\\nちょっと休憩…', 0);
insert into room_unit_comments values (1019, 102801, 3, 3, 1, 0, 1, 'うふふ、\\nかわいいものを\\n見るのは幸せね～', 0);
insert into room_unit_comments values (1020, 102801, 3, 4, 1, 0, 1, '部屋中がいい香り…\\nなんだかすごい贅沢\\nしてる気分♪', 0);
insert into room_unit_comments values (1021, 102801, 3, 5, 1, 0, 1, '風邪を引かないように\\n身体を温めなくちゃ', 0);
insert into room_unit_comments values (1022, 102801, 3, 6, 1, 0, 1, 'さっ！\u3000家の中でも\\n効率的に\\nトレーニングよ！', 0);
insert into room_unit_comments values (1023, 102801, 3, 7, 1, 0, 1, 'もぐもぐ…はっ、\\n口の周り、\\n汚れてないわよね？', 0);
insert into room_unit_comments values (1024, 102801, 3, 8, 1, 0, 1, '知識から過去を学んで\\n未来に活かすわよ', 0);
insert into room_unit_comments values (1026, 102802, 1, 1, 1, 0, 1, '安売りのお店の情報\\n整理しないと…', 0);
insert into room_unit_comments values (1027, 102802, 1, 2, 1, 0, 1, 'どんなに苦労してても\\nそう見せないのが真の\\nエレガントなレディよ', 0);
insert into room_unit_comments values (1028, 102802, 1, 3, 1, 0, 1, '安く済んであいつが\\n喜ぶ料理とか…\\nないかしら', 0);
insert into room_unit_comments values (1029, 102802, 1, 4, 1, 0, 1, '子供たちの遊びって\\nあたしが子供の頃と\\nあまり変わらないのね', 0);
insert into room_unit_comments values (1030, 102802, 1, 5, 1, 0, 1, '商売はノンゼロサムが\\n理想だなぁ。誰も損を\\nしないってことだもの', 0);
insert into room_unit_comments values (1031, 102802, 1, 101, 8, 0, 1, '焼きそばパンが\\n食べたいな～\\nあいつと…', 0);
insert into room_unit_comments values (1032, 102802, 1, 102, 8, 0, 1, 'あいつと一緒に…\\n色々なところに\\nいきたいな', 0);
insert into room_unit_comments values (1033, 102802, 2, 1, 1, 0, 1, '今度買い物に\\n付き合いなさい\\nセールがあるのよ', 0);
insert into room_unit_comments values (1034, 102802, 2, 2, 1, 0, 1, 'あんたがいると子供\\nたちも喜ぶわ♪\\nもちろんあたしもね♪', 0);
insert into room_unit_comments values (1035, 102802, 2, 3, 1, 0, 1, 'いっぱい働いて遊んで\\nよく休んでまた働く\\nそれが健全な生活よね', 0);
insert into room_unit_comments values (1036, 102802, 2, 4, 1, 0, 1, 'あんたとこうして\\nのんびりするのも\\nいいものね', 0);
insert into room_unit_comments values (1037, 102802, 2, 101, 8, 0, 1, 'ねえ、今度遊びに\\n行きたいな\\nもちろん一緒に、よ', 0);
insert into room_unit_comments values (1038, 102802, 2, 102, 8, 0, 1, 'あんたが手伝って\\nくれるから、仕事も\\n前より楽しいのよね♪', 0);
insert into room_unit_comments values (1039, 102802, 2, 1, 1, 1, 1, '面倒な用事は午前中に\\n片づけてしまうのが\\n時間の使い方のコツよ', 0);
insert into room_unit_comments values (1040, 102802, 2, 2, 1, 2, 1, 'ランチにして午後の\\n仕事に備えましょ！\\nやることは一杯よ♪', 0);
insert into room_unit_comments values (1041, 102802, 2, 3, 1, 3, 1, 'ふわあ～\\nもうこんな時間\\n子供たちは\\nもう寝たかしら', 0);
insert into room_unit_comments values (1042, 102802, 3, 1, 1, 0, 1, '忙しい時こそ\\n身だしなみは隙なく\\nぴしっとね！', 0);
insert into room_unit_comments values (1043, 102802, 3, 2, 1, 0, 1, 'これで仕事は一段落ね\\nちょっと休憩…', 0);
insert into room_unit_comments values (1044, 102802, 3, 3, 1, 0, 1, 'ふふふ\\nずっと眺めてたく\\nなっちゃうわね', 0);
insert into room_unit_comments values (1045, 102802, 3, 4, 1, 0, 1, '部屋中がいい香り…\\nなんだかすごい贅沢\\nしてる気分♪', 0);
insert into room_unit_comments values (1046, 102802, 3, 5, 1, 0, 1, '風邪を引かないように\\n身体を温めなくちゃ', 0);
insert into room_unit_comments values (1047, 102802, 3, 6, 1, 0, 1, 'さっ！\u3000家の中でも\\n効率的に\\nトレーニングよ！', 0);
insert into room_unit_comments values (1048, 102802, 3, 7, 1, 0, 1, 'しっかり食べて\\n栄養補給、栄養補給！', 0);
insert into room_unit_comments values (1049, 102802, 3, 8, 1, 0, 1, '知識から過去を学んで\\n未来に活かすわよ', 0);
insert into room_unit_comments values (1051, 102901, 1, 1, 1, 0, 1, '可愛い子が\\nいっぱいいるなぁ…\\n誰か私とユニット\\n組んでくれないかな？', 0);
insert into room_unit_comments values (1052, 102901, 1, 2, 1, 0, 1, '今度のライブ会場、\\nいつもより大きいから\\n楽しみなんだ～！', 0);
insert into room_unit_comments values (1053, 102901, 1, 3, 1, 0, 1, '新曲の衣装、もうすぐ\\n出来あがるんだって！\\n楽しみだな～', 0);
insert into room_unit_comments values (1054, 102901, 1, 4, 1, 0, 1, '彼とデュエット\\nしてみたいな～♪', 0);
insert into room_unit_comments values (1055, 102901, 1, 5, 1, 0, 1, 'キラキラ無病息災、\\nドキドキ一日一善…\\n作詞って難しい～', 0);
insert into room_unit_comments values (1056, 102901, 1, 101, 4, 0, 1, 'ファンはもちろん\\n大事だけど…\\n彼のことは、もっと\\n大切にしたいな…', 0);
insert into room_unit_comments values (1057, 102901, 1, 102, 8, 0, 1, '写真集見なくても、\\n本物がここに\\nいるのにな～', 0);
insert into room_unit_comments values (1058, 102901, 2, 1, 1, 0, 1, '握手会の練習、\\n付き合ってくれない？', 0);
insert into room_unit_comments values (1059, 102901, 2, 2, 1, 0, 1, '写真集のポーズ\\n練習中～！\\nど、どうかな？', 0);
insert into room_unit_comments values (1060, 102901, 2, 3, 1, 0, 1, '何て書いてあるか\\n読めないって？\\nもー！\\nこれは私のサイン！', 0);
insert into room_unit_comments values (1061, 102901, 2, 4, 1, 0, 1, 'ね、次のライブ\\n観に来てくれる？\\nいい席とっとくから！', 0);
insert into room_unit_comments values (1062, 102901, 2, 101, 4, 0, 1, 'ねぇ、台本読むの\\nつきあってくれる？\\n恋人役に\\nなってほしいんだ', 0);
insert into room_unit_comments values (1063, 102901, 2, 102, 8, 0, 1, '新曲、聞いてくれた？\\nキミとのことを\\nテーマにしたんだよ。\\nどこかは秘密だけど♪', 0);
insert into room_unit_comments values (1064, 102901, 2, 1, 1, 1, 1, '朝の発声練習に\\n行くけど、キミも\\n一緒に来ない？', 0);
insert into room_unit_comments values (1065, 102901, 2, 2, 1, 2, 1, 'この時間は\\nお腹すくけど…\\n水着撮影があるから\\nお昼抜いてるんだ', 0);
insert into room_unit_comments values (1066, 102901, 2, 3, 1, 3, 1, '夜の帳が二人を包み\\n…こういう方向性の\\n歌詞も悪くないなぁ。', 0);
insert into room_unit_comments values (1067, 102901, 3, 1, 1, 0, 1, '身だしなみオッケー！\\nアイドルはいつでも\\n完璧でいなくちゃ！', 0);
insert into room_unit_comments values (1068, 102901, 3, 2, 1, 0, 1, 'ふぅ…\\nこんな姿、ファンには\\n見せられないな～', 0);
insert into room_unit_comments values (1069, 102901, 3, 3, 1, 0, 1, 'かわいい～♪\\nこれは強力な\\nライバル登場かな！', 0);
insert into room_unit_comments values (1070, 102901, 3, 4, 1, 0, 1, 'ステキな香り～♪\\n歌詞のイメージが\\n浮かんできそう！', 0);
insert into room_unit_comments values (1071, 102901, 3, 5, 1, 0, 1, '体も暖まったし！\\nダンスレッスンに\\n行こうかな♪', 0);
insert into room_unit_comments values (1072, 102901, 3, 6, 1, 0, 1, 'ベストタイム更新！\\nライブに向けて\\n体力つけないと…', 0);
insert into room_unit_comments values (1073, 102901, 3, 7, 1, 0, 1, '太っちゃったら\\nどうしよう…？\\nでも手が止まらない～', 0);
insert into room_unit_comments values (1074, 102901, 3, 8, 1, 0, 1, 'ステキなお話…\\n新曲の作詞の\\n参考になりそう♪', 0);
insert into room_unit_comments values (1076, 102902, 1, 1, 1, 0, 1, 'このお部屋すてき！\\nファンに追われた時の\\n隠れ家にピッタリね！', 0);
insert into room_unit_comments values (1077, 102902, 1, 2, 1, 0, 1, 'そろそろイメチェン\\nしてみようかな…\\nそれともこの路線で\\nもう少し…？', 0);
insert into room_unit_comments values (1078, 102902, 1, 3, 1, 0, 1, 'みんながくれた\\nファンレター…\\n私の大事な宝物…', 0);
insert into room_unit_comments values (1079, 102902, 1, 4, 1, 0, 1, '彼とデュエット\\nしてみたいな～♪', 0);
insert into room_unit_comments values (1080, 102902, 1, 5, 1, 0, 1, '疾風怒濤、威風堂々\\n獅子奮迅、唯我独尊…\\nラブソングの作詞って\\n難しいな～', 0);
insert into room_unit_comments values (1081, 102902, 1, 101, 8, 0, 1, 'ファンはもちろん\\n大事だけど…\\n彼のことは、もっと\\n大切にしたいな…', 0);
insert into room_unit_comments values (1082, 102902, 1, 102, 8, 0, 1, 'トップアイドルの\\nさらに先…\\n彼とならその景色も\\n見られるかな', 0);
insert into room_unit_comments values (1083, 102902, 2, 1, 1, 0, 1, '新曲の衣装、もうすぐ\\n出来あがるんだって！\\n楽しみだな～', 0);
insert into room_unit_comments values (1084, 102902, 2, 2, 1, 0, 1, 'アイドルノゾミだけ\\nじゃなくて、私の事も\\nちゃんと見てね？', 0);
insert into room_unit_comments values (1085, 102902, 2, 3, 1, 0, 1, 'キミに響かないなら\\nファンにも響くわけ\\nないよ！\u3000練習練習！', 0);
insert into room_unit_comments values (1086, 102902, 2, 4, 1, 0, 1, '衣装のスカートは\\n鉄壁なんだよ！\\n残念でした～', 0);
insert into room_unit_comments values (1087, 102902, 2, 101, 8, 0, 1, '新曲、聞いてくれた？\\nキミとのことを\\nテーマにしたんだよ\\nどこかは秘密だけど♪', 0);
insert into room_unit_comments values (1088, 102902, 2, 102, 8, 0, 1, 'ねぇ、私がトップ\\nアイドルになっても\\nちゃんと隣にいてね\\n遠くに行かないでね？', 0);
insert into room_unit_comments values (1089, 102902, 2, 1, 1, 1, 1, '朝の発声練習に\\n行くけど、キミも\\n一緒に来ない？', 0);
insert into room_unit_comments values (1090, 102902, 2, 2, 1, 2, 1, 'お昼ごはん行かない？\\n誰にも知られてない\\nお店があるんだけど！', 0);
insert into room_unit_comments values (1091, 102902, 2, 3, 1, 3, 1, '夜の帳が二人を包み\\n…こういう方向性の\\n歌詞も悪くないなぁ', 0);
insert into room_unit_comments values (1092, 102902, 3, 1, 1, 0, 1, '身だしなみオッケー！\\nアイドルはいつでも\\n完璧でいなくちゃ！', 0);
insert into room_unit_comments values (1093, 102902, 3, 2, 1, 0, 1, 'ふぅ…\\nこんな姿、ファンには\\n見せられないな～', 0);
insert into room_unit_comments values (1094, 102902, 3, 3, 1, 0, 1, 'かわいい～♪\\nこれは強力な\\nライバル登場かな！', 0);
insert into room_unit_comments values (1095, 102902, 3, 4, 1, 0, 1, 'みんなのイメージする\\nアイドルの香りは\\nこんな感じかな～', 0);
insert into room_unit_comments values (1096, 102902, 3, 5, 1, 0, 1, '体も暖まったし！\\nダンスレッスンに\\n行こうかな♪', 0);
insert into room_unit_comments values (1097, 102902, 3, 6, 1, 0, 1, 'ベストタイム更新！\\nライブに向けて\\n体力つけないと…', 0);
insert into room_unit_comments values (1098, 102902, 3, 7, 1, 0, 1, '太っちゃったら\\nどうしよう…？\\nでも手が止まらない～', 0);
insert into room_unit_comments values (1099, 102902, 3, 8, 1, 0, 1, 'この恋愛小説ステキ！\\n私もアイドルじゃ\\nなかったら…', 0);
insert into room_unit_comments values (1101, 103001, 1, 1, 1, 0, 1, '手裏剣の数が\\n合わないデス！\\nどこかに落とした\\nデスか…？', 0);
insert into room_unit_comments values (1102, 103001, 1, 2, 1, 0, 1, 'クセモノ、隠れても\\nむだデス！\\n…気のせいデシタ', 0);
insert into room_unit_comments values (1103, 103001, 1, 3, 1, 0, 1, '金は天下の\\nマワリモノ！\\nところで、\\nどういう意味デス？', 0);
insert into room_unit_comments values (1104, 103001, 1, 4, 1, 0, 1, 'むむ、アクダイカンの\\n気配がするデース', 0);
insert into room_unit_comments values (1105, 103001, 1, 5, 1, 0, 1, 'クニトリ合戦、\\n楽しみデース！', 0);
insert into room_unit_comments values (1106, 103001, 1, 101, 4, 0, 1, 'ショーグンと\\n出会えて、\\nワタシは果報者デス！', 0);
insert into room_unit_comments values (1107, 103001, 1, 102, 8, 0, 1, '最近、ショーグンの\\nそばにいると\\nドキドキするデス…', 0);
insert into room_unit_comments values (1108, 103001, 2, 1, 1, 0, 1, 'なんでも\\n命令するデス！\\nショーグンの命は\\n絶対デス！', 0);
insert into room_unit_comments values (1109, 103001, 2, 2, 1, 0, 1, 'あっ、ショーグン、\\n出陣はいつで\\nゴザルデス！？', 0);
insert into room_unit_comments values (1110, 103001, 2, 3, 1, 0, 1, 'さ、さすが\\nショーグンデス…\\nいつの間に背後を！？', 0);
insert into room_unit_comments values (1111, 103001, 2, 4, 1, 0, 1, '出陣の合図に\\n備えるデス！\\nほら貝は\\nどこデスか！？', 0);
insert into room_unit_comments values (1112, 103001, 2, 101, 4, 0, 1, '見つめられると\\nドキドキするデス…\\n新しい忍法デスか？', 0);
insert into room_unit_comments values (1113, 103001, 2, 102, 8, 0, 1, 'ショーグン！\\nえへへ…これからも\\nおそばに置いて\\nクダサイね？', 0);
insert into room_unit_comments values (1114, 103001, 2, 1, 1, 1, 1, 'おはようデス！\\n今日も一日\\n忍法日和デス！', 0);
insert into room_unit_comments values (1115, 103001, 2, 2, 1, 2, 1, 'そろそろお腹\\n空いてきたデス。\\n昼ごはんにするデス！', 0);
insert into room_unit_comments values (1116, 103001, 2, 3, 1, 3, 1, '明日もきっと\\nいい日デスよ、\\nショーグン！', 0);
insert into room_unit_comments values (1117, 103001, 3, 1, 1, 0, 1, 'ちょんまげに\\nしてみるのも\\n面白いかもデス！', 0);
insert into room_unit_comments values (1118, 103001, 3, 2, 1, 0, 1, '心地よくて\\n眠くなってきマス…\\nもしやテキコクの\\n罠デスか！？', 0);
insert into room_unit_comments values (1119, 103001, 3, 3, 1, 0, 1, 'これを変わり身の\\n術に…かわいそう\\nだから止めるデス', 0);
insert into room_unit_comments values (1120, 103001, 3, 4, 1, 0, 1, 'ワビサビというもの\\nデスね！\\n素晴らしいデス！', 0);
insert into room_unit_comments values (1121, 103001, 3, 5, 1, 0, 1, '身体を暖めて\\nイクサに向かうデス！', 0);
insert into room_unit_comments values (1122, 103001, 3, 6, 1, 0, 1, 'アクロバットな忍法を\\n使うには、体を\\n鍛えないと危険デス！', 0);
insert into room_unit_comments values (1123, 103001, 3, 7, 1, 0, 1, 'うーん、\\n美味しいデス…\\n幸せデス～', 0);
insert into room_unit_comments values (1124, 103001, 3, 8, 1, 0, 1, 'これは…\\nＢＵＳＨＩＤＯ…\\nデスか？', 0);
insert into room_unit_comments values (1126, 103002, 1, 1, 1, 0, 1, 'ふんふんふ～ん\\n武器の手入れは\\n念入りにしマスよ～', 0);
insert into room_unit_comments values (1127, 103002, 1, 2, 1, 0, 1, 'クセモノ、隠れても\\nむだデス！\\n…気のせいデシタ', 0);
insert into room_unit_comments values (1128, 103002, 1, 3, 1, 0, 1, '金は天下の\\nマワリモノ！\\nところで\\nどういう意味デス？', 0);
insert into room_unit_comments values (1129, 103002, 1, 4, 1, 0, 1, 'むむ、アクダイカンの\\n気配がするデース', 0);
insert into room_unit_comments values (1130, 103002, 1, 5, 1, 0, 1, 'クニトリ合戦\\n楽しみデース！', 0);
insert into room_unit_comments values (1131, 103002, 1, 101, 8, 0, 1, '最近、ショーグンの\\nそばにいると\\nドキドキするデス…', 0);
insert into room_unit_comments values (1132, 103002, 1, 102, 8, 0, 1, 'ショーグンの身は\\n何があってもワタシが\\n守るデス！', 0);
insert into room_unit_comments values (1133, 103002, 2, 1, 1, 0, 1, 'あっ、ショーグン\\n出陣はいつで\\nゴザルデス！？', 0);
insert into room_unit_comments values (1134, 103002, 2, 2, 1, 0, 1, 'イクサの前に\\nホネ休めも大事デスよ\\nゆっくりするデース！', 0);
insert into room_unit_comments values (1135, 103002, 2, 3, 1, 0, 1, 'さ、さすがショーグン\\nデス…いつの間に\\n背後を！？', 0);
insert into room_unit_comments values (1136, 103002, 2, 4, 1, 0, 1, '一緒に忍法考える\\nデス！\\nショーグン用の\\n忍法も必要デスね！', 0);
insert into room_unit_comments values (1137, 103002, 2, 101, 8, 0, 1, '見つめられると\\nドキドキするデス…\\n新しい忍法デスか？', 0);
insert into room_unit_comments values (1138, 103002, 2, 102, 8, 0, 1, 'ショーグン！\\nえへへ…これからも\\nおそばに置いて\\nクダサイね？', 0);
insert into room_unit_comments values (1139, 103002, 2, 1, 1, 1, 1, 'いい朝デス！\\nトーゴク風の朝ゴハン\\n作るデス！', 0);
insert into room_unit_comments values (1140, 103002, 2, 2, 1, 2, 1, 'もうお昼デス\\nお昼寝するデスか？', 0);
insert into room_unit_comments values (1141, 103002, 2, 3, 1, 3, 1, 'そろそろおネム\\nデース…\\n一緒に寝るデス？', 0);
insert into room_unit_comments values (1142, 103002, 3, 1, 1, 0, 1, '服の乱れは心の乱れ\\nデス！\u3000きっちり\\nしないといけないデス', 0);
insert into room_unit_comments values (1143, 103002, 3, 2, 1, 0, 1, '心地よくて眠く\\nなってきマス…\\nもしやテキコクの\\n罠デスか！？', 0);
insert into room_unit_comments values (1144, 103002, 3, 3, 1, 0, 1, 'これを変わり身の\\n術に…かわいそう\\nだから止めるデス', 0);
insert into room_unit_comments values (1145, 103002, 3, 4, 1, 0, 1, 'ワビサビというもの\\nデスね！\\n素晴らしいデス！', 0);
insert into room_unit_comments values (1146, 103002, 3, 5, 1, 0, 1, '身体を暖めてイクサに\\n向かうデス！', 0);
insert into room_unit_comments values (1147, 103002, 3, 6, 1, 0, 1, 'ショーグンのお役に\\n立つため、修行\\nあるのみデス！', 0);
insert into room_unit_comments values (1148, 103002, 3, 7, 1, 0, 1, '美味しいデス…\\n酢昆布を和えて\\nみたいデス', 0);
insert into room_unit_comments values (1149, 103002, 3, 8, 1, 0, 1, '物事を知って\\n来たるべきイクサに\\n活かすデス', 0);
insert into room_unit_comments values (1151, 103101, 1, 1, 1, 0, 1, 'お父さん、そろそろ\\n子離れを…しない？\\nそうですか…', 0);
insert into room_unit_comments values (1152, 103101, 1, 2, 1, 0, 1, '父は、いつも男性に\\nきびしいですね', 0);
insert into room_unit_comments values (1153, 103101, 1, 3, 1, 0, 1, '占ってほしい人は、\\nいつでも言って\\nください', 0);
insert into room_unit_comments values (1154, 103101, 1, 4, 1, 0, 1, 'あなたの手相は…\\nて、手を握るのって\\n緊張しますね', 0);
insert into room_unit_comments values (1155, 103101, 1, 5, 1, 0, 1, 'この部屋、風水的にも\\n運気が上がりそうです', 0);
insert into room_unit_comments values (1156, 103101, 1, 101, 4, 0, 1, 'あの人とのこと占って\\nみようかな…\\n好き…嫌い…\\n好き♪…き、嫌い', 0);
insert into room_unit_comments values (1157, 103101, 1, 102, 8, 0, 1, '私との相性ですか？\\nそれなら占う必要は\\nありませんよ…\\nふふっ♪', 0);
insert into room_unit_comments values (1158, 103101, 2, 1, 1, 0, 1, '女難の相が\\n出ていますね…\\n気をつけてください', 0);
insert into room_unit_comments values (1159, 103101, 2, 2, 1, 0, 1, '今日のあなたの運勢は\\n大きょ…\\n大吉です', 0);
insert into room_unit_comments values (1160, 103101, 2, 3, 1, 0, 1, '父と散歩中です。\\n毎日決まったコースを\\n散歩させないと、\\nストレスが溜まるので', 0);
insert into room_unit_comments values (1161, 103101, 2, 4, 1, 0, 1, '小僧！\\nシノブに触るとは\\nいい度胸じゃねぇか！', 0);
insert into room_unit_comments values (1162, 103101, 2, 101, 4, 0, 1, 'あなたに触られると、\\n動悸が早くなります\\nもしかして心霊現象？', 0);
insert into room_unit_comments values (1163, 103101, 2, 102, 8, 0, 1, '今日もたくさんの幽霊\\nに慕われていますね。\\n素敵です', 0);
insert into room_unit_comments values (1164, 103101, 2, 1, 1, 1, 1, 'おはようございます\\n今日の運勢を\\n占いましょうか？', 0);
insert into room_unit_comments values (1165, 103101, 2, 2, 1, 2, 1, '今日のラッキー\\nアイテムはドクロです\\n良ければ父を\\nお貸ししましょうか？', 0);
insert into room_unit_comments values (1166, 103101, 2, 3, 1, 3, 1, '今日のあなたの運気は\\n最高潮でした。\\nもうすぐ今日は\\n終わりますが', 0);
insert into room_unit_comments values (1167, 103101, 3, 1, 1, 0, 1, 'お父さん。\\nいつも、身だしなみに\\n気を使ってるけど、\\nあまり変わってないよ', 0);
insert into room_unit_comments values (1168, 103101, 3, 2, 1, 0, 1, '一休みしましょう。\\n憑かれて疲れました', 0);
insert into room_unit_comments values (1169, 103101, 3, 3, 1, 0, 1, 'かわいい…\\n付喪神が宿らないかな', 0);
insert into room_unit_comments values (1170, 103101, 3, 4, 1, 0, 1, 'お父さん、\\nリラックスし過ぎると\\n成仏しちゃうよ？', 0);
insert into room_unit_comments values (1171, 103101, 3, 5, 1, 0, 1, '気持ちいいです…\\n極楽浄土みたい…', 0);
insert into room_unit_comments values (1172, 103101, 3, 6, 1, 0, 1, 'はぁはぁ…\\nお、お父さん、\\n代わりに運動して…', 0);
insert into room_unit_comments values (1173, 103101, 3, 7, 1, 0, 1, 'お父さんも\\n食べたいの？\\n死んでるのに？', 0);
insert into room_unit_comments values (1174, 103101, 3, 8, 1, 0, 1, 'この本…\\nもしかして予言書？', 0);
insert into room_unit_comments values (1176, 103102, 1, 1, 1, 0, 1, 'ここにいる幽霊は\\nみんな幸せそうです', 0);
insert into room_unit_comments values (1177, 103102, 1, 2, 1, 0, 1, 'お父さんが\\n女の子ばかりに\\n声をかけるので\\n困っています', 0);
insert into room_unit_comments values (1178, 103102, 1, 3, 1, 0, 1, '成仏はうれしいこと\\nです…でも友達が\\n減るのは寂しいですね', 0);
insert into room_unit_comments values (1179, 103102, 1, 4, 1, 0, 1, '幽霊に好かれる人は\\n素敵な方です\\nもちろん、あなたも', 0);
insert into room_unit_comments values (1180, 103102, 1, 5, 1, 0, 1, 'お父さん、そろそろ\\n子離れを…しない？\\nそうですか…', 0);
insert into room_unit_comments values (1181, 103102, 1, 101, 8, 0, 1, '生きている人に\\n好かれるには、\\nどうすればいい\\nのでしょう？', 0);
insert into room_unit_comments values (1182, 103102, 1, 102, 8, 0, 1, 'お父さん、どうしたら\\nあの人のことを\\n認めてくれますか？', 0);
insert into room_unit_comments values (1183, 103102, 2, 1, 1, 0, 1, 'この部屋、風水的にも\\n運気が上がりそうです', 0);
insert into room_unit_comments values (1184, 103102, 2, 2, 1, 0, 1, 'シノブには指一本\\n触れさせん！\\nガブッ！！', 0);
insert into room_unit_comments values (1185, 103102, 2, 3, 1, 0, 1, 'あなたの手相は…\\nて、手を握るのって\\n緊張しますね', 0);
insert into room_unit_comments values (1186, 103102, 2, 4, 1, 0, 1, 'ラップ音？\\nいえ、父のいびきです', 0);
insert into room_unit_comments values (1187, 103102, 2, 101, 8, 0, 1, '私との相性ですか？\\nそれなら占う必要は\\nありませんよ…\\nふふっ♪', 0);
insert into room_unit_comments values (1188, 103102, 2, 102, 8, 0, 1, '前世って信じますか？\\n私とあなたは\\nもしかすると…', 0);
insert into room_unit_comments values (1189, 103102, 2, 1, 1, 1, 1, '今日のラッキー\\nアイテムはドクロです\\n良ければ父を\\nお貸ししましょうか？', 0);
insert into room_unit_comments values (1190, 103102, 2, 2, 1, 2, 1, '明るい時間は\\nあまり得意では\\nないんです…', 0);
insert into room_unit_comments values (1191, 103102, 2, 3, 1, 3, 1, '夜のお散歩に\\n行きませんか？\\n知り合いの幽霊に\\n挨拶して回るんです', 0);
insert into room_unit_comments values (1192, 103102, 3, 1, 1, 0, 1, 'お父さん\\nいつも、身だしなみに\\n気を使ってるけど\\nあまり変わってないよ', 0);
insert into room_unit_comments values (1193, 103102, 3, 2, 1, 0, 1, 'うとうと…\\nあれ…\\n走馬灯が見える…', 0);
insert into room_unit_comments values (1194, 103102, 3, 3, 1, 0, 1, 'かわいい…\\nお父さんみたい…', 0);
insert into room_unit_comments values (1195, 103102, 3, 4, 1, 0, 1, 'お父さん\\nリラックスし過ぎると\\n成仏しちゃうよ？', 0);
insert into room_unit_comments values (1196, 103102, 3, 5, 1, 0, 1, '快適です…\\n幽霊もどんどん\\n集まってきますね…', 0);
insert into room_unit_comments values (1197, 103102, 3, 6, 1, 0, 1, 'はぁはぁ…\\nお、お父さん、\\n代わりに運動して…', 0);
insert into room_unit_comments values (1198, 103102, 3, 7, 1, 0, 1, 'お父さんの分も、\\n私が食べるね', 0);
insert into room_unit_comments values (1199, 103102, 3, 8, 1, 0, 1, 'この本の占い\\n私の占いと違う…', 0);
insert into room_unit_comments values (1201, 103201, 1, 1, 1, 0, 1, '私だって、一人で\\n買い物ぐらい\\nできますわ…きっと', 0);
insert into room_unit_comments values (1202, 103201, 1, 2, 1, 0, 1, 'そろそろ新しい\\n案件を始めないと\\nいけませんわね', 0);
insert into room_unit_comments values (1203, 103201, 1, 3, 1, 0, 1, '一日も早く、\\n一人前の商人に\\nなりたいものです', 0);
insert into room_unit_comments values (1204, 103201, 1, 4, 1, 0, 1, '平和を買うのには\\nどれほどのお金が\\n必要なのかしら？', 0);
insert into room_unit_comments values (1205, 103201, 1, 5, 1, 0, 1, 'ここももう少し広いと\\n落ち着くのですけど。\\n改築しませんこと？', 0);
insert into room_unit_comments values (1206, 103201, 1, 101, 4, 0, 1, 'あの方はお金で雇った\\nわけではないのに\\n私といてくださる…', 0);
insert into room_unit_comments values (1207, 103201, 1, 102, 8, 0, 1, 'たとえ私が間違っても\\nきっとあの方が\\n正してくれますわ…', 0);
insert into room_unit_comments values (1208, 103201, 2, 1, 1, 0, 1, '私と、庶民向けの\\nお店へ一緒に\\n参りませんか？', 0);
insert into room_unit_comments values (1209, 103201, 2, 2, 1, 0, 1, '資産運用？\\nお幾らほど\\n増やしたいのです？', 0);
insert into room_unit_comments values (1210, 103201, 2, 3, 1, 0, 1, 'どんぶり勘定だとよく\\n言われるのですが…\\n例えが小さすぎます！', 0);
insert into room_unit_comments values (1211, 103201, 2, 4, 1, 0, 1, 'お金で解決するのは\\n悪いことでは\\nありませんわよね？', 0);
insert into room_unit_comments values (1212, 103201, 2, 101, 4, 0, 1, 'その、よろしければ\\n私とお散歩など\\nいかがです？', 0);
insert into room_unit_comments values (1213, 103201, 2, 102, 8, 0, 1, 'もしあなたさまが\\n道に迷われるなら、\\n私もお供いたします！', 0);
insert into room_unit_comments values (1214, 103201, 2, 1, 1, 1, 1, '早起きは三ルピの徳と\\n申しますが…\\nもっとお得ですわね', 0);
insert into room_unit_comments values (1215, 103201, 2, 2, 1, 2, 1, '昼食は町の屋台で\\n立ったまま食べて\\nみたいですわ！', 0);
insert into room_unit_comments values (1216, 103201, 2, 3, 1, 3, 1, 'よろしければ\\nお休み前のミルクを\\n御一緒にいかが？', 0);
insert into room_unit_comments values (1217, 103201, 3, 1, 1, 0, 1, 'だらしない身なりでは\\n取引相手に信用して\\nいただけませんものね', 0);
insert into room_unit_comments values (1218, 103201, 3, 2, 1, 0, 1, 'この感触と安らぎ…\\n素晴らしい\\n費用対効果ですわ…', 0);
insert into room_unit_comments values (1219, 103201, 3, 3, 1, 0, 1, '何の見返りも求めず\\nただひたすら愛でて\\nいたいのです！', 0);
insert into room_unit_comments values (1220, 103201, 3, 4, 1, 0, 1, '目に見えないものに\\nお金をかけるのが\\n真の贅沢ですわ！', 0);
insert into room_unit_comments values (1221, 103201, 3, 5, 1, 0, 1, '誰ひとり寒い思いを\\nしない町にするために\\n私にできる事は…', 0);
insert into room_unit_comments values (1222, 103201, 3, 6, 1, 0, 1, '健康はお金では\\n買えませんが\\n運動器具は別ですわ！', 0);
insert into room_unit_comments values (1223, 103201, 3, 7, 1, 0, 1, 'なかなか\\n美味ですわ\\nシェフはどちらに？', 0);
insert into room_unit_comments values (1224, 103201, 3, 8, 1, 0, 1, '経済の仕組みを\\nしっかりと\\n学ばなくては…', 0);
insert into room_unit_comments values (1226, 103202, 1, 1, 1, 0, 1, 'そろそろ新しい\\n案件を始めないと\\nいけませんわね', 0);
insert into room_unit_comments values (1227, 103202, 1, 2, 1, 0, 1, 'ええと、これは\\nおいくらで買ったん\\nでしたっけ？', 0);
insert into room_unit_comments values (1228, 103202, 1, 3, 1, 0, 1, 'お金を見せたら\\n態度が変わる人は\\n信用できませんわ', 0);
insert into room_unit_comments values (1229, 103202, 1, 4, 1, 0, 1, '地図が読めずとも\\n道に迷わない方って\\nいらっしゃるのですね', 0);
insert into room_unit_comments values (1230, 103202, 1, 5, 1, 0, 1, 'この狭さも\\n慣れれば\\n快適ですわ♪', 0);
insert into room_unit_comments values (1231, 103202, 1, 101, 8, 0, 1, 'あの方はお金で雇った\\nわけではないのに\\n私といてくださる…', 0);
insert into room_unit_comments values (1232, 103202, 1, 102, 8, 0, 1, 'たとえ私が間違っても\\nきっとあの方が\\n正してくれますわ…', 0);
insert into room_unit_comments values (1233, 103202, 2, 1, 1, 0, 1, '一人前の商人に\\n相応しい居振る舞いを\\nしたいものですわ', 0);
insert into room_unit_comments values (1234, 103202, 2, 2, 1, 0, 1, '幼い頃\\nお店屋さんごっこを\\nなさいましたか？', 0);
insert into room_unit_comments values (1235, 103202, 2, 3, 1, 0, 1, '資産運用？\\nお幾らほど\\n増やしたいのです？', 0);
insert into room_unit_comments values (1236, 103202, 2, 4, 1, 0, 1, '今度一緒に…\\nパーティにでも\\n行きませんこと？', 0);
insert into room_unit_comments values (1237, 103202, 2, 101, 8, 0, 1, 'その、よろしければ\\n私とお散歩など\\nいかがです？', 0);
insert into room_unit_comments values (1238, 103202, 2, 102, 8, 0, 1, 'あなたさまの優しさは\\nお金には\\n代えられませんわね', 0);
insert into room_unit_comments values (1239, 103202, 2, 1, 1, 1, 1, 'なぜだか\\n眠り足りないような\\n感じがしますわ…', 0);
insert into room_unit_comments values (1240, 103202, 2, 2, 1, 2, 1, '昼食は町の屋台で\\n立ったまま食べて\\nみたいですわ！', 0);
insert into room_unit_comments values (1241, 103202, 2, 3, 1, 3, 1, 'よろしければ\\nお休み前のミルクを\\n御一緒にいかが？', 0);
insert into room_unit_comments values (1242, 103202, 3, 1, 1, 0, 1, 'ドレスは汚れていない\\nようですが…やだ\\n髪がほつれてますわ！', 0);
insert into room_unit_comments values (1243, 103202, 3, 2, 1, 0, 1, 'こういったものに\\n腰を沈めると…\\nき、気が緩んで…', 0);
insert into room_unit_comments values (1244, 103202, 3, 3, 1, 0, 1, '何の見返りも求めず\\nただひたすら愛でて\\nいたいのです！', 0);
insert into room_unit_comments values (1245, 103202, 3, 4, 1, 0, 1, '香りは質のいいものと\\nそうでないものが\\nはっきり分かりますわ', 0);
insert into room_unit_comments values (1246, 103202, 3, 5, 1, 0, 1, '誰ひとり寒い思いを\\nしない町にするために\\n私にできる事は…', 0);
insert into room_unit_comments values (1247, 103202, 3, 6, 1, 0, 1, '目標は遠くに\\n置いた方が励みに\\nなりますわ！', 0);
insert into room_unit_comments values (1248, 103202, 3, 7, 1, 0, 1, 'なかなか\\n美味ですわ\\nシェフはどちらに？', 0);
insert into room_unit_comments values (1249, 103202, 3, 8, 1, 0, 1, '商人って、物語では\\n悪役にされやすいの\\nですね…', 0);
insert into room_unit_comments values (1251, 103301, 1, 1, 1, 0, 1, '家の中のものを使って\\n物ボケ、考えるべ！', 0);
insert into room_unit_comments values (1252, 103301, 1, 2, 1, 0, 1, '毎日の日課…それは\\n炊事、洗濯、大喜利\\nだべ！', 0);
insert into room_unit_comments values (1253, 103301, 1, 3, 1, 0, 1, 'うちに塀ができたら、\\nへー、って言いたい！', 0);
insert into room_unit_comments values (1254, 103301, 1, 4, 1, 0, 1, 'オラが作る料理は\\nこの後スタッフで\\n美味しくいただくべよ', 0);
insert into room_unit_comments values (1255, 103301, 1, 5, 1, 0, 1, 'エリザベスも\\n連れてきてぇ～', 0);
insert into room_unit_comments values (1256, 103301, 1, 101, 4, 0, 1, 'あんちゃんも、\\nエリザベスと同じ位\\nめんこいべ♪', 0);
insert into room_unit_comments values (1257, 103301, 1, 102, 8, 0, 1, 'オラとあんちゃん、\\n息がぴったりに\\nなってきたべ…！', 0);
insert into room_unit_comments values (1258, 103301, 2, 1, 1, 0, 1, 'おぉ！\u3000そんな急に\\nツッコまれたら、\\nびっくらこくべやー！', 0);
insert into room_unit_comments values (1259, 103301, 2, 2, 1, 0, 1, 'ネタはオラが書くけど\\nあんちゃんが\\n書きたかったら\\n書いてもいいんだぞ？', 0);
insert into room_unit_comments values (1260, 103301, 2, 3, 1, 0, 1, 'あんちゃん、オラには\\n容赦なんかせずに\\nツッコんでくれて\\nいいから！', 0);
insert into room_unit_comments values (1261, 103301, 2, 4, 1, 0, 1, '押すなよ、\\n絶対押すなよ\\n…なんて\\n言ってないべさ？', 0);
insert into room_unit_comments values (1262, 103301, 2, 101, 4, 0, 1, 'うう…あんちゃんに\\nツッコまれたくて\\nうずうずしてきたべ～', 0);
insert into room_unit_comments values (1263, 103301, 2, 102, 8, 0, 1, '将来的には夫婦漫才\\nってのも…あ、ひ、\\nひとりごとだべさ～！', 0);
insert into room_unit_comments values (1264, 103301, 2, 1, 1, 1, 1, 'おはよう！\u3000一緒に\\n牛の乳しぼりいくべ？', 0);
insert into room_unit_comments values (1265, 103301, 2, 2, 1, 2, 1, 'お昼だ～腹が減っては\\n笑いはできぬ～！', 0);
insert into room_unit_comments values (1266, 103301, 2, 3, 1, 3, 1, '今日もよく働いたべ！\\nさ、今からは\\nお笑いの練習だ～！', 0);
insert into room_unit_comments values (1267, 103301, 3, 1, 1, 0, 1, '舞台に上がる前に\\n身なりは整えねぇと\\nだめだべ～！', 0);
insert into room_unit_comments values (1268, 103301, 3, 2, 1, 0, 1, 'ナイスなイスに\\n座りたい、\\nなんちゃって！', 0);
insert into room_unit_comments values (1269, 103301, 3, 3, 1, 0, 1, 'めんこいのは、\\nスベっても許される\\nからずるいべな～？', 0);
insert into room_unit_comments values (1270, 103301, 3, 4, 1, 0, 1, '必要以上に\\n癒されちまうべや～', 0);
insert into room_unit_comments values (1271, 103301, 3, 5, 1, 0, 1, 'ぽかぽかだ…\\nウケた会場みてぇだ', 0);
insert into room_unit_comments values (1272, 103301, 3, 6, 1, 0, 1, 'お笑い芸人は、\\n体が資本だべさ～！', 0);
insert into room_unit_comments values (1273, 103301, 3, 7, 1, 0, 1, 'もぐもぐ…\\nボケることも\\n忘れちまう美味さだ～', 0);
insert into room_unit_comments values (1274, 103301, 3, 8, 1, 0, 1, 'ネタ作りのヒントが\\n載ってねぇか探すべ', 0);
insert into room_unit_comments values (1276, 103302, 1, 1, 1, 0, 1, 'さぁ今日も張り切って\\n漫才の練習するべさ！', 0);
insert into room_unit_comments values (1277, 103302, 1, 2, 1, 0, 1, 'この部屋でも、商品\\n売っていいんだべか？', 0);
insert into room_unit_comments values (1278, 103302, 1, 3, 1, 0, 1, '眼鏡を頭の上に乗せて\\n「メガネメガネ～」\\nって言う練習した方が\\nいいべか？', 0);
insert into room_unit_comments values (1279, 103302, 1, 4, 1, 0, 1, '漫才を持ち時間に\\n収めるには、何度も\\n練習するしかねぇべ', 0);
insert into room_unit_comments values (1280, 103302, 1, 5, 1, 0, 1, 'エリザベスも\\n連れてきてぇ～', 0);
insert into room_unit_comments values (1281, 103302, 1, 101, 8, 0, 1, 'うう…あんちゃんに\\nツッコまれたくて\\nうずうずしてきたべ～', 0);
insert into room_unit_comments values (1282, 103302, 1, 102, 8, 0, 1, 'あんちゃんに\\n採れたての食材を\\n食わしてやりてぇ～', 0);
insert into room_unit_comments values (1283, 103302, 2, 1, 1, 0, 1, '押すなよ\\n絶対押すなよ\\n…なんて\\n言ってないべさ？', 0);
insert into room_unit_comments values (1284, 103302, 2, 2, 1, 0, 1, 'あんちゃん、百連\\nツッコミ特訓だ～！', 0);
insert into room_unit_comments values (1285, 103302, 2, 3, 1, 0, 1, 'あんちゃん、オラには\\n容赦なんかせずに\\nツッコんでくれて\\nいいから！', 0);
insert into room_unit_comments values (1286, 103302, 2, 4, 1, 0, 1, '「なんでだべ～！」\\nって言いながら\\nツッコむといいべ！', 0);
insert into room_unit_comments values (1287, 103302, 2, 101, 8, 0, 1, 'あはは～あんちゃんの\\nツッコミはやっぱり\\n気持ちいいなぁ～', 0);
insert into room_unit_comments values (1288, 103302, 2, 102, 8, 0, 1, '将来的には夫婦漫才\\nってのも…あ、ひ\\nひとりごとだべさ～！', 0);
insert into room_unit_comments values (1289, 103302, 2, 1, 1, 1, 1, 'おはよう！\\n今日もいい\\nネタ作り日和だ！', 0);
insert into room_unit_comments values (1290, 103302, 2, 2, 1, 2, 1, 'お昼だな\\nご飯を食べたら、\\nネタの練習するべ！', 0);
insert into room_unit_comments values (1291, 103302, 2, 3, 1, 3, 1, 'もうこんな時間だべ\\nネタ作りは\\n明日にするべ…', 0);
insert into room_unit_comments values (1292, 103302, 3, 1, 1, 0, 1, 'うーん…衣装、\\nずれてねぇべか？', 0);
insert into room_unit_comments values (1293, 103302, 3, 2, 1, 0, 1, 'ナイスなイスに\\n座りたい\\nなんちゃって！', 0);
insert into room_unit_comments values (1294, 103302, 3, 3, 1, 0, 1, 'はう～\\nなまらめんこいべや～', 0);
insert into room_unit_comments values (1295, 103302, 3, 4, 1, 0, 1, '必要以上に\\n癒されちまうべや～', 0);
insert into room_unit_comments values (1296, 103302, 3, 5, 1, 0, 1, '笑いをとることを\\n忘れるほど\\nあったけぇべ～', 0);
insert into room_unit_comments values (1297, 103302, 3, 6, 1, 0, 1, 'たくさん運動して\\n動きでも笑いがとれる\\nように頑張るべ～！', 0);
insert into room_unit_comments values (1298, 103302, 3, 7, 1, 0, 1, 'もぐもぐ…\\nボケることも\\n忘れちまう美味さだ～', 0);
insert into room_unit_comments values (1299, 103302, 3, 8, 1, 0, 1, '幅広く教養を\\n身につけて\\nいいネタ作るべ！', 0);
insert into room_unit_comments values (1301, 103401, 1, 1, 1, 0, 1, '通りにいる\\nカップル…爆発\\nすればいいのに…', 0);
insert into room_unit_comments values (1302, 103401, 1, 2, 1, 0, 1, 'う～ん、仕事なんて\\nしないで、\\n飲んでたいな～', 0);
insert into room_unit_comments values (1303, 103401, 1, 3, 1, 0, 1, '今日は一日、\\n外に出ない！\\nもう決めたわ！', 0);
insert into room_unit_comments values (1304, 103401, 1, 4, 1, 0, 1, 'お腹空いた…\\nけど、外に出るのは\\n面倒だなぁ', 0);
insert into room_unit_comments values (1305, 103401, 1, 5, 1, 0, 1, 'うぅ…頭がガンガン\\nする…昨日、\\n飲み過ぎたかな…', 0);
insert into room_unit_comments values (1306, 103401, 1, 101, 4, 0, 1, 'デートとか…\\n誘っても嫌がられ\\nないかな…？', 0);
insert into room_unit_comments values (1307, 103401, 1, 102, 8, 0, 1, 'もしかして運命の\\n相手だったり…\\nするのかな', 0);
insert into room_unit_comments values (1308, 103401, 2, 1, 1, 0, 1, 'やっぱり一杯目が\\n一番おいしいわ～！\\n…え、見てた！？', 0);
insert into room_unit_comments values (1309, 103401, 2, 2, 1, 0, 1, '頼れるお姉さんだって\\nところ、もっと見せて\\nあげるからね', 0);
insert into room_unit_comments values (1310, 103401, 2, 3, 1, 0, 1, 'ねえ、一緒に買い物に\\n行かない？\u3000その…\\nの、飲み物とか…', 0);
insert into room_unit_comments values (1311, 103401, 2, 4, 1, 0, 1, 'ひっく、うふふ…\\nもっとお姉さんと\\nお話しようよ～', 0);
insert into room_unit_comments values (1312, 103401, 2, 101, 4, 0, 1, '極力人付き合いは\\nしない主義なんだけど\\nキミは例外かも…', 0);
insert into room_unit_comments values (1313, 103401, 2, 102, 8, 0, 1, 'いつか…\\nキミと一緒に飲めたら\\n楽しいだろうな', 0);
insert into room_unit_comments values (1314, 103401, 2, 1, 1, 1, 1, 'おはよう…朝は\\nちょっとつらいな…\\n低血圧なのよ…', 0);
insert into room_unit_comments values (1315, 103401, 2, 2, 1, 2, 1, 'おっひるー♪\\nなに食べよっかな～♪', 0);
insert into room_unit_comments values (1316, 103401, 2, 3, 1, 3, 1, 'ふわあ…\\n眠る前にちょっと\\n一杯…冗談よ', 0);
insert into room_unit_comments values (1317, 103401, 3, 1, 1, 0, 1, 'うう…\\n髪がボサボサ…\\nちゃんとしなきゃ…', 0);
insert into room_unit_comments values (1318, 103401, 3, 2, 1, 0, 1, '自然体でゴロゴロ\\nするのって\\n幸せだなぁ…', 0);
insert into room_unit_comments values (1319, 103401, 3, 3, 1, 0, 1, 'こういうの男の子に\\nプレゼントして\\nもらいたいな…', 0);
insert into room_unit_comments values (1320, 103401, 3, 4, 1, 0, 1, 'うわあ、\\nこれ、私の好きな\\n香りだー！', 0);
insert into room_unit_comments values (1321, 103401, 3, 5, 1, 0, 1, 'ぽっかぽか…\\nあとは熱い一杯が\\nあれば…！', 0);
insert into room_unit_comments values (1322, 103401, 3, 6, 1, 0, 1, '家でゴロゴロして\\n付いちゃったお肉を\\n落とさないと…！', 0);
insert into room_unit_comments values (1323, 103401, 3, 7, 1, 0, 1, 'もぐもぐ…\\nおーいしー！\\n…太らないよね？', 0);
insert into room_unit_comments values (1324, 103401, 3, 8, 1, 0, 1, '大人の女らしく\\n色んなことを学んで\\nおかなくっちゃ', 0);
insert into room_unit_comments values (1326, 103402, 1, 1, 1, 0, 1, '仕事終わりの一杯の\\nために、今日も\\n頑張らないと', 0);
insert into room_unit_comments values (1327, 103402, 1, 2, 1, 0, 1, '今日は\\nのんびり\\n過ごそうかな～', 0);
insert into room_unit_comments values (1328, 103402, 1, 3, 1, 0, 1, 'あ…\\nお皿、洗って\\nなかった…', 0);
insert into room_unit_comments values (1329, 103402, 1, 4, 1, 0, 1, 'もう少し、大人の\\n魅力が出せるように\\nなりたいな', 0);
insert into room_unit_comments values (1330, 103402, 1, 5, 1, 0, 1, '素敵な彼氏…\\n欲しいなぁ…', 0);
insert into room_unit_comments values (1331, 103402, 1, 101, 8, 0, 1, '彼と私\\n釣り合うかな…\\n大丈夫よね？', 0);
insert into room_unit_comments values (1332, 103402, 1, 102, 8, 0, 1, '今後のために\\nちょっとは花嫁修業\\nしてみようかな…？', 0);
insert into room_unit_comments values (1333, 103402, 2, 1, 1, 0, 1, '何事も\\nお姉さんと一緒に\\n楽しく頑張りましょ？', 0);
insert into room_unit_comments values (1334, 103402, 2, 2, 1, 0, 1, 'ね、ねえ！\\nキミは年上と年下\\nどっちが好きかな？', 0);
insert into room_unit_comments values (1335, 103402, 2, 3, 1, 0, 1, 'もう…\\n構ってくれないと\\n泣いちゃうぞ～？', 0);
insert into room_unit_comments values (1336, 103402, 2, 4, 1, 0, 1, 'お姉さんが～\\n可愛がって\\nあげようか～？', 0);
insert into room_unit_comments values (1337, 103402, 2, 101, 8, 0, 1, '極力人付き合いは\\nしない主義なんだけど\\nキミは例外かも…', 0);
insert into room_unit_comments values (1338, 103402, 2, 102, 8, 0, 1, 'お姉さんとチュー\\nする？\u3000ふふふ～\\n冗談で～す！', 0);
insert into room_unit_comments values (1339, 103402, 2, 1, 1, 1, 1, 'さーて、今日も\\nいっちょやるぞー！', 0);
insert into room_unit_comments values (1340, 103402, 2, 2, 1, 2, 1, '後でのんびり\\nストレッチでも\\nしようっと♪', 0);
insert into room_unit_comments values (1341, 103402, 2, 3, 1, 3, 1, '一日よく働いた～！\\n自分にごほうび\\nあげたいなー♪', 0);
insert into room_unit_comments values (1342, 103402, 3, 1, 1, 0, 1, '仕事の前に、髪とか\\n整えないと…', 0);
insert into room_unit_comments values (1343, 103402, 3, 2, 1, 0, 1, '自然体でゴロゴロ\\nするのって\\n幸せだなぁ…', 0);
insert into room_unit_comments values (1344, 103402, 3, 3, 1, 0, 1, 'もう大人だし…\\nあんまり可愛いのは\\n似合わないかな…？', 0);
insert into room_unit_comments values (1345, 103402, 3, 4, 1, 0, 1, 'うわあ\\nこれ、私の好きな\\n香りだー！', 0);
insert into room_unit_comments values (1346, 103402, 3, 5, 1, 0, 1, 'あったかーい…\\nだ、だらけ\\nちゃいそう…', 0);
insert into room_unit_comments values (1347, 103402, 3, 6, 1, 0, 1, '地道な努力が\\nリア充への\\n第一歩！', 0);
insert into room_unit_comments values (1348, 103402, 3, 7, 1, 0, 1, 'おーいしっ♪\\nこのために\\n生きてるわねえ', 0);
insert into room_unit_comments values (1349, 103402, 3, 8, 1, 0, 1, '大人の女らしく\\n色んなことを学んで\\nおかなくっちゃ', 0);
insert into room_unit_comments values (1351, 103801, 1, 1, 1, 0, 1, '大切な人に\\n本をすすめるのって\\nけっこう難しいなぁ', 0);
insert into room_unit_comments values (1352, 103801, 1, 2, 1, 0, 1, 'き、きらーん☆\\nお姉ちゃんに\\n似てるかな…？', 0);
insert into room_unit_comments values (1353, 103801, 1, 3, 1, 0, 1, 'そろそろ好きな\\n作家さんの新刊が\\n出るから楽しみ…', 0);
insert into room_unit_comments values (1354, 103801, 1, 4, 1, 0, 1, 'ちょっと、休憩…\\n本でも読もうかな', 0);
insert into room_unit_comments values (1355, 103801, 1, 5, 1, 0, 1, 'もっとたくさんの本に\\n囲まれて生活したいな', 0);
insert into room_unit_comments values (1356, 103801, 1, 101, 4, 0, 1, 'むかしむかしある所に\\nシオリと\\nあの人が…', 0);
insert into room_unit_comments values (1357, 103801, 1, 102, 8, 0, 1, 'この本の主人公、\\nあの人に\\n似ているかも…\\nかっこいいな', 0);
insert into room_unit_comments values (1358, 103801, 2, 1, 1, 0, 1, 'ケホケホ…\\nコンコン…\\nゴホッゴホッ…\\nへ、平気ですよ？', 0);
insert into room_unit_comments values (1359, 103801, 2, 2, 1, 0, 1, 'あ…お姉ちゃんと\\n約束があったんだ…', 0);
insert into room_unit_comments values (1360, 103801, 2, 3, 1, 0, 1, 'しおりを探している？\\nあ、本に挟む方ですね\\nドキドキしました…', 0);
insert into room_unit_comments values (1361, 103801, 2, 4, 1, 0, 1, '最近調子がいいのは\\n牧場の牛乳やチーズの\\nおかげでしょうか？', 0);
insert into room_unit_comments values (1362, 103801, 2, 101, 4, 0, 1, '読みたい本も\\nあなたと行きたい所も\\n増えるばっかりです', 0);
insert into room_unit_comments values (1363, 103801, 2, 102, 8, 0, 1, '私の病気、\\n悪化してるのかも！？\\nすごく胸がドキドキ\\nするんです…', 0);
insert into room_unit_comments values (1364, 103801, 2, 1, 1, 1, 1, 'えっと、朝食の前には\\nこの薬を飲んで…\\n食後にはこの薬を…', 0);
insert into room_unit_comments values (1365, 103801, 2, 2, 1, 2, 1, 'ふぅ…午前中\\n動いたので体力が…\\nすこし休みますね', 0);
insert into room_unit_comments values (1366, 103801, 2, 3, 1, 3, 1, '早く寝ないと\\n体に良くないですよね\\nでも気になっている\\n本があって…', 0);
insert into room_unit_comments values (1367, 103801, 3, 1, 1, 0, 1, '寝てばかりなので、\\n髪が乱れてないかな\\n…？', 0);
insert into room_unit_comments values (1368, 103801, 3, 2, 1, 0, 1, '少し休もう\\n…やっぱり\\nたくさん休もう', 0);
insert into room_unit_comments values (1369, 103801, 3, 3, 1, 0, 1, 'かわいいものが\\n枕元にあると\\n安心できるんですよ', 0);
insert into room_unit_comments values (1370, 103801, 3, 4, 1, 0, 1, 'いい香り…\\n病は気からと言うので\\n雰囲気も大事ですね', 0);
insert into room_unit_comments values (1371, 103801, 3, 5, 1, 0, 1, 'こうして温まって\\nいると、病気も\\n治る気がします', 0);
insert into room_unit_comments values (1372, 103801, 3, 6, 1, 0, 1, '運動…イメージ\\nトレーニングだけじゃ\\nだめでしょうか…', 0);
insert into room_unit_comments values (1373, 103801, 3, 7, 1, 0, 1, '少食ですけど\\nこれならたくさん\\n食べられそうです', 0);
insert into room_unit_comments values (1374, 103801, 3, 8, 1, 0, 1, '続きが気になって\\n読むのを止める\\nタイミングが…', 0);
insert into room_unit_comments values (1376, 103802, 1, 1, 1, 0, 1, 'しっかり休まないと\\n早く回復するように', 0);
insert into room_unit_comments values (1377, 103802, 1, 2, 1, 0, 1, 'き、きらーん☆\\nお姉ちゃんに\\n似てるかな…？\u3000', 0);
insert into room_unit_comments values (1378, 103802, 1, 3, 1, 0, 1, '病室よりも…\\nずっとこの部屋に\\nいたいですね…\u3000', 0);
insert into room_unit_comments values (1379, 103802, 1, 4, 1, 0, 1, 'そろそろ好きな\\n作家さんの新刊が\\n出るから楽しみ…', 0);
insert into room_unit_comments values (1380, 103802, 1, 5, 1, 0, 1, '大切な人に\\n本をすすめるのって\\nけっこう難しいなぁ', 0);
insert into room_unit_comments values (1381, 103802, 1, 101, 8, 0, 1, 'むかしむかしある所に\\nシオリと\\nあの人が…', 0);
insert into room_unit_comments values (1382, 103802, 1, 102, 8, 0, 1, 'あの人の\\nためにも早く\\n病気を治さないと…', 0);
insert into room_unit_comments values (1383, 103802, 2, 1, 1, 0, 1, 'ケホケホ…\\nコンコン…\\nゴホッゴホッ…\\nへ、平気ですよ？', 0);
insert into room_unit_comments values (1384, 103802, 2, 2, 1, 0, 1, '新記録です！\\n一週間連続、\\n平熱を保ちました！', 0);
insert into room_unit_comments values (1385, 103802, 2, 3, 1, 0, 1, 'あ…お薬の時間…\\n苦いけど我慢しなきゃ\u3000', 0);
insert into room_unit_comments values (1386, 103802, 2, 4, 1, 0, 1, '最近調子がいいのは\\n牧場の牛乳やチーズの\\nおかげでしょうか？', 0);
insert into room_unit_comments values (1387, 103802, 2, 101, 8, 0, 1, 'しおりを探している？\\nあ、本に挟む方ですね\\nドキドキしました…', 0);
insert into room_unit_comments values (1388, 103802, 2, 102, 8, 0, 1, '私の病気\\n悪化してるのかも！？\\nすごく胸がドキドキ\\nするんです…', 0);
insert into room_unit_comments values (1389, 103802, 2, 1, 1, 1, 1, 'えっと、朝食の前には\\nこの薬を飲んで…\\n食後にはこの薬を…', 0);
insert into room_unit_comments values (1390, 103802, 2, 2, 1, 2, 1, '…お昼の薬？\\nあ、飲み忘れてました\\nありがとうございます', 0);
insert into room_unit_comments values (1391, 103802, 2, 3, 1, 3, 1, 'この薬を飲むと\\n眠くなっちゃうんです\\nでもまだ、あなたと\\nお話したいし～', 0);
insert into room_unit_comments values (1392, 103802, 3, 1, 1, 0, 1, '寝てばかりなので、\\n髪が乱れてないかな\\n…？\u3000', 0);
insert into room_unit_comments values (1393, 103802, 3, 2, 1, 0, 1, '少し休もう\\n…やっぱり\\nたくさん休もう', 0);
insert into room_unit_comments values (1394, 103802, 3, 3, 1, 0, 1, 'この子がいれば\\n病室に一人でも\\n寂しくないですね', 0);
insert into room_unit_comments values (1395, 103802, 3, 4, 1, 0, 1, 'いろんな効能が？\\n健康になる香りも\\nあるのでしょうか？', 0);
insert into room_unit_comments values (1396, 103802, 3, 5, 1, 0, 1, 'こうして温まって\\nいると、病気も\\n治る気がします', 0);
insert into room_unit_comments values (1397, 103802, 3, 6, 1, 0, 1, '私も、少しは\\n体力をつけないと\\nいけませんよね\u3000', 0);
insert into room_unit_comments values (1398, 103802, 3, 7, 1, 0, 1, 'いっぱい食べて\\n健康な体にならないと', 0);
insert into room_unit_comments values (1399, 103802, 3, 8, 1, 0, 1, '続きが気になって\\n読むのを止める\\nタイミングが…', 0);
insert into room_unit_comments values (1401, 104001, 1, 1, 1, 0, 1, '友達ができたら、\\n山の上でお弁当…\\n夢が広がります…', 0);
insert into room_unit_comments values (1402, 104001, 1, 2, 1, 0, 1, 'あ、忘れずに\\nお花に水を\\nあげなきゃ…', 0);
insert into room_unit_comments values (1403, 104001, 1, 3, 1, 0, 1, 'お菓子を作って、\\nみなさんに振る舞って\\n友達作戦！\u3000とか…', 0);
insert into room_unit_comments values (1404, 104001, 1, 4, 1, 0, 1, 'そろそろ新しい\\n草人形を作って\\n友達作りの特訓を…', 0);
insert into room_unit_comments values (1405, 104001, 1, 5, 1, 0, 1, '植物のお世話って、\\nぼっちにとっては、\\n救い…なんです…', 0);
insert into room_unit_comments values (1406, 104001, 1, 101, 4, 0, 1, 'ＢＢ団の活動日…\\nまだかな…\\nうふふふっ', 0);
insert into room_unit_comments values (1407, 104001, 1, 102, 8, 0, 1, 'もっともっとあの人の\\nそばで、一緒に友達を\\n作っていきたいな…', 0);
insert into room_unit_comments values (1408, 104001, 2, 1, 1, 0, 1, 'あ、こんにちは！\\n今日もＢＢ団で\\nお世話になります！', 0);
insert into room_unit_comments values (1409, 104001, 2, 2, 1, 0, 1, 'あの…私の友達作りの\\n練習方法、間違って\\nませんよね…？', 0);
insert into room_unit_comments values (1410, 104001, 2, 3, 1, 0, 1, 'そうだ、今度、\\n森に一緒に木の苗を\\n植えに行きませんか？', 0);
insert into room_unit_comments values (1411, 104001, 2, 4, 1, 0, 1, '人とお話するのって、\\n私、大好きです！\\n友達ふやすぞ～！', 0);
insert into room_unit_comments values (1412, 104001, 2, 101, 4, 0, 1, 'あなたと話してると、\\nまるで私がぼっちじゃ\\nないみたいです！', 0);
insert into room_unit_comments values (1413, 104001, 2, 102, 8, 0, 1, '友達もほしいけど…\\nあなたに会えたことが\\n私の一番の幸せです', 0);
insert into room_unit_comments values (1414, 104001, 2, 1, 1, 1, 1, 'おはようございます！\\n今日もＢＢ団、\\nがんばるぞー！', 0);
insert into room_unit_comments values (1415, 104001, 2, 2, 1, 2, 1, 'なんだか、お腹が\\n空いてきました。\\nお昼ごはんー♪', 0);
insert into room_unit_comments values (1416, 104001, 2, 3, 1, 3, 1, 'もう眠いかもです…\\n明日は友達、\\nできるといいなあ…', 0);
insert into room_unit_comments values (1417, 104001, 3, 1, 1, 0, 1, '私がもっと\\n可愛ければ、\\n友達できるかなあ？', 0);
insert into room_unit_comments values (1418, 104001, 3, 2, 1, 0, 1, 'ふわあ…のんびり\\nしすぎないように\\n気を付けなきゃです', 0);
insert into room_unit_comments values (1419, 104001, 3, 3, 1, 0, 1, 'かわいいなあ。\\nこの子とも\\n友達になりたい…', 0);
insert into room_unit_comments values (1420, 104001, 3, 4, 1, 0, 1, 'いい香りです…\\n精神統一して\\n友達のイメトレ…', 0);
insert into room_unit_comments values (1421, 104001, 3, 5, 1, 0, 1, '灯りを見てると、\\n心がなごみます～', 0);
insert into room_unit_comments values (1422, 104001, 3, 6, 1, 0, 1, 'もぐもぐ…\\nおいしいです…！\\nみなさんもぜひ！', 0);
insert into room_unit_comments values (1423, 104001, 3, 7, 1, 0, 1, 'おいしいです…\\n私に友達がいたら、\\n分けてあげたいな', 0);
insert into room_unit_comments values (1424, 104001, 3, 8, 1, 0, 1, '友達作りの\\n参考になりそうなこと\\n書いてないかな～？', 0);
insert into room_unit_comments values (1426, 104002, 1, 1, 1, 0, 1, '友達作りは、焦らず\\n慌てず、じっくりと…', 0);
insert into room_unit_comments values (1427, 104002, 1, 2, 1, 0, 1, 'ひとつ屋根の下\\nって感じ…\\nいいですねえ…', 0);
insert into room_unit_comments values (1428, 104002, 1, 3, 1, 0, 1, '煮汁、煮汁が\\n噴きこぼれて\\nいませんか～', 0);
insert into room_unit_comments values (1429, 104002, 1, 4, 1, 0, 1, '今度、みなさんと\\nピクニックとか…\\nいってみたいな', 0);
insert into room_unit_comments values (1430, 104002, 1, 5, 1, 0, 1, 'ぼっちでもいい\\nたくましく育てば\\n…なんて', 0);
insert into room_unit_comments values (1431, 104002, 1, 101, 8, 0, 1, '最近、毎日あの人の\\nこと考えちゃいます\\nどうしてだろう…', 0);
insert into room_unit_comments values (1432, 104002, 1, 102, 8, 0, 1, 'もっともっとあの人の\\nそばで、一緒に友達を\\n作っていきたいな…', 0);
insert into room_unit_comments values (1433, 104002, 2, 1, 1, 0, 1, 'あ！\u3000ＢＢ団の活動\\nですか？\u3000嬉しくて\\n飛び跳ねちゃいます！', 0);
insert into room_unit_comments values (1434, 104002, 2, 2, 1, 0, 1, 'あなたとのお話で友達\\n作りの練習になるなら\\n一石二鳥です！', 0);
insert into room_unit_comments values (1435, 104002, 2, 3, 1, 0, 1, '私少しは人と話しても\\nテンパらなくなって\\nきましたかね…？', 0);
insert into room_unit_comments values (1436, 104002, 2, 4, 1, 0, 1, 'あの、友達作りの\\n新しい作戦\\n考えてみたんですっ！', 0);
insert into room_unit_comments values (1437, 104002, 2, 101, 8, 0, 1, 'あなたとお話する時の\\nこの気持ち、私の宝物\\nなんです…えへへ', 0);
insert into room_unit_comments values (1438, 104002, 2, 102, 8, 0, 1, '友達もほしいけど…\\nあなたに会えたことが\\n私の一番の幸せです', 0);
insert into room_unit_comments values (1439, 104002, 2, 1, 1, 1, 1, '朝ですね！\\nこんないい朝は\\n友達作りのチャンス！', 0);
insert into room_unit_comments values (1440, 104002, 2, 2, 1, 2, 1, 'あの…そろそろお腹\\nすきませんか？\\nお昼ごはんは…', 0);
insert into room_unit_comments values (1441, 104002, 2, 3, 1, 3, 1, 'もう眠いかもです…\\n明日は友達\\nできるといいなあ…', 0);
insert into room_unit_comments values (1442, 104002, 3, 1, 1, 0, 1, '私…見た目\\nそこまで変じゃ\\nないですよね…？', 0);
insert into room_unit_comments values (1443, 104002, 3, 2, 1, 0, 1, 'ほわあ～…\\nふかふかって\\nいいものですね～', 0);
insert into room_unit_comments values (1444, 104002, 3, 3, 1, 0, 1, 'この子みたいな\\nあいくるしさを\\n目指したいです！', 0);
insert into room_unit_comments values (1445, 104002, 3, 4, 1, 0, 1, '灯りを見てると\\n心がなごみます～', 0);
insert into room_unit_comments values (1446, 104002, 3, 5, 1, 0, 1, 'ぬくぬくで、なんだか\\n眠くなっちゃいますね', 0);
insert into room_unit_comments values (1447, 104002, 3, 6, 1, 0, 1, '身体を鍛えて\\nみなさんを\\n守ります！', 0);
insert into room_unit_comments values (1448, 104002, 3, 7, 1, 0, 1, 'もぐもぐ…\\nおいしいです…！\\nみなさんもぜひ！', 0);
insert into room_unit_comments values (1449, 104002, 3, 8, 1, 0, 1, '友達作りの\\n参考になりそうなこと\\n書いてないかな～？', 0);
insert into room_unit_comments values (1451, 104201, 1, 1, 1, 0, 1, '唱喚の歌は、みだりに\\n歌っていいものでは\\nないんです', 0);
insert into room_unit_comments values (1452, 104201, 1, 2, 1, 0, 1, 'ここでアイドルの\\n練習は、さすがに\\n迷惑ですよね？', 0);
insert into room_unit_comments values (1453, 104201, 1, 3, 1, 0, 1, '練習してもあんまり\\n疲れなくなった…\\nアイドルのおかげかな', 0);
insert into room_unit_comments values (1454, 104201, 1, 4, 1, 0, 1, '人々の平和を守る旅に\\n同行してくれる人を\\n探していて…', 0);
insert into room_unit_comments values (1455, 104201, 1, 5, 1, 0, 1, 'あとで曲を復習して\\nおかないと…', 0);
insert into room_unit_comments values (1456, 104201, 1, 101, 4, 0, 1, '踊りを見られるのは\\nまだ恥ずかしいけど\\nあの人になら…', 0);
insert into room_unit_comments values (1457, 104201, 1, 102, 8, 0, 1, '浜辺で曲を書こうと\\n思うんですけど…\\n一緒に行きませんか？', 0);
insert into room_unit_comments values (1458, 104201, 2, 1, 1, 0, 1, 'いつも応援ありがとう\\nございます♪\u3000これは\\nあ、握手の練習です！', 0);
insert into room_unit_comments values (1459, 104201, 2, 2, 1, 0, 1, 'え、もう練習の時間？\\nごめんなさい\\nすぐ準備します！', 0);
insert into room_unit_comments values (1460, 104201, 2, 3, 1, 0, 1, '守るべき人たちに\\n笑顔でいてもらうのも\\n大切なんですね', 0);
insert into room_unit_comments values (1461, 104201, 2, 4, 1, 0, 1, '歌える曲を増やそうと\\n思って。どんな曲が\\n聞きたいですか？', 0);
insert into room_unit_comments values (1462, 104201, 2, 101, 4, 0, 1, '～～♪\u3000あれ？\\n今私、歌ってました？\\n気づきませんでした', 0);
insert into room_unit_comments values (1463, 104201, 2, 102, 8, 0, 1, '…歌って欲しい？\\n喜んで♪\\nどの歌にしましょう？', 0);
insert into room_unit_comments values (1464, 104201, 2, 1, 1, 1, 1, 'おはようございます♪\\n少し歌の練習を\\nしてきますね', 0);
insert into room_unit_comments values (1465, 104201, 2, 2, 1, 2, 1, 'もうお昼なんですか？\\n練習に夢中で\\n気づきませんでした', 0);
insert into room_unit_comments values (1466, 104201, 2, 3, 1, 3, 1, '明日の予定は…\\nアイドルはやることが\\n多いみたいで…', 0);
insert into room_unit_comments values (1467, 104201, 3, 1, 1, 0, 1, '見た目については\\n前よりも気をつけてと\\nノゾミに言われてます', 0);
insert into room_unit_comments values (1468, 104201, 3, 2, 1, 0, 1, '歌の調子をよくする\\nためには休息も\\n必要ですよね…', 0);
insert into room_unit_comments values (1469, 104201, 3, 3, 1, 0, 1, 'この子たちを\\n相手に練習して\\nみようかな…♪', 0);
insert into room_unit_comments values (1470, 104201, 3, 4, 1, 0, 1, '…疲れてるのかな\\n落ち着けているのが\\n自分でもわかります', 0);
insert into room_unit_comments values (1471, 104201, 3, 5, 1, 0, 1, 'ここにいると\\n穏やかな旋律が\\n浮かんできます…', 0);
insert into room_unit_comments values (1472, 104201, 3, 6, 1, 0, 1, '歌うためには\\n体力づくりは\\n欠かせません', 0);
insert into room_unit_comments values (1473, 104201, 3, 7, 1, 0, 1, '歌った後は\\nお腹が空いて\\nしまうんです', 0);
insert into room_unit_comments values (1474, 104201, 3, 8, 1, 0, 1, '音楽について\\n理論も勉強\\nしないと…', 0);
insert into room_unit_comments values (1476, 104202, 1, 1, 1, 0, 1, '歌うことの楽しさ\\n分かってきました\\nもっと歌いたいな…', 0);
insert into room_unit_comments values (1477, 104202, 1, 2, 1, 0, 1, '練習してもあんまり\\n疲れなくなった…\\nアイドルのおかげかな', 0);
insert into room_unit_comments values (1478, 104202, 1, 3, 1, 0, 1, '精霊も強くなったし\\nもっとたくさんの人を\\n守りたいです', 0);
insert into room_unit_comments values (1479, 104202, 1, 4, 1, 0, 1, '最近、よく頭の中に\\n歌が浮かんできます\\n不思議な感覚…', 0);
insert into room_unit_comments values (1480, 104202, 1, 5, 1, 0, 1, '楽譜を買いました\\n思いついた歌を\\n書き留めておくために', 0);
insert into room_unit_comments values (1481, 104202, 1, 101, 8, 0, 1, '浜辺で曲を書こうと\\n思うんですけど…\\n一緒に行きませんか？', 0);
insert into room_unit_comments values (1482, 104202, 1, 102, 8, 0, 1, '私の中にある\\n私だけの歌…\\n作ってみようかな？', 0);
insert into room_unit_comments values (1483, 104202, 2, 1, 1, 0, 1, '守るべき人たちに\\n笑顔でいてもらうのも\\n大切なんですね', 0);
insert into room_unit_comments values (1484, 104202, 2, 2, 1, 0, 1, '歌える曲を増やそうと\\n思って。どんな曲が\\n聞きたいですか？', 0);
insert into room_unit_comments values (1485, 104202, 2, 3, 1, 0, 1, '魔物退治ですか！？\\n…違います？\\n良かった…', 0);
insert into room_unit_comments values (1486, 104202, 2, 4, 1, 0, 1, 'いつも応援ありがとう\\nございます♪\u3000これは\\nあ、握手の練習です！', 0);
insert into room_unit_comments values (1487, 104202, 2, 101, 8, 0, 1, '…歌って欲しい？\\n喜んで♪\\nどの歌にしましょう？', 0);
insert into room_unit_comments values (1488, 104202, 2, 102, 8, 0, 1, '～～♪\u3000あれ？\\n今私、歌ってました？\\n気づきませんでした', 0);
insert into room_unit_comments values (1489, 104202, 2, 1, 1, 1, 1, '呼吸を深く、大きく…\\nこれでちゃんと\\n目が覚めますよ', 0);
insert into room_unit_comments values (1490, 104202, 2, 2, 1, 2, 1, '少し休んだら\\n午後の練習に\\n行ってきますね', 0);
insert into room_unit_comments values (1491, 104202, 2, 3, 1, 3, 1, '曲を作っていたら\\nもうこんな時間…\\nおやすみなさい', 0);
insert into room_unit_comments values (1492, 104202, 3, 1, 1, 0, 1, '見た目については\\n前よりも気をつけてと\\nノゾミに言われてます', 0);
insert into room_unit_comments values (1493, 104202, 3, 2, 1, 0, 1, 'あ～…♪\\nよく体がほぐれます…\\nいい歌が歌えそうです', 0);
insert into room_unit_comments values (1494, 104202, 3, 3, 1, 0, 1, 'かわいいと思う\\n気持ちを、歌にしても\\nいいかも知れませんね', 0);
insert into room_unit_comments values (1495, 104202, 3, 4, 1, 0, 1, '…疲れてるのかな\\n落ち着けているのが\\n自分でもわかります', 0);
insert into room_unit_comments values (1496, 104202, 3, 5, 1, 0, 1, 'ここにいると\\n穏やかな旋律が\\n浮かんできます…', 0);
insert into room_unit_comments values (1497, 104202, 3, 6, 1, 0, 1, 'もっと体力をつけて\\n最高のライブを\\nファンに届けます！', 0);
insert into room_unit_comments values (1498, 104202, 3, 7, 1, 0, 1, 'これでも一応\\n体形には気をつけて\\n食べてるんですよ？', 0);
insert into room_unit_comments values (1499, 104202, 3, 8, 1, 0, 1, '読書は歌に\\n新しい風を\\n吹き込んでくれます', 0);
insert into room_unit_comments values (1501, 104301, 1, 1, 1, 0, 1, '店の新メニューでも\\n考えるかな', 0);
insert into room_unit_comments values (1502, 104301, 1, 2, 1, 0, 1, 'あたしの店から、\\n出前を届けようか？', 0);
insert into room_unit_comments values (1503, 104301, 1, 3, 1, 0, 1, 'パトロール、\\nパトロール…\\nここは異常なしかな？', 0);
insert into room_unit_comments values (1504, 104301, 1, 4, 1, 0, 1, '腹へったら食う！\\n悩んだら寝る！\\nそれが一番だろ？', 0);
insert into room_unit_comments values (1505, 104301, 1, 5, 1, 0, 1, 'のんびりし過ぎるのも\\n…性に合わねぇな', 0);
insert into room_unit_comments values (1506, 104301, 1, 101, 4, 0, 1, 'そろそろあいつ、\\n腹すかしてるん\\nじゃないかな？', 0);
insert into room_unit_comments values (1507, 104301, 1, 102, 8, 0, 1, '今日の献立は…\\nあいつの好きなものに\\nしてやるか', 0);
insert into room_unit_comments values (1508, 104301, 2, 1, 1, 0, 1, '強くなりたいなら、\\nあたしがビシバシ\\n鍛えてやるよ', 0);
insert into room_unit_comments values (1509, 104301, 2, 2, 1, 0, 1, '天気がいい日は\\n外で運動したく\\nならねぇか？', 0);
insert into room_unit_comments values (1510, 104301, 2, 3, 1, 0, 1, '腹減ったか？\u3000なんか\\n作ってやろうか？', 0);
insert into room_unit_comments values (1511, 104301, 2, 4, 1, 0, 1, 'ん？\u3000なんだよ、\\n相談事か？\\nなんでも言ってくれ', 0);
insert into room_unit_comments values (1512, 104301, 2, 101, 4, 0, 1, 'お前が好きな飯って\\nなんだ？\\n今度、作ってやるよ', 0);
insert into room_unit_comments values (1513, 104301, 2, 102, 8, 0, 1, 'お前って不思議だよな\\n一緒にいるとなんだか\\n…なんでもねーよ', 0);
insert into room_unit_comments values (1514, 104301, 2, 1, 1, 1, 1, '気持ちいい朝だな！\\n体を動かしたい気分だ\\n付き合ってくれるか', 0);
insert into room_unit_comments values (1515, 104301, 2, 2, 1, 2, 1, '昼飯もう食ったか？\\nまだなら、あたしが\\nなんか作ってやるよ', 0);
insert into room_unit_comments values (1516, 104301, 2, 3, 1, 3, 1, '日中たっぷり動いたら\\nそのぶん夜はしっかり\\n休んどけよな', 0);
insert into room_unit_comments values (1517, 104301, 3, 1, 1, 0, 1, 'た、たまにはその…\\nかわいい格好とか\\nしても…', 0);
insert into room_unit_comments values (1518, 104301, 3, 2, 1, 0, 1, 'ふわぁ、\\n一休みすっかなぁ～', 0);
insert into room_unit_comments values (1519, 104301, 3, 3, 1, 0, 1, 'うっ！\u3000か、かわいい\\nじゃねぇか', 0);
insert into room_unit_comments values (1520, 104301, 3, 4, 1, 0, 1, 'へー\u3000いい匂いだな\\nあいつもこういうの\\n好きなのかな…', 0);
insert into room_unit_comments values (1521, 104301, 3, 5, 1, 0, 1, 'ふわぁ〜！\\n温かいと、つい\\nウトウトしちまうな', 0);
insert into room_unit_comments values (1522, 104301, 3, 6, 1, 0, 1, 'オラオラオラーーー！\\n燃えるぜーーー！', 0);
insert into room_unit_comments values (1523, 104301, 3, 7, 1, 0, 1, 'いい味してるぜ！\\nうちの店でも\\n出してみたいな', 0);
insert into room_unit_comments values (1524, 104301, 3, 8, 1, 0, 1, '文字を読んでると\\nどうしても眠く\\nなっちまうんだよなぁ', 0);
insert into room_unit_comments values (1526, 104302, 1, 1, 1, 0, 1, 'パトロール終了～\\n本日も異常なしっと！', 0);
insert into room_unit_comments values (1527, 104302, 1, 2, 1, 0, 1, 'あたしの店から\\n出前を届けようか？', 0);
insert into room_unit_comments values (1528, 104302, 1, 3, 1, 0, 1, 'あいつ、早く\\n帰ってこないかな', 0);
insert into room_unit_comments values (1529, 104302, 1, 4, 1, 0, 1, 'あいつ\\n腹すかせてないと\\nいいんだけど…', 0);
insert into room_unit_comments values (1530, 104302, 1, 5, 1, 0, 1, 'のんびりし過ぎるのも\\n…性に合わねぇな', 0);
insert into room_unit_comments values (1531, 104302, 1, 101, 8, 0, 1, 'あいつの事を思うと\\n胸があったかくなる？\\nなんだコレ…？', 0);
insert into room_unit_comments values (1532, 104302, 1, 102, 8, 0, 1, '今日の献立は…\\nあいつの好きなものに\\nしてやるか', 0);
insert into room_unit_comments values (1533, 104302, 2, 1, 1, 0, 1, 'ん？\u3000なんだよ\\n相談事か？\\nなんでも言ってくれ', 0);
insert into room_unit_comments values (1534, 104302, 2, 2, 1, 0, 1, '天気がいい日は\\n外で運動したく\\nならねぇか？', 0);
insert into room_unit_comments values (1535, 104302, 2, 3, 1, 0, 1, '腹減ったか？\u3000なんか\\n作ってやろうか？', 0);
insert into room_unit_comments values (1536, 104302, 2, 4, 1, 0, 1, '腹へったら食う！\\n悩んだら寝る！\\nそれが一番だろ？', 0);
insert into room_unit_comments values (1537, 104302, 2, 101, 8, 0, 1, 'あのさ…できれば\\nもっとそばに…いや\\nなんでもねぇ忘れろ！', 0);
insert into room_unit_comments values (1538, 104302, 2, 102, 8, 0, 1, 'お前って不思議だよな\\n一緒にいるとなんだか\\n…なんでもねーよ', 0);
insert into room_unit_comments values (1539, 104302, 2, 1, 1, 1, 1, '気持ちいい朝だな！\\n体を動かしたい気分だ\\n付き合ってくれるか？', 0);
insert into room_unit_comments values (1540, 104302, 2, 2, 1, 2, 1, '昼飯もう食ったか？\\nまだなら、あたしが\\nなんか作ってやるよ', 0);
insert into room_unit_comments values (1541, 104302, 2, 3, 1, 3, 1, 'あんま夜更しすんなよ\\n明日に響いたら\\n大変だろ？', 0);
insert into room_unit_comments values (1542, 104302, 3, 1, 1, 0, 1, 'た、たまにはその…\\nかわいい格好とか\\nしても…', 0);
insert into room_unit_comments values (1543, 104302, 3, 2, 1, 0, 1, 'ふぅ～♪\\n疲れがとれるな～', 0);
insert into room_unit_comments values (1544, 104302, 3, 3, 1, 0, 1, 'うっ！\u3000か、かわいい\\nじゃねぇか', 0);
insert into room_unit_comments values (1545, 104302, 3, 4, 1, 0, 1, 'へー\u3000いい匂いだな\\nあいつもこういうの\\n好きなのかな…', 0);
insert into room_unit_comments values (1546, 104302, 3, 5, 1, 0, 1, 'ふわぁ～！\\n温かいと、つい\\nウトウトしちまうな', 0);
insert into room_unit_comments values (1547, 104302, 3, 6, 1, 0, 1, 'オラオラオラーーー！\\n燃えるぜーーー！', 0);
insert into room_unit_comments values (1548, 104302, 3, 7, 1, 0, 1, 'いい味してるぜ！\\nうちの店でも\\n出してみたいな', 0);
insert into room_unit_comments values (1549, 104302, 3, 8, 1, 0, 1, '料理だけじゃなく\\n経営術とかも\\n学んどかねぇと…', 0);
insert into room_unit_comments values (1551, 104501, 1, 1, 1, 0, 1, '最近なにも\\nしてくれません…\\n焦らしてるんですね', 0);
insert into room_unit_comments values (1552, 104501, 1, 2, 1, 0, 1, 'ぐふふ、じゅるり…\\nい、いけない、また\\nいつの間にかよだれが', 0);
insert into room_unit_comments values (1553, 104501, 1, 3, 1, 0, 1, '好きな武器といえば\\n剣より槍より\\nやっぱり鞭…ぐふふ', 0);
insert into room_unit_comments values (1554, 104501, 1, 4, 1, 0, 1, '「無数の触手が\\nクウカの柔肌に\\n食い込み」…ぐふふ', 0);
insert into room_unit_comments values (1555, 104501, 1, 5, 1, 0, 1, 'もしドＳさんが\\nＭに転じたらと思うと\\n身の毛がよだちます！', 0);
insert into room_unit_comments values (1556, 104501, 1, 101, 4, 0, 1, 'ドＳさんを登場\\nさせるだけで、妄想に\\n無限の広がりが！', 0);
insert into room_unit_comments values (1557, 104501, 1, 102, 8, 0, 1, 'あっ…\\nジロジロ見てたの\\n気づいちゃいました？', 0);
insert into room_unit_comments values (1558, 104501, 2, 1, 1, 0, 1, '視線を感じると\\n思ったら…やはり\\nドＳさんでしたか', 0);
insert into room_unit_comments values (1559, 104501, 2, 2, 1, 0, 1, '今日は\\nどんなヒドイことを\\nしてくれるんですか？\\nぐふふふ', 0);
insert into room_unit_comments values (1560, 104501, 2, 3, 1, 0, 1, 'いつの間にそこに！？\\nまさかクウカを監視\\nしていたのですか！？', 0);
insert into room_unit_comments values (1561, 104501, 2, 4, 1, 0, 1, 'クウカに触るつもり\\nですか？\u3000触るつもり\\nなのですねっ！？', 0);
insert into room_unit_comments values (1562, 104501, 2, 101, 4, 0, 1, 'クウカにナニをする\\nつもりですか…\\n期待してしまいます！', 0);
insert into room_unit_comments values (1563, 104501, 2, 102, 8, 0, 1, 'ドＳさんの視界に入る\\nだけでドキドキが…\\nこれが恋！？', 0);
insert into room_unit_comments values (1564, 104501, 2, 1, 1, 1, 1, 'おはようございます。\\n朝からお盛んですね？\\nぐふふ…', 0);
insert into room_unit_comments values (1565, 104501, 2, 2, 1, 2, 1, 'こんなにも日の高い\\nうちからドＳさんは…\\nじゅるり', 0);
insert into room_unit_comments values (1566, 104501, 2, 3, 1, 3, 1, '夜はこれから、\\nですよ…\\nぐふ、ぐふふふ…', 0);
insert into room_unit_comments values (1567, 104501, 3, 1, 1, 0, 1, 'キレイにおめかし\\nしたのに力ずくで…\\nぐふふふ', 0);
insert into room_unit_comments values (1568, 104501, 3, 2, 1, 0, 1, 'ソファの背にクウカを\\n押し付けて…ぐふふ\\nいいですね\\nソファドン', 0);
insert into room_unit_comments values (1569, 104501, 3, 3, 1, 0, 1, '「見た目とは裏腹に\\nそれは激しく攻め\\nたてて」…ぐふふふ', 0);
insert into room_unit_comments values (1570, 104501, 3, 4, 1, 0, 1, '香りを吸ったクウカの\\n頬は紅潮し目はうるみ\\nもはや抗う力も…！', 0);
insert into room_unit_comments values (1571, 104501, 3, 5, 1, 0, 1, 'ああ、身体が\\n火照って…\\nぐふ、ぐふふ…', 0);
insert into room_unit_comments values (1572, 104501, 3, 6, 1, 0, 1, 'はぁ、はぁ、こうして\\nクウカの体力を\\n奪ってから…ぐふふ', 0);
insert into room_unit_comments values (1573, 104501, 3, 7, 1, 0, 1, '食欲が満たされたら\\nつ、次はやはり…！\\nそうなのですね！？', 0);
insert into room_unit_comments values (1574, 104501, 3, 8, 1, 0, 1, 'この本の下に、\\nそういう本を\\nカムフラージュ？', 0);
insert into room_unit_comments values (1576, 104502, 1, 1, 1, 0, 1, '「ドＳさんと踊り子\\n乱舞の一夜」…\\n次の日記はこれで…', 0);
insert into room_unit_comments values (1577, 104502, 1, 2, 1, 0, 1, '最近なにも\\nしてくれません…\\n焦らしてるんですね', 0);
insert into room_unit_comments values (1578, 104502, 1, 3, 1, 0, 1, 'も、妄想が\\n足りません…\\n禁断症状がっ…！', 0);
insert into room_unit_comments values (1579, 104502, 1, 4, 1, 0, 1, 'もしドＳさんが\\nＭに転じたらと思うと\\n身の毛がよだちます！', 0);
insert into room_unit_comments values (1580, 104502, 1, 5, 1, 0, 1, '次はどんなドＳを\\nされるのか、想像する\\nだけで…ぐふふふ', 0);
insert into room_unit_comments values (1581, 104502, 1, 101, 8, 0, 1, 'じっとしてると\\nドＳさんのことばかり\\n考えてしまいますね', 0);
insert into room_unit_comments values (1582, 104502, 1, 102, 8, 0, 1, '妄想が止まらなくて\\nクウカどうにかなって\\nしまいそうです！', 0);
insert into room_unit_comments values (1583, 104502, 2, 1, 1, 0, 1, 'ドＳさんといると体が\\n火照って…クウカは\\nいやらしい子です！', 0);
insert into room_unit_comments values (1584, 104502, 2, 2, 1, 0, 1, 'あっ…\\nジロジロ見てたの\\n気づいちゃいました？', 0);
insert into room_unit_comments values (1585, 104502, 2, 3, 1, 0, 1, 'ドＳさんのおかげで\\n新しい扉が開けそう\\nです…じゅるり', 0);
insert into room_unit_comments values (1586, 104502, 2, 4, 1, 0, 1, 'いやー！\u3000ドＳさんに\\n襲われ…襲って\\nくれないんですか？', 0);
insert into room_unit_comments values (1587, 104502, 2, 101, 8, 0, 1, 'クウカはドＳさんに\\n身も心も堕とされて\\nしまったのですね', 0);
insert into room_unit_comments values (1588, 104502, 2, 102, 8, 0, 1, 'ドＳさんがお望みなら\\nクウカは\\nどんなことだって！', 0);
insert into room_unit_comments values (1589, 104502, 2, 1, 1, 1, 1, '朝だからこそ\\nできる妄想が\\nあります…ぐふふ', 0);
insert into room_unit_comments values (1590, 104502, 2, 2, 1, 2, 1, 'こんな日の高いうち\\nからドＳさんは…\\nじゅるり', 0);
insert into room_unit_comments values (1591, 104502, 2, 3, 1, 3, 1, '今夜は一晩中…\\nなんですね？\\nぐふふ…', 0);
insert into room_unit_comments values (1592, 104502, 3, 1, 1, 0, 1, '意外と難しいんですよ\\n正しい亀甲縛りと\\nいうものは…', 0);
insert into room_unit_comments values (1593, 104502, 3, 2, 1, 0, 1, 'くつろいで油断\\nしているスキに何を\\nされるのでしょう！？', 0);
insert into room_unit_comments values (1594, 104502, 3, 3, 1, 0, 1, '「見た目とは裏腹に\\nそれは激しく攻め\\nたてて」…ぐふふふ', 0);
insert into room_unit_comments values (1595, 104502, 3, 4, 1, 0, 1, 'これは禁断の香り…\\nああっ一段階上の\\n妄想が開花するうぅ！', 0);
insert into room_unit_comments values (1596, 104502, 3, 5, 1, 0, 1, 'ああっ、暖気がまるで\\nロウソクのように\\nクウカを攻めますっ！', 0);
insert into room_unit_comments values (1597, 104502, 3, 6, 1, 0, 1, '激しい攻めを受けきる\\nためには、鍛えないと\\nいけないのですね', 0);
insert into room_unit_comments values (1598, 104502, 3, 7, 1, 0, 1, 'こんなにいっぱい\\n入りません…\\nお腹にっ！', 0);
insert into room_unit_comments values (1599, 104502, 3, 8, 1, 0, 1, 'どんな本も\\nよく見ると\\nいやらしいです…！', 0);
insert into room_unit_comments values (1601, 104601, 1, 1, 1, 0, 1, 'この前遊んだ猫、\\nモッフモフ\\nだったにゃあ…♪', 0);
insert into room_unit_comments values (1602, 104601, 1, 2, 1, 0, 1, 'ほっぺやお腹が、\\n肉球ぐらいぷにぷに…\\nこれはまずいにゃ…', 0);
insert into room_unit_comments values (1603, 104601, 1, 3, 1, 0, 1, '大きな仕事が\\n決まったにゃ！\\n腕が鳴るにゃ～♪', 0);
insert into room_unit_comments values (1604, 104601, 1, 4, 1, 0, 1, 'おやつのたい焼き、\\nつぶあんとこしあん、\\nどっちに\\nしようかにゃ？', 0);
insert into room_unit_comments values (1605, 104601, 1, 5, 1, 0, 1, 'うにゃー…\\nもうちょっとお昼寝\\nしたかったにゃ…\\nむにゃむにゃ…', 0);
insert into room_unit_comments values (1606, 104601, 1, 101, 4, 0, 1, 'キミに呼ばれると、\\n猫まっしぐらな気分に\\nなっちゃうにゃ♪', 0);
insert into room_unit_comments values (1607, 104601, 1, 102, 8, 0, 1, 'キミのおかげで\\nギルドの仕事も\\n大成功だにゃ♪\\nありがとにゃ♪', 0);
insert into room_unit_comments values (1608, 104601, 2, 1, 1, 0, 1, 'うずうず…その指、\\nじゃれついても\\nいいかにゃ？', 0);
insert into room_unit_comments values (1609, 104601, 2, 2, 1, 0, 1, 'にゃ？\u3000あたしに何か\\nご入り用かにゃ？\\nお安くしとくにゃ～♪', 0);
insert into room_unit_comments values (1610, 104601, 2, 3, 1, 0, 1, 'うーん、なんだか\\n退屈にゃ～\\n遊んで、遊んで～？', 0);
insert into room_unit_comments values (1611, 104601, 2, 4, 1, 0, 1, '素早い動きのコツ？\\nタダじゃ教えて\\nあげられないにゃ～♪', 0);
insert into room_unit_comments values (1612, 104601, 2, 101, 4, 0, 1, 'そんなにあたしを\\nなでたいにゃ？\\nキミならなでさせて\\nあげてもいいかにゃー', 0);
insert into room_unit_comments values (1613, 104601, 2, 102, 8, 0, 1, 'ふにゃあ、ねえねえ、\\n一緒にゴロゴロ\\nしようにゃあ？', 0);
insert into room_unit_comments values (1614, 104601, 2, 1, 1, 1, 1, 'いい朝にゃ！\\n顔を洗ってくるにゃ！', 0);
insert into room_unit_comments values (1615, 104601, 2, 2, 1, 2, 1, 'むーん、そろそろ\\nお昼…猫たちにも\\n猫缶を…', 0);
insert into room_unit_comments values (1616, 104601, 2, 3, 1, 3, 1, 'ふわあ…眠いにゃ…\\n猫は布団で\\n丸くなるにゃ', 0);
insert into room_unit_comments values (1617, 104601, 3, 1, 1, 0, 1, '客商売では、\\n外見のチェックも\\n欠かせないのにゃ！', 0);
insert into room_unit_comments values (1618, 104601, 3, 2, 1, 0, 1, 'うにゃ～！\\nお昼寝に\\nぴったりにゃ', 0);
insert into room_unit_comments values (1619, 104601, 3, 3, 1, 0, 1, 'これ…量産したら\\n子どもにバカ売れ\\nしそうだにゃ！', 0);
insert into room_unit_comments values (1620, 104601, 3, 4, 1, 0, 1, 'この灯り、まるで\\n猫みたいな\\n癒し効果にゃ！', 0);
insert into room_unit_comments values (1621, 104601, 3, 5, 1, 0, 1, 'ふにゃあ、\\nあったかいと猫は丸く\\nなっちゃうのにゃあ…', 0);
insert into room_unit_comments values (1622, 104601, 3, 6, 1, 0, 1, '本当は外で\\n運動したいん\\nだけどにゃ', 0);
insert into room_unit_comments values (1623, 104601, 3, 7, 1, 0, 1, 'むーん、\\n美味しいにゃー！\\nたい焼きに\\n匹敵するにゃ！', 0);
insert into room_unit_comments values (1624, 104601, 3, 8, 1, 0, 1, 'ふむふむ…猫の\\nしつけ方は、と…', 0);
insert into room_unit_comments values (1626, 104602, 1, 1, 1, 0, 1, 'かわいいネコの置物を\\nゲットしたにゃ！\\nどこに飾ろうか\\nにゃ～♪', 0);
insert into room_unit_comments values (1627, 104602, 1, 2, 1, 0, 1, '仕事の交渉がうまく\\n行ったにゃ～♪\\nいい気分だにゃ～♪', 0);
insert into room_unit_comments values (1628, 104602, 1, 3, 1, 0, 1, 'ねこじゃらしには\\n食いついちゃうにゃ\\nびしっ！\u3000びしっ！', 0);
insert into room_unit_comments values (1629, 104602, 1, 4, 1, 0, 1, 'ほっぺやお腹が、肉球\\nぐらいぷにぷに…\\nこれはまずいにゃ…', 0);
insert into room_unit_comments values (1630, 104602, 1, 5, 1, 0, 1, 'さっきのたいやき\\nおいしかったにゃ♪\\nごろごろごろ…', 0);
insert into room_unit_comments values (1631, 104602, 1, 101, 8, 0, 1, '手作りのたい焼き\\nあいつは食べて\\nくれるかにゃ…？', 0);
insert into room_unit_comments values (1632, 104602, 1, 102, 8, 0, 1, 'あいつには、いつか\\nたっぷり恩返しが\\nしたいにゃ…', 0);
insert into room_unit_comments values (1633, 104602, 2, 1, 1, 0, 1, 'にゃーに？\u3000あたしの\\nことがそんなに気に\\nなるのかにゃ？', 0);
insert into room_unit_comments values (1634, 104602, 2, 2, 1, 0, 1, 'あたしのこと…\\nしっかり捕まえ\\nといてにゃ？', 0);
insert into room_unit_comments values (1635, 104602, 2, 3, 1, 0, 1, 'あたしの力が\\n必要かにゃ？\u3000猫の手\\n貸してあげるにゃ♪', 0);
insert into room_unit_comments values (1636, 104602, 2, 4, 1, 0, 1, 'たいやきとクレープを\\n合わせれば…\\n新しい商売のニオイが\\nするにゃ…！', 0);
insert into room_unit_comments values (1637, 104602, 2, 101, 8, 0, 1, 'ふにゃあ、ねえねえ\\n一緒にゴロゴロ\\nしようにゃあ？', 0);
insert into room_unit_comments values (1638, 104602, 2, 102, 8, 0, 1, 'キミと一緒にいると\\n楽しくなってつい\\nじゃれちゃうにゃ！', 0);
insert into room_unit_comments values (1639, 104602, 2, 1, 1, 1, 1, 'いい朝にゃ！\\n顔を洗ってくるにゃ！', 0);
insert into room_unit_comments values (1640, 104602, 2, 2, 1, 2, 1, 'そろそろおっひる～\\nにゃーんか\\n食べたい…', 0);
insert into room_unit_comments values (1641, 104602, 2, 3, 1, 3, 1, 'うーん、眠くなって\\nきたにゃ。あたしは\\n夜行性じゃないのにゃ', 0);
insert into room_unit_comments values (1642, 104602, 3, 1, 1, 0, 1, 'にゃにゃ…\\n髪が乱れてるにゃ', 0);
insert into room_unit_comments values (1643, 104602, 3, 2, 1, 0, 1, 'ふっかふかにゃ～\\n猫がねころん\\nじゃうにゃ', 0);
insert into room_unit_comments values (1644, 104602, 3, 3, 1, 0, 1, 'これ、猫と匹敵する\\nぐらいかわいいにゃ！', 0);
insert into room_unit_comments values (1645, 104602, 3, 4, 1, 0, 1, '猫でもこわくない\\n優しい灯りにゃ！', 0);
insert into room_unit_comments values (1646, 104602, 3, 5, 1, 0, 1, 'ぽっかぽか\\nしあわせな気分にゃ～', 0);
insert into room_unit_comments values (1647, 104602, 3, 6, 1, 0, 1, '雨の日でも運動\\nできるのは、濡れ\\nなくて便利だにゃ！', 0);
insert into room_unit_comments values (1648, 104602, 3, 7, 1, 0, 1, '美味しいにゃ～！\\nこれ、朝昼晩\\n食べたいにゃ！', 0);
insert into room_unit_comments values (1649, 104602, 3, 8, 1, 0, 1, '本を読んで\\n猫の気持ちを\\n勉強するのにゃ！', 0);
insert into room_unit_comments values (1651, 104801, 1, 1, 1, 0, 1, '内職手伝える人\\nいないかしら？', 0);
insert into room_unit_comments values (1652, 104801, 1, 2, 1, 0, 1, '次の依頼は、\\nこういう計画で…\\nうん、完璧ね！', 0);
insert into room_unit_comments values (1653, 104801, 1, 3, 1, 0, 1, '次の特売セールに\\n向けて、しっかり\\n準備しないと！', 0);
insert into room_unit_comments values (1654, 104801, 1, 4, 1, 0, 1, '配達の後に売り子\\n次に採取のバイト…\\nうん、効率的ね', 0);
insert into room_unit_comments values (1655, 104801, 1, 5, 1, 0, 1, '一日に受ける\\nバイトの数、もう少し\\n増やしたいわね', 0);
insert into room_unit_comments values (1656, 104801, 1, 101, 4, 0, 1, '師匠として\\n頼りにされたいし\\nもっと頑張らなきゃ！', 0);
insert into room_unit_comments values (1657, 104801, 1, 102, 8, 0, 1, '男の子と効率的に\\n仲良くなる方法…\\nこればっかりは難題ね', 0);
insert into room_unit_comments values (1658, 104801, 2, 1, 1, 0, 1, 'あら、\\nちょうどよかった\\n今から一緒に\\nバイトでもどう？', 0);
insert into room_unit_comments values (1659, 104801, 2, 2, 1, 0, 1, '相談事かしら？\\nそれくらいなら\\n無料でいいわよ', 0);
insert into room_unit_comments values (1660, 104801, 2, 3, 1, 0, 1, '背後の気配なら\\nすぐ分かるわ\\n試してみる？', 0);
insert into room_unit_comments values (1661, 104801, 2, 4, 1, 0, 1, '道具やお金の管理は\\n大丈夫？\u3000手伝うから\\nいつでも言って', 0);
insert into room_unit_comments values (1662, 104801, 2, 101, 4, 0, 1, '暇ができたから\\n働きたいけど…\\nキミとの時間も大切ね', 0);
insert into room_unit_comments values (1663, 104801, 2, 102, 8, 0, 1, 'ねえ、あの…\\n私はキミにとって…\\nいや、何でもないわ', 0);
insert into room_unit_comments values (1664, 104801, 2, 1, 1, 1, 1, 'おはよう！\\n今日も朝から\\nバイトよ！', 0);
insert into room_unit_comments values (1665, 104801, 2, 2, 1, 2, 1, 'お昼時ね。\\n少し休憩したら、\\nまた働くわよ！', 0);
insert into room_unit_comments values (1666, 104801, 2, 3, 1, 3, 1, 'もうこんな時間！\\n明日もバイトで\\n朝早いのよ…', 0);
insert into room_unit_comments values (1667, 104801, 3, 1, 1, 0, 1, '接客業の依頼が\\nある時は、外見も\\nキレイにしないとね', 0);
insert into room_unit_comments values (1668, 104801, 3, 2, 1, 0, 1, 'はぁ～バイトで\\n疲れたから癒される～', 0);
insert into room_unit_comments values (1669, 104801, 3, 3, 1, 0, 1, 'これを内職で\\n作ったら\\n儲かるかしら？', 0);
insert into room_unit_comments values (1670, 104801, 3, 4, 1, 0, 1, 'リフレッシュできたわ\\nこれでまた、バリバリ\\n働けるわね！', 0);
insert into room_unit_comments values (1671, 104801, 3, 5, 1, 0, 1, '風邪を引いたら効率が\\n落ちちゃうから、\\n暖めないと！', 0);
insert into room_unit_comments values (1672, 104801, 3, 6, 1, 0, 1, '働き続けるには\\n健康第一！\u3000それには\\n運動が一番よ', 0);
insert into room_unit_comments values (1673, 104801, 3, 7, 1, 0, 1, 'もぐもぐ…\\n腹が減っては\\n戦ができぬ、よ！', 0);
insert into room_unit_comments values (1674, 104801, 3, 8, 1, 0, 1, '日々絶えず学んで、\\n生活に活かすのよ！', 0);
insert into room_unit_comments values (1676, 104802, 1, 1, 1, 0, 1, '家計簿をつけなきゃ！\\n覚えている時に\\nやっておかないとね', 0);
insert into room_unit_comments values (1677, 104802, 1, 2, 1, 0, 1, '次の依頼は\\nこういう計画で…\\nうん、完璧ね！', 0);
insert into room_unit_comments values (1678, 104802, 1, 3, 1, 0, 1, 'ギルドの経費\\nあとちょっとだけ\\n削れそうね…', 0);
insert into room_unit_comments values (1679, 104802, 1, 4, 1, 0, 1, '少しでも時給のいい\\nバイトがしたいけど\\nなかなか\\n出会えないのよ', 0);
insert into room_unit_comments values (1680, 104802, 1, 5, 1, 0, 1, '今度のバイトも\\nなかなか大変そう\\nね…腕が鳴るわ', 0);
insert into room_unit_comments values (1681, 104802, 1, 101, 8, 0, 1, '男の子と効率的に\\n仲良くなる方法…\\nこればっかりは難題ね', 0);
insert into room_unit_comments values (1682, 104802, 1, 102, 8, 0, 1, '私、どうしたんだろ？\\n仕事中もずっと\\n彼のこと考えてる…', 0);
insert into room_unit_comments values (1683, 104802, 2, 1, 1, 0, 1, 'この間はヘルプに\\n来てくれてありがとう\\n頼んで正解だったわ', 0);
insert into room_unit_comments values (1684, 104802, 2, 2, 1, 0, 1, '見つけた！\u3000ちょうど\\n頼みたいことが\\nあるんだけど、いい？', 0);
insert into room_unit_comments values (1685, 104802, 2, 3, 1, 0, 1, '今から\\n休憩するところなの\\n一緒にどう？', 0);
insert into room_unit_comments values (1686, 104802, 2, 4, 1, 0, 1, 'ん？\u3000どうしたの？\\n私のことが\\n気になるの？', 0);
insert into room_unit_comments values (1687, 104802, 2, 101, 8, 0, 1, '…たまには甘えても\\nいい？\u3000私だって\\n弱る時はあるのよ', 0);
insert into room_unit_comments values (1688, 104802, 2, 102, 8, 0, 1, '暇ができたから\\n働きたいけど…\\nキミとの時間も大切ね', 0);
insert into room_unit_comments values (1689, 104802, 2, 1, 1, 1, 1, 'おはよう！\\nいい朝ね。一緒に\\nランニングでもいく？', 0);
insert into room_unit_comments values (1690, 104802, 2, 2, 1, 2, 1, 'お昼時ね\\n少し休憩したら\\nまた働くわよ！', 0);
insert into room_unit_comments values (1691, 104802, 2, 3, 1, 3, 1, 'もうこんな時間！\\n明日もバイトで\\n朝早いのよ…', 0);
insert into room_unit_comments values (1692, 104802, 3, 1, 1, 0, 1, '女の子らしく…\\nどうも忘れちゃう\\nのよね', 0);
insert into room_unit_comments values (1693, 104802, 3, 2, 1, 0, 1, 'ここで少し\\n休んだら\\nまたバイトよ！', 0);
insert into room_unit_comments values (1694, 104802, 3, 3, 1, 0, 1, 'これを内職で\\n作ったら\\n儲かるかしら？', 0);
insert into room_unit_comments values (1695, 104802, 3, 4, 1, 0, 1, '仕事から帰ってきて\\nこういうのがあると\\n素敵ね', 0);
insert into room_unit_comments values (1696, 104802, 3, 5, 1, 0, 1, 'しっかり身体を\\n温めて、血流を\\nよくしなくっちゃ', 0);
insert into room_unit_comments values (1697, 104802, 3, 6, 1, 0, 1, 'これで休憩中も\\n無駄なく\\n鍛えられるわ♪', 0);
insert into room_unit_comments values (1698, 104802, 3, 7, 1, 0, 1, 'もぐもぐ…よく\\n食べて、よく働く！\\nそれが私のモットーよ', 0);
insert into room_unit_comments values (1699, 104802, 3, 8, 1, 0, 1, '日々絶えず学んで\\n生活に活かすのよ！', 0);
insert into room_unit_comments values (1701, 104901, 1, 1, 1, 0, 1, '暇だし、お料理と\\nお掃除とお洗濯と\\n買い物しようかな？', 0);
insert into room_unit_comments values (1702, 104901, 1, 2, 1, 0, 1, 'こうして歩いていれば\\n弟くんが声をかけて\\nくれるはず…', 0);
insert into room_unit_comments values (1703, 104901, 1, 3, 1, 0, 1, '弟くんがどんな生活を\\nしてるのか調べるのも\\nお姉ちゃんの務め！', 0);
insert into room_unit_comments values (1704, 104901, 1, 4, 1, 0, 1, 'くんくん、\\n弟くんのにおい…\\n近くにいるね？', 0);
insert into room_unit_comments values (1705, 104901, 1, 5, 1, 0, 1, 'お姉ちゃんの痕跡を\\n部屋中に\\n残しちゃおっと♪', 0);
insert into room_unit_comments values (1706, 104901, 1, 101, 4, 0, 1, 'この部屋を、\\n私と弟くんの\\n愛の巣に…', 0);
insert into room_unit_comments values (1707, 104901, 1, 102, 8, 0, 1, 'はぁ～…弟くん\\n禁断症状だよ～', 0);
insert into room_unit_comments values (1708, 104901, 2, 1, 1, 0, 1, '弟くんの部屋は\\nお姉ちゃんの\\n部屋だよね～', 0);
insert into room_unit_comments values (1709, 104901, 2, 2, 1, 0, 1, 'いいこいいこ～♪\\nどう、お姉ちゃんの\\nナデナデは？', 0);
insert into room_unit_comments values (1710, 104901, 2, 3, 1, 0, 1, '姉と弟の外出は\\nデートって\\nいうのかな？', 0);
insert into room_unit_comments values (1711, 104901, 2, 4, 1, 0, 1, 'もう！\\nイタズラする子には\\nお姉ちゃんチョップ！', 0);
insert into room_unit_comments values (1712, 104901, 2, 101, 4, 0, 1, 'お姉ちゃんが\\nぎゅ～ってして\\nあげるね♪', 0);
insert into room_unit_comments values (1713, 104901, 2, 102, 8, 0, 1, 'あ、あのね…\\nたまにはお姉ちゃんも\\n甘えていい？', 0);
insert into room_unit_comments values (1714, 104901, 2, 1, 1, 1, 1, '着替えは？\u3000荷物は？\\nお出かけの準備は\\nお姉ちゃんが手伝うね', 0);
insert into room_unit_comments values (1715, 104901, 2, 2, 1, 2, 1, '出かけるなら\\n明るいうちに\\n帰ってくるんだよ！', 0);
insert into room_unit_comments values (1716, 104901, 2, 3, 1, 3, 1, 'まだ起きてるの？\\nそれじゃあ、\\nお姉ちゃんも\\n夜更かししちゃお☆', 0);
insert into room_unit_comments values (1717, 104901, 3, 1, 1, 0, 1, 'きれいなお姉ちゃん\\n好きだよね♪', 0);
insert into room_unit_comments values (1718, 104901, 3, 2, 1, 0, 1, 'ここにお姉ちゃんの\\n匂いを、た～っぷり\\n残しておこうっと♪', 0);
insert into room_unit_comments values (1719, 104901, 3, 3, 1, 0, 1, 'かわいい♪\\nお姉ちゃんチョップ！', 0);
insert into room_unit_comments values (1720, 104901, 3, 4, 1, 0, 1, 'この香り、\\n弟くん好きかな？', 0);
insert into room_unit_comments values (1721, 104901, 3, 5, 1, 0, 1, 'これ、弟くんみたいに\\nあったかいね～', 0);
insert into room_unit_comments values (1722, 104901, 3, 6, 1, 0, 1, 'ダイエットダイエット\\nきれいなお姉ちゃんに\\nならなくちゃ', 0);
insert into room_unit_comments values (1723, 104901, 3, 7, 1, 0, 1, 'あ、これ\\n弟くんが好きな\\n味付けだね！', 0);
insert into room_unit_comments values (1724, 104901, 3, 8, 1, 0, 1, '弟くんが読んでいいか\\nお姉ちゃんが先に\\n中を確認しなくちゃ！', 0);
insert into room_unit_comments values (1726, 104902, 1, 1, 1, 0, 1, '暇だし、お料理と\\nお掃除とお洗濯と\\n買い物しようかな？', 0);
insert into room_unit_comments values (1727, 104902, 1, 2, 1, 0, 1, 'こうして歩いていれば\\n弟くんが声をかけて\\nくれるはず…', 0);
insert into room_unit_comments values (1728, 104902, 1, 3, 1, 0, 1, '弟くんのお友達は\\nみんな私の妹だよ♪', 0);
insert into room_unit_comments values (1729, 104902, 1, 4, 1, 0, 1, '弟くんがどんな生活を\\nしてるのか調べるのも\\nお姉ちゃんの務め！', 0);
insert into room_unit_comments values (1730, 104902, 1, 5, 1, 0, 1, 'はっ！\\n弟くんが困ってる\\n気がする！', 0);
insert into room_unit_comments values (1731, 104902, 1, 101, 8, 0, 1, 'はぁ～…弟くん、\\n禁断症状だよ～', 0);
insert into room_unit_comments values (1732, 104902, 1, 102, 8, 0, 1, 'お姉ちゃんの痕跡を\\n部屋中に\\n残しちゃおっと♪', 0);
insert into room_unit_comments values (1733, 104902, 2, 1, 1, 0, 1, 'お姉ちゃん\\nキミのお願いなら\\nなんでも聞いて\\nあげちゃうぞっ', 0);
insert into room_unit_comments values (1734, 104902, 2, 2, 1, 0, 1, '弟くんの部屋は\\nお姉ちゃんの\\n部屋だよね～', 0);
insert into room_unit_comments values (1735, 104902, 2, 3, 1, 0, 1, 'お姉ちゃんの胸に\\n飛び込んでおいでっ♪', 0);
insert into room_unit_comments values (1736, 104902, 2, 4, 1, 0, 1, 'いいこいいこ～♪\\nどう、お姉ちゃんの\\nナデナデは？', 0);
insert into room_unit_comments values (1737, 104902, 2, 101, 8, 0, 1, 'あ、あのね…\\nたまにはお姉ちゃんも\\n甘えていい？', 0);
insert into room_unit_comments values (1738, 104902, 2, 102, 8, 0, 1, 'お風呂にする？\\nごはんにする？\\nそれとも…うふふ♪', 0);
insert into room_unit_comments values (1739, 104902, 2, 1, 1, 1, 1, '着替えは？\u3000荷物は？\\nお出かけの準備は\\nお姉ちゃんが手伝うね', 0);
insert into room_unit_comments values (1740, 104902, 2, 2, 1, 2, 1, 'お姉ちゃんが\\nお昼ごはん\\n作ってあげようか？', 0);
insert into room_unit_comments values (1741, 104902, 2, 3, 1, 3, 1, '眠れないの？\\nお姉ちゃんが子守歌\\n歌ってあげるね！', 0);
insert into room_unit_comments values (1742, 104902, 3, 1, 1, 0, 1, '弟くんを\\n誘惑しちゃうぞ～♪', 0);
insert into room_unit_comments values (1743, 104902, 3, 2, 1, 0, 1, 'ここにお姉ちゃんの\\n匂いを、た～っぷり\\n残しておこうっと♪', 0);
insert into room_unit_comments values (1744, 104902, 3, 3, 1, 0, 1, 'かわいい♪\\nお姉ちゃんチョップ！', 0);
insert into room_unit_comments values (1745, 104902, 3, 4, 1, 0, 1, 'お肌に潤いが\\nでてきたみたい～♪', 0);
insert into room_unit_comments values (1746, 104902, 3, 5, 1, 0, 1, 'これ、弟くんみたいに\\nあったかいね～', 0);
insert into room_unit_comments values (1747, 104902, 3, 6, 1, 0, 1, 'ダイエットダイエット\\nきれいなお姉ちゃんに\\nならなくちゃ', 0);
insert into room_unit_comments values (1748, 104902, 3, 7, 1, 0, 1, '弟くんの手作りなら\\nもっとおいしくなると\\n思うんだけどなぁ～', 0);
insert into room_unit_comments values (1749, 104902, 3, 8, 1, 0, 1, '弟くんをきちんと\\n教育するために\\nお姉ちゃんは勉強を\\nかかさないのだ☆', 0);
insert into room_unit_comments values (1751, 105001, 1, 1, 1, 0, 1, 'ん～、エレガントで\\n大人なお部屋ね！\\nアタシにぴったり！', 0);
insert into room_unit_comments values (1752, 105001, 1, 2, 1, 0, 1, '身長とバスト以外は\\n完璧な大人\\nなのになぁ～', 0);
insert into room_unit_comments values (1753, 105001, 1, 3, 1, 0, 1, 'アタシの大人コーデで\\nあいつも夢中ね♪', 0);
insert into room_unit_comments values (1754, 105001, 1, 4, 1, 0, 1, '朝顔の観察したら\\n理系女子になれる\\nかしら？', 0);
insert into room_unit_comments values (1755, 105001, 1, 5, 1, 0, 1, 'レディは、どんな時も\\nおしとやかに…って\\nアタシも騒ぎたいー！', 0);
insert into room_unit_comments values (1756, 105001, 1, 101, 4, 0, 1, '大人っぽい子が\\n多いわね…アタシも\\n負けてられないわ！', 0);
insert into room_unit_comments values (1757, 105001, 1, 102, 8, 0, 1, 'アタシが待ってる\\nなんて、アイツは\\n幸せものよねー', 0);
insert into room_unit_comments values (1758, 105001, 2, 1, 1, 0, 1, 'わーい、アメだー♪\\n食べる食べるー♪', 0);
insert into room_unit_comments values (1759, 105001, 2, 2, 1, 0, 1, '熱いハニーラテが\\n飲みたーい！\\n淹れてー淹れてー！', 0);
insert into room_unit_comments values (1760, 105001, 2, 3, 1, 0, 1, 'なによ？\u3000もしかして\\n好きな子にイタズラ\\nしたくなるってやつ？', 0);
insert into room_unit_comments values (1761, 105001, 2, 4, 1, 0, 1, 'アタシに合う服\\n雑誌で探そうっと！\\nサイズじゃないわ、\\nデザインとかの話よ！', 0);
insert into room_unit_comments values (1762, 105001, 2, 101, 4, 0, 1, 'ねーねー！\\nアタシ、かわいい？\\nかわいいわよね？', 0);
insert into room_unit_comments values (1763, 105001, 2, 102, 8, 0, 1, 'これから出かけるの？\\nしっかりアタシを\\nエスコートしてね！', 0);
insert into room_unit_comments values (1764, 105001, 2, 1, 1, 1, 1, '朝のスキンケアは\\n大事なの！', 0);
insert into room_unit_comments values (1765, 105001, 2, 2, 1, 2, 1, 'お腹すいたー\\nダイエット\\nやめちゃおうかなー', 0);
insert into room_unit_comments values (1766, 105001, 2, 3, 1, 3, 1, 'エイジングケアを\\nしないとねー', 0);
insert into room_unit_comments values (1767, 105001, 3, 1, 1, 0, 1, 'この角度のほうが\\n大人っぽく見えるかな\\nそれともこっちかしら', 0);
insert into room_unit_comments values (1768, 105001, 3, 2, 1, 0, 1, 'あ！\u3000これ雑誌で\\n見たことあるわ～\\nだからきっと\\nオシャレなのよ！', 0);
insert into room_unit_comments values (1769, 105001, 3, 3, 1, 0, 1, 'か、かわいい♪\u3000けど\\n大人はこんなもの…\\nでも、かわいいし～！', 0);
insert into room_unit_comments values (1770, 105001, 3, 4, 1, 0, 1, 'オシャレ～♪\\n大人なレディって\\n感じよね♪', 0);
insert into room_unit_comments values (1771, 105001, 3, 5, 1, 0, 1, 'あったかーい♪\\nここで宿題\\nしようかしら？', 0);
insert into room_unit_comments values (1772, 105001, 3, 6, 1, 0, 1, '運動したら成長\\nしないかしら？\\n背とか胸とか…', 0);
insert into room_unit_comments values (1773, 105001, 3, 7, 1, 0, 1, '食べすぎると\\n太っちゃうな…\\nでも、おいしいし～っ', 0);
insert into room_unit_comments values (1774, 105001, 3, 8, 1, 0, 1, 'おもしろーい！\\n…でも絵本って\\n子供っぽいかしら？', 0);
insert into room_unit_comments values (1776, 105002, 1, 1, 1, 0, 1, 'レディは、どんな時も\\nおしとやかに…って\\nアタシも騒ぎたいー！', 0);
insert into room_unit_comments values (1777, 105002, 1, 2, 1, 0, 1, '恋人にするなら\\nイケメンか\\nただイケよね～', 0);
insert into room_unit_comments values (1778, 105002, 1, 3, 1, 0, 1, 'もう少し背が欲しいな\\n…もっと牛乳を\\n飲まなくちゃ！', 0);
insert into room_unit_comments values (1779, 105002, 1, 4, 1, 0, 1, '朝顔の観察したら\\n理系女子になれる\\nかしら？', 0);
insert into room_unit_comments values (1780, 105002, 1, 5, 1, 0, 1, 'こ、これは補習の\\nお知らせプリント！\\nアイツに見つかる前に\\n隠さなくちゃ！', 0);
insert into room_unit_comments values (1781, 105002, 1, 101, 8, 0, 1, 'アイツおっそいなー\\n別に会いたいわけじゃ\\nないけど…\\n来ないと気になる…', 0);
insert into room_unit_comments values (1782, 105002, 1, 102, 8, 0, 1, 'アタシが待ってる\\nなんて、アイツは\\n幸せものよねー ', 0);
insert into room_unit_comments values (1783, 105002, 2, 1, 1, 0, 1, 'なーに？\\nアタシに甘えたいの？', 0);
insert into room_unit_comments values (1784, 105002, 2, 2, 1, 0, 1, 'アタシに合う服\\n雑誌で探そうっと！\\nサイズじゃないわ\\nデザインとかの話よ！', 0);
insert into room_unit_comments values (1785, 105002, 2, 3, 1, 0, 1, '頭撫でないで！\\nお子様みたいに\\nあつかわないでって\\n言ってるのに～！', 0);
insert into room_unit_comments values (1786, 105002, 2, 4, 1, 0, 1, '壁ドンの練習…\\nあれ？\u3000壁ドンって\\n男がするんだっけ？', 0);
insert into room_unit_comments values (1787, 105002, 2, 101, 8, 0, 1, 'ねーねー！\\nアタシ、かわいい？\\nかわいいわよね？', 0);
insert into room_unit_comments values (1788, 105002, 2, 102, 8, 0, 1, 'これから出かけるの？\\nしっかりアタシを\\nエスコートしてね！', 0);
insert into room_unit_comments values (1789, 105002, 2, 1, 1, 1, 1, 'レディの朝は\\n忙しいのよ', 0);
insert into room_unit_comments values (1790, 105002, 2, 2, 1, 2, 1, 'お腹すいたー\\nダイエット\\nやめちゃおうかなー', 0);
insert into room_unit_comments values (1791, 105002, 2, 3, 1, 3, 1, 'エイジングケアを\\nしないとねー', 0);
insert into room_unit_comments values (1792, 105002, 3, 1, 1, 0, 1, '身だしなみチェック\\nオッケー！\u3000これで\\nいつアイツが来ても\\n大丈夫ね！', 0);
insert into room_unit_comments values (1793, 105002, 3, 2, 1, 0, 1, 'あ！\u3000これ雑誌で\\n見たことあるわ～\\nだからきっと\\nオシャレなのよ！', 0);
insert into room_unit_comments values (1794, 105002, 3, 3, 1, 0, 1, 'あたしがもっと\\nオシャレにかわいく\\nしてあげようか？', 0);
insert into room_unit_comments values (1795, 105002, 3, 4, 1, 0, 1, 'オシャレ～♪\\n大人なレディって\\n感じよね♪', 0);
insert into room_unit_comments values (1796, 105002, 3, 5, 1, 0, 1, 'あったかーい♪\\nここで宿題\\nしようかしら？', 0);
insert into room_unit_comments values (1797, 105002, 3, 6, 1, 0, 1, '運動したら成長\\nしないかしら？\\n背とか胸とか…', 0);
insert into room_unit_comments values (1798, 105002, 3, 7, 1, 0, 1, 'レディは、食べ物にも\\n気を使うのよ', 0);
insert into room_unit_comments values (1799, 105002, 3, 8, 1, 0, 1, 'おもしろーい！\\n…でも絵本って\\n子供っぽいかしら？', 0);
insert into room_unit_comments values (1801, 105101, 1, 1, 1, 0, 1, '魔法と科学\\nどっちも極めて\\nみせるわ', 0);
insert into room_unit_comments values (1802, 105101, 1, 2, 1, 0, 1, '仕事も片付いたし\\n部屋で\\n実験実験…♪', 0);
insert into room_unit_comments values (1803, 105101, 1, 3, 1, 0, 1, 'たまった治療代の\\n請求書を\\nまとめないと…', 0);
insert into room_unit_comments values (1804, 105101, 1, 4, 1, 0, 1, '新薬が出来たし\\nすぐに試したいけど…\\n実験台がいないわ', 0);
insert into room_unit_comments values (1805, 105101, 1, 5, 1, 0, 1, '部屋にこもりすぎると\\n曜日の感覚が\\nなくなるわね', 0);
insert into room_unit_comments values (1806, 105101, 1, 101, 4, 0, 1, 'あの子の記憶を\\n取り戻せる薬…\\n作れないものかしら', 0);
insert into room_unit_comments values (1807, 105101, 1, 102, 8, 0, 1, '好意に気づいて貰える\\n薬って、どうすれば\\n作れるのかしら', 0);
insert into room_unit_comments values (1808, 105101, 2, 1, 1, 0, 1, 'あら、ヒマなら\\n薬草の整理を\\n手伝って', 0);
insert into room_unit_comments values (1809, 105101, 2, 2, 1, 0, 1, 'もしかして実験に\\n付き合ってくれるの？\\nえ？\u3000違う？', 0);
insert into room_unit_comments values (1810, 105101, 2, 3, 1, 0, 1, '具合が悪い？\\nなら診てあげる\\nまずは触診から…', 0);
insert into room_unit_comments values (1811, 105101, 2, 4, 1, 0, 1, '植物に興味あるの？\\nなら教えてあげるわ\\n色々とね…', 0);
insert into room_unit_comments values (1812, 105101, 2, 101, 4, 0, 1, 'キミの傍にいるだけで\\n高揚しちゃうのは\\n何故かしら…？', 0);
insert into room_unit_comments values (1813, 105101, 2, 102, 8, 0, 1, '私はおしおきする\\n側のことが多いけど…\\nキミにはされたいかも', 0);
insert into room_unit_comments values (1814, 105101, 2, 1, 1, 1, 1, 'お昼までに調合用の\\n花を集めたいの\\n手伝ってくれる？', 0);
insert into room_unit_comments values (1815, 105101, 2, 2, 1, 2, 1, 'あら、もうお昼？\\nそろそろ一息\\n入れましょうか', 0);
insert into room_unit_comments values (1816, 105101, 2, 3, 1, 3, 1, '夜も更けて来たわね\\n私は朝まで実験だけど\\n見学していく？', 0);
insert into room_unit_comments values (1817, 105101, 3, 1, 1, 0, 1, '医者たるもの\\nいつだって\\n清潔に…♪', 0);
insert into room_unit_comments values (1818, 105101, 3, 2, 1, 0, 1, 'いいわねこれ\\n仮眠の時に\\n使わせてもらうわ', 0);
insert into room_unit_comments values (1819, 105101, 3, 3, 1, 0, 1, 'ぬいぐるみなら\\n動物も…', 0);
insert into room_unit_comments values (1820, 105101, 3, 4, 1, 0, 1, 'いい香り…\\n仕事場にも\\n置いてみようかしら', 0);
insert into room_unit_comments values (1821, 105101, 3, 5, 1, 0, 1, 'ここにいると\\nついウトウト\\nしちゃうわ…', 0);
insert into room_unit_comments values (1822, 105101, 3, 6, 1, 0, 1, '座ってる時間が多いと\\n運動不足になるし\\nたまにはいいわね', 0);
insert into room_unit_comments values (1823, 105101, 3, 7, 1, 0, 1, '研究していると\\nつい食べるのを\\n忘れちゃうのよね', 0);
insert into room_unit_comments values (1824, 105101, 3, 8, 1, 0, 1, '実験もいいけど\\nいつか成果を\\n本にしないと…', 0);
insert into room_unit_comments values (1826, 105102, 1, 1, 1, 0, 1, '徹夜はツラいけど\\n集中すると時間の\\n感覚がなくなって…', 0);
insert into room_unit_comments values (1827, 105102, 1, 2, 1, 0, 1, '痛みに悶える顔って\\nどうしてあんなに\\n興奮するのかしら？', 0);
insert into room_unit_comments values (1828, 105102, 1, 3, 1, 0, 1, '彼に罵られたら\\nどんな気分かしら\\n意外と快感かも？', 0);
insert into room_unit_comments values (1829, 105102, 1, 4, 1, 0, 1, '毒を薄めると\\n薬になるのって\\n今でも不思議だわ', 0);
insert into room_unit_comments values (1830, 105102, 1, 5, 1, 0, 1, '綺麗なバラには\\nトゲがあるけど\\n魅力の一つよね', 0);
insert into room_unit_comments values (1831, 105102, 1, 101, 8, 0, 1, 'カレをさりげなく\\n惚れさせる方法を\\n研究するわよ…♪', 0);
insert into room_unit_comments values (1832, 105102, 1, 102, 8, 0, 1, '好意に気づいて貰える\\n薬って、どうすれば\\n作れるのかしら', 0);
insert into room_unit_comments values (1833, 105102, 2, 1, 1, 0, 1, '構って欲しいの？\\nじゃあ、君の体を\\n調べさせて？', 0);
insert into room_unit_comments values (1834, 105102, 2, 2, 1, 0, 1, '実験に付き合って\\n大丈夫よ、試すのは\\nただの栄養剤だから', 0);
insert into room_unit_comments values (1835, 105102, 2, 3, 1, 0, 1, '欲しい薬が\\nあったら言ってね\\n調合してみるから', 0);
insert into room_unit_comments values (1836, 105102, 2, 4, 1, 0, 1, 'おしおきされたいの？\\nキミにだったら\\nいつでもしてあげる', 0);
insert into room_unit_comments values (1837, 105102, 2, 101, 8, 0, 1, 'キミの傍にいるだけで\\n高揚しちゃうのは\\n何故かしら…？', 0);
insert into room_unit_comments values (1838, 105102, 2, 102, 8, 0, 1, '私はおしおきする\\n側のことが多いけど…\\nキミにはされたいかも', 0);
insert into room_unit_comments values (1839, 105102, 2, 1, 1, 1, 1, '朝しか取れない\\n植物があるの\\n採取しに行くわよ', 0);
insert into room_unit_comments values (1840, 105102, 2, 2, 1, 2, 1, 'お昼時ってやけに\\n眠たくなるわよね\\n…調べたくなるわ', 0);
insert into room_unit_comments values (1841, 105102, 2, 3, 1, 3, 1, '今日くらいは\\nゆっくり眠りたいわ\\n…キミと一緒にね', 0);
insert into room_unit_comments values (1842, 105102, 3, 1, 1, 0, 1, '身なりについて\\n研究するのも\\n楽しそうね', 0);
insert into room_unit_comments values (1843, 105102, 3, 2, 1, 0, 1, '休息に必要な道具は\\n妥協せずに選ぶ！\\nこれだけは譲れないわ', 0);
insert into room_unit_comments values (1844, 105102, 3, 3, 1, 0, 1, 'たまにはこういう\\n可愛らしいものに\\n触れないとね♪', 0);
insert into room_unit_comments values (1845, 105102, 3, 4, 1, 0, 1, 'いい香り…\\n仕事場にも\\n置いてみようかしら', 0);
insert into room_unit_comments values (1846, 105102, 3, 5, 1, 0, 1, '仕事がなかったら\\nこのまますーっと\\n眠りたいのに…', 0);
insert into room_unit_comments values (1847, 105102, 3, 6, 1, 0, 1, '運動しないと\\n体型の維持が…', 0);
insert into room_unit_comments values (1848, 105102, 3, 7, 1, 0, 1, '適度な食事も\\n大切よね', 0);
insert into room_unit_comments values (1849, 105102, 3, 8, 1, 0, 1, 'まさか私が\\n恋愛読本を読む\\n日が来るなんて…', 0);
insert into room_unit_comments values (1851, 105201, 1, 1, 1, 0, 1, 'ぺっぺっ！\\n…い、いけないっ！', 0);
insert into room_unit_comments values (1852, 105201, 1, 2, 1, 0, 1, 'いっけな～い！\\nひづめで床に傷が！', 0);
insert into room_unit_comments values (1853, 105201, 1, 3, 1, 0, 1, '太っちゃったかも～！\\n伐採でダイエット\\nしなくっちゃ！', 0);
insert into room_unit_comments values (1854, 105201, 1, 4, 1, 0, 1, 'きちんと生活すると\\n毛づやが良くなる\\nみたいなのよね～', 0);
insert into room_unit_comments values (1855, 105201, 1, 5, 1, 0, 1, 'みんな、体重\\nどれくらいなのかな？', 0);
insert into room_unit_comments values (1856, 105201, 1, 101, 4, 0, 1, '体力なら自信\\nあるんだけど…\\n恋にはちょっぴり\\n臆病になっちゃう', 0);
insert into room_unit_comments values (1857, 105201, 1, 102, 8, 0, 1, 'いつか人間の女の子\\nみたいなデート、\\nしてみたいな～♪', 0);
insert into room_unit_comments values (1858, 105201, 2, 1, 1, 0, 1, '私ね「どこにでもいる\\n普通の女の子」って\\n言葉が憧れなんだ～♪', 0);
insert into room_unit_comments values (1859, 105201, 2, 2, 1, 0, 1, 'チャームポイント？\\n自分では分からない\\nけど…まつげかなぁ？', 0);
insert into room_unit_comments values (1860, 105201, 2, 3, 1, 0, 1, 'リマリマ～♪\\nはっ！？\\nわ、私ったら今何を？', 0);
insert into room_unit_comments values (1861, 105201, 2, 4, 1, 0, 1, '力仕事ならまかせて！', 0);
insert into room_unit_comments values (1862, 105201, 2, 101, 4, 0, 1, '人間になりたいな～\\nそれか、あなたが\\n私みたいな姿に…♪', 0);
insert into room_unit_comments values (1863, 105201, 2, 102, 8, 0, 1, 'しょうがないなあ、\\nこんなにモフらせるの\\nあなただけだよ？', 0);
insert into room_unit_comments values (1864, 105201, 2, 1, 1, 1, 1, '今朝は寝癖がひどいわ\\nしっぽの辺りとか～', 0);
insert into room_unit_comments values (1865, 105201, 2, 2, 1, 2, 1, 'ランチは\\nおしゃれなカフェで\\nしてみたいな～♪', 0);
insert into room_unit_comments values (1866, 105201, 2, 3, 1, 3, 1, 'お肌のケアに\\nパックしながら\\n寝ようかな～', 0);
insert into room_unit_comments values (1867, 105201, 3, 1, 1, 0, 1, 'やだっ、\\nまた寝ぐせついてる！\\n直さないと！', 0);
insert into room_unit_comments values (1868, 105201, 3, 2, 1, 0, 1, 'ミシッっていった！\\n私、重すぎるかも！？', 0);
insert into room_unit_comments values (1869, 105201, 3, 3, 1, 0, 1, 'あ！\u3000あなたも\\n美人さんね～♪', 0);
insert into room_unit_comments values (1870, 105201, 3, 4, 1, 0, 1, 'はぁ、まったり…\\n四足歩行しちゃい\\nそうだわ…', 0);
insert into room_unit_comments values (1871, 105201, 3, 5, 1, 0, 1, 'あったか～い♪\\n…私、毛皮だから\\n暑すぎるかも', 0);
insert into room_unit_comments values (1872, 105201, 3, 6, 1, 0, 1, 'な、なんだか野生に\\n帰っちゃいそう！', 0);
insert into room_unit_comments values (1873, 105201, 3, 7, 1, 0, 1, 'ぱくぱく、もぐもぐ、\\nぺっぺっ…\\nやだ、はしたない！', 0);
insert into room_unit_comments values (1874, 105201, 3, 8, 1, 0, 1, 'きゃーーー！\\nこの恋愛小説\\nとっても\\nドキドキしちゃう～', 0);
insert into room_unit_comments values (1876, 105202, 1, 1, 1, 0, 1, '素敵ね～、居るだけで\\n女子力があがりそうな\\nお部屋だわ～', 0);
insert into room_unit_comments values (1877, 105202, 1, 2, 1, 0, 1, '私、大丈夫かしら？\\n他の子に怖がられたり\\nしないかな…？', 0);
insert into room_unit_comments values (1878, 105202, 1, 3, 1, 0, 1, '動物苑…って\\n嫌なギルド名ね…', 0);
insert into room_unit_comments values (1879, 105202, 1, 4, 1, 0, 1, '好き、嫌い、好き…\\nあっ！\u3000うっかりして\\n花占いのお花\\n食べちゃった！', 0);
insert into room_unit_comments values (1880, 105202, 1, 5, 1, 0, 1, 'ここ、女の子らしい\\nものでいっぱいね～！\\nときめいちゃうわ～♪', 0);
insert into room_unit_comments values (1881, 105202, 1, 101, 8, 0, 1, '体力なら自信\\nあるんだけど…\\n恋にはちょっぴり\\n臆病になっちゃう', 0);
insert into room_unit_comments values (1882, 105202, 1, 102, 8, 0, 1, 'あの人が\\n来てくれるまで薪割り\\nでもしてよっかな？', 0);
insert into room_unit_comments values (1883, 105202, 2, 1, 1, 0, 1, '一緒にお出かけ？\\nうれしいけど…\\n心の準備が！\\nはわわわ！', 0);
insert into room_unit_comments values (1884, 105202, 2, 2, 1, 0, 1, 'どうしたの？\\n急に抱きついてきて…\\n癒されたいの？', 0);
insert into room_unit_comments values (1885, 105202, 2, 3, 1, 0, 1, 'ぺっぺっ！\\n…い、いけないっ！', 0);
insert into room_unit_comments values (1886, 105202, 2, 4, 1, 0, 1, 'メタモルアップルを\\nここで食べたら、\\nみんな驚くわよね', 0);
insert into room_unit_comments values (1887, 105202, 2, 101, 8, 0, 1, 'しょうがないなあ、\\nこんなにモフらせるの\\nあなただけだよ？', 0);
insert into room_unit_comments values (1888, 105202, 2, 102, 8, 0, 1, '人間になりたいな～\\nそれか、あなたが\\n私みたいな姿に…♪', 0);
insert into room_unit_comments values (1889, 105202, 2, 1, 1, 1, 1, '今朝は寝癖がひどいわ\\nしっぽの辺りとか～', 0);
insert into room_unit_comments values (1890, 105202, 2, 2, 1, 2, 1, 'ダイエット中だから\\nお昼は抜いてるの～', 0);
insert into room_unit_comments values (1891, 105202, 2, 3, 1, 3, 1, 'お肌のケアに\\nパックしながら\\n寝ようかな～', 0);
insert into room_unit_comments values (1892, 105202, 3, 1, 1, 0, 1, 'ちゃんとかわいく\\nしてないと刈られ…\\n狩られちゃうもんね！', 0);
insert into room_unit_comments values (1893, 105202, 3, 2, 1, 0, 1, 'ミシッっていった！\\n私、重すぎるかも！？', 0);
insert into room_unit_comments values (1894, 105202, 3, 3, 1, 0, 1, 'あ！\u3000あなたも\\n美人さんね～♪', 0);
insert into room_unit_comments values (1895, 105202, 3, 4, 1, 0, 1, 'いい香り～\\n森の中にいるみたいに\\nとっても落ち着く～', 0);
insert into room_unit_comments values (1896, 105202, 3, 5, 1, 0, 1, '素敵～♪\u3000…\\nきゃっ！\u3000私の毛が\\nたいへんなことに～！', 0);
insert into room_unit_comments values (1897, 105202, 3, 6, 1, 0, 1, 'な、なんだか野生に\\n帰っちゃいそう！', 0);
insert into room_unit_comments values (1898, 105202, 3, 7, 1, 0, 1, '何を食べるかより\\n誰と食べるかが\\n大事なのよね', 0);
insert into room_unit_comments values (1899, 105202, 3, 8, 1, 0, 1, 'きゃーーー！\\nこの恋愛小説\\nとっても\\nドキドキしちゃう～', 0);
insert into room_unit_comments values (1901, 105301, 1, 1, 1, 0, 1, 'ヴァイスフリューゲル\\nを盛り上げる方法、\\n共に語らおう！', 0);
insert into room_unit_comments values (1902, 105301, 1, 2, 1, 0, 1, '私は子供ではない…！\\nが、お菓子は\\nいただこう！', 0);
insert into room_unit_comments values (1903, 105301, 1, 3, 1, 0, 1, '部屋はきちんと\\n片づけておかなくては\\n部屋の汚れは\\n心の汚れだ', 0);
insert into room_unit_comments values (1904, 105301, 1, 4, 1, 0, 1, 'むむむ…明日\\n目が覚めたら、身長が\\n伸びていないものか…', 0);
insert into room_unit_comments values (1905, 105301, 1, 5, 1, 0, 1, 'お菓子が常備されて\\nいる部屋。そんな\\nものが、私の好みだ…', 0);
insert into room_unit_comments values (1906, 105301, 1, 101, 4, 0, 1, 'あいつとの新たな\\n鍛錬が\\n待ち遠しいな…！', 0);
insert into room_unit_comments values (1907, 105301, 1, 102, 8, 0, 1, '最近、あいつと\\n過ごしていて、毎日が\\n充実しているな…', 0);
insert into room_unit_comments values (1908, 105301, 2, 1, 1, 0, 1, '軍人の本分は日々の\\n研鑽にあるからな。\\n今日も鍛錬に\\n行かないか？', 0);
insert into room_unit_comments values (1909, 105301, 2, 2, 1, 0, 1, '毎日牛乳を飲んでいる\\nのだが、なかなか背が\\n伸びないものだな…', 0);
insert into room_unit_comments values (1910, 105301, 2, 3, 1, 0, 1, '貴公にも、飴をくれて\\nやろうか？\\nあまいぞ～！\\n美味しいぞ～！', 0);
insert into room_unit_comments values (1911, 105301, 2, 4, 1, 0, 1, '私ともっと高く、\\n共に飛ぼう！', 0);
insert into room_unit_comments values (1912, 105301, 2, 101, 4, 0, 1, '貴公は、本当に頼りに\\nなる男だな…いや、\\nふとそう思っただけだ', 0);
insert into room_unit_comments values (1913, 105301, 2, 102, 8, 0, 1, '貴公と共にいられる\\nことは私の喜びだ。\\nこれからも\\nよろしく頼むぞ', 0);
insert into room_unit_comments values (1914, 105301, 2, 1, 1, 1, 1, 'うむ、いい朝だ。\\n本国の夜明けを\\n思い出してしまうな！', 0);
insert into room_unit_comments values (1915, 105301, 2, 2, 1, 2, 1, 'そろそろ昼食に\\nするか。腹が減っては\\n戦はできないからな', 0);
insert into room_unit_comments values (1916, 105301, 2, 3, 1, 3, 1, 'ふわああ…私は子供\\nではないが…眠い時は\\n眠いのだ…', 0);
insert into room_unit_comments values (1917, 105301, 3, 1, 1, 0, 1, '身だしなみは、心の\\n在りようを映すから\\n気をつけなくてはな', 0);
insert into room_unit_comments values (1918, 105301, 3, 2, 1, 0, 1, 'ふう…軍人たるもの\\n常日頃、油断は\\nできないのだが…\\nお、落ち着くな…', 0);
insert into room_unit_comments values (1919, 105301, 3, 3, 1, 0, 1, 'うむ…このかわいさ…\\n本国に持って\\n帰りたい…', 0);
insert into room_unit_comments values (1920, 105301, 3, 4, 1, 0, 1, 'このともし火、戦いに\\n明け暮れる我らの心を\\n癒すものだな…', 0);
insert into room_unit_comments values (1921, 105301, 3, 5, 1, 0, 1, 'はあ～、ぽかぽか…\\nい、いや！\\n気を緩めないぞっ！', 0);
insert into room_unit_comments values (1922, 105301, 3, 6, 1, 0, 1, 'うおおおおおっ！\\n鍛錬、鍛錬、\\n鍛錬っ！！', 0);
insert into room_unit_comments values (1923, 105301, 3, 7, 1, 0, 1, 'いつ戦いになっても\\n困らぬように、\\n腹八分目に\\nしておくのだ！', 0);
insert into room_unit_comments values (1924, 105301, 3, 8, 1, 0, 1, 'これを読んで、新たな\\n戦術を編み出すぞっ！', 0);
insert into room_unit_comments values (1926, 105302, 1, 1, 1, 0, 1, 'たまには掃除でも\\nするか。部屋が\\n綺麗になるのは\\n喜ばしいことだ', 0);
insert into room_unit_comments values (1927, 105302, 1, 2, 1, 0, 1, '部屋の中では\\n剣を振り回せないのが\\n玉に瑕だな…', 0);
insert into room_unit_comments values (1928, 105302, 1, 3, 1, 0, 1, 'お菓子が常備されて\\nいる部屋。そんな\\nものが、私の好みだ…', 0);
insert into room_unit_comments values (1929, 105302, 1, 4, 1, 0, 1, '毎日牛乳を飲んでいる\\nのだが、なかなか背が\\n伸びないものだな…', 0);
insert into room_unit_comments values (1930, 105302, 1, 5, 1, 0, 1, '家庭を守れない者が\\n国を守れるはずが\\nない。この部屋も\\n私が守るぞ！', 0);
insert into room_unit_comments values (1931, 105302, 1, 101, 8, 0, 1, 'あいつは今頃、何を\\nしているのだろうな…\\nふふっ', 0);
insert into room_unit_comments values (1932, 105302, 1, 102, 8, 0, 1, 'あいつと会える日が\\nこんなにも待ち遠しく\\nなるとはな…', 0);
insert into room_unit_comments values (1933, 105302, 2, 1, 1, 0, 1, '軍人の本分は日々の\\n研鑽にあるからな\\n今日も鍛錬に\\n行かないか？', 0);
insert into room_unit_comments values (1934, 105302, 2, 2, 1, 0, 1, 'おお、今日も鍛錬の\\n時間だったか！\\nすまないな\\nすぐ行く！', 0);
insert into room_unit_comments values (1935, 105302, 2, 3, 1, 0, 1, '私は子供ではない！\\nが…たまには童心に\\n帰りたい時もある…', 0);
insert into room_unit_comments values (1936, 105302, 2, 4, 1, 0, 1, '貴公にも、飴を\\nくれてやろうか？\\nあまいぞ～！\\n美味しいぞ～！', 0);
insert into room_unit_comments values (1937, 105302, 2, 101, 8, 0, 1, '私と歩きたいのか…？\\nそうだな。二人で\\n散歩でも行こうか', 0);
insert into room_unit_comments values (1938, 105302, 2, 102, 8, 0, 1, '貴公と共にいられる\\nことは私の喜びだ\\nこれからも\\nよろしく頼むぞ', 0);
insert into room_unit_comments values (1939, 105302, 2, 1, 1, 1, 1, 'うむ、いい朝だ\\n本国の夜明けを\\n思い出してしまうな！', 0);
insert into room_unit_comments values (1940, 105302, 2, 2, 1, 2, 1, 'そろそろ昼時だな\\n鍛錬の手を緩めて\\n昼食にするか', 0);
insert into room_unit_comments values (1941, 105302, 2, 3, 1, 3, 1, '寝る前に…あと少し\\nだけ、鍛錬を…', 0);
insert into room_unit_comments values (1942, 105302, 3, 1, 1, 0, 1, 'ヴァイス\\nフリューゲルの一員と\\nして恥ずかしくないよう\\n身なりを整えなくては', 0);
insert into room_unit_comments values (1943, 105302, 3, 2, 1, 0, 1, 'ふう…軍人たるもの\\n常日頃、油断は\\nできないのだが…\\nお、落ち着くな…', 0);
insert into room_unit_comments values (1944, 105302, 3, 3, 1, 0, 1, 'うむ…このかわいさ…\\n本国に持って\\n帰りたい…', 0);
insert into room_unit_comments values (1945, 105302, 3, 4, 1, 0, 1, 'このともし火\\n戦いに明け暮れる\\n我らの心を\\n癒すものだな…', 0);
insert into room_unit_comments values (1946, 105302, 3, 5, 1, 0, 1, 'はあ～、ぽかぽか…\\nい、いや！\\n気を緩めないぞっ！', 0);
insert into room_unit_comments values (1947, 105302, 3, 6, 1, 0, 1, 'うおおおおおっ！\\n鍛錬、鍛錬\\n鍛錬っ！！', 0);
insert into room_unit_comments values (1948, 105302, 3, 7, 1, 0, 1, 'いつ戦いになっても\\n困らぬように\\n腹八分目に\\nしておくのだ！', 0);
insert into room_unit_comments values (1949, 105302, 3, 8, 1, 0, 1, 'うむ…脳細胞が\\n活性化してきたぞ\\n読書は大事だな', 0);
insert into room_unit_comments values (1951, 105701, 1, 1, 1, 0, 1, '私たちの騎空艇\\nどんなデザインに\\nしよう…？', 0);
insert into room_unit_comments values (1952, 105701, 1, 2, 1, 0, 1, '団員募集の\\nポスター\\n作ろうっと♪', 0);
insert into room_unit_comments values (1953, 105701, 1, 3, 1, 0, 1, '父さん…\\n今頃どこで\\n何してるんだろ？', 0);
insert into room_unit_comments values (1954, 105701, 1, 4, 1, 0, 1, '騎空艇に乗って、\\n誰もいったことがない\\n場所を見つけたいな', 0);
insert into room_unit_comments values (1955, 105701, 1, 5, 1, 0, 1, '父さん以上の\\n世界一の\\n騎空士になりたい！', 0);
insert into room_unit_comments values (1956, 105701, 1, 101, 4, 0, 1, '仲間と行く空の旅…\\n何度想像しても\\nドキドキするなぁ', 0);
insert into room_unit_comments values (1957, 105701, 1, 102, 8, 0, 1, '父さん…\\n私にもね、大切な\\n仲間ができたよ', 0);
insert into room_unit_comments values (1958, 105701, 2, 1, 1, 0, 1, '仕事の依頼？\\nすぐに支度\\nしてくるね！', 0);
insert into room_unit_comments values (1959, 105701, 2, 2, 1, 0, 1, 'ねえねえ！\\n団員募集のポスター\\n一緒に作ろうよ！', 0);
insert into room_unit_comments values (1960, 105701, 2, 3, 1, 0, 1, 'なーにー？\\nどうしたの？\\n今呼んだよね？', 0);
insert into room_unit_comments values (1961, 105701, 2, 4, 1, 0, 1, '今は休憩中だよ？\\nだからあなたも\\nゆっくりしてて', 0);
insert into room_unit_comments values (1962, 105701, 2, 101, 4, 0, 1, '私にとってあなたは\\nとっても頼りになる、\\n自慢の団員だよ！', 0);
insert into room_unit_comments values (1963, 105701, 2, 102, 8, 0, 1, 'お父さんに会えたら、\\n大切な仲間として\\nあなたを紹介するね！', 0);
insert into room_unit_comments values (1964, 105701, 2, 1, 1, 1, 1, 'おはよう！\\n体の調子はどう？\\n今日は頑張れそう？', 0);
insert into room_unit_comments values (1965, 105701, 2, 2, 1, 2, 1, 'ねえねえ、お昼\\n食べに行こうよ！\\nお腹空いちゃった', 0);
insert into room_unit_comments values (1966, 105701, 2, 3, 1, 3, 1, '…あれ？\\nおしゃべりしてたら\\nもうこんな時間？', 0);
insert into room_unit_comments values (1967, 105701, 3, 1, 1, 0, 1, 'どうせならオシャレな\\n騎空士って\\n呼ばれたいな', 0);
insert into room_unit_comments values (1968, 105701, 3, 2, 1, 0, 1, 'ふぅ、疲れた～…\\nちょっとだけ\\n休んじゃおっと', 0);
insert into room_unit_comments values (1969, 105701, 3, 3, 1, 0, 1, 'よし！\u3000キミは\\n今から団長代理だ！\\n…なんてね♪', 0);
insert into room_unit_comments values (1970, 105701, 3, 4, 1, 0, 1, 'いい香り～♪\\n気持ちが\\n落ち着く～…', 0);
insert into room_unit_comments values (1971, 105701, 3, 5, 1, 0, 1, 'これって\\n騎空艇に\\n置けるかな…？', 0);
insert into room_unit_comments values (1972, 105701, 3, 6, 1, 0, 1, 'どんな仕事でも\\nこなせるような\\n体力がないとね…！', 0);
insert into room_unit_comments values (1973, 105701, 3, 7, 1, 0, 1, 'あむっ…うん！\\n美味しい～！\\n今度作ってみよう♪', 0);
insert into room_unit_comments values (1974, 105701, 3, 8, 1, 0, 1, '空を冒険するには\\n色んなことを\\n知っておかないと…', 0);
insert into room_unit_comments values (1976, 105702, 1, 1, 1, 0, 1, '…戻らなくなったよ\\nどうすれば元に\\n戻る…？', 0);
insert into room_unit_comments values (1977, 105702, 1, 2, 1, 0, 1, '暇だよ…\\nどこかに強い人は\\nいないか？', 0);
insert into room_unit_comments values (1978, 105702, 1, 3, 1, 0, 1, 'ジョブチェンジ！\\n…叫んでも\\n戻らないよ', 0);
insert into room_unit_comments values (1979, 105702, 1, 4, 1, 0, 1, '今のうちに、\\n魔物退治の\\n仕事に行くね！', 0);
insert into room_unit_comments values (1980, 105702, 1, 5, 1, 0, 1, 'ハァ～…\\nうん、気の巡りは\\n問題ないね！', 0);
insert into room_unit_comments values (1981, 105702, 1, 101, 8, 0, 1, '私の力の源は\\n仲間との\\n絆だよ！', 0);
insert into room_unit_comments values (1982, 105702, 1, 102, 8, 0, 1, 'いつかこの拳を\\n空を越えた、星まで\\n届かせたいね', 0);
insert into room_unit_comments values (1983, 105702, 2, 1, 1, 0, 1, '功夫が足りない人は\\nどうすればいいか？\\nもちろん修行だよ！', 0);
insert into room_unit_comments values (1984, 105702, 2, 2, 1, 0, 1, '私はいつも通りに\\n喋ってるつもり\\nだよ？', 0);
insert into room_unit_comments values (1985, 105702, 2, 3, 1, 0, 1, 'どうした？\\nもしかして手合せ\\nしたいか？', 0);
insert into room_unit_comments values (1986, 105702, 2, 4, 1, 0, 1, '騎空士としても\\n拳法家としても\\n目指すは世界一ね！', 0);
insert into room_unit_comments values (1987, 105702, 2, 101, 8, 0, 1, '背中はあなたに\\n預けたよ！\\nよろしくね！', 0);
insert into room_unit_comments values (1988, 105702, 2, 102, 8, 0, 1, 'あなたと一緒なら\\nきっと、今よりもっと\\n強くなれるよ！', 0);
insert into room_unit_comments values (1989, 105702, 2, 1, 1, 1, 1, 'ちゃんと起きてるか？\\n寝ぼけてたら\\nダメよ？', 0);
insert into room_unit_comments values (1990, 105702, 2, 2, 1, 2, 1, '腹減ったね…\\nなにか食べに\\n行くよ！', 0);
insert into room_unit_comments values (1991, 105702, 2, 3, 1, 3, 1, '修行のしすぎは\\n良くないよ？\\n気をつけるね', 0);
insert into room_unit_comments values (1992, 105702, 3, 1, 1, 0, 1, '美しい技は\\n美しい体が\\nあってこそ！', 0);
insert into room_unit_comments values (1993, 105702, 3, 2, 1, 0, 1, 'よいしょっと…\\nちょっとのんびり\\nさせてもらうよ', 0);
insert into room_unit_comments values (1994, 105702, 3, 3, 1, 0, 1, '…練習に\\n使うのはさすがに\\n可哀そうね', 0);
insert into room_unit_comments values (1995, 105702, 3, 4, 1, 0, 1, 'これは…\\n瞑想の時にも\\n使ってみたいね', 0);
insert into room_unit_comments values (1996, 105702, 3, 5, 1, 0, 1, '出来ればもっと\\n熱いほうが\\n嬉しいよ', 0);
insert into room_unit_comments values (1997, 105702, 3, 6, 1, 0, 1, 'ここでも\\n修行出来るなんて\\n最高だよ！', 0);
insert into room_unit_comments values (1998, 105702, 3, 7, 1, 0, 1, '気力の源は体力！\\n体力の源は\\n健康とご飯！', 0);
insert into room_unit_comments values (1999, 105702, 3, 8, 1, 0, 1, 'んー…\\n難しいことは\\nわかんないよ！', 0);
insert into room_unit_comments values (2001, 105801, 1, 1, 1, 0, 1, 'わたしたちの\\nギルドハウスへ\\nようこそ～！', 0);
insert into room_unit_comments values (2002, 105801, 1, 2, 1, 0, 1, 'ぐるるる～…\\nあ、お腹が\\n鳴っちゃいました…', 0);
insert into room_unit_comments values (2003, 105801, 1, 3, 1, 0, 1, 'ん？\\n食べ物のにおい？', 0);
insert into room_unit_comments values (2004, 105801, 1, 4, 1, 0, 1, 'みんなと仲良く食卓を\\n囲みたいですね～', 0);
insert into room_unit_comments values (2005, 105801, 1, 5, 1, 0, 1, 'この部屋が、わたしの\\n帰る場所です♪', 0);
insert into room_unit_comments values (2006, 105801, 1, 101, 4, 0, 1, 'あの人を見ると\\n胸が満たされます～\\nお腹は空いてますが！', 0);
insert into room_unit_comments values (2007, 105801, 1, 102, 8, 0, 1, 'あの人、\\n大食いの子って\\n嫌いかな？', 0);
insert into room_unit_comments values (2008, 105801, 2, 1, 1, 0, 1, '食べもの、くれるん\\nですか？\u3000わーい！\\n恋しちゃいそう♪', 0);
insert into room_unit_comments values (2009, 105801, 2, 2, 1, 0, 1, 'つ、つまみ食いなんて\\nしてませんよ？\\nこれは味見です！', 0);
insert into room_unit_comments values (2010, 105801, 2, 3, 1, 0, 1, 'おやつは別腹、\\nごはんも別腹、\\n魔物も別腹～', 0);
insert into room_unit_comments values (2011, 105801, 2, 4, 1, 0, 1, '好きなものを、\\n好きな人達と食べる！\\n最高の贅沢ですね☆', 0);
insert into room_unit_comments values (2012, 105801, 2, 101, 4, 0, 1, 'あなたは、\\nごはん王子ですね～', 0);
insert into room_unit_comments values (2013, 105801, 2, 102, 8, 0, 1, '大好きです～\\n愛してます～\\nえへへ～♪', 0);
insert into room_unit_comments values (2014, 105801, 2, 1, 1, 1, 1, '朝ごはんも終わったし\\n早速ブランチを\\n食べませんか？', 0);
insert into room_unit_comments values (2015, 105801, 2, 2, 1, 2, 1, 'お昼ご飯、\\nおいしかったですね～\\nそれじゃあ、そろそろ\\nおやつにしましょう☆', 0);
insert into room_unit_comments values (2016, 105801, 2, 3, 1, 3, 1, 'お夕飯も、晩ごはんも\\n食べたし…さぁ！\\nお夜食の時間ですよ☆', 0);
insert into room_unit_comments values (2017, 105801, 3, 1, 1, 0, 1, '身だしなみ、\\n身だしなみ…\\nきちんとしないとね♪', 0);
insert into room_unit_comments values (2018, 105801, 3, 2, 1, 0, 1, 'ふい～\\n消化中です～', 0);
insert into room_unit_comments values (2019, 105801, 3, 3, 1, 0, 1, 'おいしそ…\\nか、かわいいです～', 0);
insert into room_unit_comments values (2020, 105801, 3, 4, 1, 0, 1, 'いい香りですね～\\n空気までおいしそう～\\nじゅるり♪', 0);
insert into room_unit_comments values (2021, 105801, 3, 5, 1, 0, 1, 'ほっかほか～♪\\n魔物の丸焼きが\\n作れちゃいますね！', 0);
insert into room_unit_comments values (2022, 105801, 3, 6, 1, 0, 1, '走って食べて！\\n走って食べて！\\n\\この無限ループです！', 0);
insert into room_unit_comments values (2023, 105801, 3, 7, 1, 0, 1, 'いくつでも\\n食べられますよ！\\n幸せ～☆', 0);
insert into room_unit_comments values (2024, 105801, 3, 8, 1, 0, 1, '料理の絵を\\n見ているだけで、\\nよ、よだれが～', 0);
insert into room_unit_comments values (2026, 105802, 1, 1, 1, 0, 1, 'この部屋が、わたしの\\n帰る場所です♪', 0);
insert into room_unit_comments values (2027, 105802, 1, 2, 1, 0, 1, 'ギルドハウス\\nどんどん素敵に\\nなっていくな～♪', 0);
insert into room_unit_comments values (2028, 105802, 1, 3, 1, 0, 1, '「やばい」とか\\n「おいっす」とか…\\n民の言葉って難しい', 0);
insert into room_unit_comments values (2029, 105802, 1, 4, 1, 0, 1, 'お菓子の家に\\n住みたいな～', 0);
insert into room_unit_comments values (2030, 105802, 1, 5, 1, 0, 1, 'あ、頼んでた出前が\\n届いたかな？', 0);
insert into room_unit_comments values (2031, 105802, 1, 101, 8, 0, 1, '大切な人がいて\\n大切な場所がある\\nすごく幸せです♪', 0);
insert into room_unit_comments values (2032, 105802, 1, 102, 8, 0, 1, 'あの人\\n大食いの子って\\n嫌いかな？', 0);
insert into room_unit_comments values (2033, 105802, 2, 1, 1, 0, 1, 'ごはんに行きますか？\\n作りましょうか？\\n店屋物もいいですね～', 0);
insert into room_unit_comments values (2034, 105802, 2, 2, 1, 0, 1, 'モグモグ…\\nあげませんよ～', 0);
insert into room_unit_comments values (2035, 105802, 2, 3, 1, 0, 1, 'おやつは別腹\\nごはんも別腹\\n魔物も別腹～', 0);
insert into room_unit_comments values (2036, 105802, 2, 4, 1, 0, 1, '好きなものを\\n好きな人達と食べる！\\n最高の贅沢ですね☆', 0);
insert into room_unit_comments values (2037, 105802, 2, 101, 8, 0, 1, '大好きです～\\n愛してます～\\nえへへ～♪', 0);
insert into room_unit_comments values (2038, 105802, 2, 102, 8, 0, 1, 'わたし食べても\\n太らないんです♪\\nほらほら～触って\\nみてくださいよ～', 0);
insert into room_unit_comments values (2039, 105802, 2, 1, 1, 1, 1, '朝ごはんも終わったし\\n早速ブランチを\\n食べませんか？', 0);
insert into room_unit_comments values (2040, 105802, 2, 2, 1, 2, 1, 'お昼ご飯\\nおいしかったですね～\\nそれじゃあ、そろそろ\\nおやつにしましょう☆', 0);
insert into room_unit_comments values (2041, 105802, 2, 3, 1, 3, 1, 'お夕飯も、晩ごはんも\\n食べたし～。さぁ！\\nお夜食の時間ですよ☆', 0);
insert into room_unit_comments values (2042, 105802, 3, 1, 1, 0, 1, 'お姫さまみたいに\\nきれいに\\nならないと…', 0);
insert into room_unit_comments values (2043, 105802, 3, 2, 1, 0, 1, 'のんびりしていても\\nお腹がすいちゃうん\\nですよね～', 0);
insert into room_unit_comments values (2044, 105802, 3, 3, 1, 0, 1, 'おいしそ…\\nか、かわいいです～', 0);
insert into room_unit_comments values (2045, 105802, 3, 4, 1, 0, 1, 'アップル系、ピーチ系\\nオレンジ系…\\n香りも色々ですね～', 0);
insert into room_unit_comments values (2046, 105802, 3, 5, 1, 0, 1, 'ここでお魚を\\n焼けたら\\n最高ですね～♪', 0);
insert into room_unit_comments values (2047, 105802, 3, 6, 1, 0, 1, '身体も鍛えなきゃ～！\\nお腹がすいちゃいます\\nけど…', 0);
insert into room_unit_comments values (2048, 105802, 3, 7, 1, 0, 1, 'もぐもぐもぐもぐもぐ\\nもぐもぐもぐもぐもぐ\\nもぐもぐもぐもぐ…', 0);
insert into room_unit_comments values (2049, 105802, 3, 8, 1, 0, 1, '流行語発表…\\nこんな言葉遣いが！\\nやばいですね', 0);
insert into room_unit_comments values (2051, 106001, 1, 1, 1, 0, 1, 'いろいろ美味しいもの\\n食べられるし…\\nけっこう幸せかも', 0);
insert into room_unit_comments values (2052, 106001, 1, 2, 1, 0, 1, 'んーー、あたし\\nなんで、このギルドに\\n入っちゃったんだろ？', 0);
insert into room_unit_comments values (2053, 106001, 1, 3, 1, 0, 1, 'あいつが来たら、\\n尾行しなくちゃ♪', 0);
insert into room_unit_comments values (2054, 106001, 1, 4, 1, 0, 1, 'この部屋のどこかに、\\nあいつの秘密が\\n隠されてるかも？', 0);
insert into room_unit_comments values (2055, 106001, 1, 5, 1, 0, 1, 'ま、まずいわ…\\nギルド活動、\\nけっこう楽しい♪', 0);
insert into room_unit_comments values (2056, 106001, 1, 101, 4, 0, 1, 'あいつを監視してる\\nと…な、なんか\\n変な気分', 0);
insert into room_unit_comments values (2057, 106001, 1, 102, 8, 0, 1, '主さま…\\nだ、誰も聞いてない\\nわよね！？', 0);
insert into room_unit_comments values (2058, 106001, 2, 1, 1, 0, 1, '気まぐれは\\nチャームポイント\\nみたいなもんよ', 0);
insert into room_unit_comments values (2059, 106001, 2, 2, 1, 0, 1, 'うひゃっ！？\\nど、どうしてあんたは\\nいつも驚かせるのよ！', 0);
insert into room_unit_comments values (2060, 106001, 2, 3, 1, 0, 1, 'ぎゃー！\\n虫もって近づくなー！', 0);
insert into room_unit_comments values (2061, 106001, 2, 4, 1, 0, 1, 'この部屋って、\\n野良猫を拾ってきたら\\nだめかな？', 0);
insert into room_unit_comments values (2062, 106001, 2, 101, 4, 0, 1, '遊びにいくわよ！\\nあんたはあたしの\\n言うとおりにすれば\\nいいの♪', 0);
insert into room_unit_comments values (2063, 106001, 2, 102, 8, 0, 1, 'あんた、あたしに\\n操られてみない？', 0);
insert into room_unit_comments values (2064, 106001, 2, 1, 1, 1, 1, '美食殿としては、\\n朝食もこだわらないと\\nねぇ～', 0);
insert into room_unit_comments values (2065, 106001, 2, 2, 1, 2, 1, 'ギルド活動だもん！\\n美味しいランチを\\n食べましょ♪', 0);
insert into room_unit_comments values (2066, 106001, 2, 3, 1, 3, 1, 'ディナーに行くわよ！\\nギルドの目的、\\n食べ歩きだもんね♪', 0);
insert into room_unit_comments values (2067, 106001, 3, 1, 1, 0, 1, '今日もしっぽが\\nいい感じ♪', 0);
insert into room_unit_comments values (2068, 106001, 3, 2, 1, 0, 1, 'こういう所だと、\\n丸くなっちゃうのよね\\nうにゃぁ～～', 0);
insert into room_unit_comments values (2069, 106001, 3, 3, 1, 0, 1, 'これ、あたしの能力で\\n操れないかな？', 0);
insert into room_unit_comments values (2070, 106001, 3, 4, 1, 0, 1, 'うにゃぁ～♪\\nにゃん、にゃお～ん♪', 0);
insert into room_unit_comments values (2071, 106001, 3, 5, 1, 0, 1, 'はぁ～ゴロゴロ\\nしたくなるわね', 0);
insert into room_unit_comments values (2072, 106001, 3, 6, 1, 0, 1, '特訓特訓！\\nあたしは\\nやればできる！', 0);
insert into room_unit_comments values (2073, 106001, 3, 7, 1, 0, 1, 'おいしいものを\\nたくさん食べる…\\nギルド活動って\\n楽しい～♪', 0);
insert into room_unit_comments values (2074, 106001, 3, 8, 1, 0, 1, '魔法を使うにも、\\n知識が必要だものね', 0);
insert into room_unit_comments values (2076, 106002, 1, 1, 1, 0, 1, 'ま、まずいわ…\\nギルド活動\\nけっこう楽しい♪', 0);
insert into room_unit_comments values (2077, 106002, 1, 2, 1, 0, 1, 'いろいろ美味しいもの\\n食べられるし…\\nけっこう幸せかも', 0);
insert into room_unit_comments values (2078, 106002, 1, 3, 1, 0, 1, '主さま…\\nだ、誰も聞いてない\\nわよね！？', 0);
insert into room_unit_comments values (2079, 106002, 1, 4, 1, 0, 1, '監視監視…\\nうん！\u3000あたしは\\nなまけてないわよね', 0);
insert into room_unit_comments values (2080, 106002, 1, 5, 1, 0, 1, 'へ、陛下に\\nみつからないように\\nしなくっちゃ…', 0);
insert into room_unit_comments values (2081, 106002, 1, 101, 8, 0, 1, 'あいつが来たら、\\n尾行しなくちゃ♪', 0);
insert into room_unit_comments values (2082, 106002, 1, 102, 8, 0, 1, 'あいつと会ってから\\n調子くるったな…\\n楽しいけどさ', 0);
insert into room_unit_comments values (2083, 106002, 2, 1, 1, 0, 1, '食わず嫌いって\\nあるのよね\\n食べ物もだけど\\n人も…', 0);
insert into room_unit_comments values (2084, 106002, 2, 2, 1, 0, 1, 'うひゃっ！？\\nど、どうしてあんたは\\nいつも驚かせるのよ！', 0);
insert into room_unit_comments values (2085, 106002, 2, 3, 1, 0, 1, '話し相手になって\\nやるわよ…情報\\n聞き出せるかもだし', 0);
insert into room_unit_comments values (2086, 106002, 2, 4, 1, 0, 1, 'この部屋って\\n野良猫を拾ってきたら\\nだめかな？', 0);
insert into room_unit_comments values (2087, 106002, 2, 101, 8, 0, 1, '遊びにいくわよ！\\nあんたはあたしの\\n言うとおりにすれば\\nいいの♪', 0);
insert into room_unit_comments values (2088, 106002, 2, 102, 8, 0, 1, 'あんた、あたしに\\n操られてみない？', 0);
insert into room_unit_comments values (2089, 106002, 2, 1, 1, 1, 1, '美食殿としては\\n朝食もこだわらないと\\nねぇ～', 0);
insert into room_unit_comments values (2090, 106002, 2, 2, 1, 2, 1, 'ギルド活動だもん！\\n美味しいランチを\\n食べましょ♪', 0);
insert into room_unit_comments values (2091, 106002, 2, 3, 1, 3, 1, 'ディナーに行くわよ！\\nギルドの目的\\n食べ歩きだもんね♪', 0);
insert into room_unit_comments values (2092, 106002, 3, 1, 1, 0, 1, '今日もしっぽが\\nいい感じ♪', 0);
insert into room_unit_comments values (2093, 106002, 3, 2, 1, 0, 1, 'うにゃ～\\nどんどん眠く\\nなる～', 0);
insert into room_unit_comments values (2094, 106002, 3, 3, 1, 0, 1, 'これ、あたしの能力で\\n操れないかな？', 0);
insert into room_unit_comments values (2095, 106002, 3, 4, 1, 0, 1, 'あたし、みんなや\\nあいつと同じ香りを\\n身に着けてるんだ…', 0);
insert into room_unit_comments values (2096, 106002, 3, 5, 1, 0, 1, 'うっ、のんびり\\nしたくなる…\\n特訓しなきゃ\\nいけないのに～', 0);
insert into room_unit_comments values (2097, 106002, 3, 6, 1, 0, 1, '特訓特訓！\\nあたしは\\nやればできる！', 0);
insert into room_unit_comments values (2098, 106002, 3, 7, 1, 0, 1, 'おいしいものを\\nたくさん食べる…\\nギルド活動って\\n楽しい～♪', 0);
insert into room_unit_comments values (2099, 106002, 3, 8, 1, 0, 1, '魔法を使うにも\\n知識が必要だものね', 0);
insert into room_unit_comments values (2101, 105901, 1, 1, 1, 0, 1, 'この空間は主さまの\\n香りがします\\n…ふふふ♪', 0);
insert into room_unit_comments values (2102, 105901, 1, 2, 1, 0, 1, '炊事、洗濯、お掃除、\\nお買いものもしなくて\\nはいけませんね', 0);
insert into room_unit_comments values (2103, 105901, 1, 3, 1, 0, 1, 'アメスさまへの、\\nお祈りができそうな\\n場所は…', 0);
insert into room_unit_comments values (2104, 105901, 1, 4, 1, 0, 1, 'さすが都会…\\nおいしいものが\\nたくさんあるのですね', 0);
insert into room_unit_comments values (2105, 105901, 1, 5, 1, 0, 1, '主さまが不自由なく\\n使える部屋に\\nしなくては…', 0);
insert into room_unit_comments values (2106, 105901, 1, 101, 4, 0, 1, 'できるなら…\\n主さまと二人だけの\\n部屋の方が…', 0);
insert into room_unit_comments values (2107, 105901, 1, 102, 8, 0, 1, '主さまの隣には\\nわたくしが…\\nわたくしの隣には、\\n主さまが…幸せです', 0);
insert into room_unit_comments values (2108, 105901, 2, 1, 1, 0, 1, 'わたくし、背が伸び\\nましたでしょうか？\\n…そうですか', 0);
insert into room_unit_comments values (2109, 105901, 2, 2, 1, 0, 1, 'もしお疲れでしたら\\n肩でも\\nお揉みしましょうか？', 0);
insert into room_unit_comments values (2110, 105901, 2, 3, 1, 0, 1, '主さま、なにか\\nしてほしいことは\\nありませんか？\\n欲しいものは？', 0);
insert into room_unit_comments values (2111, 105901, 2, 4, 1, 0, 1, '今日のおこづかいです\\n何かおいしいものを\\n召し上がってください', 0);
insert into room_unit_comments values (2112, 105901, 2, 101, 4, 0, 1, '主さまのおてて\\n温かいですね…♪', 0);
insert into room_unit_comments values (2113, 105901, 2, 102, 8, 0, 1, '主さまのおそばに\\nいられて、わたくし、\\n嬉しいです…', 0);
insert into room_unit_comments values (2114, 105901, 2, 1, 1, 1, 1, 'おはようございます。\\n洗濯をしなければ…', 0);
insert into room_unit_comments values (2115, 105901, 2, 2, 1, 2, 1, 'そろそろお昼ですね。\\nおいしいものを\\n食べましょう', 0);
insert into room_unit_comments values (2116, 105901, 2, 3, 1, 3, 1, 'おやすみになる時は、\\nお声をかけてください\\nお供致します', 0);
insert into room_unit_comments values (2117, 105901, 3, 1, 1, 0, 1, 'もう少し…\\nおっきくなりたい\\nです', 0);
insert into room_unit_comments values (2118, 105901, 3, 2, 1, 0, 1, 'このふかふかの優しさ\\n主さまのようです', 0);
insert into room_unit_comments values (2119, 105901, 3, 3, 1, 0, 1, 'かわいい♪\\n主さまにそっくり♪', 0);
insert into room_unit_comments values (2120, 105901, 3, 4, 1, 0, 1, '故郷の香りとは\\n違いますが、これも\\n心地よいものです…', 0);
insert into room_unit_comments values (2121, 105901, 3, 5, 1, 0, 1, 'ここで洗濯物を\\n乾かせるでしょうか', 0);
insert into room_unit_comments values (2122, 105901, 3, 6, 1, 0, 1, '都会の人々は\\nこんなふうに\\n運動を…！？', 0);
insert into room_unit_comments values (2123, 105901, 3, 7, 1, 0, 1, 'これは…主さまにも\\n食べさせて\\n差し上げたい…\\nあーんって♪', 0);
insert into room_unit_comments values (2124, 105901, 3, 8, 1, 0, 1, 'よく学んで、\\n主さまのお役に\\n立たなければ', 0);
insert into room_unit_comments values (2126, 105902, 1, 1, 1, 0, 1, '主さまがいつ戻って\\n来ても平気なよう\\n部屋を綺麗に保たねば', 0);
insert into room_unit_comments values (2127, 105902, 1, 2, 1, 0, 1, '節約のためにも\\n自家菜園などするのは\\nどうでしょう…\u3000', 0);
insert into room_unit_comments values (2128, 105902, 1, 3, 1, 0, 1, 'アメスさまへの\\nお祈りができそうな\\n場所は…', 0);
insert into room_unit_comments values (2129, 105902, 1, 4, 1, 0, 1, '瞑想をすると\\n心が安らぎます…', 0);
insert into room_unit_comments values (2130, 105902, 1, 5, 1, 0, 1, '都会の方の身なりを\\n勉強した方が\\n良いのでしょうか？', 0);
insert into room_unit_comments values (2131, 105902, 1, 101, 8, 0, 1, 'わたくしの居場所は\\n主さまのお傍です\\nずっと、ずっと…♪', 0);
insert into room_unit_comments values (2132, 105902, 1, 102, 8, 0, 1, '主さまの隣には\\nわたくしが…\\nわたくしの隣には\\n主さまが…幸せです', 0);
insert into room_unit_comments values (2133, 105902, 2, 1, 1, 0, 1, '主さま、なにか\\nしてほしいことは\\nありませんか？\\n欲しいものは？', 0);
insert into room_unit_comments values (2134, 105902, 2, 2, 1, 0, 1, 'わたくし、背が伸び\\nましたでしょうか？\\n…そうですか', 0);
insert into room_unit_comments values (2135, 105902, 2, 3, 1, 0, 1, 'お出かけですか？\\nわたくしもお供\\nいたします', 0);
insert into room_unit_comments values (2136, 105902, 2, 4, 1, 0, 1, 'ひゃん！\\n主さま…\\nいじわるです', 0);
insert into room_unit_comments values (2137, 105902, 2, 101, 8, 0, 1, '主さま、なにか御用は\\nありませんか？\\nわたくし、主さまの\\nお役にたちたいのです', 0);
insert into room_unit_comments values (2138, 105902, 2, 102, 8, 0, 1, '主さまの優しさに\\nわたくしはいつも\\n癒されています…', 0);
insert into room_unit_comments values (2139, 105902, 2, 1, 1, 1, 1, 'おはようございます♪\\n主さまの可愛らしい\\n寝顔、堪能致しました', 0);
insert into room_unit_comments values (2140, 105902, 2, 2, 1, 2, 1, 'のんびりした時間帯\\nですね…ふぁ～…\\nし、失礼致しました', 0);
insert into room_unit_comments values (2141, 105902, 2, 3, 1, 3, 1, 'ふむ、都会は夜でも\\nこんなにも、にぎやか\\nなのですね', 0);
insert into room_unit_comments values (2142, 105902, 3, 1, 1, 0, 1, '主さまに会う前に\\n身なりを整えなくては\\nいけませんね', 0);
insert into room_unit_comments values (2143, 105902, 3, 2, 1, 0, 1, 'このふかふかの優しさ\\n主さまのようです', 0);
insert into room_unit_comments values (2144, 105902, 3, 3, 1, 0, 1, 'かわいい♪\\n主さまにそっくり♪', 0);
insert into room_unit_comments values (2145, 105902, 3, 4, 1, 0, 1, 'この心地よさ…\\n主さまのようです♪', 0);
insert into room_unit_comments values (2146, 105902, 3, 5, 1, 0, 1, 'ここで洗濯物を\\n乾かせるでしょうか\u3000', 0);
insert into room_unit_comments values (2147, 105902, 3, 6, 1, 0, 1, 'はぁっはぁっはぁっ\\n…すべては\\n主さまのため…', 0);
insert into room_unit_comments values (2148, 105902, 3, 7, 1, 0, 1, '都会の味…\\nとてもおいしいです\\n…もぐもぐもぐ', 0);
insert into room_unit_comments values (2149, 105902, 3, 8, 1, 0, 1, '都会のことを\\n学ばないと…\\nふむふむ', 0);
insert into room_unit_comments values (2151, 190801, 2, 1, 1, 0, 1, 'ふぁ～…あっ\\n見られちゃい\\nましたか？', 0);
insert into room_unit_comments values (2152, 190801, 2, 2, 1, 0, 1, 'ギルドハウスの\\n使い心地は\\nどうですか？', 0);
insert into room_unit_comments values (2153, 190801, 2, 3, 1, 0, 1, 'ご用があれば\\nなんでも言って\\nくださいね～♪', 0);
insert into room_unit_comments values (2154, 190801, 2, 4, 1, 0, 1, 'ときどきみなさんと\\nクエストに行きたいな\\nって思っちゃいます', 0);
insert into room_unit_comments values (2155, 190801, 2, 1, 1, 1, 1, 'おはようございます！\\nお掃除の方、\\nはじめていきますね', 0);
insert into room_unit_comments values (2156, 190801, 2, 2, 1, 2, 1, '皆さん、お昼ごはんの\\nご要望がありましたら\\n用意致しますよ♪', 0);
insert into room_unit_comments values (2157, 190801, 2, 3, 1, 3, 1, 'ここは夜でも\\nにぎやかですね', 0);
insert into room_unit_comments values (2158, 104701, 1, 1, 1, 0, 1, '…\\n少しうとうと\\nしてしまった', 0);
insert into room_unit_comments values (2159, 104701, 1, 2, 1, 0, 1, '室内だし兜を脱ぐか\\n…いや\\nやはりやめておこう', 0);
insert into room_unit_comments values (2160, 104701, 1, 3, 1, 0, 1, '部屋にいると\\n鎧が蒸し暑くなるが\\n我慢せねば…', 0);
insert into room_unit_comments values (2161, 104701, 1, 4, 1, 0, 1, '仕事が門番だからか\\n部屋にいても\\nじっとしてしまう…', 0);
insert into room_unit_comments values (2162, 104701, 1, 5, 1, 0, 1, '少年と会話したことを\\n思いだすと\\n自然と楽しくなるな', 0);
insert into room_unit_comments values (2163, 104701, 1, 101, 4, 0, 1, '少年のことを考えると\\n顔がにやけてしまう', 0);
insert into room_unit_comments values (2164, 104701, 1, 102, 8, 0, 1, '少年は今頃\\n平和に過ごせて\\nいるかな…', 0);
insert into room_unit_comments values (2165, 104701, 2, 1, 1, 0, 1, 'ん？\u3000悪いが\\n兜は脱がないぞ', 0);
insert into room_unit_comments values (2166, 104701, 2, 2, 1, 0, 1, '私と遊びたいのか？\\nそう言われても\\n何をしていいやら…', 0);
insert into room_unit_comments values (2167, 104701, 2, 3, 1, 0, 1, '鎧が重くないかって？\\n大丈夫。けっこう\\n鍛えているからな', 0);
insert into room_unit_comments values (2168, 104701, 2, 4, 1, 0, 1, '少年、寒くはないか？\\nいや自分がこうなので\\n人が薄着に見えてね', 0);
insert into room_unit_comments values (2169, 104701, 2, 101, 4, 0, 1, '君といると、兜の中が\\nいつもより暑いんだ', 0);
insert into room_unit_comments values (2170, 104701, 2, 102, 8, 0, 1, '私としゃべりたい？\\n物好きだな\\nでも、嬉しいよ', 0);
insert into room_unit_comments values (2171, 104701, 2, 1, 1, 1, 1, '早いな少年\\nえ？\u3000私の仕事に\\n合わせてくれたのか', 0);
insert into room_unit_comments values (2172, 104701, 2, 2, 1, 2, 1, '昼食の誘い？\\n嬉しいけど\\n人前では食べないんだ', 0);
insert into room_unit_comments values (2173, 104701, 2, 3, 1, 3, 1, '王宮騎士団の\\n日報を書かなければ…\\n『何事もなし』、と', 0);
insert into room_unit_comments values (2175, 104701, 3, 2, 1, 0, 1, '鎧を着ているから\\n感触が分かりづらい\\nのが残念だ…', 0);
insert into room_unit_comments values (2176, 104701, 3, 3, 1, 0, 1, 'か、かわいいな…\\n私には似合わないが\\nぎゅ…ってしよう', 0);
insert into room_unit_comments values (2177, 104701, 3, 4, 1, 0, 1, '良い香りだ…\\n普段はどうしても\\n鉄くさくなるからな', 0);
insert into room_unit_comments values (2178, 104701, 3, 5, 1, 0, 1, 'わかっていたけど\\n鎧を着たまま暖炉に\\nあたると暑い…', 0);
insert into room_unit_comments values (2180, 104701, 3, 7, 1, 0, 1, '兜を脱がずに食べる\\nうん、段々コツが\\n掴めてきた…', 0);
insert into room_unit_comments values (2181, 104701, 3, 8, 1, 0, 1, '兜があっても\\n意外と本くらいは\\n難なく読めるんだ', 0);
insert into room_unit_comments values (2183, 102601, 1, 1, 1, 0, 1, '居心地よくて\\nゴロゴロしちゃうよ～\\n…いつも通りだね', 0);
insert into room_unit_comments values (2184, 102601, 1, 2, 1, 0, 1, 'ドングリの木\\n近くに生えてない？', 0);
insert into room_unit_comments values (2185, 102601, 1, 3, 1, 0, 1, '快適な寝床があれば\\nそれだけで幸せだねぇ', 0);
insert into room_unit_comments values (2186, 102601, 1, 4, 1, 0, 1, 'あたしと一緒に\\nだらけてくれる人が\\nいそうだねぇ', 0);
insert into room_unit_comments values (2187, 102601, 1, 5, 1, 0, 1, 'ここなら牧場よりも\\n速く配達が\\n届きそうだね～', 0);
insert into room_unit_comments values (2188, 102601, 1, 101, 4, 0, 1, 'あんパン買ったし\\nあいつにも\\n分けてあげよう', 0);
insert into room_unit_comments values (2189, 102601, 1, 102, 8, 0, 1, 'あいつと一緒に\\nだらけられたら\\n最高に幸せだね', 0);
insert into room_unit_comments values (2190, 102601, 2, 1, 1, 0, 1, 'ドングリでも\\nつまみながら\\n一緒にゲームしようよ', 0);
insert into room_unit_comments values (2191, 102601, 2, 2, 1, 0, 1, '横になりたいから\\n枕になっておくれよ～\\nあんたあったかいしさ', 0);
insert into room_unit_comments values (2192, 102601, 2, 3, 1, 0, 1, 'ドングリあげるから\\nあんパン買ってきて～', 0);
insert into room_unit_comments values (2193, 102601, 2, 4, 1, 0, 1, 'う～\\n疲れちゃったよ～\\nおんぶして運んで～', 0);
insert into room_unit_comments values (2194, 102601, 2, 101, 4, 0, 1, 'あんたといると\\nリア充って\\n感じがするよ', 0);
insert into room_unit_comments values (2195, 102601, 2, 102, 8, 0, 1, 'あんたが一生\\n世話してくれたら\\n人生安泰なんだけどね', 0);
insert into room_unit_comments values (2196, 102601, 2, 1, 1, 1, 1, 'ふわ～っ…\\nおはよう…あたしは\\nまだ眠いよ', 0);
insert into room_unit_comments values (2197, 102601, 2, 2, 1, 2, 1, 'そろそろお昼寝でも\\nしたい気分だねぇ', 0);
insert into room_unit_comments values (2198, 102601, 2, 3, 1, 3, 1, '徹夜でゲームするけど\\nあんたもどうだい？\\nあたしは強いよ', 0);
insert into room_unit_comments values (2200, 102601, 3, 2, 1, 0, 1, 'あ…だめだこれ。\\n気持ち良くて\\n落ちそう…', 0);
insert into room_unit_comments values (2201, 102601, 3, 3, 1, 0, 1, 'かわいいものに\\n囲まれて寝るのも\\nよさそうだねぇ…', 0);
insert into room_unit_comments values (2202, 102601, 3, 4, 1, 0, 1, '心身ともに\\nリラックスした状態で\\nぐうたら出来そうだね', 0);
insert into room_unit_comments values (2203, 102601, 3, 5, 1, 0, 1, 'ふい～…\\nごくらくごくらく…\\n暖かいねぇ', 0);
insert into room_unit_comments values (2205, 102601, 3, 7, 1, 0, 1, '食べてすぐ寝ると\\n牛になるって\\n本当なのかな？', 0);
insert into room_unit_comments values (2206, 102601, 3, 8, 1, 0, 1, 'おー！\u3000この本なら\\nあたしも居眠りせずに\\n読めそうだよ', 0);
insert into room_unit_comments values (2208, 106301, 1, 1, 1, 0, 1, 'ランドソル…\\nおっきな街だなぁ…', 0);
insert into room_unit_comments values (2209, 106301, 1, 2, 1, 0, 1, 'ロザリア…\\nきっと、いるよね？', 0);
insert into room_unit_comments values (2210, 106301, 1, 3, 1, 0, 1, '最近、弓の練習\\nサボっちゃってるな…', 0);
insert into room_unit_comments values (2211, 106301, 1, 4, 1, 0, 1, '今日の私は\\n森番じゃなくて\\n家番だよ！', 0);
insert into room_unit_comments values (2212, 106301, 1, 5, 1, 0, 1, 'ちょっとだけ\\n慣れてきたかも？', 0);
insert into room_unit_comments values (2213, 106301, 1, 101, 4, 0, 1, 'いつか、\\nあの人と一緒に…', 0);
insert into room_unit_comments values (2214, 106301, 1, 102, 8, 0, 1, '…なんか最近、\\nあの人のこと\\nばっかり…', 0);
insert into room_unit_comments values (2215, 106301, 2, 1, 1, 0, 1, 'もしよかったら\\n街に出かけない？', 0);
insert into room_unit_comments values (2216, 106301, 2, 2, 1, 0, 1, 'この部屋、\\n妖精さんも\\n気に入るかも！', 0);
insert into room_unit_comments values (2217, 106301, 2, 3, 1, 0, 1, '今日は\\nなににしよっか？', 0);
insert into room_unit_comments values (2218, 106301, 2, 4, 1, 0, 1, '今日はどこ行く？', 0);
insert into room_unit_comments values (2219, 106301, 2, 101, 4, 0, 1, 'たまには二人で…\\nな、なんちゃって！', 0);
insert into room_unit_comments values (2220, 106301, 2, 102, 8, 0, 1, '最近、\\nずっと楽しいんだ！\\nあなたのおかげかな', 0);
insert into room_unit_comments values (2221, 106301, 2, 1, 1, 1, 1, 'おはよう！\\n今日も一緒に\\n頑張ろうね！', 0);
insert into room_unit_comments values (2222, 106301, 2, 2, 1, 2, 1, 'お昼はどうする？\\nあなたのオススメに\\n連れて行って欲しいな', 0);
insert into room_unit_comments values (2223, 106301, 2, 3, 1, 3, 1, 'ランドソルは\\n夜でも賑やかだね！', 0);
insert into room_unit_comments values (2225, 106301, 3, 2, 1, 0, 1, 'わぁっ！\\nすっごく\\nふわふわだよ！', 0);
insert into room_unit_comments values (2226, 106301, 3, 3, 1, 0, 1, 'かわい～！\\nぎゅってしたく\\nなっちゃうかも！', 0);
insert into room_unit_comments values (2227, 106301, 3, 4, 1, 0, 1, 'くんくん\\nなんか…いい匂い？', 0);
insert into room_unit_comments values (2228, 106301, 3, 5, 1, 0, 1, 'すっごいなー\\nあったかいなー！', 0);
insert into room_unit_comments values (2230, 106301, 3, 7, 1, 0, 1, 'わぁっ、おいしい！\\nもっと食べたい\\nかも…！', 0);
insert into room_unit_comments values (2231, 106301, 3, 8, 1, 0, 1, 'も、文字は苦手…\\nでも、頑張らないと\\nだよね…！', 0);
insert into room_unit_comments values (2233, 103601, 1, 1, 1, 0, 1, 'にんじんとピーマンを\\n食べないでいい方法\\nないかな…', 0);
insert into room_unit_comments values (2234, 103601, 1, 2, 1, 0, 1, 'カップケーキが\\n食べたいな…', 0);
insert into room_unit_comments values (2235, 103601, 1, 3, 1, 0, 1, '予習が終わりました！\\nさて、次は復習を\\nしないと…', 0);
insert into room_unit_comments values (2236, 103601, 1, 4, 1, 0, 1, 'あの人の部屋にいる\\n私って…もしかして\\nふしんしゃなんじゃ？', 0);
insert into room_unit_comments values (2237, 103601, 1, 5, 1, 0, 1, '男の人は、みんな\\nへんたいだと\\n聞きました…', 0);
insert into room_unit_comments values (2238, 103601, 1, 101, 4, 0, 1, 'あの人に、一緒に\\n遊んでほしいけど…\\nな、なんていえば？', 0);
insert into room_unit_comments values (2239, 103601, 1, 102, 8, 0, 1, '早く大人になりたいな\\n…あの人と同じくらい', 0);
insert into room_unit_comments values (2240, 103601, 2, 1, 1, 0, 1, 'ぼ、防犯魔石を\\n鳴らしますよ！？', 0);
insert into room_unit_comments values (2241, 103601, 2, 2, 1, 0, 1, 'へんたい！？\u3000…\\nあ、あなたでしたか～\\nやっぱりへんたーい！', 0);
insert into room_unit_comments values (2242, 103601, 2, 3, 1, 0, 1, 'これ宿題です\\nやっておいて\\nくださいね', 0);
insert into room_unit_comments values (2243, 103601, 2, 4, 1, 0, 1, 'あ、遅刻ですよ\\n待っていたんですから', 0);
insert into room_unit_comments values (2244, 103601, 2, 101, 4, 0, 1, 'にらめっこですか？\\nあ、あなたの前で変顔\\nするのはちょっと…', 0);
insert into room_unit_comments values (2245, 103601, 2, 102, 8, 0, 1, 'あの…何歳まで\\n子供だと思いますか？', 0);
insert into room_unit_comments values (2246, 103601, 2, 1, 1, 1, 1, '顔を洗って、着替えて\\n朝ごはんを食べて、\\n歯を磨いて…', 0);
insert into room_unit_comments values (2247, 103601, 2, 2, 1, 2, 1, 'て、鉄棒の練習！？\u3000\\nほ、他のことを\\nしませんか？', 0);
insert into room_unit_comments values (2248, 103601, 2, 3, 1, 3, 1, 'ね、眠くないです\\n子供ではありません\\nから…ふわぁ', 0);
insert into room_unit_comments values (2250, 103601, 3, 2, 1, 0, 1, 'ひと休みしよっと\\n………うん、\\nひと休みおしまい♪', 0);
insert into room_unit_comments values (2251, 103601, 3, 3, 1, 0, 1, 'つ、つぶらな瞳には\\n弱いんです', 0);
insert into room_unit_comments values (2252, 103601, 3, 4, 1, 0, 1, 'リラックスできますね\\n集中力も\\n上がりそうです', 0);
insert into room_unit_comments values (2253, 103601, 3, 5, 1, 0, 1, 'あったかいと\\n眠くなっちゃうな…\\n勉強しなくちゃなのに', 0);
insert into room_unit_comments values (2255, 103601, 3, 7, 1, 0, 1, 'ピーマンもこれくらい\\nおいしければ\\nいいのに…', 0);
insert into room_unit_comments values (2256, 103601, 3, 8, 1, 0, 1, 'この本、むずかしい\\n…もっと勉強\\nがんばらなくちゃ', 0);
insert into room_unit_comments values (2258, 101501, 1, 1, 1, 0, 1, '今日はみんなに\\nなにを読んで\\nあげようかしら', 0);
insert into room_unit_comments values (2259, 101501, 1, 2, 1, 0, 1, '子どもたちと同じ\\n目線で考えるのが\\n大事よね', 0);
insert into room_unit_comments values (2260, 101501, 1, 3, 1, 0, 1, 'お天気が良い日は\\nみんなでお散歩に\\n行きたいわね～', 0);
insert into room_unit_comments values (2261, 101501, 1, 4, 1, 0, 1, '鬼ごっこにかくれんぼ\\n…みんなは\\nどっちが好きかしら', 0);
insert into room_unit_comments values (2262, 101501, 1, 5, 1, 0, 1, 'お遊戯会の配役、\\n考え出すと\\n大変だわ～', 0);
insert into room_unit_comments values (2263, 101501, 1, 101, 4, 0, 1, '彼は優しいから、\\nきっと良い\\nお父さんになるわね', 0);
insert into room_unit_comments values (2264, 101501, 1, 102, 8, 0, 1, '彼には私がいないと\\n…っていうのは少し\\n過保護すぎるかしら？', 0);
insert into room_unit_comments values (2265, 101501, 2, 1, 1, 0, 1, '保育園の行事を\\n考えてるんだけど…\\n良い案ないかしら？', 0);
insert into room_unit_comments values (2266, 101501, 2, 2, 1, 0, 1, '今度、子どもたちと\\nおやつを作るから、\\n食べに来てね', 0);
insert into room_unit_comments values (2267, 101501, 2, 3, 1, 0, 1, 'よかったら一緒に\\n絵本を作らない？', 0);
insert into room_unit_comments values (2268, 101501, 2, 4, 1, 0, 1, 'あなたはいつも元気ね\\n先生も見習わないと♪', 0);
insert into room_unit_comments values (2269, 101501, 2, 101, 4, 0, 1, '先生は\\nずーっと、ずーっと、\\nあなたの味方だからね', 0);
insert into room_unit_comments values (2270, 101501, 2, 102, 8, 0, 1, 'あなたみたいな\\nいい子をお世話できて\\n先生は幸せものだわ', 0);
insert into room_unit_comments values (2271, 101501, 2, 1, 1, 1, 1, 'おはよう～\\nちゃんと朝ごはんは\\n食べた？', 0);
insert into room_unit_comments values (2272, 101501, 2, 2, 1, 2, 1, 'お昼寝の時間ね♪\\nあなたも一緒に\\n寝ましょうか', 0);
insert into room_unit_comments values (2273, 101501, 2, 3, 1, 3, 1, 'すっかり真っ暗ね。\\n今日も一日、\\nよくできました♪', 0);
insert into room_unit_comments values (2275, 101501, 3, 2, 1, 0, 1, 'ふかふかねぇ♪\\n年甲斐もなく、\\n飛び跳ねちゃいそう', 0);
insert into room_unit_comments values (2276, 101501, 3, 3, 1, 0, 1, 'あらあら、かわいい！\\n保育園のみんなに\\n見せてあげたいわ', 0);
insert into room_unit_comments values (2277, 101501, 3, 4, 1, 0, 1, 'いい香りね～\\n保育園にも\\n置こうかしら', 0);
insert into room_unit_comments values (2278, 101501, 3, 5, 1, 0, 1, '寒い日は、ここで\\n子どもたちに絵本を\\n読んであげましょ♪', 0);
insert into room_unit_comments values (2280, 101501, 3, 7, 1, 0, 1, '美味しい～♪\\n遠足に持っていったら\\nみんな喜びそう', 0);
insert into room_unit_comments values (2281, 101501, 3, 8, 1, 0, 1, 'みんなが\\n楽しめる読み聞かせの\\n方法特集♪\u3000素敵ねぇ', 0);
insert into room_unit_comments values (2283, 104401, 1, 1, 1, 0, 1, '世界の前に、\\nこの部屋を征服\\nしてやろう♪', 0);
insert into room_unit_comments values (2284, 104401, 1, 2, 1, 0, 1, '拠点とはやはり\\n斯くあるべきじゃの', 0);
insert into room_unit_comments values (2285, 104401, 1, 3, 1, 0, 1, '眷属の物はわらわの物\\n故に、この部屋は\\nわらわの部屋じゃな！', 0);
insert into room_unit_comments values (2286, 104401, 1, 4, 1, 0, 1, '永く眠っている間に\\n随分と世界は変わった\\nようじゃな…', 0);
insert into room_unit_comments values (2287, 104401, 1, 5, 1, 0, 1, 'うるさいのう～\\nまったく、近頃の\\n若いもんは…', 0);
insert into room_unit_comments values (2288, 104401, 1, 101, 4, 0, 1, 'あやつが来てから\\n動悸が治まらぬ…\\n如何ような病で\\nあろうかの…', 0);
insert into room_unit_comments values (2289, 104401, 1, 102, 8, 0, 1, '眷属よ、どこに行った\\nのじゃ？\\nわらわの世話を\\n許可するのじゃ', 0);
insert into room_unit_comments values (2290, 104401, 2, 1, 1, 0, 1, 'いずれ世界は\\n我が手中に収まる\\nふふふ、\\n楽しみじゃのう', 0);
insert into room_unit_comments values (2291, 104401, 2, 2, 1, 0, 1, '眷属よ、わらわから\\n離れてはならんぞ！\\n子供に戻ってしまう\\nではないか！', 0);
insert into room_unit_comments values (2292, 104401, 2, 3, 1, 0, 1, 'トマトジュースが\\n欲しいのじゃ！\\n野菜ジュースでは\\nダメだぞ！', 0);
insert into room_unit_comments values (2293, 104401, 2, 4, 1, 0, 1, '蚊にくわれたぞ！\\nわらわの血を吸う\\nとは～！', 0);
insert into room_unit_comments values (2294, 104401, 2, 101, 4, 0, 1, 'こら、頭をなでるな\\nお主はこの姿でも\\n子供扱いするのか？', 0);
insert into room_unit_comments values (2295, 104401, 2, 102, 8, 0, 1, 'お主が望むなら世界の\\n半分をくれてやっても\\n良いのじゃぞ？', 0);
insert into room_unit_comments values (2296, 104401, 2, 1, 1, 1, 1, '朝早くから感心じゃの\\nさすがわらわの\\n眷属じゃ', 0);
insert into room_unit_comments values (2297, 104401, 2, 2, 1, 2, 1, '太陽は苦手じゃ…\\nこの部屋の中で\\n過ごそうぞ', 0);
insert into room_unit_comments values (2298, 104401, 2, 3, 1, 3, 1, '夜も更けてきた！\\nわらわ達の時間は\\nこれからじゃ～♪', 0);
insert into room_unit_comments values (2300, 104401, 3, 2, 1, 0, 1, 'よい座り心地じゃ\\nわらわの玉座としよう', 0);
insert into room_unit_comments values (2301, 104401, 3, 3, 1, 0, 1, '可愛いではないか\\nわらわの眷属に\\nしてやろうかのう', 0);
insert into room_unit_comments values (2302, 104401, 3, 4, 1, 0, 1, 'うむ、良い気持ちじゃ\\nこれを作った者、\\n褒めてつかわすぞ', 0);
insert into room_unit_comments values (2303, 104401, 3, 5, 1, 0, 1, 'あたたかい…\\n身も心も\\n浄化されるようじゃ', 0);
insert into room_unit_comments values (2305, 104401, 3, 7, 1, 0, 1, '吸血鬼のわらわが、\\nこのようなもの…\\nうまい♪', 0);
insert into room_unit_comments values (2306, 104401, 3, 8, 1, 0, 1, 'このまま大人の姿を\\n保つ方法…どこかに\\n書いてないかのう', 0);
insert into room_unit_comments values (2308, 105401, 1, 1, 1, 0, 1, 'いろんな人がいて\\nいろんな服を着てて…\\n目の保養になります♪', 0);
insert into room_unit_comments values (2309, 105401, 1, 2, 1, 0, 1, 'レイ様への新作\\nどんな服にしよう…\\n方向性が絞れない～！', 0);
insert into room_unit_comments values (2310, 105401, 1, 3, 1, 0, 1, '忘れないうちに\\n隠し糸のメンテナンス\\nやっておこうっと！', 0);
insert into room_unit_comments values (2311, 105401, 1, 4, 1, 0, 1, 'むっ！\u3000あの人の\\nスリーサイズは…\\nほほう…なるほど♪', 0);
insert into room_unit_comments values (2312, 105401, 1, 5, 1, 0, 1, 'ノゾミさんの\\n衣装はああして\\nチカさんのは…', 0);
insert into room_unit_comments values (2313, 105401, 1, 101, 4, 0, 1, '私がアイドル…\\n…実感ないけど\\n精一杯やってみよう', 0);
insert into room_unit_comments values (2314, 105401, 1, 102, 8, 0, 1, 'まさか私が\\nアイドルになるなんて\\n思ってなかったです', 0);
insert into room_unit_comments values (2315, 105401, 2, 1, 1, 0, 1, 'なんですかぁ？\\n衣装作りで疲れて\\n眠いんですぅ…', 0);
insert into room_unit_comments values (2316, 105401, 2, 2, 1, 0, 1, 'あーっ！\u3000また\\n服がほつれてる…\\nしょうがないですね', 0);
insert into room_unit_comments values (2317, 105401, 2, 3, 1, 0, 1, 'はっ！\u3000ちょうど今\\n新しいデザインが\\n思い浮かびました！', 0);
insert into room_unit_comments values (2318, 105401, 2, 4, 1, 0, 1, '暇そうですね？\\n時間あるなら仕事\\n手伝ってください！', 0);
insert into room_unit_comments values (2319, 105401, 2, 101, 4, 0, 1, 'どうしました？\\n新しい服が\\n欲しくなりましたか？', 0);
insert into room_unit_comments values (2320, 105401, 2, 102, 8, 0, 1, '騎士さんのおかげで\\nカルミナでも\\n頑張れてますよ！', 0);
insert into room_unit_comments values (2321, 105401, 2, 1, 1, 1, 1, 'おはようございます…\\nなんで朝って毎日\\nやってくるんでしょう', 0);
insert into room_unit_comments values (2322, 105401, 2, 2, 1, 2, 1, 'お腹空きましたね\\n騎士さんはちゃんと\\n御飯食べましたか？', 0);
insert into room_unit_comments values (2323, 105401, 2, 3, 1, 3, 1, '夜の方が\\n作業が捗るのは\\n私だけですかね？', 0);
insert into room_unit_comments values (2325, 105401, 3, 2, 1, 0, 1, 'このふかふか具合\\nいい素材を\\n使ってますね', 0);
insert into room_unit_comments values (2326, 105401, 3, 3, 1, 0, 1, '小さくて可愛い♪\\nそうだ！\u3000レイ様の\\nぬいぐるみを…！', 0);
insert into room_unit_comments values (2327, 105401, 3, 4, 1, 0, 1, 'こういう時くらい\\n何も考えずに\\nリラックスしないと♪', 0);
insert into room_unit_comments values (2328, 105401, 3, 5, 1, 0, 1, '炎を使った服って\\nカッコ良いかも…\\nでも材料がな～…', 0);
insert into room_unit_comments values (2330, 105401, 3, 7, 1, 0, 1, '何をするにも\\n食事は大切！\\n体力が資本です！', 0);
insert into room_unit_comments values (2331, 105401, 3, 8, 1, 0, 1, '私もいつか\\nデザインを\\nまとめて本に…', 0);
insert into room_unit_comments values (2333, 107501, 1, 1, 1, 0, 1, 'またお魚を\\n捕りにいこうかな♪', 0);
insert into room_unit_comments values (2334, 107501, 1, 2, 1, 0, 1, 'そろそろみんなも\\nお腹が空くころ\\nじゃないですか～？', 0);
insert into room_unit_comments values (2335, 107501, 1, 3, 1, 0, 1, 'ここなら、\\n日焼けの心配は\\nありませんね！', 0);
insert into room_unit_comments values (2336, 107501, 1, 4, 1, 0, 1, 'お刺身に焼き貝…\\nお腹が魚介類を\\n求めてますっ！', 0);
insert into room_unit_comments values (2337, 107501, 1, 5, 1, 0, 1, '泳ぐのも食べるのも\\n大得意です！', 0);
insert into room_unit_comments values (2338, 107501, 1, 101, 4, 0, 1, 'あの人と二人で\\n浜辺を散歩…\\n素敵ですねぇ', 0);
insert into room_unit_comments values (2339, 107501, 1, 102, 8, 0, 1, 'あの人に水着を\\n褒めてもらえたら、\\nすごく嬉しいなぁ', 0);
insert into room_unit_comments values (2340, 107501, 2, 1, 1, 0, 1, 'たまには釣りじゃなく\\n一緒に素潜りでも\\n行きませんか？', 0);
insert into room_unit_comments values (2341, 107501, 2, 2, 1, 0, 1, '男の子に水着を\\n見られるのって\\n少し緊張しちゃいます', 0);
insert into room_unit_comments values (2342, 107501, 2, 3, 1, 0, 1, 'ギルドハウスの\\nみんなとも、\\n海に行きたいですね！', 0);
insert into room_unit_comments values (2343, 107501, 2, 4, 1, 0, 1, 'あなたの水着、\\n私が選んであげます！', 0);
insert into room_unit_comments values (2344, 107501, 2, 101, 4, 0, 1, '泳ぎの練習なら\\n付き合いますよ！\\n手取り足取り♪', 0);
insert into room_unit_comments values (2345, 107501, 2, 102, 8, 0, 1, '水着姿が好きなら\\nいくらでも\\n着てあげますよぉ♪', 0);
insert into room_unit_comments values (2346, 107501, 2, 1, 1, 1, 1, '朝の海も\\n幻想的で\\nいいですよねぇ～！', 0);
insert into room_unit_comments values (2347, 107501, 2, 2, 1, 2, 1, 'お昼はみんなで、\\n海鮮バーベキューとか\\nどうでしょう！', 0);
insert into room_unit_comments values (2348, 107501, 2, 3, 1, 3, 1, '夜の海は星が\\nきれいですよ！\\n見に行きましょう！', 0);
insert into room_unit_comments values (2350, 107501, 3, 2, 1, 0, 1, '泳ぎ疲れたので\\nちょっと休憩です～', 0);
insert into room_unit_comments values (2351, 107501, 3, 3, 1, 0, 1, 'あなたにも、\\n可愛い水着を\\n着せてあげたいです', 0);
insert into room_unit_comments values (2352, 107501, 3, 4, 1, 0, 1, 'なんだか、\\nリゾート気分です…', 0);
insert into room_unit_comments values (2353, 107501, 3, 5, 1, 0, 1, 'ふい～、泳ぎで冷えた\\n身体を暖めましょう～', 0);
insert into room_unit_comments values (2355, 107501, 3, 7, 1, 0, 1, 'おいひ～です～\\nこれ、海水浴にも\\n持っていきたいですね', 0);
insert into room_unit_comments values (2356, 107501, 3, 8, 1, 0, 1, '南国のフルーツ図鑑\\n…じゅるり…', 0);
insert into room_unit_comments values (2358, 107501, 3, 10, 1, 0, 1, 'わ～♪\u3000おいしそ…\\nか、かわいいですね～', 0);
insert into room_unit_comments values (2359, 107501, 3, 11, 1, 0, 1, 'これくらい大きな貝…\\n食べたいな～\\n食べたいな～～', 0);
insert into room_unit_comments values (2360, 107601, 1, 1, 1, 0, 1, 'この格好で\\n部屋をうろつくのは\\n不思議な感じがします', 0);
insert into room_unit_comments values (2361, 107601, 1, 2, 1, 0, 1, '南国の果実を使って\\n主さまにデザートを\\nお作りしましょう', 0);
insert into room_unit_comments values (2362, 107601, 1, 3, 1, 0, 1, 'せっかくの水着ですし\\nこれから定期的に\\n海水浴に行きたいです', 0);
insert into room_unit_comments values (2363, 107601, 1, 4, 1, 0, 1, '海の生き物も、\\n森の生き物に負けず\\n可愛かったです…', 0);
insert into room_unit_comments values (2364, 107601, 1, 5, 1, 0, 1, 'クロールの練習なら、\\n部屋でもできそうです', 0);
insert into room_unit_comments values (2365, 107601, 1, 101, 4, 0, 1, '主さまに、水着姿を\\n褒めていただけた…\\nえへへ♪', 0);
insert into room_unit_comments values (2366, 107601, 1, 102, 8, 0, 1, '水着で主さまの\\nお世話をしたら、\\n喜びますでしょうか…', 0);
insert into room_unit_comments values (2367, 107601, 2, 1, 1, 0, 1, 'お疲れでしたら\\nわたくしの膝を\\nお使いくださいね', 0);
insert into room_unit_comments values (2368, 107601, 2, 2, 1, 0, 1, '主さま、海の家で\\nつかうおこづかいを\\n渡しておきますね', 0);
insert into room_unit_comments values (2369, 107601, 2, 3, 1, 0, 1, '海の美しさは、\\n森とはちがう\\n魅力がありました', 0);
insert into room_unit_comments values (2370, 107601, 2, 4, 1, 0, 1, 'この髪飾りですか？\\n造花ですから\\n水の中も平気です', 0);
insert into room_unit_comments values (2371, 107601, 2, 101, 4, 0, 1, '水着でくっついて\\n眠ると、いつもより\\n密着して暖かいです', 0);
insert into room_unit_comments values (2372, 107601, 2, 102, 8, 0, 1, 'はじめての海が、\\n主さまと一緒で\\n幸せです♪', 0);
insert into room_unit_comments values (2373, 107601, 2, 1, 1, 1, 1, 'おはようございます。\\n泳ぎに行く準備は\\n万端です', 0);
insert into room_unit_comments values (2374, 107601, 2, 2, 1, 2, 1, '午後は泳ぐのをやめて\\nスイカ割りなど\\nいかがでしょう？', 0);
insert into room_unit_comments values (2375, 107601, 2, 3, 1, 3, 1, '夜も更けてきました…\\n波の音を聞きながら\\n少しお話しませんか？', 0);
insert into room_unit_comments values (2377, 107601, 3, 2, 1, 0, 1, 'あぅ…この家具には、\\n人をダメにする魔法が\\nかけられています…', 0);
insert into room_unit_comments values (2378, 107601, 3, 3, 1, 0, 1, 'ふふっ♪\\nあなたも、海水浴に\\n行きますか？', 0);
insert into room_unit_comments values (2379, 107601, 3, 4, 1, 0, 1, 'この香り…\\nきっと主さまも\\n気に入ります', 0);
insert into room_unit_comments values (2380, 107601, 3, 5, 1, 0, 1, 'これは暖かいです…\\n後ほど主さまと一緒に\\nあたりましょう', 0);
insert into room_unit_comments values (2382, 107601, 3, 7, 1, 0, 1, '泳いだ後の食事は\\n一段と美味しく\\n感じます', 0);
insert into room_unit_comments values (2383, 107601, 3, 8, 1, 0, 1, '深海魚の生態…\\nこれは主さまにも\\nお伝えしなくては…', 0);
insert into room_unit_comments values (2385, 107601, 3, 10, 1, 0, 1, '顔立ちが、主さまに\\n似ております…\\nかわいらしい♪', 0);
insert into room_unit_comments values (2386, 107601, 3, 11, 1, 0, 1, 'ふかふかですね\\n主さまのようです♪', 0);
insert into room_unit_comments values (2387, 107701, 1, 1, 1, 0, 1, 'お掃除、お掃除\\nふんふふ～ん☆\\nあ、聞かれてました？', 0);
insert into room_unit_comments values (2388, 107701, 1, 2, 1, 0, 1, '日焼けには回復魔法が\\n効きますよ。どうして\\n逃げるんですか～！', 0);
insert into room_unit_comments values (2389, 107701, 1, 3, 1, 0, 1, '今日はドジを\\nしませんように！', 0);
insert into room_unit_comments values (2390, 107701, 1, 4, 1, 0, 1, '接客業を極めれば\\nメイドとして\\n成長できるかも？', 0);
insert into room_unit_comments values (2391, 107701, 1, 5, 1, 0, 1, '水着って\\n動きやすいんですけど\\n人の目が気になります', 0);
insert into room_unit_comments values (2392, 107701, 1, 101, 4, 0, 1, 'あの人の気持ちを知る\\n魔法とかあれば…\\nな、なんでもないです', 0);
insert into room_unit_comments values (2393, 107701, 1, 102, 8, 0, 1, '水着でご奉仕したら、\\nあの人は喜ぶかな？', 0);
insert into room_unit_comments values (2394, 107701, 2, 1, 1, 0, 1, '暑いのでしたら、\\n私が魔法で涼しく…\\nえ？\u3000いらない？', 0);
insert into room_unit_comments values (2395, 107701, 2, 2, 1, 0, 1, '何か御用ですか？\\n特にないのでしたら、\\nお話ししましょう♪', 0);
insert into room_unit_comments values (2396, 107701, 2, 3, 1, 0, 1, '水着姿でも\\nメイドはメイドです\\nご奉仕しますよ！', 0);
insert into room_unit_comments values (2397, 107701, 2, 4, 1, 0, 1, 'ひゃっ！\u3000あ、危うく\\n転ぶところでした…\\n…きゃうっ！', 0);
insert into room_unit_comments values (2398, 107701, 2, 101, 4, 0, 1, 'どうかしましたか？\\nあなたの御用なら、\\n喜んでお受けしますよ', 0);
insert into room_unit_comments values (2399, 107701, 2, 102, 8, 0, 1, '水着姿をあなたに\\n見られると、\\nドキドキしちゃいます', 0);
insert into room_unit_comments values (2400, 107701, 2, 1, 1, 1, 1, '朝は暑くてやる気が\\n出ない？\u3000でしたら、\\nえぇい、元気になぁれ', 0);
insert into room_unit_comments values (2401, 107701, 2, 2, 1, 2, 1, 'お腹がぺこぺこなら、\\nお昼は海の家で\\n食べましょう♪', 0);
insert into room_unit_comments values (2402, 107701, 2, 3, 1, 3, 1, '夜の浜辺でお散歩も\\nいいですね。たくさん\\n転びそうですけど…', 0);
insert into room_unit_comments values (2404, 107701, 3, 2, 1, 0, 1, '休憩しながら、\\nお掃除すれば\\n一石二鳥です！', 0);
insert into room_unit_comments values (2405, 107701, 3, 3, 1, 0, 1, 'きれいにすれば\\nかわいさも倍増\\nですよ～♪', 0);
insert into room_unit_comments values (2406, 107701, 3, 4, 1, 0, 1, '素敵な香りです～\\n救護院に置けば、\\nみんな喜ぶかも～', 0);
insert into room_unit_comments values (2407, 107701, 3, 5, 1, 0, 1, 'あったかいですね…\\nはっ！\u3000いけません！\\nメイドがサボるなんて', 0);
insert into room_unit_comments values (2409, 107701, 3, 7, 1, 0, 1, '料理のできない\\nメイドなんて…\\nはぐはぐ、おいしい♪', 0);
insert into room_unit_comments values (2410, 107701, 3, 8, 1, 0, 1, '水着姿で接客をすると\\n売り上げが倍になる\\n…本当ですか、これ', 0);
insert into room_unit_comments values (2412, 107701, 3, 10, 1, 0, 1, 'えへへ♪\\n南の島まで\\n乗せてください！', 0);
insert into room_unit_comments values (2413, 107701, 3, 11, 1, 0, 1, 'なんだか、\\n人魚姫に\\nなった気分です♪', 0);
insert into room_unit_comments values (2414, 107801, 1, 1, 1, 0, 1, 'みんなで過ごす\\n休日っていいわよね…\\nずっと続かないかな', 0);
insert into room_unit_comments values (2415, 107801, 1, 2, 1, 0, 1, '海に浮輪でぷかぷか\\n浮かぶのって\\n癖になりそう', 0);
insert into room_unit_comments values (2416, 107801, 1, 3, 1, 0, 1, 'ビーチにいると\\n日焼けが心配だわ', 0);
insert into room_unit_comments values (2417, 107801, 1, 4, 1, 0, 1, '水着姿って楽よね。\\n室内だとちょっと\\n落ち着かないけど…', 0);
insert into room_unit_comments values (2418, 107801, 1, 5, 1, 0, 1, 'お、泳ぎの練習なんて\\nしないからね！', 0);
insert into room_unit_comments values (2419, 107801, 1, 101, 4, 0, 1, '楽しすぎて立場を\\n忘れそう…あんたの\\nせいなんだから！', 0);
insert into room_unit_comments values (2420, 107801, 1, 102, 8, 0, 1, 'みんなで遊んで\\n美味しいもの食べて\\nほんっとに楽しいっ♪', 0);
insert into room_unit_comments values (2421, 107801, 2, 1, 1, 0, 1, 'マジであっついわね…\\nよっし！\u3000海に入って\\n涼みましょ！', 0);
insert into room_unit_comments values (2422, 107801, 2, 2, 1, 0, 1, 'シャワー浴びたばかり\\nなのに…また、遊び\\nたくなってきたわ！', 0);
insert into room_unit_comments values (2423, 107801, 2, 3, 1, 0, 1, '遊び足りないって？\\nしょうがないわね…\\n付き合ってあげるわ♪', 0);
insert into room_unit_comments values (2424, 107801, 2, 4, 1, 0, 1, '一応伝えておくけど\\n猫って水が苦手なの！\\nわかった！？', 0);
insert into room_unit_comments values (2425, 107801, 2, 101, 4, 0, 1, 'あたしと話したいの？\\nふふ。\\nまぁ、いいわよ。\\nほら隣に座りなさい', 0);
insert into room_unit_comments values (2426, 107801, 2, 102, 8, 0, 1, 'こんなに楽しいの\\n初めてかも…\\nずっと続けばいいのに', 0);
insert into room_unit_comments values (2427, 107801, 2, 1, 1, 1, 1, 'は、早起きしたのは、\\n楽しみで眠れなかった\\nからじゃないわよ！', 0);
insert into room_unit_comments values (2428, 107801, 2, 2, 1, 2, 1, '昼食後のストレッチ\\n終わり！\u3000さあ、\\nビーチが待ってるわ！', 0);
insert into room_unit_comments values (2429, 107801, 2, 3, 1, 3, 1, '夜の海に散歩に\\n行こうかな～\\nあんたも来なさいよ☆', 0);
insert into room_unit_comments values (2431, 107801, 3, 2, 1, 0, 1, '海ではしゃぎすぎて\\n疲れたわ…ちょっと\\n休もうかしら？', 0);
insert into room_unit_comments values (2432, 107801, 3, 3, 1, 0, 1, 'こんな魔物がいたら\\n操るのも楽しいかも', 0);
insert into room_unit_comments values (2433, 107801, 3, 4, 1, 0, 1, 'にゃう～♪\\nまるで南国にいる\\n気分ね♪', 0);
insert into room_unit_comments values (2434, 107801, 3, 5, 1, 0, 1, 'あったかぁい♪\\n身体が冷えてきたから\\n丁度いいわ！', 0);
insert into room_unit_comments values (2436, 107801, 3, 7, 1, 0, 1, '運動後のご飯って\\nなんでこんなに\\n美味しいんだろ♪', 0);
insert into room_unit_comments values (2437, 107801, 3, 8, 1, 0, 1, 'どんなカナヅチでも、\\n絶対必ず泳げる方法、\\n書いてないかしら？', 0);
insert into room_unit_comments values (2439, 107801, 3, 10, 1, 0, 1, 'あんたもあたしが\\n操ってあげる！\\nなんてね～♪', 0);
insert into room_unit_comments values (2440, 107801, 3, 11, 1, 0, 1, 'リゾートリゾートっ\\nのんびりしましょ♪', 0);
insert into room_unit_comments values (2441, 108001, 1, 1, 1, 0, 1, 'ここなら思う存分\\nデスクワークに\\n励めるわね！', 0);
insert into room_unit_comments values (2442, 108001, 1, 2, 1, 0, 1, '武器のメンテナンスも\\nしっかりしないと\\n最高効率は望めないわ', 0);
insert into room_unit_comments values (2443, 108001, 1, 3, 1, 0, 1, '準備をしっかり整えて\\nもっともっと\\n稼がなくちゃね！', 0);
insert into room_unit_comments values (2444, 108001, 1, 4, 1, 0, 1, '少し休んだら\\n次のバイトに\\n行ってくるわね！', 0);
insert into room_unit_comments values (2445, 108001, 1, 5, 1, 0, 1, 'この格好でここに\\nいるのって\\n気恥ずかしいわね…', 0);
insert into room_unit_comments values (2446, 108001, 1, 101, 4, 0, 1, 'キミが望むなら\\n今日のバイト\\n休んでもいいわよ？', 0);
insert into room_unit_comments values (2447, 108001, 1, 102, 8, 0, 1, 'キミだけね…\\n私のことをここまで\\n理解してくれるのは', 0);
insert into room_unit_comments values (2448, 108001, 2, 1, 1, 0, 1, '普段と違う格好\\nだからって\\nそんなに見ないでよ…', 0);
insert into room_unit_comments values (2449, 108001, 2, 2, 1, 0, 1, 'キミを立派な\\nバイト戦士にするのが\\n師匠としての役目よね', 0);
insert into room_unit_comments values (2450, 108001, 2, 3, 1, 0, 1, 'そろそろ次のバイトに\\n行かないと…\\nキミも一緒に来る？', 0);
insert into room_unit_comments values (2451, 108001, 2, 4, 1, 0, 1, '効率は大事だけど\\nゆっくりするのも\\n悪くないわね', 0);
insert into room_unit_comments values (2452, 108001, 2, 101, 4, 0, 1, '一緒の時間が楽しくて\\nバイトのことを\\n忘れちゃいそうね', 0);
insert into room_unit_comments values (2453, 108001, 2, 102, 8, 0, 1, 'キミと一緒なら\\nどんなミッションも\\n楽勝ね！', 0);
insert into room_unit_comments values (2454, 108001, 2, 1, 1, 1, 1, 'おはよう、いい朝ね！\\n今日もめいっぱい\\n稼ぐわよ！', 0);
insert into room_unit_comments values (2455, 108001, 2, 2, 1, 2, 1, 'もうお昼だったのね…\\n内職のバイトに\\n集中しすぎちゃったわ', 0);
insert into room_unit_comments values (2456, 108001, 2, 3, 1, 3, 1, 'スケジュールは、と…\\nこういう管理の徹底が\\n効率を生み出すのよ♪', 0);
insert into room_unit_comments values (2458, 108001, 3, 2, 1, 0, 1, 'しっかり働いて休む…\\n最高効率にまた一歩\\n近づいたわね', 0);
insert into room_unit_comments values (2459, 108001, 3, 3, 1, 0, 1, 'なごんじゃうわね…\\nよぉし、次のバイトも\\n頑張らないと！', 0);
insert into room_unit_comments values (2460, 108001, 3, 4, 1, 0, 1, 'いい香りね…\\n働く意欲が\\n湧いてくるわ', 0);
insert into room_unit_comments values (2461, 108001, 3, 5, 1, 0, 1, '身体が冷えたから\\n助かるわ…冷えは\\n女の天敵だもの', 0);
insert into room_unit_comments values (2463, 108001, 3, 7, 1, 0, 1, '海のバイトは\\n体力勝負よ\\nエネルギーはしっかり\\n摂取しないとね！', 0);
insert into room_unit_comments values (2464, 108001, 3, 8, 1, 0, 1, '座学も大切ね\\nもっと知識を\\n身につけないと…', 0);
insert into room_unit_comments values (2466, 108001, 3, 10, 1, 0, 1, '海の楽園みたいね…\\n今だけは効率を\\n忘れちゃいそう…', 0);
insert into room_unit_comments values (2467, 108001, 3, 11, 1, 0, 1, '落ち着くわ…\\n海とひとつになった\\n気分ね！', 0);
insert into room_unit_comments values (2468, 107901, 1, 1, 1, 0, 1, 'ちょっと休憩にゃ～\\n潮風は体に\\n良くないにゃ～', 0);
insert into room_unit_comments values (2469, 107901, 1, 2, 1, 0, 1, '猫グッズで\\n海の家を飾りたいにゃ', 0);
insert into room_unit_comments values (2470, 107901, 1, 3, 1, 0, 1, '海の幸は美味しいけど\\n水はイヤだにゃ…', 0);
insert into room_unit_comments values (2471, 107901, 1, 4, 1, 0, 1, '開店にゃ！\\nこのたい焼きなら\\nきっと大繁盛にゃ！', 0);
insert into room_unit_comments values (2472, 107901, 1, 5, 1, 0, 1, '海と言えば水着にゃ\\n似合ってるかにゃ？', 0);
insert into room_unit_comments values (2473, 107901, 1, 101, 4, 0, 1, 'キミが頼むなら\\n手伝ってあげても\\nいいにゃ', 0);
insert into room_unit_comments values (2474, 107901, 1, 102, 8, 0, 1, 'あたしの宝は\\nここにあるにゃ～', 0);
insert into room_unit_comments values (2475, 107901, 2, 1, 1, 0, 1, 'にゃ？\\nそんなに見つめても\\n何も出ないにゃ', 0);
insert into room_unit_comments values (2476, 107901, 2, 2, 1, 0, 1, '今からキミを\\nあたしの相棒に\\n任命するにゃ！', 0);
insert into room_unit_comments values (2477, 107901, 2, 3, 1, 0, 1, 'これから\\n開店の準備にゃ\\nキミも手伝って\\nくれるのかにゃ？', 0);
insert into room_unit_comments values (2478, 107901, 2, 4, 1, 0, 1, '海の家で出す\\n新しいメニューを\\n考え中なのにゃ～', 0);
insert into room_unit_comments values (2479, 107901, 2, 101, 4, 0, 1, 'キミと一緒なら\\n売上げナンバーワンに\\nなれるにゃ！', 0);
insert into room_unit_comments values (2480, 107901, 2, 102, 8, 0, 1, 'キミと一緒にいると\\n楽しくて、もっと\\nいたくなるにゃ', 0);
insert into room_unit_comments values (2481, 107901, 2, 1, 1, 1, 1, 'おはようにゃ！\\n今日も頑張って\\nいくにゃー！', 0);
insert into room_unit_comments values (2482, 107901, 2, 2, 1, 2, 1, 'お腹すいたにゃ～…\\nお魚、ちょっとだけ、\\nつまみ食いするにゃ', 0);
insert into room_unit_comments values (2483, 107901, 2, 3, 1, 3, 1, '明日の準備は万端にゃ\\nいつでも\\n出発できるにゃ', 0);
insert into room_unit_comments values (2485, 107901, 3, 2, 1, 0, 1, 'このふかふか具合\\nまるで子猫の\\n毛並みのようにゃ～', 0);
insert into room_unit_comments values (2486, 107901, 3, 3, 1, 0, 1, 'にゃにゃ～\\nなんてかわいさにゃ～', 0);
insert into room_unit_comments values (2487, 107901, 3, 4, 1, 0, 1, 'この匂い…\\nもう少し香ばしいと\\nいいかもしれないにゃ', 0);
insert into room_unit_comments values (2488, 107901, 3, 5, 1, 0, 1, 'にゃ～…\\nあったかくて\\nぬくぬくだにゃ～', 0);
insert into room_unit_comments values (2490, 107901, 3, 7, 1, 0, 1, '働くにはまず体力にゃ\\nしっかり食べて\\nスタミナアップ\\nだにゃ!', 0);
insert into room_unit_comments values (2491, 107901, 3, 8, 1, 0, 1, 'ふむふむ…\\nここにお宝が\\n眠ってるんだにゃ', 0);
insert into room_unit_comments values (2493, 107901, 3, 10, 1, 0, 1, 'シードレイクにゃ！\\n本物は怖かったけど、\\nぬいぐるみなら\\nかわいいにゃ～', 0);
insert into room_unit_comments values (2494, 107901, 3, 11, 1, 0, 1, '貝なのにふかふかの\\nクッションにゃ！\\n屋台の前にも\\n置いてみたいにゃあ', 0);
insert into room_unit_comments values (2495, 103701, 1, 1, 1, 0, 1, '人の家って、道場とは\\n違った香りがするね', 0);
insert into room_unit_comments values (2496, 103701, 1, 2, 1, 0, 1, 'ちょっと退屈だね…\\nあの人をからかいに\\n行こうかな♪', 0);
insert into room_unit_comments values (2497, 103701, 1, 3, 1, 0, 1, '普通の女の子みたいに\\n遊びたいって思う\\nこともあるんだよね', 0);
insert into room_unit_comments values (2498, 103701, 1, 4, 1, 0, 1, '剣の手入れを怠らない\\nようにしないと。\\nいざという時、困るし', 0);
insert into room_unit_comments values (2499, 103701, 1, 5, 1, 0, 1, 'もっと\\n上手く立ち回って\\n出世したいな', 0);
insert into room_unit_comments values (2500, 103701, 1, 101, 4, 0, 1, 'おかえりなさい！\\nふふ、なんだか奥さん\\nになった気分だよ♪', 0);
insert into room_unit_comments values (2501, 103701, 1, 102, 8, 0, 1, '恥ずかしくて、あなた\\nを見られないよ…\\n私らしくないなぁ…', 0);
insert into room_unit_comments values (2502, 103701, 2, 1, 1, 0, 1, '私、お話好きなんだ。\\nどうせなら楽しい話を\\nしたいな♪', 0);
insert into room_unit_comments values (2503, 103701, 2, 2, 1, 0, 1, '女の子っぽい子と、\\n男勝りな子、あなたは\\nどっちが好き？', 0);
insert into room_unit_comments values (2504, 103701, 2, 3, 1, 0, 1, 'そろそろ見回りの\\n時間かな。あなたも\\n一緒に行く？', 0);
insert into room_unit_comments values (2505, 103701, 2, 4, 1, 0, 1, '構って欲しいのかな？\\nそれじゃ一緒に\\nランニングに行こうか', 0);
insert into room_unit_comments values (2506, 103701, 2, 101, 4, 0, 1, '二人で出かけるなら、\\n手を繋がないとね。\\nあはは、冗談冗談♪', 0);
insert into room_unit_comments values (2507, 103701, 2, 102, 8, 0, 1, 'ねえ、あなた♪\\nおや、顔が真っ赤だ！\\n…ふふ、私も、かな？', 0);
insert into room_unit_comments values (2508, 103701, 2, 1, 1, 1, 1, '私は朝から鍛錬だよ。\\n慣れてるけど大変だ。\\nお互いに頑張ろうね', 0);
insert into room_unit_comments values (2509, 103701, 2, 2, 1, 2, 1, '鍛錬でお腹ぺこぺこ。\\nお昼ごはんが\\n楽しみだね', 0);
insert into room_unit_comments values (2510, 103701, 2, 3, 1, 3, 1, '今日も一日見回りと\\n鍛錬を頑張ったよ。\\nあなたもお疲れさま', 0);
insert into room_unit_comments values (2512, 103701, 3, 2, 1, 0, 1, 'いざという時のため\\nにも、休憩は大事だね', 0);
insert into room_unit_comments values (2513, 103701, 3, 3, 1, 0, 1, 'こういうものには\\n今まで\\n縁がなかったけど。\\nうん、可愛いね♪', 0);
insert into room_unit_comments values (2514, 103701, 3, 4, 1, 0, 1, '精神統一に通じる\\nものがあるね。\\nふぅ、癒されるなぁ', 0);
insert into room_unit_comments values (2515, 103701, 3, 5, 1, 0, 1, 'あったかいなぁ。\\nたまにはのんびり\\nしようか', 0);
insert into room_unit_comments values (2517, 103701, 3, 7, 1, 0, 1, '鍛錬後はすごくお腹が\\n空くんだよね。\\nう～ん、おいしい♪', 0);
insert into room_unit_comments values (2518, 103701, 3, 8, 1, 0, 1, '剣術書だけで強くなる\\nには飛びぬけた才能と\\n努力が必要だよね', 0);
insert into room_unit_comments values (2520, 100501, 1, 1, 1, 0, 1, '正義の刃で\\n悪を挫く！\\n…キマったッス♪', 0);
insert into room_unit_comments values (2521, 100501, 1, 2, 1, 0, 1, 'ヒーローの\\n秘密特訓を\\n始めるッスよ～！', 0);
insert into room_unit_comments values (2522, 100501, 1, 3, 1, 0, 1, '正義の味方目指して\\n今日も明日も\\n全力ッスよ♪', 0);
insert into room_unit_comments values (2523, 100501, 1, 4, 1, 0, 1, '一日一善！\\nヒーローだったら\\n当たり前ッス♪', 0);
insert into room_unit_comments values (2524, 100501, 1, 5, 1, 0, 1, 'どうッスか\\nこのポーズ！\\nイイ感じッスか？', 0);
insert into room_unit_comments values (2525, 100501, 1, 101, 4, 0, 1, 'た、たまには\\nよく頑張ったねって\\n褒めてほしいッス…', 0);
insert into room_unit_comments values (2526, 100501, 1, 102, 8, 0, 1, '自分を信じてくれる\\nあんたと一緒なら\\n何でもやれるッス！', 0);
insert into room_unit_comments values (2527, 100501, 2, 1, 1, 0, 1, 'おつかれッス♪\\n冒険の準備は\\nばっちりッスよ！', 0);
insert into room_unit_comments values (2528, 100501, 2, 2, 1, 0, 1, 'どうしたんッスか？\\n…はっ！\u3000もしや敵が\\n迫ってるんスかっ！？', 0);
insert into room_unit_comments values (2529, 100501, 2, 3, 1, 0, 1, 'べ、別に\\n頭を撫でてほしいとか\\n思ってないッスよ？', 0);
insert into room_unit_comments values (2530, 100501, 2, 4, 1, 0, 1, 'スーパーヒーロー\\nトラタイガーは\\n絶対無敵ッス！', 0);
insert into room_unit_comments values (2531, 100501, 2, 101, 4, 0, 1, 'あんたと自分で\\n正義の心を燃やして\\n悪を一網打尽ッス！', 0);
insert into room_unit_comments values (2532, 100501, 2, 102, 8, 0, 1, 'あんたと一緒だと\\n幸せな気持ちに\\nなるんッス…♪', 0);
insert into room_unit_comments values (2533, 100501, 2, 1, 1, 1, 1, 'お、早いッスね～♪\\n今日も一日一善\\nよろしくッス！', 0);
insert into room_unit_comments values (2534, 100501, 2, 2, 1, 2, 1, '一休みしながら\\nヒーローについて\\n語り合うッスよ～！', 0);
insert into room_unit_comments values (2535, 100501, 2, 3, 1, 3, 1, '夜のパトロールで\\n一緒に平和を\\n守るッス！', 0);
insert into room_unit_comments values (2537, 100501, 3, 2, 1, 0, 1, 'ふぅぅ…\\n落ち着くッスね\\n戦士の休息ッス♪', 0);
insert into room_unit_comments values (2538, 100501, 3, 3, 1, 0, 1, 'くぅぅ、可愛いッス…\\nヒーローが守るべき\\n愛らしさッスね！', 0);
insert into room_unit_comments values (2539, 100501, 3, 4, 1, 0, 1, 'なんスかこの香り？\\nすぅぅ…ふぅぅ…\\n力がみなぎるッス！', 0);
insert into room_unit_comments values (2540, 100501, 3, 5, 1, 0, 1, '優しい光ッスね…\\nヒーローの優しさ\\nそのものッス！', 0);
insert into room_unit_comments values (2542, 100501, 3, 7, 1, 0, 1, 'あむあむあむ…\\nんぅう、元気が溢れて\\n止まらないッス！', 0);
insert into room_unit_comments values (2543, 100501, 3, 8, 1, 0, 1, 'トラタイガーのお話は\\n笑いあり涙ありで\\n超おすすめッス！', 0);
insert into room_unit_comments values (2545, 108101, 1, 1, 1, 0, 1, 'ハッピーハロウィン\\nお父さん、お菓子は…\\n食べられないね', 0);
insert into room_unit_comments values (2546, 108101, 1, 2, 1, 0, 1, 'トリックオアトリート\\nお菓子をくれないと\\n不吉な占いをします', 0);
insert into room_unit_comments values (2547, 108101, 1, 3, 1, 0, 1, 'ふふ、あなたの後ろで\\n霊のみなさんが\\n踊り始めました', 0);
insert into room_unit_comments values (2548, 108101, 1, 4, 1, 0, 1, '霊感がいつも以上に\\n冴えているので\\n占いの調子も良好です', 0);
insert into room_unit_comments values (2549, 108101, 1, 5, 1, 0, 1, '父はハロウィンが\\n大好きだそうです\\n大胆な格好をする子が\\n多いので…', 0);
insert into room_unit_comments values (2550, 108101, 1, 101, 4, 0, 1, 'あなたは霊たちにも\\n大人気ですよね\\n私も見てほしいな…', 0);
insert into room_unit_comments values (2551, 108101, 1, 102, 8, 0, 1, 'ハロウィンの賑やかさ\\n今は好きです…\\nあなたといられるので', 0);
insert into room_unit_comments values (2552, 108101, 2, 1, 1, 0, 1, '霊のみなさんとの\\nダンスパーティー…\\n楽しみです', 0);
insert into room_unit_comments values (2553, 108101, 2, 2, 1, 0, 1, 'お父さん、元気だね\\nえ？\u3000ここは色んな\\n女の子に会えて幸せ？', 0);
insert into room_unit_comments values (2554, 108101, 2, 3, 1, 0, 1, 'ハロウィンのお菓子\\n食べすぎちゃったな…\\nでも、美味しかった…', 0);
insert into room_unit_comments values (2555, 108101, 2, 4, 1, 0, 1, 'あなたの女難の相…\\n悪化していますね\\nお祓いが必要かも', 0);
insert into room_unit_comments values (2556, 108101, 2, 101, 4, 0, 1, 'あの、霊のみなさんが\\nあなたと踊りたいと…\\nえっと、私も…', 0);
insert into room_unit_comments values (2557, 108101, 2, 102, 8, 0, 1, 'あなたと手を繋ぐと\\n胸が苦しくなります\\nでも、繋ぎたいな…', 0);
insert into room_unit_comments values (2558, 108101, 2, 1, 1, 1, 1, 'ハッピーハロウィン…\\n父が元気なので\\n今日の運気は良好です', 0);
insert into room_unit_comments values (2559, 108101, 2, 2, 1, 2, 1, '父はお昼寝中です\\n本当に寝ているかは\\n私にも分かりませんが', 0);
insert into room_unit_comments values (2560, 108101, 2, 3, 1, 3, 1, 'お父さん、\\nもう眠っちゃったの？\\n…眠れるんだったっけ', 0);
insert into room_unit_comments values (2562, 108101, 3, 2, 1, 0, 1, '落ち着きますね…\\n霊のみなさんも\\n喜んでいます', 0);
insert into room_unit_comments values (2563, 108101, 3, 3, 1, 0, 1, 'つん、つん。ふふっ♪\\n癒やされます…', 0);
insert into room_unit_comments values (2564, 108101, 3, 4, 1, 0, 1, '精神が研ぎ澄まされる\\n香りですね…\\n占いが捗ります', 0);
insert into room_unit_comments values (2565, 108101, 3, 5, 1, 0, 1, 'あったかいね\\nお父さん…\\nえ？\u3000分からない？', 0);
insert into room_unit_comments values (2567, 108101, 3, 7, 1, 0, 1, '霊のみなさんは\\n食べられないので…\\n私がいただきます', 0);
insert into room_unit_comments values (2568, 108101, 3, 8, 1, 0, 1, 'お父さんを元に戻す\\n手掛かり…\\n書かれていないかな？', 0);
insert into room_unit_comments values (2570, 108101, 3, 12, 1, 0, 1, 'わぁ、お菓子が沢山…', 0);
insert into room_unit_comments values (2572, 108201, 1, 1, 1, 0, 1, '無料でプリンが\\nもらえるなんて、\\nハロウィンはすごいの', 0);
insert into room_unit_comments values (2573, 108201, 1, 2, 1, 0, 1, '生きてるときも、\\nミヤコはハロウィンが\\n好きだった気がするの', 0);
insert into room_unit_comments values (2574, 108201, 1, 3, 1, 0, 1, 'みんなに仮装を\\n見せつけて、\\nプリンをもらうの～', 0);
insert into room_unit_comments values (2575, 108201, 1, 4, 1, 0, 1, 'この仮装で、\\nみんなに恐怖を\\n教えてやるの！', 0);
insert into room_unit_comments values (2576, 108201, 1, 5, 1, 0, 1, 'アオーン、アオーン！\\nミヤコ、狼女に\\nなりきってるの～', 0);
insert into room_unit_comments values (2577, 108201, 1, 101, 4, 0, 1, 'アイツに秘密で、\\nパーティーの\\n飾り付けをするの♪', 0);
insert into room_unit_comments values (2578, 108201, 1, 102, 8, 0, 1, 'アイツが狼男の\\n仮装をすれば、\\nおそろいなの～', 0);
insert into room_unit_comments values (2579, 108201, 2, 1, 1, 0, 1, 'プリンをくれなきゃ、\\nオマエをカボチャに\\nしてやるの～', 0);
insert into room_unit_comments values (2580, 108201, 2, 2, 1, 0, 1, 'ハロウィンは幽霊でも\\n参加できるから\\n楽しいの～！', 0);
insert into room_unit_comments values (2581, 108201, 2, 3, 1, 0, 1, 'プリンがないなら\\nカボチャプリンを\\n食べればいいの！', 0);
insert into room_unit_comments values (2582, 108201, 2, 4, 1, 0, 1, 'プリンの可能性は\\n無限大なの～', 0);
insert into room_unit_comments values (2583, 108201, 2, 101, 4, 0, 1, 'オマエの隣で\\nプリンを食べると、\\nいつもより美味しいの', 0);
insert into room_unit_comments values (2584, 108201, 2, 102, 8, 0, 1, 'オマエが死んでも、\\nミヤコはずーっと\\n一緒にいてやるの～', 0);
insert into room_unit_comments values (2585, 108201, 2, 1, 1, 1, 1, '朝ごはんは\\nカボチャプリンなの！\\nハロウィンっぽいの～', 0);
insert into room_unit_comments values (2586, 108201, 2, 2, 1, 2, 1, 'ランチは豪華に\\nプリンアラモードなの', 0);
insert into room_unit_comments values (2587, 108201, 2, 3, 1, 3, 1, '夜は幽霊たちと\\nハロウィンするの！\\nオマエも来るの！', 0);
insert into room_unit_comments values (2589, 108201, 3, 2, 1, 0, 1, '幽霊にも休息は\\n必要なの！\\nプリンもってこいなの', 0);
insert into room_unit_comments values (2590, 108201, 3, 3, 1, 0, 1, 'オマエもミヤコの\\nパーティーに\\n招待してあげるの～', 0);
insert into room_unit_comments values (2591, 108201, 3, 4, 1, 0, 1, '癒されるの～\\nまるで天国なの～', 0);
insert into room_unit_comments values (2592, 108201, 3, 5, 1, 0, 1, 'ここでなら、\\n焼きプリンが\\n作れるの！', 0);
insert into room_unit_comments values (2594, 108201, 3, 7, 1, 0, 1, '腹が減っては\\nハロウィンは\\nできぬなの！', 0);
insert into room_unit_comments values (2595, 108201, 3, 8, 1, 0, 1, '丸ごとカボチャ\\nプリン特集！？\\n美味しそうなの～♪', 0);
insert into room_unit_comments values (2597, 108201, 3, 12, 1, 0, 1, 'お菓子がたくさんで、\\nミヤコはとっても\\nハッピーなの♪', 0);
insert into room_unit_comments values (2599, 108301, 1, 1, 1, 0, 1, '魔女以外にも、\\n色々な仮装を\\nしてみたいわね', 0);
insert into room_unit_comments values (2600, 108301, 1, 2, 1, 0, 1, 'チョコやアメよりも、\\nアタシに相応しい\\nスイーツがあるはず…', 0);
insert into room_unit_comments values (2601, 108301, 1, 3, 1, 0, 1, 'お菓子の食べ過ぎは、\\nお母さんに\\n怒られるかも…', 0);
insert into room_unit_comments values (2602, 108301, 1, 4, 1, 0, 1, 'この格好で学院に\\n行ったら、\\nみんな驚くかしら', 0);
insert into room_unit_comments values (2603, 108301, 1, 5, 1, 0, 1, '大人のレディは、\\nどういうハロウィンを\\n過ごすべきかしら…？', 0);
insert into room_unit_comments values (2604, 108301, 1, 101, 4, 0, 1, 'お菓子、アイツの分も\\nとっといてあげよ！\\n大人の余裕ってやつね', 0);
insert into room_unit_comments values (2605, 108301, 1, 102, 8, 0, 1, 'アイツを魅了する\\n魔法とかないかしら？', 0);
insert into room_unit_comments values (2606, 108301, 2, 1, 1, 0, 1, 'おしゃれスイーツを\\nくれなきゃ\\nイタズラするわよ！', 0);
insert into room_unit_comments values (2607, 108301, 2, 2, 1, 0, 1, 'アタシの大人センスで\\nアンタに似合う仮装を\\n選んであげるわ！', 0);
insert into room_unit_comments values (2608, 108301, 2, 3, 1, 0, 1, '不気味よねぇ…\\nジャックオーランタン\\nこ、怖くないわよ？', 0);
insert into room_unit_comments values (2609, 108301, 2, 4, 1, 0, 1, 'ハロウィンが楽しくて\\n宿題やり忘れてたわ…\\nて、手伝って～！', 0);
insert into room_unit_comments values (2610, 108301, 2, 101, 4, 0, 1, 'お菓子をもらうのも\\nアンタと一緒なら\\n恥ずかしくないわ！', 0);
insert into room_unit_comments values (2611, 108301, 2, 102, 8, 0, 1, 'アタシのエスコートを\\n任せられるのは、\\nアンタだけなんだから', 0);
insert into room_unit_comments values (2612, 108301, 2, 1, 1, 1, 1, '朝食はオシャレに\\nグリーンスムージー！\\n…に、にがぁ', 0);
insert into room_unit_comments values (2613, 108301, 2, 2, 1, 2, 1, '昼下がりはカフェで\\n優雅なティータイム\\n…憧れるわ～', 0);
insert into room_unit_comments values (2614, 108301, 2, 3, 1, 3, 1, 'ハロウィンナイトの\\nはじまりよ！\\n街に繰り出しましょ！', 0);
insert into room_unit_comments values (2616, 108301, 3, 2, 1, 0, 1, 'あう～、お菓子の\\n食べすぎで\\n動けな～い', 0);
insert into room_unit_comments values (2617, 108301, 3, 3, 1, 0, 1, 'アンタも仮装する？\\nいまよりもーっと\\nかわいくなるわよ！', 0);
insert into room_unit_comments values (2618, 108301, 3, 4, 1, 0, 1, '大人な香りに\\n包まれてる～♪', 0);
insert into room_unit_comments values (2619, 108301, 3, 5, 1, 0, 1, 'ポカポカね～♪\\n…ああー！\\nチョコが溶けてる！', 0);
insert into room_unit_comments values (2621, 108301, 3, 7, 1, 0, 1, 'おいしい～♪\\n…じゃなくて！\\nび、美味ですわ～', 0);
insert into room_unit_comments values (2622, 108301, 3, 8, 1, 0, 1, 'この服かわい～♪\\nって、なにこの値段！\\nお小遣い何年分よ！？', 0);
insert into room_unit_comments values (2624, 108301, 3, 12, 1, 0, 1, 'お、お菓子なんかで\\n喜ぶほど、子供じゃ…', 0);
insert into room_unit_comments values (2626, 107101, 1, 1, 1, 0, 1, '次はどんな策で団長を\\nからかってみようか…', 0);
insert into room_unit_comments values (2627, 107101, 1, 2, 1, 0, 1, 'む？\\n血の臭いがするな\\n祭りの時間か☆', 0);
insert into room_unit_comments values (2628, 107101, 1, 3, 1, 0, 1, '平和に飼い殺される\\n前に、混沌の愛を\\n育みたいね', 0);
insert into room_unit_comments values (2629, 107101, 1, 4, 1, 0, 1, '本気を出した団長と\\nいつか手加減なしに\\n殺り合いたいな', 0);
insert into room_unit_comments values (2630, 107101, 1, 5, 1, 0, 1, 'おばさん呼ばわりする\\n新米騎士の小娘を\\n懲らしめてやろうか', 0);
insert into room_unit_comments values (2631, 107101, 1, 101, 4, 0, 1, '胸を触られるまで\\n誓約のことなど\\nすっかり忘れていたな', 0);
insert into room_unit_comments values (2632, 107101, 1, 102, 8, 0, 1, 'まさかこのワタシが\\nプロポーズするとはな\\n…笑えるじゃないか', 0);
insert into room_unit_comments values (2633, 107101, 2, 1, 1, 0, 1, '面白い暇つぶしを\\n思いついたんだ\\n戯れに付き合え☆', 0);
insert into room_unit_comments values (2634, 107101, 2, 2, 1, 0, 1, '退屈で死にそうだ\\n愉しい話題を\\nワタシに提供してくれ', 0);
insert into room_unit_comments values (2635, 107101, 2, 3, 1, 0, 1, 'なんだ、暇なのか？\\n心躍ることでも探しに\\n出かけようではないか', 0);
insert into room_unit_comments values (2636, 107101, 2, 4, 1, 0, 1, 'このワタシを愉快に\\nさせてくれる事でも\\nあったのか？', 0);
insert into room_unit_comments values (2637, 107101, 2, 101, 4, 0, 1, 'ワタシに求婚した男の\\n数だと？\\nいちいち覚えてないな', 0);
insert into room_unit_comments values (2638, 107101, 2, 102, 8, 0, 1, '最強無敵の女と\\n結婚できるんだ\\n誇りに思えよ☆', 0);
insert into room_unit_comments values (2639, 107101, 2, 1, 1, 1, 1, 'なにか愉快なことが\\n起こりそうな朝だ☆\\nワクワクするね', 0);
insert into room_unit_comments values (2640, 107101, 2, 2, 1, 2, 1, 'うーむ、腹がすいたな\\n愉快なことで\\nこの空腹を満たしたい', 0);
insert into room_unit_comments values (2641, 107101, 2, 3, 1, 3, 1, 'これからは大人の\\n時間だ。愉しみ方を\\n知りたいのかい？', 0);
insert into room_unit_comments values (2643, 107101, 3, 2, 1, 0, 1, 'このワタシとした事が\\n穏やかな気分に\\nなってしまうとは…', 0);
insert into room_unit_comments values (2644, 107101, 3, 3, 1, 0, 1, '可愛い姿をしたものが\\n惨たらしい\\n醜態を晒すのを\\n想像してしまう', 0);
insert into room_unit_comments values (2645, 107101, 3, 4, 1, 0, 1, '悪くはない香りだ\\nだが、ワタシは血の\\n臭いを嗅ぎたいぞ☆', 0);
insert into room_unit_comments values (2646, 107101, 3, 5, 1, 0, 1, 'ぬるい、ぬるすぎる！\\n地獄の業火には\\nほど遠い熱さだ！', 0);
insert into room_unit_comments values (2648, 107101, 3, 7, 1, 0, 1, 'ワタシの腕前に\\n勝るとも劣らない\\nなかなかの味だ', 0);
insert into room_unit_comments values (2649, 107101, 3, 8, 1, 0, 1, '意中の男性を絶対に\\n落とす方法…？\\nく、下らんっ！', 0);
insert into room_unit_comments values (2651, 105601, 1, 1, 1, 0, 1, '明日はあの釣り場に\\n行くとしようかな\\nあの子も誘ってみるか', 0);
insert into room_unit_comments values (2652, 105601, 1, 2, 1, 0, 1, 'ぷはーっ！\\n体を動かしたあとの\\n一杯は格別だね', 0);
insert into room_unit_comments values (2653, 105601, 1, 3, 1, 0, 1, '天気が良いと\\n昼寝か釣りかで\\n迷っちまうな…', 0);
insert into room_unit_comments values (2654, 105601, 1, 4, 1, 0, 1, '大物が釣れたときの\\n快感は、他じゃ\\n味わえないね', 0);
insert into room_unit_comments values (2655, 105601, 1, 5, 1, 0, 1, 'ふあぁ～…\\n昼寝でもするか', 0);
insert into room_unit_comments values (2656, 105601, 1, 101, 4, 0, 1, 'ふふっ…\\nあの子、見た目より\\n根性あるんだね', 0);
insert into room_unit_comments values (2657, 105601, 1, 102, 8, 0, 1, 'あの子が強くなるには\\nどんな魚を食べさせて\\nあげればいいのやら…', 0);
insert into room_unit_comments values (2658, 105601, 2, 1, 1, 0, 1, '姉御って呼ぶんじゃ\\nないよ。からかうと\\nタダじゃおかないよ', 0);
insert into room_unit_comments values (2659, 105601, 2, 2, 1, 0, 1, '釣りのコツ？\\n何事も経験が大事だ\\n今から行くかい？', 0);
insert into room_unit_comments values (2660, 105601, 2, 3, 1, 0, 1, 'どうしたのさ？\\n助太刀が必要かい？\\nアタシにまかせときな', 0);
insert into room_unit_comments values (2661, 105601, 2, 4, 1, 0, 1, '困ってる人がいたら\\nまた力を貸しておくれ\\n頼りにしてるよ', 0);
insert into room_unit_comments values (2662, 105601, 2, 101, 4, 0, 1, 'なにか困りごとかい？\\nどうやら昼寝は\\nまた今度だね', 0);
insert into room_unit_comments values (2663, 105601, 2, 102, 8, 0, 1, 'よしよし！\\nお人好しのお前さんを\\n労ってあげるよ', 0);
insert into room_unit_comments values (2664, 105601, 2, 1, 1, 1, 1, 'おはよう、お前さん\\n魚屋は早起きでなきゃ\\nつとまらないよ？', 0);
insert into room_unit_comments values (2665, 105601, 2, 2, 1, 2, 1, '昼飯かい？\u3000今朝\\n仕入れた魚があるんだ\\n食べてみるかい？', 0);
insert into room_unit_comments values (2666, 105601, 2, 3, 1, 3, 1, '夜釣りにぴったりの\\n月が出てるよ\\nいい釣りが出来そうだ', 0);
insert into room_unit_comments values (2668, 105601, 3, 2, 1, 0, 1, 'コイツに座って\\nのんびり釣りが\\nできりゃいいのにな', 0);
insert into room_unit_comments values (2669, 105601, 3, 3, 1, 0, 1, 'よしよし…♪\\nおっと、かわいい物も\\nつい抱きしめちまうな', 0);
insert into room_unit_comments values (2670, 105601, 3, 4, 1, 0, 1, 'これで魚の臭いを\\n消せれば、猫も\\n寄らなくなるのかね', 0);
insert into room_unit_comments values (2671, 105601, 3, 5, 1, 0, 1, '冬場の釣りも\\nこれくらい暖かけりゃ\\nいいんだけどね', 0);
insert into room_unit_comments values (2673, 105601, 3, 7, 1, 0, 1, '腹が減っては\\n釣りもできぬ、ってな\\nまずは腹ごしらえだ', 0);
insert into room_unit_comments values (2674, 105601, 3, 8, 1, 0, 1, 'へぇ…こんな魚が\\nいたとは…いつか\\n釣りたいもんだね', 0);
insert into room_unit_comments values (2676, 101301, 1, 1, 1, 0, 1, '流石に室内で\\n魔法ぶっぱしたら\\n怒られるよねぇ', 0);
insert into room_unit_comments values (2677, 101301, 1, 2, 1, 0, 1, '可愛い女の子が\\nたくさんいる！\\nここは楽園か！？', 0);
insert into room_unit_comments values (2678, 101301, 1, 3, 1, 0, 1, 'みんなに漫画とか\\n勧めてみようかな！\\n布教用のがあるし！', 0);
insert into room_unit_comments values (2679, 101301, 1, 4, 1, 0, 1, 'わ、私一人の\\n部屋じゃないから\\n色々自重せねば！', 0);
insert into room_unit_comments values (2680, 101301, 1, 5, 1, 0, 1, '「ぬるぽ」\\n…くっ、\\n誰も反応なしか！', 0);
insert into room_unit_comments values (2681, 101301, 1, 101, 4, 0, 1, '次はどの漫画を\\n貸そうかなー♪', 0);
insert into room_unit_comments values (2682, 101301, 1, 102, 8, 0, 1, '次の定期巡回で\\nとっておきの店に\\n連れてってあげよう！', 0);
insert into room_unit_comments values (2683, 101301, 2, 1, 1, 0, 1, '君に似合いそうな\\n衣装を買ったよ！\\n君もいざ魔法少女に！', 0);
insert into room_unit_comments values (2684, 101301, 2, 2, 1, 0, 1, 'さあ！\\n暇なら定期巡回に\\nレッツラゴー！', 0);
insert into room_unit_comments values (2685, 101301, 2, 3, 1, 0, 1, '戦闘だけじゃなくて、\\n日常にも役立つ\\n魔法を習得したいね！', 0);
insert into room_unit_comments values (2686, 101301, 2, 4, 1, 0, 1, '新魔法思いついた！\\n私って天才！？', 0);
insert into room_unit_comments values (2687, 101301, 2, 101, 4, 0, 1, '決め台詞は超大事！\\n君の決め台詞も\\n私が考えてあげよう！', 0);
insert into room_unit_comments values (2688, 101301, 2, 102, 8, 0, 1, '私ってもしやリア充？\\n…そんなバカな！\\n非リア代表のはずが！', 0);
insert into room_unit_comments values (2689, 101301, 2, 1, 1, 1, 1, 'おはよー…\\n徹夜で本読んでたから\\nまだ眠い～', 0);
insert into room_unit_comments values (2690, 101301, 2, 2, 1, 2, 1, '昼飯食べて、\\n午後の定期巡回も\\n頑張りましょー！', 0);
insert into room_unit_comments values (2691, 101301, 2, 3, 1, 3, 1, '夜からが、\\nオタ活本番でしょ！', 0);
insert into room_unit_comments values (2693, 101301, 3, 2, 1, 0, 1, 'ふいー！\\nくつろいで本を読む！\\n最高だねー！', 0);
insert into room_unit_comments values (2694, 101301, 3, 3, 1, 0, 1, '君、可愛いね～♪\\n魔法少女の\\n使い魔みたい！', 0);
insert into room_unit_comments values (2695, 101301, 3, 4, 1, 0, 1, '良い匂いに\\n釣られてしまった…\\nまさか、孔明の罠！？', 0);
insert into room_unit_comments values (2696, 101301, 3, 5, 1, 0, 1, '暖かいけど、\\nここで本を読むのは\\nちょっち危ないかな', 0);
insert into room_unit_comments values (2698, 101301, 3, 7, 1, 0, 1, 'ウマ―！\\nこれの詳細きぼんぬ！', 0);
insert into room_unit_comments values (2699, 101301, 3, 8, 1, 0, 1, 'こ、古代語の本！？\\n現代語でおk…', 0);
insert into room_unit_comments values (2701, 190901, 1, 1, 1, 0, 1, 'ふふふっ♪\\n次はどんな悪戯を\\nしてやろうかしら♪', 0);
insert into room_unit_comments values (2702, 190901, 1, 2, 1, 0, 1, '幻影湖の霧を吸った\\n人間たちの\\nリアクションって、\\nサイコーよねぇ～♪', 0);
insert into room_unit_comments values (2703, 190901, 1, 3, 1, 0, 1, '室内だけとはいえ…\\n自由に動けるって、\\nやっぱりいいわ～♪', 0);
insert into room_unit_comments values (2704, 190901, 1, 4, 1, 0, 1, '改めて見ると良い\\n部屋ね…悪戯とか\\nしやすそうだしぃ♪', 0);
insert into room_unit_comments values (2705, 190901, 1, 5, 1, 0, 1, '私を封じていた部屋\\nなのに…急に居心地が\\n良くなったわね♪', 0);
insert into room_unit_comments values (2706, 190901, 2, 1, 1, 0, 1, 'あんたの頭、座り心地\\n良いわね…私専用の\\n椅子にしてあげる♪', 0);
insert into room_unit_comments values (2707, 190901, 2, 2, 1, 0, 1, '外は大変みたいねぇ…\\nまあ、私は好き勝手に\\nやらせてもらうわ♪', 0);
insert into room_unit_comments values (2708, 190901, 2, 3, 1, 0, 1, '顔に落書された？\\n誰か知らないけど、\\n悪いことする奴も\\nいるものねぇ～♪', 0);
insert into room_unit_comments values (2709, 190901, 2, 4, 1, 0, 1, 'フィオのやつ…\\nどこをウロチョロ\\nしてるのかしら？', 0);
insert into room_unit_comments values (2710, 190901, 2, 1, 1, 1, 1, '人間の朝は大変ねぇ…\\n私はその様を見ながら\\nゆっくりするわね♪', 0);
insert into room_unit_comments values (2711, 190901, 2, 2, 1, 2, 1, 'う～私も、お日様を\\n浴びながら、お外を\\nお散歩したーい！', 0);
insert into room_unit_comments values (2712, 190901, 2, 3, 1, 3, 1, 'この暗さ…閉じ込め\\nられていた時を\\n思い出すわね…', 0);
insert into room_unit_comments values (2714, 190901, 3, 2, 1, 0, 1, '悪戯しすぎて\\n疲れたから、ちょっと\\n休憩しよっと♪', 0);
insert into room_unit_comments values (2715, 190901, 3, 3, 1, 0, 1, 'ガイド妖精たる私が、\\nこんな造形物に\\n惹かれる…わけが……\\nかわいい♪', 0);
insert into room_unit_comments values (2716, 190901, 3, 4, 1, 0, 1, 'この香りを囮にして、\\n周りに悪戯を仕込む…\\n完璧ね♪', 0);
insert into room_unit_comments values (2717, 190901, 3, 5, 1, 0, 1, '不思議ねぇ…私は\\n温度とか関係ないのに\\n離れられないわ', 0);
insert into room_unit_comments values (2719, 190901, 3, 7, 1, 0, 1, '食事の必要がない体…\\nつまり、食べたければ\\n食べていいのよね～♪', 0);
insert into room_unit_comments values (2720, 190901, 3, 8, 1, 0, 1, 'へぇ…最近はこんな\\n悪戯もあるのねぇ…\\nあいつで試さないと♪', 0);
insert into room_unit_comments values (2722, 108401, 1, 1, 1, 0, 1, 'メリークリスマス！\\n歌で幸せを\\n届けます…！', 0);
insert into room_unit_comments values (2723, 108401, 1, 2, 1, 0, 1, 'あなたと出会えたのは\\n偶然ではなくて…\\nクリスマスの奇跡だと\\n思うんです', 0);
insert into room_unit_comments values (2724, 108401, 1, 3, 1, 0, 1, 'クリスマスは華やかで\\nつい子供のように\\nはしゃいでしまいます', 0);
insert into room_unit_comments values (2725, 108401, 1, 4, 1, 0, 1, '曲が書けるのは\\nあなたが側に\\nいてくれるからです…', 0);
insert into room_unit_comments values (2726, 108401, 1, 5, 1, 0, 1, '感動を与えられる歌…\\nあなたと一緒になら\\n生み出せるはず…', 0);
insert into room_unit_comments values (2727, 108401, 1, 101, 4, 0, 1, 'クリスマスの幸せを\\nあなたと\\n感じ合えたらな…', 0);
insert into room_unit_comments values (2728, 108401, 1, 102, 8, 0, 1, 'あなたの幸せを願った\\nクリスマスソング…\\nいつか披露しますね', 0);
insert into room_unit_comments values (2729, 108401, 2, 1, 1, 0, 1, 'みなさんの笑顔を\\n守りたいから…\\n私は歌い続けます', 0);
insert into room_unit_comments values (2730, 108401, 2, 2, 1, 0, 1, '歌を届ける\\nサンタさんに\\nなりたいな…', 0);
insert into room_unit_comments values (2731, 108401, 2, 3, 1, 0, 1, 'お暇でしたら\\nクリスマスのお祝いを\\nしませんか？', 0);
insert into room_unit_comments values (2732, 108401, 2, 4, 1, 0, 1, 'ステージに立つ前に\\n喉を整えないと…\\n発声練習は念入りに…', 0);
insert into room_unit_comments values (2733, 108401, 2, 101, 4, 0, 1, 'まわりはかわいい子\\nばっかりだけど…\\nこの服なら\\nアピールになるかな？', 0);
insert into room_unit_comments values (2734, 108401, 2, 102, 8, 0, 1, '歌でならいくらでも\\nあの人への気持ちを\\n込められるのに…', 0);
insert into room_unit_comments values (2735, 108401, 2, 1, 1, 1, 1, '今日も一日\\n幸せな歌で世界が\\n包まれますように…', 0);
insert into room_unit_comments values (2736, 108401, 2, 2, 1, 2, 1, 'お茶を飲みながら\\n好きな音楽を\\n語り合いませんか？', 0);
insert into room_unit_comments values (2737, 108401, 2, 3, 1, 3, 1, 'ふふ、寝かしつけの\\n子守唄を\\nお望みですか？', 0);
insert into room_unit_comments values (2739, 108401, 3, 2, 1, 0, 1, 'ふかふかですね\\n心地良すぎて\\n眠ってしまいそう…', 0);
insert into room_unit_comments values (2740, 108401, 3, 3, 1, 0, 1, '素敵…\\n優しい歌みたいに\\n気持ちが落ち着く…', 0);
insert into room_unit_comments values (2741, 108401, 3, 4, 1, 0, 1, 'インスピレーションが\\n溢れてくる…\\nいい曲が書けそう…', 0);
insert into room_unit_comments values (2742, 108401, 3, 5, 1, 0, 1, 'この光みたいに\\n灯火になるような\\n歌を歌いたい…', 0);
insert into room_unit_comments values (2744, 108401, 3, 7, 1, 0, 1, '喉の健康のためにも\\n食事はしっかり\\nとるようにしています', 0);
insert into room_unit_comments values (2745, 108401, 3, 8, 1, 0, 1, '物語には\\n曲作りのヒントが\\n詰まっているんです', 0);
insert into room_unit_comments values (2747, 108401, 3, 14, 1, 0, 1, '絵が飛び出してくる\\nなんて…精霊が宿って\\nいるのでしょうか？', 0);
insert into room_unit_comments values (2748, 108401, 3, 15, 1, 0, 1, 'か、可愛い…♪\\nちょっとだけ触っても\\nいいですよね…？', 0);
insert into room_unit_comments values (2749, 108501, 1, 1, 1, 0, 1, 'クリスマスでも、\\n演劇の練習は\\nしっかりやらないと！', 0);
insert into room_unit_comments values (2750, 108501, 1, 2, 1, 0, 1, 'あうぅ…\\nクリスマスの準備が\\n終わらないよぅ…', 0);
insert into room_unit_comments values (2751, 108501, 1, 3, 1, 0, 1, 'アヤネちゃんが\\n摘み食いしないように\\n見ておかないと…', 0);
insert into room_unit_comments values (2752, 108501, 1, 4, 1, 0, 1, 'サンタさんみたいに、\\n皆に笑顔で接する…\\nうぅ…私には無理ぃ…', 0);
insert into room_unit_comments values (2753, 108501, 1, 5, 1, 0, 1, '新しいお洋服～♪\\nスズメお姉ちゃんに\\nお礼をいわないと♪', 0);
insert into room_unit_comments values (2754, 108501, 1, 101, 4, 0, 1, 'お兄ちゃんの為に、\\nプレゼントを\\n用意しないと♪', 0);
insert into room_unit_comments values (2755, 108501, 1, 102, 8, 0, 1, 'クリスマス…\\n恋人の日…ひゃわっ！\\nわ、私ってば何を…！', 0);
insert into room_unit_comments values (2756, 108501, 2, 1, 1, 0, 1, 'メリー\\nクリスマスです、\\nお兄ちゃん♪', 0);
insert into room_unit_comments values (2757, 108501, 2, 2, 1, 0, 1, 'そ、そんなに\\n見られると…\\n恥ずかしいよぉ…', 0);
insert into room_unit_comments values (2758, 108501, 2, 3, 1, 0, 1, 'ひゃわぁっ！？\\n急に触られると、\\n驚くからやめてぇ…', 0);
insert into room_unit_comments values (2759, 108501, 2, 4, 1, 0, 1, 'あ…クリスマスの\\n準備を手伝って\\nくれるんですか？', 0);
insert into room_unit_comments values (2760, 108501, 2, 101, 4, 0, 1, 'お兄ちゃんと\\n過ごすクリスマス、\\n楽しみですぅ…♪', 0);
insert into room_unit_comments values (2761, 108501, 2, 102, 8, 0, 1, 'クリスマスはその…\\n二人で…あうぅ…\\nなんでもないですぅ…', 0);
insert into room_unit_comments values (2762, 108501, 2, 1, 1, 1, 1, 'うう…パーティーが\\n楽しみで、あんまり\\n眠れなかったよぅ…', 0);
insert into room_unit_comments values (2763, 108501, 2, 2, 1, 2, 1, 'ケーキを食べられなく\\nなっちゃうから、\\nお昼は軽めにしないと', 0);
insert into room_unit_comments values (2764, 108501, 2, 3, 1, 3, 1, 'ちょっと眠いけど…\\n今日は少しだけ\\n夜更かししたいです♪', 0);
insert into room_unit_comments values (2766, 108501, 3, 2, 1, 0, 1, 'ふかふかぁ…\\nクリスマスの準備中に\\n眠くなっちゃいますぅ', 0);
insert into room_unit_comments values (2767, 108501, 3, 3, 1, 0, 1, 'この子と一緒に\\nおままごとしたいな♪', 0);
insert into room_unit_comments values (2768, 108501, 3, 4, 1, 0, 1, 'いい匂い…♪\\nみんなで\\nアロマパーティー\\nしたいなぁ…♪', 0);
insert into room_unit_comments values (2769, 108501, 3, 5, 1, 0, 1, 'ぬっくぬく…♪\\nもう、ここから\\n離れたくないよぉ…♪', 0);
insert into room_unit_comments values (2771, 108501, 3, 7, 1, 0, 1, 'はむはむ…♪\\nクリスマスのお料理\\nより美味しいかも～♪', 0);
insert into room_unit_comments values (2772, 108501, 3, 8, 1, 0, 1, 'すごい…\\nクリスマスの\\n演劇って、\\nこんなにあるんだ…', 0);
insert into room_unit_comments values (2774, 108501, 3, 14, 1, 0, 1, 'すごい…まるで、\\nクリスマスの演劇を\\n観てるようですぅ…♪', 0);
insert into room_unit_comments values (2775, 108501, 3, 15, 1, 0, 1, 'とっても可愛いです♪\\nお芝居の相手役に\\nしたいなぁ…♪', 0);
insert into room_unit_comments values (2776, 108601, 1, 1, 1, 0, 1, '甘ぁいケーキも、\\nデッカイ七面鳥も、\\nぜーんぶ私のだー♪', 0);
insert into room_unit_comments values (2777, 108601, 1, 2, 1, 0, 1, '毎日が\\nクリスマスだったら\\nいいのにな～♪', 0);
insert into room_unit_comments values (2778, 108601, 1, 3, 1, 0, 1, 'プレゼントはあるし、\\n料理は美味しいし、\\nクリスマス最高ー♪', 0);
insert into room_unit_comments values (2779, 108601, 1, 4, 1, 0, 1, 'ここでぷうきちの\\nクリスマス一発芸♪\\n『無茶ぶりするな！』', 0);
insert into room_unit_comments values (2780, 108601, 1, 5, 1, 0, 1, 'ぷうきちがいつもより\\n重いかも…太ったの？\\n『衣装の重さだよ！』', 0);
insert into room_unit_comments values (2781, 108601, 1, 101, 4, 0, 1, 'お兄ちゃんが\\n一緒にいてくれると\\nクリスマス楽しいね♪', 0);
insert into room_unit_comments values (2782, 108601, 1, 102, 8, 0, 1, 'お兄ちゃんに抱きつく\\nと、なんだかドキドキ\\nする…なんでかな？', 0);
insert into room_unit_comments values (2783, 108601, 2, 1, 1, 0, 1, 'メリークリスマス♪\\nプレゼントは、\\nいつでも受付中だよ♪', 0);
insert into room_unit_comments values (2784, 108601, 2, 2, 1, 0, 1, 'このクマさん耳\\n可愛いでしょ♪\\nぷうきちと\\nお揃いなんだー♪', 0);
insert into room_unit_comments values (2785, 108601, 2, 3, 1, 0, 1, 'お兄ちゃん…私、\\n甘ぁいケーキが\\n食べたいなぁ…♪', 0);
insert into room_unit_comments values (2786, 108601, 2, 4, 1, 0, 1, 'クリスマスぷうきちは\\nぬくぬく感が凄いよ！\\nお兄ちゃんもさわる？', 0);
insert into room_unit_comments values (2787, 108601, 2, 101, 4, 0, 1, 'えへへ…お兄ちゃんの\\n手は、大きくて、\\n暖かくて大好き～♪', 0);
insert into room_unit_comments values (2788, 108601, 2, 102, 8, 0, 1, '来年のクリスマスも、\\nこうやって\\nお兄ちゃんに\\n甘えていたいな～♪', 0);
insert into room_unit_comments values (2789, 108601, 2, 1, 1, 1, 1, 'あれぇ…\\n私のケーキはぁ…？\\n『ちゃんと起きろ』', 0);
insert into room_unit_comments values (2790, 108601, 2, 2, 1, 2, 1, 'お昼はデッカイ\\n七面鳥が食べたーい♪\\n『夜まで我慢しろ』', 0);
insert into room_unit_comments values (2791, 108601, 2, 3, 1, 3, 1, '『もう寝る時間だぞ』\\nサンタさんが来る\\nまで起きてるぅ…', 0);
insert into room_unit_comments values (2793, 108601, 3, 2, 1, 0, 1, 'このふかふか具合…\\nぷうきち！\\n負けてられないよ！', 0);
insert into room_unit_comments values (2794, 108601, 3, 3, 1, 0, 1, 'この子、\\nすっごくかわいい～♪\\n『ライバル登場か！』', 0);
insert into room_unit_comments values (2795, 108601, 3, 4, 1, 0, 1, '良い匂い…あっ！\\nぷうきちにこの\\n匂いを移せば…！\\n『匂い袋にするな』', 0);
insert into room_unit_comments values (2796, 108601, 3, 5, 1, 0, 1, 'あったか～い♪\\nえへへ、ぷうきちも\\nあっためてあげる♪', 0);
insert into room_unit_comments values (2798, 108601, 3, 7, 1, 0, 1, 'ぷうきち！\u3000これ、\\nとってもおいしいよ♪\\n『食べすぎるなよ』', 0);
insert into room_unit_comments values (2799, 108601, 3, 8, 1, 0, 1, 'お、大人の私なら、\\nこれぐらい…読め…\\n『無理するな…』', 0);
insert into room_unit_comments values (2801, 108601, 3, 14, 1, 0, 1, '絵が飛び出す…\\nぷうきちに絵本を\\n入れれば、イタズラに\\n使えるかも…♪', 0);
insert into room_unit_comments values (2802, 108601, 3, 15, 1, 0, 1, 'か、可愛いけど…\\nぷうきちサンタの方が\\n可愛いんだからぁ…！', 0);
insert into room_unit_comments values (2803, 108901, 1, 1, 1, 0, 1, '着物も慣れると\\n動きやすいものさ', 0);
insert into room_unit_comments values (2804, 108901, 1, 2, 1, 0, 1, '鼻緒が緩んでしまった\\n下駄で修業は\\n無理があったかな…', 0);
insert into room_unit_comments values (2805, 108901, 1, 3, 1, 0, 1, '小腹が空いた…\\nユイが作った餅、\\nまだ食べられるかな？', 0);
insert into room_unit_comments values (2806, 108901, 1, 4, 1, 0, 1, '服装も変わったし\\nいつもと違う戦い方を\\n想定しないと…', 0);
insert into room_unit_comments values (2807, 108901, 1, 5, 1, 0, 1, '…ヒヨリは動きすぎて\\n着崩れしてないか\\n心配だ', 0);
insert into room_unit_comments values (2808, 108901, 1, 101, 4, 0, 1, 'これからもずっと\\n仲間と、彼と\\n一緒に…', 0);
insert into room_unit_comments values (2809, 108901, 1, 102, 8, 0, 1, '願いを叶えるために\\nもっと自分を\\n鍛えていかないと！', 0);
insert into room_unit_comments values (2810, 108901, 2, 1, 1, 0, 1, '頭の飾りがずれてた？\\nそうか、直してくれて\\nありがとう', 0);
insert into room_unit_comments values (2811, 108901, 2, 2, 1, 0, 1, '着物がそんなに\\n珍しい？\\nキミも着てみる？\\n…冗談だよ', 0);
insert into room_unit_comments values (2812, 108901, 2, 3, 1, 0, 1, '肩掛けの触り心地が\\n気に入った？\\nならもっと触る？', 0);
insert into room_unit_comments values (2813, 108901, 2, 4, 1, 0, 1, 'ああ、この刀？\\n釣り仲間に見繕って\\nもらったんだ', 0);
insert into room_unit_comments values (2814, 108901, 2, 101, 4, 0, 1, 'キミといると\\n気持ちが段々と\\n安らいでいくよ', 0);
insert into room_unit_comments values (2815, 108901, 2, 102, 8, 0, 1, 'キミは私の行く先を\\n照らしてくれる\\n光のような存在だよ', 0);
insert into room_unit_comments values (2816, 108901, 2, 1, 1, 1, 1, 'おはよう\\n朝の修行を始めるけど\\nキミもどう？', 0);
insert into room_unit_comments values (2817, 108901, 2, 2, 1, 2, 1, 'この時間に軽く\\n休憩をとるといい\\n能率がよくなるよ', 0);
insert into room_unit_comments values (2818, 108901, 2, 3, 1, 3, 1, 'もう夜か…\\n明日もまた頑張ろう\\nそれじゃ、おやすみ', 0);
insert into room_unit_comments values (2820, 108901, 3, 2, 1, 0, 1, '…疲れていたのかな\\nもう少しで眠る\\nところだった…', 0);
insert into room_unit_comments values (2821, 108901, 3, 3, 1, 0, 1, 'ふふっ、正月衣装を\\n着せてやるのも\\nよさそうだ', 0);
insert into room_unit_comments values (2822, 108901, 3, 4, 1, 0, 1, 'ふぅ…いい香りだ\\n慌ただしい日々から\\n心が解放される', 0);
insert into room_unit_comments values (2823, 108901, 3, 5, 1, 0, 1, 'この心地よさ…\\n寝てしまわないよう\\n気をつけないと', 0);
insert into room_unit_comments values (2825, 108901, 3, 7, 1, 0, 1, 'おいしいけど\\n帯がきつくなる前に\\n手を止めよう…', 0);
insert into room_unit_comments values (2826, 108901, 3, 8, 1, 0, 1, '外を出歩くのも\\nいいけど、中で\\n読書もありだな', 0);
insert into room_unit_comments values (2828, 108801, 1, 1, 1, 0, 1, '…騎士クンって\\nおせち料理で\\n何が好きなんだろう？', 0);
insert into room_unit_comments values (2829, 108801, 1, 2, 1, 0, 1, '着物でお掃除や\\nお洗濯するの\\n慣れてきた♪', 0);
insert into room_unit_comments values (2830, 108801, 1, 3, 1, 0, 1, '今年は\\nどんな福袋を\\n買おうかな…♪', 0);
insert into room_unit_comments values (2831, 108801, 1, 4, 1, 0, 1, 'お餅に使う調味料\\nみんなで違うから\\n色々用意しなきゃ', 0);
insert into room_unit_comments values (2832, 108801, 1, 5, 1, 0, 1, 'ほっぺがお餅みたいに\\nぷにぷに…\\n食べ過ぎちゃった…', 0);
insert into room_unit_comments values (2833, 108801, 1, 101, 4, 0, 1, '来年も、再来年も\\nみんなで一緒に\\n新年を迎えたいな', 0);
insert into room_unit_comments values (2834, 108801, 1, 102, 8, 0, 1, 'お願いです…\\nいつかこの気持ちが\\n伝わりますように…', 0);
insert into room_unit_comments values (2835, 108801, 2, 1, 1, 0, 1, '髪飾りが落ちそう？\\nじゃあ…騎士クン\\nつけ直してくれる？', 0);
insert into room_unit_comments values (2836, 108801, 2, 2, 1, 0, 1, '着物が着たいの？\\nじゃあ今度一緒に\\n買いに…行く？', 0);
insert into room_unit_comments values (2837, 108801, 2, 3, 1, 0, 1, 'あっ、騎士クン\\nお雑煮のお餅\\nいくつ入れたい？', 0);
insert into room_unit_comments values (2838, 108801, 2, 4, 1, 0, 1, '外、寒かったよね？\\nはいこれ。熱い甘粥\\n飲むと温まるよ', 0);
insert into room_unit_comments values (2839, 108801, 2, 101, 4, 0, 1, '今年は騎士クンと…\\nえっ？\u3000騎士クン！？\\nな、なんでもないよ！', 0);
insert into room_unit_comments values (2840, 108801, 2, 102, 8, 0, 1, '騎士クンの願い事\\nわたしが\\n叶えてあげたいな…', 0);
insert into room_unit_comments values (2841, 108801, 2, 1, 1, 1, 1, 'おはよう\\n太陽の光に当たると\\n元気が出るよ', 0);
insert into room_unit_comments values (2842, 108801, 2, 2, 1, 2, 1, 'お昼ごはん\\n作らなきゃ…\\n騎士クンも食べる？', 0);
insert into room_unit_comments values (2843, 108801, 2, 3, 1, 3, 1, '一日が終わるのは\\nあっという間だよね\\n一年も同じなのかな？', 0);
insert into room_unit_comments values (2845, 108801, 3, 2, 1, 0, 1, 'ふぅ…\\n帯も少し\\nゆるめちゃおう…', 0);
insert into room_unit_comments values (2846, 108801, 3, 3, 1, 0, 1, 'お正月用に\\n着物を縫って\\nあげたいな', 0);
insert into room_unit_comments values (2847, 108801, 3, 4, 1, 0, 1, 'これでお肌が\\n保湿出来たら\\nいいのになぁ', 0);
insert into room_unit_comments values (2848, 108801, 3, 5, 1, 0, 1, 'ん～…\\nぬくぬくしてて\\n動きたくないよ～', 0);
insert into room_unit_comments values (2850, 108801, 3, 7, 1, 0, 1, '…冬眠しないのに\\n熊さんみたいに\\n食べちゃいそう', 0);
insert into room_unit_comments values (2851, 108801, 3, 8, 1, 0, 1, '年末年始は\\n告白のチャンス…\\nむ、無理無理！', 0);
insert into room_unit_comments values (2853, 108701, 1, 1, 1, 0, 1, 'みんな忙しそう…\\n待っててね、\\nすぐ助けるから！', 0);
insert into room_unit_comments values (2854, 108701, 1, 2, 1, 0, 1, 'ユイちゃんと\\nレイさん…よし！\\nどっちも手伝おう！', 0);
insert into room_unit_comments values (2855, 108701, 1, 3, 1, 0, 1, 'あっ、着崩れてる！\\nわわっ、どうしよ！\\n帯が結べないよー！', 0);
insert into room_unit_comments values (2856, 108701, 1, 4, 1, 0, 1, '初詣楽しみー！\\n出店はどこから\\n行こうかな？', 0);
insert into room_unit_comments values (2857, 108701, 1, 5, 1, 0, 1, 'お正月だし\\nみんなで楽しく\\n遊んじゃおー！', 0);
insert into room_unit_comments values (2858, 108701, 1, 101, 4, 0, 1, 'うーん…\\n騎士くんはお正月\\n何してるんだろ…', 0);
insert into room_unit_comments values (2859, 108701, 1, 102, 8, 0, 1, 'ううぅー…\\n騎士くんを見てると\\nドキってなっちゃう…', 0);
insert into room_unit_comments values (2860, 108701, 2, 1, 1, 0, 1, 'あたしから\\nおいしそうな匂い？\\nくんくん…ソースだ！', 0);
insert into room_unit_comments values (2861, 108701, 2, 2, 1, 0, 1, 'ヘアピンが…\\n拾ってくれたんだ！\\nありがとう騎士くん！', 0);
insert into room_unit_comments values (2862, 108701, 2, 3, 1, 0, 1, '髪飾りがかわいい？\\n耳の近く触りたい？\\n…優しくね？\u3000', 0);
insert into room_unit_comments values (2863, 108701, 2, 4, 1, 0, 1, 'グローブで食べるの\\n大変そう？\u3000特訓して\\n今はお箸も使えるよ！', 0);
insert into room_unit_comments values (2864, 108701, 2, 101, 4, 0, 1, 'えっ、ほっぺが赤い？\\nそうかな…？\\n気のせい気のせい！', 0);
insert into room_unit_comments values (2865, 108701, 2, 102, 8, 0, 1, '騎士くんといるとね…\\nなんでもない！\\nまだ内緒っ！', 0);
insert into room_unit_comments values (2866, 108701, 2, 1, 1, 1, 1, 'おはよー！\\n今日も明るく元気に\\nがんばろー！', 0);
insert into room_unit_comments values (2867, 108701, 2, 2, 1, 2, 1, 'お腹すいてない？\\n一緒にご飯食べよ！\\n何にしようかなー♪', 0);
insert into room_unit_comments values (2868, 108701, 2, 3, 1, 3, 1, '今日もいっぱい\\nがんばったー！\\nいつも？\u3000…そう？', 0);
insert into room_unit_comments values (2870, 108701, 3, 2, 1, 0, 1, '休憩休憩♪\\nちょっと休んで\\nガンガン動くぞー！', 0);
insert into room_unit_comments values (2871, 108701, 3, 3, 1, 0, 1, 'かわいい♪\\nでも、壊しそうで\\nちょっと怖い…', 0);
insert into room_unit_comments values (2872, 108701, 3, 4, 1, 0, 1, 'はぁー♪\\nいい香りー…\\n気分スッキリ♪', 0);
insert into room_unit_comments values (2873, 108701, 3, 5, 1, 0, 1, 'ほっこりしてて\\nぬくぬく…\\n丸まりたい…', 0);
insert into room_unit_comments values (2875, 108701, 3, 7, 1, 0, 1, 'ど、どうしよう…！\\n手が、止まんないよ！', 0);
insert into room_unit_comments values (2876, 108701, 3, 8, 1, 0, 1, 'へー…お年玉って\\n昔はお餅だったんだ\\n…今のほうがいいね', 0);
insert into room_unit_comments values (2878, 109001, 1, 1, 1, 0, 1, '甘いチョコの香りを\\n漂わせて…ふふっ\\nこれで準備万端ですわ', 0);
insert into room_unit_comments values (2879, 109001, 1, 2, 1, 0, 1, 'ここを私のチョコで\\n埋め尽くしますわ', 0);
insert into room_unit_comments values (2880, 109001, 1, 3, 1, 0, 1, 'エプロンを着て\\nあの方を待つ私…\\nまるで…クスクス', 0);
insert into room_unit_comments values (2881, 109001, 1, 4, 1, 0, 1, 'キッチンはどこかしら\\n今のうちに作って\\nおきたいものが…', 0);
insert into room_unit_comments values (2882, 109001, 1, 5, 1, 0, 1, 'あのお方を私のチョコ\\nなしでは生きられない\\n体に…ふふっ\\n冗談ですわ…', 0);
insert into room_unit_comments values (2883, 109001, 1, 101, 4, 0, 1, 'このチョコは運命の味\\n一口食べれば私の虜…\\nそれも運命ですわ…', 0);
insert into room_unit_comments values (2884, 109001, 1, 102, 8, 0, 1, '私ともあろうものが\\nなんだかドキドキして\\nきましたわ…', 0);
insert into room_unit_comments values (2885, 109001, 2, 1, 1, 0, 1, 'あなた様。私に\\n隠しているものなど\\nありませんよね…？', 0);
insert into room_unit_comments values (2886, 109001, 2, 2, 1, 0, 1, '私の手作りチョコです\\n味の方にも自信\\nありますのよ？', 0);
insert into room_unit_comments values (2887, 109001, 2, 3, 1, 0, 1, '少し苦いのは\\nチョコがビターなだけ\\nお気になさらず…', 0);
insert into room_unit_comments values (2888, 109001, 2, 4, 1, 0, 1, '解毒薬はどこに\\nいれたかしら…？', 0);
insert into room_unit_comments values (2889, 109001, 2, 101, 4, 0, 1, '運命で結ばれている\\nあなた様と私…\\nチョコも特別でないと\\nいけませんわ', 0);
insert into room_unit_comments values (2890, 109001, 2, 102, 8, 0, 1, 'チョコを食べた後は\\nメインディッシュ…\\nさぁ、私を召し上がれ', 0);
insert into room_unit_comments values (2891, 109001, 2, 1, 1, 1, 1, '目覚めのチョコですわ\\nすっきり目が覚めます\\nしばらく眠れなく\\nなりますけど…', 0);
insert into room_unit_comments values (2892, 109001, 2, 2, 1, 2, 1, 'おやつのチョコですわ\\nデザートにどうぞ\\n空腹を感じなく\\nなりますわ…クスクス', 0);
insert into room_unit_comments values (2893, 109001, 2, 3, 1, 3, 1, 'お夜食のチョコですわ\\nとてもよく眠れます\\nさ、溶けてしまう前に', 0);
insert into room_unit_comments values (2895, 109001, 3, 2, 1, 0, 1, 'この心地良さ…\\n参考になりますわ\\n次の薬は…クスクス', 0);
insert into room_unit_comments values (2896, 109001, 3, 3, 1, 0, 1, 'この中、何か\\n入りそうですわね\\n…チョコレート、とか', 0);
insert into room_unit_comments values (2897, 109001, 3, 4, 1, 0, 1, 'いい香り…この香りと\\n同じものを調合して\\n私も持っていたい', 0);
insert into room_unit_comments values (2898, 109001, 3, 5, 1, 0, 1, 'この暖かさ…\\nチョコが溶けないよう\\n気を付けなくては', 0);
insert into room_unit_comments values (2900, 109001, 3, 7, 1, 0, 1, 'いい味をしていますわ\\n私も腕を磨きましょう\\n料理と、調合の腕を…', 0);
insert into room_unit_comments values (2901, 109001, 3, 8, 1, 0, 1, '勉強になりますわ\\n知識はいくらあっても\\n困りませんもの\\n特に、人体の知識は…', 0);
insert into room_unit_comments values (2903, 109101, 1, 1, 1, 0, 1, '弟くんのことを\\n考えると\\nあっという間に時間が\\n過ぎちゃう…', 0);
insert into room_unit_comments values (2904, 109101, 1, 2, 1, 0, 1, 'お姉ちゃんの\\n元気の源は、弟くんの\\n喜ぶ顔なんだから♪', 0);
insert into room_unit_comments values (2905, 109101, 1, 3, 1, 0, 1, '弟くんと会ったら\\nまずは抱きしめて\\nそれからそれから…', 0);
insert into room_unit_comments values (2906, 109101, 1, 4, 1, 0, 1, '今日のお姉ちゃんは\\n昨日のお姉ちゃんより\\nいいお姉ちゃんだよ♪', 0);
insert into room_unit_comments values (2907, 109101, 1, 5, 1, 0, 1, '弟くん、もっと\\nお姉ちゃんに\\n甘えてもいいのに♪', 0);
insert into room_unit_comments values (2908, 109101, 1, 101, 4, 0, 1, 'お姉ちゃんのチョコ\\n食べさせてあげたい…', 0);
insert into room_unit_comments values (2909, 109101, 1, 102, 8, 0, 1, 'ドキドキしてきた…\\nお姉ちゃんなのに\\nどうしてかなぁ…', 0);
insert into room_unit_comments values (2910, 109101, 2, 1, 1, 0, 1, 'お姉ちゃんを\\n好きなだけ\\n触っていいよ♪', 0);
insert into room_unit_comments values (2911, 109101, 2, 2, 1, 0, 1, 'そんなにお姉ちゃんの\\nチョコが欲しいの？\\n食いしん坊さん♪', 0);
insert into room_unit_comments values (2912, 109101, 2, 3, 1, 0, 1, 'ナデナデするのは\\nお姉ちゃんの仕事！', 0);
insert into room_unit_comments values (2913, 109101, 2, 4, 1, 0, 1, 'ありがとうなんて…\\nお姉ちゃんとして\\n当たり前だよ♪', 0);
insert into room_unit_comments values (2914, 109101, 2, 101, 4, 0, 1, 'どうしたのかなっ？\\nお姉ちゃんはいつでも\\n弟くんのそばにいるよ', 0);
insert into room_unit_comments values (2915, 109101, 2, 102, 8, 0, 1, 'チョコを作ったよ\\n隠し味は、たくさんの\\n弟くんへの愛情♪', 0);
insert into room_unit_comments values (2916, 109101, 2, 1, 1, 1, 1, 'おはよ。お姉ちゃんが\\n顔を洗うの\\n手伝ってあげるね♪', 0);
insert into room_unit_comments values (2917, 109101, 2, 2, 1, 2, 1, 'ご飯を食べたら\\n眠たくなるよね…\\nお姉ちゃんと寝る？', 0);
insert into room_unit_comments values (2918, 109101, 2, 3, 1, 3, 1, 'そろそろ眠くなった？\\nお姉ちゃんが添い寝\\nしてあげるね♪', 0);
insert into room_unit_comments values (2920, 109101, 3, 2, 1, 0, 1, 'この気持ちよさは\\nお姉ちゃんも太鼓判♪', 0);
insert into room_unit_comments values (2921, 109101, 3, 3, 1, 0, 1, 'このかわいさは\\nお姉ちゃんも大満足♪', 0);
insert into room_unit_comments values (2922, 109101, 3, 4, 1, 0, 1, 'この香り、チョコに\\n使えるかな…？', 0);
insert into room_unit_comments values (2923, 109101, 3, 5, 1, 0, 1, '弟くんと一緒に\\nぬくぬくしたいな…♪', 0);
insert into room_unit_comments values (2925, 109101, 3, 7, 1, 0, 1, 'すごくおいしいねっ♪\\nあとで運動しなきゃ…', 0);
insert into room_unit_comments values (2926, 109101, 3, 8, 1, 0, 1, '本を読んでる\\n知的なお姉ちゃん\\n素敵でしょ♪', 0);
insert into room_unit_comments values (2928, 106101, 1, 1, 1, 0, 1, 'アタシって…\\nここにいても\\nいいのか…？', 0);
insert into room_unit_comments values (2929, 106101, 1, 2, 1, 0, 1, 'ちゃんとした建物に\\nいるのが久しぶりで\\nそわそわする…', 0);
insert into room_unit_comments values (2930, 106101, 1, 3, 1, 0, 1, 'ここで天楼覇断剣\\n出す練習したら\\nアイツら怒るかな？', 0);
insert into room_unit_comments values (2931, 106101, 1, 4, 1, 0, 1, 'ギルドハウスか…\\nこういう隠れ家\\n欲しかったんだよな', 0);
insert into room_unit_comments values (2932, 106101, 1, 5, 1, 0, 1, 'めちゃくちゃ暇だ…\\n…なんかやること\\nないのか？', 0);
insert into room_unit_comments values (2933, 106101, 1, 101, 4, 0, 1, 'みんなが早く\\nアタシのこと\\n思い出さないかな', 0);
insert into room_unit_comments values (2934, 106101, 1, 102, 8, 0, 1, 'アイツはいいヤツだし\\n戦う時はアタシも\\n協力してやるか！', 0);
insert into room_unit_comments values (2935, 106101, 2, 1, 1, 0, 1, 'ちゃんはいらん！\\nノウェムでいい！\\n分かったか？', 0);
insert into room_unit_comments values (2936, 106101, 2, 2, 1, 0, 1, 'どうした？\\n戦うのか！？\\n…なんだ、違うのか', 0);
insert into room_unit_comments values (2937, 106101, 2, 3, 1, 0, 1, '身長のことは\\nあんまり言うな！\\n気にしてるからな！', 0);
insert into room_unit_comments values (2938, 106101, 2, 4, 1, 0, 1, 'アタシの戦い方は\\nなんでもアリだ！\\nだから見習うなよ？', 0);
insert into room_unit_comments values (2939, 106101, 2, 101, 4, 0, 1, 'オマエとの思い出か…\\n敵として戦ってばっか\\nだったな！', 0);
insert into room_unit_comments values (2940, 106101, 2, 102, 8, 0, 1, 'オマエやオクトーと\\n一緒に、あちこち\\nいってみたいんだ！', 0);
insert into room_unit_comments values (2941, 106101, 2, 1, 1, 1, 1, 'よっ！\u3000おはよう！\\n朝だぞー！\\n起きてるかー？', 0);
insert into room_unit_comments values (2942, 106101, 2, 2, 1, 2, 1, '腹減ったー！\\n飯食うぞ、飯！\\nオマエも行くよな？', 0);
insert into room_unit_comments values (2943, 106101, 2, 3, 1, 3, 1, 'ふわぁ…\\nまだ起きてんのか？\\n元気だなオマエ…', 0);
insert into room_unit_comments values (2945, 106101, 3, 2, 1, 0, 1, 'ふぃ～…\\n極楽極楽…', 0);
insert into room_unit_comments values (2946, 106101, 3, 3, 1, 0, 1, 'おいオマエ！\\n寝技の練習に\\n付き合ってもらうぞ', 0);
insert into room_unit_comments values (2947, 106101, 3, 4, 1, 0, 1, 'くんくん…\\nたまにはこういうのも\\n悪くないかもな', 0);
insert into room_unit_comments values (2948, 106101, 3, 5, 1, 0, 1, 'あー…\\nもっと前にコイツと\\n出会いたかった…', 0);
insert into room_unit_comments values (2950, 106101, 3, 7, 1, 0, 1, 'VRでも飯はうまい！\\n腹が減るのはちゃんと\\n生きてる気がするな', 0);
insert into room_unit_comments values (2951, 106101, 3, 8, 1, 0, 1, '勉強は大事だな！\\nうん！…だめだ！\\n全然わからん！', 0);
insert into room_unit_comments values (2953, 101401, 1, 1, 1, 0, 1, '探偵というのは\\n謎を追い求める\\n生き物なのさっ！', 0);
insert into room_unit_comments values (2954, 101401, 1, 2, 1, 0, 1, '事件のオチは\\n往々にして\\n取るに足らないものさ', 0);
insert into room_unit_comments values (2955, 101401, 1, 3, 1, 0, 1, '読書で得る知識が\\n探偵の\\n血肉になるんだよ', 0);
insert into room_unit_comments values (2956, 101401, 1, 4, 1, 0, 1, 'この前の\\n捜査資料…\\nどこにあったかな？', 0);
insert into room_unit_comments values (2957, 101401, 1, 5, 1, 0, 1, 'どんな小さな謎も\\n私にとっては\\n宝石みたいなものさ！', 0);
insert into room_unit_comments values (2958, 101401, 1, 101, 4, 0, 1, '助手くんと一緒だと\\nよい発想が浮かぶ…\\nどうしてだろうね？', 0);
insert into room_unit_comments values (2959, 101401, 1, 102, 8, 0, 1, '助手くんの好きな\\nタイプって…\\nす、推理してみるっ！', 0);
insert into room_unit_comments values (2960, 101401, 2, 1, 1, 0, 1, '珈琲、淹れたてだよ\\n一杯どうだい？', 0);
insert into room_unit_comments values (2961, 101401, 2, 2, 1, 0, 1, '事件の考察を\\nまとめてみたんだけど\\n聞いてくれるかな？', 0);
insert into room_unit_comments values (2962, 101401, 2, 3, 1, 0, 1, '小さな違和感を\\n見逃さない…\\n探偵の心得だよ', 0);
insert into room_unit_comments values (2963, 101401, 2, 4, 1, 0, 1, '機能的な手帳とペン…\\nこの仕事には\\n欠かせないね！', 0);
insert into room_unit_comments values (2964, 101401, 2, 101, 4, 0, 1, '助手くんに\\n珈琲…\\n淹れてほしいなぁ～', 0);
insert into room_unit_comments values (2965, 101401, 2, 102, 8, 0, 1, '助手くんは\\n私にとって\\n最高の相棒だよ☆', 0);
insert into room_unit_comments values (2966, 101401, 2, 1, 1, 1, 1, '朝はいいひらめきが\\n得られるんだ…\\nさあ捜査を始めよう！', 0);
insert into room_unit_comments values (2967, 101401, 2, 2, 1, 2, 1, '一休みしたら\\n推理の答え合わせを\\nしてみようか？', 0);
insert into room_unit_comments values (2968, 101401, 2, 3, 1, 3, 1, '夜の張りこみかい？\\nなら私も\\n同行させてほしいな！', 0);
insert into room_unit_comments values (2970, 101401, 3, 2, 1, 0, 1, '脳を酷使した後は\\nゆっくり休む…\\nこれも仕事だよ？', 0);
insert into room_unit_comments values (2971, 101401, 3, 3, 1, 0, 1, 'この愛らしさ…\\n要捜査対象だね！', 0);
insert into room_unit_comments values (2972, 101401, 3, 4, 1, 0, 1, '思考が活性化される\\n素敵な香りだね…', 0);
insert into room_unit_comments values (2973, 101401, 3, 5, 1, 0, 1, 'くぅ、心地よすぎる…\\n今だけは捜査も\\n一休みだね♪', 0);
insert into room_unit_comments values (2975, 101401, 3, 7, 1, 0, 1, 'いっぱい食べて\\nいっぱい考える\\n探偵の本分だね！', 0);
insert into room_unit_comments values (2976, 101401, 3, 8, 1, 0, 1, '探偵だからね\\nミステリには\\n一家言あるんだ', 0);
insert into room_unit_comments values (2978, 105501, 1, 1, 1, 0, 1, '先輩、素敵だなぁ…\\nもっと近づければ\\nいいのに…', 0);
insert into room_unit_comments values (2979, 105501, 1, 2, 1, 0, 1, 'せ、先輩がいた部屋！\\n私には刺激が強い…', 0);
insert into room_unit_comments values (2980, 105501, 1, 3, 1, 0, 1, '先輩を観察しやすい\\n場所はあるかな…', 0);
insert into room_unit_comments values (2981, 105501, 1, 4, 1, 0, 1, 'バ、バイト代出たし、\\nせ、先輩をご飯とかに\\n誘いたい…な', 0);
insert into room_unit_comments values (2982, 105501, 1, 5, 1, 0, 1, '今頃先輩は\\nあの辺かな…？\\n見に行ってみよう！', 0);
insert into room_unit_comments values (2983, 105501, 1, 101, 4, 0, 1, '私と先輩の出会いって\\n思い返すと少女漫画\\nみたい…えへへ', 0);
insert into room_unit_comments values (2984, 105501, 1, 102, 8, 0, 1, 'せ、先輩になら\\n観察されてもいいなぁ', 0);
insert into room_unit_comments values (2985, 105501, 2, 1, 1, 0, 1, 'バイト先に新しい子が\\n入って来たんです…\\nわ、私、先輩です♪', 0);
insert into room_unit_comments values (2986, 105501, 2, 2, 1, 0, 1, 'せ、先輩…？\\nえっと、あの、その、\\nあわわわわ…！', 0);
insert into room_unit_comments values (2987, 105501, 2, 3, 1, 0, 1, 'えへへ…えへへ～\\nせ、先輩から\\n話しかけてくれました', 0);
insert into room_unit_comments values (2988, 105501, 2, 4, 1, 0, 1, 'ま、また…\\n先輩と一緒に\\nバイトしたい…です', 0);
insert into room_unit_comments values (2989, 105501, 2, 101, 4, 0, 1, '私と先輩が同じ空間に\\n…ゆ、夢みたいです', 0);
insert into room_unit_comments values (2990, 105501, 2, 102, 8, 0, 1, 'せ、先輩のそばに\\n居られて、私\\n今、とっても\\n幸せです…', 0);
insert into room_unit_comments values (2991, 105501, 2, 1, 1, 1, 1, 'せ、先輩…！\\nおひゃっ！\\nおはようございます！', 0);
insert into room_unit_comments values (2992, 105501, 2, 2, 1, 2, 1, '先輩ランチに\\n行きましょう！\\nよし、練習はバッチリ', 0);
insert into room_unit_comments values (2993, 105501, 2, 3, 1, 3, 1, 'あ、せ、先輩。\\nえと、そ、外…\\nもう真っ暗ですねぇ', 0);
insert into room_unit_comments values (2995, 105501, 3, 2, 1, 0, 1, 'こ、ここで先輩も\\n休んだり…はっ！\\nわ、私ったらなにを！', 0);
insert into room_unit_comments values (2996, 105501, 3, 3, 1, 0, 1, 'かわいいですねー\\n君も一緒に、\\n先輩を観察する？', 0);
insert into room_unit_comments values (2997, 105501, 3, 4, 1, 0, 1, 'ここから先輩の\\n香りがすればなあ', 0);
insert into room_unit_comments values (2998, 105501, 3, 5, 1, 0, 1, '先輩と一緒に\\nぬくぬくできたら\\n最高なんだけどなぁ', 0);
insert into room_unit_comments values (3000, 105501, 3, 7, 1, 0, 1, 'おいし～\\nこれは\\n先輩も好きな味かな', 0);
insert into room_unit_comments values (3001, 105501, 3, 8, 1, 0, 1, 'す、好きな人に\\n近づく方法…', 0);
insert into room_unit_comments values (3003, 109201, 1, 1, 1, 0, 1, '私の力は、大切な\\n人たちを護るために\\n役立てたいんだ', 0);
insert into room_unit_comments values (3004, 109201, 1, 2, 1, 0, 1, 'きれいな景色と\\n美味しいご飯！\\nこの世界も素敵だね', 0);
insert into room_unit_comments values (3005, 109201, 1, 3, 1, 0, 1, 'この世界のみんなとも\\nもっと仲良く\\nなりたいな！', 0);
insert into room_unit_comments values (3006, 109201, 1, 4, 1, 0, 1, 'わー！\\nあれもこれも\\n気になっちゃうな！', 0);
insert into room_unit_comments values (3007, 109201, 1, 5, 1, 0, 1, 'しっかりしなきゃって\\n思ってても、\\nグレアといるとつい\\n甘えちゃうんだよね～', 0);
insert into room_unit_comments values (3008, 109201, 1, 101, 4, 0, 1, '違う世界でも\\n友だちができて、\\nすごくうれしいよ！', 0);
insert into room_unit_comments values (3009, 109201, 1, 102, 8, 0, 1, 'みんなとも一緒に\\n授業とか受けたいな～\\n絶対楽しそうだもん！', 0);
insert into room_unit_comments values (3010, 109201, 2, 1, 1, 0, 1, '歩き方がきれい？\\nえへへ、そうかな…？', 0);
insert into room_unit_comments values (3011, 109201, 2, 2, 1, 0, 1, '勉強は好きだよ！\\n知識が増えていくのは\\nやっぱり楽しいから', 0);
insert into room_unit_comments values (3012, 109201, 2, 3, 1, 0, 1, '私たちの国マナリアは\\n人々の間に魔法が\\n伝えられた、その\\n始まりの地なんだ！', 0);
insert into room_unit_comments values (3013, 109201, 2, 4, 1, 0, 1, 'この部屋にも、\\nもっとたくさん本棚が\\n増えないかな～…？', 0);
insert into room_unit_comments values (3014, 109201, 2, 101, 4, 0, 1, 'あなたも魔法、\\n覚えてみる？\\n私、教えるよ！', 0);
insert into room_unit_comments values (3015, 109201, 2, 102, 8, 0, 1, 'お茶の時間に\\nしたいな～…\\n一緒にどう？', 0);
insert into room_unit_comments values (3016, 109201, 2, 1, 1, 1, 1, 'おはようっ！\\n今日も素敵な\\n一日にしようね！', 0);
insert into room_unit_comments values (3017, 109201, 2, 2, 1, 2, 1, 'お昼ご飯は\\nちゃんと食べた？\\n午後も頑張ろうね！', 0);
insert into room_unit_comments values (3018, 109201, 2, 3, 1, 3, 1, 'つい本の続きが\\n気になって、夜更かし\\nしちゃうんだよね～…', 0);
insert into room_unit_comments values (3020, 109201, 3, 2, 1, 0, 1, 'はぁ、気持ちいい～…\\nちょっとだけ\\n眠っちゃおうかな…', 0);
insert into room_unit_comments values (3021, 109201, 3, 3, 1, 0, 1, 'わあ、これ可愛い！\\nグレアにも見せて\\nあげたいな', 0);
insert into room_unit_comments values (3022, 109201, 3, 4, 1, 0, 1, 'いい香り～！\\nなんだか気持ちが\\n落ち着くね', 0);
insert into room_unit_comments values (3023, 109201, 3, 5, 1, 0, 1, 'あぁ、あったかくて\\n幸せ～♪\u3000身体が\\nポカポカしてきたよ！', 0);
insert into room_unit_comments values (3025, 109201, 3, 7, 1, 0, 1, 'こ、これ美味し～！\\n止められないよー！', 0);
insert into room_unit_comments values (3026, 109201, 3, 8, 1, 0, 1, 'ふんふん…\\n…はっ！\u3000む、夢中に\\nなっちゃってた…', 0);
insert into room_unit_comments values (3028, 109301, 1, 1, 1, 0, 1, '新しい建物に入ると\\n必ず一度は迷子に\\nなっちゃうですよ…', 0);
insert into room_unit_comments values (3029, 109301, 1, 2, 1, 0, 1, 'おやつはどこですか？\\nお腹が空いて\\nきちゃったですぅ', 0);
insert into room_unit_comments values (3030, 109301, 1, 3, 1, 0, 1, '宿題、７つぐらい\\n出しそびれたですけど\\nまあ大丈夫ですぅ！', 0);
insert into room_unit_comments values (3031, 109301, 1, 4, 1, 0, 1, '不思議なこと\\nばかりですけど…\\nまぁ大丈夫です！\\nこれもせいしゅんです', 0);
insert into room_unit_comments values (3032, 109301, 1, 5, 1, 0, 1, 'なにか面白そうなもの\\nないですかね～？', 0);
insert into room_unit_comments values (3033, 109301, 1, 101, 4, 0, 1, 'ここのみんなとも\\nもうお友だちですぅ！', 0);
insert into room_unit_comments values (3034, 109301, 1, 102, 8, 0, 1, 'おなかが減ったです…', 0);
insert into room_unit_comments values (3035, 109301, 2, 1, 1, 0, 1, 'ごはんも美味しいし\\nここはいいところです\\nルゥは幸せですぅ！', 0);
insert into room_unit_comments values (3036, 109301, 2, 2, 1, 0, 1, '魔法の話ですか？\\nそれはアンせんぱいに\\n聞いてほしいですぅ…', 0);
insert into room_unit_comments values (3037, 109301, 2, 3, 1, 0, 1, 'あなたもお勉強\\n苦手ですか？', 0);
insert into room_unit_comments values (3038, 109301, 2, 4, 1, 0, 1, 'ルゥの帽子、\\nかわいいです？\\nお気に入りですぅ♪', 0);
insert into room_unit_comments values (3039, 109301, 2, 101, 4, 0, 1, 'お友だちいっぱいで、\\nルゥはうれしいです♪', 0);
insert into room_unit_comments values (3040, 109301, 2, 102, 8, 0, 1, '一緒にお勉強…！？\\nぐえぇ、イヤですぅ！', 0);
insert into room_unit_comments values (3041, 109301, 2, 1, 1, 1, 1, '朝ですねぇ…ふわわ…\\nルゥはまだ夢の中に\\nいたいですぅ…', 0);
insert into room_unit_comments values (3042, 109301, 2, 2, 1, 2, 1, '午後もいっぱい\\n遊ぶですよ～！', 0);
insert into room_unit_comments values (3043, 109301, 2, 3, 1, 3, 1, '夜ふかしって\\nドキドキするです！\\nせいしゅんですぅ！', 0);
insert into room_unit_comments values (3045, 109301, 3, 2, 1, 0, 1, 'ふかふかですぅ～♪\\nおひるねが\\nしたくなるですぅ！', 0);
insert into room_unit_comments values (3046, 109301, 3, 3, 1, 0, 1, 'これふかふかですぅ！\\n机でうとうとする時の\\n枕によさそうですぅ', 0);
insert into room_unit_comments values (3047, 109301, 3, 4, 1, 0, 1, 'ふぁぁ、いいにおい…\\nなんだか気持ちが\\nよくなってきたですぅ', 0);
insert into room_unit_comments values (3048, 109301, 3, 5, 1, 0, 1, 'ぽっかぽかですぅ～！\\nあったまったら\\nまた遊びにいくですぅ', 0);
insert into room_unit_comments values (3050, 109301, 3, 7, 1, 0, 1, 'お、おいしいですぅ！\\n全部ルゥに\\nくださいですぅ！', 0);
insert into room_unit_comments values (3051, 109301, 3, 8, 1, 0, 1, '本は…読むと、\\nすぐ眠気がぁ…\\n…ぐぅ…', 0);
insert into room_unit_comments values (3053, 109401, 1, 1, 1, 0, 1, 'ピアノ…\\nどこかにないかな？', 0);
insert into room_unit_comments values (3054, 109401, 1, 2, 1, 0, 1, 'ふぅ…\\n落ち着くな…', 0);
insert into room_unit_comments values (3055, 109401, 1, 3, 1, 0, 1, 'マナリアはいつも\\n賑やかなんだ…', 0);
insert into room_unit_comments values (3056, 109401, 1, 4, 1, 0, 1, 'みんな…\\n今頃何してるかな？', 0);
insert into room_unit_comments values (3057, 109401, 1, 5, 1, 0, 1, 'まさか違う世界に\\n来ちゃうなんて…\\nびっくりだよね…', 0);
insert into room_unit_comments values (3058, 109401, 1, 101, 4, 0, 1, '人と話すのは\\n得意じゃないな…', 0);
insert into room_unit_comments values (3059, 109401, 1, 102, 8, 0, 1, 'ここのみんなと一緒に\\n学院に通えたら…\\nちょっと面白いかも', 0);
insert into room_unit_comments values (3060, 109401, 2, 1, 1, 0, 1, 'やっぱり、私の翼や\\n尻尾…気になる？', 0);
insert into room_unit_comments values (3061, 109401, 2, 2, 1, 0, 1, '一番得意なのは、\\nやっぱり炎魔法かな…\\n加減は難しいけど…', 0);
insert into room_unit_comments values (3062, 109401, 2, 3, 1, 0, 1, '私の故郷は竜の国…\\n険しい山脈を\\n越えた先にあるんだ', 0);
insert into room_unit_comments values (3063, 109401, 2, 4, 1, 0, 1, 'アン…？\\nあっ、ご、ごめんね！\\n間違えちゃった…', 0);
insert into room_unit_comments values (3064, 109401, 2, 101, 4, 0, 1, 'ふん…ふん…♪\\n…わっ！\\n今の、聞いてた…？\\nは、恥ずかしい…', 0);
insert into room_unit_comments values (3065, 109401, 2, 102, 8, 0, 1, '私に手伝えること、\\nなにかある…？\\nなんでも言ってね', 0);
insert into room_unit_comments values (3066, 109401, 2, 1, 1, 1, 1, '朝の空気って\\nすごく\\n静かで透き通ってて…\\nなんだか落ち着くよね', 0);
insert into room_unit_comments values (3067, 109401, 2, 2, 1, 2, 1, '学院食堂のランチも\\n美味しいけど…\\nここのご飯も好きかな', 0);
insert into room_unit_comments values (3068, 109401, 2, 3, 1, 3, 1, 'そろそろベッドに\\n行かないとだね\\n…寝相、今夜こそ\\n気を付けよう…！', 0);
insert into room_unit_comments values (3070, 109401, 3, 2, 1, 0, 1, '羽を伸ばしたく\\nなっちゃうね…ふふ', 0);
insert into room_unit_comments values (3071, 109401, 3, 3, 1, 0, 1, 'わ、私が持つには\\nかわいすぎるかな…\\nでも、素敵だね', 0);
insert into room_unit_comments values (3072, 109401, 3, 4, 1, 0, 1, 'いい香り…\\nこれ、\\nアンも好きそう…', 0);
insert into room_unit_comments values (3073, 109401, 3, 5, 1, 0, 1, '火を見ていると\\n少し落ち着くんだ…\\nへ、変かな？', 0);
insert into room_unit_comments values (3075, 109401, 3, 7, 1, 0, 1, 'わ、美味しい…！\\nこれ、どうやって\\n作ったのかな…？', 0);
insert into room_unit_comments values (3076, 109401, 3, 8, 1, 0, 1, 'この本…アンにも\\n見せてあげたら\\n喜ぶかな、ふふっ', 0);
insert into room_unit_comments values (3078, 109501, 1, 1, 1, 0, 1, '着物はきれいですが\\n歩きにくいです…\\nいっそ脱いで…ぐふふ', 0);
insert into room_unit_comments values (3079, 109501, 1, 2, 1, 0, 1, 'あっ、いけません\\n着物がはだけて…はっ\\nもしやドＳさんが…！', 0);
insert into room_unit_comments values (3080, 109501, 1, 3, 1, 0, 1, 'この部屋は妄想する\\nのにうってつけです…\\nぐふふ…じゅるり', 0);
insert into room_unit_comments values (3081, 109501, 1, 4, 1, 0, 1, '扇をゆっくりと開く\\nこの感触…なぜだか\\n艶めかしさを感じます', 0);
insert into room_unit_comments values (3082, 109501, 1, 5, 1, 0, 1, '「マッサージをすると\\n言いながらドＳさんの\\n手は次第に」…ぐふふ', 0);
insert into room_unit_comments values (3083, 109501, 1, 101, 4, 0, 1, '…ドＳさんの視線を\\n思い出しながら踊りの\\n練習です…イイ！', 0);
insert into room_unit_comments values (3084, 109501, 1, 102, 8, 0, 1, 'よいではないか\\nよいではないか～\\nいけませんご堪忍を～', 0);
insert into room_unit_comments values (3085, 109501, 2, 1, 1, 0, 1, 'あ～れ～～～！\\nドＳさんもお好きな人\\nですねぇ…ぐふふ', 0);
insert into room_unit_comments values (3086, 109501, 2, 2, 1, 0, 1, 'どこにいてもドＳさん\\nの気配を感じ取れる\\nようになりました…', 0);
insert into room_unit_comments values (3087, 109501, 2, 3, 1, 0, 1, 'こんな場所で\\nなんというプレイを！\\n…妄想でした', 0);
insert into room_unit_comments values (3088, 109501, 2, 4, 1, 0, 1, 'クウカを押し倒して\\nそのまま…じゅるり\\nああっ、着物が…！', 0);
insert into room_unit_comments values (3089, 109501, 2, 101, 4, 0, 1, 'ドＳさんは優しいです\\n優しいのにドＳとは\\nさすが人格破綻者…！', 0);
insert into room_unit_comments values (3090, 109501, 2, 102, 8, 0, 1, 'ドＳさんの考えている\\nことが伝わってきます\\nはい…クウカ脱ぎます', 0);
insert into room_unit_comments values (3091, 109501, 2, 1, 1, 1, 1, '眩しい朝日がクウカの\\n体を焦がします\\n…それもイイ！', 0);
insert into room_unit_comments values (3092, 109501, 2, 2, 1, 2, 1, 'お昼のランチは\\nクウカがいいだなんて\\n大胆過ぎです…じゅる', 0);
insert into room_unit_comments values (3093, 109501, 2, 3, 1, 3, 1, '…今夜のドＳさんは\\n大胆です…ぐふふ…\\nはっ、視線が…！？', 0);
insert into room_unit_comments values (3095, 109501, 3, 2, 1, 0, 1, 'この心地良さ、\\n心が休まりすぎて\\n体が疼いてきます…！', 0);
insert into room_unit_comments values (3096, 109501, 3, 3, 1, 0, 1, 'すごく愛らしいです…\\n妄想も出てこない\\nくらい…じゅるり', 0);
insert into room_unit_comments values (3097, 109501, 3, 4, 1, 0, 1, 'この香りに包まれて\\nいると、いい気持ちに\\nなって…いきますぅ…', 0);
insert into room_unit_comments values (3098, 109501, 3, 5, 1, 0, 1, '「熱を帯びた体は\\nどうしようもなく\\n誰かを求め…」ぐふふ', 0);
insert into room_unit_comments values (3100, 109501, 3, 7, 1, 0, 1, 'お腹が膨らんで\\nいきます…それは\\nまるで…ぐふふ', 0);
insert into room_unit_comments values (3101, 109501, 3, 8, 1, 0, 1, 'クウカの探している\\nジャンルはどこに\\nありますかね？', 0);
insert into room_unit_comments values (3103, 109601, 1, 1, 1, 0, 1, 'カチョーフーゲツは\\nトーゴクの心を\\n表した言葉デスね', 0);
insert into room_unit_comments values (3104, 109601, 1, 2, 1, 0, 1, 'オー！\u3000新しい忍法を\\n思いついたデス！\\nさっそく試すデス！', 0);
insert into room_unit_comments values (3105, 109601, 1, 3, 1, 0, 1, 'トーゴクの天気には\\n槍が降る日も\\nあるそうデス…', 0);
insert into room_unit_comments values (3106, 109601, 1, 4, 1, 0, 1, '我がショーグンは\\n永遠にフメツデース\\nいざ出陣デース！', 0);
insert into room_unit_comments values (3107, 109601, 1, 5, 1, 0, 1, '壁に耳あり\\n障子に…ん？\\nメアリーって誰デス？', 0);
insert into room_unit_comments values (3108, 109601, 1, 101, 4, 0, 1, 'ショーグンがいれば\\nワタシはどんな\\n忍法も使いこなせマス', 0);
insert into room_unit_comments values (3109, 109601, 1, 102, 8, 0, 1, '不届き者はどこで\\nゴザルデス？\u3000忍法で\\n退治してくれヨウ！', 0);
insert into room_unit_comments values (3110, 109601, 2, 1, 1, 0, 1, 'ショーグン！\u3000新しい\\n忍法を覚えたデス！\\n見てほしいデース！', 0);
insert into room_unit_comments values (3111, 109601, 2, 2, 1, 0, 1, 'レッツ手裏剣道デス！\\n投げてソウロウで\\nゴザルデース！', 0);
insert into room_unit_comments values (3112, 109601, 2, 3, 1, 0, 1, 'ふりかかる火の粉は\\nワタシが払うデス！\\nバンバン！', 0);
insert into room_unit_comments values (3113, 109601, 2, 4, 1, 0, 1, 'とっておきの忍法が\\n吹き荒れるデス！\\nよそ見はダメデスヨ？', 0);
insert into room_unit_comments values (3114, 109601, 2, 101, 4, 0, 1, 'ショーグンは\\n何階建てのお城を\\n建てたいデスか？', 0);
insert into room_unit_comments values (3115, 109601, 2, 102, 8, 0, 1, 'テンシュカクから\\n平和な城下町を\\n眺めてみたいデス…', 0);
insert into room_unit_comments values (3116, 109601, 2, 1, 1, 1, 1, 'おはようございマス！\\n本日はオヒガラモヨク\\n良い日になりそうデス', 0);
insert into room_unit_comments values (3117, 109601, 2, 2, 1, 2, 1, 'お腹すいたデース…\\nショーグンもご飯に\\nしまショウ！', 0);
insert into room_unit_comments values (3118, 109601, 2, 3, 1, 3, 1, '闇討ちに遭わぬよう\\n夜は気を付けて\\n歩くデスよー？', 0);
insert into room_unit_comments values (3120, 109601, 3, 2, 1, 0, 1, '天下分け目の\\n戦いに備えて…\\nマッタリデース', 0);
insert into room_unit_comments values (3121, 109601, 3, 3, 1, 0, 1, '口寄せの術で\\n召喚したいくらい\\nかわいいデース', 0);
insert into room_unit_comments values (3122, 109601, 3, 4, 1, 0, 1, 'いい匂いデ～ス\\n香り玉の開発の\\n参考になりそうデスね', 0);
insert into room_unit_comments values (3123, 109601, 3, 5, 1, 0, 1, 'ワタシの懐よりも\\nゾーリが暖まりマス…\\nライバル出現デス…！', 0);
insert into room_unit_comments values (3125, 109601, 3, 7, 1, 0, 1, '腹が減っては\\n戦はできぬデース！\\n天下統一に向けて\\n腹ごしらえデス！', 0);
insert into room_unit_comments values (3126, 109601, 3, 8, 1, 0, 1, 'ムム、暗号文デス！？\\n解読には時間が\\nかかりそうデース…', 0);
insert into room_unit_comments values (3128, 109701, 1, 1, 1, 0, 1, '掃除も終わりましたし\\nそろそろ、食事の\\n準備をしなくては', 0);
insert into room_unit_comments values (3129, 109701, 1, 2, 1, 0, 1, '異世界の演劇…\\n許されるならば、\\n観てみたいです', 0);
insert into room_unit_comments values (3130, 109701, 1, 3, 1, 0, 1, 'こちらの世界には、\\nマヨネーズが普通に\\n存在するのですね…', 0);
insert into room_unit_comments values (3131, 109701, 1, 4, 1, 0, 1, 'こちらの世界は食材も\\n面白い物が多いですね\\nなにかレシピを\\n考えてみましょうか', 0);
insert into room_unit_comments values (3132, 109701, 1, 5, 1, 0, 1, 'みょんみょんみょん…\\n魔法の練習は\\nこれぐらいですね', 0);
insert into room_unit_comments values (3133, 109701, 1, 101, 4, 0, 1, '倒木の撤去で思わぬ\\n収入となりました\\nサレン様に\\nお渡ししておかないと', 0);
insert into room_unit_comments values (3134, 109701, 1, 102, 8, 0, 1, '料理を美味しく\\n召し上がって頂けると\\nメイド冥利につきます', 0);
insert into room_unit_comments values (3135, 109701, 2, 1, 1, 0, 1, 'お出かけでしたら、\\nレムも同行\\nさせてくださいね', 0);
insert into room_unit_comments values (3136, 109701, 2, 2, 1, 0, 1, 'レムにできること\\nでしたら、なんでも\\nお申し付けください', 0);
insert into room_unit_comments values (3137, 109701, 2, 3, 1, 0, 1, 'じーー。いえ、\\nその髪の長さが少し、\\nとても少し、かなり\\n少し気になったもので', 0);
insert into room_unit_comments values (3138, 109701, 2, 4, 1, 0, 1, '鉄球ですか？\\nあれは護身用ですので\\n問題はありませんよ？', 0);
insert into room_unit_comments values (3139, 109701, 2, 101, 4, 0, 1, '計算の勉強は\\n進んでおりますか？\\nレムでよろしければ、\\nいつでもお教えします', 0);
insert into room_unit_comments values (3140, 109701, 2, 102, 8, 0, 1, '次はもっと、大きな\\n魔物料理に挑戦します\\nワイバーンの姿焼き\\nなんてどうでしょうか', 0);
insert into room_unit_comments values (3141, 109701, 2, 1, 1, 1, 1, 'おはようございます\\n朝食の準備が\\nできておりますので、\\n食卓におこしください', 0);
insert into room_unit_comments values (3142, 109701, 2, 2, 1, 2, 1, '昼食の時間ですね\\n何か食べたいものは\\nありますか？', 0);
insert into room_unit_comments values (3143, 109701, 2, 3, 1, 3, 1, '寝ないのか、ですか？\\nメイドの就寝は、\\n屋敷で最後と\\n決まっておりますので', 0);
insert into room_unit_comments values (3145, 109701, 3, 2, 1, 0, 1, 'ふんわり…\\nこのふんわりさは、\\n鬼をも黙らせます…', 0);
insert into room_unit_comments values (3146, 109701, 3, 3, 1, 0, 1, 'ふふっ…異世界でも\\nかわいいものは\\n共通なのですね', 0);
insert into room_unit_comments values (3147, 109701, 3, 4, 1, 0, 1, 'よい香りですね\\n魔女教の悪臭とは\\n大違いです', 0);
insert into room_unit_comments values (3148, 109701, 3, 5, 1, 0, 1, 'ぬくぬくです…はっ！\\nこれはいけません！\\n人を…いえ、\\n鬼をだめにします！', 0);
insert into room_unit_comments values (3150, 109701, 3, 7, 1, 0, 1, 'はむはむ…美味しい！\\nこの味を再現できたら\\n褒めてもらえる\\nかもしれません…！', 0);
insert into room_unit_comments values (3151, 109701, 3, 8, 1, 0, 1, '絵がいっぱい…\\n異世界の本は\\nとても面白いですね', 0);
insert into room_unit_comments values (3153, 109801, 1, 1, 1, 0, 1, '異世界であろうと、\\nラムのやるべきことは\\n変わらないわ\\nまずは休憩するわよ', 0);
insert into room_unit_comments values (3154, 109801, 1, 2, 1, 0, 1, 'マヨネーズがある\\nということは、\\nバルスの故郷が近い\\nのかもしれないわね', 0);
insert into room_unit_comments values (3155, 109801, 1, 3, 1, 0, 1, 'この世界では、バルス\\nの言う言葉が使われる\\nときがあるのね\\n忌々しいかぎりだわ', 0);
insert into room_unit_comments values (3156, 109801, 1, 4, 1, 0, 1, 'ラムたち以外にも\\nメイドが居るのね\\nラムが…いえ、\\n仕事を押しつけるわ', 0);
insert into room_unit_comments values (3157, 109801, 1, 5, 1, 0, 1, '…千里眼で視るかぎり\\n周囲に異変はないわね\\n危険がないなら、\\nあとはレムに任せるわ', 0);
insert into room_unit_comments values (3158, 109801, 1, 101, 4, 0, 1, '…ラムもまた、\\n「お姉ちゃん」って\\n呼ばれる日が\\nくるのかしらね', 0);
insert into room_unit_comments values (3159, 109801, 1, 102, 8, 0, 1, 'ハッ！\u3000ラムが作る\\n蒸かし芋は完璧ね\\n…気が向いたら、また\\n作ってやろうかしら', 0);
insert into room_unit_comments values (3160, 109801, 2, 1, 1, 0, 1, 'ラムに構う暇が\\nあるなら働きなさい\\nそうすれば、\\nラムが楽をできるわ', 0);
insert into room_unit_comments values (3161, 109801, 2, 2, 1, 0, 1, 'ラムに何かを\\n期待しても無駄よ\\nラムに命令できるのは\\nロズワール様だけだわ', 0);
insert into room_unit_comments values (3162, 109801, 2, 3, 1, 0, 1, '暇なら買い物に\\n付き合いなさい\\n荷物を\\n持たせてあげるわ', 0);
insert into room_unit_comments values (3163, 109801, 2, 4, 1, 0, 1, 'ラムになんの用？\\nふざけた内容なら\\nねじ切るわよ', 0);
insert into room_unit_comments values (3164, 109801, 2, 101, 4, 0, 1, 'そういえば、あなたは\\n記憶喪失だったわね…\\n思い出す努力をなさい\\n…家族が悲しむわよ', 0);
insert into room_unit_comments values (3165, 109801, 2, 102, 8, 0, 1, '蒸かし芋が欲しい？\\n随分と厚かましいわね\\n…まだ残りがあるから\\n好きに食べなさい', 0);
insert into room_unit_comments values (3166, 109801, 2, 1, 1, 1, 1, 'だらしない顔ね\\n顔を洗って\\nしゃんとなさい', 0);
insert into room_unit_comments values (3167, 109801, 2, 2, 1, 2, 1, 'お腹が空く時間ね\\nラムの昼食を\\n用意させてあげるわ', 0);
insert into room_unit_comments values (3168, 109801, 2, 3, 1, 3, 1, 'メイドが寝るのは\\n屋敷で最後…\\nラムが寝るために、\\nさっさと寝なさい', 0);
insert into room_unit_comments values (3170, 109801, 3, 2, 1, 0, 1, '…ここから動かない\\nという、誓いを\\n立てたくなるわね', 0);
insert into room_unit_comments values (3171, 109801, 3, 3, 1, 0, 1, 'これは…かわいいわね\\nもちろん、\\nラムほどではないけど', 0);
insert into room_unit_comments values (3172, 109801, 3, 4, 1, 0, 1, '…香炉かしら？\\nこちらの世界にも\\n質のよい物があるのね', 0);
insert into room_unit_comments values (3173, 109801, 3, 5, 1, 0, 1, '見つけてしまったの\\nかもしれないわ…\\nラムの楽園を！', 0);
insert into room_unit_comments values (3175, 109801, 3, 7, 1, 0, 1, '…はむっ\\nラムの蒸かし芋ほど\\nではないけど、\\nなかなかいけるわね', 0);
insert into room_unit_comments values (3176, 109801, 3, 8, 1, 0, 1, '異世界ならではの\\n面白い内容もあるわね\\nとても興味深いわ', 0);
insert into room_unit_comments values (3178, 109901, 1, 1, 1, 0, 1, 'ねえパック、\\nにゃんにゃか\\nにゃかにゃんしよっか', 0);
insert into room_unit_comments values (3179, 109901, 1, 2, 1, 0, 1, '時間もあるし、\\nこっちの世界の石で\\n石積みしようかな', 0);
insert into room_unit_comments values (3180, 109901, 1, 3, 1, 0, 1, '私もお姉さんだし、\\nサレンさんを\\n見習わないと…うん！\\n私、すごーく頑張る！', 0);
insert into room_unit_comments values (3181, 109901, 1, 4, 1, 0, 1, 'この世界は、銀髪で\\nハーフエルフでも受け\\n入れてくれるのね…\\nなんだか嬉しいな', 0);
insert into room_unit_comments values (3182, 109901, 1, 5, 1, 0, 1, '今日のご飯…\\nピーマルは\\n入ってないわよね…？', 0);
insert into room_unit_comments values (3183, 109901, 1, 101, 4, 0, 1, 'また、みんなで\\n一緒に買い物に\\n行きたいな', 0);
insert into room_unit_comments values (3184, 109901, 1, 102, 8, 0, 1, 'パック以外から\\n家族って呼ばれたの\\n初めて…ふふっ♪\\nちょっと嬉しいかも！', 0);
insert into room_unit_comments values (3185, 109901, 2, 1, 1, 0, 1, '今からパックの\\n毛繕いをするけど…\\n一緒にする？', 0);
insert into room_unit_comments values (3186, 109901, 2, 2, 1, 0, 1, '私も何かお手伝いを…\\nあ、そうだ！\\n料理とかどうかな！', 0);
insert into room_unit_comments values (3187, 109901, 2, 3, 1, 0, 1, 'ねえ、ここで\\n歌の練習って、\\nしてもいいかな？', 0);
insert into room_unit_comments values (3188, 109901, 2, 4, 1, 0, 1, '…あ、ごめんなさい！\\n話しかけられるのって\\nあまり慣れてなくて…', 0);
insert into room_unit_comments values (3189, 109901, 2, 101, 4, 0, 1, 'すごーく頑張るから、\\nこれからも勉強を\\n手伝ってね', 0);
insert into room_unit_comments values (3190, 109901, 2, 102, 8, 0, 1, 'せーの、びくとりー！\\nふふっ…また、一緒に\\nラジーオタイソー\\nしようね♪', 0);
insert into room_unit_comments values (3191, 109901, 2, 1, 1, 1, 1, 'ちゃんと起きてる？\\nふふっ…よかった。\\nあ、べ、別に心配した\\nわけじゃないからね？', 0);
insert into room_unit_comments values (3192, 109901, 2, 2, 1, 2, 1, 'お昼ご飯が楽しみね♪\\nあ、こっちの世界って\\nまよねーずはあるの？', 0);
insert into room_unit_comments values (3193, 109901, 2, 3, 1, 3, 1, 'そろそろ寝る時間よ。\\n夜更かししたら、\\nめっ！\u3000だからね！', 0);
insert into room_unit_comments values (3195, 109901, 3, 2, 1, 0, 1, '勉強も終わったし…\\nちょっ、ちょっとだけ\\n休んでもいいよね…？', 0);
insert into room_unit_comments values (3196, 109901, 3, 3, 1, 0, 1, 'か、かわいい…！\\nパックのかわいさに\\n匹敵するかも…！', 0);
insert into room_unit_comments values (3197, 109901, 3, 4, 1, 0, 1, '良い香り…\\nロズワールの屋敷にも\\nこういうのって\\nあるのかな？', 0);
insert into room_unit_comments values (3198, 109901, 3, 5, 1, 0, 1, 'あったかい…\\nずっとここに…はっ！\\nダメダメ！\u3000王選の\\nために勉強しないと！', 0);
insert into room_unit_comments values (3200, 109901, 3, 7, 1, 0, 1, 'あ…これ美味しい！\\nこっちの世界は色んな\\n食べ物があるのね。', 0);
insert into room_unit_comments values (3201, 109901, 3, 8, 1, 0, 1, '知らないことが\\nいっぱい書いてある…\\n異世界の本って、\\n面白いのね', 0);
insert into room_unit_comments values (3203, 110001, 1, 1, 1, 0, 1, '海ってマジ最高！\\nビーチの撮影も\\n超楽しいしー♪', 0);
insert into room_unit_comments values (3204, 110001, 1, 2, 1, 0, 1, '20パーって何パ？\\n今度ヒデサイに\\n聞いてみよっ！', 0);
insert into room_unit_comments values (3205, 110001, 1, 3, 1, 0, 1, '夏の思い出を\\nヒデサイと一緒に\\n作りたいな～', 0);
insert into room_unit_comments values (3206, 110001, 1, 4, 1, 0, 1, 'テンションあがる\\n水着ゲットして\\n超ラッキーだよ～♪', 0);
insert into room_unit_comments values (3207, 110001, 1, 5, 1, 0, 1, '休憩が終わったら\\n撮影にもどらないと！\\n気合入れてこ♪', 0);
insert into room_unit_comments values (3208, 110001, 1, 101, 4, 0, 1, 'ヒデサイとビーチで\\nパーティーしたいな～\\n超楽しそうだよね！', 0);
insert into room_unit_comments values (3209, 110001, 1, 102, 8, 0, 1, 'ヒデサイといると\\n楽しくてうれしくて…\\nカレシってこんな感じ\\nなのかなぁ？', 0);
insert into room_unit_comments values (3210, 110001, 2, 1, 1, 0, 1, '見て見て～！\\n夏らしいネイルに\\nしてみたんだ～♪', 0);
insert into room_unit_comments values (3211, 110001, 2, 2, 1, 0, 1, 'ヒデサイ～\\nこの水着どうかな？\\nイケてるっしょ♪', 0);
insert into room_unit_comments values (3212, 110001, 2, 3, 1, 0, 1, '水着姿の写真？\\nもちいいよ！\\nかわいく撮ってね！', 0);
insert into room_unit_comments values (3213, 110001, 2, 4, 1, 0, 1, 'うちだって\\n夏の海みたいに\\nキラキラしちゃうよ！', 0);
insert into room_unit_comments values (3214, 110001, 2, 101, 4, 0, 1, 'ヒデサイとうちの\\nフィーリングって\\nめっちゃエモいよね♪', 0);
insert into room_unit_comments values (3215, 110001, 2, 102, 8, 0, 1, 'ねーねーヒデサイ！\\n一緒に泳ぎにいこっ！\\nほら、手繋いで♪', 0);
insert into room_unit_comments values (3216, 110001, 2, 1, 1, 1, 1, '水着オッケー！\\nネイルもばっちり！\\n朝から遊んじゃおー♪', 0);
insert into room_unit_comments values (3217, 110001, 2, 2, 1, 2, 1, 'お昼食べたら\\n昼寝して\\nリフレッシュしよー♪', 0);
insert into room_unit_comments values (3218, 110001, 2, 3, 1, 3, 1, '水着ってマジで\\n最強かも…このまま\\nお風呂にも入れるし♪', 0);
insert into room_unit_comments values (3220, 110001, 3, 2, 1, 0, 1, 'マジ気持ちいいー♪\\nおに癒やされるん\\nですけど～！', 0);
insert into room_unit_comments values (3221, 110001, 3, 3, 1, 0, 1, 'やばばばばー！\\nかわいすぎだってば！\\nマジらぶだよ～♪', 0);
insert into room_unit_comments values (3222, 110001, 3, 4, 1, 0, 1, 'あ、この香り超好き！\\nモデル仲間に\\n教えたげよ～♪', 0);
insert into room_unit_comments values (3223, 110001, 3, 5, 1, 0, 1, 'あったか～い♪\\n夏の太陽みたい！', 0);
insert into room_unit_comments values (3225, 110001, 3, 7, 1, 0, 1, 'マジ美味しいねこれ♪\\nビーチで\\n流行っちゃうかも！', 0);
insert into room_unit_comments values (3226, 110001, 3, 8, 1, 0, 1, '夏のために\\n最新ファッションを\\n勉強ちう！', 0);
insert into room_unit_comments values (3228, 110001, 3, 10, 1, 0, 1, 'なにコレもにカワ～♪\\nなんて生き物？\\nヒデサイ知ってる？', 0);
insert into room_unit_comments values (3229, 110001, 3, 11, 1, 0, 1, 'うわっ超フカフカ～\\nなんかうち眠く\\nなってきちゃった…', 0);
insert into room_unit_comments values (3230, 110101, 1, 1, 1, 0, 1, '海の家でのんびり\\n過ごしましょう\\n熱中症には注意してね', 0);
insert into room_unit_comments values (3231, 110101, 1, 2, 1, 0, 1, 'はぁ、どうやったら\\n泳げるように\\nなれるのかしら～', 0);
insert into room_unit_comments values (3232, 110101, 1, 3, 1, 0, 1, '海で日焼け止めを\\n塗らないと、あとで\\n大変なことになるわよ', 0);
insert into room_unit_comments values (3233, 110101, 1, 4, 1, 0, 1, '久しぶりに水着を\\n着たんだけど\\n変じゃなかったかな…', 0);
insert into room_unit_comments values (3234, 110101, 1, 5, 1, 0, 1, '波の音って落ち着くわ\\n授業中に聞いたら\\nみんな寝ちゃうかも？', 0);
insert into room_unit_comments values (3235, 110101, 1, 101, 4, 0, 1, '海が楽しいって\\n思えたのも\\nあの子のおかげね', 0);
insert into room_unit_comments values (3236, 110101, 1, 102, 8, 0, 1, 'あの子と二人で海に\\n来られてよかったわ\\n一日があっという間ね', 0);
insert into room_unit_comments values (3237, 110101, 2, 1, 1, 0, 1, '男の子と海だなんて\\n少女漫画みたいで\\n憧れてたの～', 0);
insert into room_unit_comments values (3238, 110101, 2, 2, 1, 0, 1, '夏休みの宿題は\\nちゃんとやった？\\n遊んでばかりではダメ', 0);
insert into room_unit_comments values (3239, 110101, 2, 3, 1, 0, 1, '昼の海と夜の海\\nどっちが好き？\u3000私は\\n君といる海が一番よ', 0);
insert into room_unit_comments values (3240, 110101, 2, 4, 1, 0, 1, 'ふう、疲れたわ～\\n冷たいジュースで\\n元気回復ね！', 0);
insert into room_unit_comments values (3241, 110101, 2, 101, 4, 0, 1, '海で見た君の背中\\nすごく大きく見えたわ\\nやっぱり男の子なのね', 0);
insert into room_unit_comments values (3242, 110101, 2, 102, 8, 0, 1, '君と一緒に見た\\n夜の海…\\n忘れられそうにないわ', 0);
insert into room_unit_comments values (3243, 110101, 2, 1, 1, 1, 1, '準備ができたら\\n海に出かけようよ\\n今日も楽しみましょう', 0);
insert into room_unit_comments values (3244, 110101, 2, 2, 1, 2, 1, 'あら、もうお昼？\\n海の家でランチに\\nしましょ♪', 0);
insert into room_unit_comments values (3245, 110101, 2, 3, 1, 3, 1, '夜の海岸についてきて\\nくれる？\u3000暗がりは\\n一人じゃ怖くて…', 0);
insert into room_unit_comments values (3247, 110101, 3, 2, 1, 0, 1, '泳ぐ練習をしたら\\n疲れちゃったわ～\\nちょっと一休み…', 0);
insert into room_unit_comments values (3248, 110101, 3, 3, 1, 0, 1, 'かわいいわね～\\n浮き輪に乗せて\\n海に浮かべたいわ～', 0);
insert into room_unit_comments values (3249, 110101, 3, 4, 1, 0, 1, 'この匂い…\\nなんだか夏の海を\\n思い出すわ～', 0);
insert into room_unit_comments values (3250, 110101, 3, 5, 1, 0, 1, '夜の海風で冷えない\\nように、しっかりと\\n身体を暖めましょうね', 0);
insert into room_unit_comments values (3252, 110101, 3, 7, 1, 0, 1, '海で遊ぶ前に\\nしっかり食べて\\n体力つけましょう', 0);
insert into room_unit_comments values (3253, 110101, 3, 8, 1, 0, 1, '夏休み中でも\\nしっかりお勉強\\nしないと！', 0);
insert into room_unit_comments values (3255, 110101, 3, 10, 1, 0, 1, 'この子に乗れば\\n海の上でも\\nすいすい進めるかしら', 0);
insert into room_unit_comments values (3256, 110101, 3, 11, 1, 0, 1, 'ビーナスの誕生！\\n…なんちゃって\\nはしゃぎすぎかしら？', 0);
insert into room_unit_comments values (3257, 110301, 1, 1, 1, 0, 1, '夏の海には商機が\\nあるはず…\\nのがす手はないわね♪', 0);
insert into room_unit_comments values (3258, 110301, 1, 2, 1, 0, 1, 'あたしが作った\\n日焼け止め…\\nこれは売れそうね！', 0);
insert into room_unit_comments values (3259, 110301, 1, 3, 1, 0, 1, '子どもたちのために\\n浮き輪を用意して\\nおかないと…', 0);
insert into room_unit_comments values (3260, 110301, 1, 4, 1, 0, 1, '海っていいわよね！\\nみんなで羽を伸ばしに\\n行きたいわ！', 0);
insert into room_unit_comments values (3261, 110301, 1, 5, 1, 0, 1, '波の音を聞いて\\nのんびりするのも\\n悪くないわね…', 0);
insert into room_unit_comments values (3262, 110301, 1, 101, 4, 0, 1, 'ただの砂遊びも\\nあんたと一緒なら\\n楽しいから不思議ね…', 0);
insert into room_unit_comments values (3263, 110301, 1, 102, 8, 0, 1, 'あんたがあたしの\\nなんであれ、大切な\\n存在ではあるのよね…', 0);
insert into room_unit_comments values (3264, 110301, 2, 1, 1, 0, 1, '夏の海って\\nすごい人よね…\\n迷子にならないでよ？', 0);
insert into room_unit_comments values (3265, 110301, 2, 2, 1, 0, 1, 'ぼんやり海に浮かんで\\n波に揺られるのも\\n悪くないわよ？', 0);
insert into room_unit_comments values (3266, 110301, 2, 3, 1, 0, 1, 'ビーチで子どもたちと\\n一緒に砂のお城を\\n作りたいわ♪', 0);
insert into room_unit_comments values (3267, 110301, 2, 4, 1, 0, 1, '海で食べる\\n焼きそばパン…\\nいいかもしれないわね', 0);
insert into room_unit_comments values (3268, 110301, 2, 101, 4, 0, 1, 'あたしの水着\\n似合ってる？\\nそう、ありがとう♪', 0);
insert into room_unit_comments values (3269, 110301, 2, 102, 8, 0, 1, 'あんたが居ると\\nうれしい…って、\\n子どもたちが\\n言ってたわ！', 0);
insert into room_unit_comments values (3270, 110301, 2, 1, 1, 1, 1, '朝の浜辺って\\nいいわよね\\n散歩しに行きたいわ', 0);
insert into room_unit_comments values (3271, 110301, 2, 2, 1, 2, 1, '海の家のご飯って\\nなんであんなに\\nおいしいのかしら♪', 0);
insert into room_unit_comments values (3272, 110301, 2, 3, 1, 3, 1, '夜の海って、\\nロマンチックよね。\\nずっと眺めてたいわ…', 0);
insert into room_unit_comments values (3274, 110301, 3, 2, 1, 0, 1, 'やわらかくて\\n気持ちいい…\\nこのまま寝ちゃいそう', 0);
insert into room_unit_comments values (3275, 110301, 3, 3, 1, 0, 1, '海に一緒に入れる\\nぬいぐるみとか\\nないかしら？', 0);
insert into room_unit_comments values (3276, 110301, 3, 4, 1, 0, 1, '夏らしい\\nいい香りね…\\nなんの香りかしら？', 0);
insert into room_unit_comments values (3277, 110301, 3, 5, 1, 0, 1, 'あったかい…\\n濡れた体を乾かすには\\nちょうどいいわね♪', 0);
insert into room_unit_comments values (3279, 110301, 3, 7, 1, 0, 1, '泳いだ後の食事は\\n普段の何倍も\\nおいしく感じるわね！', 0);
insert into room_unit_comments values (3280, 110301, 3, 8, 1, 0, 1, '海に行く前にいろいろ\\n調べなきゃね。備え\\nあれば憂いなしよ！', 0);
insert into room_unit_comments values (3282, 110301, 3, 10, 1, 0, 1, '海の守り神？\\nずいぶんかわいらしい\\n神様ね♪', 0);
insert into room_unit_comments values (3283, 110301, 3, 11, 1, 0, 1, 'このぐらい\\n大きな貝があったら\\n食費も浮くかしら？', 0);
insert into room_unit_comments values (3284, 110401, 1, 1, 1, 0, 1, '浜辺で食うものって\\nなんであんなに\\nうまいのかな～', 0);
insert into room_unit_comments values (3285, 110401, 1, 2, 1, 0, 1, 'いてて…\\nちょっと日焼け\\nしすぎたかな', 0);
insert into room_unit_comments values (3286, 110401, 1, 3, 1, 0, 1, '砂浜で走ると\\nいいトレーニングに\\nなるんだぜ', 0);
insert into room_unit_comments values (3287, 110401, 1, 4, 1, 0, 1, '夏ならではの\\n料理…か\\n何がいいかな…', 0);
insert into room_unit_comments values (3288, 110401, 1, 5, 1, 0, 1, 'やっぱりここは\\n涼しくて快適だな', 0);
insert into room_unit_comments values (3289, 110401, 1, 101, 4, 0, 1, '泳ぎの練習だったら\\nいつでも付き合って\\nやるからな！', 0);
insert into room_unit_comments values (3290, 110401, 1, 102, 8, 0, 1, '水着で部屋の中に\\nいるのって\\n変な感じだな…', 0);
insert into room_unit_comments values (3291, 110401, 2, 1, 1, 0, 1, 'うおっ！\\nきゅ、急に\\n触るなって…\\nびっくりした', 0);
insert into room_unit_comments values (3292, 110401, 2, 2, 1, 0, 1, 'え、砂がついてた？\\n払ってくれたのか\\nありがとよ', 0);
insert into room_unit_comments values (3293, 110401, 2, 3, 1, 0, 1, '夏バテしてないか？\\nここで休んでけよ', 0);
insert into room_unit_comments values (3294, 110401, 2, 4, 1, 0, 1, '…そう見られると\\n照れるっていうか…', 0);
insert into room_unit_comments values (3295, 110401, 2, 101, 4, 0, 1, 'カキ氷とか\\n食いたくないか？\\n氷、削ってやるよ', 0);
insert into room_unit_comments values (3296, 110401, 2, 102, 8, 0, 1, 'おまえと\\n夏の思い出ができて\\nよかったよ', 0);
insert into room_unit_comments values (3297, 110401, 2, 1, 1, 1, 1, 'ふう…\\n朝一番で泳ぐの\\nやっぱ気持ちいいな', 0);
insert into room_unit_comments values (3298, 110401, 2, 2, 1, 2, 1, '一番あちぃ時間だ\\n水分補給は\\nこまめにな！', 0);
insert into room_unit_comments values (3299, 110401, 2, 3, 1, 3, 1, '今日もお疲れ\\n明日のパトロールも\\nよろしくな', 0);
insert into room_unit_comments values (3301, 110401, 3, 2, 1, 0, 1, '泳ぎ疲れたからな\\n少し休憩だ…', 0);
insert into room_unit_comments values (3302, 110401, 3, 3, 1, 0, 1, 'か、かわいい…\\nいや、なんでもねぇ！', 0);
insert into room_unit_comments values (3303, 110401, 3, 4, 1, 0, 1, 'この香り落ち着くな\\nこういうのも\\n悪くねーかも…', 0);
insert into room_unit_comments values (3304, 110401, 3, 5, 1, 0, 1, 'あったけえ…！\\n泳ぎ終わった後って\\nけっこう体冷えてよ…', 0);
insert into room_unit_comments values (3306, 110401, 3, 7, 1, 0, 1, '海で食べると\\nまた一味違うよな', 0);
insert into room_unit_comments values (3307, 110401, 3, 8, 1, 0, 1, '夏のサバイバル特集…\\nちょっと読んでみるか', 0);
insert into room_unit_comments values (3309, 110401, 3, 10, 1, 0, 1, 'へー！\u3000こいつ、\\nよくできてんな！\\nいいなあ、実物も\\n乗れたらいいのに', 0);
insert into room_unit_comments values (3310, 110401, 3, 11, 1, 0, 1, 'か、かわ…！\\nいや、じゃなくて\\nあ、あたしがここに\\n寝ていいのか…？', 0);
insert into room_unit_comments values (3311, 110501, 1, 1, 1, 0, 1, '故郷の花を飾っても\\nいいかな～？\\n部屋が楽しくなるよ～', 0);
insert into room_unit_comments values (3312, 110501, 1, 2, 1, 0, 1, '水着で歩いてると\\n泳ぎたくなるさ～\\n我慢できないさ～！', 0);
insert into room_unit_comments values (3313, 110501, 1, 3, 1, 0, 1, '夏が眩しいのは\\nてぃーだがにこにこ\\n笑ってるからさ～！', 0);
insert into room_unit_comments values (3314, 110501, 1, 4, 1, 0, 1, '泳ぎ疲れたら\\n涼しい木陰で\\nお昼寝するさ～', 0);
insert into room_unit_comments values (3315, 110501, 1, 5, 1, 0, 1, 'クロールも\\n犬かきも\\n大得意さ～！', 0);
insert into room_unit_comments values (3316, 110501, 1, 101, 4, 0, 1, 'なんだか歌いたい\\n気分さ～\\nキミもどう～？', 0);
insert into room_unit_comments values (3317, 110501, 1, 102, 8, 0, 1, '海の近くに住んで\\nキミと歌って踊って\\nそれが理想さ～！', 0);
insert into room_unit_comments values (3318, 110501, 2, 1, 1, 0, 1, '私とキミ\\nどっちがたくさん\\n泳げるか\\n競争するさ～！', 0);
insert into room_unit_comments values (3319, 110501, 2, 2, 1, 0, 1, 'キミも三線に興味が\\nあるのかな～？\\n私が教えるさ～！', 0);
insert into room_unit_comments values (3320, 110501, 2, 3, 1, 0, 1, '嫌なことがあっても\\n私と歌って踊れば\\nなんくるないさー！', 0);
insert into room_unit_comments values (3321, 110501, 2, 4, 1, 0, 1, 'たまには時間を忘れて\\n私とのーんびり\\n海を眺めるさ～', 0);
insert into room_unit_comments values (3322, 110501, 2, 101, 4, 0, 1, 'ぶるぶるぶるっ！\\n毛が濡れちゃっても\\nへっちゃらさ～！', 0);
insert into room_unit_comments values (3323, 110501, 2, 102, 8, 0, 1, '泳ぐ前は準備体操～！\\n背中押してあげるから\\nしっかりやるさ～！', 0);
insert into room_unit_comments values (3324, 110501, 2, 1, 1, 1, 1, '朝の浜辺は\\nちゅらさんよ～\\n一緒に歩こうよー！', 0);
insert into room_unit_comments values (3325, 110501, 2, 2, 1, 2, 1, 'お昼ご飯は\\n決まったかな～？\\n私はタコライスさ～！', 0);
insert into room_unit_comments values (3326, 110501, 2, 3, 1, 3, 1, '星と波音の中で\\n三線鳴らすのも\\nオツなものさ～', 0);
insert into room_unit_comments values (3328, 110501, 3, 2, 1, 0, 1, 'ちょうどよかったさー\\nゆっくり休んだら\\nまた泳ぎに行くさ～！', 0);
insert into room_unit_comments values (3329, 110501, 3, 3, 1, 0, 1, '砂浜に飾って\\nおきたいさ～\\nきっとかわいいさ～！', 0);
insert into room_unit_comments values (3330, 110501, 3, 4, 1, 0, 1, 'くんくん…はあ\\n癒されるさ…\\n故郷の夏の匂いさ～', 0);
insert into room_unit_comments values (3331, 110501, 3, 5, 1, 0, 1, 'おおー…！\\n濡れた髪が\\nみるみる乾いてくさ～', 0);
insert into room_unit_comments values (3333, 110501, 3, 7, 1, 0, 1, 'ん～！\u3000これ、\\n海で食べたら\\nもっとおいしいさ～', 0);
insert into room_unit_comments values (3334, 110501, 3, 8, 1, 0, 1, '海の生物図鑑ね～\\nこの前みかけた魚も\\n載ってるかな～？', 0);
insert into room_unit_comments values (3336, 110501, 3, 10, 1, 0, 1, 'わぁ～！\u3000みてみて！\\n背中に乗れるさー！\\nキミと一緒に\\n乗りたいさ～！', 0);
insert into room_unit_comments values (3337, 110501, 3, 11, 1, 0, 1, 'ふかふかさ～\\n海の底の\\n人魚になった気分さ～', 0);
insert into room_unit_comments values (3338, 105801, 1, 103, 12, 0, 1, 'あの人が\\nわたしの騎士だったら\\nいいのにな…', 0);
insert into room_unit_comments values (3339, 105801, 2, 103, 12, 0, 1, 'あなたのおかげで\\nわたしの心はいつも\\nお腹いっぱいです♪', 0);
insert into room_unit_comments values (3340, 105901, 1, 103, 12, 0, 1, '許されるのならば、\\n今すぐにでも、\\n主さまのおそばに\\n行きたいです…', 0);
insert into room_unit_comments values (3341, 105901, 2, 103, 12, 0, 1, '主さま…\\nお慕いしております…\\nいつまでも、おそばに\\n居させてください…', 0);
insert into room_unit_comments values (3342, 106001, 1, 103, 12, 0, 1, 'なんか最近、\\nあいつのことしか\\n考えてない…\\nあたし…どうしよう…', 0);
insert into room_unit_comments values (3343, 106001, 2, 103, 12, 0, 1, 'そ、外に行くなら、\\n連れていきなさいよね\\nその…あたしが\\n守ってあげるから…', 0);
insert into room_unit_comments values (3344, 110601, 1, 1, 1, 0, 1, '部屋の中は涼しくて\\n気持ちええどすなぁ\\n天国やわぁ', 0);
insert into room_unit_comments values (3345, 110601, 1, 2, 1, 0, 1, 'クラゲはんって\\nフリルいっぱいの\\nドレスみたいやねぇ', 0);
insert into room_unit_comments values (3346, 110601, 1, 3, 1, 0, 1, '外でセミはんが\\n元気に鳴いてはるねぇ\\n今日もええ天気やわぁ', 0);
insert into room_unit_comments values (3347, 110601, 1, 4, 1, 0, 1, 'こないに暑いと\\n海に入って\\n涼みたくなるわぁ', 0);
insert into room_unit_comments values (3348, 110601, 1, 5, 1, 0, 1, 'いつか\\nマホマホ王国にも\\n海の家作りまひょ♪', 0);
insert into room_unit_comments values (3349, 110601, 1, 101, 4, 0, 1, 'うちも\\n付き合いますえ\\n泳ぎの練習しまひょ♪', 0);
insert into room_unit_comments values (3350, 110601, 1, 102, 8, 0, 1, 'うちの里帰り\\n王子はんも一緒に\\n来まへんか？', 0);
insert into room_unit_comments values (3351, 110601, 2, 1, 1, 0, 1, '王子はんは日焼けより\\n色白美人の方が\\n好きでっしゃろか？', 0);
insert into room_unit_comments values (3352, 110601, 2, 2, 1, 0, 1, 'うちと一緒に\\n浮き輪で海、\\nプカプカしまへん？', 0);
insert into room_unit_comments values (3353, 110601, 2, 3, 1, 0, 1, '日が落ちたら\\n線香花火\\nやりたいわぁ♪', 0);
insert into room_unit_comments values (3354, 110601, 2, 4, 1, 0, 1, '木陰でのんびり\\nお昼寝…\\n最高やね～', 0);
insert into room_unit_comments values (3355, 110601, 2, 101, 4, 0, 1, 'お祭ではぐれても\\n王子はんなら見つけて\\nくれはります？', 0);
insert into room_unit_comments values (3356, 110601, 2, 102, 8, 0, 1, '楽しい夏やわぁ\\nずっとこんな日が\\nつづくとええね', 0);
insert into room_unit_comments values (3357, 110601, 2, 1, 1, 1, 1, 'うちにしては早起き？\\n暑くて目が早う\\n覚めてもうたんどす', 0);
insert into room_unit_comments values (3358, 110601, 2, 2, 1, 2, 1, 'お昼は冷たい\\nおそうめんとか\\nどうでっしゃろ', 0);
insert into room_unit_comments values (3359, 110601, 2, 3, 1, 3, 1, '夜は星がきれいやね\\n二人で浜辺でも\\n行きまへんか？', 0);
insert into room_unit_comments values (3361, 110601, 3, 2, 1, 0, 1, 'うーん、遊び疲れた\\n身体にちょうどええ\\nほっこり具合やわぁ', 0);
insert into room_unit_comments values (3362, 110601, 3, 3, 1, 0, 1, 'かいらしい子は\\nみーんな\\nマホマホ王国の\\n住人どすえ♪', 0);
insert into room_unit_comments values (3363, 110601, 3, 4, 1, 0, 1, 'この香り…\\n南国にいる気分やねぇ\\n癒されるわぁ～', 0);
insert into room_unit_comments values (3364, 110601, 3, 5, 1, 0, 1, 'これで\\n冷えた身体も\\nポカポカやねぇ', 0);
insert into room_unit_comments values (3366, 110601, 3, 7, 1, 0, 1, '外はまだ暑いやろうし\\nバテんよう\\nしっかり食べんとね', 0);
insert into room_unit_comments values (3367, 110601, 3, 8, 1, 0, 1, '海の中にもお城が\\nあるんやねぇ\\n行ってみたいわぁ', 0);
insert into room_unit_comments values (3369, 110601, 3, 10, 1, 0, 1, 'この子、ふかふかやね\\nこのままマホマホ王国\\n乗せてってくれはる？', 0);
insert into room_unit_comments values (3370, 110601, 3, 11, 1, 0, 1, '人魚姫になっても\\n最後は王子はんと\\nハッピーエンド\\nどすえ～', 0);
insert into room_unit_comments values (3371, 107001, 1, 1, 1, 0, 1, '真似したくなる\\n人がここには\\n大勢いますね', 0);
insert into room_unit_comments values (3372, 107001, 1, 2, 1, 0, 1, '偽物を一人\\n紛れこませました\\n…冗談です', 0);
insert into room_unit_comments values (3373, 107001, 1, 3, 1, 0, 1, '動物に変身して\\nその辺りを\\n散歩してきます', 0);
insert into room_unit_comments values (3374, 107001, 1, 4, 1, 0, 1, '失った記憶は\\nどの程度回復するの\\nでしょうね', 0);
insert into room_unit_comments values (3375, 107001, 1, 5, 1, 0, 1, '人や物だけでなく\\nいずれは世界すら\\n真似てみせます', 0);
insert into room_unit_comments values (3376, 107001, 1, 101, 4, 0, 1, '次は彼に\\nどんなことを\\n教えましょうか…', 0);
insert into room_unit_comments values (3377, 107001, 1, 102, 8, 0, 1, '知識はともかく\\n私の力はまだ\\n必要なようですね', 0);
insert into room_unit_comments values (3378, 107001, 2, 1, 1, 0, 1, 'どうしました？\\n…何でもない？\\n…そうですか', 0);
insert into room_unit_comments values (3379, 107001, 2, 2, 1, 0, 1, '退屈しています\\n芸でもして\\n楽しませなさい', 0);
insert into room_unit_comments values (3380, 107001, 2, 3, 1, 0, 1, '研究のためです\\n少し話し相手に\\nなりなさい', 0);
insert into room_unit_comments values (3381, 107001, 2, 4, 1, 0, 1, '何か真似して欲しい？\\n私の能力を何だと\\n思っているのですか', 0);
insert into room_unit_comments values (3382, 107001, 2, 101, 4, 0, 1, '貴方にはまだ色々と\\n教えるべきことが\\nありますね', 0);
insert into room_unit_comments values (3383, 107001, 2, 102, 8, 0, 1, '随分多くの女性と\\n知り合いなのですね\\n驚きました', 0);
insert into room_unit_comments values (3384, 107001, 2, 1, 1, 1, 1, '…\\nおはようございます\\n…まだ朝ですよ', 0);
insert into room_unit_comments values (3385, 107001, 2, 2, 1, 2, 1, '食事にします\\n…どうしました？\\n早く持ってきなさい', 0);
insert into room_unit_comments values (3386, 107001, 2, 3, 1, 3, 1, '早く寝なさい\\n夜更かしすると\\n背が伸びませんよ？', 0);
insert into room_unit_comments values (3388, 107001, 3, 2, 1, 0, 1, 'マサキより\\n座り心地は\\nいいですね', 0);
insert into room_unit_comments values (3389, 107001, 3, 3, 1, 0, 1, '意外に複雑な\\n構造ですね', 0);
insert into room_unit_comments values (3390, 107001, 3, 4, 1, 0, 1, '真似るなら\\n香りまで\\n再現しなくては', 0);
insert into room_unit_comments values (3391, 107001, 3, 5, 1, 0, 1, '発火現象の\\n模倣…なかなか\\n難しいものです', 0);
insert into room_unit_comments values (3393, 107001, 3, 7, 1, 0, 1, '偽物や分身を作るには\\nエネルギーが\\n必要不可欠なのです', 0);
insert into room_unit_comments values (3394, 107001, 3, 8, 1, 0, 1, '暇つぶしには\\nちょうどよさそうです\\n…', 0);
insert into room_unit_comments values (3396, 110701, 1, 1, 1, 0, 1, '学院かぁ…\\n友達の作り方の\\n授業はないかな？', 0);
insert into room_unit_comments values (3397, 110701, 1, 2, 1, 0, 1, '学院でぼっちに\\nなったときのために、\\n避難場所を\\n探しておかないと…', 0);
insert into room_unit_comments values (3398, 110701, 1, 3, 1, 0, 1, 'ぼっちの私が学院…\\nな、なんだか\\n目まいがしてきました', 0);
insert into room_unit_comments values (3399, 110701, 1, 4, 1, 0, 1, 'クラスメイトに\\n話しかける練習…\\nむ、難しすぎます…！', 0);
insert into room_unit_comments values (3400, 110701, 1, 5, 1, 0, 1, '目指せ友達100人…\\n無理かな…10人…\\nや、やっぱり一人！', 0);
insert into room_unit_comments values (3401, 110701, 1, 101, 4, 0, 1, 'あなたと学院生活が\\n送れるなんて、\\nとっても\\nうれしいです！', 0);
insert into room_unit_comments values (3402, 110701, 1, 102, 8, 0, 1, 'えへへ…\\n学院でも、\\nあなたと一緒に\\n居られてうれしいな♪', 0);
insert into room_unit_comments values (3403, 110701, 2, 1, 1, 0, 1, 'が、学院ってあんなに\\n人が居るんですね…\\n友達作りのイメトレを\\nやり直さないと！', 0);
insert into room_unit_comments values (3404, 110701, 2, 2, 1, 0, 1, '私にとって\\n部活動とはＢＢ団！\\n今日もたくさん\\n活動しましょうね！', 0);
insert into room_unit_comments values (3405, 110701, 2, 3, 1, 0, 1, '休み時間は寝たふり…\\nご飯はおトイレ…\\nぼっち対策は完璧です', 0);
insert into room_unit_comments values (3406, 110701, 2, 4, 1, 0, 1, '学院で友達を作る\\n勉強は完璧ですよ！\\n購買部でパンを買って\\n渡すんですよね！', 0);
insert into room_unit_comments values (3407, 110701, 2, 101, 4, 0, 1, '学院でも、\\nBB団の活動を\\nしていきましょうね♪', 0);
insert into room_unit_comments values (3408, 110701, 2, 102, 8, 0, 1, 'ぼっちに学院生活は\\n厳しいですね…でも、\\nあなたと一緒なら\\n乗りこえられそうです', 0);
insert into room_unit_comments values (3409, 110701, 2, 1, 1, 1, 1, 'もうこんな時間…\\nあの…一緒に学院に\\n行ってくれませんか？', 0);
insert into room_unit_comments values (3410, 110701, 2, 2, 1, 2, 1, 'お昼ですね！\\n言ってくれれば、\\nパンでもお握りでも\\n買ってきますよ！', 0);
insert into room_unit_comments values (3411, 110701, 2, 3, 1, 3, 1, '今日もぼっち…\\nいつか友達と一緒に、\\nパジャマパーティー\\nしたいなぁ…', 0);
insert into room_unit_comments values (3413, 110701, 3, 2, 1, 0, 1, '森とは違う\\n心地良さが…このまま\\n眠っちゃいそうです…', 0);
insert into room_unit_comments values (3414, 110701, 3, 3, 1, 0, 1, 'かわいい…この子を、\\n話す練習の相手役に\\nしてみようかな？', 0);
insert into room_unit_comments values (3415, 110701, 3, 4, 1, 0, 1, 'いい香り…\\nいつ友達ができても\\nいいように、私の\\n部屋にも置こうかな', 0);
insert into room_unit_comments values (3416, 110701, 3, 5, 1, 0, 1, 'こ、これは…\\nぼっちで\\n日陰者の私には\\n暖かすぎます！', 0);
insert into room_unit_comments values (3418, 110701, 3, 7, 1, 0, 1, 'おいしい…！\\nお弁当にして、学院に\\n持っていけないかな？', 0);
insert into room_unit_comments values (3419, 110701, 3, 8, 1, 0, 1, '学院の授業に\\nついていくためにも、\\n勉強しておこうかな…', 0);
insert into room_unit_comments values (3421, 110801, 1, 1, 1, 0, 1, 'あんた、何してんの。\\nいいけど、なんでも', 0);
insert into room_unit_comments values (3422, 110801, 1, 2, 1, 0, 1, '邪魔。どいて。\\nいや怒ってないし。\\nコレがフツーだから', 0);
insert into room_unit_comments values (3423, 110801, 1, 3, 1, 0, 1, 'いいけど、\\n散らかしめの部屋だと\\n片付けたくなるよね…', 0);
insert into room_unit_comments values (3424, 110801, 1, 4, 1, 0, 1, '暇なときは明日の\\nコーデ考えてるよ。\\n考えるのはタダだし', 0);
insert into room_unit_comments values (3425, 110801, 1, 5, 1, 0, 1, '昔よくシオリン\\n構いすぎてハツネに\\n文句言われたなァ…', 0);
insert into room_unit_comments values (3426, 110801, 1, 101, 4, 0, 1, 'なんかさ。あんたって\\n謎に女子トモ多いよね\\n…いいけど、べつに', 0);
insert into room_unit_comments values (3427, 110801, 1, 102, 8, 0, 1, 'ねえ。あのさあ。\\nあんた弁当で好きな\\n具とかってあんの', 0);
insert into room_unit_comments values (3428, 110801, 2, 1, 1, 0, 1, 'あ？\u3000何。なんか用。\\nや、ないならないで\\nいいけど、べつに', 0);
insert into room_unit_comments values (3429, 110801, 2, 2, 1, 0, 1, 'ごめ、ちょっと\\n黙っててくんない。\\n明日の試験ヤバだから', 0);
insert into room_unit_comments values (3430, 110801, 2, 3, 1, 0, 1, '歩き方が静か？\\n癖になってるんだよね\\n足音を殺すの', 0);
insert into room_unit_comments values (3431, 110801, 2, 4, 1, 0, 1, 'うちの血液型？\\n大雑把のОだけど。\\nなんか文句あんの', 0);
insert into room_unit_comments values (3432, 110801, 2, 101, 4, 0, 1, 'ひゃんっ！\\nや、だからさ…急に\\n話しかけんなっての', 0);
insert into room_unit_comments values (3433, 110801, 2, 102, 8, 0, 1, 'な、何…あんまジッと\\n見ないでくんない…\\nなんか、その、ハズい', 0);
insert into room_unit_comments values (3434, 110801, 2, 1, 1, 1, 1, '早起きは得意な方だと\\n思うけど。昔から\\nそれがデフォだったし', 0);
insert into room_unit_comments values (3435, 110801, 2, 2, 1, 2, 1, 'こんな時間か…\\n昼ごはん\\nサクッと作っちゃお', 0);
insert into room_unit_comments values (3436, 110801, 2, 3, 1, 3, 1, 'あ？\u3000夜遊び？\\nはッ…そんなん\\n５歳で卒業したっての', 0);
insert into room_unit_comments values (3438, 110801, 3, 2, 1, 0, 1, 'あーヤバじゃんコレ…\\nふかついてる場合\\nじゃないっつーのに…', 0);
insert into room_unit_comments values (3439, 110801, 3, 3, 1, 0, 1, 'なんだこれ\\nかわいいかよ', 0);
insert into room_unit_comments values (3440, 110801, 3, 4, 1, 0, 1, 'ふーん。\\nこの匂い…\\nなんかいいじゃん', 0);
insert into room_unit_comments values (3441, 110801, 3, 5, 1, 0, 1, '暖炉はアドじゃん。\\n煮物、焼き物、蒸し物\\nいろいろ作れそう', 0);
insert into room_unit_comments values (3443, 110801, 3, 7, 1, 0, 1, '何コレ\\n食べ物困んないじゃん\\nうちにも一台くんない', 0);
insert into room_unit_comments values (3444, 110801, 3, 8, 1, 0, 1, '本かァー…んー\\n学校の勉強だけで\\nいいかなァ…', 0);
insert into room_unit_comments values (3446, 111101, 1, 1, 1, 0, 1, 'イタズラってなにを\\nしたらいいのかな？', 0);
insert into room_unit_comments values (3447, 111101, 1, 2, 1, 0, 1, 'カップケーキ\\n上手に作れました\\n食べてくれるかな…', 0);
insert into room_unit_comments values (3448, 111101, 1, 3, 1, 0, 1, 'あの人、\\nお菓子くれるかな？\\nくれなかったら…ふふ', 0);
insert into room_unit_comments values (3449, 111101, 1, 4, 1, 0, 1, 'オバケ…いないよね？\\n怖くなんてないけど！', 0);
insert into room_unit_comments values (3450, 111101, 1, 5, 1, 0, 1, 'ハロウィンは\\n楽しいけどオバケの\\nお祭りなんだよね…', 0);
insert into room_unit_comments values (3451, 111101, 1, 101, 4, 0, 1, 'にゃ～、にゃお～！\\nちゃんと怖いかな？\\n早く帰ってこないかな', 0);
insert into room_unit_comments values (3452, 111101, 1, 102, 8, 0, 1, 'あの人のことだから\\nお菓子欲しがるよね…\\n準備はバッチリです♪', 0);
insert into room_unit_comments values (3453, 111101, 2, 1, 1, 0, 1, 'えへへ。猫さんのお耳\\nよく出来てるでしょ？', 0);
insert into room_unit_comments values (3454, 111101, 2, 2, 1, 0, 1, '触りましたね？\\nイタズラしましたね？\\nへんた～い！', 0);
insert into room_unit_comments values (3455, 111101, 2, 3, 1, 0, 1, 'フー！\u3000頭を撫でたら\\n怒りますよ！\u3000あれ？\\n猫みたいでした？', 0);
insert into room_unit_comments values (3456, 111101, 2, 4, 1, 0, 1, 'きゃっ！\u3000も、もう、\\n脅かさないでください\\n怖くありませんけど！', 0);
insert into room_unit_comments values (3457, 111101, 2, 101, 4, 0, 1, 'お菓子ですか？\\nありがとうございます\\nハッピーハロウィン♪', 0);
insert into room_unit_comments values (3458, 111101, 2, 102, 8, 0, 1, 'ゴロゴロ…\\nね、猫さんの真似です\\n…似てましたか？', 0);
insert into room_unit_comments values (3459, 111101, 2, 1, 1, 1, 1, 'さぁ、お菓子作りを\\n始めますよ。下準備は\\n大事ですからね！', 0);
insert into room_unit_comments values (3460, 111101, 2, 2, 1, 2, 1, '今、つまみ食い\\nしましたね！？\u3000あっ\\nおやつの時間でしたか', 0);
insert into room_unit_comments values (3461, 111101, 2, 3, 1, 3, 1, 'さぁ、ハロウィンの\\n始まりです…ふぁ…\\nね、眠くありません！', 0);
insert into room_unit_comments values (3463, 111101, 3, 2, 1, 0, 1, 'ちょっと疲れたかも…\\nパーティの時間まで\\nひと休みしなきゃ', 0);
insert into room_unit_comments values (3464, 111101, 3, 3, 1, 0, 1, '私も今、こんな感じ\\nなのかな？\u3000こんなに\\nかわいいといいなぁ', 0);
insert into room_unit_comments values (3465, 111101, 3, 4, 1, 0, 1, '甘い匂いがいっぱい…\\nお菓子の香りかな？', 0);
insert into room_unit_comments values (3466, 111101, 3, 5, 1, 0, 1, '温かくなると、\\n丸まりたくなって…\\n…猫になっちゃう！？', 0);
insert into room_unit_comments values (3468, 111101, 3, 7, 1, 0, 1, 'ニンジンもこれくらい\\nおいしければ\\nいいのに…', 0);
insert into room_unit_comments values (3469, 111101, 3, 8, 1, 0, 1, 'ハロウィンの本、\\nオバケがたくさん\\n載ってて怖いかも…', 0);
insert into room_unit_comments values (3471, 111101, 3, 12, 1, 0, 1, '美味しそうなお菓子が\\nいっぱい…これなら\\nイタズラされませんね', 0);
insert into room_unit_comments values (3473, 111201, 1, 1, 1, 0, 1, 'たくさんいたずら\\nできるから\\nハロウィン大好き！', 0);
insert into room_unit_comments values (3474, 111201, 1, 2, 1, 0, 1, 'ハロウィンだから\\nいつもよりすごい\\nいたずらしたいな～！', 0);
insert into room_unit_comments values (3475, 111201, 1, 3, 1, 0, 1, 'カボチャを綺麗に\\nくり抜いてすごく怖い\\nランタン作っちゃお！', 0);
insert into room_unit_comments values (3476, 111201, 1, 4, 1, 0, 1, 'お菓子がたくさんで\\nどれから食べるか\\n迷っちゃうな～！', 0);
insert into room_unit_comments values (3477, 111201, 1, 5, 1, 0, 1, 'どうすればみんなを\\nびっくりさせられる\\nかな～？', 0);
insert into room_unit_comments values (3478, 111201, 1, 101, 4, 0, 1, 'カボチャ見てたら\\nお腹空いて来たな～\\nお菓子食べちゃお♪', 0);
insert into room_unit_comments values (3479, 111201, 1, 102, 8, 0, 1, 'にいちゃんには\\n特別ないたずらを\\n用意してあげるね！', 0);
insert into room_unit_comments values (3480, 111201, 2, 1, 1, 0, 1, 'カボチャにクラッカー\\nを仕掛けて…わっ！？\\nみ、見ちゃダメだよ！', 0);
insert into room_unit_comments values (3481, 111201, 2, 2, 1, 0, 1, 'ん？\u3000なぁに？\\nお菓子ほしいの？\\nもう、しかたないな～', 0);
insert into room_unit_comments values (3482, 111201, 2, 3, 1, 0, 1, 'にいちゃんの\\n面白い仮装が\\n見てみたいな～！', 0);
insert into room_unit_comments values (3483, 111201, 2, 4, 1, 0, 1, 'お菓子くれたお礼に\\nとびっきりの\\nいたずらしちゃうね！', 0);
insert into room_unit_comments values (3484, 111201, 2, 101, 4, 0, 1, 'にいちゃんは\\nハロウィンでも最高の\\nいたずら相手だよ！', 0);
insert into room_unit_comments values (3485, 111201, 2, 102, 8, 0, 1, 'にいちゃんと一緒に\\nハロウィンパレード\\n歩きたいな～！', 0);
insert into room_unit_comments values (3486, 111201, 2, 1, 1, 1, 1, 'おはようにいちゃん！\\n仮装して出かける\\n準備しなきゃ！', 0);
insert into room_unit_comments values (3487, 111201, 2, 2, 1, 2, 1, 'お腹すいたな～\\nもらったお菓子\\n食べちゃだめかな？', 0);
insert into room_unit_comments values (3488, 111201, 2, 3, 1, 3, 1, 'たくさんいたずらして\\nもうクタクタ～\\nミソギもう寝るね…', 0);
insert into room_unit_comments values (3490, 111201, 3, 2, 1, 0, 1, 'やわらか～い…\\nここでひと休みして\\nまたいたずらしよう！', 0);
insert into room_unit_comments values (3491, 111201, 3, 3, 1, 0, 1, 'かわいいもので\\n油断させてわっ！\\nってするのどうかな？', 0);
insert into room_unit_comments values (3492, 111201, 3, 4, 1, 0, 1, 'いいにお～い！\\nいたずらのアイデアが\\nわいてくるよ！', 0);
insert into room_unit_comments values (3493, 111201, 3, 5, 1, 0, 1, 'もらったお菓子\\nあったかくしたら\\nおいしいかな～？', 0);
insert into room_unit_comments values (3495, 111201, 3, 7, 1, 0, 1, 'お菓子ばっかりじゃ\\n飽きちゃうもんね！\\nご飯も食べよう！', 0);
insert into room_unit_comments values (3496, 111201, 3, 8, 1, 0, 1, '本のなかに\\nいたずらのヒント\\nないかな～？', 0);
insert into room_unit_comments values (3498, 111201, 3, 12, 1, 0, 1, 'お菓子がたくさん！\\n一人で食べていいの？\\nやっぱりだめか～！', 0);
insert into room_unit_comments values (3500, 101101, 1, 103, 12, 0, 1, 'お勉強は順調ですよ\\nやっぱりお兄ちゃんの\\nおかげなんでしょうか', 0);
insert into room_unit_comments values (3501, 101101, 2, 103, 12, 0, 1, 'お兄ちゃんとの\\n思い出の場所\\nまた行きましょうね', 0);
insert into room_unit_comments values (3502, 111301, 1, 1, 1, 0, 1, 'えへへ～♪\\nハロウィンの\\nミイラさんうさぎさん\\nぴょんぴょ～ん！', 0);
insert into room_unit_comments values (3503, 111301, 1, 2, 1, 0, 1, 'るんたった～\\nハロウィンハロウィン\\n楽しいな～♪', 0);
insert into room_unit_comments values (3504, 111301, 1, 3, 1, 0, 1, 'ハロウィンって\\nどんなお菓子を\\nもらえるのかな～？', 0);
insert into room_unit_comments values (3505, 111301, 1, 4, 1, 0, 1, 'お菓子をもらう\\n練習をしなくちゃ！\\nトリックオア\\nトリート～♪', 0);
insert into room_unit_comments values (3506, 111301, 1, 5, 1, 0, 1, 'おにいちゃんと\\nハロウィンするの\\nミミ楽しみだな～♪', 0);
insert into room_unit_comments values (3507, 111301, 1, 101, 4, 0, 1, 'おにいちゃんと\\nいっしょにお菓子を\\n食べたいな～', 0);
insert into room_unit_comments values (3508, 111301, 1, 102, 8, 0, 1, 'おにいちゃんと\\n毎日ハロウィン\\nできたらいいな～♪', 0);
insert into room_unit_comments values (3509, 111301, 2, 1, 1, 0, 1, 'えへへ～\\nおにいちゃん！\\nハッピーハロウィン♪', 0);
insert into room_unit_comments values (3510, 111301, 2, 2, 1, 0, 1, 'おにいちゃんも\\nいっしょに\\nハロウィンパレード\\nしようね～！', 0);
insert into room_unit_comments values (3511, 111301, 2, 3, 1, 0, 1, 'ミイラさんうさぎさん\\nだぞ～…えへへ\\nミミこわかったかな？', 0);
insert into room_unit_comments values (3512, 111301, 2, 4, 1, 0, 1, 'おにいちゃん！\\nハロウィンのお菓子\\nおいしいね～♪', 0);
insert into room_unit_comments values (3513, 111301, 2, 101, 4, 0, 1, 'おにいちゃんと\\nいっしょなら\\nおばけさんも\\nこわくないよ！', 0);
insert into room_unit_comments values (3514, 111301, 2, 102, 8, 0, 1, 'ミミね\\nハロウィンも\\nおにいちゃんも\\nだ～いすき♪', 0);
insert into room_unit_comments values (3515, 111301, 2, 1, 1, 1, 1, 'おひさまさんも\\nハロウィンの\\nおようふく\\n着たいかな～？', 0);
insert into room_unit_comments values (3516, 111301, 2, 2, 1, 2, 1, 'ねえねえおにいちゃん\\nお昼ごはんはもらった\\nお菓子でもい～い？', 0);
insert into room_unit_comments values (3517, 111301, 2, 3, 1, 3, 1, 'まだハロウィン…？\\nうぅん…眠くないよぅ\\nでもちょっと…ふぁ～', 0);
insert into room_unit_comments values (3519, 111301, 3, 2, 1, 0, 1, 'ふかふか～♪\\nおばけさんが\\n中にいるのかな～？', 0);
insert into room_unit_comments values (3520, 111301, 3, 3, 1, 0, 1, 'わぁ、かわいい～♪\\nミミといっしょに\\nあそぼ～！', 0);
insert into room_unit_comments values (3521, 111301, 3, 4, 1, 0, 1, 'ふわぁ～\\nミミ、このにおい\\nだ～いすき♪', 0);
insert into room_unit_comments values (3522, 111301, 3, 5, 1, 0, 1, 'あったかいね～♪\\nおばけさんも\\nポカポカしてるかな？', 0);
insert into room_unit_comments values (3524, 111301, 3, 7, 1, 0, 1, 'おいしい～♪\\nおにいちゃんも\\n食べようよー！', 0);
insert into room_unit_comments values (3525, 111301, 3, 8, 1, 0, 1, 'この本\\nおにいちゃんと\\nいっしょに\\n読みたいな～', 0);
insert into room_unit_comments values (3527, 111301, 3, 12, 1, 0, 1, 'ハッピーハロウィン♪\\nえへへ、お菓子が\\nいっぱいだね～！', 0);
insert into room_unit_comments values (3529, 111401, 1, 1, 1, 0, 1, 'ここ、好きだよ。\\nみんな優しいから…', 0);
insert into room_unit_comments values (3530, 111401, 1, 2, 1, 0, 1, 'なんかさみしいな', 0);
insert into room_unit_comments values (3531, 111401, 1, 3, 1, 0, 1, '知らない人怖いな', 0);
insert into room_unit_comments values (3532, 111401, 1, 4, 1, 0, 1, 'お部屋おっきいねー', 0);
insert into room_unit_comments values (3533, 111401, 1, 5, 1, 0, 1, 'ルナね…\\nお昼寝したいかも', 0);
insert into room_unit_comments values (3534, 111401, 1, 101, 4, 0, 1, 'おにいさん！\\n今日は何して遊ぶの？', 0);
insert into room_unit_comments values (3535, 111401, 1, 102, 8, 0, 1, 'あのね、\\nお料理教えてほしい！', 0);
insert into room_unit_comments values (3536, 111401, 2, 1, 1, 0, 1, 'あっ、おにいさんだ！', 0);
insert into room_unit_comments values (3537, 111401, 2, 2, 1, 0, 1, 'ルナは元気だよ！\\nいいこだもん！', 0);
insert into room_unit_comments values (3538, 111401, 2, 3, 1, 0, 1, '今日は何しようかな', 0);
insert into room_unit_comments values (3539, 111401, 2, 4, 1, 0, 1, 'ルナと遊んでよ！', 0);
insert into room_unit_comments values (3540, 111401, 2, 101, 4, 0, 1, 'ねーねー、\\nルナとお出かけして！', 0);
insert into room_unit_comments values (3541, 111401, 2, 102, 8, 0, 1, 'おにいさんと、\\n遊びたいなー！', 0);
insert into room_unit_comments values (3542, 111401, 2, 1, 1, 1, 1, 'ふふっ！\\nなんかまぶしいね！', 0);
insert into room_unit_comments values (3543, 111401, 2, 2, 1, 2, 1, 'ルナ、お腹空いたな', 0);
insert into room_unit_comments values (3544, 111401, 2, 3, 1, 3, 1, 'どこに行こうかな？', 0);
insert into room_unit_comments values (3546, 111401, 3, 2, 1, 0, 1, 'ルナ、これ好きだな', 0);
insert into room_unit_comments values (3547, 111401, 3, 3, 1, 0, 1, 'かわいい！\u3000好き！', 0);
insert into room_unit_comments values (3548, 111401, 3, 4, 1, 0, 1, 'なんかいい匂い！', 0);
insert into room_unit_comments values (3549, 111401, 3, 5, 1, 0, 1, 'あったかいねー', 0);
insert into room_unit_comments values (3551, 111401, 3, 7, 1, 0, 1, 'ふふっ\\nおいしいね', 0);
insert into room_unit_comments values (3552, 111401, 3, 8, 1, 0, 1, 'ルナ、\\n眠くなっちゃう…', 0);
insert into room_unit_comments values (3554, 105201, 1, 103, 12, 0, 1, 'えへへ。あの人と\\nランドソルでデート\\nできたらうれしいな♪', 0);
insert into room_unit_comments values (3555, 105201, 2, 103, 12, 0, 1, 'あなたとなら\\nどんなことだって\\nできる気がするわ♪', 0);
insert into room_unit_comments values (3556, 106501, 1, 1, 1, 0, 1, 'あーあ、退屈だな\\nカレでも探しに\\nいこうかな', 0);
insert into room_unit_comments values (3557, 106501, 1, 2, 1, 0, 1, 'この前のケンカは\\n最高に燃えたなぁ\\n…拳が疼いてきたぜ', 0);
insert into room_unit_comments values (3558, 106501, 1, 3, 1, 0, 1, '一体、この世界は\\nどうなっちまったって\\nいうんだ…？', 0);
insert into room_unit_comments values (3559, 106501, 1, 4, 1, 0, 1, 'もう仕事の時間か\\nボスも人使いが荒いぜ\\n…ま、いいけどさ！', 0);
insert into room_unit_comments values (3560, 106501, 1, 5, 1, 0, 1, 'オレたち以外に\\nドラゴン族はあと何人\\nいるんだろうな…', 0);
insert into room_unit_comments values (3561, 106501, 1, 101, 4, 0, 1, 'カレの真剣な顔\\n面白かったな\\nまた遊びたいぜ', 0);
insert into room_unit_comments values (3562, 106501, 1, 102, 8, 0, 1, 'どうしてカレがそばに\\nいると、腹の底から\\n力が湧いてくるんだ？', 0);
insert into room_unit_comments values (3563, 106501, 2, 1, 1, 0, 1, 'よっす！\\nなんかオイシイ話でも\\nあったりしない？', 0);
insert into room_unit_comments values (3564, 106501, 2, 2, 1, 0, 1, 'なあ、オレと遊ぼうぜ\\n心配すんなよ。危ない\\nことはよしとくからさ', 0);
insert into room_unit_comments values (3565, 106501, 2, 3, 1, 0, 1, 'どうした。オレに\\nケンカ売ろうってか？\\n…ははは、冗談だよ！', 0);
insert into room_unit_comments values (3566, 106501, 2, 4, 1, 0, 1, 'ちょうど退屈してた\\nところだ、特訓に\\n付き合ってくれよ', 0);
insert into room_unit_comments values (3567, 106501, 2, 101, 4, 0, 1, 'ったくよぉ…\\nオレがかわいいなんて\\n冗談はもうよせよ？', 0);
insert into room_unit_comments values (3568, 106501, 2, 102, 8, 0, 1, '次の仕事も一緒に\\n来るだろ？\u3000断っても\\n連れて行くけどな！', 0);
insert into room_unit_comments values (3569, 106501, 2, 1, 1, 1, 1, 'おはよう！\u3000今日の\\n予定はまずケンカして\\nで、その後もケンカだ', 0);
insert into room_unit_comments values (3570, 106501, 2, 2, 1, 2, 1, 'よっす！\\n腹ごしらえが済んだら\\nオレと遊ぼうぜ！', 0);
insert into room_unit_comments values (3571, 106501, 2, 3, 1, 3, 1, '夜は危ないから\\nあんま出歩くな？\\n…だから面白えんだろ', 0);
insert into room_unit_comments values (3573, 106501, 3, 2, 1, 0, 1, '次のケンカに備えて\\n今は休んでおくか…\\n全力で暴れたいからな', 0);
insert into room_unit_comments values (3574, 106501, 3, 3, 1, 0, 1, 'ボスの飼ってる\\nラーゴが、中に\\n入ってるんじゃ？', 0);
insert into room_unit_comments values (3575, 106501, 3, 4, 1, 0, 1, 'ああ、たぎる匂いが\\nする…ひと暴れ\\nしたくなってきた！', 0);
insert into room_unit_comments values (3576, 106501, 3, 5, 1, 0, 1, 'おおぉ…\\nオレの拳もなんだか\\n熱くなってきたぜ…！', 0);
insert into room_unit_comments values (3578, 106501, 3, 7, 1, 0, 1, 'いつでも全力で\\nケンカするために\\n力を蓄えないとな', 0);
insert into room_unit_comments values (3579, 106501, 3, 8, 1, 0, 1, 'やっぱりな…オレが\\n知ってる地図とは\\nまるで違ってやがる', 0);
insert into room_unit_comments values (3581, 111501, 1, 1, 1, 0, 1, 'さぁプレゼントで\\n埋め尽くしてやろう！\\n大いに喜ぶがいいよ！', 0);
insert into room_unit_comments values (3582, 111501, 1, 2, 1, 0, 1, 'メリークリスマス☆\\n聖夜の宴だ\\n派手に楽しむとしよう', 0);
insert into room_unit_comments values (3583, 111501, 1, 3, 1, 0, 1, '煙突から入る？\\nいいや、ワタシは\\nいつでも正面からさ♪', 0);
insert into room_unit_comments values (3584, 111501, 1, 4, 1, 0, 1, 'サンタクロースの\\nお出ましだ！\\n歓迎するがいいよ♪', 0);
insert into room_unit_comments values (3585, 111501, 1, 5, 1, 0, 1, '飾り付けが足りん！\\nワタシが演出して\\nやろうじゃないか！', 0);
insert into room_unit_comments values (3586, 111501, 1, 101, 4, 0, 1, '人の喜ぶ顔を見るのも\\n悪くはないな…おっと\\nワタシらしくないな☆', 0);
insert into room_unit_comments values (3587, 111501, 1, 102, 8, 0, 1, 'プレゼントはまだか？\\nワタシを喜ばせたら\\nお返しは弾むぞ♪', 0);
insert into room_unit_comments values (3588, 111501, 2, 1, 1, 0, 1, 'ワタシを呼んだか？\\n退屈な要件だったら\\n覚悟しておくことだ', 0);
insert into room_unit_comments values (3589, 111501, 2, 2, 1, 0, 1, 'なんだ？\\nワタシへの挑戦か？\\nよし、受けた♪', 0);
insert into room_unit_comments values (3590, 111501, 2, 3, 1, 0, 1, 'おっと、当たらんよ\\nワタシの乱数聖域は\\n絶対だからな…♪', 0);
insert into room_unit_comments values (3591, 111501, 2, 4, 1, 0, 1, 'なんだ、オマエも\\n暇なのか？\\n奇遇だな、ワタシもさ', 0);
insert into room_unit_comments values (3592, 111501, 2, 101, 4, 0, 1, 'なにか愉しいことでも\\nしようじゃないか\\nさぁ、何をする？', 0);
insert into room_unit_comments values (3593, 111501, 2, 102, 8, 0, 1, 'こうもワタシに\\n気安く触れるのは\\nオマエくらいだよ…♪', 0);
insert into room_unit_comments values (3594, 111501, 2, 1, 1, 1, 1, '朝だろうと関係ない！\\nさぁ愉しく苛烈に\\n騒ごうじゃないか♪', 0);
insert into room_unit_comments values (3595, 111501, 2, 2, 1, 2, 1, '調子の出てくる時間だ\\nしっかりワタシを\\n愉しませてくれよ♪', 0);
insert into room_unit_comments values (3596, 111501, 2, 3, 1, 3, 1, '眠いなどと言わせんぞ\\nまだまだ一日は\\n終わらんからな！', 0);
insert into room_unit_comments values (3598, 111501, 3, 2, 1, 0, 1, 'いい具合じゃないか\\nこのまま持って帰って\\nしまおうか…♪', 0);
insert into room_unit_comments values (3599, 111501, 3, 3, 1, 0, 1, 'なかなか愛らしい\\n造形をしているな？\\nワタシには負けるがな', 0);
insert into room_unit_comments values (3600, 111501, 3, 4, 1, 0, 1, 'ほう、悪くない香りだ\\n戦いの匂いをうまく\\n隠してくれそうだ…♪', 0);
insert into room_unit_comments values (3601, 111501, 3, 5, 1, 0, 1, '体が温まってくると\\nひと暴れしたくなるな', 0);
insert into room_unit_comments values (3603, 111501, 3, 7, 1, 0, 1, 'ワタシの舌は厳しいぞ\\n…ふーむ、なるほど\\n認めざるをえんな', 0);
insert into room_unit_comments values (3604, 111501, 3, 8, 1, 0, 1, 'クリスティーナさんは\\n知識の収集も\\n欠かさないんだよ', 0);
insert into room_unit_comments values (3606, 111501, 3, 14, 1, 0, 1, 'これは驚いたな\\nだがもっと、もっとだ\\nワタシを退屈させるな', 0);
insert into room_unit_comments values (3607, 111501, 3, 15, 1, 0, 1, 'こんな戯れだって\\n軽くこなしてしまう\\nクリスティーナさんさ', 0);
insert into room_unit_comments values (3608, 111601, 1, 1, 1, 0, 1, 'メリークリスマス！\\nさあ、パーティーを\\n盛り上げるよ！', 0);
insert into room_unit_comments values (3609, 111601, 1, 2, 1, 0, 1, '衣装一つで全然\\n気分が違うね！\\n最高のクリスマスに\\nなりそうだよ！', 0);
insert into room_unit_comments values (3610, 111601, 1, 3, 1, 0, 1, 'ツリーのてっぺんの\\n星って、なんだか\\n欲しくなるんだよね', 0);
insert into room_unit_comments values (3611, 111601, 1, 4, 1, 0, 1, 'めいっぱい\\nクリスマスを楽しむよ\\n遊びだって本気\\nなんだからね！', 0);
insert into room_unit_comments values (3612, 111601, 1, 5, 1, 0, 1, '赤、白、緑、金\\nクリスマスカラー\\nってお洒落だよね', 0);
insert into room_unit_comments values (3613, 111601, 1, 101, 4, 0, 1, '雪、降らないかな？\\nホワイトクリスマス\\nってちょっと\\n憧れるなぁ', 0);
insert into room_unit_comments values (3614, 111601, 1, 102, 8, 0, 1, 'キミと過ごすこの\\n楽しい時間がずーっと\\n続けばいいのにな', 0);
insert into room_unit_comments values (3615, 111601, 2, 1, 1, 0, 1, 'クリスマスライブ\\nチケット用意するから\\n絶対来てよね！', 0);
insert into room_unit_comments values (3616, 111601, 2, 2, 1, 0, 1, 'カンパーイ！\\nジュースだけど\\nちょっと大人の\\n気分だね', 0);
insert into room_unit_comments values (3617, 111601, 2, 3, 1, 0, 1, 'クリスマス衣装どう？\\nかわいいでしょ\\nあっ、どこ見てるの！', 0);
insert into room_unit_comments values (3618, 111601, 2, 4, 1, 0, 1, 'ねえ、後で街に\\n行こうよ\\n大きなツリーを\\n一緒に見たいんだ♪', 0);
insert into room_unit_comments values (3619, 111601, 2, 101, 4, 0, 1, 'ねえ、ダンスの練習に\\n付き合ってくれない？\\n大丈夫、手取り足取り\\n教えてあげるから♪', 0);
insert into room_unit_comments values (3620, 111601, 2, 102, 8, 0, 1, '来年のクリスマスも\\n隣にキミが\\nいてくれたら\\nうれしいのにな', 0);
insert into room_unit_comments values (3621, 111601, 2, 1, 1, 1, 1, 'クリスマスって朝から\\nドキドキしちゃうね\\nなんだか子どもみたい', 0);
insert into room_unit_comments values (3622, 111601, 2, 2, 1, 2, 1, 'パーティーの準備も\\n大分進んだね\\n一息ついて\\nランチにしよっか', 0);
insert into room_unit_comments values (3623, 111601, 2, 3, 1, 3, 1, '静かな夜だね\\n心臓の音まで\\n聞こえちゃいそう…', 0);
insert into room_unit_comments values (3625, 111601, 3, 2, 1, 0, 1, 'あ～、この絶妙な\\n柔らかさ…\\nいい仕事してるなぁ…', 0);
insert into room_unit_comments values (3626, 111601, 3, 3, 1, 0, 1, 'アイドル顔負けの\\nかわいさ、ズルい！\\nでもかわいい！', 0);
insert into room_unit_comments values (3627, 111601, 3, 4, 1, 0, 1, 'ん～、落ち着くなぁ\\n今日はゆっくり\\n眠れそうだよ', 0);
insert into room_unit_comments values (3628, 111601, 3, 5, 1, 0, 1, 'ぬくぬく～\\nどうしよう、ここから\\n動きたくないなぁ', 0);
insert into room_unit_comments values (3630, 111601, 3, 7, 1, 0, 1, 'ダンスの練習もしたし\\nちょっとくらいなら\\nいいよね！', 0);
insert into room_unit_comments values (3631, 111601, 3, 8, 1, 0, 1, 'アイドルといえど\\nかわいいだけじゃダメ\\n知識も必要だよね', 0);
insert into room_unit_comments values (3633, 111601, 3, 14, 1, 0, 1, '面白ーい！\\nこの演出、ライブでも\\nできないかな？', 0);
insert into room_unit_comments values (3634, 111601, 3, 15, 1, 0, 1, 'もふもふ～♪\\n寒い日には最高の\\n抱き心地だね！', 0);
insert into room_unit_comments values (3635, 101801, 1, 103, 12, 0, 1, '彼ともっとお話し\\nしたいな…もう少し\\n補習を増やそうかしら', 0);
insert into room_unit_comments values (3636, 101801, 2, 103, 12, 0, 1, '君のこともっともっと\\n教えて欲しいな。私に\\n補習授業してくれる？', 0);
insert into room_unit_comments values (3637, 111701, 1, 1, 1, 0, 1, 'この姿ならあやつも\\n子ども扱いできまい！\\n…じゃがなぜか、少し\\n物足りないような…', 0);
insert into room_unit_comments values (3638, 111701, 1, 2, 1, 0, 1, '時間もあるし、\\n聖夜の宴の\\n準備をするかのう♪', 0);
insert into room_unit_comments values (3639, 111701, 1, 3, 1, 0, 1, '…わらわの知る聖夜と\\n随分違うが、宴は宴\\n楽しませて\\nもらおうかのう♪', 0);
insert into room_unit_comments values (3640, 111701, 1, 4, 1, 0, 1, '大人の姿で\\nできること…ふむ\\n少しあやつを\\nからかってやるか♪', 0);
insert into room_unit_comments values (3641, 111701, 1, 5, 1, 0, 1, '…クリスマスは\\n恋人たちの夜！？\\nち、近頃の若いもんは\\n破廉恥なのじゃ！', 0);
insert into room_unit_comments values (3642, 111701, 1, 101, 4, 0, 1, '…あやつがおらんと、\\n宴も物足りぬな\\n…馬鹿者が\\n早く帰ってこい…', 0);
insert into room_unit_comments values (3643, 111701, 1, 102, 8, 0, 1, '誰も見ておらぬな…？\\n…よし、あやつへの\\nプレゼントを\\n準備するとしようか！', 0);
insert into room_unit_comments values (3644, 111701, 2, 1, 1, 0, 1, 'クリスマスの\\nチキンにケーキ…\\nべ、別に楽しみになど\\nしておらぬぞ！', 0);
insert into room_unit_comments values (3645, 111701, 2, 2, 1, 0, 1, 'この姿では、わらわの\\n頭をなでるのは\\n難しかろう…べ、\\n別に残念ではないわ！', 0);
insert into room_unit_comments values (3646, 111701, 2, 3, 1, 0, 1, 'メリー\\nクリスマスじゃ！\\nさあ、わらわのために\\n宴の準備をするのじゃ', 0);
insert into room_unit_comments values (3647, 111701, 2, 4, 1, 0, 1, 'そんなにこの衣装が\\n気になるのか？\\n…だったら、直に\\n触ってみるがよい♪', 0);
insert into room_unit_comments values (3648, 111701, 2, 101, 4, 0, 1, 'いつもと逆に、お主を\\n子ども扱いしてやるか\\nほれ、膝枕をしてやる\\nからそばに来い♪', 0);
insert into room_unit_comments values (3649, 111701, 2, 102, 8, 0, 1, '…せ、聖夜の予定は\\n空けておくのじゃぞ？\\nなんでって…\\nな、なんでもじゃ！', 0);
insert into room_unit_comments values (3650, 111701, 2, 1, 1, 1, 1, 'もう朝か…聖夜の宴が\\n楽しみで…ではなく！\\n準備のせいで、\\nあまり眠れんかったぞ', 0);
insert into room_unit_comments values (3651, 111701, 2, 2, 1, 2, 1, '…ずっと雪が\\n降っておれば、\\n陽光が強いこの時間も\\n怯えずにすむのにのう', 0);
insert into room_unit_comments values (3652, 111701, 2, 3, 1, 3, 1, '時は来た…\\nさあ眷属よ！\\nわらわと共に、\\n聖夜の宴を楽しもうぞ', 0);
insert into room_unit_comments values (3654, 111701, 3, 2, 1, 0, 1, '良い椅子ではないか\\nここから聖夜の宴を\\n眺めるのもよいかもな', 0);
insert into room_unit_comments values (3655, 111701, 3, 3, 1, 0, 1, 'か、かわい…こほん\\nなかなか良い\\nデザインをしておるな', 0);
insert into room_unit_comments values (3656, 111701, 3, 4, 1, 0, 1, 'ふむ、良い香りじゃ\\n聖夜の宴でも\\nこれを使うとしよう', 0);
insert into room_unit_comments values (3657, 111701, 3, 5, 1, 0, 1, 'これが癒し…はっ！\\nあやうく浄化される\\nところであった…', 0);
insert into room_unit_comments values (3659, 111701, 3, 7, 1, 0, 1, 'ニ、ニンニクは\\n入っておらぬよな？\\n…うむ、美味じゃ♪', 0);
insert into room_unit_comments values (3660, 111701, 3, 8, 1, 0, 1, '聖夜は恋人たちの夜…\\n…き、気になるわけ\\nではないが、\\n少し調べてみるか', 0);
insert into room_unit_comments values (3662, 111701, 3, 14, 1, 0, 1, 'ほう…これは面白い\\n魔法の使い方じゃな\\nまるで本物の\\n演劇のようじゃ', 0);
insert into room_unit_comments values (3663, 111701, 3, 15, 1, 0, 1, 'こ、この程度の\\nかわいさに誘惑される\\nわらわでは…\\nふわもこなのじゃ～♪', 0);
insert into room_unit_comments values (3664, 112001, 1, 1, 1, 0, 1, 'おせち料理も\\n魔物尽くしだったり\\nしないわよね！', 0);
insert into room_unit_comments values (3665, 112001, 1, 2, 1, 0, 1, '初詣で何をお祈り\\nしようかしら…\\n定番でいいわよね？', 0);
insert into room_unit_comments values (3666, 112001, 1, 3, 1, 0, 1, '初日の出って\\n特別な感じがして\\nいいわよね…', 0);
insert into room_unit_comments values (3667, 112001, 1, 4, 1, 0, 1, '寒い中並んで飲む\\n甘酒って不思議なほど\\nおいしいわよね', 0);
insert into room_unit_comments values (3668, 112001, 1, 5, 1, 0, 1, '羽根つきで勝負…\\nあいつにだったら\\n勝てるかしら？', 0);
insert into room_unit_comments values (3669, 112001, 1, 101, 4, 0, 1, '年賀状になんて書こう\\n…いろいろと\\n恥ずかしくなるのよね', 0);
insert into room_unit_comments values (3670, 112001, 1, 102, 8, 0, 1, '今年もあいつと\\n居られること…\\n結構うれしいわ', 0);
insert into room_unit_comments values (3671, 112001, 2, 1, 1, 0, 1, '何じっと\\n見てんのよ？\\nお年玉はあげないわよ', 0);
insert into room_unit_comments values (3672, 112001, 2, 2, 1, 0, 1, 'おせち料理一緒に\\n食べる？\\n結構おいしいわよ', 0);
insert into room_unit_comments values (3673, 112001, 2, 3, 1, 0, 1, '羽根つきで負けたら\\n顔に墨塗られるのよ\\n覚悟しなさい！', 0);
insert into room_unit_comments values (3674, 112001, 2, 4, 1, 0, 1, '門松飾るから\\nちょっと手伝って\\nくれる？', 0);
insert into room_unit_comments values (3675, 112001, 2, 101, 4, 0, 1, 'あんたと一緒に\\n初詣行くのも悪くない\\n…かも', 0);
insert into room_unit_comments values (3676, 112001, 2, 102, 8, 0, 1, '初詣で何をお祈り\\nしたか？\u3000うっさい！\\n内緒よ！内緒！', 0);
insert into room_unit_comments values (3677, 112001, 2, 1, 1, 1, 1, 'もう朝なの…\\n正月くらいゆっくり\\n寝ていたいわよね…', 0);
insert into room_unit_comments values (3678, 112001, 2, 2, 1, 2, 1, 'おせちに飽きたら\\n次は何を食べよう\\nかしら…', 0);
insert into room_unit_comments values (3679, 112001, 2, 3, 1, 3, 1, 'そろそろ寝ましょ\\nいい初夢が見られると\\nいいわね', 0);
insert into room_unit_comments values (3681, 112001, 3, 2, 1, 0, 1, 'この格好でいるのも\\nなかなか疲れるわね\\n休憩～', 0);
insert into room_unit_comments values (3682, 112001, 3, 3, 1, 0, 1, 'か、かわいい…う～ん\\n鏡餅も顔を描けば\\nかわいくなるかしら？', 0);
insert into room_unit_comments values (3683, 112001, 3, 4, 1, 0, 1, 'いい匂いね\\n落ち着いて\\n眠れそう…', 0);
insert into room_unit_comments values (3684, 112001, 3, 5, 1, 0, 1, 'ここでお餅焼いたら\\n一段とおいしく\\nなりそうね', 0);
insert into room_unit_comments values (3686, 112001, 3, 7, 1, 0, 1, '正月に食べるものは\\nなんでもおいしく\\n感じちゃうわね！', 0);
insert into room_unit_comments values (3687, 112001, 3, 8, 1, 0, 1, '魔物を使わない\\nおせちを\\n調べておかなきゃ…', 0);
insert into room_unit_comments values (3689, 112101, 1, 1, 1, 0, 1, '新年を気持ちよく\\n過ごせるように\\nお掃除がんばります！', 0);
insert into room_unit_comments values (3690, 112101, 1, 2, 1, 0, 1, '神殿に通っていたら\\nいつの間にか足腰が\\n鍛えられたような…', 0);
insert into room_unit_comments values (3691, 112101, 1, 3, 1, 0, 1, '神殿付近は屋台も\\nあるので、良い香りが\\n漂ってくるんですよ～', 0);
insert into room_unit_comments values (3692, 112101, 1, 4, 1, 0, 1, 'おせちを作れるように\\nなれば、子どもたちも\\n喜んでくれるかな…？', 0);
insert into room_unit_comments values (3693, 112101, 1, 5, 1, 0, 1, 'コホォォォォォ…！\\nふぅ、深呼吸すると\\n落ち着きますね♪', 0);
insert into room_unit_comments values (3694, 112101, 1, 101, 4, 0, 1, 'お仕事以外の時も\\nあなたと…い、いえ！\\nなんでもないです！', 0);
insert into room_unit_comments values (3695, 112101, 1, 102, 8, 0, 1, 'あなたと一緒だと\\nなんだかポカポカ\\nしてくるんです…', 0);
insert into room_unit_comments values (3696, 112101, 2, 1, 1, 0, 1, 'この格好をしていると\\nなんだか神殿にいる\\n気分になりますね', 0);
insert into room_unit_comments values (3697, 112101, 2, 2, 1, 0, 1, 'そういえば神殿で\\n甘酒をもらったんです\\nあなたも飲みますか？', 0);
insert into room_unit_comments values (3698, 112101, 2, 3, 1, 0, 1, 'あっ、髪飾りが\\nズレちゃってました！\\nいけないいけない…', 0);
insert into room_unit_comments values (3699, 112101, 2, 4, 1, 0, 1, 'ひゃわっ！？\\nく、くすぐったり\\nしないでください～', 0);
insert into room_unit_comments values (3700, 112101, 2, 101, 4, 0, 1, 'そ、そんなに\\n見つめられると\\nて、照れちゃいます…', 0);
insert into room_unit_comments values (3701, 112101, 2, 102, 8, 0, 1, '今度、私が考えた\\n運気上昇のおまじない\\nかけてあげますね♪', 0);
insert into room_unit_comments values (3702, 112101, 2, 1, 1, 1, 1, 'おはようございます\\n神殿のお手伝いに行く\\n準備もしなきゃですね', 0);
insert into room_unit_comments values (3703, 112101, 2, 2, 1, 2, 1, 'お昼になりましたし\\nご飯は私が作…\\nえっ、ダメですか！？', 0);
insert into room_unit_comments values (3704, 112101, 2, 3, 1, 3, 1, '明日も早いですし\\nそろそろ寝る支度を…\\nふわぁ…', 0);
insert into room_unit_comments values (3706, 112101, 3, 2, 1, 0, 1, 'お掃除も終わったので\\n少し休憩を…ふわぁ…\\n急に眠気が…', 0);
insert into room_unit_comments values (3707, 112101, 3, 3, 1, 0, 1, '新年を気持ちよく\\n過ごせるようこの子も\\nきれいにしましょう♪', 0);
insert into room_unit_comments values (3708, 112101, 3, 4, 1, 0, 1, '神殿のお香のような\\n香りだと落ち着いて\\n過ごせそうですよね', 0);
insert into room_unit_comments values (3709, 112101, 3, 5, 1, 0, 1, 'ぽかぽかですね～…\\n甘酒も飲んで体の\\n芯から温めましょう', 0);
insert into room_unit_comments values (3711, 112101, 3, 7, 1, 0, 1, '今年こそ\\n料理も上手に…\\nもぐもぐもぐもぐ…', 0);
insert into room_unit_comments values (3712, 112101, 3, 8, 1, 0, 1, '失敗続きだと\\n逆に運が良くなる…\\nほ、本当ですかぁ…？', 0);
insert into room_unit_comments values (3714, 103401, 1, 103, 12, 0, 1, 'キミにならもう\\nどんな私を見られても\\n大丈夫かな…♪', 0);
insert into room_unit_comments values (3715, 103401, 2, 103, 12, 0, 1, 'なになにどしたのぉ？\\nお姉さんが撫でたげる\\nこっちにきなさぁい♪', 0);
insert into room_unit_comments values (3716, 111901, 1, 1, 1, 0, 1, 'わたくしの舞を\\n主さまは喜んで\\nくださるでしょうか…', 0);
insert into room_unit_comments values (3717, 111901, 1, 2, 1, 0, 1, '年を越したあとに\\n食べるおそばも\\nおいしいです', 0);
insert into room_unit_comments values (3718, 111901, 1, 3, 1, 0, 1, '甘酒を飲むと\\n心まで温まる\\n気がいたします', 0);
insert into room_unit_comments values (3719, 111901, 1, 4, 1, 0, 1, '主さまのために\\n真心を込めたおせちを\\nご用意しなくては', 0);
insert into room_unit_comments values (3720, 111901, 1, 5, 1, 0, 1, 'おみくじを引くのは\\nドキドキしつつも\\n楽しいものです', 0);
insert into room_unit_comments values (3721, 111901, 1, 101, 4, 0, 1, '主さまの温もりは\\n心まで温めてくれる\\nようです', 0);
insert into room_unit_comments values (3722, 111901, 1, 102, 8, 0, 1, 'うまくできなくとも\\n心を込めて精いっぱい\\n舞いましょう', 0);
insert into room_unit_comments values (3723, 111901, 2, 1, 1, 0, 1, '主さま、この晴れ着は\\n似合っている\\nでしょうか？', 0);
insert into room_unit_comments values (3724, 111901, 2, 2, 1, 0, 1, 'お餅はゆっくりと\\n召し上がって\\nくださいまし', 0);
insert into room_unit_comments values (3725, 111901, 2, 3, 1, 0, 1, '主さまのお顔の\\n福笑いなら、完璧に\\nできる気がいたします', 0);
insert into room_unit_comments values (3726, 111901, 2, 4, 1, 0, 1, '主さまはどのような\\n初夢をご覧になった\\nのでしょう？', 0);
insert into room_unit_comments values (3727, 111901, 2, 101, 4, 0, 1, '甘酒の飲み過ぎは\\nいけませんよ？\\nめっ、でございます', 0);
insert into room_unit_comments values (3728, 111901, 2, 102, 8, 0, 1, '二人羽織とは\\nあんなにも暖かい\\nものなのですね…', 0);
insert into room_unit_comments values (3729, 111901, 2, 1, 1, 1, 1, 'おはようございます\\n寒い季節の朝日は\\nとても美しいですね', 0);
insert into room_unit_comments values (3730, 111901, 2, 2, 1, 2, 1, 'おいしくとも\\n食べ過ぎは正月太りの\\nもとでございます', 0);
insert into room_unit_comments values (3731, 111901, 2, 3, 1, 3, 1, 'いい夢が見られるよう\\n暖かくして\\n眠るといたしましょう', 0);
insert into room_unit_comments values (3733, 111901, 3, 2, 1, 0, 1, 'ふかふか…\\nこのまま\\n寝てしまいそうです', 0);
insert into room_unit_comments values (3734, 111901, 3, 3, 1, 0, 1, 'あなたと一緒に\\nお正月遊びを\\n楽しんでみたいです', 0);
insert into room_unit_comments values (3735, 111901, 3, 4, 1, 0, 1, '神殿の独特な香りを\\nおうちに持ち込むのは\\nどうでしょうか', 0);
insert into room_unit_comments values (3736, 111901, 3, 5, 1, 0, 1, '風邪をひきませんよう\\n暖かくいたしましょう', 0);
insert into room_unit_comments values (3738, 111901, 3, 7, 1, 0, 1, '食べ過ぎは\\n正月太りの\\nもとだというのに…', 0);
insert into room_unit_comments values (3739, 111901, 3, 8, 1, 0, 1, '主さまのために\\n参拝の作法を\\n予習しておきましょう', 0);
insert into room_unit_comments values (3741, 112201, 1, 1, 1, 0, 1, '…この杖、変身前には\\n無いパーツがあるけど\\nこれはどこから…うん\\n考えないようにしよう', 0);
insert into room_unit_comments values (3742, 112201, 1, 2, 1, 0, 1, 'フ、フリフリの\\nかわいい衣装…はっ！\\n素に戻ってはダメだ！', 0);
insert into room_unit_comments values (3743, 112201, 1, 3, 1, 0, 1, '魔法探偵\\nミスティ★カスミ！\\n魔法の力で捜査開始！\\n…練習終わりっと', 0);
insert into room_unit_comments values (3744, 112201, 1, 4, 1, 0, 1, '怪しい視線を感じる…\\nまさか、近くに\\n闇の力を持つ人が！？', 0);
insert into room_unit_comments values (3745, 112201, 1, 5, 1, 0, 1, '時間もあるし、\\n魔法少女の修行を…\\nじゃ、じゃなくて！\\n探偵の仕事をしよう！', 0);
insert into room_unit_comments values (3746, 112201, 1, 101, 4, 0, 1, '助手くんとずっと\\n一緒に居られるし、\\n魔法少女も\\n案外悪くないかも♪', 0);
insert into room_unit_comments values (3747, 112201, 1, 102, 8, 0, 1, '魔法少女の訓練のため\\n助手くんの所に行こう\\nかな…あ、あくまで\\n訓練のためにね！', 0);
insert into room_unit_comments values (3748, 112201, 2, 1, 1, 0, 1, '…髪型が急に\\n変わって驚いた？\\nき、気になるなら…\\n少し触ってみるかい？', 0);
insert into room_unit_comments values (3749, 112201, 2, 2, 1, 0, 1, '助手くんは魔法少女に\\nなりたいのかい？\\nその場合は魔法騎士…\\nいや、魔法助手とか？', 0);
insert into room_unit_comments values (3750, 112201, 2, 3, 1, 0, 1, '頭に浮かぶ呪文…\\n強制変身…助手くん\\n魔法少女とは\\n呪いか何かなのかな？', 0);
insert into room_unit_comments values (3751, 112201, 2, 4, 1, 0, 1, 'あ、あまり触らないで\\nくれ…魔法少女になる\\nと感覚が鋭くなって、\\n耳も敏感に…ひゃう！', 0);
insert into room_unit_comments values (3752, 112201, 2, 101, 4, 0, 1, 'や、やっぱりこの\\n格好は変かな…え、\\nかわいい？\u3000じゃあ…\\nいや、でも、う～ん', 0);
insert into room_unit_comments values (3753, 112201, 2, 102, 8, 0, 1, '…この変身は助手くん\\nのせいでもあるんだよ\\nだから…せ、責任を\\n取ってもらうからね！', 0);
insert into room_unit_comments values (3754, 112201, 2, 1, 1, 1, 1, 'おはよう助手くん\\nさあ、そろそろ\\n街のパトロールに\\n行こうじゃないか！', 0);
insert into room_unit_comments values (3755, 112201, 2, 2, 1, 2, 1, 'もうお昼…助手くん、\\nそろそろ本業に戻ろう\\n…その顔は何かな？\\n私の本業は探偵だぞ！', 0);
insert into room_unit_comments values (3756, 112201, 2, 3, 1, 3, 1, '夜だけど、私は\\nもう少し仕事をするよ\\n魔法少女の強い体は\\nこんなときに便利だね', 0);
insert into room_unit_comments values (3758, 112201, 3, 2, 1, 0, 1, '気持ちいい…\\nこの癒しを、魔法と\\n論理の二つの観点から\\n解明したいね…', 0);
insert into room_unit_comments values (3759, 112201, 3, 3, 1, 0, 1, 'ダ、ダメ！！\\nここで感情のままに\\n飛びついたら、私の\\nイメージがぁ～！', 0);
insert into room_unit_comments values (3760, 112201, 3, 4, 1, 0, 1, '心が安らぐ香りだね…\\n…今なら、魔法少女も\\nすんなりと受け入れ…\\nてはダメだっ！', 0);
insert into room_unit_comments values (3761, 112201, 3, 5, 1, 0, 1, 'あったかい…\\n魔法少女だろうと\\n休息は必要だし、少し\\n休んでいこうかな', 0);
insert into room_unit_comments values (3763, 112201, 3, 7, 1, 0, 1, '魔法少女も探偵も、\\nやっぱり体が資本！\\n食べられるときに\\n食べておかないとね♪', 0);
insert into room_unit_comments values (3764, 112201, 3, 8, 1, 0, 1, '…魔法少女\\nセリイちゃんの本は\\nどこにあるのかな？', 0);
insert into room_unit_comments values (3766, 112301, 1, 1, 1, 0, 1, '魔法少女かぁ…\\nせっかくだし思う存分\\n体を動かしてみたいな', 0);
insert into room_unit_comments values (3767, 112301, 1, 2, 1, 0, 1, 'ニャットちゃん…\\nこの格好を見て\\n私って気づくかな？', 0);
insert into room_unit_comments values (3768, 112301, 1, 3, 1, 0, 1, 'ふふ…\\n今日はなんだか\\n調子がいいかも', 0);
insert into room_unit_comments values (3769, 112301, 1, 4, 1, 0, 1, '魔法は便利だけど\\nあまり頼りすぎちゃ\\nダメだよね', 0);
insert into room_unit_comments values (3770, 112301, 1, 5, 1, 0, 1, 'さっき街で小さな子に\\n声かけられちゃった\\n照れるけどうれしいな', 0);
insert into room_unit_comments values (3771, 112301, 1, 101, 4, 0, 1, 'あの人がいると\\nなんだかホッとする\\n不思議…', 0);
insert into room_unit_comments values (3772, 112301, 1, 102, 8, 0, 1, '魔法少女になっても\\nあの人への気持ちは\\nずっと同じ…', 0);
insert into room_unit_comments values (3773, 112301, 2, 1, 1, 0, 1, '今日の私…ですか？\\nはいとっても元気です\\n…あなたのおかげかも', 0);
insert into room_unit_comments values (3774, 112301, 2, 2, 1, 0, 1, 'よかったら魔法の\\n練習に付き合って\\nくれませんか？', 0);
insert into room_unit_comments values (3775, 112301, 2, 3, 1, 0, 1, 'あの…\\nこの格好どうですか？\\n似合ってると…いいな', 0);
insert into room_unit_comments values (3776, 112301, 2, 4, 1, 0, 1, '…な、なんですか？\\nあまり見られると\\n恥ずかしいです…', 0);
insert into room_unit_comments values (3777, 112301, 2, 101, 4, 0, 1, '私、あなたのそばに\\nいられたら、それで…', 0);
insert into room_unit_comments values (3778, 112301, 2, 102, 8, 0, 1, '想い人と結ばれる\\n魔法は…ひゃっ！？\\n今の聞いてましたか？', 0);
insert into room_unit_comments values (3779, 112301, 2, 1, 1, 1, 1, 'おはようございます\\n今日も街の平和の\\nために頑張らなきゃ', 0);
insert into room_unit_comments values (3780, 112301, 2, 2, 1, 2, 1, 'お腹すきましたね。\\nあの…一緒にランチは\\nいかがですか？', 0);
insert into room_unit_comments values (3781, 112301, 2, 3, 1, 3, 1, 'あ、もうこんな時間…\\nふふ、まだこんなに\\n体力が余ってるのに', 0);
insert into room_unit_comments values (3783, 112301, 3, 2, 1, 0, 1, '気持ちいい…\\nこの気持ち良さは\\nどんな魔法も勝てない', 0);
insert into room_unit_comments values (3784, 112301, 3, 3, 1, 0, 1, '何これ、かわいい…\\nお姉ちゃんにも\\n見せてあげたいな', 0);
insert into room_unit_comments values (3785, 112301, 3, 4, 1, 0, 1, 'ん～、いい香り\\n…これ、魔法で\\n出せたりしないかな？', 0);
insert into room_unit_comments values (3786, 112301, 3, 5, 1, 0, 1, 'あったか～い\\nえへへ…なんだか\\nお姉ちゃんみたい', 0);
insert into room_unit_comments values (3788, 112301, 3, 7, 1, 0, 1, 'おいしいなぁ、これ\\n魔法少女になってから\\n食欲旺盛かも…', 0);
insert into room_unit_comments values (3789, 112301, 3, 8, 1, 0, 1, 'ふふ…\\n魔法少女になっても\\n読書はやめられないな', 0);
insert into room_unit_comments values (3791, 101001, 1, 103, 12, 0, 1, 'みらくるまほりん\\nくるりんぱ～♪\\n王子はんのために\\n花嫁修業や～♪', 0);
insert into room_unit_comments values (3792, 101001, 2, 103, 12, 0, 1, 'あ、あのな王子はん\\nできたらその…\\nお姫さまだっこを\\nお願いしてもええ…？', 0);
insert into room_unit_comments values (3793, 180401, 1, 1, 1, 0, 1, 'やっぱりわたしたちの\\nギルドハウスの\\n居心地は最高ですね☆', 0);
insert into room_unit_comments values (3794, 180401, 1, 2, 1, 0, 1, '王宮じゃできないこと\\nやっちゃいましょう♪\\n例えば、えっと～…', 0);
insert into room_unit_comments values (3795, 180401, 1, 3, 1, 0, 1, 'そうだ、隠しておいた\\nおやつがありました！\\nまだ食べられますね☆', 0);
insert into room_unit_comments values (3796, 180401, 1, 4, 1, 0, 1, 'ごはんはみんなで\\n楽しく食べましょう！\\nそれが一番の\\n調味料です♪', 0);
insert into room_unit_comments values (3797, 180401, 1, 5, 1, 0, 1, 'やっぱりここが、\\nわたしの帰る場所です\\n…ただいま☆', 0);
insert into room_unit_comments values (3798, 180401, 1, 101, 4, 0, 1, 'なんだか物足りません\\nきっと、あの人が隣に\\nいないからですね…', 0);
insert into room_unit_comments values (3799, 180401, 1, 102, 8, 0, 1, 'どこを見ても、大切な\\n思い出がたくさん\\n詰まっていますね♪', 0);
insert into room_unit_comments values (3800, 180401, 2, 1, 1, 0, 1, '無礼者～、なんて\\n冗談です♪\u3000どんどん\\n触っちゃってください', 0);
insert into room_unit_comments values (3801, 180401, 2, 2, 1, 0, 1, 'ぷにぷにでしょう～？\\nい～っぱい食べるのが\\nぷにぷにの秘訣です！', 0);
insert into room_unit_comments values (3802, 180401, 2, 3, 1, 0, 1, '握手したいんですか？\\nはい、にぎにぎ～！\\nもう離しませんよ♪', 0);
insert into room_unit_comments values (3803, 180401, 2, 4, 1, 0, 1, 'どうかしましたか？\\n退屈してるんでしたら\\nお散歩に行きましょう', 0);
insert into room_unit_comments values (3804, 180401, 2, 101, 4, 0, 1, 'ごはん王子♪\\nわたしは王女ですから\\nこれでピッタリですね', 0);
insert into room_unit_comments values (3805, 180401, 2, 102, 8, 0, 1, '大好きです～\\n愛してます～\\n…ほんと、ですよ♪', 0);
insert into room_unit_comments values (3806, 180401, 2, 1, 1, 1, 1, '朝ごはんは大事です！\\n山盛りごはんを食べて\\n元気いっぱいですよ☆', 0);
insert into room_unit_comments values (3807, 180401, 2, 2, 1, 2, 1, 'お腹ぺこぺこになる\\n時間ですね～！\\nごはん特盛、一つ！', 0);
insert into room_unit_comments values (3808, 180401, 2, 3, 1, 3, 1, 'お腹いっぱい、今日は\\nよく眠れそうですね♪\\n明日もおいしい一日を', 0);
insert into room_unit_comments values (3810, 180401, 3, 2, 1, 0, 1, '休憩休憩～♪\\nお腹を休めて、次の\\nごはんに挑みます…☆', 0);
insert into room_unit_comments values (3811, 180401, 3, 3, 1, 0, 1, 'かわいらしい\\nぬいぐるみですね～\\nキャルちゃんみたい☆', 0);
insert into room_unit_comments values (3812, 180401, 3, 4, 1, 0, 1, 'すんすん…この匂い\\n食欲増進の効果が\\nありそうですね…？', 0);
insert into room_unit_comments values (3813, 180401, 3, 5, 1, 0, 1, '体温が上がってくると\\n眠くなっちゃいます…\\nほわぁ～', 0);
insert into room_unit_comments values (3815, 180401, 3, 7, 1, 0, 1, 'もぐもぐもぐもぐもぐ\\nむぐむぐむぐむぐむぐ\\nはぐはぐはぐはぐはぐ', 0);
insert into room_unit_comments values (3816, 180401, 3, 8, 1, 0, 1, '教養を身に着けるには\\n読書が一番です！\\nえっと次のレシピは～', 0);
insert into room_unit_comments values (3818, 112401, 1, 1, 1, 0, 1, 'アイドルらしくなる\\nコツって、何か\\nあるんでしょうか？', 0);
insert into room_unit_comments values (3819, 112401, 1, 2, 1, 0, 1, '色んな人と話すのが\\n好きなんです。つい\\n長くなっちゃって…', 0);
insert into room_unit_comments values (3820, 112401, 1, 3, 1, 0, 1, 'アイドルを目指すって\\n決めてから、毎日が\\nワクワクなんです♪', 0);
insert into room_unit_comments values (3821, 112401, 1, 4, 1, 0, 1, 'ちゃんとストレッチ\\nしておかなくっちゃ\\nよいしょ、よいしょ…', 0);
insert into room_unit_comments values (3822, 112401, 1, 5, 1, 0, 1, 'リンちゃんミオちゃん\\n二人に負けないように\\n私、頑張ります！', 0);
insert into room_unit_comments values (3823, 112401, 1, 101, 4, 0, 1, '私の笑顔は素敵だって\\n誰かに褒められた…\\nそんな気がするんです', 0);
insert into room_unit_comments values (3824, 112401, 1, 102, 8, 0, 1, '私たちを支えてくれる\\n誰かが、ずっと一緒に\\nいてくれたような…', 0);
insert into room_unit_comments values (3825, 112401, 2, 1, 1, 0, 1, 'どうかしましたか？\\n何か困ってるのなら\\nお手伝いしますよ！', 0);
insert into room_unit_comments values (3826, 112401, 2, 2, 1, 0, 1, 'みなさん個性的で\\n普通じゃない人ばかり\\nいるような気が…', 0);
insert into room_unit_comments values (3827, 112401, 2, 3, 1, 0, 1, '今日はポカポカした\\nいい天気ですね～\\nお散歩日和です！', 0);
insert into room_unit_comments values (3828, 112401, 2, 4, 1, 0, 1, '今、ミルクティーを\\n淹れてたんです♪\\nあなたも飲みますか？', 0);
insert into room_unit_comments values (3829, 112401, 2, 101, 4, 0, 1, '私の得意なこと？\\nうーんなんでしょう…\\nあっ、肩たたきです！', 0);
insert into room_unit_comments values (3830, 112401, 2, 102, 8, 0, 1, '生・ハム・メローン！\\nあ、ライブの掛け声を\\n練習してたんですよ♪', 0);
insert into room_unit_comments values (3831, 112401, 2, 1, 1, 1, 1, 'おはようございます！\\n今日も一日\\n頑張りましょうね！', 0);
insert into room_unit_comments values (3832, 112401, 2, 2, 1, 2, 1, 'しっかりお昼を食べて\\n午後からも張り切って\\nいきましょうね♪', 0);
insert into room_unit_comments values (3833, 112401, 2, 3, 1, 3, 1, 'ぐっすり眠れるよう\\n早めに用事を済ませて\\nお休みしましょうね', 0);
insert into room_unit_comments values (3835, 112401, 3, 2, 1, 0, 1, 'ちょっと休んだら\\nレッスンの続きも\\n頑張ります！', 0);
insert into room_unit_comments values (3836, 112401, 3, 3, 1, 0, 1, 'えへへ～\\nふわふわもこもこで\\nかわいいです～♪', 0);
insert into room_unit_comments values (3837, 112401, 3, 4, 1, 0, 1, 'リラックスできる\\nいい香りですね～♪', 0);
insert into room_unit_comments values (3838, 112401, 3, 5, 1, 0, 1, 'わぁ、ポカポカです♪\\n温かい飲み物も\\nほしくなりますね', 0);
insert into room_unit_comments values (3840, 112401, 3, 7, 1, 0, 1, 'レッスンしたら\\nお腹が空いちゃって…\\nぱくぱくもぐもぐ…', 0);
insert into room_unit_comments values (3841, 112401, 3, 8, 1, 0, 1, 'レッスンに役立つ\\n運動の情報とか\\n載ってるでしょうか…', 0);
insert into room_unit_comments values (3843, 112601, 1, 1, 1, 0, 1, 'きらきらーん☆\\nよし、次のステージは\\nこれで行けるかも！', 0);
insert into room_unit_comments values (3844, 112601, 1, 2, 1, 0, 1, '私の元気でみんなも\\n元気になってくれたら\\nうれしいな～', 0);
insert into room_unit_comments values (3845, 112601, 1, 3, 1, 0, 1, 'ちょっとレッスンで\\n疲れちゃったかも…\\nでも頑張るぞっ！', 0);
insert into room_unit_comments values (3846, 112601, 1, 4, 1, 0, 1, '晩ごはん何にしよう？\\nそーだ、しぶりんにも\\n聞いてみよっと！', 0);
insert into room_unit_comments values (3847, 112601, 1, 5, 1, 0, 1, '元気だから笑顔になる\\nじゃなくて\\n笑顔だから\\n元気になるんだよね～', 0);
insert into room_unit_comments values (3848, 112601, 1, 101, 4, 0, 1, '声援を聞いてる時ね\\nすごく懐かしいって\\n思うことがあるんだ', 0);
insert into room_unit_comments values (3849, 112601, 1, 102, 8, 0, 1, '私を応援してくれる\\n一番大事な人が\\n隣にいた気がする…', 0);
insert into room_unit_comments values (3850, 112601, 2, 1, 1, 0, 1, 'なになにー？\\nミオちゃんに\\n何か用かな～？', 0);
insert into room_unit_comments values (3851, 112601, 2, 2, 1, 0, 1, 'おっ、やっほー！\\n元気そうだね～、キミ\\n私？\\nもちろん元気～！', 0);
insert into room_unit_comments values (3852, 112601, 2, 3, 1, 0, 1, 'ねぇねぇ、ちょっと\\n遊びに行かない？\\nたまには息抜きで！', 0);
insert into room_unit_comments values (3853, 112601, 2, 4, 1, 0, 1, 'ね、この魔物料理さ\\nプリンって言い張れば\\n食べてもらえそうかな', 0);
insert into room_unit_comments values (3854, 112601, 2, 101, 4, 0, 1, 'えへへ\\nいつもありがとねっ！\\nパワーもらってるよ～', 0);
insert into room_unit_comments values (3855, 112601, 2, 102, 8, 0, 1, 'どうしたどうした～\\nミオちゃんの魅力に\\nメロメロなのかい？', 0);
insert into room_unit_comments values (3856, 112601, 2, 1, 1, 1, 1, 'おっはよ～！\\n一日の始まりだし\\nテンション上げてこ！', 0);
insert into room_unit_comments values (3857, 112601, 2, 2, 1, 2, 1, 'お腹空いた～…\\nねぇねぇ、一緒に\\nお昼食べようよ～', 0);
insert into room_unit_comments values (3858, 112601, 2, 3, 1, 3, 1, 'ふわぁ～…\\n眠くなってきちゃった\\nそろそろ休もっかなぁ', 0);
insert into room_unit_comments values (3860, 112601, 3, 2, 1, 0, 1, 'わぁ、ふっかふか～！\\nレッスンの疲れも\\n吹っ飛んじゃうね☆', 0);
insert into room_unit_comments values (3861, 112601, 3, 3, 1, 0, 1, '何これ…かわいーっ！\\n早くしまむーに\\n教えてあげなきゃ！', 0);
insert into room_unit_comments values (3862, 112601, 3, 4, 1, 0, 1, 'すぅ～…\\nうんっ、これ私の\\n好きな香りだな～♪', 0);
insert into room_unit_comments values (3863, 112601, 3, 5, 1, 0, 1, 'ポッカポカだね～♪\\n…あ～ん、ここから\\n動きたくないーっ！', 0);
insert into room_unit_comments values (3865, 112601, 3, 7, 1, 0, 1, 'わっ、おーいしー！\\nこれはテンション\\n上がっちゃうね♪', 0);
insert into room_unit_comments values (3866, 112601, 3, 8, 1, 0, 1, 'ふむふむ…\\nふむふむふむ…！\\n勉強になった、ブイ☆', 0);
insert into room_unit_comments values (3868, 100101, 1, 103, 12, 0, 1, 'なんでドキドキが\\n止まらないの…？\\n騎士くんのせいだー！', 0);
insert into room_unit_comments values (3869, 100101, 2, 103, 12, 0, 1, 'ドキドキしてるの\\nあたしだけ、かな…\\n騎士くんはどう…？', 0);
insert into room_unit_comments values (3870, 100201, 1, 103, 12, 0, 1, '騎士クンの前で\\n好きって言えるように\\n練習しないと…', 0);
insert into room_unit_comments values (3871, 100201, 2, 103, 12, 0, 1, '騎士クン…大好き\\n…き、騎士クン！？\\nなんでここに！？', 0);
insert into room_unit_comments values (3872, 100301, 1, 103, 12, 0, 1, '困ったな…\\n彼が居ないだけで、\\nここまで\\n寂しいと思うなんて…', 0);
insert into room_unit_comments values (3873, 100301, 2, 103, 12, 0, 1, 'えっと…\\n今日は訓練じゃなくて\\nその…二人でゆっくり\\n過ごしたいな…', 0);
insert into room_unit_comments values (3874, 112501, 1, 1, 1, 0, 1, 'アイドルの心構え…\\nどういう風に考えると\\nしっくりくるのかな', 0);
insert into room_unit_comments values (3875, 112501, 1, 2, 1, 0, 1, '何か始めるのって\\nドキドキするよね\\nだから最近楽しいんだ', 0);
insert into room_unit_comments values (3876, 112501, 1, 3, 1, 0, 1, '冒険者の時って毎日\\nバタバタしてたけど…\\n目標ができると違うね', 0);
insert into room_unit_comments values (3877, 112501, 1, 4, 1, 0, 1, '少しお腹が空いた…\\nチョコレート一粒だけ\\n食べようかな', 0);
insert into room_unit_comments values (3878, 112501, 1, 5, 1, 0, 1, 'ウヅキもミオも\\n頑張ってるし\\n私も負けられないね', 0);
insert into room_unit_comments values (3879, 112501, 1, 101, 4, 0, 1, 'レッスンしてる時さ\\n何か、誰かが足りない\\nそう思うことがあるの', 0);
insert into room_unit_comments values (3880, 112501, 1, 102, 8, 0, 1, '大事なのは笑顔…\\n誰か、大切な人から\\n言われた気がするんだ', 0);
insert into room_unit_comments values (3881, 112501, 2, 1, 1, 0, 1, 'どうしたの、何か用？\\n手伝えることがあれば\\nすぐに言ってね', 0);
insert into room_unit_comments values (3882, 112501, 2, 2, 1, 0, 1, '姿勢がいい？\\n普段から鍛えてるし\\n自然とそうなるのかも', 0);
insert into room_unit_comments values (3883, 112501, 2, 3, 1, 0, 1, 'さっき散歩してたら\\n犬を見かけたんだ\\n人懐っこい子だったよ', 0);
insert into room_unit_comments values (3884, 112501, 2, 4, 1, 0, 1, '今から冒険？\\nなら私も一緒に行くよ\\n前衛は任せておいて', 0);
insert into room_unit_comments values (3885, 112501, 2, 101, 4, 0, 1, '今からレッスンに\\n行くつもりだったんだ\\n少し手伝ってくれる？', 0);
insert into room_unit_comments values (3886, 112501, 2, 102, 8, 0, 1, '蒼の剣を受けよ！\\nえ、何してるのって？\\nただの発声練習だけど', 0);
insert into room_unit_comments values (3887, 112501, 2, 1, 1, 1, 1, 'おはよう、早いね\\n今日は依頼もないし\\nゆっくりしようかな', 0);
insert into room_unit_comments values (3888, 112501, 2, 2, 1, 2, 1, 'そろそろお昼だね\\nうーん、今日は\\n何を食べよう…', 0);
insert into room_unit_comments values (3889, 112501, 2, 3, 1, 3, 1, 'もうこんな時間…\\n明日も早いし\\nそろそろ寝なくちゃ', 0);
insert into room_unit_comments values (3891, 112501, 3, 2, 1, 0, 1, 'レッスンで疲れたし\\nちょっとだけ\\n休んでおこうかな', 0);
insert into room_unit_comments values (3892, 112501, 3, 3, 1, 0, 1, 'ふふっ、かわいい\\nふわふわしたものって\\n撫でたくなるんだよね', 0);
insert into room_unit_comments values (3893, 112501, 3, 4, 1, 0, 1, 'うん、いい香り…\\nこういうものがあると\\n落ち着くからいいよね', 0);
insert into room_unit_comments values (3894, 112501, 3, 5, 1, 0, 1, '温かい場所って\\n居心地がいいから\\nのんびりしちゃうよ', 0);
insert into room_unit_comments values (3896, 112501, 3, 7, 1, 0, 1, 'レッスン頑張ったら\\nすぐお腹が空くし\\n食べておかないと…！', 0);
insert into room_unit_comments values (3897, 112501, 3, 8, 1, 0, 1, 'アイドルのことを\\nもっと勉強して\\n成長しなくちゃ', 0);
insert into room_unit_comments values (3899, 111001, 1, 1, 1, 0, 1, 'ああ、知りたい…\\nなんでもかんでも\\nとにかく知りたい…', 0);
insert into room_unit_comments values (3900, 111001, 1, 2, 1, 0, 1, 'ああ、眠い…\\nいつでもどこでも\\nとにかく眠い…', 0);
insert into room_unit_comments values (3901, 111001, 1, 3, 1, 0, 1, '君、気を付けたまえ\\nぼーっと歩いていると\\nほわっ！\u3000転んだ…', 0);
insert into room_unit_comments values (3902, 111001, 1, 4, 1, 0, 1, 'ミツキ師にいただいた\\n新作サプリ…丁度よい\\n被験体はいないものか', 0);
insert into room_unit_comments values (3903, 111001, 1, 5, 1, 0, 1, 'サレンディア救護院に\\nユニちゃん８歳として\\n潜入済みだが何か？', 0);
insert into room_unit_comments values (3904, 111001, 1, 101, 4, 0, 1, '君がユニちゃんズの\\n同志であること、\\nぼくは誇りに思うぞ', 0);
insert into room_unit_comments values (3905, 111001, 1, 102, 8, 0, 1, 'ぼくは青春がしたい\\nおい、君\\nぼくと青春しないか', 0);
insert into room_unit_comments values (3906, 111001, 2, 1, 1, 0, 1, 'ああ、そうだな。\\nぼくもそう思う。\\n……えっ、何が？', 0);
insert into room_unit_comments values (3907, 111001, 2, 2, 1, 0, 1, '待て、話しかけるな。\\n今の閃きをメモに…\\n…ああっ、忘れた！', 0);
insert into room_unit_comments values (3908, 111001, 2, 3, 1, 0, 1, '歩き方が綺麗？\\n何を今更なこと\\n言っとるんだ君は', 0);
insert into room_unit_comments values (3909, 111001, 2, 4, 1, 0, 1, 'ぼくの血液型？\\n大らかのОだ。\\n何か異論あるかね', 0);
insert into room_unit_comments values (3910, 111001, 2, 101, 4, 0, 1, '君の声は精神に\\n高揚をもたらすな…\\n波形を分析したいぞ', 0);
insert into room_unit_comments values (3911, 111001, 2, 102, 8, 0, 1, '妙だな…最近\\n君に話しかけられると\\n心拍に乱れを覚える', 0);
insert into room_unit_comments values (3912, 111001, 2, 1, 1, 1, 1, 'おっと、朝だな。\\nそろそろ寝るか、\\n朝更かしは体に悪い', 0);
insert into room_unit_comments values (3913, 111001, 2, 2, 1, 2, 1, 'ふむ、昼餉時か…\\n今日のランチは\\nサプリ定食にしよう', 0);
insert into room_unit_comments values (3914, 111001, 2, 3, 1, 3, 1, 'もう夜だな、\\nそろそろ起きるか。\\n最高の一日にするぞ！', 0);
insert into room_unit_comments values (3916, 111001, 3, 2, 1, 0, 1, 'ほわぁ～\\n副交感神経が…\\n優位に…ふふっひ', 0);
insert into room_unit_comments values (3917, 111001, 3, 3, 1, 0, 1, 'かわいすぎるな…\\nセクシーユニには\\nミスマッチか…', 0);
insert into room_unit_comments values (3918, 111001, 3, 4, 1, 0, 1, 'ほぁあアあァぁー…\\nいい香りー…\\nあアァあ…イイ…', 0);
insert into room_unit_comments values (3919, 111001, 3, 5, 1, 0, 1, '炎はいいぞ\\nそこには人類発展の\\nドラマがある', 0);
insert into room_unit_comments values (3921, 111001, 3, 7, 1, 0, 1, 'フオオー！\\n次から次へと固形食物\\n原理気になるー！', 0);
insert into room_unit_comments values (3922, 111001, 3, 8, 1, 0, 1, '良書は時間を忘れる\\n…ふむ、今度\\n布団を持ってこよう', 0);
insert into room_unit_comments values (3924, 101201, 1, 103, 12, 0, 1, 'きらーん☆\\nハツネちゃんに\\n不可能はないのだ☆', 0);
insert into room_unit_comments values (3925, 101201, 2, 103, 12, 0, 1, 'キミと一緒だと\\n寝ちゃうのが\\nもったいないよ～', 0);
insert into room_unit_comments values (3933, 192101, 2, 1, 1, 0, 1, 'ちぇるーん☆', 0);
insert into room_unit_comments values (3951, 110901, 1, 1, 1, 0, 1, 'ちぇる～ん☆\\n今日もチエルは\\nかわいいですよね～？', 0);
insert into room_unit_comments values (3952, 110901, 1, 2, 1, 0, 1, 'どこかに楽しいもの\\n落ちてないかにゃー', 0);
insert into room_unit_comments values (3953, 110901, 1, 3, 1, 0, 1, 'チエルのオキニは\\n甘々カフェラテ！\\nシクヨロでぇ～す☆', 0);
insert into room_unit_comments values (3954, 110901, 1, 4, 1, 0, 1, '先輩、ひまですよね？\\nチエル遊んであげても\\nいいですけど？', 0);
insert into room_unit_comments values (3955, 110901, 1, 5, 1, 0, 1, 'はぁー…しゅき…\\nカルミナ尊い…\\n一生すこれる…', 0);
insert into room_unit_comments values (3956, 110901, 1, 101, 4, 0, 1, '先輩、ひまー\\nちょっとは構えよーう\\nデュクシ！デュクシ！', 0);
insert into room_unit_comments values (3957, 110901, 1, 102, 8, 0, 1, '先輩なんか\\nおごって～！\\nてか…おごらなくても\\nいいから遊んでよ…', 0);
insert into room_unit_comments values (3958, 110901, 2, 1, 1, 0, 1, 'え、なんですか？\\n告白だったら\\n間に合ってますけど', 0);
insert into room_unit_comments values (3959, 110901, 2, 2, 1, 0, 1, 'ちょっと静かに！\\n今ヤバかわポーズの\\nイメトレ中なんです！', 0);
insert into room_unit_comments values (3960, 110901, 2, 3, 1, 0, 1, '足取りが軽やか？\\nあー…ダンスとか\\n習ってるからですかね', 0);
insert into room_unit_comments values (3961, 110901, 2, 4, 1, 0, 1, 'チエルの血液型？\\n大型新人のОです\\n何か問題でも？', 0);
insert into room_unit_comments values (3962, 110901, 2, 101, 4, 0, 1, '先輩って何気に\\nいい声してますよね\\n言うことは変だけど', 0);
insert into room_unit_comments values (3963, 110901, 2, 102, 8, 0, 1, 'え、なんですか？\\nたまにだったら\\n告白してもいいですよ', 0);
insert into room_unit_comments values (3964, 110901, 2, 1, 1, 1, 1, 'おはちぇる～ん☆\\nハイ、ご一緒に～？', 0);
insert into room_unit_comments values (3965, 110901, 2, 2, 1, 2, 1, '今日のランチは\\nどこで\\n映えよっかにゃー', 0);
insert into room_unit_comments values (3966, 110901, 2, 3, 1, 3, 1, 'こんばんちぇるるん☆\\nハイ、ご一緒に～？', 0);
insert into room_unit_comments values (3968, 110901, 3, 2, 1, 0, 1, 'ふかふかチエルン\\n略して、ふかルン♪', 0);
insert into room_unit_comments values (3969, 110901, 3, 3, 1, 0, 1, 'かわいいこの子と\\nかわいいチエル！\\n映ぁ～え～る～！', 0);
insert into room_unit_comments values (3970, 110901, 3, 4, 1, 0, 1, 'かわいい香り～！\\n持って帰ろっと！\\nすぅーっ…', 0);
insert into room_unit_comments values (3971, 110901, 3, 5, 1, 0, 1, 'マシュマロは\\n焼かない方のが\\nかわいくないです？', 0);
insert into room_unit_comments values (3973, 110901, 3, 7, 1, 0, 1, 'チエル食べても\\n太らない体質\\nなんでぇ～！', 0);
insert into room_unit_comments values (3974, 110901, 3, 8, 1, 0, 1, '読書は好きですよ\\nシンプルに楽しいし\\nギャップ萌えでしょ？', 0);
insert into room_unit_comments values (3976, 112701, 1, 1, 1, 0, 1, 'みんなのあたしを\\n見る目が違うね\\nま、気にしないけどね', 0);
insert into room_unit_comments values (3977, 112701, 1, 2, 1, 0, 1, '今日も疲れた～\\nやる気ゼロだし\\nもう寝ちゃおうかな', 0);
insert into room_unit_comments values (3978, 112701, 1, 3, 1, 0, 1, 'あたしの代わりに誰か\\n働いてくれないかね', 0);
insert into room_unit_comments values (3979, 112701, 1, 4, 1, 0, 1, '労働の後に食べる\\nあんパン最高～', 0);
insert into room_unit_comments values (3980, 112701, 1, 5, 1, 0, 1, '仕事の合間に\\nちょっと一息いれよ\\nあ～ドングリ美味し～', 0);
insert into room_unit_comments values (3981, 112701, 1, 101, 4, 0, 1, '報酬も入ったことだし\\nあいつに何か\\n買ってあげようかな', 0);
insert into room_unit_comments values (3982, 112701, 1, 102, 8, 0, 1, '次の休みはあいつと\\n一日中だらだら\\nしたいな～', 0);
insert into room_unit_comments values (3983, 112701, 2, 1, 1, 0, 1, 'あたしは褒められて\\n伸びるタイプなんだ\\nだから褒めて褒めて', 0);
insert into room_unit_comments values (3984, 112701, 2, 2, 1, 0, 1, 'お、差し入れ？\\n気が利くねぇ\\nあんがと', 0);
insert into room_unit_comments values (3985, 112701, 2, 3, 1, 0, 1, '新しい依頼？\\n今日はもう無理～\\n閉店で～す', 0);
insert into room_unit_comments values (3986, 112701, 2, 4, 1, 0, 1, 'サ、サボってないよ！\\nちょっと休憩してた\\nだけだから！', 0);
insert into room_unit_comments values (3987, 112701, 2, 101, 4, 0, 1, 'ねえ、一緒に\\nサボろうよ？\\n働き過ぎはよくないよ', 0);
insert into room_unit_comments values (3988, 112701, 2, 102, 8, 0, 1, 'あんたが近くにいると\\n仕事の疲れも\\n和らぐんだよね～', 0);
insert into room_unit_comments values (3989, 112701, 2, 1, 1, 1, 1, 'はぁ…もう起きなきゃ\\nつらい労働の\\nはじまりだ～', 0);
insert into room_unit_comments values (3990, 112701, 2, 2, 1, 2, 1, 'うぅ、お昼に\\nあんパン食べ過ぎた…\\n苦しい…眠い…', 0);
insert into room_unit_comments values (3991, 112701, 2, 3, 1, 3, 1, '明日は仕事ないし\\nガッツリ夜ふかし\\nしちゃうよ～', 0);
insert into room_unit_comments values (3993, 112701, 3, 2, 1, 0, 1, '猫みたいに\\n丸くなっちゃうよ～\\nあたしリスだけどね', 0);
insert into room_unit_comments values (3994, 112701, 3, 3, 1, 0, 1, 'ふかふか～\\nあたしの尻尾と\\n互角とはやるね～', 0);
insert into room_unit_comments values (3995, 112701, 3, 4, 1, 0, 1, 'あんパンの香りの\\nアロマとか\\nあればいいのにな～', 0);
insert into room_unit_comments values (3996, 112701, 3, 5, 1, 0, 1, 'これは危険な\\nあたたかさだね～\\n労働意欲が\\nなくなるよ～', 0);
insert into room_unit_comments values (3998, 112701, 3, 7, 1, 0, 1, 'いっぱい働いたから\\nいっぱい食べても\\nカロリー０だよ', 0);
insert into room_unit_comments values (3999, 112701, 3, 8, 1, 0, 1, 'あたしだってたまには\\n本くらい読むって\\n全然似合わないけどね', 0);
insert into room_unit_comments values (4001, 104601, 1, 103, 12, 0, 1, 'あたしの作った\\nオリジナルたい焼き…\\nあいつ、\\n喜んでくれるかにゃ？', 0);
insert into room_unit_comments values (4002, 104601, 2, 103, 12, 0, 1, 'あ、お帰りにゃー♪\\nえへへ…キミに\\nお帰りって言えるのが\\nなんかうれしいにゃ♪', 0);
insert into room_unit_comments values (4003, 112801, 1, 1, 1, 0, 1, 'フロンティア\\nスピリッツを\\nお見せするべ！', 0);
insert into room_unit_comments values (4004, 112801, 1, 2, 1, 0, 1, 'この鎧を着ると\\n気が引き締まる\\n感じがするべ', 0);
insert into room_unit_comments values (4005, 112801, 1, 3, 1, 0, 1, '搾りたての牛乳飲んで\\n今日も一日\\nがんばるべ！', 0);
insert into room_unit_comments values (4006, 112801, 1, 4, 1, 0, 1, 'みんなに牧場の\\n乳製品を\\n味わってもらいてぇべ', 0);
insert into room_unit_comments values (4007, 112801, 1, 5, 1, 0, 1, 'ここはいいとこだべ\\nうちの動物たちも\\n連れてきてやりてぇな', 0);
insert into room_unit_comments values (4008, 112801, 1, 101, 4, 0, 1, 'みんなオラより\\n若ぇのに働いてて\\n立派だべな', 0);
insert into room_unit_comments values (4009, 112801, 1, 102, 8, 0, 1, '牧場もギルドの\\nみんなもオラが\\nまとめて面倒見るべ！', 0);
insert into room_unit_comments values (4010, 112801, 2, 1, 1, 0, 1, 'さあ、今日も\\n忙しくなるべよ\\n気合入れてくべ！', 0);
insert into room_unit_comments values (4011, 112801, 2, 2, 1, 0, 1, 'お、あんちゃん\\n丁度いいとこに！\\n一緒に街に\\n行商しに行くべ！', 0);
insert into room_unit_comments values (4012, 112801, 2, 3, 1, 0, 1, '牧場仕事で培った力が\\n戦いでも役立つなら\\n一石二鳥だべさ！', 0);
insert into room_unit_comments values (4013, 112801, 2, 4, 1, 0, 1, '疲れた時は牧場産の\\nミルク菓子で\\n糖分補給だべ', 0);
insert into room_unit_comments values (4014, 112801, 2, 101, 4, 0, 1, 'これ、牧場の\\n新製品だべ\\n一番最初に味見\\nしてほしいべさ', 0);
insert into room_unit_comments values (4015, 112801, 2, 102, 8, 0, 1, '働きづめはよくねぇベ\\n膝枕してやっから\\nこっち来るべさ', 0);
insert into room_unit_comments values (4016, 112801, 2, 1, 1, 1, 1, 'ふぁあ…\\n酪農家の朝は\\n早ぇんだべ…', 0);
insert into room_unit_comments values (4017, 112801, 2, 2, 1, 2, 1, 'ごはんの時間だべ！\\n腹が減っては酪農も\\n戦いもできねえべ！', 0);
insert into room_unit_comments values (4018, 112801, 2, 3, 1, 3, 1, 'そろそろ寝るべ！\\n健全なお笑いは\\n健全な肉体に宿るべ！', 0);
insert into room_unit_comments values (4020, 112801, 3, 2, 1, 0, 1, '牧草みたいに\\nふっかふかだべ～', 0);
insert into room_unit_comments values (4021, 112801, 3, 3, 1, 0, 1, 'この子、目の感じが\\nエリザベスに似てるべ', 0);
insert into room_unit_comments values (4022, 112801, 3, 4, 1, 0, 1, 'いい匂いだべ～\\n疲れた体に\\nしみるべな～', 0);
insert into room_unit_comments values (4023, 112801, 3, 5, 1, 0, 1, 'あったけぇな～\\n牧場にも\\n置いてみっかな～', 0);
insert into room_unit_comments values (4025, 112801, 3, 7, 1, 0, 1, 'うまいべ！\\n生産者のこだわりを\\n感じるべさ', 0);
insert into room_unit_comments values (4026, 112801, 3, 8, 1, 0, 1, '酪農も戦いも\\nまずは知識だべ！', 0);
insert into room_unit_comments values (4028, 113001, 1, 1, 1, 0, 1, 'ぴょん、ぴょん♪\\nこの服のおかげで、\\n体が軽いなぁ…♪', 0);
insert into room_unit_comments values (4029, 113001, 1, 2, 1, 0, 1, '今の内に部屋の\\n掃除をしておこっと…\\nみんな喜んで\\nくれるといいなぁ', 0);
insert into room_unit_comments values (4030, 113001, 1, 3, 1, 0, 1, '耳と尻尾…この服、\\n本当にウサギさん\\nみたいだなぁ', 0);
insert into room_unit_comments values (4031, 113001, 1, 4, 1, 0, 1, 'なんだか先輩の\\n気配がするような…\\n気のせいかな？', 0);
insert into room_unit_comments values (4032, 113001, 1, 5, 1, 0, 1, 'ウサギさんの真似を\\nしたら、存在感が薄い\\nとか言われないかな？\\nア、アユミだぴょん♪', 0);
insert into room_unit_comments values (4033, 113001, 1, 101, 4, 0, 1, 'えへへ…\\nいつもとは違う先輩が\\nたくさん見られて、\\nうれしいな♪', 0);
insert into room_unit_comments values (4034, 113001, 1, 102, 8, 0, 1, '本の中の世界で先輩と\\n旅をするなんて…\\n幸せすぎて、罰が\\n当たりそうだよぉ…', 0);
insert into room_unit_comments values (4035, 113001, 2, 1, 1, 0, 1, 'じ～…はっ！？\\nす、すみません！\\n話しかけてもらえる\\nなんて思ってなくて！', 0);
insert into room_unit_comments values (4036, 113001, 2, 2, 1, 0, 1, '先輩がすぐそばに…\\nし、幸せすぎて\\n倒れそうですぅ！', 0);
insert into room_unit_comments values (4037, 113001, 2, 3, 1, 0, 1, 'え、えっと…あの…！\\nうう…いざ先輩と\\n向き合うと\\n緊張しちゃうよぉ…', 0);
insert into room_unit_comments values (4038, 113001, 2, 4, 1, 0, 1, 'はうっ！？\\nしょ、正面から見る\\n先輩は、私にとって\\n神々しすぎますぅ…！', 0);
insert into room_unit_comments values (4039, 113001, 2, 101, 4, 0, 1, '先輩…その…\\nい、一緒にご飯でも\\nどうでひゅか！\\nうう…またかんだぁ…', 0);
insert into room_unit_comments values (4040, 113001, 2, 102, 8, 0, 1, 'せ、先輩…\\nハーブティーを\\n入れたんですが、\\n一緒にどうですか…？', 0);
insert into room_unit_comments values (4041, 113001, 2, 1, 1, 1, 1, 'せ、先輩！\\nおはようございます！\\nえへへ、練習通りに\\nバッチリ言えたぁ♪', 0);
insert into room_unit_comments values (4042, 113001, 2, 2, 1, 2, 1, 'あ、もうお昼ですね\\n時計を持ってて\\n良かったです', 0);
insert into room_unit_comments values (4043, 113001, 2, 3, 1, 3, 1, 'もうこんな時間…\\nお休みする\\n準備をしちゃいますね', 0);
insert into room_unit_comments values (4045, 113001, 3, 2, 1, 0, 1, 'あ…ちょっとだけ\\n先輩の匂いがする…\\nえへへ、幸せだなぁ♪', 0);
insert into room_unit_comments values (4046, 113001, 3, 3, 1, 0, 1, '…私もウサギさんの\\nぬいぐるみとして、\\n先輩のそばに…はっ！\\n私ったら何を…！', 0);
insert into room_unit_comments values (4047, 113001, 3, 4, 1, 0, 1, 'あ、いい香り…\\n先輩もこういうのが\\n好きなのかな？', 0);
insert into room_unit_comments values (4048, 113001, 3, 5, 1, 0, 1, '先輩が隣に\\n居たら、もっと\\n暖かいのになぁ…♪', 0);
insert into room_unit_comments values (4050, 113001, 3, 7, 1, 0, 1, 'おいしい…でも、\\n先輩と一緒に\\n食べたら、もっと\\nおいしいだろうな…', 0);
insert into room_unit_comments values (4051, 113001, 3, 8, 1, 0, 1, 'ウサギさんって、穴を\\n掘ったりするんだ…\\n私も、隠れたいときに\\n掘ってみようかな？', 0);
insert into room_unit_comments values (4053, 180501, 1, 1, 1, 0, 1, 'ネビアさまのように\\n普段からパタパタと\\n飛んでみるのも…', 0);
insert into room_unit_comments values (4054, 180501, 1, 2, 1, 0, 1, 'ご立派になられた\\n主さまと並べるように\\nもっと精進しなくては', 0);
insert into room_unit_comments values (4055, 180501, 1, 3, 1, 0, 1, '月々の食費が\\n増えてしまいました\\n申し訳ございません…', 0);
insert into room_unit_comments values (4056, 180501, 1, 4, 1, 0, 1, 'ワンワンのほうの\\n主さまは、この姿に\\n驚くでしょうか…？', 0);
insert into room_unit_comments values (4057, 180501, 1, 5, 1, 0, 1, '主さまと離れていても\\n主さまとの絆は\\n胸に感じております…', 0);
insert into room_unit_comments values (4058, 180501, 1, 101, 4, 0, 1, 'このギルドハウスは\\nみなさまの帰る場所…\\nわたくしが守ります', 0);
insert into room_unit_comments values (4059, 180501, 1, 102, 8, 0, 1, 'どんな未来が\\n待ち受けようとも\\n主さまと添い遂げます', 0);
insert into room_unit_comments values (4060, 180501, 2, 1, 1, 0, 1, 'おでかけですか？\\nではわたくしも\\nお供いたします', 0);
insert into room_unit_comments values (4061, 180501, 2, 2, 1, 0, 1, 'もう二度と主さまと\\n離れたくはありません\\nいつ何時も…', 0);
insert into room_unit_comments values (4062, 180501, 2, 3, 1, 0, 1, 'なにかお困りごと\\nでございますか？\\nわたくしに何なりと…', 0);
insert into room_unit_comments values (4063, 180501, 2, 4, 1, 0, 1, 'どうぞゆっくりと\\n心ゆくまでくつろいで\\nくださいまし、主さま', 0);
insert into room_unit_comments values (4064, 180501, 2, 101, 4, 0, 1, 'この羽で主さまを\\nどこまでも遠く…\\n高くへと導きます', 0);
insert into room_unit_comments values (4065, 180501, 2, 102, 8, 0, 1, '主さま、主さま…♪\\nおそばにいられるのが\\nうれしくて、つい…', 0);
insert into room_unit_comments values (4066, 180501, 2, 1, 1, 1, 1, 'おはようございます\\n今日も一日、主さまの\\nサポートをいたします', 0);
insert into room_unit_comments values (4067, 180501, 2, 2, 1, 2, 1, '今日も頑張っている\\n主さまに、スタンプを\\nもう一つ…ポン！', 0);
insert into room_unit_comments values (4068, 180501, 2, 3, 1, 3, 1, '寝付けないのでしたら\\nわたくしが子守唄を\\n歌ってさしあげます', 0);
insert into room_unit_comments values (4070, 180501, 3, 2, 1, 0, 1, 'ふかふか…\\nまるで主さまのような\\n柔らかさでございます', 0);
insert into room_unit_comments values (4071, 180501, 3, 3, 1, 0, 1, 'あなたも一緒に\\n主さまと遊びますか？\\n至福の時間ですよ♪', 0);
insert into room_unit_comments values (4072, 180501, 3, 4, 1, 0, 1, '主さまの優しくて\\nくすぐったい匂いが\\nたまらなく恋しいです', 0);
insert into room_unit_comments values (4073, 180501, 3, 5, 1, 0, 1, '主さまの心と\\n繋がったときのような\\n温もりを感じます', 0);
insert into room_unit_comments values (4075, 180501, 3, 7, 1, 0, 1, 'いけませんっ…！\\n元の姿に戻ると、また\\n食べてしまうのに…！', 0);
insert into room_unit_comments values (4076, 180501, 3, 8, 1, 0, 1, '主さまに読み聞かせる\\n絵本は…妖精が主役の\\n物語にいたしましょう', 0);
insert into room_unit_comments values (4078, 104801, 1, 103, 12, 0, 1, '…彼のこと弟みたいに\\n思ってきたのに…私、\\nどうしたらいいの…？', 0);
insert into room_unit_comments values (4079, 104801, 2, 103, 12, 0, 1, 'よ、予定がなかったら\\nでいいんだけど…\\nその、ふ、二人で\\n訓練とか…どうかな？', 0);
insert into room_unit_comments values (4080, 112901, 1, 1, 1, 0, 1, 'おめかしもしたし\\nあとはお兄ちゃんを\\n待つだけですね～♪', 0);
insert into room_unit_comments values (4081, 112901, 1, 2, 1, 0, 1, 'お兄ちゃんの身の回り\\nをお片付け～、これぞ\\nデキる妹アピール！', 0);
insert into room_unit_comments values (4082, 112901, 1, 3, 1, 0, 1, 'あ、衣装がほつれてる\\nこれくらいなら自分で\\n繕えますね…！', 0);
insert into room_unit_comments values (4083, 112901, 1, 4, 1, 0, 1, 'この格好で歩いてると\\n見慣れた景色も\\n違うものに見えますね', 0);
insert into room_unit_comments values (4084, 112901, 1, 5, 1, 0, 1, '勉強もちゃんとします\\n…でも、一人だと\\n集中力がもちません～', 0);
insert into room_unit_comments values (4085, 112901, 1, 101, 4, 0, 1, 'お兄ちゃんを大好きな\\n妹が待ってますよ～\\n…まだですかね～', 0);
insert into room_unit_comments values (4086, 112901, 1, 102, 8, 0, 1, 'お兄ちゃんのために\\n掃除洗濯をする私って\\nお嫁さんみたい…\\n…えへへ～', 0);
insert into room_unit_comments values (4087, 112901, 2, 1, 1, 0, 1, 'おに～いちゃん！\\n縫い物、一緒に\\nやりましょうよ！', 0);
insert into room_unit_comments values (4088, 112901, 2, 2, 1, 0, 1, 'かわいい妹を\\n愛でたくなりました？\\n思う存分、どうぞ♪', 0);
insert into room_unit_comments values (4089, 112901, 2, 3, 1, 0, 1, 'わっ、ビックリした～\\nもう、お兄ちゃんてば\\nイタズラっ子ですね～', 0);
insert into room_unit_comments values (4090, 112901, 2, 4, 1, 0, 1, '一緒にお買い物\\n行きませんか？\\n妹とデートですよっ♪', 0);
insert into room_unit_comments values (4091, 112901, 2, 101, 4, 0, 1, 'お兄ちゃん…頭を\\n撫でてくれませんか？\\nえへへ、これが一番♪', 0);
insert into room_unit_comments values (4092, 112901, 2, 102, 8, 0, 1, 'お兄ちゃん大好き♪\\n何度でも言いますよ！\\nお兄ちゃん大好きっ♪', 0);
insert into room_unit_comments values (4093, 112901, 2, 1, 1, 1, 1, 'おはよ～お兄ちゃん！\\n妹モーニングコールの\\n時間ですよっ♪', 0);
insert into room_unit_comments values (4094, 112901, 2, 2, 1, 2, 1, 'そろそろ休憩ですね！\\n甘いお菓子で\\n元気回復しましょ～！', 0);
insert into room_unit_comments values (4095, 112901, 2, 3, 1, 3, 1, '夜更かし厳禁！\\nでも、もう少しだけ\\nお話ししたいなぁ～', 0);
insert into room_unit_comments values (4097, 112901, 3, 2, 1, 0, 1, 'ふっかふかですよ！\\nお兄ちゃんと一緒に\\n座りたいなぁ…♪', 0);
insert into room_unit_comments values (4098, 112901, 3, 3, 1, 0, 1, 'このぬいぐるみの\\nかわいさ…う～ん\\n負けられません…！', 0);
insert into room_unit_comments values (4099, 112901, 3, 4, 1, 0, 1, '香りにも気をつかって\\nパーフェクトな妹に\\nなっちゃいますから！', 0);
insert into room_unit_comments values (4100, 112901, 3, 5, 1, 0, 1, 'はぁ～ぬくぬくです～\\nお兄ちゃんと一緒に\\n温まりたいなぁ…♪', 0);
insert into room_unit_comments values (4102, 112901, 3, 7, 1, 0, 1, 'これは止まりませんね\\nもぐもぐ…いくらでも\\n食べられちゃいます', 0);
insert into room_unit_comments values (4103, 112901, 3, 8, 1, 0, 1, 'これ、デザインの\\n参考になりそう！\\n私にも作れるかなぁ', 0);
insert into room_unit_comments values (4105, 106601, 1, 1, 1, 0, 1, '退屈です…\\nなにか楽しいことは\\nないですか？', 0);
insert into room_unit_comments values (4106, 106601, 1, 2, 1, 0, 1, 'ギャングの仕事は\\n今日はお休みです\\nのんびりするですよ', 0);
insert into room_unit_comments values (4107, 106601, 1, 3, 1, 0, 1, 'ひうっ！\u3000あたしの\\n尻尾なんて食べても\\nおいしくないですよ？', 0);
insert into room_unit_comments values (4108, 106601, 1, 4, 1, 0, 1, 'ふう…どうやら\\n例の件はまだボスに\\nバレてないですね…', 0);
insert into room_unit_comments values (4109, 106601, 1, 5, 1, 0, 1, '下克上…いい言葉です\\nって、ボスに聞かれて\\nないですよね…？', 0);
insert into room_unit_comments values (4110, 106601, 1, 101, 4, 0, 1, 'いつか絶対ビッグに\\nなってやるです！\\nあたしを信じるです！', 0);
insert into room_unit_comments values (4111, 106601, 1, 102, 8, 0, 1, 'あたしが覚醒したら\\nきっと誰よりも\\n強くなるはずです！', 0);
insert into room_unit_comments values (4112, 106601, 2, 1, 1, 0, 1, 'なんですか？\\n貢ぎ物なら\\nいつでも歓迎ですよ！', 0);
insert into room_unit_comments values (4113, 106601, 2, 2, 1, 0, 1, 'あたしだって\\nやる時はやるですよ！\\nその時がこないだけ！', 0);
insert into room_unit_comments values (4114, 106601, 2, 3, 1, 0, 1, 'しりとり勝負ですか？\\nいい度胸ですね、\\nかかってくるです！', 0);
insert into room_unit_comments values (4115, 106601, 2, 4, 1, 0, 1, 'お兄さんは\\nヒマそうですね…\\nうらやましいです', 0);
insert into room_unit_comments values (4116, 106601, 2, 101, 4, 0, 1, 'かまってほしいです？\\nまったく…いいですよ\\nしょうがないですね', 0);
insert into room_unit_comments values (4117, 106601, 2, 102, 8, 0, 1, 'お兄さんのことは\\nこのあたしが\\n守ってやるですよ！', 0);
insert into room_unit_comments values (4118, 106601, 2, 1, 1, 1, 1, 'デキるギャングの\\n朝は早いのです…\\nふぁあ…', 0);
insert into room_unit_comments values (4119, 106601, 2, 2, 1, 2, 1, 'お腹がすいたですね\\nなにか食べにいくです\\nお兄さんのおごりで！', 0);
insert into room_unit_comments values (4120, 106601, 2, 3, 1, 3, 1, 'ふぁあ…むにゅう…\\nまだ起きてるですよぉ', 0);
insert into room_unit_comments values (4122, 106601, 3, 2, 1, 0, 1, 'はぁ～…\\nもうここから一歩も\\n動きたくないです', 0);
insert into room_unit_comments values (4123, 106601, 3, 3, 1, 0, 1, 'なかなかいいモフりを\\nしてやがるです…\\n舎弟にしてやるですよ', 0);
insert into room_unit_comments values (4124, 106601, 3, 4, 1, 0, 1, 'なんかおしゃれな\\n匂いがするですね…', 0);
insert into room_unit_comments values (4125, 106601, 3, 5, 1, 0, 1, 'ふふーん！\\nあたしのブレスの方が\\n火力は上ですね！', 0);
insert into room_unit_comments values (4127, 106601, 3, 7, 1, 0, 1, 'あたしに貢ぎ物とは\\nよく分かってるですね\\n食べてやるですよ', 0);
insert into room_unit_comments values (4128, 106601, 3, 8, 1, 0, 1, 'ふーむ…\\nもっと楽しい本は\\nないですかね？', 0);
insert into room_unit_comments values (4130, 113201, 1, 1, 1, 0, 1, '海に眠る秘宝…\\n心躍る響きだ！\\n早く見つけたい…！', 0);
insert into room_unit_comments values (4131, 113201, 1, 2, 1, 0, 1, 'うう～、暑いぃ…\\nかき氷を食べて\\nすっきりしたいぃ…', 0);
insert into room_unit_comments values (4132, 113201, 1, 3, 1, 0, 1, 'アターック！\\nいや、もっとこう…\\nアタァーック！', 0);
insert into room_unit_comments values (4133, 113201, 1, 4, 1, 0, 1, 'スイカ割りで\\n目を回さない\\nコツはなんだろうか…', 0);
insert into room_unit_comments values (4134, 113201, 1, 5, 1, 0, 1, 'せっかく海に来たのだ\\n泳ぎも上手に\\nなりたいものだな', 0);
insert into room_unit_comments values (4135, 113201, 1, 101, 4, 0, 1, 'ふっふっふ…\\n疼く…疼くぞ！\\n日焼けの痕が…', 0);
insert into room_unit_comments values (4136, 113201, 1, 102, 8, 0, 1, 'シグルドと私は\\n来世でも共にある…\\nつまり我らはずっと…\\nはわわ…！', 0);
insert into room_unit_comments values (4137, 113201, 2, 1, 1, 0, 1, 'シグルド、私と共に\\n日光浴に行かないか？\\n光の力を集めよう！', 0);
insert into room_unit_comments values (4138, 113201, 2, 2, 1, 0, 1, 'この格好だからできる\\n必殺技を考えている\\n何か案はないか？', 0);
insert into room_unit_comments values (4139, 113201, 2, 3, 1, 0, 1, 'シグルド～！\\nスイカを貰ったから\\n一緒に食べよう！', 0);
insert into room_unit_comments values (4140, 113201, 2, 4, 1, 0, 1, 'こう日差しが強いと\\n日焼けしそうだな\\n跡になってないか…？', 0);
insert into room_unit_comments values (4141, 113201, 2, 101, 4, 0, 1, '我らの夏の黙示録\\nしっかりと記録\\nしておかねばな', 0);
insert into room_unit_comments values (4142, 113201, 2, 102, 8, 0, 1, 'ちゃんと日焼けどめを\\n塗ってもらうべき\\nだったかな…？\\nシ、シグルドに…！', 0);
insert into room_unit_comments values (4143, 113201, 2, 1, 1, 1, 1, '朝だぞシグルド！\\nさぁ、日光を浴びて\\n光の加護を得るのだ！', 0);
insert into room_unit_comments values (4144, 113201, 2, 2, 1, 2, 1, 'もう昼食の時間か…\\n私の魔力も減ったし\\n早く補給しなければ', 0);
insert into room_unit_comments values (4145, 113201, 2, 3, 1, 3, 1, '夜でも我らの活動は\\n終わることはない！\\nさぁ準備を…ふわぁ…', 0);
insert into room_unit_comments values (4147, 113201, 3, 2, 1, 0, 1, '海で遊んでいると\\n疲れてしまうからな\\n少し休まるとしよう', 0);
insert into room_unit_comments values (4148, 113201, 3, 3, 1, 0, 1, 'えへへ～、君の名前は\\n何にしまちょうかね♪\\n…はっ、見たのか！？', 0);
insert into room_unit_comments values (4149, 113201, 3, 4, 1, 0, 1, '心地よい香りで\\n我が精神も安らぐ…', 0);
insert into room_unit_comments values (4150, 113201, 3, 5, 1, 0, 1, '別に寒くなどないぞ！\\n寒くないが、ちょっと\\n暖まりたくなってな！', 0);
insert into room_unit_comments values (4152, 113201, 3, 7, 1, 0, 1, 'もぐ…食べ過ぎた分は\\n魔力に変換されるのだ\\n…たぶん', 0);
insert into room_unit_comments values (4153, 113201, 3, 8, 1, 0, 1, '…なな、なんだ！？\\nシグルドはこういう\\n趣味なのか…！？', 0);
insert into room_unit_comments values (4155, 113201, 3, 10, 1, 0, 1, 'むむ、この乗り心地…\\nいざゆかん、\\nシードラゴンよ！', 0);
insert into room_unit_comments values (4156, 113201, 3, 11, 1, 0, 1, '疾風の冥姫の名に\\nふさわしき\\n深海の玉座よ…\\nふああ…柔らかい～', 0);
insert into room_unit_comments values (4157, 180201, 1, 1, 1, 0, 1, 'この姿でいると\\nわたしもお姫様に\\nなれた気がする…♪', 0);
insert into room_unit_comments values (4158, 180201, 1, 2, 1, 0, 1, 'お腹空いてきちゃった\\nまずは買い出しに…\\n…変身解かなくちゃ！', 0);
insert into room_unit_comments values (4159, 180201, 1, 3, 1, 0, 1, '胸のところが空いてて\\nスースーするの\\nまだ慣れないな…', 0);
insert into room_unit_comments values (4160, 180201, 1, 4, 1, 0, 1, '治癒魔法に使ってた\\n魔力を攻撃魔法に…\\n頭の中でも練習練習', 0);
insert into room_unit_comments values (4161, 180201, 1, 5, 1, 0, 1, '何もできなかった\\nわたしから、少しは\\n変われたのかな…？', 0);
insert into room_unit_comments values (4162, 180201, 1, 101, 4, 0, 1, '騎士クン…\\n今どこにいるの…？\\n…会いたいな', 0);
insert into room_unit_comments values (4163, 180201, 1, 102, 8, 0, 1, '離れてても分かるよ…\\n温かい力で騎士クンに\\n守られてるの', 0);
insert into room_unit_comments values (4164, 180201, 2, 1, 1, 0, 1, 'わたしが戦えてるのは\\n騎士クンのおかげだよ\\nいつもありがとう！', 0);
insert into room_unit_comments values (4165, 180201, 2, 2, 1, 0, 1, 'お腹空いてそう…？\\n…内緒で作ったおやつ\\n騎士クンも食べる？', 0);
insert into room_unit_comments values (4166, 180201, 2, 3, 1, 0, 1, 'ひゃうっ！\u3000え！？\\nせ、背中はダメ～！\\n言ってから触って～！', 0);
insert into room_unit_comments values (4167, 180201, 2, 4, 1, 0, 1, 'この格好、どうかな？\\nえ？\u3000似合ってる…？\\n本当？\u3000…うれしい！', 0);
insert into room_unit_comments values (4168, 180201, 2, 101, 4, 0, 1, 'かわいい？\u3000そうだね\\nひらひらが…わたし？\\nええっ、そ、そんな！', 0);
insert into room_unit_comments values (4169, 180201, 2, 102, 8, 0, 1, '騎士クン、これからも\\nずっと…わたしの\\nそばにいてください', 0);
insert into room_unit_comments values (4170, 180201, 2, 1, 1, 1, 1, '朝からこんなに\\n食べる日が来るなんて\\n思ってなかったよ…', 0);
insert into room_unit_comments values (4171, 180201, 2, 2, 1, 2, 1, 'お昼を作らなくちゃ\\n騎士クン、一緒に\\nお料理してみる？', 0);
insert into room_unit_comments values (4172, 180201, 2, 3, 1, 3, 1, '騎士クン、もう眠い？\\n眠るまで、わたしが\\nずっとそばにいるね', 0);
insert into room_unit_comments values (4174, 180201, 3, 2, 1, 0, 1, '攻撃参加するからこそ\\n適度に体を休めるのは\\n大切だよね！', 0);
insert into room_unit_comments values (4175, 180201, 3, 3, 1, 0, 1, 'かわいい…騎士クンと\\nシェフィちゃんにも\\nプレゼントしたいな', 0);
insert into room_unit_comments values (4176, 180201, 3, 4, 1, 0, 1, 'いい香り～…\\nあれ？\u3000お腹が空いて\\nきちゃった…！？', 0);
insert into room_unit_comments values (4177, 180201, 3, 5, 1, 0, 1, '温かい…\\n騎士クンがくれる\\n力みたい…', 0);
insert into room_unit_comments values (4179, 180201, 3, 7, 1, 0, 1, 'ぱくっ、\\nあむ、はむっ…\\nううぅ～…やっぱり\\n手が止まらないよぉ～', 0);
insert into room_unit_comments values (4180, 180201, 3, 8, 1, 0, 1, '新しく覚えたいな…\\nみんなで食べられる\\n大皿向けの料理♪', 0);
insert into room_unit_comments values (4182, 104901, 1, 103, 12, 0, 1, 'お姉ちゃんの愛\\nこのままじゃ\\nあふれちゃうよ…♪', 0);
insert into room_unit_comments values (4183, 104901, 2, 103, 12, 0, 1, '弟くん♪\\n弟くんっ♪\\nおっとうっとくんっ♪', 0);
insert into room_unit_comments values (4184, 113101, 1, 1, 1, 0, 1, '泳ぐのもいいけど\\n今日は砂浜で\\nのんびりしようかね', 0);
insert into room_unit_comments values (4185, 113101, 1, 2, 1, 0, 1, 'さてと\\nちょっくらひと泳ぎ\\n行ってくるかね', 0);
insert into room_unit_comments values (4186, 113101, 1, 3, 1, 0, 1, 'あっついねぇ…\\nうちわがないと\\nしんどいったらないよ', 0);
insert into room_unit_comments values (4187, 113101, 1, 4, 1, 0, 1, '冷たすぎる飲み物で\\n体を冷やさないよう\\n気をつけないと…', 0);
insert into room_unit_comments values (4188, 113101, 1, 5, 1, 0, 1, '夏はあっという間だし\\n悔いがないように\\n楽しまないとね', 0);
insert into room_unit_comments values (4189, 113101, 1, 101, 4, 0, 1, 'きっとこの夏は\\nアタシにとって大事な\\n想い出になるね…', 0);
insert into room_unit_comments values (4190, 113101, 1, 102, 8, 0, 1, '…前に比べたら\\nアタシたちの距離も\\n近づいたみたいだね', 0);
insert into room_unit_comments values (4191, 113101, 2, 1, 1, 0, 1, 'もし暇なら\\n今日も笹舟釣り\\n一緒にどうだい？', 0);
insert into room_unit_comments values (4192, 113101, 2, 2, 1, 0, 1, 'お前さん、釣りに\\n興味が湧いたなら今度\\n道具を見に行こうよ', 0);
insert into room_unit_comments values (4193, 113101, 2, 3, 1, 0, 1, '今から砂浜に行くんだ\\nお前さんも一緒に\\n散歩するかい？', 0);
insert into room_unit_comments values (4194, 113101, 2, 4, 1, 0, 1, 'え、日焼け跡？\\nおや…本当だ\\nすぐ焼けちまうねえ', 0);
insert into room_unit_comments values (4195, 113101, 2, 101, 4, 0, 1, 'ひゃっ！？\\nちょっと！\\n日焼け跡をいきなり\\n触らないでおくれ！', 0);
insert into room_unit_comments values (4196, 113101, 2, 102, 8, 0, 1, 'お前さんは、その…\\nアタシと一緒にいて\\n楽しかったかい？', 0);
insert into room_unit_comments values (4197, 113101, 2, 1, 1, 1, 1, 'おはようさん\\n今日も砂浜に行って\\nゆっくりしようか', 0);
insert into room_unit_comments values (4198, 113101, 2, 2, 1, 2, 1, 'お昼か…\\nそうだ、よかったら\\n刺身定食、作ろうか？', 0);
insert into room_unit_comments values (4199, 113101, 2, 3, 1, 3, 1, '夜の空を見てるとさ\\nなつかしい気持ちに\\nなるんだよね', 0);
insert into room_unit_comments values (4201, 113101, 3, 2, 1, 0, 1, '適度に休憩して\\n夏バテしないよう\\n気をつけないとね', 0);
insert into room_unit_comments values (4202, 113101, 3, 3, 1, 0, 1, 'あんたたちも\\n海を楽しみたいって\\n思っているのかね', 0);
insert into room_unit_comments values (4203, 113101, 3, 4, 1, 0, 1, 'ん～…香りでも\\nバカンスらしさを\\n楽しめるもんだね', 0);
insert into room_unit_comments values (4204, 113101, 3, 5, 1, 0, 1, 'こういう格好だと\\n少し冷えちまうんだよ', 0);
insert into room_unit_comments values (4206, 113101, 3, 7, 1, 0, 1, 'もぐもぐもぐ…\\n遊んだ分、お腹が\\n空いちまってねぇ', 0);
insert into room_unit_comments values (4207, 113101, 3, 8, 1, 0, 1, '…ん、なんだいこの本\\n催眠…うーん読めない\\nナナカに聞いてみるか', 0);
insert into room_unit_comments values (4209, 113101, 3, 10, 1, 0, 1, 'へえ…\\nなかなかいい\\n乗り心地じゃないか', 0);
insert into room_unit_comments values (4210, 113101, 3, 11, 1, 0, 1, 'そうそうハマグリって\\n竿でも釣れるんだよ\\n知ってたかい？', 0);
insert into room_unit_comments values (4211, 113301, 1, 1, 1, 0, 1, '海を満喫しなきゃね\\nちょっとひと泳ぎ\\n行ってこようかな？', 0);
insert into room_unit_comments values (4212, 113301, 1, 2, 1, 0, 1, 'う～ん…♪\\nいつもと違った\\n開放感～\\nなんちゃって！', 0);
insert into room_unit_comments values (4213, 113301, 1, 3, 1, 0, 1, '今のナナカちゃんは\\nたぶん水属性！', 0);
insert into room_unit_comments values (4214, 113301, 1, 4, 1, 0, 1, '水着もバッチリ！\\nサイカワサイツヨ\\nナナカちゃ～ん☆', 0);
insert into room_unit_comments values (4215, 113301, 1, 5, 1, 0, 1, 'んっふっふ\\nドキ！\u3000水着だらけの\\nギルドハウス！\\nとかどうかな？', 0);
insert into room_unit_comments values (4216, 113301, 1, 101, 4, 0, 1, 'そんなに見られると\\nちょ～っと\\n恥ずかしいかも…\\nなんてねなんてね！', 0);
insert into room_unit_comments values (4217, 113301, 1, 102, 8, 0, 1, 'ちょっとくらい\\nドキッとしてくれても\\nいいのにな～、もう…', 0);
insert into room_unit_comments values (4218, 113301, 2, 1, 1, 0, 1, '水着魔法少女の\\n相方がほしいなぁ～…\\nね、君やってみない？', 0);
insert into room_unit_comments values (4219, 113301, 2, 2, 1, 0, 1, 'いつもの格好と同じ？\\nも～、わかってない！\\nセクスィー度が違う！', 0);
insert into room_unit_comments values (4220, 113301, 2, 3, 1, 0, 1, 'どうかなどうかな？\\nこのひらひらのとこが\\nかわいーかなー\\nとか思うんだけど！', 0);
insert into room_unit_comments values (4221, 113301, 2, 4, 1, 0, 1, 'せっかくだから\\nギャルゲーイベント\\nごっことか\\nやってみる？', 0);
insert into room_unit_comments values (4222, 113301, 2, 101, 4, 0, 1, 'ナナカちゃんの\\n好感度を上げたい？\\nならおでかけだー！', 0);
insert into room_unit_comments values (4223, 113301, 2, 102, 8, 0, 1, 'おうちで水着って\\nなんだかコスプレ\\nみたいで楽しいかも♪', 0);
insert into room_unit_comments values (4224, 113301, 2, 1, 1, 1, 1, 'おっはよーう！\\n今日はバカンス日和！\\n海へゴーですぞ～♪', 0);
insert into room_unit_comments values (4225, 113301, 2, 2, 1, 2, 1, 'お昼ご飯どうしよ～…\\nあ、ナナカちゃんと\\nどっか食べに行く？', 0);
insert into room_unit_comments values (4226, 113301, 2, 3, 1, 3, 1, '夜は本を読むのが\\n捗りまくりですな～！\\n今日はなに読もっかな', 0);
insert into room_unit_comments values (4228, 113301, 3, 2, 1, 0, 1, '次のイベントもあるし\\nちょっと休んで体力を\\n回復しなきゃね～', 0);
insert into room_unit_comments values (4229, 113301, 3, 3, 1, 0, 1, 'こういうマスコット\\n私にもいたらなぁ\\nいっそ作っちゃう…？', 0);
insert into room_unit_comments values (4230, 113301, 3, 4, 1, 0, 1, '水着魔法少女に\\n似合う香りってのも\\n考えてみよっかな♪', 0);
insert into room_unit_comments values (4231, 113301, 3, 5, 1, 0, 1, '夜になると急に冷えて\\n肌寒いんだよね～…', 0);
insert into room_unit_comments values (4233, 113301, 3, 7, 1, 0, 1, 'あんまり食べると\\nお腹が出て…でも…\\nうう、止まらない～！', 0);
insert into room_unit_comments values (4234, 113301, 3, 8, 1, 0, 1, 'この催眠魔法の本\\n誰にもばれないように\\n保管しとかなきゃね…', 0);
insert into room_unit_comments values (4236, 113301, 3, 10, 1, 0, 1, 'ゴーゴーゴーゴーゴー\\nナナカちゃーん♪', 0);
insert into room_unit_comments values (4237, 113301, 3, 11, 1, 0, 1, 'ナナカちゃんの\\n誕生～\\nなんちゃって', 0);
insert into room_unit_comments values (4238, 113401, 1, 1, 1, 0, 1, 'ファイトファイト☆\\n一生懸命\\n応援するね！', 0);
insert into room_unit_comments values (4239, 113401, 1, 2, 1, 0, 1, 'みんながんばってる！\\n私も応援でみんなを\\n盛り上げなきゃ！', 0);
insert into room_unit_comments values (4240, 113401, 1, 3, 1, 0, 1, 'もし元気のない人が\\nいたら…応援で少し\\nでも元気にしたいな！', 0);
insert into room_unit_comments values (4241, 113401, 1, 4, 1, 0, 1, 'がんばれ～☆\\nよし、発声練習OK！\\n応援は、声も大事！', 0);
insert into room_unit_comments values (4242, 113401, 1, 5, 1, 0, 1, 'せっかく水着なんだし\\n泳いだり潜ったりして\\n遊びたいな～！', 0);
insert into room_unit_comments values (4243, 113401, 1, 101, 4, 0, 1, 'チアリーダーとして\\nキミを精一杯\\n応援したいな…！', 0);
insert into room_unit_comments values (4244, 113401, 1, 102, 8, 0, 1, 'キミへの応援\\nちゃんと\\n届いてるかな…', 0);
insert into room_unit_comments values (4245, 113401, 2, 1, 1, 0, 1, 'えへへ…今ね、\\nキミへの応援歌を\\n考えてたのだ～♪', 0);
insert into room_unit_comments values (4246, 113401, 2, 2, 1, 0, 1, 'どうしたの？\\n元気がないなら\\n私が応援するよ☆', 0);
insert into room_unit_comments values (4247, 113401, 2, 3, 1, 0, 1, 'がんばったあとは休憩\\nしなきゃね！\u3000私と\\n一緒にお昼寝する？', 0);
insert into room_unit_comments values (4248, 113401, 2, 4, 1, 0, 1, 'シオリンとおそろいの\\n水着で応援…\\nしてみたいなぁ～', 0);
insert into room_unit_comments values (4249, 113401, 2, 101, 4, 0, 1, '次はなにして遊ぶ？\\nキミがしたいことを\\n教えてよ！', 0);
insert into room_unit_comments values (4250, 113401, 2, 102, 8, 0, 1, 'キミを応援\\nすることができて…\\n私、すごく幸せ…', 0);
insert into room_unit_comments values (4251, 113401, 2, 1, 1, 1, 1, 'キミって早起き\\nなんだね！\u3000私も\\n見習わなきゃ！', 0);
insert into room_unit_comments values (4252, 113401, 2, 2, 1, 2, 1, 'ちょっとお疲れかな？\\nそれじゃあ\\n応援してあげるね♪', 0);
insert into room_unit_comments values (4253, 113401, 2, 3, 1, 3, 1, '遅い時間まで\\nがんばってえらいね！\\nでも無理はダメだよ♪', 0);
insert into room_unit_comments values (4255, 113401, 3, 2, 1, 0, 1, 'ちょっとだけ休憩…\\n…あう、座り心地が\\n良すぎて…眠気が…', 0);
insert into room_unit_comments values (4256, 113401, 3, 3, 1, 0, 1, 'ここにいるみんなを\\n私の応援でもっと\\n元気にするのだ～！', 0);
insert into room_unit_comments values (4257, 113401, 3, 4, 1, 0, 1, '元気の出る香り～♪\\nこれもうまく応援に\\n活かせないかな～？', 0);
insert into room_unit_comments values (4258, 113401, 3, 5, 1, 0, 1, 'ぽかぽかあったまって\\n元気をチャージ\\nするのだ～☆', 0);
insert into room_unit_comments values (4260, 113401, 3, 7, 1, 0, 1, 'いっぱい食べて、\\nみんなを応援する\\nパワーをつけなきゃ！', 0);
insert into room_unit_comments values (4261, 113401, 3, 8, 1, 0, 1, 'みんなを元気にする\\n方法は…どこかに\\n書いてないかなぁ…？', 0);
insert into room_unit_comments values (4263, 113401, 3, 10, 1, 0, 1, 'わぁ、この子\\n怪獣さんみたいで\\nかわいいね～♪', 0);
insert into room_unit_comments values (4264, 113401, 3, 11, 1, 0, 1, '水着でこれに\\n乗ってると海にいる\\n気分になれるね！', 0);
insert into room_unit_comments values (4265, 113501, 1, 1, 1, 0, 1, 'すごく忙しいけど\\nとても充実した気分\\nこれが青春なのかしら', 0);
insert into room_unit_comments values (4266, 113501, 1, 2, 1, 0, 1, '森の静かな雰囲気も\\n海の開放的な空気も\\nどちらも素敵ね～', 0);
insert into room_unit_comments values (4267, 113501, 1, 3, 1, 0, 1, '汚れたお洗濯物は\\nみんなが頑張った証\\nなんだか愛おしいわ', 0);
insert into room_unit_comments values (4268, 113501, 1, 4, 1, 0, 1, 'みんなを見てると\\n何だか私も\\n走りたくなっちゃうわ', 0);
insert into room_unit_comments values (4269, 113501, 1, 5, 1, 0, 1, 'せっかくの水着だし\\n泳ぐ練習でも\\nしてみようかしら', 0);
insert into room_unit_comments values (4270, 113501, 1, 101, 4, 0, 1, 'みんな～ファイト～！\\n応援するのも大事よね\\n練習しておかなきゃ♪', 0);
insert into room_unit_comments values (4271, 113501, 1, 102, 8, 0, 1, '先生に教えられること\\nまだまだい～っぱいね\\n次は何がいいかしら♪', 0);
insert into room_unit_comments values (4272, 113501, 2, 1, 1, 0, 1, '今日も暑くなりそうね\\nこまめな水分補給を\\n忘れないでね', 0);
insert into room_unit_comments values (4273, 113501, 2, 2, 1, 0, 1, '手伝ってくれるの？\\nありがとう♪\\n先生、頼りにしてるわ', 0);
insert into room_unit_comments values (4274, 113501, 2, 3, 1, 0, 1, '休憩はこまめに\\nとりましょうね\\n無理は厳禁よ', 0);
insert into room_unit_comments values (4275, 113501, 2, 4, 1, 0, 1, '海の遊びって\\nどんなのがあるの？\\n先生に教えてね', 0);
insert into room_unit_comments values (4276, 113501, 2, 101, 4, 0, 1, '水着は初めてだけど\\nどう？\u3000変じゃない？\\nふふ、ありがとう', 0);
insert into room_unit_comments values (4277, 113501, 2, 102, 8, 0, 1, 'あなたと過ごした\\nこの夏は、きっと…\\n忘れられない思い出ね', 0);
insert into room_unit_comments values (4278, 113501, 2, 1, 1, 1, 1, 'おはよう～\\n朝練前にちゃんと\\nごはん食べましょうね', 0);
insert into room_unit_comments values (4279, 113501, 2, 2, 1, 2, 1, 'お弁当作ってきたの\\n栄養いっぱい摂って\\n午後も頑張ろうね', 0);
insert into room_unit_comments values (4280, 113501, 2, 3, 1, 3, 1, 'もうお休みしなきゃね\\n先生が子守唄を歌って\\nあげましょうか？', 0);
insert into room_unit_comments values (4282, 113501, 3, 2, 1, 0, 1, 'ふふ、いい気持ちねぇ\\n先生、少しだけ\\n休憩しちゃおうかしら', 0);
insert into room_unit_comments values (4283, 113501, 3, 3, 1, 0, 1, 'あらかわいい♪\\nチームにもこういう\\nマスコットが欲しいわ', 0);
insert into room_unit_comments values (4284, 113501, 3, 4, 1, 0, 1, 'あら、海の香り？\\n波の音まで聞こえて\\nきちゃいそうだわ', 0);
insert into room_unit_comments values (4285, 113501, 3, 5, 1, 0, 1, 'うふふ\\nこれなら濡れた水着を\\n乾かすのも簡単ね♪', 0);
insert into room_unit_comments values (4287, 113501, 3, 7, 1, 0, 1, 'これ、美味しいわね♪\\nでも、食べ過ぎは\\n禁物よ', 0);
insert into room_unit_comments values (4288, 113501, 3, 8, 1, 0, 1, '先生だって日々勉強よ\\n新しいことを知るのは\\nとても楽しいわ♪', 0);
insert into room_unit_comments values (4290, 113501, 3, 10, 1, 0, 1, 'あらあら、楽しいわね\\nみんなもきっと\\nおおはしゃぎね', 0);
insert into room_unit_comments values (4291, 113501, 3, 11, 1, 0, 1, 'ふふ、これで\\n夏らしい気分を\\n満喫するわよ♪', 0);
insert into room_unit_comments values (4292, 102301, 1, 103, 12, 0, 1, 'サンドイッチも\\n作ったし、\\nお兄ちゃんのお出迎え\\n準備は完璧だね♪', 0);
insert into room_unit_comments values (4293, 102301, 2, 103, 12, 0, 1, 'えへへ、お兄ちゃんと\\nぷうきちが居てくれる\\nだけで、なんだか\\nうれしくなっちゃう♪', 0);
insert into room_unit_comments values (4294, 113601, 1, 1, 1, 0, 1, '少し赤くなっているな\\n日焼けなんてしたのは\\nいつ以来だろう', 0);
insert into room_unit_comments values (4295, 113601, 1, 2, 1, 0, 1, 'この格好で\\n過ごすのは\\n少し勇気がいるな…', 0);
insert into room_unit_comments values (4296, 113601, 1, 3, 1, 0, 1, '暑いのは平気だが\\n肌が外気に触れるの\\nにはまだ慣れないな…', 0);
insert into room_unit_comments values (4297, 113601, 1, 4, 1, 0, 1, 'この格好でも\\n堂々としていれば\\n恥ずかしくはない…\\nのかな？', 0);
insert into room_unit_comments values (4298, 113601, 1, 5, 1, 0, 1, 'おっと…鎧姿の時と\\n重心が違うせいか\\nちょっと不安定だな', 0);
insert into room_unit_comments values (4299, 113601, 1, 101, 4, 0, 1, 'この水着…\\n私に似合って\\nいるのだろうか…？\\n少年には聞きづらいな', 0);
insert into room_unit_comments values (4300, 113601, 1, 102, 8, 0, 1, '少年との\\n海のバカンス…\\nまた行きたい\\nものだな', 0);
insert into room_unit_comments values (4301, 113601, 2, 1, 1, 0, 1, 'あまり見るのは\\nよしてくれ…\\n恥ずかしいじゃ\\nないか…', 0);
insert into room_unit_comments values (4302, 113601, 2, 2, 1, 0, 1, 'どうかしたのかい？\\n私でよければ\\n話し相手くらいには\\nなろうじゃないか', 0);
insert into room_unit_comments values (4303, 113601, 2, 3, 1, 0, 1, 'ひゃっ！\\nす、すまない\\nちょっと過敏に\\nなっているようだ', 0);
insert into room_unit_comments values (4304, 113601, 2, 4, 1, 0, 1, '…っくしゅん！\\nすまない\\n薄着には慣れて\\nないものでね', 0);
insert into room_unit_comments values (4305, 113601, 2, 101, 4, 0, 1, 'まあ、少年になら\\n見られても…\\nい、いや！\\nなんでもない！', 0);
insert into room_unit_comments values (4306, 113601, 2, 102, 8, 0, 1, '私がこうして\\nゆっくりできるのは\\n少年がそばにいて\\nくれるからだよ', 0);
insert into room_unit_comments values (4307, 113601, 2, 1, 1, 1, 1, 'この時間なら\\nビーチにも人は\\n少ないだろうね…\\n遊びに行くかい？', 0);
insert into room_unit_comments values (4308, 113601, 2, 2, 1, 2, 1, '昼食のお誘いかい？\\nいいよ、付き合おう', 0);
insert into room_unit_comments values (4309, 113601, 2, 3, 1, 3, 1, 'もう夜か…\\n一日が経つのは\\nはやいものだね', 0);
insert into room_unit_comments values (4311, 113601, 3, 2, 1, 0, 1, 'これは楽でいいな…\\nいつもは鎧姿で\\n家具を傷つけないか\\n気を使っているからね', 0);
insert into room_unit_comments values (4312, 113601, 3, 3, 1, 0, 1, 'うん…ふわふわの\\n感触が\\nよくわかるな…', 0);
insert into room_unit_comments values (4313, 113601, 3, 4, 1, 0, 1, 'いつもは\\n鎧に匂いが\\n移ってしまうのが\\n悩みなんだよ…', 0);
insert into room_unit_comments values (4314, 113601, 3, 5, 1, 0, 1, 'うーむ…\\n涼しいのに暖かい\\nなんだか奇妙な気分だ', 0);
insert into room_unit_comments values (4316, 113601, 3, 7, 1, 0, 1, '兜を気にせず\\n食べられるのは\\n楽でいいな…', 0);
insert into room_unit_comments values (4317, 113601, 3, 8, 1, 0, 1, 'ふむ…鎧がないと\\nページがめくりやすい', 0);
insert into room_unit_comments values (4319, 113601, 3, 10, 1, 0, 1, '身軽でいいな…\\n鎧を着ていると\\n騎乗訓練の時\\n馬に申し訳がなくてね', 0);
insert into room_unit_comments values (4320, 113601, 3, 11, 1, 0, 1, '貝をうまく使えば\\n水中でも\\n守りを固められそうだ', 0);
insert into room_unit_comments values (4321, 106801, 1, 1, 1, 0, 1, 'どこをアジトと\\nつなげようかな～…\\nこのへんにしよっと♪', 0);
insert into room_unit_comments values (4322, 106801, 1, 2, 1, 0, 1, 'ここってちょっと\\n変わった建物だね\\n妖精がいるでしょ？', 0);
insert into room_unit_comments values (4323, 106801, 1, 3, 1, 0, 1, '色んな人を観察できて\\n眼福眼福…♪', 0);
insert into room_unit_comments values (4324, 106801, 1, 4, 1, 0, 1, '家具の配置変更なら\\nアタシにおまかせあれ\\n…家の形は変えない？', 0);
insert into room_unit_comments values (4325, 106801, 1, 5, 1, 0, 1, '新メニューどうしよう\\n思いついた人がいたら\\nアタシに教えてね！', 0);
insert into room_unit_comments values (4326, 106801, 1, 101, 4, 0, 1, '少年、早く帰って\\nこないかな…\\nよし、迎えに行こう！', 0);
insert into room_unit_comments values (4327, 106801, 1, 102, 8, 0, 1, '結局またあちこち\\n移動する日々だし…\\n少年に会いたいな～', 0);
insert into room_unit_comments values (4328, 106801, 2, 1, 1, 0, 1, 'どしたの少年？\\nお姉さんに何でも\\n相談してみな～？', 0);
insert into room_unit_comments values (4329, 106801, 2, 2, 1, 0, 1, 'あれをああして…\\nおや少年！\u3000ごめんね\\nすぐに気づけなくて！', 0);
insert into room_unit_comments values (4330, 106801, 2, 3, 1, 0, 1, '何？\u3000クリスが\\nアタシを探してる？\\n…いないって言って！', 0);
insert into room_unit_comments values (4331, 106801, 2, 4, 1, 0, 1, 'よければリノちゃんと\\nシズルちゃんにも\\n顔を見せてあげて', 0);
insert into room_unit_comments values (4332, 106801, 2, 101, 4, 0, 1, '少年～！\\nもうヘトヘトだよ～！\\nお願い癒して～！', 0);
insert into room_unit_comments values (4333, 106801, 2, 102, 8, 0, 1, '…アタシが素直に\\n助けてって言えるのは\\n少年だけだよ', 0);
insert into room_unit_comments values (4334, 106801, 2, 1, 1, 1, 1, '朝だよ少年！\\n爽やかな朝の\\nクレープはいかが？', 0);
insert into room_unit_comments values (4335, 106801, 2, 2, 1, 2, 1, 'お腹空いたな～\\nお昼のクレープ\\n少年は食べる？', 0);
insert into room_unit_comments values (4336, 106801, 2, 3, 1, 3, 1, '夜までクレープは\\nやめとけ？\u3000ごめん\\nそれだけは無理…！', 0);
insert into room_unit_comments values (4338, 106801, 3, 2, 1, 0, 1, 'アタシこんなに\\nゆっくりしちゃって\\nいいんだっけ～？', 0);
insert into room_unit_comments values (4339, 106801, 3, 3, 1, 0, 1, '…これ\\nネネカが変身\\nしてないよね？', 0);
insert into room_unit_comments values (4340, 106801, 3, 4, 1, 0, 1, 'いい香りだ…\\n解析完了\\n今度生成しようっと♪', 0);
insert into room_unit_comments values (4341, 106801, 3, 5, 1, 0, 1, '安心するな～…\\nアジトに置けないから\\n羨ましいよ', 0);
insert into room_unit_comments values (4343, 106801, 3, 7, 1, 0, 1, '食べ物を消化するって\\n仕組み、どんなものか\\n気になる…', 0);
insert into room_unit_comments values (4344, 106801, 3, 8, 1, 0, 1, '速読できるけど\\n本を読む時くらい\\n文字にじっくり\\n浸かりたいんだよね…', 0);
insert into room_unit_comments values (4346, 113701, 1, 1, 1, 0, 1, 'エンジェルとして\\nみんなを元気に…！\\nアカリ、頑張ります♪', 0);
insert into room_unit_comments values (4347, 113701, 1, 2, 1, 0, 1, 'お姉ちゃんと一緒に\\nお兄ちゃんを…えへへ\\nまだかな、お兄ちゃん', 0);
insert into room_unit_comments values (4348, 113701, 1, 3, 1, 0, 1, 'エンジェルの音色を\\n目指して、今日も\\nサックスの練習です♪', 0);
insert into room_unit_comments values (4349, 113701, 1, 4, 1, 0, 1, 'お兄ちゃんとの特訓も\\n頑張らないと…\\n厳しくしてくださいね', 0);
insert into room_unit_comments values (4350, 113701, 1, 5, 1, 0, 1, 'かわいいエンジェルの\\n格好、お兄ちゃんなら\\n喜んでくれますよね♪', 0);
insert into room_unit_comments values (4351, 113701, 1, 101, 4, 0, 1, 'エンジェルの力で\\nお兄ちゃんのハートも\\nイチコロですよ♪', 0);
insert into room_unit_comments values (4352, 113701, 1, 102, 8, 0, 1, 'アカリが一番\\n元気にしたいのは\\nお兄ちゃんですよ♪', 0);
insert into room_unit_comments values (4353, 113701, 2, 1, 1, 0, 1, 'お兄ちゃん？\\n触りたいなら…\\nこことかどうですか♪', 0);
insert into room_unit_comments values (4354, 113701, 2, 2, 1, 0, 1, '特訓の時間ですか？\\nアカリ、楽しみに\\nしてたんですよ♪', 0);
insert into room_unit_comments values (4355, 113701, 2, 3, 1, 0, 1, 'あ、お兄ちゃん！\\nそろそろアカリと\\n休憩…しませんか♪', 0);
insert into room_unit_comments values (4356, 113701, 2, 4, 1, 0, 1, 'この羽、触り心地\\nいいですか？\u3000あんっ\\nくすぐったいですよぉ', 0);
insert into room_unit_comments values (4357, 113701, 2, 101, 4, 0, 1, 'お兄ちゃんも元気に\\nなりたいんですか？\\nアカリにお任せです♪', 0);
insert into room_unit_comments values (4358, 113701, 2, 102, 8, 0, 1, 'やんっ♪\\nお兄ちゃんったら\\nダイタンですね♪', 0);
insert into room_unit_comments values (4359, 113701, 2, 1, 1, 1, 1, 'お兄ちゃん、朝ですよ\\nすっごく気持ちのいい\\nお天気ですよ…♪', 0);
insert into room_unit_comments values (4360, 113701, 2, 2, 1, 2, 1, 'お昼寝しませんか\\nお兄ちゃん？\\nアカリの膝枕で…♪', 0);
insert into room_unit_comments values (4361, 113701, 2, 3, 1, 3, 1, '夜ですね、お兄ちゃん\\nアカリ、なんだか胸が\\nドキドキしちゃいます', 0);
insert into room_unit_comments values (4363, 113701, 3, 2, 1, 0, 1, 'フカフカですね…\\n隣にお兄ちゃんが\\nいてくれたらなぁ…♪', 0);
insert into room_unit_comments values (4364, 113701, 3, 3, 1, 0, 1, 'えへへ、アカリも\\nこんな風にかわいく\\nなりたいな～', 0);
insert into room_unit_comments values (4365, 113701, 3, 4, 1, 0, 1, 'お兄ちゃんが好きな\\n匂いなのかな？\\n参考にしますね！', 0);
insert into room_unit_comments values (4366, 113701, 3, 5, 1, 0, 1, '体が火照ってきて\\nなんだかアカリ…\\nクラクラしちゃう…', 0);
insert into room_unit_comments values (4368, 113701, 3, 7, 1, 0, 1, 'はむ、んぐ…あっ\\nほっぺについちゃった\\nベトベトですよぉ～', 0);
insert into room_unit_comments values (4369, 113701, 3, 8, 1, 0, 1, 'エンジェルって色んな\\n物語に出てきますよね\\nもっと調べなくちゃ！', 0);
insert into room_unit_comments values (4371, 103201, 1, 103, 12, 0, 1, 'あの方の前では\\n常に気高く\\nありたいですわね', 0);
insert into room_unit_comments values (4372, 103201, 2, 103, 12, 0, 1, 'どんなに道に迷っても\\nあなたさまの元には\\n絶対に辿り着く\\n自信がありますわ', 0);
insert into room_unit_comments values (4373, 102801, 1, 103, 12, 0, 1, 'あんたと一緒に\\nいるときが一番楽しい\\n一時かもしれないわ', 0);
insert into room_unit_comments values (4374, 102801, 2, 103, 12, 0, 1, 'いつかあんたと一緒に\\nサレンディア救護院を\\n切り盛り…なんてね♪', 0);
insert into room_unit_comments values (4375, 113801, 1, 1, 1, 0, 1, '今日も\\nエンジェルとして、\\nみんなの幸せの\\nために頑張らないと', 0);
insert into room_unit_comments values (4376, 113801, 1, 2, 1, 0, 1, 'せっかく羽が\\nついてるのに\\n飛べないのが残念だわ', 0);
insert into room_unit_comments values (4377, 113801, 1, 3, 1, 0, 1, 'この格好、子供たちに\\n妙にウケがいいわね\\nま、悪くないけど', 0);
insert into room_unit_comments values (4378, 113801, 1, 4, 1, 0, 1, 'や、やっぱりみんな\\n注目してくるわね…\\nエンジェルって珍しい\\nからしかたないか', 0);
insert into room_unit_comments values (4379, 113801, 1, 5, 1, 0, 1, 'エンジェルになると\\n人見知りがなおる！\\n…わけないか', 0);
insert into room_unit_comments values (4380, 113801, 1, 101, 4, 0, 1, 'エンジェルの活動は\\n大変だけど、自分が\\n成長してるって\\n実感がうれしいわね', 0);
insert into room_unit_comments values (4381, 113801, 1, 102, 8, 0, 1, 'もし誰かの願いを\\nかなえられるなら\\n私はアイツの…\\nって何考えてるのよ！', 0);
insert into room_unit_comments values (4382, 113801, 2, 1, 1, 0, 1, '何ボサっとしてるの！\\nさあ、街に出て\\n人助けするわよ！', 0);
insert into room_unit_comments values (4383, 113801, 2, 2, 1, 0, 1, 'エンジェリック\\nアロー！\\nなんてね…え、アンタ\\nいつから見てたのよ！', 0);
insert into room_unit_comments values (4384, 113801, 2, 3, 1, 0, 1, 'コラ！\\n羽は触らないで！\\n壊れたらどうするのよ', 0);
insert into room_unit_comments values (4385, 113801, 2, 4, 1, 0, 1, 'エンジェルじゃなく\\nても、アンタはいつも\\n人助けしてるわよね\\n…ちょっと尊敬するわ', 0);
insert into room_unit_comments values (4386, 113801, 2, 101, 4, 0, 1, 'この服なら他の子より\\n私を見てくれるかも…\\nって、な、何\\n見てるのよ！', 0);
insert into room_unit_comments values (4387, 113801, 2, 102, 8, 0, 1, 'ね、ねえ、もし私が\\n困ってたら、一番に\\n駆けつけて…やっぱり\\n何でもないわ！', 0);
insert into room_unit_comments values (4388, 113801, 2, 1, 1, 1, 1, 'おはよう…あ、あの、\\nエンジェルとして\\n町に行くんだけど…\\n一緒に行かない？', 0);
insert into room_unit_comments values (4389, 113801, 2, 2, 1, 2, 1, 'ふぅ、いいことした\\n後のランチは\\nおいしいわね', 0);
insert into room_unit_comments values (4390, 113801, 2, 3, 1, 3, 1, 'もうこんな時間…\\n夜更かししてないで\\n早く寝なさいよね', 0);
insert into room_unit_comments values (4392, 113801, 3, 2, 1, 0, 1, 'いい座り心地ね～\\nまさに天にも昇る\\n心地よさだわ～', 0);
insert into room_unit_comments values (4393, 113801, 3, 3, 1, 0, 1, 'ふふ、かわいい…\\nあ、羽付けたら\\nもっとかわいく\\nなるんじゃないかな？', 0);
insert into room_unit_comments values (4394, 113801, 3, 4, 1, 0, 1, 'はぁ～落ち着くわ～\\n回復アイテムみたいで\\n癒やされちゃうわ～', 0);
insert into room_unit_comments values (4395, 113801, 3, 5, 1, 0, 1, 'わっ、とと…\\n危ない、羽が\\nこげちゃうところ\\nだったわ', 0);
insert into room_unit_comments values (4397, 113801, 3, 7, 1, 0, 1, '人の役に立つのって\\nすごく大変だから、\\nこれでライフ回復よ！', 0);
insert into room_unit_comments values (4398, 113801, 3, 8, 1, 0, 1, 'エンジェルに関する\\n本はあるかしら…あ！\\nこれ探してた攻略本！', 0);
insert into room_unit_comments values (4400, 113901, 1, 1, 1, 0, 1, 'ふっふっふ\\n吸血鬼らしく\\n驚かせてあげましょう', 0);
insert into room_unit_comments values (4401, 113901, 1, 2, 1, 0, 1, '獲物はどこですか～！\\nう～ん、もうちょっと\\n迫力が欲しいですね', 0);
insert into room_unit_comments values (4402, 113901, 1, 3, 1, 0, 1, 'トリックオアトリート\\n…返事がないので\\nイタズラしておきます', 0);
insert into room_unit_comments values (4403, 113901, 1, 4, 1, 0, 1, 'ハロウィンですし\\nたまには騎士さんでも\\n誘ってあげますかね', 0);
insert into room_unit_comments values (4404, 113901, 1, 5, 1, 0, 1, 'マントは動きに\\nメリハリがついて\\nいいですね', 0);
insert into room_unit_comments values (4405, 113901, 1, 101, 4, 0, 1, '色んな仮装が見られて\\nやっぱりハロウィンは\\n最高ですね', 0);
insert into room_unit_comments values (4406, 113901, 1, 102, 8, 0, 1, '吸血鬼らしい行動って\\n噛みついたり…いや\\nそれは大胆過ぎです！', 0);
insert into room_unit_comments values (4407, 113901, 2, 1, 1, 0, 1, '呼びましたか？\\n手短にお願いしますよ\\n忙しいんですから！', 0);
insert into room_unit_comments values (4408, 113901, 2, 2, 1, 0, 1, 'え？\u3000衣装に穴が？\\nありがとうございます\\n…よく見てるんですね', 0);
insert into room_unit_comments values (4409, 113901, 2, 3, 1, 0, 1, 'ふわあ…吸血鬼の\\n姿でも、眠い時は\\n眠いんですよね…', 0);
insert into room_unit_comments values (4410, 113901, 2, 4, 1, 0, 1, 'ハロウィンってライブ\\nとは違った賑やかさが\\nあってワクワクします', 0);
insert into room_unit_comments values (4411, 113901, 2, 101, 4, 0, 1, '私を驚かそうとしても\\n無駄ですよ！\\nすぐ分かるんですから', 0);
insert into room_unit_comments values (4412, 113901, 2, 102, 8, 0, 1, '騎士さん、一緒に\\nハロウィンを…いいえ\\nなんでもないですっ！', 0);
insert into room_unit_comments values (4413, 113901, 2, 1, 1, 1, 1, '仕事で寝不足だから\\n太陽がまぶしいです…\\n私、吸血鬼っぽいかも', 0);
insert into room_unit_comments values (4414, 113901, 2, 2, 1, 2, 1, 'お昼ご飯は真っ赤な…\\nトマト尽くしのお弁当\\nにしてみました', 0);
insert into room_unit_comments values (4415, 113901, 2, 3, 1, 3, 1, '夜はハロウィンが\\n盛り上がる時間…\\n行きますよ騎士さん！', 0);
insert into room_unit_comments values (4417, 113901, 3, 2, 1, 0, 1, 'このフィット感\\nどうにか服作りにも\\n活かせれば…！', 0);
insert into room_unit_comments values (4418, 113901, 3, 3, 1, 0, 1, 'よく出来てますね…！\\nぬいぐるみの服を作る\\nのも楽しそうですね！', 0);
insert into room_unit_comments values (4419, 113901, 3, 4, 1, 0, 1, 'いい感じですね…\\n服に合わせた香りって\\nいうのも、いいかも…', 0);
insert into room_unit_comments values (4420, 113901, 3, 5, 1, 0, 1, 'はぁ、温まりますね…\\nおっと、マントに火が\\n点いちゃいそうです！', 0);
insert into room_unit_comments values (4422, 113901, 3, 7, 1, 0, 1, 'あぁ、美味しい～\\n食べた分は、働いて\\n燃焼しますからね！', 0);
insert into room_unit_comments values (4423, 113901, 3, 8, 1, 0, 1, '伝説の吸血鬼…\\n夜を統べる者…\\nほうほう…', 0);
insert into room_unit_comments values (4425, 113901, 3, 12, 1, 0, 1, 'やっぱりハロウィンと\\nいえばお菓子です！\\nさぁ配りましょうか！', 0);
insert into room_unit_comments values (4427, 114101, 1, 1, 1, 0, 1, 'この格好…\\nカッコイイのに\\n動きやすくて\\n着心地も最高ッス！', 0);
insert into room_unit_comments values (4428, 114101, 1, 2, 1, 0, 1, 'キメポーズはこう…\\nいやこっちのほうが…\\nなやましいッス…！', 0);
insert into room_unit_comments values (4429, 114101, 1, 3, 1, 0, 1, 'トリックオア\\nジャスティス！\\nって言ったら何か\\nもらえるッスかね？', 0);
insert into room_unit_comments values (4430, 114101, 1, 4, 1, 0, 1, '新しい必殺技の\\n特訓もしなくちゃ\\nいけないッスね…\\n忙しいッス！', 0);
insert into room_unit_comments values (4431, 114101, 1, 5, 1, 0, 1, '自分のこの姿\\nトモね～ちゃんにも\\nみせてあげるッス！', 0);
insert into room_unit_comments values (4432, 114101, 1, 101, 4, 0, 1, 'ホワイトタイガー\\n参上ッス！\\n今のポーズは\\nキマったッス！', 0);
insert into room_unit_comments values (4433, 114101, 1, 102, 8, 0, 1, 'あの人と一緒だと\\nほんとにヒーローに\\nなれる気がするッス！', 0);
insert into room_unit_comments values (4434, 114101, 2, 1, 1, 0, 1, 'どうッスか？\\nこの色、自分に\\n似合ってるッスかね？', 0);
insert into room_unit_comments values (4435, 114101, 2, 2, 1, 0, 1, 'ヒマだったら\\n必殺技の特訓に\\n付き合ってもらって\\nいいッスか？', 0);
insert into room_unit_comments values (4436, 114101, 2, 3, 1, 0, 1, 'ちょうどいいところに\\n来たッスね！\\nこのキメポーズ\\nどうッスか？', 0);
insert into room_unit_comments values (4437, 114101, 2, 4, 1, 0, 1, 'お！\u3000この格好、\\n気になるッスか？\\nじっくり見ても\\nいいッスよ♪', 0);
insert into room_unit_comments values (4438, 114101, 2, 101, 4, 0, 1, 'あんたも一緒に\\n新しい技の練習\\nどうッスか？', 0);
insert into room_unit_comments values (4439, 114101, 2, 102, 8, 0, 1, '今日もあんたと一緒に\\nランドソルの平和を\\n守るッスよ！', 0);
insert into room_unit_comments values (4440, 114101, 2, 1, 1, 1, 1, '朝ッス！\\n一緒に早朝特訓\\nやるッスよ！', 0);
insert into room_unit_comments values (4441, 114101, 2, 2, 1, 2, 1, 'お昼休憩ッス！\\nヒーローにも\\n休息は必要ッス！', 0);
insert into room_unit_comments values (4442, 114101, 2, 3, 1, 3, 1, '闇夜に映える\\n白い衣装で\\n平和を守るッスよ！', 0);
insert into room_unit_comments values (4444, 114101, 3, 2, 1, 0, 1, 'トラも狩りの時以外は\\nごろごろしてるって\\n本で読んだッスよー', 0);
insert into room_unit_comments values (4445, 114101, 3, 3, 1, 0, 1, 'もこもこッスね♪\\nこのかわいらしさを\\n守ってあげるのも\\nヒーローの役目ッス！', 0);
insert into room_unit_comments values (4446, 114101, 3, 4, 1, 0, 1, 'いい匂いッスね…\\nリラックスして\\n瞑想するッス！', 0);
insert into room_unit_comments values (4447, 114101, 3, 5, 1, 0, 1, '燃える炎は\\nヒーローの心意気ッス\\nいつまでも\\n見てられるッスよ', 0);
insert into room_unit_comments values (4449, 114101, 3, 7, 1, 0, 1, 'もぐもぐ…\\nいっぱい食べて\\n強いヒーローに\\nなるッスよ！', 0);
insert into room_unit_comments values (4450, 114101, 3, 8, 1, 0, 1, 'ちゃんと勉強の本も\\n読んでるッスよ…！\\nヒーローには賢さも\\n必要らしいッス！', 0);
insert into room_unit_comments values (4452, 114101, 3, 12, 1, 0, 1, 'わわっ、お菓子が\\nいっぱいッス！\\nみんなで\\n食べるッスよ！', 0);
insert into room_unit_comments values (4454, 103001, 1, 103, 12, 0, 1, 'ワタシがチューシンと\\nなった今、天下統一は\\n目の前デス！', 0);
insert into room_unit_comments values (4455, 103001, 2, 103, 12, 0, 1, 'もうショーグンってば\\nそれはセイシツに\\nすることデ～ス…', 0);
insert into room_unit_comments values (4456, 114001, 1, 1, 1, 0, 1, '女幽霊…うらめしや…\\nうーん、これは\\nちょっと違う気が\\nするな…', 0);
insert into room_unit_comments values (4457, 114001, 1, 2, 1, 0, 1, '何だか寒気がする…\\nま、まさか\\nこの部屋にも幽霊が？', 0);
insert into room_unit_comments values (4458, 114001, 1, 3, 1, 0, 1, 'ハロウィンは楽しいね\\n童心に帰ったような\\n気分だよ', 0);
insert into room_unit_comments values (4459, 114001, 1, 4, 1, 0, 1, '今度のハロウィンは\\nユイとヒヨリを\\n誘ってみようかな', 0);
insert into room_unit_comments values (4460, 114001, 1, 5, 1, 0, 1, 'ハロウィンのお菓子は\\nどれもかわいいね\\n…一つくらいなら\\nいいかな？', 0);
insert into room_unit_comments values (4461, 114001, 1, 101, 4, 0, 1, '次は彼と\\nどんなハロウィンを\\n過ごそうかな…', 0);
insert into room_unit_comments values (4462, 114001, 1, 102, 8, 0, 1, 'こんな賑やかさも\\nいいものだね\\n彼といられるのなら\\nなおさら…', 0);
insert into room_unit_comments values (4463, 114001, 2, 1, 1, 0, 1, '…いたずらしようと\\nしてない、キミ？\\nふふ、お見通しだよ', 0);
insert into room_unit_comments values (4464, 114001, 2, 2, 1, 0, 1, 'え、私にもお菓子を？\\nありがとう…ふふ\\nうれしいものだね\\nハッピーハロウィン！', 0);
insert into room_unit_comments values (4465, 114001, 2, 3, 1, 0, 1, 'どうしたの？\\n出かけるなら\\n私も同行しようか', 0);
insert into room_unit_comments values (4466, 114001, 2, 4, 1, 0, 1, 'この格好、舞踏会にも\\n出られそうだね\\n一曲、踊ってみる？', 0);
insert into room_unit_comments values (4467, 114001, 2, 101, 4, 0, 1, 'やるからには本気で\\nやらせてもらおう\\nトリックオア\\nトリート！', 0);
insert into room_unit_comments values (4468, 114001, 2, 102, 8, 0, 1, '他の子に目移りする\\nのも分かるが、その…\\nせっかくの特別な衣装\\n見てほしいな', 0);
insert into room_unit_comments values (4469, 114001, 2, 1, 1, 1, 1, '寝起きの体を\\n慣らしておこうか\\nほら、剣を取って', 0);
insert into room_unit_comments values (4470, 114001, 2, 2, 1, 2, 1, 'お菓子もいいけど\\nちゃんと昼食も\\nとるんだよ', 0);
insert into room_unit_comments values (4471, 114001, 2, 3, 1, 3, 1, 'さあ、行こうか！\\nハロウィンは\\nこれからが本番だよ', 0);
insert into room_unit_comments values (4473, 114001, 3, 2, 1, 0, 1, 'ハロウィンはまだ\\nこれからだ\\n一休みしようか', 0);
insert into room_unit_comments values (4474, 114001, 3, 3, 1, 0, 1, 'キミたちも\\n仮装に興味は\\nあるかな？\u3000…ふふ', 0);
insert into room_unit_comments values (4475, 114001, 3, 4, 1, 0, 1, 'いい香りだけど\\n幽霊が集まったり\\nしないだろうか…？', 0);
insert into room_unit_comments values (4476, 114001, 3, 5, 1, 0, 1, '暖かい…一息ついたら\\nハロウィンの\\nパレードを\\n見に行こうかな', 0);
insert into room_unit_comments values (4478, 114001, 3, 7, 1, 0, 1, 'ハロウィンを本気で\\n楽しむなら\\n食事もしっかり\\nとっておかないとね', 0);
insert into room_unit_comments values (4479, 114001, 3, 8, 1, 0, 1, 'ハロウィンの\\nホラー小説か…\\nけ、結構\\n怖いものだね…？', 0);
insert into room_unit_comments values (4481, 114001, 3, 12, 1, 0, 1, 'お菓子がいっぱいだ…\\nこういうのって\\n見ているだけで心が\\n躍ってしまうね', 0);
insert into room_unit_comments values (4483, 114201, 1, 1, 1, 0, 1, 'こんなにかわいい\\n武器で戦えるとは…\\nすごいものだな\\n魔法少女は', 0);
insert into room_unit_comments values (4484, 114201, 1, 2, 1, 0, 1, '決めポーズの訓練も\\nしっかりやっておくか\\n…誰も見ていないな？', 0);
insert into room_unit_comments values (4485, 114201, 1, 3, 1, 0, 1, 'こういう格好は\\nユキあたりがすごく\\n似合いそうだな', 0);
insert into room_unit_comments values (4486, 114201, 1, 4, 1, 0, 1, '子どもたちにサインを\\n求められてしまった…\\nこれもまた私の使命！', 0);
insert into room_unit_comments values (4487, 114201, 1, 5, 1, 0, 1, 'この格好は目立つな…\\nいや、提督とは人々の\\n視線を集めるものだ！', 0);
insert into room_unit_comments values (4488, 114201, 1, 101, 4, 0, 1, 'あいつと作戦会議を\\nしておくか。あれで\\nなかなか頼れるからな', 0);
insert into room_unit_comments values (4489, 114201, 1, 102, 8, 0, 1, 'あいつには私の勇姿を\\nちゃんと見ていて\\nほしいものだな', 0);
insert into room_unit_comments values (4490, 114201, 2, 1, 1, 0, 1, '一仕事終えたことだし\\n一緒に甘いものでも\\n食べに行くか？', 0);
insert into room_unit_comments values (4491, 114201, 2, 2, 1, 0, 1, '怪しげな気配がするな\\n貴公も警戒を\\n怠るなよ！', 0);
insert into room_unit_comments values (4492, 114201, 2, 3, 1, 0, 1, 'シオリに魔法少女の\\n本を借りたんだ\\n一緒に読まないか？', 0);
insert into room_unit_comments values (4493, 114201, 2, 4, 1, 0, 1, '巡回の時間まで\\nお茶にでもするか\\n貴公も付き合うがいい', 0);
insert into room_unit_comments values (4494, 114201, 2, 101, 4, 0, 1, '貴公がサポートして\\nくれるのなら心強いな\\n頼りにしているぞ', 0);
insert into room_unit_comments values (4495, 114201, 2, 102, 8, 0, 1, '頭を撫でるな～！\\n…まったく、貴公だけ\\nだぞ、こんな風に私を\\n撫でてくるのは…', 0);
insert into room_unit_comments values (4496, 114201, 2, 1, 1, 1, 1, '起きろ貴公！\\n魔法少女の朝は\\n早いぞ！', 0);
insert into room_unit_comments values (4497, 114201, 2, 2, 1, 2, 1, 'ほら、食後の\\nデザートだ\\nて、適度な糖分は\\n体に必要なんだ！', 0);
insert into room_unit_comments values (4498, 114201, 2, 3, 1, 3, 1, 'ふわぁ…魔法少女も…\\n眠気、には…い、いや\\n寝てないぞ！？', 0);
insert into room_unit_comments values (4500, 114201, 3, 2, 1, 0, 1, '任務や訓練で\\n疲れた体に\\nこれは効くなぁ…', 0);
insert into room_unit_comments values (4501, 114201, 3, 3, 1, 0, 1, 'うむ、かわいいな\\nモーラのやつを隣に\\n並べようか', 0);
insert into room_unit_comments values (4502, 114201, 3, 4, 1, 0, 1, 'ああ、身も心も\\n安らぐ…\\nまるで魔法だな…', 0);
insert into room_unit_comments values (4503, 114201, 3, 5, 1, 0, 1, 'この温かさ…\\n愛と希望に\\n通じるものがある…', 0);
insert into room_unit_comments values (4505, 114201, 3, 7, 1, 0, 1, '食事の大切さは\\n魔法少女も軍人も\\n変わりない\\nしっかり食べるんだ！', 0);
insert into room_unit_comments values (4506, 114201, 3, 8, 1, 0, 1, '魔法少女の本を\\n読んでるのだが\\nわ、私もこんななのか', 0);
insert into room_unit_comments values (4508, 103301, 1, 103, 12, 0, 1, 'オラとあんちゃんは\\nボケもツッコミも\\nあうんの呼吸だべ♪', 0);
insert into room_unit_comments values (4509, 103301, 2, 103, 12, 0, 1, 'あんちゃんと二人で\\nネタ合わせ…初めての\\n共同作業だべ♪', 0);
insert into room_unit_comments values (4510, 192501, 1, 1, 1, 0, 1, 'ぴっぷる！', 0);
insert into room_unit_comments values (4511, 192501, 1, 2, 1, 0, 1, 'ぴっぷるぴっぷる♪', 0);
insert into room_unit_comments values (4512, 192501, 1, 3, 1, 0, 1, 'ぴっ！', 0);
insert into room_unit_comments values (4513, 192501, 1, 4, 1, 0, 1, 'ぷっぷー', 0);
insert into room_unit_comments values (4514, 192501, 1, 5, 1, 0, 1, 'ぴぃ？', 0);
insert into room_unit_comments values (4515, 192501, 2, 1, 1, 0, 1, 'ぴっぷるんるん♪', 0);
insert into room_unit_comments values (4516, 192501, 2, 2, 1, 0, 1, 'ぷぅ！', 0);
insert into room_unit_comments values (4517, 192501, 2, 3, 1, 0, 1, 'ぴぴっ♪', 0);
insert into room_unit_comments values (4518, 192501, 2, 4, 1, 0, 1, 'ぷぅー…', 0);
insert into room_unit_comments values (4519, 192501, 2, 1, 1, 1, 1, 'ちゅ！', 0);
insert into room_unit_comments values (4520, 192501, 2, 2, 1, 2, 1, 'ぷはー', 0);
insert into room_unit_comments values (4521, 192501, 2, 3, 1, 3, 1, 'ぴぇー', 0);
insert into room_unit_comments values (4531, 114301, 1, 1, 1, 0, 1, '魔法少女になったら\\n髪型も変わるんだね\\n色々試してみようかな', 0);
insert into room_unit_comments values (4532, 114301, 1, 2, 1, 0, 1, '…煌く剣技で、\\n悪を断つ！\\nうん、今日も\\n完璧なポーズだね♪', 0);
insert into room_unit_comments values (4533, 114301, 1, 3, 1, 0, 1, 'ミクマ流剣術で、\\n魔法少女の技に使え\\nそうなものは…よし、\\n早速試してみよっと♪', 0);
insert into room_unit_comments values (4534, 114301, 1, 4, 1, 0, 1, '魔法少女になったから\\nには、サインの練習も\\nしないと…\\nよし、頑張るぞ！', 0);
insert into room_unit_comments values (4535, 114301, 1, 5, 1, 0, 1, '魔法少女の姿はすごく\\nかわいいけど…この\\n姿はジュンさんたちに\\n見せられないなぁ…', 0);
insert into room_unit_comments values (4536, 114301, 1, 101, 4, 0, 1, 'あの人は魔法少女\\nのこと好きなのかな？\\n…好きだったら\\nうれしいな♪', 0);
insert into room_unit_comments values (4537, 114301, 1, 102, 8, 0, 1, '…やっぱり、\\nあの人がいないと\\n特訓に身が入らない…\\n早く帰ってこないかな', 0);
insert into room_unit_comments values (4538, 114301, 2, 1, 1, 0, 1, 'もし時間があるなら、\\n私と街の見回りに\\n行かない？', 0);
insert into room_unit_comments values (4539, 114301, 2, 2, 1, 0, 1, 'あ、いいところに！\\n新しい魔法剣術を\\n編み出したから、\\n見てくれないかな？', 0);
insert into room_unit_comments values (4540, 114301, 2, 3, 1, 0, 1, '魔法少女の姿が気に\\nなるのは分かるけど…\\nず、ずっと見られる\\nのは照れるからやめて', 0);
insert into room_unit_comments values (4541, 114301, 2, 4, 1, 0, 1, '変身ポーズ中の動き、\\n少し変えた方が\\nいいかな…\\nあなたはどう思う？', 0);
insert into room_unit_comments values (4542, 114301, 2, 101, 4, 0, 1, 'よければ、\\n魔法少女の特訓に\\n付き合ってくれない？\\nその…二人きりでさ…', 0);
insert into room_unit_comments values (4543, 114301, 2, 102, 8, 0, 1, '私…あなただけの\\n魔法少女になっても…\\nふふっ、な～んてね♪', 0);
insert into room_unit_comments values (4544, 114301, 2, 1, 1, 1, 1, '今日もいい朝だね\\nさあ、一緒に\\n街の見回りに行こうか', 0);
insert into room_unit_comments values (4545, 114301, 2, 2, 1, 2, 1, 'もう昼か…なにか\\n食べたいものある？\\n簡単なのでいいなら、\\n私が作ってあげるよ', 0);
insert into room_unit_comments values (4546, 114301, 2, 3, 1, 3, 1, 'そろそろ休もうか\\n…なんなら、添い寝\\nしてあげようか？\\nふふっ、冗談だよ♪', 0);
insert into room_unit_comments values (4548, 114301, 3, 2, 1, 0, 1, 'これは…\\n心身ともに安らぐね\\nなんだか\\n眠くなっちゃいそう', 0);
insert into room_unit_comments values (4549, 114301, 3, 3, 1, 0, 1, 'か、かわいい…これ、\\n魔法で動かせたり\\nしないかな？', 0);
insert into room_unit_comments values (4550, 114301, 3, 4, 1, 0, 1, 'いい香りだね\\nなんだか頭が冴えて\\nきたし、新しい技でも\\n考えようかな', 0);
insert into room_unit_comments values (4551, 114301, 3, 5, 1, 0, 1, 'あったかいな…\\nこの温もりは、\\n魔法少女の魔法でも\\n再現不可能だね…', 0);
insert into room_unit_comments values (4553, 114301, 3, 7, 1, 0, 1, 'こ、これは…\\nおいしすぎて手が\\n止まらないかも', 0);
insert into room_unit_comments values (4554, 114301, 3, 8, 1, 0, 1, 'この本の\\nキャラの動き、\\n変身ポーズの\\n参考にできるかも！', 0);
insert into room_unit_comments values (4556, 114401, 1, 1, 1, 0, 1, 'メリークリスマス！\\nさあ、素敵な\\nパーティーを始めると\\nいたしましょう！', 0);
insert into room_unit_comments values (4557, 114401, 1, 2, 1, 0, 1, 'ふふっ、\\nいくつになっても、\\nやはりクリスマスは、\\nワクワクしますわね♪', 0);
insert into room_unit_comments values (4558, 114401, 1, 3, 1, 0, 1, '自分で料理をしてみて\\nシェフたちのすごさが\\n改めて分かりましたわ', 0);
insert into room_unit_comments values (4559, 114401, 1, 4, 1, 0, 1, '何事も自分で\\n体験してみると\\n新しい発見が\\nあるものですわね♪', 0);
insert into room_unit_comments values (4560, 114401, 1, 5, 1, 0, 1, 'やはり、クリスマスは\\n街が活発になり\\nますわね…これは、\\n絶好の商機ですわ♪', 0);
insert into room_unit_comments values (4561, 114401, 1, 101, 4, 0, 1, '他のクリスマス料理も\\n作れるようになったら\\nあのお方は食べて\\nくださるかしら…？', 0);
insert into room_unit_comments values (4562, 114401, 1, 102, 8, 0, 1, 'あのお方に贈る\\nプレゼント…\\nこれはかなりの\\n難題ですわね…', 0);
insert into room_unit_comments values (4563, 114401, 2, 1, 1, 0, 1, 'メリークリスマス！\\nよろしければ、一緒に\\nクリスマスの準備を\\nいたしませんか？', 0);
insert into room_unit_comments values (4564, 114401, 2, 2, 1, 0, 1, 'まあ、クリスマスの\\n飾りつけを手伝って\\nいただけるのですか？\\nありがとうございます', 0);
insert into room_unit_comments values (4565, 114401, 2, 3, 1, 0, 1, 'クリスマスに合わせて\\nあつらえた自慢の衣装\\nなのですが…その、\\nいかがでしょうか？', 0);
insert into room_unit_comments values (4566, 114401, 2, 4, 1, 0, 1, '幼い頃はサンタさんが\\nいらっしゃるのを\\n待ちわびたものです\\n今は…内緒ですわ♪', 0);
insert into room_unit_comments values (4567, 114401, 2, 101, 4, 0, 1, 'も、もしお時間が\\nあるようでしたら、\\nクリスマスの街を\\n一緒に歩きませんか？', 0);
insert into room_unit_comments values (4568, 114401, 2, 102, 8, 0, 1, '来年のクリスマスも\\nあのお方と一緒に\\n迎えられたら…', 0);
insert into room_unit_comments values (4569, 114401, 2, 1, 1, 1, 1, '時は金なり…\\nせっかくの朝ですもの\\n時間を有効活用\\nいたしましょう！', 0);
insert into room_unit_comments values (4570, 114401, 2, 2, 1, 2, 1, 'お昼になりましたわね\\nさあ、\\nパーティーの準備を\\n進めますわよ！', 0);
insert into room_unit_comments values (4571, 114401, 2, 3, 1, 3, 1, '静かな夜ですわね…\\nもうちょっとだけ、\\nあなたさまとお話を\\nしていたい気分です', 0);
insert into room_unit_comments values (4573, 114401, 3, 2, 1, 0, 1, '適度な休息は\\n成功の秘訣ですわ！', 0);
insert into room_unit_comments values (4574, 114401, 3, 3, 1, 0, 1, 'このかわいらしさ…\\nいつまでも見て\\nいられそうですわ♪', 0);
insert into room_unit_comments values (4575, 114401, 3, 4, 1, 0, 1, '人をもてなすには\\nこうしたところにも\\n気を配らないと\\nいけませんわね', 0);
insert into room_unit_comments values (4576, 114401, 3, 5, 1, 0, 1, '暖かい…\\nこういう憩いの\\nひと時こそ、大事に\\nしたいものですわね', 0);
insert into room_unit_comments values (4578, 114401, 3, 7, 1, 0, 1, 'この奥深い味わい…\\n何か隠し味など\\n使われていまして？', 0);
insert into room_unit_comments values (4579, 114401, 3, 8, 1, 0, 1, 'クリスマス料理の\\nレシピも、\\nこれだけあると\\n迷ってしまいますわね', 0);
insert into room_unit_comments values (4581, 114401, 3, 14, 1, 0, 1, 'この絵本、とっても\\n面白いつくりですわね\\nうちの商品に\\nしたいぐらいですわ', 0);
insert into room_unit_comments values (4582, 114401, 3, 15, 1, 0, 1, 'これだけ大きな\\n着ぐるみ…\\n職人の技術が\\n光りますわね', 0);
insert into room_unit_comments values (4583, 114601, 1, 1, 1, 0, 1, 'クリスマスといえば\\nパーティーよね！\\nいっぱい飲むわよ～♪', 0);
insert into room_unit_comments values (4584, 114601, 1, 2, 1, 0, 1, '私を麦しゅわだけの\\n女と思ったら\\n大間違いなんだから♪', 0);
insert into room_unit_comments values (4585, 114601, 1, 3, 1, 0, 1, 'クリスマスらしい\\n飲み物も結構いいわね\\n私も今度\\n作ってみようかしら', 0);
insert into room_unit_comments values (4586, 114601, 1, 4, 1, 0, 1, '暖かい部屋で飲む\\n麦しゅわも\\nまた格別なのよね…', 0);
insert into room_unit_comments values (4587, 114601, 1, 5, 1, 0, 1, '今日はオフの日だし\\n朝から飲んでも\\n怒られないわよね？', 0);
insert into room_unit_comments values (4588, 114601, 1, 101, 4, 0, 1, 'クリスマスの\\nデートスポットで\\n彼と一緒に…ってなに\\n考えてるのユカリ！？', 0);
insert into room_unit_comments values (4589, 114601, 1, 102, 8, 0, 1, '背伸びしなくても\\nありのままの自分を\\n受け入れてくれるって\\nすごく…幸せ…', 0);
insert into room_unit_comments values (4590, 114601, 2, 1, 1, 0, 1, '大丈夫よ～\\n飲んでない\\n飲んでないひゃら～', 0);
insert into room_unit_comments values (4591, 114601, 2, 2, 1, 0, 1, 'クリスマスは\\n特別だもの\\n特別な一杯を\\n飲まないとね♪', 0);
insert into room_unit_comments values (4592, 114601, 2, 3, 1, 0, 1, 'メリークリスマース！\\nほらほらぁ\\n乾杯しましょ♪', 0);
insert into room_unit_comments values (4593, 114601, 2, 4, 1, 0, 1, 'お姉さんの\\n頼れるところ\\n見せてあげるわね', 0);
insert into room_unit_comments values (4594, 114601, 2, 101, 4, 0, 1, '何かあったら\\n頼ってくれても\\nいいんだからね？', 0);
insert into room_unit_comments values (4595, 114601, 2, 102, 8, 0, 1, 'ふふ…これからも\\nキミのこと…\\n頼りにしちゃうからね', 0);
insert into room_unit_comments values (4596, 114601, 2, 1, 1, 1, 1, 'さわやかな朝ね\\n…二日酔いがないと\\n朝ってこんなに\\n気持ちいいのね', 0);
insert into room_unit_comments values (4597, 114601, 2, 2, 1, 2, 1, '昼間から飲むのって\\nまた格別よね…って\\nガマン、ガマンよ…', 0);
insert into room_unit_comments values (4598, 114601, 2, 3, 1, 3, 1, 'もうこんな時間かあ…\\nあとは寝るだけだし\\nちょっとくらいは…', 0);
insert into room_unit_comments values (4600, 114601, 3, 2, 1, 0, 1, 'ゴロゴロするのって\\n最高ね～\\nあとは麦しゅわが\\nあればなぁ', 0);
insert into room_unit_comments values (4601, 114601, 3, 3, 1, 0, 1, '私だって…\\nかわいいものは\\n好きでいいわよね？', 0);
insert into room_unit_comments values (4602, 114601, 3, 4, 1, 0, 1, 'んっ～…いい香りね\\n日頃の疲れが\\n取れる気がするわ', 0);
insert into room_unit_comments values (4603, 114601, 3, 5, 1, 0, 1, 'ポカポカする～\\n…なんだかのどが\\nかわいてきたわね', 0);
insert into room_unit_comments values (4605, 114601, 3, 7, 1, 0, 1, 'もぐもぐ…労働の\\n後のご飯はやっぱり\\nおいしいわぁ…', 0);
insert into room_unit_comments values (4606, 114601, 3, 8, 1, 0, 1, 'クリスマスデート\\n完全攻略マニュアル？\\n…読んでおかなくちゃ', 0);
insert into room_unit_comments values (4608, 114601, 3, 14, 1, 0, 1, 'あら、絵が飛び出して\\n見えるけど…\\n酔っ払ってるせいじゃ\\nないわよね…？', 0);
insert into room_unit_comments values (4609, 114601, 3, 15, 1, 0, 1, 'いい手触りね～\\nウチにもほしいけど\\n麦しゅわをこぼしたら\\n大変そうだわ…', 0);
insert into room_unit_comments values (4610, 101601, 1, 103, 12, 0, 1, 'ヒデサイの視線\\nずっと独り占め\\nしてたいな～', 0);
insert into room_unit_comments values (4611, 101601, 2, 103, 12, 0, 1, 'ヒデサイといるだけで\\nうち、おに楽しいし！\\nヒデサイもっしょ～？', 0);
insert into room_unit_comments values (4612, 114501, 1, 1, 1, 0, 1, 'メリークリスマス！\\nふふ、口にするだけで\\n何だか楽しくなるわね', 0);
insert into room_unit_comments values (4613, 114501, 1, 2, 1, 0, 1, 'いつもは子どもたちを\\n見守る方だけど\\n今ははしゃいでも\\nいいわよね？', 0);
insert into room_unit_comments values (4614, 114501, 1, 3, 1, 0, 1, 'ツリーや料理\\nそしてプレゼント！\\nいくつになっても\\nやっぱり心躍るわね♪', 0);
insert into room_unit_comments values (4615, 114501, 1, 4, 1, 0, 1, '飾り付けも料理も\\nいいセンスしてるわね\\n救護院のパーティーの\\n参考にさせてもらうわ', 0);
insert into room_unit_comments values (4616, 114501, 1, 5, 1, 0, 1, '焼きそばパンを\\nクリスマスの定番に\\nするにはどうすれば…', 0);
insert into room_unit_comments values (4617, 114501, 1, 101, 4, 0, 1, 'これ、あいつの\\n好きそうな料理だわ\\n取っといて食べさせて\\nあげようかしら♪', 0);
insert into room_unit_comments values (4618, 114501, 1, 102, 8, 0, 1, 'あいつのプレゼント\\nちょっとだけ奮発\\nしたのよね…\\n喜んでくれるかしら', 0);
insert into room_unit_comments values (4619, 114501, 2, 1, 1, 0, 1, 'このドレス\\n似合ってるかしら？\\n今だけは見とれても\\n許してあげるわ♪', 0);
insert into room_unit_comments values (4620, 114501, 2, 2, 1, 0, 1, '見て、このケーキ！\\nおいしそうでしょ\\nたまにはこんな贅沢も\\nいいわよね♪', 0);
insert into room_unit_comments values (4621, 114501, 2, 3, 1, 0, 1, '料理も飲み物も\\nおいしいわね！\\nいっぱい食べて\\n元を取らないと♪', 0);
insert into room_unit_comments values (4622, 114501, 2, 4, 1, 0, 1, '子どもたちと一緒に\\n雪遊び、楽しそうね\\nあんたもどう？', 0);
insert into room_unit_comments values (4623, 114501, 2, 101, 4, 0, 1, 'せっかくの\\nクリスマスなんだもの\\nエスコート\\nよろしくね♪', 0);
insert into room_unit_comments values (4624, 114501, 2, 102, 8, 0, 1, '寒い？\u3000そう…\\nなら、もっとこっち\\n来ていいわよ…？', 0);
insert into room_unit_comments values (4625, 114501, 2, 1, 1, 1, 1, 'ほら、早く起きて？\\nパーティー用の\\n買い出しに\\n付き合ってちょうだい', 0);
insert into room_unit_comments values (4626, 114501, 2, 2, 1, 2, 1, 'パーティーの料理の\\n準備をしながらお昼も\\n作っておいたわ\\n我ながらいい手際ね', 0);
insert into room_unit_comments values (4627, 114501, 2, 3, 1, 3, 1, 'にぎやかなパーティー\\nもいいけど、聖夜の\\n余韻を感じるのも\\n結構素敵ね', 0);
insert into room_unit_comments values (4629, 114501, 3, 2, 1, 0, 1, 'いい座り心地だわ～\\n腕のいい職人の仕事ね\\nうちでも扱いたいわ', 0);
insert into room_unit_comments values (4630, 114501, 3, 3, 1, 0, 1, 'かわいい！\\n子どもたちに\\nプレゼントしたら\\n喜んでくれるかも', 0);
insert into room_unit_comments values (4631, 114501, 3, 4, 1, 0, 1, '華やかな香りね\\nクリスマスに\\nピッタリだわ', 0);
insert into room_unit_comments values (4632, 114501, 3, 5, 1, 0, 1, '寒い日にはやっぱり\\nこれよね…\\nはぁ、極楽極楽♪', 0);
insert into room_unit_comments values (4634, 114501, 3, 7, 1, 0, 1, 'んー、おいしいわ！\\n焼きそばパン味の\\nものも、作れない\\nかしら？', 0);
insert into room_unit_comments values (4635, 114501, 3, 8, 1, 0, 1, 'たまにはのんびり\\n読書でも…なんだか\\nラブロマンスばかりね\\nクリスマスだから？', 0);
insert into room_unit_comments values (4637, 114501, 3, 14, 1, 0, 1, 'これ、面白いわね！\\n子どもたちの\\nプレゼントに\\nピッタリだわ', 0);
insert into room_unit_comments values (4638, 114501, 3, 15, 1, 0, 1, 'こんないい毛並み\\n初めて見るわ…\\n一体どこで手に\\n入るのかしら？', 0);
insert into room_unit_comments values (4639, 114701, 1, 1, 1, 0, 1, 'アタシもみんなと\\n一緒に正月を\\n楽しんでいいのか？', 0);
insert into room_unit_comments values (4640, 114701, 1, 2, 1, 0, 1, '今年こそ、もう少し\\n身長が伸びます\\nように…', 0);
insert into room_unit_comments values (4641, 114701, 1, 3, 1, 0, 1, 'げっ！\u3000お年玉が\\n全然残ってないぞ！？\\nそんな、嘘だろ…？', 0);
insert into room_unit_comments values (4642, 114701, 1, 4, 1, 0, 1, '大勢で過ごす\\n正月か…初めてだけど\\n悪くないもんだな', 0);
insert into room_unit_comments values (4643, 114701, 1, 5, 1, 0, 1, 'んー…ここじゃ\\n天楼覇断剣の\\n出番はなさそうだな', 0);
insert into room_unit_comments values (4644, 114701, 1, 101, 4, 0, 1, 'アイツらと作る\\n戦い以外の思い出も\\nもっと増やしたいな', 0);
insert into room_unit_comments values (4645, 114701, 1, 102, 8, 0, 1, 'こんなに賑やかな\\n正月は初めてだ\\n…温かくて、いいな', 0);
insert into room_unit_comments values (4646, 114701, 2, 1, 1, 0, 1, '記憶がなくったって\\n楽しい思い出は\\n新しく作れるよな？', 0);
insert into room_unit_comments values (4647, 114701, 2, 2, 1, 0, 1, '早くでかけるぞ！\\nアタシはもっと\\n正月を楽しみたい！', 0);
insert into room_unit_comments values (4648, 114701, 2, 3, 1, 0, 1, 'なあ、オマエはもう\\nノウェムって名前\\n覚えてくれたよな？', 0);
insert into room_unit_comments values (4649, 114701, 2, 4, 1, 0, 1, 'この服、アタシに\\n似合ってるのか？\\n…そっか。\\nありがとな！', 0);
insert into room_unit_comments values (4650, 114701, 2, 101, 4, 0, 1, 'オマエらと見た朝日は\\nきっと忘れないぞ！\\n思い出ができたな！', 0);
insert into room_unit_comments values (4651, 114701, 2, 102, 8, 0, 1, 'いつかオクトーも\\n一緒に、みんなで\\n正月を過ごせたらな…', 0);
insert into room_unit_comments values (4652, 114701, 2, 1, 1, 1, 1, '朝から元気だな！\\nアタシもいっちょ\\n見習ってみるか！', 0);
insert into room_unit_comments values (4653, 114701, 2, 2, 1, 2, 1, '昼飯は何にする？\\n正月はうまいものが\\n多くて迷うよな！', 0);
insert into room_unit_comments values (4654, 114701, 2, 3, 1, 3, 1, 'いい夜だな！\\nアタシと一緒に\\n夜更かしを楽しむか？', 0);
insert into room_unit_comments values (4656, 114701, 3, 2, 1, 0, 1, '正月らしく、たまには\\nゆっくりするのも\\nいいかもな…', 0);
insert into room_unit_comments values (4657, 114701, 3, 3, 1, 0, 1, 'なんだ？\\nオマエも初詣に\\n行きたいのか？', 0);
insert into room_unit_comments values (4658, 114701, 3, 4, 1, 0, 1, 'すーはー…\\n神殿のニオイがするな\\nいい事ありそうだ！', 0);
insert into room_unit_comments values (4659, 114701, 3, 5, 1, 0, 1, 'コイツがあれば\\nうまい魚が\\n焼けそうだな…', 0);
insert into room_unit_comments values (4661, 114701, 3, 7, 1, 0, 1, 'ううー\\n食べ過ぎて帯が\\nきつくなってきたぞ…', 0);
insert into room_unit_comments values (4662, 114701, 3, 8, 1, 0, 1, 'おみくじって\\n書いてあることが\\nむずかしいんだよな…', 0);
insert into room_unit_comments values (4664, 180101, 1, 1, 1, 0, 1, '困ってる人は\\nいないみたいだし…\\nちょっとここで、\\n特訓しようかな♪', 0);
insert into room_unit_comments values (4665, 180101, 1, 2, 1, 0, 1, '空が飛べるんだから\\nもっとたくさんの人を\\n助けにいけちゃう！\\n…ここじゃ飛べないや', 0);
insert into room_unit_comments values (4666, 180101, 1, 3, 1, 0, 1, '炎の翼\\nかっこいいなー！\\nこれ、もっと大きく\\nできないのかな？', 0);
insert into room_unit_comments values (4667, 180101, 1, 4, 1, 0, 1, 'やっぱり変身すると\\nお腹すくんだね…\\n…今ならペコさんの\\n食欲の理由が分かるよ', 0);
insert into room_unit_comments values (4668, 180101, 1, 5, 1, 0, 1, '色なんかは違うけど…\\nマントがあるから\\n騎士くんとお揃いに\\nなったみたい♪', 0);
insert into room_unit_comments values (4669, 180101, 1, 101, 4, 0, 1, '…騎士くんがいないと\\nなんか調子でない…\\n早く会いたいよぉ…', 0);
insert into room_unit_comments values (4670, 180101, 1, 102, 8, 0, 1, 'この姿になると、\\n騎士くんを近くに\\n感じる…なんだろ\\nドキドキしちゃう…', 0);
insert into room_unit_comments values (4671, 180101, 2, 1, 1, 0, 1, '騎士くん騎士くん！\\n今大丈夫？\\nトレーニングメニュー\\n考えるの手伝って！', 0);
insert into room_unit_comments values (4672, 180101, 2, 2, 1, 0, 1, '…うにゃっ！？\\nこ、この姿になっても\\n尻尾は触っちゃ\\nダメー！', 0);
insert into room_unit_comments values (4673, 180101, 2, 3, 1, 0, 1, 'もしかして、この服が\\n気になってるの？\\nだったら、もっと\\n近くで見ていいよ♪', 0);
insert into room_unit_comments values (4674, 180101, 2, 4, 1, 0, 1, 'あ、騎士くん！\\n困ってる人がいないか\\n見回りに行くんだけど\\nついてきて欲しいな！', 0);
insert into room_unit_comments values (4675, 180101, 2, 101, 4, 0, 1, '耳に触りたいの？\\nだったら頭もなでて！\\nそしたら、好きなだけ\\n触っていいよ♪', 0);
insert into room_unit_comments values (4676, 180101, 2, 102, 8, 0, 1, '…あたし、強くなって\\n騎士くんを守るよ！\\nだから…これからも\\n一緒にいていい？', 0);
insert into room_unit_comments values (4677, 180101, 2, 1, 1, 1, 1, 'おっはよー！\\nさあさあ騎士くん！\\n今日も一緒に\\nはりきっていこー♪', 0);
insert into room_unit_comments values (4678, 180101, 2, 2, 1, 2, 1, 'お昼、お昼～♪\\n今日のご飯は何かな～\\nあ、騎士くん！\\n早くお昼食べ行こ！', 0);
insert into room_unit_comments values (4679, 180101, 2, 3, 1, 3, 1, '今日もお疲れ様ー！\\n騎士くん、あたしが\\nマッサージしよっか？\\n結構評判なんだよ！', 0);
insert into room_unit_comments values (4681, 180101, 3, 2, 1, 0, 1, 'うにゃぁ…\\nこの気持ちよさ…\\n溶けちゃいそう…\\nにゃぁ…', 0);
insert into room_unit_comments values (4682, 180101, 3, 3, 1, 0, 1, 'か、かわいい～\\nこれ、なでなで\\nしていいんだよね…？\\nよしよし…♪', 0);
insert into room_unit_comments values (4683, 180101, 3, 4, 1, 0, 1, 'とってもいい香り！\\n気分も落ち着くし、\\n特訓の後なんかに\\nいいかもー！', 0);
insert into room_unit_comments values (4684, 180101, 3, 5, 1, 0, 1, 'ぬくぬくだぁ…\\nなんだか、\\nふにゃふにゃに\\nなっちゃうよぉ…', 0);
insert into room_unit_comments values (4686, 180101, 3, 7, 1, 0, 1, 'お、おいひぃ…！\\nこの姿になると\\nお腹すくし、すっごく\\n助かっちゃった！', 0);
insert into room_unit_comments values (4687, 180101, 3, 8, 1, 0, 1, 'この本で勉強して、\\nぶんぶりょーどーの\\n超ウルトラヒヨリに\\nなっちゃうぞー！', 0);
insert into room_unit_comments values (4689, 111801, 1, 1, 1, 0, 1, '今年もみんなで\\nおいしいものを\\nたくさん食べたいです', 0);
insert into room_unit_comments values (4690, 111801, 1, 2, 1, 0, 1, '挑戦は大切ですよね☆\\nというわけで\\nおせちに魔物を…', 0);
insert into room_unit_comments values (4691, 111801, 1, 3, 1, 0, 1, 'おせちは縁起物です！\\n食べれば食べるほど\\n幸せになるはずです！', 0);
insert into room_unit_comments values (4692, 111801, 1, 4, 1, 0, 1, '食べ物がたくさん\\n入った福袋は\\nないんでしょうか…？', 0);
insert into room_unit_comments values (4693, 111801, 1, 5, 1, 0, 1, '初詣で何を\\nお願いしましょう…\\n五穀豊穣？', 0);
insert into room_unit_comments values (4694, 111801, 1, 101, 4, 0, 1, 'ずっとこうして\\n年の始まりを\\n過ごしたいですね', 0);
insert into room_unit_comments values (4695, 111801, 1, 102, 8, 0, 1, 'いつか二人きりで\\n初日の出を\\n見たいです', 0);
insert into room_unit_comments values (4696, 111801, 2, 1, 1, 0, 1, 'お餅おかわりです！\\nいくらでも\\n食べられますよ！', 0);
insert into room_unit_comments values (4697, 111801, 2, 2, 1, 0, 1, 'おせちの食材を\\n取りに行きませんか？\\nいい運動です☆', 0);
insert into room_unit_comments values (4698, 111801, 2, 3, 1, 0, 1, '凧揚げって\\n難しいですね～\\n糸が絡まっちゃいます', 0);
insert into room_unit_comments values (4699, 111801, 2, 4, 1, 0, 1, '一年の計は元旦にあり\\n今年一年分の\\n献立を作りましょう！', 0);
insert into room_unit_comments values (4700, 111801, 2, 101, 4, 0, 1, 'ほらほら！\\nもっと近くで着物を\\n見ていいんですよ☆', 0);
insert into room_unit_comments values (4701, 111801, 2, 102, 8, 0, 1, 'あなたはどんな\\n初夢を見ましたか？\\nわたしは…内緒です☆', 0);
insert into room_unit_comments values (4702, 111801, 2, 1, 1, 1, 1, '年明けの朝は\\n心なしか\\n気持ちいいですね☆', 0);
insert into room_unit_comments values (4703, 111801, 2, 2, 1, 2, 1, 'お雑煮のあとは\\nおしるこで\\nおやつタイムです！', 0);
insert into room_unit_comments values (4704, 111801, 2, 3, 1, 3, 1, 'あたたかくして\\n幸せな初夢を\\n見ましょうね', 0);
insert into room_unit_comments values (4706, 111801, 3, 2, 1, 0, 1, 'はぁ～屋台巡りを\\n満喫しました☆\\n一休み一休み', 0);
insert into room_unit_comments values (4707, 111801, 3, 3, 1, 0, 1, '縁起のいい\\nぬいぐるみを並べて\\n福を呼びましょう！', 0);
insert into room_unit_comments values (4708, 111801, 3, 4, 1, 0, 1, 'おしるこのアロマって\\nないんでしょうか？\\nそれなら作るしか…', 0);
insert into room_unit_comments values (4709, 111801, 3, 5, 1, 0, 1, 'ここでお餅を\\n焼いたらおいしく\\nなりそうですね～♪', 0);
insert into room_unit_comments values (4711, 111801, 3, 7, 1, 0, 1, 'おいしすぎて\\n食べる手が\\n止まりません～', 0);
insert into room_unit_comments values (4712, 111801, 3, 8, 1, 0, 1, '新しいおせち料理の\\nヒントは…なるほど…\\nふむふむ…', 0);
insert into room_unit_comments values (4714, 100601, 1, 103, 12, 0, 1, 'お兄ちゃんとあんな\\n特訓やこんな特訓が\\nしたいなぁ、えへへ♪', 0);
insert into room_unit_comments values (4715, 100601, 2, 103, 12, 0, 1, 'お兄ちゃんに褒めて\\nもらうと、身体が\\nじぃーんと\\n熱くなっちゃいます♪', 0);
insert into room_unit_comments values (4716, 115001, 1, 1, 1, 0, 1, '見目麗しい衣装に\\n身を包むのも\\n悪い気分では\\nありませんね', 0);
insert into room_unit_comments values (4717, 115001, 1, 2, 1, 0, 1, '縁起物で\\n験を担ぐというのも\\nたまにはよいでしょう', 0);
insert into room_unit_comments values (4718, 115001, 1, 3, 1, 0, 1, '非効率なので\\nあまり行いませんが\\n私も手料理くらいは\\n作れるのですよ', 0);
insert into room_unit_comments values (4719, 115001, 1, 4, 1, 0, 1, '研究のためなら\\n時に遠路を超え\\n実地へ赴くことも\\n必要なのです', 0);
insert into room_unit_comments values (4720, 115001, 1, 5, 1, 0, 1, 'トゥンヌスの\\n突然変異…\\n大いに興味を\\nそそられますね', 0);
insert into room_unit_comments values (4721, 115001, 1, 101, 4, 0, 1, '漁師の技法も\\n再現できたことで\\nまた一つ、仮説が\\n実証できました', 0);
insert into room_unit_comments values (4722, 115001, 1, 102, 8, 0, 1, '正月くらいは\\n私ものんびりしたい\\n気持ちなのですよ\\n意外ですか？', 0);
insert into room_unit_comments values (4723, 115001, 2, 1, 1, 0, 1, '模倣に頼らずとも\\n衣装に合わせた\\n所作程度は\\nできて当然です', 0);
insert into room_unit_comments values (4724, 115001, 2, 2, 1, 0, 1, 'お年玉の使い道は\\n思いつきましたか\\nゆっくり考えても\\nいいのですよ', 0);
insert into room_unit_comments values (4725, 115001, 2, 3, 1, 0, 1, 'トランプでも花札でも\\n相手をしましょう\\n手心が必要なら\\nいつでも言いなさい', 0);
insert into room_unit_comments values (4726, 115001, 2, 4, 1, 0, 1, '初詣でお祈りする\\n内容ですか\\n…ヒミツ、として\\nおきましょう', 0);
insert into room_unit_comments values (4727, 115001, 2, 101, 4, 0, 1, '私たちでオーマ中の\\nトゥンヌスを\\n釣り上げましょうか\\n…冗談ですよ', 0);
insert into room_unit_comments values (4728, 115001, 2, 102, 8, 0, 1, '見返りを求めない願い\\nそれは祈りに通じるの\\nかもしれませんね', 0);
insert into room_unit_comments values (4729, 115001, 2, 1, 1, 1, 1, '…貴方がその眠たげな\\n顔を洗ってくる間に、\\n温かいお茶でも\\n淹れておきましょう', 0);
insert into room_unit_comments values (4730, 115001, 2, 2, 1, 2, 1, 'さて、本格的に\\n活動を再開します\\n貴方も同行しなさい\\n昼食は済みましたか？', 0);
insert into room_unit_comments values (4731, 115001, 2, 3, 1, 3, 1, '私はもう少し\\n作業を片付けてから\\n寝ることにします\\n早く眠りなさい', 0);
insert into room_unit_comments values (4733, 115001, 3, 2, 1, 0, 1, '少し休みます…\\n時間が来たら\\n起こすように', 0);
insert into room_unit_comments values (4734, 115001, 3, 3, 1, 0, 1, '贈り物を模倣して\\n潜入…試してみる\\n価値はありそうですね', 0);
insert into room_unit_comments values (4735, 115001, 3, 4, 1, 0, 1, '嗅覚から得られる\\n情報量は侮れません\\n動物の模倣において\\n注意すべき点ですよ', 0);
insert into room_unit_comments values (4736, 115001, 3, 5, 1, 0, 1, '穏やかな炎による\\nリラックス効果は\\n本能によるものかも\\nしれませんね', 0);
insert into room_unit_comments values (4738, 115001, 3, 7, 1, 0, 1, 'いかなる強者でも\\n兵站、補給は\\n必要なものです', 0);
insert into room_unit_comments values (4739, 115001, 3, 8, 1, 0, 1, 'あらゆる学問は\\n完璧な模倣のための\\n大きな礎となります', 0);
insert into room_unit_comments values (4741, 115501, 1, 1, 1, 0, 1, '新たに得たこの力で\\n仲間と目指す未来を\\n切り拓いてみせます', 0);
insert into room_unit_comments values (4742, 115501, 1, 2, 1, 0, 1, 'ここは、みなさまと…\\nわたくしの\\n帰る場所でございます', 0);
insert into room_unit_comments values (4743, 115501, 1, 3, 1, 0, 1, '主さまも精霊の召喚を\\n試してみますか？', 0);
insert into room_unit_comments values (4744, 115501, 1, 4, 1, 0, 1, '主さま、おこづかいは\\n足りていますか？\\n遠慮は無用ですよ', 0);
insert into room_unit_comments values (4745, 115501, 1, 5, 1, 0, 1, 'この装束をまとうと\\n自然と背筋が伸びる\\n思いがいたします', 0);
insert into room_unit_comments values (4746, 115501, 1, 101, 4, 0, 1, '進化した精霊に\\n負けぬよう\\n修行に励みます', 0);
insert into room_unit_comments values (4747, 115501, 1, 102, 8, 0, 1, '仲間たちといられる\\nこの幸せが、末永く\\n続きますように…', 0);
insert into room_unit_comments values (4748, 115501, 2, 1, 1, 0, 1, '主さまのお手手は\\n大きくて温かいですね\\nぎゅっぎゅっ…ふふ♪', 0);
insert into room_unit_comments values (4749, 115501, 2, 2, 1, 0, 1, '今度、主さまにも\\n里に伝わる昔話を\\nお話しいたしましょう', 0);
insert into room_unit_comments values (4750, 115501, 2, 3, 1, 0, 1, '里で採れた果物を\\n持って参りました\\n召し上がってください', 0);
insert into room_unit_comments values (4751, 115501, 2, 4, 1, 0, 1, '里のお土産を\\nここのみなさまに\\nお配りいたしましょう', 0);
insert into room_unit_comments values (4752, 115501, 2, 101, 4, 0, 1, '仲間と囲む食卓…この\\n温もりは、みなさまの\\n心の温かさなのですね', 0);
insert into room_unit_comments values (4753, 115501, 2, 102, 8, 0, 1, '主さまに名前を\\n呼んでいただくと\\n心が温かくなります♪', 0);
insert into room_unit_comments values (4754, 115501, 2, 1, 1, 1, 1, 'ふふっ…主さま\\n寝癖がついて\\nおりますよ？', 0);
insert into room_unit_comments values (4755, 115501, 2, 2, 1, 2, 1, '今日の昼食は\\n里の伝統料理です\\nお口に合うでしょうか', 0);
insert into room_unit_comments values (4756, 115501, 2, 3, 1, 3, 1, '主さまが眠れるよう\\n安らぎの風を…\\nおやすみなさいませ', 0);
insert into room_unit_comments values (4758, 115501, 3, 2, 1, 0, 1, 'この癒し…\\n主さまにも味わって\\nいただきたい…', 0);
insert into room_unit_comments values (4759, 115501, 3, 3, 1, 0, 1, 'この愛らしさ…\\n精霊たちと似たものを\\n感じます…♪', 0);
insert into room_unit_comments values (4760, 115501, 3, 4, 1, 0, 1, '精霊よ…この安らぐ\\n香りを、隅々まで\\n届けてくださいまし', 0);
insert into room_unit_comments values (4761, 115501, 3, 5, 1, 0, 1, '瞑想するのに\\nちょうどよい暖かさで\\nございます', 0);
insert into room_unit_comments values (4763, 115501, 3, 7, 1, 0, 1, '進化した精霊を\\n使役するためにも\\nよく食べて体力を…！', 0);
insert into room_unit_comments values (4764, 115501, 3, 8, 1, 0, 1, '風の精霊について\\nもっと詳しく知って\\nおかなければ…', 0);
insert into room_unit_comments values (4766, 115601, 1, 1, 1, 0, 1, '儀式の時を思い出して\\n精霊に呼びかける…\\n出ておいで～♪', 0);
insert into room_unit_comments values (4767, 115601, 1, 2, 1, 0, 1, 'ひゃうっ！\u3000もう…\\n急に背中を触るなんて\\nいたずら好きな精霊に\\n育てた覚えはないのに', 0);
insert into room_unit_comments values (4768, 115601, 1, 3, 1, 0, 1, '儀式用の衣装…\\nあんまり激しい動きは\\nできないよね…でも\\n戦う時は気にしない！', 0);
insert into room_unit_comments values (4769, 115601, 1, 4, 1, 0, 1, 'そうだ…精霊に\\n騎士クンのそばで\\n見守っていてって\\n頼んでみようかな…', 0);
insert into room_unit_comments values (4770, 115601, 1, 5, 1, 0, 1, 'ふふっ、こうやって、\\n楽しく精霊とお話し\\nしていられる、平穏な\\n日々が続くといいな', 0);
insert into room_unit_comments values (4771, 115601, 1, 101, 4, 0, 1, 'き、きき、騎士クン！\\nわたしと、あの…！\\nうう…練習ですら\\n上手く誘えないよぉ…', 0);
insert into room_unit_comments values (4772, 115601, 1, 102, 8, 0, 1, 'あっ、精霊が…\\nふふ、応援ありがとう\\nわたしの想い…いつか\\n必ず伝えるね', 0);
insert into room_unit_comments values (4773, 115601, 2, 1, 1, 0, 1, '新しく覚えた料理\\n作ってみたんだけど\\n騎士クンも食べない？', 0);
insert into room_unit_comments values (4774, 115601, 2, 2, 1, 0, 1, '騎士クン、\\n疲れてない？\\nわたしと精霊で\\n治療するよ？', 0);
insert into room_unit_comments values (4775, 115601, 2, 3, 1, 0, 1, 'もう、いたずらしない\\n…騎士クン！？\\nご、ごめんなさい！\\n精霊だと思って！', 0);
insert into room_unit_comments values (4776, 115601, 2, 4, 1, 0, 1, '騎士クン！\\n時間が合ったら、\\n精霊と一緒に\\nお話しない？', 0);
insert into room_unit_comments values (4777, 115601, 2, 101, 4, 0, 1, '…こういう服着るの\\n初めてなんだけど…\\nえっ、かわいい…？\\nあ、ありがとう…！', 0);
insert into room_unit_comments values (4778, 115601, 2, 102, 8, 0, 1, '困ったことがあったら\\n相談してね。わたし、\\n騎士クンのためなら…\\n色々できるよ、色々！', 0);
insert into room_unit_comments values (4779, 115601, 2, 1, 1, 1, 1, 'おはよう騎士クン！\\n今からお外で\\n瞑想するんだけど…\\n騎士クンもどうかな？', 0);
insert into room_unit_comments values (4780, 115601, 2, 2, 1, 2, 1, 'お昼の時間だ\\nご飯ならわたしが\\n用意するから\\nゆっくりしてて', 0);
insert into room_unit_comments values (4781, 115601, 2, 3, 1, 3, 1, 'もうこんな時間…\\n騎士クン、はいどうぞ\\n寝る前の温かいミルク\\nぐっすり眠れるよ♪', 0);
insert into room_unit_comments values (4783, 115601, 3, 2, 1, 0, 1, '…うん、落ち着く\\n精霊との魔法で\\nこんな風に誰かを\\n安心させたいな', 0);
insert into room_unit_comments values (4784, 115601, 3, 3, 1, 0, 1, 'かわいい…\\n精霊も気に入ってる…\\nそうだ、同じ物\\n作ってあげようかな？', 0);
insert into room_unit_comments values (4785, 115601, 3, 4, 1, 0, 1, 'いい香り…これ、\\nうちに置いたら、\\nお母さん喜ぶかも！', 0);
insert into room_unit_comments values (4786, 115601, 3, 5, 1, 0, 1, 'あったかい…\\nまるで誰かが\\n抱きしめてくれた\\nみたい…', 0);
insert into room_unit_comments values (4788, 115601, 3, 7, 1, 0, 1, '自然の恵みに\\n感謝して…\\nいただきます♪', 0);
insert into room_unit_comments values (4789, 115601, 3, 8, 1, 0, 1, 'もっと精霊について\\n勉強して、みんなを\\n守れるように\\nなりたいな…', 0);
insert into room_unit_comments values (4791, 102201, 1, 103, 12, 0, 1, 'アイツといると胸が\\nぎゅーっとなる…\\nこれってもしかして…', 0);
insert into room_unit_comments values (4792, 102201, 2, 103, 12, 0, 1, 'アンタとならきっと\\nどんなゲームでも…\\nそ、その、たた、\\n楽しいって思えるわ！', 0);
insert into room_unit_comments values (4793, 106401, 1, 1, 1, 0, 1, '色んな人と話したら\\n記憶探しの手がかりが\\n見つかるかも…？', 0);
insert into room_unit_comments values (4794, 106401, 1, 2, 1, 0, 1, 'アイスクリームでも\\n作ろうかしら？\\nバニラにミントに…', 0);
insert into room_unit_comments values (4795, 106401, 1, 3, 1, 0, 1, 'ネビアに話しかけると\\n逃げられるのよね…\\nもう、襲わないのに…', 0);
insert into room_unit_comments values (4796, 106401, 1, 4, 1, 0, 1, '「コッコロさん」、\\n「コッコロさん」…\\n…間違えないように…', 0);
insert into room_unit_comments values (4797, 106401, 1, 5, 1, 0, 1, '最近少し太ったかも？\\nきっとおいしいもの、\\n食べ過ぎね…', 0);
insert into room_unit_comments values (4798, 106401, 1, 101, 4, 0, 1, 'ここにいると、\\nとても落ち着くわ…\\n自分の家、だものね', 0);
insert into room_unit_comments values (4799, 106401, 1, 102, 8, 0, 1, 'みんなと一緒の時間、\\nずっと記憶に残したい\\n…そう思っているのよ', 0);
insert into room_unit_comments values (4800, 106401, 2, 1, 1, 0, 1, 'ドラゴン族って、\\nそんなに珍しいの？\\nあまり実感ないけど…', 0);
insert into room_unit_comments values (4801, 106401, 2, 2, 1, 0, 1, '料理、練習してるのよ\\n…味見してもらえる？\\n期待はしないでね', 0);
insert into room_unit_comments values (4802, 106401, 2, 3, 1, 0, 1, '頭を叩いたら、\\n記憶が戻ったり\\nしないかしら…？\\nやらなくていいわよ？', 0);
insert into room_unit_comments values (4803, 106401, 2, 4, 1, 0, 1, '赤ちゃんみたいだった\\n時のことは、忘れて…\\nお願いだから…', 0);
insert into room_unit_comments values (4804, 106401, 2, 101, 4, 0, 1, 'ひゃんっ！？\\nし、しっぽを掴むのは\\nダメよ？', 0);
insert into room_unit_comments values (4805, 106401, 2, 102, 8, 0, 1, '記憶が戻っても…\\n私は、あなたたちと\\n一緒にいたいわ', 0);
insert into room_unit_comments values (4806, 106401, 2, 1, 1, 1, 1, 'おはよう。\\n寝ぐせついてるわよ？\\n…ふふっ、これでよし', 0);
insert into room_unit_comments values (4807, 106401, 2, 2, 1, 2, 1, 'そろそろお昼かしら？\\nおいしいごはんを、\\nみんなで一緒に…ね', 0);
insert into room_unit_comments values (4808, 106401, 2, 3, 1, 3, 1, 'もうこんな時間ね。\\nそろそろ休みましょ？\\n…ふわぁ…', 0);
insert into room_unit_comments values (4810, 106401, 3, 2, 1, 0, 1, 'ふかふか、ぎゅう～…\\n…あっ、これはその…\\nストレッチしててっ…', 0);
insert into room_unit_comments values (4811, 106401, 3, 3, 1, 0, 1, 'あまり、興味ないわ。\\nけど…けど…\\n…か、かわいい…', 0);
insert into room_unit_comments values (4812, 106401, 3, 4, 1, 0, 1, 'いい香りね。\\nとっても落ち着くわ…\\n…っくしゅっ', 0);
insert into room_unit_comments values (4813, 106401, 3, 5, 1, 0, 1, '冷やす方が得意だけど\\nあったかいのも、\\nキライじゃないのよ', 0);
insert into room_unit_comments values (4815, 106401, 3, 7, 1, 0, 1, '別に、食いしん坊\\nじゃないのよ？\\nでも、もう一口だけ…', 0);
insert into room_unit_comments values (4816, 106401, 3, 8, 1, 0, 1, 'ん…なるほどね。\\n勉強になるわ…', 0);
insert into room_unit_comments values (4818, 115701, 1, 1, 1, 0, 1, '水着の探偵か…\\nちょっと恥ずかしい\\n気がしてきたよ…', 0);
insert into room_unit_comments values (4819, 115701, 1, 2, 1, 0, 1, '依頼があれば\\n海でも山でも\\n赴くさ！', 0);
insert into room_unit_comments values (4820, 115701, 1, 3, 1, 0, 1, '今のうちに\\n助手くんの秘密を…\\nわ…私はなにをっ！？', 0);
insert into room_unit_comments values (4821, 115701, 1, 4, 1, 0, 1, '休暇も時には必要さ\\n海でゆっくりと…\\nむっ？\u3000事件の気配！', 0);
insert into room_unit_comments values (4822, 115701, 1, 5, 1, 0, 1, '探偵の秘密道具…\\n水着だと隠す\\n場所がない…！', 0);
insert into room_unit_comments values (4823, 115701, 1, 101, 4, 0, 1, 'そろそろ助手くんが\\n現れる時間かな？\\nふふっ、楽しみだね', 0);
insert into room_unit_comments values (4824, 115701, 1, 102, 8, 0, 1, '真実は私と助手くん\\n二人だからこそ\\n解き明かせるのさ', 0);
insert into room_unit_comments values (4825, 115701, 2, 1, 1, 0, 1, 'ひゃああっ！？\\nわ、私の不意を突く\\nとは…やるね助手くん', 0);
insert into room_unit_comments values (4826, 115701, 2, 2, 1, 0, 1, 'さて、なにか気づいた\\nことはあるかな？\\n言ってごらん♪', 0);
insert into room_unit_comments values (4827, 115701, 2, 3, 1, 0, 1, 'この感触…分かった！\\n助手くんだね！\\nふふっ、やっぱり♪', 0);
insert into room_unit_comments values (4828, 115701, 2, 4, 1, 0, 1, '水着…どうかな？\\n探偵らしさは\\n残してるつもりだけど', 0);
insert into room_unit_comments values (4829, 115701, 2, 101, 4, 0, 1, 'ん？\u3000依頼かな？\\n助手くんの頼みなら\\nなんでもお安い御用さ', 0);
insert into room_unit_comments values (4830, 115701, 2, 102, 8, 0, 1, '助手くん、私と海に\\n行かないかな\\n…事件じゃないよ？', 0);
insert into room_unit_comments values (4831, 115701, 2, 1, 1, 1, 1, '珈琲でも淹れて\\n目を覚ますとしよう\\n一緒に飲むかい？', 0);
insert into room_unit_comments values (4832, 115701, 2, 2, 1, 2, 1, '昼食は済ませた？\\nなにを食べたか\\n当ててあげよう！', 0);
insert into room_unit_comments values (4833, 115701, 2, 3, 1, 3, 1, '夜は謎が深まる時間…\\n闇に覆い隠された真実\\n必ず暴いてみせる！', 0);
insert into room_unit_comments values (4835, 115701, 3, 2, 1, 0, 1, 'さて、推理の時間だ\\n…サボってないよ？\\n考えてるんだからね？', 0);
insert into room_unit_comments values (4836, 115701, 3, 3, 1, 0, 1, 'これはもしや、中に\\n秘密のメッセージが？\\n…かわいいだけだね', 0);
insert into room_unit_comments values (4837, 115701, 3, 4, 1, 0, 1, 'ふむ、なんだか\\n頭がスッキリするね\\n…閃いた！', 0);
insert into room_unit_comments values (4838, 115701, 3, 5, 1, 0, 1, 'ポカポカするね…\\n助手くん\\n君もおいでよ', 0);
insert into room_unit_comments values (4840, 115701, 3, 7, 1, 0, 1, 'はむ、はむ…んぐっ\\nた、食べてるところを\\n見つめられると～…', 0);
insert into room_unit_comments values (4841, 115701, 3, 8, 1, 0, 1, '秘密の依頼とか\\nこういう場所に\\n隠したりするよね…♪', 0);
insert into room_unit_comments values (4843, 115701, 3, 10, 1, 0, 1, 'これはいい乗り心地だ\\n事件現場にこれで登場\\n…は、やめておこう', 0);
insert into room_unit_comments values (4844, 115701, 3, 11, 1, 0, 1, '不思議な感触だね…\\nでも、いい発想が\\n生まれてきそうだ…♪', 0);
insert into room_unit_comments values (4845, 180601, 1, 1, 1, 0, 1, 'これはあたしが\\n前へ進むために\\nあいつがくれた\\n大切な力…！', 0);
insert into room_unit_comments values (4846, 180601, 1, 2, 1, 0, 1, 'チェンジ・\\nプリンセスフォーム！\\n練習練習、っと', 0);
insert into room_unit_comments values (4847, 180601, 1, 3, 1, 0, 1, 'もうあいつに助けて\\nもらいっぱなしの\\nあたしは…\\n卒業しなきゃね', 0);
insert into room_unit_comments values (4848, 180601, 1, 4, 1, 0, 1, '気ままに、お気楽に\\nあいつと冒険する…\\nそれって幸せよね', 0);
insert into room_unit_comments values (4849, 180601, 1, 5, 1, 0, 1, 'プリンセスフォーム…\\nお姫様みたいね\\nあたしがお姫様か…\\nそっかぁ…ふふ♪', 0);
insert into room_unit_comments values (4850, 180601, 1, 101, 4, 0, 1, 'あいつと繋がって\\n生まれたこの絆は\\nあたしの宝物だわ', 0);
insert into room_unit_comments values (4851, 180601, 1, 102, 8, 0, 1, 'あたしの命の使い方…\\n全て受け止めてくれた\\nあいつにだったら…', 0);
insert into room_unit_comments values (4852, 180601, 2, 1, 1, 0, 1, 'ふふ～ん♪\\nプリンセスフォームの\\n天才魔法使い\\nキャル様に用かしら？', 0);
insert into room_unit_comments values (4853, 180601, 2, 2, 1, 0, 1, 'これからは\\nあたしの力で\\nなんでもパパっと\\n解決してあげるわね！', 0);
insert into room_unit_comments values (4854, 180601, 2, 3, 1, 0, 1, '魔力がみなぎってる…\\nねえ、もしかして\\n今のあたしって本気で\\nすごいんじゃない？', 0);
insert into room_unit_comments values (4855, 180601, 2, 4, 1, 0, 1, '変身の反動で\\nお腹が空いても\\n魔物料理だけは\\nいやだからね！？', 0);
insert into room_unit_comments values (4856, 180601, 2, 101, 4, 0, 1, 'ねぇ、あんたになら\\nあたしの心…\\n全部預けていいかも', 0);
insert into room_unit_comments values (4857, 180601, 2, 102, 8, 0, 1, 'あいつと一緒に\\nいられたら、他には\\n何も…って、あああ\\nあんたいつの間に！？', 0);
insert into room_unit_comments values (4858, 180601, 2, 1, 1, 1, 1, '早起きも悪くないわね\\n読みかけの魔導書\\n今のうちに\\n読んじゃおうかしら', 0);
insert into room_unit_comments values (4859, 180601, 2, 2, 1, 2, 1, 'ねぇ～お腹すいたー\\nあんたなんか\\n作りなさいよ\\n魔物料理以外でね！', 0);
insert into room_unit_comments values (4860, 180601, 2, 3, 1, 3, 1, 'ふぁぁ…眠すぎて\\n今なら変身しても\\nお腹が減らない\\n自信があるわ…', 0);
insert into room_unit_comments values (4862, 180601, 3, 2, 1, 0, 1, 'あー♪\u3000最っ高！\\n休んで魔力を高めて…\\nあいつの役に\\n立ってあげなきゃね', 0);
insert into room_unit_comments values (4863, 180601, 3, 3, 1, 0, 1, 'なにこれかわいい…！\\nコレクションにしたく\\nなっちゃうじゃない', 0);
insert into room_unit_comments values (4864, 180601, 3, 4, 1, 0, 1, 'この香り…すごく\\nリラックスできるわ…\\nあ、いい感じの魔法\\n思いついちゃったかも', 0);
insert into room_unit_comments values (4865, 180601, 3, 5, 1, 0, 1, 'あったかい…\\n落ち着くわ…\\nあいつの手の\\nぬくもりみたいね', 0);
insert into room_unit_comments values (4867, 180601, 3, 7, 1, 0, 1, 'プリンセスフォーム…\\nこ、こんなに\\nお腹が減るのね\\n甘く見てたわ…！', 0);
insert into room_unit_comments values (4868, 180601, 3, 8, 1, 0, 1, 'ま、魔物料理の本！？\\n誰よこんな本\\n買ったの！\u3000って…\\n一人しかいないか', 0);
insert into room_unit_comments values (4870, 115801, 1, 1, 1, 0, 1, '憧れの舞踏会…\\n私、きちんと\\n踊れるかしら', 0);
insert into room_unit_comments values (4871, 115801, 1, 2, 1, 0, 1, 'アン・ドゥ・トロワ\\nアン・ドゥ・トロワ\\n練習はばっちりね♪', 0);
insert into room_unit_comments values (4872, 115801, 1, 3, 1, 0, 1, 'こんなにすてきな\\nドレスを着られて\\n本当に夢みたいだわ♪', 0);
insert into room_unit_comments values (4873, 115801, 1, 4, 1, 0, 1, '魔法はいつか解ける…\\nでも、その時間は心に\\n残り続けるわ♪', 0);
insert into room_unit_comments values (4874, 115801, 1, 5, 1, 0, 1, 'ガラスの靴は夢へ\\n踏み出す魔法の道具…\\n私、がんばっちゃう！', 0);
insert into room_unit_comments values (4875, 115801, 1, 101, 4, 0, 1, '舞踏会であなたと\\n一緒に踊れたら\\nいいのにな', 0);
insert into room_unit_comments values (4876, 115801, 1, 102, 8, 0, 1, '舞踏会に行く前に\\n運命の王子様には\\n出会ってるのよね', 0);
insert into room_unit_comments values (4877, 115801, 2, 1, 1, 0, 1, 'どうかしら？\\n私、きちんとドレス\\n着られてる？', 0);
insert into room_unit_comments values (4878, 115801, 2, 2, 1, 0, 1, 'あなたも一緒に\\n踊ってみる？\\nしゃなりしゃなり♪', 0);
insert into room_unit_comments values (4879, 115801, 2, 3, 1, 0, 1, 'あなたにエスコート\\nされてきれいなお城を\\n歩いてみたいわ♪', 0);
insert into room_unit_comments values (4880, 115801, 2, 4, 1, 0, 1, 'どう？\u3000レッスンの\\n成果はきちんと\\n出てるかしら？', 0);
insert into room_unit_comments values (4881, 115801, 2, 101, 4, 0, 1, 'あなたが隣にいれば\\n私も立派なお姫様に\\n見えるかしら♪', 0);
insert into room_unit_comments values (4882, 115801, 2, 102, 8, 0, 1, '私にとって\\n一番の魔法はあなたが\\nくれる勇気よ♪', 0);
insert into room_unit_comments values (4883, 115801, 2, 1, 1, 1, 1, 'さぁ！\u3000今日も一日\\n立派な淑女を目指して\\nいきましょう♪', 0);
insert into room_unit_comments values (4884, 115801, 2, 2, 1, 2, 1, 'お昼ごはん代わりに\\nメタモルアップルを\\n食べておきましょう', 0);
insert into room_unit_comments values (4885, 115801, 2, 3, 1, 3, 1, 'そろそろ魔法が解ける\\n時間…でも淑女の\\n心得は忘れないわ♪', 0);
insert into room_unit_comments values (4887, 115801, 3, 2, 1, 0, 1, '淑女にも休息は\\n必要よね…少しだけ\\n休ませてもらおっと', 0);
insert into room_unit_comments values (4888, 115801, 3, 3, 1, 0, 1, 'かわいいものに\\n囲まれた部屋も\\n女の子の夢よね…', 0);
insert into room_unit_comments values (4889, 115801, 3, 4, 1, 0, 1, 'すてきな香り…\\nお花かしら？\\n森で探してみようかな', 0);
insert into room_unit_comments values (4890, 115801, 3, 5, 1, 0, 1, '暖かい…暖炉のそばで\\nおとぎ話を聞くのも\\nいいわよね♪', 0);
insert into room_unit_comments values (4892, 115801, 3, 7, 1, 0, 1, 'レッスンのために\\n栄養補給して\\nおかないと！', 0);
insert into room_unit_comments values (4893, 115801, 3, 8, 1, 0, 1, '教養を身に着ける\\nことも大切よね！\\nなになに…', 0);
insert into room_unit_comments values (4895, 115901, 1, 1, 1, 0, 1, 'や、やっぱスカートは\\n落ち着かねえな…\\nなんか、\\nスースーするしよ…', 0);
insert into room_unit_comments values (4896, 115901, 1, 2, 1, 0, 1, 'せっかくこんな格好\\nしてるし、いつもとは\\n違う剣術の訓練を\\nしてみるかな', 0);
insert into room_unit_comments values (4897, 115901, 1, 3, 1, 0, 1, 'さて、他の連中が\\n帰ってくる前に、\\nなんか料理でも\\n作っといてやるか', 0);
insert into room_unit_comments values (4898, 115901, 1, 4, 1, 0, 1, 'こ、こんな服着てる\\nわけだし、紅茶とか\\n楽しんじゃっても\\n変じゃないよな！', 0);
insert into room_unit_comments values (4899, 115901, 1, 5, 1, 0, 1, '暇だし運動でも…\\nあ、あぶねえ！\\nスカートなの忘れてた\\n…誰も見てねえよな？', 0);
insert into room_unit_comments values (4900, 115901, 1, 101, 4, 0, 1, '紅茶が切れてるな…\\nよし、あいつと一緒に\\n買い物にでも行くか♪', 0);
insert into room_unit_comments values (4901, 115901, 1, 102, 8, 0, 1, '…あいつがいねえと、\\nつまんねえな…ったく\\n飯用意してやるから、\\n早く帰ってこいよな…', 0);
insert into room_unit_comments values (4902, 115901, 2, 1, 1, 0, 1, 'あ、あんまり\\nジロジロ見んなよ\\n…結構、\\n恥ずかしいんだからな', 0);
insert into room_unit_comments values (4903, 115901, 2, 2, 1, 0, 1, 'ダンスの相手は\\n無理だが、\\n剣の訓練なら\\nいつでも付き合うぜ！', 0);
insert into room_unit_comments values (4904, 115901, 2, 3, 1, 0, 1, 'この服に\\n触りたいのか？\\nすごい作りだし、\\n気持ちは分かるぜ', 0);
insert into room_unit_comments values (4905, 115901, 2, 4, 1, 0, 1, 'お、いいところに！\\nクッキーを焼く\\nところだったんだが、\\nおまえも食うか？', 0);
insert into room_unit_comments values (4906, 115901, 2, 101, 4, 0, 1, 'おまえにもこういう服\\n似合うんじゃねえか？\\n今度あたしが\\n選んでやるよ♪', 0);
insert into room_unit_comments values (4907, 115901, 2, 102, 8, 0, 1, '…おまえの前でなら、\\nこういう格好を\\nすんのも…\\nな、なんでもねえよ！', 0);
insert into room_unit_comments values (4908, 115901, 2, 1, 1, 1, 1, '朝の訓練を始めるか\\n時間あるなら、\\nおまえも付き合えよな', 0);
insert into room_unit_comments values (4909, 115901, 2, 2, 1, 2, 1, 'もうこんな時間か…\\n昼飯作るけど、\\nなんか\\n食いたいものあるか？', 0);
insert into room_unit_comments values (4910, 115901, 2, 3, 1, 3, 1, '眠れないなら、\\nホットミルク飲むか？\\n体あったまって、\\n眠くなると思うぜ', 0);
insert into room_unit_comments values (4912, 115901, 3, 2, 1, 0, 1, 'ちょっと休憩して…\\nおっと、服にしわが\\nできないように\\nしねえとな', 0);
insert into room_unit_comments values (4913, 115901, 3, 3, 1, 0, 1, 'だ、誰も\\n見てねえよな？\\n…よ～しよしよし、\\nかわいいなおまえー♪', 0);
insert into room_unit_comments values (4914, 115901, 3, 4, 1, 0, 1, 'すげぇいい香りだな\\nうちの居酒屋にも…\\nいや、合わねえか', 0);
insert into room_unit_comments values (4915, 115901, 3, 5, 1, 0, 1, 'あったけぇ…\\nちょっとだけなら、\\n寝ちまっても\\nいいよな…？', 0);
insert into room_unit_comments values (4917, 115901, 3, 7, 1, 0, 1, 'これうめえな！\\nたぶん材料は…よし！\\nあたしも作ってみるか', 0);
insert into room_unit_comments values (4918, 115901, 3, 8, 1, 0, 1, 'この本は…\\n誰でも分かる作法…か\\n最低限このぐらいは\\n勉強しとくか…', 0);
insert into room_unit_comments values (4920, 102001, 1, 103, 12, 0, 1, 'ミミがおとなに\\nなっても\\nおにいちゃんとは\\nずーっといっしょ♪', 0);
insert into room_unit_comments values (4921, 102001, 2, 103, 12, 0, 1, 'ミミとくべつなだっこ\\nしてほしいな…うん！\\nおひめさまだっこ～♪', 0);
insert into room_unit_comments values (4922, 100401, 1, 103, 12, 0, 1, '次はにいちゃんに\\nどんなイタズラしよう\\n早く会いたいな～', 0);
insert into room_unit_comments values (4923, 100401, 2, 103, 12, 0, 1, 'ミソギの特別な\\nイタズラ見てくれる？\\nいいよねっ♪', 0);
insert into room_unit_comments values (4924, 103601, 1, 103, 12, 0, 1, '大人になったら、\\nあの人と何しようかな\\n…楽しみだなぁ', 0);
insert into room_unit_comments values (4925, 103601, 2, 103, 12, 0, 1, '頭を撫でないで\\nください！\u3000もう、\\n少しだけ、ですからね', 0);
insert into room_unit_comments values (4926, 116001, 1, 1, 1, 0, 1, 'くるくる〜♪\\nうちのドレス\\nかわええなぁ', 0);
insert into room_unit_comments values (4927, 116001, 1, 2, 1, 0, 1, '日差しは苦手やけど\\nたまにはひなたの下で\\nぽかぽかしたいわぁ', 0);
insert into room_unit_comments values (4928, 116001, 1, 3, 1, 0, 1, '外はお花が咲いてる\\n久しぶりにお花を\\n活けたいなぁ', 0);
insert into room_unit_comments values (4929, 116001, 1, 4, 1, 0, 1, 'お花をたくさん集めて\\nギルドハウスに飾れば\\n喜んでくれはるかな', 0);
insert into room_unit_comments values (4930, 116001, 1, 5, 1, 0, 1, 'あたたかい日は\\n紅茶を飲みながら\\nゆっくりしたいなぁ', 0);
insert into room_unit_comments values (4931, 116001, 1, 101, 4, 0, 1, 'お稽古事を始めるなら\\nうちに言ってな\\nどんなことも教えたる', 0);
insert into room_unit_comments values (4932, 116001, 1, 102, 8, 0, 1, 'うちにいろんな夢を\\n見せてくれはって\\nほんま、おおきにな♪', 0);
insert into room_unit_comments values (4933, 116001, 2, 1, 1, 0, 1, '王子はん\\n一緒におとぎの国へ\\nお散歩にいきまひょ♪', 0);
insert into room_unit_comments values (4934, 116001, 2, 2, 1, 0, 1, 'ふんふんふ〜ん♪\\n今な、王子はんに\\n花冠を作ってるんよ', 0);
insert into room_unit_comments values (4935, 116001, 2, 3, 1, 0, 1, '王子はんは\\nお菓子好きどす？\\nうち、作りますわ', 0);
insert into room_unit_comments values (4936, 116001, 2, 4, 1, 0, 1, 'うーん。ドレスの柄は\\nお花とお星さま\\nどっちにしまひょか', 0);
insert into room_unit_comments values (4937, 116001, 2, 101, 4, 0, 1, '王子はんとの\\n思い出が増えるたび\\nうちの宝物も増えます', 0);
insert into room_unit_comments values (4938, 116001, 2, 102, 8, 0, 1, '王子はんと一緒なら\\nどんな場所でも\\n夢の国になりますわ', 0);
insert into room_unit_comments values (4939, 116001, 2, 1, 1, 1, 1, '夢の中におりたいけど\\n王子はんに会いたくて\\n起きてもうたわ♪', 0);
insert into room_unit_comments values (4940, 116001, 2, 2, 1, 2, 1, '王子はん一緒に\\nアフタヌーンティー\\nいかがやろか？', 0);
insert into room_unit_comments values (4941, 116001, 2, 3, 1, 3, 1, '夜の舞踏会…\\n夢が広がるわぁ\\nもちろんお相手は…♪', 0);
insert into room_unit_comments values (4943, 116001, 3, 2, 1, 0, 1, 'ふわふわや〜\\nなんや心地よぉて\\n眠ってしまいそうや…', 0);
insert into room_unit_comments values (4944, 116001, 3, 3, 1, 0, 1, 'かいらしいなぁ\\n新しいお洋服でも\\n作ってあげまひょか♪', 0);
insert into room_unit_comments values (4945, 116001, 3, 4, 1, 0, 1, 'お花やろうか…\\nリラックスできて\\nええ香りやねぇ', 0);
insert into room_unit_comments values (4946, 116001, 3, 5, 1, 0, 1, 'こういう場所で\\n絵本を読むと\\n気分が出てええなぁ♪', 0);
insert into room_unit_comments values (4948, 116001, 3, 7, 1, 0, 1, '舞踏会を楽しむなら\\nたくさん食べて\\nたくさん踊りまひょ', 0);
insert into room_unit_comments values (4949, 116001, 3, 8, 1, 0, 1, 'うち、この本好きや\\n王子さまと結ばれる\\nお姫さまのお話なんよ', 0);
insert into room_unit_comments values (4951, 116301, 1, 1, 1, 0, 1, 'はぁ、宿題めんどい…\\nこれは楽しくない…\\nこんな青春いらない…', 0);
insert into room_unit_comments values (4952, 116301, 1, 2, 1, 0, 1, '奨学金の道は遠いなぁ\\nメルクリちゃんたちが\\nお金くれればいいのに', 0);
insert into room_unit_comments values (4953, 116301, 1, 3, 1, 0, 1, 'アオイちゃん元気かな\\nチエルに会いたくて\\n泣いてるんだろうな…', 0);
insert into room_unit_comments values (4954, 116301, 1, 4, 1, 0, 1, '暇だし鏡でも見るか…\\nうわ、顔良っ！\\nえ誰この超絶美少女！', 0);
insert into room_unit_comments values (4955, 116301, 1, 5, 1, 0, 1, 'ワンツーワンツー♪\\nうーん…カルミナの\\n振りコピ難しいにゃー', 0);
insert into room_unit_comments values (4956, 116301, 1, 101, 4, 0, 1, '先輩も運動してます？\\nチエルが一緒に走って\\nあげてもいいですよ？', 0);
insert into room_unit_comments values (4957, 116301, 1, 102, 8, 0, 1, '来年のテレフェスも\\n今から楽しみだなあ…\\nまた一緒にお化け屋敷\\n入ってくださいね', 0);
insert into room_unit_comments values (4958, 116301, 2, 1, 1, 0, 1, 'ちぇる～ん☆\\nフェス仕様でも\\nかわいいちえるん！', 0);
insert into room_unit_comments values (4959, 116301, 2, 2, 1, 0, 1, 'いま話しかけないで！\\n来年の聖学祭ライブの\\nイメトレ中なんです！', 0);
insert into room_unit_comments values (4960, 116301, 2, 3, 1, 0, 1, 'クロエ先輩のウェア姿\\nめっちゃカッコよ！\\n思わずおへそ触ったら\\nぶたれましたけど', 0);
insert into room_unit_comments values (4961, 116301, 2, 4, 1, 0, 1, 'ユニ先輩の体操着姿…\\nあれはあれで実に良き\\n一生見てられますよね', 0);
insert into room_unit_comments values (4962, 116301, 2, 101, 4, 0, 1, '先輩って体操着持って\\nないんですか？\u3000ハ？\\nチエルのを貸せと…？\\nえっ…変態かな？', 0);
insert into room_unit_comments values (4963, 116301, 2, 102, 8, 0, 1, 'テレフェスでは先輩も\\n地味に頑張ってました\\nね。まあ格好よかった\\nんじゃないですか…', 0);
insert into room_unit_comments values (4964, 116301, 2, 1, 1, 1, 1, 'おはちぇる～ん☆\\nさあ今日も楽しいを\\n探しに行きますよー！', 0);
insert into room_unit_comments values (4965, 116301, 2, 2, 1, 2, 1, '先輩ビッグニュース！\\n今からお昼ごはん\\nおごらせてあげます！', 0);
insert into room_unit_comments values (4966, 116301, 2, 3, 1, 3, 1, 'こんばんちぇるるん☆\\nさあ朝まで楽しいを\\n探しに行きますよー！', 0);
insert into room_unit_comments values (4968, 116301, 3, 2, 1, 0, 1, 'はぁ…ふかふか～…\\n運動の後は…眠たく…\\nなり…ま…', 0);
insert into room_unit_comments values (4969, 116301, 3, 3, 1, 0, 1, 'ユニ先輩に似合いそ！\\nいやクロエ先輩かな？\\nチエルは当然すぎて…', 0);
insert into room_unit_comments values (4970, 116301, 3, 4, 1, 0, 1, 'やん、いい香り～！\\nまるでチエルのために\\n存在するみたい！', 0);
insert into room_unit_comments values (4971, 116301, 3, 5, 1, 0, 1, 'この火を使って\\n聖火リレーしましょう\\n先輩、一本抜いて！', 0);
insert into room_unit_comments values (4973, 116301, 3, 7, 1, 0, 1, 'あむあむ…ちゃんと\\n食べないとユニ先輩\\nみたいになっちゃう！', 0);
insert into room_unit_comments values (4974, 116301, 3, 8, 1, 0, 1, 'ふむふむ…ちゃんと\\n読まないとクロエ先輩\\nみたいになっちゃう！', 0);
insert into room_unit_comments values (4976, 102901, 1, 103, 12, 0, 1, '今なら書ける気がする\\n私の本当の\\n想いを込めた\\nラブソングを！', 0);
insert into room_unit_comments values (4977, 102901, 2, 103, 12, 0, 1, '輝きを増した私を\\nいっぱい見てね！\\n…ちょ、ちょっと\\n見つめすぎだよ！', 0);
insert into room_unit_comments values (4978, 116201, 1, 1, 1, 0, 1, 'テレフェスかぁー…\\nあんまいい記憶ないな\\nよし、忘れとこ', 0);
insert into room_unit_comments values (4979, 116201, 1, 2, 1, 0, 1, '暇だし鏡でも見るか…\\nふふ～ん…いいじゃん\\nあ？\u3000何見てんだコラ', 0);
insert into room_unit_comments values (4980, 116201, 1, 3, 1, 0, 1, 'ワンツー、ワンツー♪\\nああクソ、難しいな…\\nあ？\u3000何見てんだコラ', 0);
insert into room_unit_comments values (4981, 116201, 1, 4, 1, 0, 1, 'アオイ元気してるかな\\nまた絶叫したり白目\\n剥いたりしてんのかな', 0);
insert into room_unit_comments values (4982, 116201, 1, 5, 1, 0, 1, 'ミフユねえさんが\\nバイトリーダーしてる\\n工場…うちも行くか…', 0);
insert into room_unit_comments values (4983, 116201, 1, 101, 4, 0, 1, 'うーん…今日の晩御飯\\n何にすっかなァ…\\nあんたも食べてく？', 0);
insert into room_unit_comments values (4984, 116201, 1, 102, 8, 0, 1, '来年のテレフェスは\\nどーなンだかねえ？\\nま、一緒にまた弟の\\n相手してやってよ', 0);
insert into room_unit_comments values (4985, 116201, 2, 1, 1, 0, 1, '体操着なんてフツーに\\n着てもつまんないし？\\nその辺センス出るよね', 0);
insert into room_unit_comments values (4986, 116201, 2, 2, 1, 0, 1, '奨学金の道、遠くね？\\nアキノ先輩と仲良く\\nなった方が早いかも…', 0);
insert into room_unit_comments values (4987, 116201, 2, 3, 1, 0, 1, 'あんた体操着は持って\\nないの。ハ？\u3000うちの\\n貸せって？\u3000いいけど\\n…いや、よくねえよ', 0);
insert into room_unit_comments values (4988, 116201, 2, 4, 1, 0, 1, 'にゃんっ！\\nや、だからさ…急に\\n話しかけんなっての', 0);
insert into room_unit_comments values (4989, 116201, 2, 101, 4, 0, 1, 'え、なに？\u3000この服？\\nハ？\u3000似合ってる？\\n…え、聞こえなかった\\nちょ、もっかい言って', 0);
insert into room_unit_comments values (4990, 116201, 2, 102, 8, 0, 1, 'あんたもテレフェスで\\n一応は頑張ってたよね\\nま格好よかったんじゃ\\nないの。知んないけど', 0);
insert into room_unit_comments values (4991, 116201, 2, 1, 1, 1, 1, 'ふぁ～あ…おはーす\\n昨日も寝たの遅くて\\nまだ目がショボだよ…', 0);
insert into room_unit_comments values (4992, 116201, 2, 2, 1, 2, 1, 'なに。あんた昼御飯\\nまだなの。じゃ、うち\\n適当になんか作ろうか', 0);
insert into room_unit_comments values (4993, 116201, 2, 3, 1, 3, 1, '夜っていいよね。色々\\n見えすぎない感じとか\\n…この話したっけ？', 0);
insert into room_unit_comments values (4995, 116201, 3, 2, 1, 0, 1, 'あ、ヤバ…運動の後に\\nこのフカついたのは…\\n秒でスヤれる…すやぁ', 0);
insert into room_unit_comments values (4996, 116201, 3, 3, 1, 0, 1, 'へーこんなんチエルに\\n似合いそうじゃん。\\n…いやユニ先輩かな？', 0);
insert into room_unit_comments values (4997, 116201, 3, 4, 1, 0, 1, 'お、なんか良さげな\\n香りじゃん。これは\\n何の…いや分かんね', 0);
insert into room_unit_comments values (4998, 116201, 3, 5, 1, 0, 1, '熱ッ！\u3000この野郎なに\\n爆ぜてンだコラァ！\\n濡らすぞ木、てめえ！', 0);
insert into room_unit_comments values (5000, 116201, 3, 7, 1, 0, 1, '何コレよく分かんない\\nけど、今日モヤシしか\\n食ってないから助かる', 0);
insert into room_unit_comments values (5001, 116201, 3, 8, 1, 0, 1, '今日、体操着だしね。\\n読書には逆アドかな。\\nうん帰ろ。いやあ残念', 0);
insert into room_unit_comments values (5003, 116501, 1, 1, 1, 0, 1, 'ビッグボス・イノリ様\\nふっふっふ…\\nしびれる響きです！', 0);
insert into room_unit_comments values (5004, 116501, 1, 2, 1, 0, 1, 'いつかお兄さんを\\nあたしの側近に\\nしてやるですよ！', 0);
insert into room_unit_comments values (5005, 116501, 1, 3, 1, 0, 1, 'ビッグボスになったら\\nみんなからたくさん\\nお菓子をもらうです！', 0);
insert into room_unit_comments values (5006, 116501, 1, 4, 1, 0, 1, 'ふふん！\\nこの服はあたしにしか\\n着こなせませんよ！', 0);
insert into room_unit_comments values (5007, 116501, 1, 5, 1, 0, 1, 'ばーんと立って\\nどーんと腕を組む！\\nこれがボスのポーズ！', 0);
insert into room_unit_comments values (5008, 116501, 1, 101, 4, 0, 1, 'イノリ様の側近に\\n選ばれるなんて\\n名誉なことですよ！', 0);
insert into room_unit_comments values (5009, 116501, 1, 102, 8, 0, 1, '未来の側近として\\nあたしをしっかり\\n甘やかすですよ！', 0);
insert into room_unit_comments values (5010, 116501, 2, 1, 1, 0, 1, 'あたしがお兄さんを\\n立派なギャングに\\nしてあげますからね！', 0);
insert into room_unit_comments values (5011, 116501, 2, 2, 1, 0, 1, '側近たるもの\\nボスを甘やかなさいと\\nだめですよ！', 0);
insert into room_unit_comments values (5012, 116501, 2, 3, 1, 0, 1, 'なに見てやがるです…\\nくぅ、分かりました！\\nお菓子は半分こです！', 0);
insert into room_unit_comments values (5013, 116501, 2, 4, 1, 0, 1, 'お兄さんも\\nあたしがボスなら\\nうれしいですよね！', 0);
insert into room_unit_comments values (5014, 116501, 2, 101, 4, 0, 1, 'お兄さんが側近なら\\nあたしも安心して\\n夜眠れるですよ！', 0);
insert into room_unit_comments values (5015, 116501, 2, 102, 8, 0, 1, 'ビッグボスになったら\\nお兄さんにいい思い\\nさせてあげますから！', 0);
insert into room_unit_comments values (5016, 116501, 2, 1, 1, 1, 1, 'ボスたるもの\\n早起きは鉄則ですよ！\\nふぁあ…', 0);
insert into room_unit_comments values (5017, 116501, 2, 2, 1, 2, 1, 'お腹が空きました…\\nご飯食べにいきますよ', 0);
insert into room_unit_comments values (5018, 116501, 2, 3, 1, 3, 1, 'ボスたるものぉ〜…\\n夜更かしぐらい当然…\\nぐー…', 0);
insert into room_unit_comments values (5020, 116501, 3, 2, 1, 0, 1, 'は〜これは人をだめに\\nしやがるやつですね\\nあたし専用です', 0);
insert into room_unit_comments values (5021, 116501, 3, 3, 1, 0, 1, 'これはけしからん\\nかわいらしさですね\\nあたしにぴったりです', 0);
insert into room_unit_comments values (5022, 116501, 3, 4, 1, 0, 1, '高級な香りがするです\\nボスになったら\\n部屋に置いてやるです', 0);
insert into room_unit_comments values (5023, 116501, 3, 5, 1, 0, 1, 'あったかいですねぇ\\nちょっとこのまま\\n一休憩です…', 0);
insert into room_unit_comments values (5025, 116501, 3, 7, 1, 0, 1, 'はむはむ♪\\nボスたるもの食べねば\\n戦はできませんよ！', 0);
insert into room_unit_comments values (5026, 116501, 3, 8, 1, 0, 1, 'ボスなら経済書ぐらい\\n…う。難しくて\\n読めねーです…', 0);
insert into room_unit_comments values (5028, 102501, 1, 103, 12, 0, 1, 'あなたはドジな私を\\n受け入れてくれる…\\nだから、頑張れます！', 0);
insert into room_unit_comments values (5029, 102501, 2, 103, 12, 0, 1, '何でも仰ってください\\nちょっぴり大胆な\\nことでも…な～んて♪', 0);
insert into room_unit_comments values (5030, 116601, 1, 1, 1, 0, 1, 'あーあー、よし\\nのどの調子もいいし\\nはりきってガイド\\nしてくるか！', 0);
insert into room_unit_comments values (5031, 116601, 1, 2, 1, 0, 1, 'さあ、そろそろ行くか\\nガイドが\\n遅刻したんじゃ\\n話になんないからな', 0);
insert into room_unit_comments values (5032, 116601, 1, 3, 1, 0, 1, 'しれっとドラゴン族が\\n旅行に来たり\\nしてくれないかな', 0);
insert into room_unit_comments values (5033, 116601, 1, 4, 1, 0, 1, 'たぎるガイド先…\\n火山、魔物の巣…\\nダメだ、そんなとこ\\nオレしか行けないや', 0);
insert into room_unit_comments values (5034, 116601, 1, 5, 1, 0, 1, 'この前行った絶景\\nスポットよかったな\\nキレイな景色を見る\\nのもいいもんだぜ', 0);
insert into room_unit_comments values (5035, 116601, 1, 101, 4, 0, 1, 'お、今日はカレと\\n一緒か。なんだか\\nやる気出てきたぜ！', 0);
insert into room_unit_comments values (5036, 116601, 1, 102, 8, 0, 1, 'カレにガイドして\\nもらったら\\nどこに行っても\\n楽しいだろうな', 0);
insert into room_unit_comments values (5037, 116601, 2, 1, 1, 0, 1, 'よっしゃあ！\\nどっちが上手く\\nガイドできるか\\n勝負しようぜ！', 0);
insert into room_unit_comments values (5038, 116601, 2, 2, 1, 0, 1, '飯でも食いがてら\\nおススメの店の\\n下調べでもしようぜ！', 0);
insert into room_unit_comments values (5039, 116601, 2, 3, 1, 0, 1, 'なかなかいいだろ？\\nこの格好。キミも\\n作ってもらったら\\nどうだ？', 0);
insert into room_unit_comments values (5040, 116601, 2, 4, 1, 0, 1, '普通は行けない\\n場所とか行きたいよな\\nキミならどんな\\nとこがいい？', 0);
insert into room_unit_comments values (5041, 116601, 2, 101, 4, 0, 1, 'ガイドの仕事は\\nキミの方が得意そうだ\\n参考にさせてもらうぜ\\nよろしくな！', 0);
insert into room_unit_comments values (5042, 116601, 2, 102, 8, 0, 1, 'キミの探してきた店\\n結構よさそうじゃん\\nそうだ、今度二人で\\n下見に行こうぜ！', 0);
insert into room_unit_comments values (5043, 116601, 2, 1, 1, 1, 1, 'いい朝だな。絶好の\\n仕事日和だぜ！\\n今日もよろしくな！', 0);
insert into room_unit_comments values (5044, 116601, 2, 2, 1, 2, 1, 'よし、昼飯にしよう\\nこの後も激務だし\\n飯抜きじゃあ\\nぶっ倒れちまうからな', 0);
insert into room_unit_comments values (5045, 116601, 2, 3, 1, 3, 1, 'お疲れさん！\u3000さーて\\n次はオレと遊んで\\nくれよ。まだまだ\\nいけるだろ？', 0);
insert into room_unit_comments values (5047, 116601, 3, 2, 1, 0, 1, 'ガイドは一日\\n歩きっぱなしだからな\\nゆっくり休ませて\\nもらうぜ', 0);
insert into room_unit_comments values (5048, 116601, 3, 3, 1, 0, 1, 'これ、どこで\\n売ってるんだろ？\\n土産の情報も\\n仕入れとかなきゃな', 0);
insert into room_unit_comments values (5049, 116601, 3, 4, 1, 0, 1, 'アロマとかよく\\n分かんねえけど\\n土産にはいいかもな\\n覚えておくぜ', 0);
insert into room_unit_comments values (5050, 116601, 3, 5, 1, 0, 1, '体が温まると心も\\n熱くなるんだよな\\nいい仕事が\\nできそうだぜ', 0);
insert into room_unit_comments values (5052, 116601, 3, 7, 1, 0, 1, '食べ放題か\\nこれはお客さんも\\n喜んでくれそうだな！', 0);
insert into room_unit_comments values (5053, 116601, 3, 8, 1, 0, 1, 'へえ、こんなスポット\\nあったんだ。やっぱ\\nたまには勉強も\\nしとくもんだな', 0);
insert into room_unit_comments values (5055, 116701, 1, 1, 1, 0, 1, 'バイト先になじめる\\nように笑顔の練習を！\\nに、にへぇ〜…', 0);
insert into room_unit_comments values (5056, 116701, 1, 2, 1, 0, 1, '働いて働いて働いて\\n…いつかその先に\\nぼっちの出口が\\n見えるのかも…！', 0);
insert into room_unit_comments values (5057, 116701, 1, 3, 1, 0, 1, 'バイトのイメトレを\\n始めます。ポーズを\\n決めて…よし！\\n角度を変えて…よし！', 0);
insert into room_unit_comments values (5058, 116701, 1, 4, 1, 0, 1, 'バイト仲間に入る\\nためには厳しい修業が\\n必須と聞きました…！', 0);
insert into room_unit_comments values (5059, 116701, 1, 5, 1, 0, 1, 'どんどん技術を磨いて\\nバイト仲間として\\n認めてもらうんです！\\n目指せ職人技…！', 0);
insert into room_unit_comments values (5060, 116701, 1, 101, 4, 0, 1, 'あの人が応援して\\nくれる…だから必ず\\nバイト仲間の輪に\\n入ってみせます…！', 0);
insert into room_unit_comments values (5061, 116701, 1, 102, 8, 0, 1, 'あの人がいてくれると\\n勇気が湧いてきます…\\nぼっち卒業を夢見ても\\nいいんだ、って…♪', 0);
insert into room_unit_comments values (5062, 116701, 2, 1, 1, 0, 1, '緊張するけど\\n思い切って声をかけて\\nみます…バイト仲間に\\n入るために…！', 0);
insert into room_unit_comments values (5063, 116701, 2, 2, 1, 0, 1, 'ぼっちの私が\\nおもちゃ作りで\\n人と共同作業…！\\nか、感動です…！', 0);
insert into room_unit_comments values (5064, 116701, 2, 3, 1, 0, 1, '好きなおもちゃって\\nありますか？\u3000私は\\nもちろんマイフレンド\\nくんです！', 0);
insert into room_unit_comments values (5065, 116701, 2, 4, 1, 0, 1, '私が作ったおもちゃも\\n誰かの友達に\\nなってたら\\nいいなぁ…♪', 0);
insert into room_unit_comments values (5066, 116701, 2, 101, 4, 0, 1, '今日も明日もバイト\\nですね！\u3000バイト\\n仲間ができる日が\\n楽しみです…♪', 0);
insert into room_unit_comments values (5067, 116701, 2, 102, 8, 0, 1, '脱ぼっちを目指して\\nこれからも一緒に\\n頑張りましょう！\\n目指せ、バイト仲間！', 0);
insert into room_unit_comments values (5068, 116701, 2, 1, 1, 1, 1, 'おはようございます\\n今日も気合いを入れて\\nおもちゃ作りします！', 0);
insert into room_unit_comments values (5069, 116701, 2, 2, 1, 2, 1, 'ランチの時間です…♪\\nもちろん工場の隅で\\nぼっち飯です…！', 0);
insert into room_unit_comments values (5070, 116701, 2, 3, 1, 3, 1, 'ふわぁ…今日も\\nお疲れさまでした\\n明日も働きます～！', 0);
insert into room_unit_comments values (5072, 116701, 3, 2, 1, 0, 1, 'バイトで頑張った日は\\nふわふわの誘惑に\\n勝てません…', 0);
insert into room_unit_comments values (5073, 116701, 3, 3, 1, 0, 1, 'こういうおもちゃの\\nアイデアも\\n素敵かも…♪', 0);
insert into room_unit_comments values (5074, 116701, 3, 4, 1, 0, 1, 'いい香りがする\\nおもちゃはどうかな…\\n森の薬草を使って…', 0);
insert into room_unit_comments values (5075, 116701, 3, 5, 1, 0, 1, 'ぽかぽか…\\n幸せなひとときですね', 0);
insert into room_unit_comments values (5077, 116701, 3, 7, 1, 0, 1, 'もぐもぐ…たくさん\\n食べて厳しいバイトを\\n乗り切ります…！', 0);
insert into room_unit_comments values (5078, 116701, 3, 8, 1, 0, 1, 'ふむふむ…おもちゃの\\n設計図を見るのも\\n勉強になりますね！', 0);
insert into room_unit_comments values (5080, 116801, 1, 1, 1, 0, 1, 'う～ん\\n次はどんなたい焼きを\\n作ろうかにゃぁ…', 0);
insert into room_unit_comments values (5081, 116801, 1, 2, 1, 0, 1, 'あたしが売る\\nたい焼きには\\n夢が詰まってるにゃ！', 0);
insert into room_unit_comments values (5082, 116801, 1, 3, 1, 0, 1, 'いつか絶対に\\nたい焼き工場を\\n建て直してみせるにゃ', 0);
insert into room_unit_comments values (5083, 116801, 1, 4, 1, 0, 1, 'たまにたい焼き以外の\\nおやつも食べるにゃ\\nたとえば煮干しとか！', 0);
insert into room_unit_comments values (5084, 116801, 1, 5, 1, 0, 1, '悪い商売人がいたら\\nファントムキャッツに\\n知らせるにゃ！', 0);
insert into room_unit_comments values (5085, 116801, 1, 101, 4, 0, 1, 'キミと一緒にいると\\nたい焼きのアイデアが\\n次々出てくるにゃ♪', 0);
insert into room_unit_comments values (5086, 116801, 1, 102, 8, 0, 1, '出来ないことも\\nキミと一緒にいれば\\n出来る気がするにゃ♪', 0);
insert into room_unit_comments values (5087, 116801, 2, 1, 1, 0, 1, 'なんにゃ～？\\nお姉さんにかまって\\nほしいのかにゃ♪', 0);
insert into room_unit_comments values (5088, 116801, 2, 2, 1, 0, 1, 'キミ、いいところに！\\nあたしとライバル店へ\\n視察にいくにゃ！', 0);
insert into room_unit_comments values (5089, 116801, 2, 3, 1, 0, 1, 'くんくん…この匂い！\\nたい焼き持ってるなら\\nちょうだいにゃ♪', 0);
insert into room_unit_comments values (5090, 116801, 2, 4, 1, 0, 1, '次はどんなたい焼きを\\n売ろうかにゃ～\\nキミの案も欲しいにゃ', 0);
insert into room_unit_comments values (5091, 116801, 2, 101, 4, 0, 1, 'ファントムキャッツに\\n相棒が必要にゃ\\nたとえばキミとか…', 0);
insert into room_unit_comments values (5092, 116801, 2, 102, 8, 0, 1, '相棒！\\n…ってキミのこと\\n呼んでいいかにゃ？', 0);
insert into room_unit_comments values (5093, 116801, 2, 1, 1, 1, 1, '早起きは三文の徳にゃ\\n今日もたい焼き\\n売れますよーににゃ！', 0);
insert into room_unit_comments values (5094, 116801, 2, 2, 1, 2, 1, 'お腹空いたにゃ…\\n賄いのたい焼きを\\nいただくにゃ！', 0);
insert into room_unit_comments values (5095, 116801, 2, 3, 1, 3, 1, '猫は夜が本番にゃ\\nでもあたしは…\\nふわぁ～眠いにゃ…', 0);
insert into room_unit_comments values (5097, 116801, 3, 2, 1, 0, 1, 'ふかふかにゃ～\\nここで体を丸めて\\n一眠りしたいにゃ', 0);
insert into room_unit_comments values (5098, 116801, 3, 3, 1, 0, 1, 'これは…！\\n猫にも負けない\\nかわいさだにゃ…！', 0);
insert into room_unit_comments values (5099, 116801, 3, 4, 1, 0, 1, 'いい香りにゃ～\\nゴロゴロのどが\\n鳴りそうだにゃ～', 0);
insert into room_unit_comments values (5100, 116801, 3, 5, 1, 0, 1, 'ふにゃ～…\\nこのまま働かずに\\nまるまってたいにゃ…', 0);
insert into room_unit_comments values (5102, 116801, 3, 7, 1, 0, 1, '商売は戦いにゃ\\nたくさん食べて\\nたくさん働くにゃ！', 0);
insert into room_unit_comments values (5103, 116801, 3, 8, 1, 0, 1, 'ふむふむ。たい焼きの\\nアレンジレシピ集…\\nためになるにゃ…', 0);
insert into room_unit_comments values (5105, 102101, 1, 103, 12, 0, 1, 'お芝居の前に\\nお兄ちゃんの顔を\\n見ると、とっても\\n落ち着きますぅ…♪', 0);
insert into room_unit_comments values (5106, 102101, 2, 103, 12, 0, 1, 'お兄ちゃんにもっと\\n見てもらいたい…\\nだから私…\\n強くなりたいです…！', 0);
insert into room_unit_comments values (5107, 116901, 1, 1, 1, 0, 1, 'さらなる効率化で\\nみんなといい仕事を\\nしたいわね！', 0);
insert into room_unit_comments values (5108, 116901, 1, 2, 1, 0, 1, '他のバイトとの\\nスケジュールを\\n調整しないと…', 0);
insert into room_unit_comments values (5109, 116901, 1, 3, 1, 0, 1, '時給がアップしたわ！\\n働きが認められると\\nやる気が出るわね', 0);
insert into room_unit_comments values (5110, 116901, 1, 4, 1, 0, 1, '効率的に動ければ\\n業務を追加できる…\\n燃えてきたわ！', 0);
insert into room_unit_comments values (5111, 116901, 1, 5, 1, 0, 1, '帳簿付けのコツ…\\nユカリさんに教わって\\nみようかしら', 0);
insert into room_unit_comments values (5112, 116901, 1, 101, 4, 0, 1, 'バイトリーダーとして\\nみんなをビシバシ\\n鍛えていくわ！', 0);
insert into room_unit_comments values (5113, 116901, 1, 102, 8, 0, 1, '戦いでもバイトでも\\nキミなら安心して\\n背中を預けられるわね', 0);
insert into room_unit_comments values (5114, 116901, 2, 1, 1, 0, 1, 'どうしたの？\\n仕事のことなら\\nなんでも相談してね！', 0);
insert into room_unit_comments values (5115, 116901, 2, 2, 1, 0, 1, 'さすがは私の弟子ね\\nこれなら安心して\\n仕事を任せられるわ', 0);
insert into room_unit_comments values (5116, 116901, 2, 3, 1, 0, 1, 'みんなのお手本になる\\n働きぶりを見せないと\\nいけないわね！', 0);
insert into room_unit_comments values (5117, 116901, 2, 4, 1, 0, 1, 'キミのこと…もっと\\n頼りにしちゃっても\\nいいのかしら…？', 0);
insert into room_unit_comments values (5118, 116901, 2, 101, 4, 0, 1, 'ふふ、キミも一人前の\\nバイト戦士として\\n立派に成長したわね！', 0);
insert into room_unit_comments values (5119, 116901, 2, 102, 8, 0, 1, '新しいおもちゃの\\n企画書を作ってみたの\\nちょっと見てくれる？', 0);
insert into room_unit_comments values (5120, 116901, 2, 1, 1, 1, 1, '朝は一番効率がいい\\n時間帯よ！\\nバリバリ働くわよ！', 0);
insert into room_unit_comments values (5121, 116901, 2, 2, 1, 2, 1, 'さ、お昼に行きましょ\\n今日の日替わり定食は\\n何かしら…楽しみね♪', 0);
insert into room_unit_comments values (5122, 116901, 2, 3, 1, 3, 1, 'もうこんな時間…\\nちゃんと寝て明日に\\n備えなくちゃね', 0);
insert into room_unit_comments values (5124, 116901, 3, 2, 1, 0, 1, '適度な労働と休息の\\nサイクルが最大効率を\\n生み出すのよ…ふぅ…', 0);
insert into room_unit_comments values (5125, 116901, 3, 3, 1, 0, 1, 'はぁ～なんて素敵な\\n抱き心地なのかしら…\\n最高効率の癒やしね♪', 0);
insert into room_unit_comments values (5126, 116901, 3, 4, 1, 0, 1, '落ち着く香りね…\\nなんだか集中力が\\nアップした気がするわ', 0);
insert into room_unit_comments values (5127, 116901, 3, 5, 1, 0, 1, 'ふぅ…癒されるわね…\\n仕事のオンオフの\\n切り替えは重要よね', 0);
insert into room_unit_comments values (5129, 116901, 3, 7, 1, 0, 1, '働くためには\\nエネルギーをちゃんと\\n摂っておかないと', 0);
insert into room_unit_comments values (5130, 116901, 3, 8, 1, 0, 1, '効率を上げるため\\n生産管理の勉強も\\nしておきたいわね', 0);
insert into room_unit_comments values (5132, 180301, 1, 1, 1, 0, 1, '変身している間に\\n色々と試しておこう\\nまずは…', 0);
insert into room_unit_comments values (5133, 180301, 1, 2, 1, 0, 1, '飛べるというのは\\n便利だな。料理が\\n暖かいうちに\\n持ち帰れる', 0);
insert into room_unit_comments values (5134, 180301, 1, 3, 1, 0, 1, 'プリンセスか…\\n柄ではないけれど\\n嫌な気はしないな', 0);
insert into room_unit_comments values (5135, 180301, 1, 4, 1, 0, 1, 'この力で\\n何を成すべきなのか…\\n剣に聞いてみよう', 0);
insert into room_unit_comments values (5136, 180301, 1, 5, 1, 0, 1, '変身したとて私は私\\n一時的に強くなろうと\\n元が弱くてはだめだ', 0);
insert into room_unit_comments values (5137, 180301, 1, 101, 4, 0, 1, '変身していない時でも\\n彼がそばにいると\\n力が湧いてくる…', 0);
insert into room_unit_comments values (5138, 180301, 1, 102, 8, 0, 1, '私の思い…\\nいつか伝えてみせるよ\\n…きっといつか！', 0);
insert into room_unit_comments values (5139, 180301, 2, 1, 1, 0, 1, '何者かと戦うの？\\nそれとも修行？\\nどちらだとしても\\n付き合うよ', 0);
insert into room_unit_comments values (5140, 180301, 2, 2, 1, 0, 1, '変身し続けたら\\nどれだけ空腹に…\\n私は試さないからね？', 0);
insert into room_unit_comments values (5141, 180301, 2, 3, 1, 0, 1, '本物のプリンセスに\\nなるのは御免だが\\nナイトがいて\\nくれるのは頼もしいよ', 0);
insert into room_unit_comments values (5142, 180301, 2, 4, 1, 0, 1, 'いつかこの力を\\n誰かを救うために…\\n戦い以外に使える時が\\nくることを願うよ', 0);
insert into room_unit_comments values (5143, 180301, 2, 101, 4, 0, 1, 'キミに感じてほしいな\\n私に流れてくる\\nキミからの力を…\\nその…私の、思いも…', 0);
insert into room_unit_comments values (5144, 180301, 2, 102, 8, 0, 1, '思いを告げる…\\nそれがこんなにも\\n難しいなんて…\\nでも、いつか必ず…！', 0);
insert into room_unit_comments values (5145, 180301, 2, 1, 1, 1, 1, 'おはよう！\\nいい変身日和だ！\\n…ふふっ、冗談だよ', 0);
insert into room_unit_comments values (5146, 180301, 2, 2, 1, 2, 1, 'いつもより多く\\n昼食を用意しよう\\n変身が解けたら大変だ', 0);
insert into room_unit_comments values (5147, 180301, 2, 3, 1, 3, 1, '一日お疲れ様\\n私もそろそろ変身を\\n解いて休むとするよ', 0);
insert into room_unit_comments values (5149, 180301, 3, 2, 1, 0, 1, '変身してしまうと\\n動かずにいても\\n空腹になるのかな…？', 0);
insert into room_unit_comments values (5150, 180301, 3, 3, 1, 0, 1, '私もキミたちくらい\\n可愛げがある姿に\\nなっているかな？', 0);
insert into room_unit_comments values (5151, 180301, 3, 4, 1, 0, 1, '香りに対する感覚も\\nいつもより鋭く\\nなっているみたいだ…', 0);
insert into room_unit_comments values (5152, 180301, 3, 5, 1, 0, 1, 'ありがたいな\\n少し足元が\\n冷えていたところだ', 0);
insert into room_unit_comments values (5154, 180301, 3, 7, 1, 0, 1, 'これは…！\\n持ち運べるように\\n改良できないかな？', 0);
insert into room_unit_comments values (5155, 180301, 3, 8, 1, 0, 1, '祖父に貰った\\n技法書を読んで\\n初心に帰ろう', 0);
insert into room_unit_comments values (5157, 117001, 1, 1, 1, 0, 1, '最強の惚れ薬を作って\\nあのおかたの心を\\n私の思いのままに…', 0);
insert into room_unit_comments values (5158, 117001, 1, 2, 1, 0, 1, '夏といえば海にスイカ\\n花火に水着…\\nそして惚れ薬ですわ…', 0);
insert into room_unit_comments values (5159, 117001, 1, 3, 1, 0, 1, 'あのおかたの心を\\n手に入れるための\\n準備を進めましょう\\nこの夏こそ確実に…', 0);
insert into room_unit_comments values (5160, 117001, 1, 4, 1, 0, 1, 'あのおかたに近づく\\n虫どもを、どうやって\\n片付けようかしら…\\nまったく忌々しいこと', 0);
insert into room_unit_comments values (5161, 117001, 1, 5, 1, 0, 1, '…クスクス\\n薬の調合を考えるのは\\n至福の時間ですわ…', 0);
insert into room_unit_comments values (5162, 117001, 1, 101, 4, 0, 1, 'あのおかたの全てが\\n早く私のものに\\nなりますように…', 0);
insert into room_unit_comments values (5163, 117001, 1, 102, 8, 0, 1, 'かき氷も花火も海も…\\nあなた様がいてこそ…\\nそう、あなた様は\\n私の全てなのですわ', 0);
insert into room_unit_comments values (5164, 117001, 2, 1, 1, 0, 1, '二人だけの夏を\\n楽しみましょう…？\\n…クスクス', 0);
insert into room_unit_comments values (5165, 117001, 2, 2, 1, 0, 1, 'あら、あなた様\\n私に秘密でどこに\\n行こうとして\\nいますの…？', 0);
insert into room_unit_comments values (5166, 117001, 2, 3, 1, 0, 1, '海に行きませんか？\\nあなた様と一緒に\\n過ごすには\\n最高の場所ですから…', 0);
insert into room_unit_comments values (5167, 117001, 2, 4, 1, 0, 1, 'ちょうどいいところに\\nいらっしゃいました\\nできたての薬を…\\nさぁどうぞ…クスクス', 0);
insert into room_unit_comments values (5168, 117001, 2, 101, 4, 0, 1, '夏の海のきらめきも\\nあなた様の存在が\\nなければ色あせて\\nしまいますわ…', 0);
insert into room_unit_comments values (5169, 117001, 2, 102, 8, 0, 1, '私とあなた様は\\n結ばれる運命に\\nあるのです…\\n逃がしませんわ…', 0);
insert into room_unit_comments values (5170, 117001, 2, 1, 1, 1, 1, '起きてすぐに会いに\\n来てくださるなんて\\nようやく私の伴侶たる\\n自覚が…クスクス', 0);
insert into room_unit_comments values (5171, 117001, 2, 2, 1, 2, 1, 'お食事はまだですか？\\n特製の薬草ランチを\\n召し上がれ…クスクス', 0);
insert into room_unit_comments values (5172, 117001, 2, 3, 1, 3, 1, '私の夢を見られる薬を\\n差し上げますわ…\\nおやすみなさいませ\\nあなた様…クスクス', 0);
insert into room_unit_comments values (5174, 117001, 3, 2, 1, 0, 1, 'いい肌触りですわ…\\n考え事にもぴったり\\n眠くなるのが\\n玉に瑕ですが…', 0);
insert into room_unit_comments values (5175, 117001, 3, 3, 1, 0, 1, 'こういったものに\\n揮発性の薬を仕込む\\nのも一つの手ですわね', 0);
insert into room_unit_comments values (5176, 117001, 3, 4, 1, 0, 1, 'この香り…開発中の\\n薬に使えそうな気が\\nしますわ…クスクス', 0);
insert into room_unit_comments values (5177, 117001, 3, 5, 1, 0, 1, 'あのおかたの\\nぬくもりを\\n思い出しますわ…', 0);
insert into room_unit_comments values (5179, 117001, 3, 7, 1, 0, 1, '美味しい…この味なら\\n薬を混ぜても違和感は\\nなさそうですわ…', 0);
insert into room_unit_comments values (5180, 117001, 3, 8, 1, 0, 1, 'この薬の調合法…\\n今度試してみましょう\\nもちろんあのおかたに\\n飲んでいただいて…', 0);
insert into room_unit_comments values (5182, 117001, 3, 10, 1, 0, 1, '二人乗りができると\\nいいですわね…', 0);
insert into room_unit_comments values (5183, 117001, 3, 11, 1, 0, 1, 'ふかふかですわ…\\nあのおかたの分も\\n欲しくなります…', 0);
insert into room_unit_comments values (5184, 101701, 1, 103, 12, 0, 1, '今日はキミと\\nいつまでも歌って\\n踊りたい気分さ～♪', 0);
insert into room_unit_comments values (5185, 101701, 2, 103, 12, 0, 1, 'あは～♪\\nキミの隣は、故郷より\\n落ち着くかも～…♪', 0);
insert into room_unit_comments values (5186, 117101, 1, 1, 1, 0, 1, 'この水着…\\n一番に弟くんに\\n見せたいな♪', 0);
insert into room_unit_comments values (5187, 117101, 1, 2, 1, 0, 1, '弟くんをこっそり\\n海に運んで…\\nサプライズしちゃお♪', 0);
insert into room_unit_comments values (5188, 117101, 1, 3, 1, 0, 1, 'いつもと違う髪型に\\nしてみたけど…\\n気に入ってくれるかな', 0);
insert into room_unit_comments values (5189, 117101, 1, 4, 1, 0, 1, '海は楽しみだけど\\n日焼けしないように\\n気を付けなきゃね', 0);
insert into room_unit_comments values (5190, 117101, 1, 5, 1, 0, 1, 'まだかな、弟くん\\n水着のお姉ちゃんが\\nお出迎えだよっ♪', 0);
insert into room_unit_comments values (5191, 117101, 1, 101, 4, 0, 1, '海が見えるおうちで\\n弟くんと一緒に\\n暮らしたいなぁ～', 0);
insert into room_unit_comments values (5192, 117101, 1, 102, 8, 0, 1, '弟くんの水着…\\nどんな感じかなぁ\\n…あ、想像してたら\\nドキドキして…えへへ', 0);
insert into room_unit_comments values (5193, 117101, 2, 1, 1, 0, 1, 'こーら、水着の\\nお姉ちゃんは\\nおさわり禁止♪\\n…なんてね？', 0);
insert into room_unit_comments values (5194, 117101, 2, 2, 1, 0, 1, 'なぁに？\\nふふっ、何回でも\\n呼んでいいんだよ♪', 0);
insert into room_unit_comments values (5195, 117101, 2, 3, 1, 0, 1, '海で迷子に\\nならないように\\n手を繋ごうね♪', 0);
insert into room_unit_comments values (5196, 117101, 2, 4, 1, 0, 1, 'お姉ちゃんが\\n海の楽しみ方を\\n教えてあげるねっ！', 0);
insert into room_unit_comments values (5197, 117101, 2, 101, 4, 0, 1, 'わっ、弟くん\\nどこ触ってるの？\\nも～驚いちゃったぞ♪', 0);
insert into room_unit_comments values (5198, 117101, 2, 102, 8, 0, 1, 'お姉ちゃん、海でも\\nずっとキミを見てるよ\\n…安心してね', 0);
insert into room_unit_comments values (5199, 117101, 2, 1, 1, 1, 1, 'まだ眠そうだね？\\nほら、海が待ってるよ\\n早く起きて起きて♪', 0);
insert into room_unit_comments values (5200, 117101, 2, 2, 1, 2, 1, '大丈夫、疲れてない？\\n海で遊び疲れた時は\\n素直に休憩しようね', 0);
insert into room_unit_comments values (5201, 117101, 2, 3, 1, 3, 1, 'ほら、早く寝ないと\\n明日もお姉ちゃんと\\n遊べないぞ♪', 0);
insert into room_unit_comments values (5203, 117101, 3, 2, 1, 0, 1, 'だらけたお姉ちゃんは\\n弟くんには\\n見せられないな～', 0);
insert into room_unit_comments values (5204, 117101, 3, 3, 1, 0, 1, 'ふふっ、かわいいね♪\\n弟くんが持つと\\nもっとかわいいよっ♪', 0);
insert into room_unit_comments values (5205, 117101, 3, 4, 1, 0, 1, 'いい香りだね…\\n一味違うお姉ちゃんに\\nなれそう…♪', 0);
insert into room_unit_comments values (5206, 117101, 3, 5, 1, 0, 1, 'あったか～い♪\\nほら、弟くんも\\nおいでよ♪', 0);
insert into room_unit_comments values (5208, 117101, 3, 7, 1, 0, 1, 'よく食べて、いつでも\\n弟くんの呼び声に\\n応える準備を…！', 0);
insert into room_unit_comments values (5209, 117101, 3, 8, 1, 0, 1, '弟くんの水着の写真\\nこの辺りに隠して\\nおこうかな', 0);
insert into room_unit_comments values (5211, 117101, 3, 10, 1, 0, 1, 'この子の背に乗って\\nお姉ちゃんと弟くんの\\n楽園へ…な～んて♪', 0);
insert into room_unit_comments values (5212, 117101, 3, 11, 1, 0, 1, '海を感じる感触だね\\n弟くんとの楽しい夏を\\n思い出しちゃうな…♪', 0);
insert into room_unit_comments values (5213, 117201, 1, 1, 1, 0, 1, 'この夏、誰よりも\\nキラキラしてみせる！\\nだって私は\\nアイドルだから！', 0);
insert into room_unit_comments values (5214, 117201, 1, 2, 1, 0, 1, '日傘にアームカバー\\n帽子にサングラス…\\n紫外線対策は完璧！', 0);
insert into room_unit_comments values (5215, 117201, 1, 3, 1, 0, 1, 'とっておきの\\nサマーソングを\\nみんなに届けるよ！', 0);
insert into room_unit_comments values (5216, 117201, 1, 4, 1, 0, 1, 'なんにもしないのって\\n苦手かも…\\n彼、早く来ないかな？', 0);
insert into room_unit_comments values (5217, 117201, 1, 5, 1, 0, 1, 'ラムネって\\n夏って感じするよね\\n後で彼と飲もっと♪', 0);
insert into room_unit_comments values (5218, 117201, 1, 101, 4, 0, 1, '夏は恋の季節！\\n燃えるような恋…\\nいつかしたいな', 0);
insert into room_unit_comments values (5219, 117201, 1, 102, 8, 0, 1, '今年の夏の目標は\\n…彼との思い出を\\nいっぱい作ること！', 0);
insert into room_unit_comments values (5220, 117201, 2, 1, 1, 0, 1, '私の水着写真集\\n見てくれたんだ！\\nどう、かわいかった？', 0);
insert into room_unit_comments values (5221, 117201, 2, 2, 1, 0, 1, 'スイカ割りしたいの？\\nいいね、楽しそう！\\nみんなも誘おうよ♪', 0);
insert into room_unit_comments values (5222, 117201, 2, 3, 1, 0, 1, 'ねぇ、見て見て！\\n水着の映える\\nポーズ考えたんだ！', 0);
insert into room_unit_comments values (5223, 117201, 2, 4, 1, 0, 1, 'ライブ中に\\n花火を打ち上げたら\\n絶対盛り上がるよね！', 0);
insert into room_unit_comments values (5224, 117201, 2, 101, 4, 0, 1, '最近、忙しいけど…\\nキミの顔見たら\\n疲れなんて\\n消えちゃった！', 0);
insert into room_unit_comments values (5225, 117201, 2, 102, 8, 0, 1, 'この夏もいーっぱい\\nドキドキさせるから！\\n覚悟しててよね♪', 0);
insert into room_unit_comments values (5226, 117201, 2, 1, 1, 1, 1, '外は朝から暑いね\\nけど、負けないから！\\nお仕事、頑張るぞー！', 0);
insert into room_unit_comments values (5227, 117201, 2, 2, 1, 2, 1, '自分へのご褒美に、\\nアイス食べちゃお♪\\nキミも一緒に食べよ！', 0);
insert into room_unit_comments values (5228, 117201, 2, 3, 1, 3, 1, '夏の夜って\\nワクワクするね♪\\nホタル見に行こうよ！', 0);
insert into room_unit_comments values (5230, 117201, 3, 2, 1, 0, 1, 'ふわぁ…眠い…\\n仕事とかの疲れ、\\nたまってるのかな…？', 0);
insert into room_unit_comments values (5231, 117201, 3, 3, 1, 0, 1, '私のぬいぐるみが\\nグッズになったら…\\n彼にかわいがって\\nもらえるかな？', 0);
insert into room_unit_comments values (5232, 117201, 3, 4, 1, 0, 1, 'この香り…\\n夏限定のやつでしょ？\\nいいセンスしてるね♪', 0);
insert into room_unit_comments values (5233, 117201, 3, 5, 1, 0, 1, '暑～い！\\nけど…汗かいて\\n気持ちいいかも！', 0);
insert into room_unit_comments values (5235, 117201, 3, 7, 1, 0, 1, 'レッスンの後のご飯は\\n特別おいしい♪\\n…もうひとつだけ\\n食べちゃおっかな', 0);
insert into room_unit_comments values (5236, 117201, 3, 8, 1, 0, 1, 'あ、この前撮影した\\n水着グラビアだ\\nうんうん、いい感じ！', 0);
insert into room_unit_comments values (5238, 117201, 3, 10, 1, 0, 1, 'この子、もふもふだね\\n触るのクセになりそう\\nもふもふもふもふ…', 0);
insert into room_unit_comments values (5239, 117201, 3, 11, 1, 0, 1, 'わ、かわいい♪\\n今度のグラビア撮影で\\nこれ使ってもいい？', 0);
insert into room_unit_comments values (5240, 117401, 1, 1, 1, 0, 1, '水着っていいですよね\\n海に浮かぶ一輪の花\\nって感じがして！', 0);
insert into room_unit_comments values (5241, 117401, 1, 2, 1, 0, 1, '自分の水着を作るのも\\n誰かの水着を作るのも\\n楽しいですね♪', 0);
insert into room_unit_comments values (5242, 117401, 1, 3, 1, 0, 1, '水着の最終チェック！\\n伸縮性や動きやすさは\\n…いい感じですね！', 0);
insert into room_unit_comments values (5243, 117401, 1, 4, 1, 0, 1, '振り付けや衣装作りに\\n歌や踊りの練習…\\n…やることがいっぱい', 0);
insert into room_unit_comments values (5244, 117401, 1, 5, 1, 0, 1, 'はぁ…レイ様の水着…\\n私に作らせて\\nもらえないかなぁ～…', 0);
insert into room_unit_comments values (5245, 117401, 1, 101, 4, 0, 1, '騎士さんのことは\\n気に入らないですけど\\n別に嫌いという\\nわけじゃなくて…', 0);
insert into room_unit_comments values (5246, 117401, 1, 102, 8, 0, 1, '騎士さん暇そうですね\\nに、荷物持ちとして\\n誘ってみようかな…', 0);
insert into room_unit_comments values (5247, 117401, 2, 1, 1, 0, 1, '騎士さんいいところに\\nこの衣装\\nどう思います？', 0);
insert into room_unit_comments values (5248, 117401, 2, 2, 1, 0, 1, '何見てるんですか？\\nもしかしてこの水着の\\n良さが分かります！？', 0);
insert into room_unit_comments values (5249, 117401, 2, 3, 1, 0, 1, '真夏でも涼しい…\\nそれも水着の良さの\\n一つですね', 0);
insert into room_unit_comments values (5250, 117401, 2, 4, 1, 0, 1, '仕立て屋も\\nアイドルも\\n諦めません！', 0);
insert into room_unit_comments values (5251, 117401, 2, 101, 4, 0, 1, '夏と言えば\\nバカンスですけど…\\n予定、あるんですか？', 0);
insert into room_unit_comments values (5252, 117401, 2, 102, 8, 0, 1, 'う～ん…騎士さんを\\n海へ誘うには…って\\nなんでもないですよ！', 0);
insert into room_unit_comments values (5253, 117401, 2, 1, 1, 1, 1, 'ふー…夏はやっぱり\\n朝が一番過ごしやすい\\nですね～！', 0);
insert into room_unit_comments values (5254, 117401, 2, 2, 1, 2, 1, '暑い時こそ海です！\\n体力づくりのためにも\\n泳ぎにいきますよ！', 0);
insert into room_unit_comments values (5255, 117401, 2, 3, 1, 3, 1, '外で虫が鳴いてる…\\n夏って感じがして\\n風流ですねぇ…', 0);
insert into room_unit_comments values (5257, 117401, 3, 2, 1, 0, 1, '少し休憩です…\\nこのまま寝ないよう\\n気をつけないと…', 0);
insert into room_unit_comments values (5258, 117401, 3, 3, 1, 0, 1, 'か、かわいい…！\\nこの感動を次の\\nステージ衣装にも…！', 0);
insert into room_unit_comments values (5259, 117401, 3, 4, 1, 0, 1, 'いい香りですね～\\n波の音が聞こえて\\nきそうです…', 0);
insert into room_unit_comments values (5260, 117401, 3, 5, 1, 0, 1, '泳いだ後は\\n少し寒いので\\nちょうどいいですね', 0);
insert into room_unit_comments values (5262, 117401, 3, 7, 1, 0, 1, '夏バテしないように\\n栄養はしっかり\\n取らないと！', 0);
insert into room_unit_comments values (5263, 117401, 3, 8, 1, 0, 1, '次のトレンドは…\\nふむふむ、やっぱり\\nこう来ましたか…', 0);
insert into room_unit_comments values (5265, 117401, 3, 10, 1, 0, 1, 'デザインはもちろん\\n触り心地も\\n最高ですね♪', 0);
insert into room_unit_comments values (5266, 117401, 3, 11, 1, 0, 1, '夏の撮影スポットに\\n活用できそうですね\\nさっそく衣装考えて…', 0);
insert into room_unit_comments values (5267, 104001, 1, 103, 12, 0, 1, 'えへへ…♪\\n団長さんが初めての\\n友達で本当に良かった', 0);
insert into room_unit_comments values (5268, 104001, 2, 103, 12, 0, 1, 'あっ、団長さん！\\n今日のＢＢ団の活動\\nなんですけど…二人で\\n大縄跳びしませんか！', 0);
insert into room_unit_comments values (5269, 117301, 1, 1, 1, 0, 1, 'この衣装で\\nライブするのは\\n恥ずかしいな…', 0);
insert into room_unit_comments values (5270, 117301, 1, 2, 1, 0, 1, 'せっかくの夏だし\\n肝試しに\\n行ってみたいかも…', 0);
insert into room_unit_comments values (5271, 117301, 1, 3, 1, 0, 1, '歌もダンスも\\nより上を目指すために\\n夏合宿をしよう…！', 0);
insert into room_unit_comments values (5272, 117301, 1, 4, 1, 0, 1, '夏の暑さにも負けない\\n熱いライブに\\nしてみせる…！', 0);
insert into room_unit_comments values (5273, 117301, 1, 5, 1, 0, 1, '新曲のアイデア\\nまとめたいな…\\n少し海辺を散歩しよう', 0);
insert into room_unit_comments values (5274, 117301, 1, 101, 4, 0, 1, 'かき氷、食べたいな\\n…あの人は何味が\\n好きなんだろう？', 0);
insert into room_unit_comments values (5275, 117301, 1, 102, 8, 0, 1, '水着、似合ってるって\\n言ってもらえるかな…', 0);
insert into room_unit_comments values (5276, 117301, 2, 1, 1, 0, 1, 'サインして、ですか？\\nいいですけど…\\n少し照れますね…', 0);
insert into room_unit_comments values (5277, 117301, 2, 2, 1, 0, 1, '少し待ってください\\n今、新曲の楽譜を\\n書いているので…', 0);
insert into room_unit_comments values (5278, 117301, 2, 3, 1, 0, 1, 'なんでしょう？\\nもしかして…\\nボイトレに興味が？', 0);
insert into room_unit_comments values (5279, 117301, 2, 4, 1, 0, 1, '今度のライブでは\\n夏らしい爽やかな歌を\\nファンにお届けします', 0);
insert into room_unit_comments values (5280, 117301, 2, 101, 4, 0, 1, '…水鉄砲で遊ぼう？\\nふふ。楽しそうですね\\nお手柔らかに…♪', 0);
insert into room_unit_comments values (5281, 117301, 2, 102, 8, 0, 1, 'あなたの声を\\n聴いていると、\\n何だか落ち着きます…', 0);
insert into room_unit_comments values (5282, 117301, 2, 1, 1, 1, 1, '今日も暑くなりそう…\\nお互いしっかりと\\n水分補給しましょうね', 0);
insert into room_unit_comments values (5283, 117301, 2, 2, 1, 2, 1, 'お腹空きましたよね\\n海の家で、\\nなにか買ってきます', 0);
insert into room_unit_comments values (5284, 117301, 2, 3, 1, 3, 1, '夜の海で月明かりと\\n波の音を楽しもうかと\\n…一緒に行きますか？', 0);
insert into room_unit_comments values (5286, 117301, 3, 2, 1, 0, 1, 'レッスンだけでなく\\nリラックスすることも\\n大事、ですよね', 0);
insert into room_unit_comments values (5287, 117301, 3, 3, 1, 0, 1, 'ふふ、かわいい\\n精霊も負けないくらい\\nかわいいですけどね', 0);
insert into room_unit_comments values (5288, 117301, 3, 4, 1, 0, 1, '夏らしい爽やかで\\nいい匂い…あなたに\\nピッタリな香りですね', 0);
insert into room_unit_comments values (5289, 117301, 3, 5, 1, 0, 1, '海に入った後は、\\n体が冷えてしまいます\\n一緒に温まりましょう', 0);
insert into room_unit_comments values (5291, 117301, 3, 7, 1, 0, 1, 'アイドルとして、\\n食べすぎには\\n気をつけないと…', 0);
insert into room_unit_comments values (5292, 117301, 3, 8, 1, 0, 1, '夏は恋の季節…\\nガンガン攻めるべし…\\nなるほど…', 0);
insert into room_unit_comments values (5294, 117301, 3, 10, 1, 0, 1, 'この子に乗りながら\\nライブをする…\\nというのはどうですか', 0);
insert into room_unit_comments values (5295, 117301, 3, 11, 1, 0, 1, 'まるで人魚になった\\n気分…なんて、ふふ', 0);
insert into room_unit_comments values (5296, 118301, 1, 1, 1, 0, 1, 'お姉ちゃんとして\\nシオリンにかっこいい\\nとこ見せなくっちゃ☆', 0);
insert into room_unit_comments values (5297, 118301, 1, 2, 1, 0, 1, 'いつかシオリンと\\n一緒に空を飛んで\\n空中散歩してみたいな', 0);
insert into room_unit_comments values (5298, 118301, 1, 3, 1, 0, 1, 'すこし眠くなってきた\\nかも…シオリンと\\nお昼寝しようかな', 0);
insert into room_unit_comments values (5299, 118301, 1, 4, 1, 0, 1, 'お散歩してこよっと！\\nシオリンとお出かけ\\nするのにいい場所\\n探さなくっちゃ！', 0);
insert into room_unit_comments values (5300, 118301, 1, 5, 1, 0, 1, 'シオリンに過保護って\\n言われちゃった…♪\\nそれでも心配しちゃう\\nのが姉心…だよね？', 0);
insert into room_unit_comments values (5301, 118301, 1, 101, 4, 0, 1, '気持ちいい日差し！\\nシオリンと彼と、\\nお昼寝したら\\n気持ちよさそ～♪', 0);
insert into room_unit_comments values (5302, 118301, 1, 102, 8, 0, 1, '今度天気がいい日には\\nシオリンと彼を誘って\\n一緒にお出かけ\\nしたいな～♪', 0);
insert into room_unit_comments values (5303, 118301, 2, 1, 1, 0, 1, '今日はご機嫌なんだ♪\\nだって、シオリンの\\n調子がいいんだもん☆', 0);
insert into room_unit_comments values (5304, 118301, 2, 2, 1, 0, 1, '今からシオリンと\\nピクニックに\\n行くんだ♪\u3000そうだ！\\nキミも一緒にどう？', 0);
insert into room_unit_comments values (5305, 118301, 2, 3, 1, 0, 1, 'わっ、びっくりした！\\nシオリンから借りた本\\n読むのに集中\\nしてたから…', 0);
insert into room_unit_comments values (5306, 118301, 2, 4, 1, 0, 1, 'うん？\u3000どうしたの？\\nあっ、もしかして\\nこの服、気になる？', 0);
insert into room_unit_comments values (5307, 118301, 2, 101, 4, 0, 1, 'シオリンもキミも元気\\nいっぱいだと、私も\\n元気になっちゃうよ☆', 0);
insert into room_unit_comments values (5308, 118301, 2, 102, 8, 0, 1, 'シオリンの前だけ\\nじゃなくて、キミにも\\nかっこいい私の姿を\\n見てほしいな☆', 0);
insert into room_unit_comments values (5309, 118301, 2, 1, 1, 1, 1, 'おはよう！\u3000えへへっ\\n今日は早起きなんだ♪\\nシオリンにかっこ悪い\\nとこ見せたくないから', 0);
insert into room_unit_comments values (5310, 118301, 2, 2, 1, 2, 1, 'おなかすいたなぁ～…\\nシオリンと一緒に\\nおいしいもの食べに\\n行こうかな！', 0);
insert into room_unit_comments values (5311, 118301, 2, 3, 1, 3, 1, 'もうこんな時間！？\\nシオリンと一緒だと\\n時間が早く\\n過ぎていっちゃうね！', 0);
insert into room_unit_comments values (5313, 118301, 3, 2, 1, 0, 1, 'この快適な寝心地…！\\nシオリンにもおすすめ\\nしなきゃ…！', 0);
insert into room_unit_comments values (5314, 118301, 3, 3, 1, 0, 1, 'わあ、かわいい！\\nそれにさわり心地も\\nいいし、抱き枕に\\nちょうどいいかも！', 0);
insert into room_unit_comments values (5315, 118301, 3, 4, 1, 0, 1, 'いいにおい…♪\\nなんだかリラックス\\nできて…すやぁ…', 0);
insert into room_unit_comments values (5316, 118301, 3, 5, 1, 0, 1, 'ぽかぽか～☆\\nシオリンと一緒に\\nぬくぬくしたら\\n気持ちよさそう♪', 0);
insert into room_unit_comments values (5318, 118301, 3, 7, 1, 0, 1, '仲のいい人が一緒だと\\nつい食が進んじゃうね\\nえへへ…♪', 0);
insert into room_unit_comments values (5319, 118301, 3, 8, 1, 0, 1, 'ふむふむ…この本…\\nシオリンが好きかも！\\n今度おすすめしよっと', 0);
insert into room_unit_comments values (5322, 118401, 1, 1, 1, 0, 1, 'お姉ちゃん、\\n私のために無理は\\nしてないかな…？', 0);
insert into room_unit_comments values (5323, 118401, 1, 2, 1, 0, 1, '新しく買った絵本…\\nこういうのなら\\nお姉ちゃんと楽しく\\n読めるよね', 0);
insert into room_unit_comments values (5324, 118401, 1, 3, 1, 0, 1, 'ニャットちゃんを\\nここに連れてきて\\nみんなで遊べないかな', 0);
insert into room_unit_comments values (5325, 118401, 1, 4, 1, 0, 1, '本屋さんに行こうかな\\nみんなで読める\\n面白い本が\\nあるといいなぁ', 0);
insert into room_unit_comments values (5326, 118401, 1, 5, 1, 0, 1, 'たまには…読むだけ\\nじゃなくて、自分で\\nお話を書いて\\nみようかな…？', 0);
insert into room_unit_comments values (5327, 118401, 1, 101, 4, 0, 1, '時々…お姉ちゃんと\\nあの人が似てるって\\n思うことがあります…', 0);
insert into room_unit_comments values (5328, 118401, 1, 102, 8, 0, 1, 'お姉ちゃんとあの人…\\n優しくて頼もしい\\n二人に囲まれて…\\n私、幸せ者だなぁ…', 0);
insert into room_unit_comments values (5329, 118401, 2, 1, 1, 0, 1, 'どうかしましたか？\\nもしかして…あなたも\\n一緒にこの本を\\n読みたい…とか？', 0);
insert into room_unit_comments values (5330, 118401, 2, 2, 1, 0, 1, 'けほっ…けほっ…\\nあっ、心配いりません\\n飲み物を飲んで\\nむせただけですから', 0);
insert into room_unit_comments values (5331, 118401, 2, 3, 1, 0, 1, 'この格好…\\n似合ってますか…？\\nえへへ、照れますね…', 0);
insert into room_unit_comments values (5332, 118401, 2, 4, 1, 0, 1, 'なぁに、お姉ちゃん？\\n…あっ、すみません\\n読書に集中していて…\\n間違えちゃいました…', 0);
insert into room_unit_comments values (5333, 118401, 2, 101, 4, 0, 1, 'お姉ちゃん、時々無理\\nしちゃうから…\\nあなたも一緒だと\\n安心できます', 0);
insert into room_unit_comments values (5334, 118401, 2, 102, 8, 0, 1, 'お姉ちゃんとあなたと\\n頼れる人に囲まれて\\n私は幸せものですね', 0);
insert into room_unit_comments values (5335, 118401, 2, 1, 1, 1, 1, 'なんだか朝から\\n調子がいい…今日は\\nいい日になりそうです', 0);
insert into room_unit_comments values (5336, 118401, 2, 2, 1, 2, 1, 'せっかくだから、\\nお姉ちゃんを誘って\\nお外でランチも\\nいいかも', 0);
insert into room_unit_comments values (5337, 118401, 2, 3, 1, 3, 1, 'お姉ちゃんに心配\\nかけないように…もう\\nちょっと本を読んだら\\n寝なくちゃね', 0);
insert into room_unit_comments values (5339, 118401, 3, 2, 1, 0, 1, 'ふんわり柔らかくて\\n気持ちいい手触り…\\nお姉ちゃんが寝るのに\\nちょうどよさそう', 0);
insert into room_unit_comments values (5340, 118401, 3, 3, 1, 0, 1, 'ふふっ、かわいい♪\\n絵本の物語みたいに\\nおしゃべりできない\\nかな…？', 0);
insert into room_unit_comments values (5341, 118401, 3, 4, 1, 0, 1, '素敵な落ち着く香り♪\\nなんだかお姉ちゃん\\nみたい、ふふっ', 0);
insert into room_unit_comments values (5342, 118401, 3, 5, 1, 0, 1, 'あったかくてほっと\\nするなぁ\\nここでゆっくり\\n読書しようかな', 0);
insert into room_unit_comments values (5344, 118401, 3, 7, 1, 0, 1, 'この味…\\nお姉ちゃんが好きそう\\n少しもらって、\\n持って行こうかな…？', 0);
insert into room_unit_comments values (5345, 118401, 3, 8, 1, 0, 1, 'この本みたいな、\\n心躍る大冒険も\\nお姉ちゃんと一緒なら\\nできちゃいそう', 0);
insert into room_unit_comments values (5348, 117501, 1, 1, 1, 0, 1, 'いい部屋ね\\nここを私の分院に\\nするのもいいかも\\nしれないわね…♪', 0);
insert into room_unit_comments values (5349, 117501, 1, 2, 1, 0, 1, '珍しいカンポーが\\n手に入ったから\\n色々試してみたいわ\\n色々と、ね♪', 0);
insert into room_unit_comments values (5350, 117501, 1, 3, 1, 0, 1, 'この服を着ると\\n自分が医者だって\\nより実感するわね\\nまあ、闇医者だけどね', 0);
insert into room_unit_comments values (5351, 117501, 1, 4, 1, 0, 1, '新薬開発のために\\n薬草を採取して\\nおこうかしら', 0);
insert into room_unit_comments values (5352, 117501, 1, 5, 1, 0, 1, 'いつ急患が来ても\\n対応できるように\\nしておきましょうか', 0);
insert into room_unit_comments values (5353, 117501, 1, 101, 4, 0, 1, 'あの子の研究資料も\\nだいぶ増えてきたわね\\nちゃんとまとめて\\nおかないと♪', 0);
insert into room_unit_comments values (5354, 117501, 1, 102, 8, 0, 1, 'あの子は大事な\\n研究対象。だから\\nいつまでも健康で\\nいてもらわないとね♪', 0);
insert into room_unit_comments values (5355, 117501, 2, 1, 1, 0, 1, '薬に興味があるの？\\nなら、今度ゆっくりと\\n教えてあげるわね', 0);
insert into room_unit_comments values (5356, 117501, 2, 2, 1, 0, 1, '少し時間があいたから\\n一緒に新薬の実験を\\nしましょうか♪', 0);
insert into room_unit_comments values (5357, 117501, 2, 3, 1, 0, 1, 'どうしたの？\\nまさか急患…！？\\nあら、違うのね\\nならよかったわ', 0);
insert into room_unit_comments values (5358, 117501, 2, 4, 1, 0, 1, '具合が悪い時はすぐに\\n言うのよ。君には\\nいつでも健康でいて\\nほしいから', 0);
insert into room_unit_comments values (5359, 117501, 2, 101, 4, 0, 1, '少し仮眠したいわね\\n肩…いいえ、膝を\\n貸してもらえる？', 0);
insert into room_unit_comments values (5360, 117501, 2, 102, 8, 0, 1, 'たまには…君の隣なら\\n闇医者も悪い研究者も\\nお休みにするのも\\n悪くないわね♪', 0);
insert into room_unit_comments values (5361, 117501, 2, 1, 1, 1, 1, 'たまには朝の陽ざしを\\n浴びるのも…\\n悪くないわね', 0);
insert into room_unit_comments values (5362, 117501, 2, 2, 1, 2, 1, '天気がいい日は\\nいい薬草が採れるの\\n君も集めるの、\\n手伝ってくれる？', 0);
insert into room_unit_comments values (5363, 117501, 2, 3, 1, 3, 1, 'いけない、もうこんな\\n時間なのね\\n診察に没頭すると\\n時間感覚がなくなるわ', 0);
insert into room_unit_comments values (5365, 117501, 3, 2, 1, 0, 1, 'もう少し固い方が\\n私好みだけど…\\n悪くない寝心地ね', 0);
insert into room_unit_comments values (5366, 117501, 3, 3, 1, 0, 1, 'このぬいぐるみ…\\n闇医者として\\n興味深いわね…', 0);
insert into room_unit_comments values (5367, 117501, 3, 4, 1, 0, 1, '落ち着く香りね\\n私も診察室で\\n使ってみようかしら', 0);
insert into room_unit_comments values (5368, 117501, 3, 5, 1, 0, 1, '冷えは病につながるわ\\nしっかり温めて\\n体をいたわりましょ', 0);
insert into room_unit_comments values (5370, 117501, 3, 7, 1, 0, 1, 'おいしい♪\\n研究のお供に\\nもってこいの\\n味だわ', 0);
insert into room_unit_comments values (5371, 117501, 3, 8, 1, 0, 1, '医学は日進月歩…\\n闇医者とはいえ\\n最新の論文には\\n目を通しておかないと', 0);
insert into room_unit_comments values (5400, 117601, 1, 1, 1, 0, 1, '白衣の天使かあ\\nまさにボクのための\\n呼び方だね', 0);
insert into room_unit_comments values (5401, 117601, 1, 2, 1, 0, 1, '美しさとは\\n日々の努力が\\n作るものなんだよ', 0);
insert into room_unit_comments values (5402, 117601, 1, 3, 1, 0, 1, '大変だ…\\nボクは美しく\\nなりすぎたかも', 0);
insert into room_unit_comments values (5403, 117601, 1, 4, 1, 0, 1, 'ボクのかわいさで\\n癒やされて\\nみんな健康に\\nなっちゃうね', 0);
insert into room_unit_comments values (5404, 117601, 1, 5, 1, 0, 1, 'どんな服装をしても\\nボクの美しさは\\n変わらないね', 0);
insert into room_unit_comments values (5405, 117601, 1, 101, 4, 0, 1, 'これからはボクも\\n美の伝道師として\\nがんばらないとね♪', 0);
insert into room_unit_comments values (5406, 117601, 1, 102, 8, 0, 1, 'ボクのかわいい笑顔を\\n近くで見る以上の\\n癒やしはないよね♪', 0);
insert into room_unit_comments values (5407, 117601, 2, 1, 1, 0, 1, 'どう？\u3000看護師姿の\\nボクもかわいいでしょ\\nもっと近くで見る？', 0);
insert into room_unit_comments values (5408, 117601, 2, 2, 1, 0, 1, 'ほら！\u3000美しいボクの\\n看護師姿を見たら\\n元気でちゃうでしょ？', 0);
insert into room_unit_comments values (5409, 117601, 2, 3, 1, 0, 1, '白衣の天使のボクも\\n最高に美しいね\\n存分に癒されてよ♪', 0);
insert into room_unit_comments values (5410, 117601, 2, 4, 1, 0, 1, '具合が悪いの？\\nならボクの美しい顔を\\n処方してあげる♪', 0);
insert into room_unit_comments values (5411, 117601, 2, 101, 4, 0, 1, 'さあ今日もボクと\\n一緒に美の追求に\\n付き合ってもらうよ♪', 0);
insert into room_unit_comments values (5412, 117601, 2, 102, 8, 0, 1, 'かわいい天使のボクが\\nいつもそばにいるんだ\\nキミって幸せ者だね♪', 0);
insert into room_unit_comments values (5413, 117601, 2, 1, 1, 1, 1, 'さすがボク\\n目が覚めるような\\n美しさでしょ？', 0);
insert into room_unit_comments values (5414, 117601, 2, 2, 1, 2, 1, '美は食で作られる\\n美容にいいものを\\n食べようよ！', 0);
insert into room_unit_comments values (5415, 117601, 2, 3, 1, 3, 1, 'ふああ…早く寝よ？\\n夜更かしは美容の\\n大敵だからね', 0);
insert into room_unit_comments values (5417, 117601, 3, 2, 1, 0, 1, 'ふう～…\\nリラックスする\\nボクも美しい', 0);
insert into room_unit_comments values (5418, 117601, 3, 3, 1, 0, 1, 'ボクが抱きしめると\\n普段よりかわいく\\n見えちゃうね♪', 0);
insert into room_unit_comments values (5419, 117601, 3, 4, 1, 0, 1, '美しいボクは\\n常にいい香りを\\nしていなくちゃね', 0);
insert into room_unit_comments values (5420, 117601, 3, 5, 1, 0, 1, '光がボクを照らしてる\\nんじゃなくて、ボクが\\n光を輝かせてるのさ', 0);
insert into room_unit_comments values (5422, 117601, 3, 7, 1, 0, 1, 'バランスのいい食事が\\n美しいボクを\\n作るのさ', 0);
insert into room_unit_comments values (5423, 117601, 3, 8, 1, 0, 1, 'ふむふむ…なるほど\\nこうすればより美しく\\nなれるかもしれない', 0);
insert into room_unit_comments values (5425, 105701, 1, 103, 12, 0, 1, '仲間のためなら\\nきっと…どこまでも\\n強くなれるよね', 0);
insert into room_unit_comments values (5426, 105701, 2, 103, 12, 0, 1, 'プリンセスフォーム？\\n私と同じような力を\\n持ってる人がいるの？\\n会ってみたいな～！', 0);
